def _start_cli_token_list(argv: object = None) -> list[str]:
    if argv is None:
        return [str(item) for item in sys.argv[1:]]
    if isinstance(argv, (str, bytes, bytearray)):
        return [str(argv)]
    if isinstance(argv, _FlatlineIterable):
        return [str(item) for item in argv]
    return [str(argv)]


def _start_chat_cli_quiet_requested(argv: object = None) -> bool:
    tokens = _start_cli_token_list(argv)
    for index, raw in enumerate(tokens):
        lowered = str(raw or '').strip().lower()
        if lowered in {'--chat', '-chat', '/chat'}:
            return True
        if index == 0 and lowered == 'chat':
            return True
    return False


_START_CHAT_CLI_QUIET = _start_chat_cli_quiet_requested(sys.argv[1:])


def _start_debug_log_path() -> Path:
    try:
        value = str(os.environ.get('TRIO_LAUNCHER_DEBUG_LOG_PATH') or os.environ.get('TRIO_DEBUG_LOG_PATH') or os.environ.get('LAUNCHER_DEBUG_LOG_PATH') or os.environ.get('DEBUG_LOG_PATH') or '').strip()
        return Path(value).expanduser().resolve() if value else (Path(__file__).resolve().parent / 'debug.log')
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        return Path(__file__).resolve().parent / 'debug.log'

def _start_error_log_paths() -> list[Path]:
    base = Path(__file__).resolve().parent
    paths: list[Path] = []
    for key in ('TRIO_LAUNCHER_ERROR_LOG_PATH', 'TRIO_ERROR_LOG_PATH', 'LAUNCHER_ERROR_LOG_PATH', 'ERROR_LOG_PATH'):
        try:
            value = str(os.environ.get(key) or '').strip()
            if value:
                paths.append(Path(value).expanduser().resolve())
        except Exception:  # swallow-ok: log path fallback must never break startup
            pass
    paths.append(base / 'error.log')
    paths.append(base / 'logs' / 'error.log')
    unique: list[Path] = []
    seen: set[str] = set()
    for path in paths:
        try:
            key = str(path.resolve())
        except Exception:  # swallow-ok: path de-dupe fallback
            key = str(path)
        if key not in seen:
            seen.add(key)
            unique.append(path)
    return unique


def _truncate_startup_logs() -> None:
    try:
        debug_path = _start_debug_log_path()
        RuntimeLog.configure(debug_path, buffer_limit=30, reset=True)
        try:
            RuntimeLog.absorbSidecarLogs(Path(__file__).resolve().parent)
        except Exception:
            pass
    except Exception:  # swallow-ok: startup diagnostics must not fail because log cleanup failed
        pass
    # Historical sidecar runtime logs are no longer active.  Truncate them on
    # parent launch so stale data cannot be mistaken for a fresh run.
    for path in _start_error_log_paths():
        try:
            if path.exists() and path.resolve() != _start_debug_log_path().resolve():
                path.unlink(missing_ok=True)
        except Exception:  # swallow-ok: startup diagnostics must not fail because log cleanup failed
            pass



class File:
    """Early-start small file wrapper used before the full data layer exists.

    The launcher diagnostic routes run before normal imports and before the
    project data.File class is available. Keep this wrapper tiny so early
    detector reports can still be written without raw Path calls or NameError.
    """

    def __init__(self, path):
        self.path = Path(path)

    def writeText(self, text: str, encoding: str = 'utf-8', errors: str = 'replace') -> int:  # noqa: N802
        self.path.parent.mkdir(parents=True, exist_ok=True)
        return self.path.write_text(str(text or ''), encoding=encoding, errors=errors)  # file-wrapper-ok

    def appendText(self, text: str, encoding: str = 'utf-8', errors: str = 'replace') -> int:  # noqa: N802
        self.path.parent.mkdir(parents=True, exist_ok=True)
        existing = self.path.read_text(encoding=encoding, errors=errors) if self.path.exists() else ''  # file-wrapper-ok
        return self.path.write_text(existing + str(text or ''), encoding=encoding, errors=errors)  # file-wrapper-ok

    def readText(self, encoding: str = 'utf-8', errors: str = 'replace') -> str:  # noqa: N802
        return self.path.read_text(encoding=encoding, errors=errors)  # file-wrapper-ok

    def writeBytes(self, data: bytes | bytearray | memoryview) -> int:  # noqa: N802
        self.path.parent.mkdir(parents=True, exist_ok=True)
        payload = bytes(data or b'')
        return self.path.write_bytes(payload)  # file-wrapper-ok

    def readBytes(self) -> bytes:  # noqa: N802
        return self.path.read_bytes()  # file-wrapper-ok

    def open(self, *args: Any, **kwargs: Any) -> Any:
        return self.path.open(*args, **kwargs)  # file-wrapper-ok

    def copyTo(self, target: object) -> Path:  # noqa: N802
        destination = Path(str(target))
        destination.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(self.path, destination)  # file-wrapper-ok
        return destination

    def md5Hex(self) -> str:  # noqa: N802
        import hashlib
        return hashlib.md5(self.readBytes()).hexdigest()


def _mirror_start_console_text(text: str) -> None:
    global _START_CONSOLE_MIRROR_BUSY
    if _START_CONSOLE_MIRROR_BUSY:
        return
    value = str(text or '')
    if not value:
        return
    _START_CONSOLE_MIRROR_BUSY = True
    try:
        RuntimeLog.configure(_start_debug_log_path(), buffer_limit=30)
        RuntimeLog.log(value, channel='start-console')
    except Exception:  # swallow-ok: console mirror must never break startup
        pass
    finally:
        _START_CONSOLE_MIRROR_BUSY = False


class StartConsoleMirrorStream:
    """Mirror parent start.py stdout/stderr writes into root debug.log.

    Trio's child already mirrors print/stdout/stderr.  The universal debugger
    parent can be most of startup and all of startup when the child never
    launches, so start.py must mirror the same way before any risky bootstrap
    work runs.
    """
    _flatline_start_console_mirror_stream = True

    def __init__(self, stream, name: str):
        self._stream = stream
        self._name = str(name or 'stdout')

    def write(self, data):
        value = str(data or '')
        written = self._stream.write(value)
        if value:
            _mirror_start_console_text(value)
        return written

    def flush(self):
        try:
            RuntimeLog.flush(final=True)
        except Exception:
            pass
        return self._stream.flush()

    def isatty(self):
        return bool(getattr(self._stream, 'isatty', lambda: False)())

    def fileno(self):
        return self._stream.fileno()

    @property
    def encoding(self):
        return getattr(self._stream, 'encoding', None)

    @property
    def errors(self):
        return getattr(self._stream, 'errors', None)

    def reconfigure(self, *args, **kwargs):
        fn = getattr(self._stream, 'reconfigure', None)
        if callable(fn):
            return fn(*args, **kwargs)
        return None

    def __getattr__(self, name):
        return getattr(self._stream, name)


def installStartConsoleStreamMirror() -> None:
    global _START_CONSOLE_STREAM_MIRROR_INSTALLED
    try:
        path = _start_debug_log_path()
        path.parent.mkdir(parents=True, exist_ok=True)
        _is_worker = any(str(os.environ.get(k) or '').strip().lower() in {'1', 'true', 'yes', 'y', 'on'}
                         for k in ('FONT_WORKER', 'MODEL_CATALOG_WORKER', 'DEPENDENCY_WORKER',
                                   'STARTUP_TOOLS_WORKER', 'CHAT_TEST_WORKER', 'TRIO_WORKER', 'FLATLINE_WORKER'))
        if not _is_worker:
            try:
                worker_tokens = {str(token or '').strip().lower().lstrip('-/').replace('_', '-') for token in _start_cli_token_list(sys.argv[1:])}
                _is_worker = bool(worker_tokens.intersection({'shell-rpc-worker', 'shellrpc-worker', 'shell-worker', 'model-catalog-worker', 'dependency-worker', 'font-worker'}))
            except Exception:
                _is_worker = False
        if not _is_worker:
            _truncate_startup_logs()  # only truncate on fresh parent launch, not in worker subprocesses
    except Exception:  # swallow-ok: mirror setup must not block startup
        pass
    try:
        if not getattr(sys.stdout, '_flatline_start_console_mirror_stream', False):
            sys.stdout = StartConsoleMirrorStream(sys.stdout, 'stdout')  # monkeypatch-ok: intentional parent startup stdout mirror
        if not getattr(sys.stderr, '_flatline_start_console_mirror_stream', False):
            sys.stderr = StartConsoleMirrorStream(sys.stderr, 'stderr')  # monkeypatch-ok: intentional parent startup stderr mirror
        _START_CONSOLE_STREAM_MIRROR_INSTALLED = True
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        pass


def safeStartConsolePrint(*args, sep=' ', end='\n', file=None, flush=False):
    try:
        target = file if file is not None else sys.stdout
        return _START_ORIGINAL_PRINT(*args, sep=sep, end=end, file=target, flush=flush)
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        try:
            rendered = str(sep).join(str(arg) for arg in args) + str(end)
            _mirror_start_console_text(rendered)
        except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
            pass
        return None


def installStartConsolePrintMirror() -> None:
    global _START_CONSOLE_PRINT_MIRROR_INSTALLED
    try:
        if getattr(_flatline_builtins, 'print', None) is not safeStartConsolePrint:
            _flatline_builtins.print = safeStartConsolePrint
        _START_CONSOLE_PRINT_MIRROR_INSTALLED = True
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        pass


if not _START_CHAT_CLI_QUIET:
    installStartConsoleStreamMirror()
    installStartConsolePrintMirror()
    print(f'[TRACE:start-console-mirror] start.py stdout/stderr/print mirroring to {_start_debug_log_path()}', file=sys.stderr, flush=True)

