def requiredSharedSymbol(name: str, value: Any) -> Any:
    """Return a shared models.py symbol or raise a clear launcher error."""
    if value is None:
        raise RuntimeError(f'models.py shared symbol {name} is not available; provider/runtime route cannot continue.')
    return cast(Any, value)


