class AppException(Exception):
    def __init__(self, message: str = '', context: str = '', source: str = 'start.py'):
        super().__init__(message)
        self.context = str(context or '')
        self.source = str(source or 'start.py')


def _flatlineProjectSqlitePath() -> Path:
    for name in ('FLATLINE_SQLITE_PATH', 'TRIO_SQLITE_PATH', 'SQLITE_PATH'):
        raw = str(os.environ.get(name, '') or '').strip()
        if raw:
            path = Path(raw).expanduser()
            if not path.is_absolute():
                path = Path(__file__).resolve().parent / path
            resolved = path.resolve()
            os.environ['FLATLINE_SQLITE_PATH'] = str(resolved)
            os.environ['TRIO_SQLITE_PATH'] = str(resolved)
            os.environ['SQLITE_PATH'] = str(resolved)
            return resolved
    root = Path(__file__).resolve().parent
    db_name = 'triodesktop.db'
    try:
        import configparser as _configparser
        parser = _configparser.ConfigParser()
        config_path = root / 'config.ini'
        if config_path.exists():
            parser.read(config_path, encoding='utf-8')
            db_name = str(parser.get('sqlite', 'path', fallback=db_name) or db_name).strip() or db_name
    except Exception as error:  # swallow-ok: config fallback must not recurse during exception recording
        safeStartConsolePrint(f'[WARNING:exception-db-config] {type(error).__name__}: {error}; using triodesktop.db', file=sys.stderr, flush=True)
    path = Path(db_name).expanduser()
    if not path.is_absolute():
        path = root / path
    resolved = path.resolve()
    os.environ['FLATLINE_SQLITE_PATH'] = str(resolved)
    os.environ['TRIO_SQLITE_PATH'] = str(resolved)
    os.environ['SQLITE_PATH'] = str(resolved)
    return resolved

def _traceSwallowedException(context: str, error=None) -> None:
    try:
        detail = f'{type(error).__name__}: {error}' if error is not None else '<unknown>'
        print(f'[WARN:swallowed] {context}: {detail}', file=sys.stderr, flush=True)
    except Exception:  # swallow-ok: trace helper fallback must never recurse
        pass
    try:
        recordException(context, error, handled=True)
    except Exception:  # swallow-ok: trace helper fallback must never recurse
        pass


def recordException(context: str, error=None, *, handled: bool = True, source: str = 'start.py') -> int:
    """Persist caught exceptions into the debugger-visible exceptions table."""
    if bool(globals().get('_RECORD_EXCEPTION_BUSY', False)):
        return 0
    globals()['_RECORD_EXCEPTION_BUSY'] = True
    try:
        import datetime as _dt
        import os as _os
        import sys as _sys
        import traceback as _traceback
        from pathlib import Path as _Path
        caught = error if isinstance(error, BaseException) else _sys.exc_info()[1]
        if isinstance(caught, AppException):
            context = caught.context or context
            source = caught.source or source
        type_name = type(caught).__name__ if caught is not None else 'Exception'
        message = str(caught or context or '')
        try:
            traceback_text = ''.join(_traceback.format_exception(type(caught), caught, getattr(caught, '__traceback__', None))) if caught is not None else _traceback.format_exc()
        except Exception:  # swallow-ok: exception recorder must not recurse while formatting traceback
            traceback_text = message
        payload = {
            'created': _dt.datetime.now(),
            'source': str(source or 'start.py'),
            'context': str(context or ''),
            'typeName': str(type_name or 'Exception'),
            'message': message,
            'tracebackText': str(traceback_text or ''),
            'sourceContext': '',
            'worker': 'launcher',
            'pid': int(_os.getpid() or 0),
            'handled': 1 if bool(handled) else 0,
            'processed': 0,
        }
        database_type = globals().get('Database')
        if database_type is not None:
            try:
                database = database_type.FromEnvironment()
            except Exception:  # swallow-ok: fallback path for exception recorder
                sqlite_path = str(_flatlineProjectSqlitePath())
                _os.environ['SQLITE_PATH'] = sqlite_path
                _os.environ['FLATLINE_SQLITE_PATH'] = sqlite_path
                _os.environ['TRIO_SQLITE_PATH'] = sqlite_path
                database = database_type.ForSqlitePath(sqlite_path)
            try:
                row_id = int(database.InsertDebuggerException(payload) or 0)
                if row_id:
                    return row_id
            except Exception as db_error:  # swallow-ok: log fallback below if DB insert fails
                try:
                    
                    try:
                        RuntimeLog.log(f'[WARN:exception-db] {context}: {type(db_error).__name__}: {db_error}\n', flush=True, channel='exception-db')
                    except Exception:  # swallow-ok: final fallback while recording an exception
                        pass
                except Exception:  # swallow-ok: stderr fallback must not recurse
                    pass
        try:
            RuntimeLog.log(f"[{_dt.datetime.now().isoformat(timespec='seconds')}] {payload['source']} {payload['context']} {payload['typeName']}: {payload['message']}\n{payload['tracebackText']}\n\n", flush=True, channel='exceptions')
        except Exception:  # swallow-ok: final recorder fallback cannot recurse
            pass
        return 0
    finally:
        globals()['_RECORD_EXCEPTION_BUSY'] = False


