def _early_clean_cli_name(token: str) -> str:
    value = str(token or '').strip().lower()
    while value.startswith('-') or value.startswith('/'):
        value = value[1:]
    for separator in ('=', ':'):
        if separator in value:
            value = value.split(separator, 1)[0]
    return value.strip()


def _early_has_diagnostic(argv: list[str], names: set[str]) -> bool:
    return any(_early_clean_cli_name(token) in names for token in list(argv or [])[1:])


def _early_common_bootstrap_targets(project_root: Path) -> list[Path]:
    candidates = [project_root / 'trio.py', project_root / 'main.py', project_root / 'app.py']
    unique: list[Path] = []
    for candidate in candidates:
        if candidate.exists() and candidate not in unique:
            unique.append(candidate)
    return unique


def _early_command_text(command: list[str]) -> str:
    return ' '.join(shlex.quote(str(part)) for part in command)


def _early_python_detector_command(script: Path, *args: str) -> list[str]:
    # Claude detectors are stdlib-only; -S avoids slow/hostile site imports and keeps report-only mode fast.
    return [sys.executable, '-S', str(script), *[str(arg) for arg in args]]





def _early_run_command_filebacked(command: list[str], *, cwd: Path, stdout_path: Path, stderr_path: Path, timeout_seconds: int = 120) -> tuple[int, str, str]:
    """Run a detector with file-backed output and a hard process-tree watchdog.

    The old implementation wrapped Linux commands in /usr/bin/timeout.  That can
    leave the universal debugger waiting on the wrapper even after the detector
    report was written.  Use one direct child process, close stdin, write stdout
    and stderr to files, and kill the process group on timeout.
    """
    stdout_path.parent.mkdir(parents=True, exist_ok=True)
    stderr_path.parent.mkdir(parents=True, exist_ok=True)
    timeout_seconds = max(1, int(timeout_seconds or 120))
    process = None
    return_code = 2
    with stdout_path.open('w', encoding='utf-8', errors='replace') as stdout_handle, stderr_path.open('w', encoding='utf-8', errors='replace') as stderr_handle:  # file-wrapper-ok
        popen_kwargs: dict[str, Any] = {
            'cwd': str(cwd),
            'text': True,
            'stdout': stdout_handle,
            'stderr': stderr_handle,
            'stdin': subprocess.DEVNULL,
        }
        try:
            if os.name == 'nt':
                popen_kwargs['creationflags'] = (
                    int(getattr(subprocess, 'CREATE_NEW_PROCESS_GROUP', 0) or 0)
                    | int(getattr(subprocess, 'CREATE_NO_WINDOW', 0) or 0)
                )
                try:
                    startupinfo = subprocess.STARTUPINFO()
                    startupinfo.dwFlags |= int(getattr(subprocess, 'STARTF_USESHOWWINDOW', 0) or 0)
                    startupinfo.wShowWindow = 0
                    popen_kwargs['startupinfo'] = startupinfo
                except Exception:
                    recordException('start.py:early-run-command-filebacked-startupinfo', sys.exc_info()[1], handled=True)
            else:
                popen_kwargs['start_new_session'] = True
        except Exception:
            recordException('start.py:early-run-command-filebacked-popen-flags', sys.exc_info()[1])
        try:
            process = subprocess.Popen(command, **popen_kwargs)  # lifecycle-bypass-ok  # phase-ownership-ok
            deadline = time.monotonic() + timeout_seconds
            last_trace = 0.0
            while True:
                poll_code = process.poll()
                if poll_code is not None:
                    return_code = int(poll_code or 0)
                    break
                now = time.monotonic()
                if now - last_trace >= 5.0:
                    print(f'[TRACE:detector] still running pid={process.pid} timeout={timeout_seconds}s command={Path(str(command[2] if len(command) > 2 else command[0])).name}', flush=True)
                    last_trace = now
                if now >= deadline:
                    stderr_handle.write(f"\nTimed out after {timeout_seconds} second(s).\n")
                    stderr_handle.flush()
                    try:
                        if os.name == 'nt':
                            subprocess.run(['taskkill', '/PID', str(process.pid), '/T', '/F'], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, stdin=subprocess.DEVNULL, check=False, timeout=15)  # lifecycle-bypass-ok  # phase-ownership-ok
                        else:
                            try:
                                os.killpg(int(process.pid), signal.SIGTERM)
                            except Exception:
                                recordException('start.py:early-run-command-filebacked-killpg-term', sys.exc_info()[1])
                                process.terminate()
                            try:
                                process.wait(timeout=5)
                            except Exception:
                                recordException('start.py:early-run-command-filebacked-wait-after-term', sys.exc_info()[1])
                                try:
                                    os.killpg(int(process.pid), signal.SIGKILL)
                                except Exception:
                                    recordException('start.py:early-run-command-filebacked-killpg-kill', sys.exc_info()[1])
                                    process.kill()
                                try:
                                    process.wait(timeout=5)
                                except Exception:
                                    recordException('start.py:early-run-command-filebacked-wait-after-kill', sys.exc_info()[1])
                    finally:
                        return_code = 124
                    break
                time.sleep(0.05)
        except Exception as error:
            recordException('start.py:early-run-command-filebacked', sys.exc_info()[1])
            stderr_handle.write(f'{type(error).__name__}: {error}\n')
            stderr_handle.flush()
            return_code = 2
    return int(return_code or 0), File(stdout_path).readText(), File(stderr_path).readText()


def _early_run_command(command: list[str], *, cwd: Path, timeout_seconds: int = 120) -> tuple[int, str, str]:
    """Run an early diagnostic command with hard timeout cleanup.

    subprocess.run(timeout=...) is normally enough, but detector certification
    must not hold the universal debugger hostage.  This implementation starts a
    distinct process group/session, closes stdin, captures output, and kills the
    whole child tree when the deadline expires.
    """
    # lifecycle-bypass-ok: early report-only diagnostics run before the launcher lifecycle exists.
    popen_kwargs: dict[str, Any] = {
        'cwd': str(cwd),
        'text': True,
        'stdout': subprocess.PIPE,
        'stderr': subprocess.PIPE,
        'stdin': subprocess.DEVNULL,
    }
    try:
        if os.name == 'nt':
            popen_kwargs['creationflags'] = (
                int(getattr(subprocess, 'CREATE_NEW_PROCESS_GROUP', 0) or 0)
                | int(getattr(subprocess, 'CREATE_NO_WINDOW', 0) or 0)
            )
            try:
                startupinfo = subprocess.STARTUPINFO()
                startupinfo.dwFlags |= int(getattr(subprocess, 'STARTF_USESHOWWINDOW', 0) or 0)
                startupinfo.wShowWindow = 0
                popen_kwargs['startupinfo'] = startupinfo
            except Exception:
                recordException('start.py:early-run-command-startupinfo', sys.exc_info()[1], handled=True)
        else:
            popen_kwargs['start_new_session'] = True
    except Exception:
        recordException('start.py:early-run-command-popen-flags', sys.exc_info()[1])
    process = None
    try:
        process = subprocess.Popen(command, **popen_kwargs)  # lifecycle-bypass-ok  # phase-ownership-ok
        try:
            stdout, stderr = process.communicate(timeout=max(1, int(timeout_seconds or 120)))
            return int(process.returncode or 0), str(stdout or ''), str(stderr or '')
        except subprocess.TimeoutExpired as error:
            recordException('start.py:early-run-command-timeout', sys.exc_info()[1])
            stdout = error.stdout.decode('utf-8', 'replace') if isinstance(error.stdout, bytes) else str(error.stdout or '')
            stderr = error.stderr.decode('utf-8', 'replace') if isinstance(error.stderr, bytes) else str(error.stderr or '')
            try:
                if process is not None and process.poll() is None:
                    if os.name == 'nt':
                        subprocess.run(['taskkill', '/PID', str(process.pid), '/T', '/F'], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, stdin=subprocess.DEVNULL, check=False, timeout=15)  # lifecycle-bypass-ok  # phase-ownership-ok
                    else:
                        try:
                            os.killpg(int(process.pid), signal.SIGTERM)
                        except Exception:
                            recordException('start.py:early-run-command-killpg-term', sys.exc_info()[1])
                            try:
                                process.terminate()
                            except Exception:
                                recordException('start.py:early-run-command-terminate', sys.exc_info()[1])
                        try:
                            process.wait(timeout=5)
                        except Exception:
                            recordException('start.py:early-run-command-wait-after-term', sys.exc_info()[1])
                            try:
                                os.killpg(int(process.pid), signal.SIGKILL)
                            except Exception:
                                recordException('start.py:early-run-command-killpg-kill', sys.exc_info()[1])
                                try:
                                    process.kill()
                                except Exception:
                                    recordException('start.py:early-run-command-kill', sys.exc_info()[1])
            finally:
                try:
                    extra_stdout, extra_stderr = process.communicate(timeout=1) if process is not None else ('', '')
                    stdout += str(extra_stdout or '')
                    stderr += str(extra_stderr or '')
                except Exception:
                    recordException('start.py:early-run-command-communicate-after-kill', sys.exc_info()[1])
            return 124, stdout, (stderr + f"\nTimed out after {timeout_seconds} second(s).\n").strip() + '\n'
    except Exception as error:
        recordException('start.py:early-run-command', sys.exc_info()[1])
        return 2, '', f'{type(error).__name__}: {error}\n'


def _early_resolve_ruff_command(project_root: Path, transcript: list[str]) -> tuple[list[str], str]:
    env_command = os.environ.get('TRIO_RUFF_COMMAND') or os.environ.get('TRIO_ROUGH_COMMAND')
    if env_command:
        command = shlex.split(env_command)
        code, stdout, stderr = _early_run_command([*command, '--version'], cwd=project_root, timeout_seconds=30)
        transcript.extend(['Environment Ruff command probe:', _early_command_text([*command, '--version']), stdout.strip(), stderr.strip(), ''])
        if code == 0:
            return command, 'environment command'

    executable = shutil.which('ruff') or shutil.which('ruff.exe')
    if executable:
        code, stdout, stderr = _early_run_command([executable, '--version'], cwd=project_root, timeout_seconds=30)
        transcript.extend(['PATH Ruff command probe:', _early_command_text([executable, '--version']), stdout.strip(), stderr.strip(), ''])
        if code == 0:
            return [executable], 'PATH ruff'

    module_probe = [sys.executable, '-m', 'ruff', '--version']
    code, stdout, stderr = _early_run_command(module_probe, cwd=project_root, timeout_seconds=30)
    transcript.extend(['Python module Ruff probe:', _early_command_text(module_probe), stdout.strip(), stderr.strip(), ''])
    if code == 0:
        return [sys.executable, '-m', 'ruff'], 'python -m ruff'

    if os.environ.get('TRIO_ROUGH_NO_INSTALL') or os.environ.get('TRIO_RUFF_NO_INSTALL'):
        transcript.append('Automatic Ruff installation skipped because TRIO_ROUGH_NO_INSTALL/TRIO_RUFF_NO_INSTALL is set.')
        return [], ''

    pip_command = [sys.executable, '-m', 'pip', 'install', 'ruff']
    if sys.platform.startswith('linux'):
        pip_command.append('--break-system-packages')
    install_timeout = int(os.environ.get('TRIO_ROUGH_INSTALL_TIMEOUT', '120') or '120')
    code, stdout, stderr = _early_run_command(pip_command, cwd=project_root, timeout_seconds=install_timeout)
    transcript.extend(['Ruff pip install attempt:', _early_command_text(pip_command), stdout.strip(), stderr.strip(), f'install exit code: {code}', ''])
    if code == 0:
        executable = shutil.which('ruff') or shutil.which('ruff.exe')
        if executable:
            return [executable], 'pip-installed ruff command'
        code, stdout, stderr = _early_run_command(module_probe, cwd=project_root, timeout_seconds=30)
        transcript.extend(['Post-install Python module Ruff probe:', _early_command_text(module_probe), stdout.strip(), stderr.strip(), ''])
        if code == 0:
            return [sys.executable, '-m', 'ruff'], 'pip-installed python -m ruff'
    return [], ''


def _early_run_rough_mode(argv: list[str]) -> int:
    project_root = _EARLY_DIAGNOSTIC_ROOT
    report_path = project_root / 'rough.txt'
    logs_dir = project_root / 'logs'
    logs_dir.mkdir(parents=True, exist_ok=True)
    log_report_path = logs_dir / 'Ruff.txt'
    start_file = Path(__file__).resolve()
    targets = [start_file, *_early_common_bootstrap_targets(project_root)]
    targets = [path for index, path in enumerate(targets) if path.exists() and path not in targets[:index]]
    transcript: list[str] = []
    exit_code = 2
    lines = [
        'ROUGH / RUFF REPORT',
        '===================',
        '',
        f'Generated at: {datetime.datetime.now().isoformat(timespec="seconds")}',
        f'Project root: {project_root}',
        f'Launcher: {start_file.name}',
        f'Bootstrapped target(s): {", ".join(path.name for path in targets if path.name != start_file.name) or "<none detected>"}',
        f'Files requested: {", ".join(path.name for path in targets) or "<none>"}',
        '',
        '[ROUGH] Real Ruff diagnostic mode; normal TrioDesktop startup was skipped.',
        '',
    ]
    try:
        command_base, source_label = _early_resolve_ruff_command(project_root, transcript)
        lines.extend(['RUFF RESOLUTION:', *[line for line in transcript if line is not None], ''])
        if not command_base:
            lines.extend([
                'Ruff setup or execution failed.',
                'No runnable Ruff command was found. The launcher tried TRIO_RUFF_COMMAND/TRIO_ROUGH_COMMAND, PATH ruff, python -m ruff, and pip install ruff.',
                '',
            ])
            exit_code = 2
        else:
            relative_files = [str(path.relative_to(project_root)) for path in targets]
            command = [*command_base, 'check', *relative_files]
            code, stdout, stderr = _early_run_command(command, cwd=project_root, timeout_seconds=int(os.environ.get('TRIO_ROUGH_TIMEOUT', '900') or '900'))
            exit_code = code
            lines.extend([
                f'Ruff source: {source_label}',
                f'Command: {_early_command_text(command)}',
                f'Exit code: {code}',
                '',
                'STDOUT:',
                stdout.rstrip() or '<empty>',
                '',
                'STDERR:',
                stderr.rstrip() or '<empty>',
                '',
            ])
    except Exception as error:
        recordException('start.py:263', sys.exc_info()[1])
        lines.extend(['Ruff setup or execution failed.', f'{type(error).__name__}: {error}', ''])
        exit_code = 2
    lines.extend([
        'NEXT STEPS:',
        '1. Read each Ruff diagnostic if Ruff produced one.',
        '2. Fix the smallest safe issue first.',
        '3. Re-run: python start.py --rough',
        '4. Repeat until Ruff reports: All checks passed!',
        '',
    ])
    report = '\n'.join(lines)
    File(report_path).writeText(report)
    File(log_report_path).writeText(report)
    print(report, flush=True)
    print(f'[ROUGH] Report written to {report_path}', flush=True)
    print(f'[ROUGH] Log copy written to {log_report_path}', flush=True)
    return int(exit_code)


