from typing import Any, Callable, TYPE_CHECKING, cast


def runtimeModuleName(*parts: object) -> str:
    # Keep optional/lazy imports dynamic so Pylance does not flag modules that
    # are installed at runtime by the launcher dependency flow.
    cleaned = [str(part or EMPTY_STRING).strip().strip('.') for part in parts if str(part or EMPTY_STRING).strip().strip('.')]
    return '.'.join(cleaned)


def runtimeImportModule(*parts: object) -> Any:
    module_name = runtimeModuleName(*parts)
    if not module_name:
        raise ImportError('empty runtime module name')
    return importlib.import_module(module_name)


