def localize(owner=None, tokenKey=EMPTY_STRING, default: str = EMPTY_STRING, element=None, language=None) -> str:
    """Launcher-safe localization shim for early/debugger UI text.

    The real child app has a full localization engine.  start.py must also avoid
    raw Qt string literals so detector coverage stays honest, but it cannot rely
    on the child runtime being imported.  This helper returns the provided
    default text and gives detectors a single localization boundary.
    """
    text = default if default is not None and str(default) != EMPTY_STRING else tokenKey
    return str(text or EMPTY_STRING)


