class WindowPolicy:
    CONSOLE_HELPER = 'console_helper'
    GUI_CHILD = 'gui_child'
    DAEMON = 'daemon'
    PROBE = 'probe'


def _flatlinePolicyFromLegacy(policy: object, command: object = None) -> str:
    normalized = _normalizeWindowPolicy(policy, command) if '_normalizeWindowPolicy' in globals() else str(policy or '').strip().lower()
    if normalized in {globals().get('WINDOW_POLICY_QT_CHILD', 'qt-child'), 'qt-child', 'gui', 'gui-child', 'gui_child'}:
        return WindowPolicy.GUI_CHILD
    if normalized in {globals().get('WINDOW_POLICY_ALLOW', 'allow-window'), 'allow-window', 'allow'}:
        return WindowPolicy.GUI_CHILD
    raw = str(policy or '').strip().lower().replace('-', '_')
    if raw in {'daemon'}:
        return WindowPolicy.DAEMON
    if raw in {'probe'}:
        return WindowPolicy.PROBE
    return WindowPolicy.CONSOLE_HELPER


def windowsCreationFlagsForPolicy(policy: str = WindowPolicy.CONSOLE_HELPER, existing: int = 0) -> int:
    flags = int(existing or 0)
    if os.name != 'nt':
        return flags
    flags |= int(getattr(subprocess, 'CREATE_NO_WINDOW', 0) or 0)
    if policy in {WindowPolicy.DAEMON, WindowPolicy.GUI_CHILD, WindowPolicy.CONSOLE_HELPER, WindowPolicy.PROBE}:
        flags |= int(getattr(subprocess, 'CREATE_NEW_PROCESS_GROUP', 0) or 0)
    return flags


def windowsStartupInfoForProbe() -> Any:
    if os.name != 'nt':
        return None
    try:
        startupinfo = subprocess.STARTUPINFO()
        startupinfo.dwFlags |= int(getattr(subprocess, 'STARTF_USESHOWWINDOW', 0) or 0)
        startupinfo.wShowWindow = 0
        return startupinfo
    except Exception:
        recordException('start.py:windowsStartupInfoForProbe', sys.exc_info()[1])
        return None


def hiddenHelperEnvironment(base_env: object = None) -> dict[str, str]:
    """Return an environment for helper/probe subprocesses that must not show UI.

    Helper probes are supposed to be invisible.  On Windows we combine
    CREATE_NO_WINDOW + STARTF_USESHOWWINDOW with this environment.  On Qt-aware
    helper imports, QT_QPA_PLATFORM=offscreen keeps accidental Qt work off the
    desktop.  Real TrioDesktop GUI children do not use this helper environment.
    """
    try:
        env = dict(base_env or os.environ)
    except Exception:
        recordException('start.py:hidden-helper-environment-copy', sys.exc_info()[1], handled=True)
        env = dict(os.environ)
    env.setdefault('PYTHONUNBUFFERED', '1')
    env.setdefault('PYTHONIOENCODING', 'utf-8')
    env.setdefault('QT_QPA_PLATFORM', 'offscreen')
    env.setdefault('TRIO_HELPER_NO_WINDOW', '1')
    env.setdefault('FLATLINE_HELPER_NO_WINDOW', '1')
    return env


def flatlineSubprocessKwargs(command: Any, kwargs: dict[str, Any] | None = None, *, policy: str = WindowPolicy.CONSOLE_HELPER) -> dict[str, Any]:
    result = dict(kwargs or {})
    result.setdefault('stdin', subprocess.DEVNULL)
    if os.name == 'nt':
        result['creationflags'] = windowsCreationFlagsForPolicy(policy, int(result.get('creationflags', 0) or 0))
        if policy in {WindowPolicy.CONSOLE_HELPER, WindowPolicy.PROBE}:
            if result.get('startupinfo') is None:
                result['startupinfo'] = windowsStartupInfoForProbe()
            result['env'] = hiddenHelperEnvironment(result.get('env'))
    else:
        if policy in {WindowPolicy.DAEMON, WindowPolicy.GUI_CHILD, WindowPolicy.CONSOLE_HELPER}:
            result.setdefault('start_new_session', True)
        if policy in {WindowPolicy.CONSOLE_HELPER, WindowPolicy.PROBE}:
            result['env'] = hiddenHelperEnvironment(result.get('env'))
    return result



