def _callerSourceContext(skip: int = 2) -> str:
    """Return the real launcher callsite used to create a process/window."""
    try:
        stack = traceback.extract_stack(limit=max(4, int(skip or 2) + 4))
        frame = stack[-max(2, int(skip or 2))]
        frame_lineno = int(frame.lineno or 0)
        code = str(linecache.getline(frame.filename, frame_lineno) or frame.line or EMPTY_STRING).strip()
        return f'{Path(frame.filename).name}:{frame_lineno}:{frame.name}: {code}'
    except Exception:
        recordException('start.py:window-monitor-caller-source', sys.exc_info()[1], handled=True)
        return 'unknown launcher callsite'


def _windowMonitorEnabled() -> bool:
    try:
        env_value = str(os.environ.get('TRIO_WINDOW_MONITOR', os.environ.get('FLATLINE_WINDOW_MONITOR', '1')) or '1').strip().lower()
        if env_value in WINDOW_MONITOR_ALLOW_ENV_VALUES:
            return False
        fail_value = str(os.environ.get('TRIO_FAIL_ON_DEAD_WINDOW', os.environ.get('FLATLINE_FAIL_ON_DEAD_WINDOW', '1')) or '1').strip().lower()
        if fail_value in WINDOW_MONITOR_ALLOW_ENV_VALUES:
            return False
        tokens = {str(arg or EMPTY_STRING).strip().lower() for arg in sys.argv[1:]}
        return not bool(tokens.intersection(WINDOW_MONITOR_DISABLE_FLAGS))
    except Exception:
        recordException('start.py:window-monitor-enabled', sys.exc_info()[1], handled=True)
        return True


def _normalizeWindowPolicy(policy: object, command: object = None) -> str:
    raw = str(policy or EMPTY_STRING).strip().lower().replace('_', '-').replace(' ', '-')
    if raw in {'allow', 'allowed', 'allow-window', 'window-ok', 'gui-ok'}:
        return WINDOW_POLICY_ALLOW
    if raw in {'qt', 'qt-child', 'gui', 'gui-child', 'python-gui'}:
        return WINDOW_POLICY_QT_CHILD
    if raw in {'helper', 'console-helper', 'no-window', 'helper-no-window', 'probe'}:
        return WINDOW_POLICY_HELPER
    try:
        parts = [str(part or EMPTY_STRING).replace('\\', '/').lower() for part in (command if isinstance(command, (list, tuple)) else [command])]
        command_text = ' '.join(parts)
        if any(token in command_text for token in ('trio.py', 'cutie.py', 'gtp.py', 'operator_client.py', 'operator-client.py')):
            return WINDOW_POLICY_QT_CHILD
    except Exception:
        recordException('start.py:window-monitor-normalize-policy', sys.exc_info()[1], handled=True)
    return WINDOW_POLICY_HELPER


class WindowRow:
    __slots__ = ('hwnd', 'pid', 'title', 'className', 'visible')

    def __init__(self, hwnd: int, pid: int, title: str, className: str, visible: bool):
        self.hwnd = int(hwnd or 0)
        self.pid = int(pid or 0)
        self.title = str(title or EMPTY_STRING)
        self.className = str(className or EMPTY_STRING)
        self.visible = bool(visible)

    def key(self) -> int:
        return int(self.hwnd or 0)

    def toDict(self) -> dict[str, object]:  # noqa: N802
        return {
            'hwnd': int(self.hwnd or 0),
            'pid': int(self.pid or 0),
            'title': self.title,
            'className': self.className,
            'visible': bool(self.visible),
        }

    def describe(self) -> str:
        return json.dumps(self.toDict(), sort_keys=True, ensure_ascii=False)



def windowsProcessParentMap() -> dict[int, int]:  # noqa: N802
    """Return pid -> parent-pid on Windows without launching another helper.

    The window monitor must never blame random desktop popups that appear while a
    probe is running.  This Toolhelp snapshot lets us restrict failures to the
    launched process tree without spawning tasklist/wmic/powershell, which could
    itself create the very windows we are trying to prevent.
    """
    if os.name != 'nt':
        return {}
    parent_map: dict[int, int] = {}
    try:
        from ctypes import wintypes  # type: ignore
        TH32CS_SNAPPROCESS = 0x00000002
        INVALID_HANDLE_VALUE = ctypes.c_void_p(-1).value

        class PROCESSENTRY32W(ctypes.Structure):
            _fields_ = [
                ('dwSize', wintypes.DWORD),
                ('cntUsage', wintypes.DWORD),
                ('th32ProcessID', wintypes.DWORD),
                ('th32DefaultHeapID', ctypes.c_void_p),
                ('th32ModuleID', wintypes.DWORD),
                ('cntThreads', wintypes.DWORD),
                ('th32ParentProcessID', wintypes.DWORD),
                ('pcPriClassBase', wintypes.LONG),
                ('dwFlags', wintypes.DWORD),
                ('szExeFile', wintypes.WCHAR * 260),
            ]

        kernel32 = ctypes.windll.kernel32  # type: ignore[attr-defined]
        snapshot = kernel32.CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0)
        if int(snapshot or 0) == int(INVALID_HANDLE_VALUE or -1):
            return parent_map
        try:
            entry = PROCESSENTRY32W()
            entry.dwSize = ctypes.sizeof(PROCESSENTRY32W)
            ok = bool(kernel32.Process32FirstW(snapshot, ctypes.byref(entry)))
            while ok:
                parent_map[int(entry.th32ProcessID or 0)] = int(entry.th32ParentProcessID or 0)
                ok = bool(kernel32.Process32NextW(snapshot, ctypes.byref(entry)))
        finally:
            try:
                kernel32.CloseHandle(snapshot)
            except Exception:
                recordException('start.py:windows-process-parent-map-close', sys.exc_info()[1], handled=True)
    except Exception:
        recordException('start.py:windows-process-parent-map', sys.exc_info()[1], handled=True)
    return parent_map


def windowsPidInProcessTree(pid: int, rootPid: int, parent_map: dict[int, int] | None = None) -> bool:  # noqa: N802
    pid_value = int(pid or 0)
    root_value = int(rootPid or 0)
    if pid_value <= 0 or root_value <= 0:
        return False
    if pid_value == root_value:
        return True
    if os.name != 'nt':
        return False
    parents = parent_map if parent_map is not None else windowsProcessParentMap()
    seen: set[int] = set()
    current = pid_value
    for _ in range(96):
        if current <= 0 or current in seen:
            return False
        if current == root_value:
            return True
        seen.add(current)
        current = int(parents.get(current, 0) or 0)
    return False


class DeadWindowMonitor:
    """Fail-fast diagnostic monitor for unexpected visible Windows windows.

    This is intentionally not a janitor.  If a hidden console helper or Python
    subprocess leaks a visible dead console window, FlatLine logs the opener,
    kills the owner once, and exits nonzero so the bad launch site gets fixed.
    Qt/Python GUI children may create their intended Qt window, but never a
    visible Python ConsoleWindowClass.
    """

    CONSOLE_CLASSES = {'consolewindowclass'}
    PYTHON_TITLE_TOKENS = ('python', 'python.exe', 'pythonw.exe', 'py.exe')
    ALLOWED_QT_CLASS_TOKENS = ('qt', 'qwindow', 'qwidget')

    def __init__(self) -> None:
        self.currentPid = os.getpid()

    def snapshot(self) -> dict[int, WindowRow]:
        if os.name != 'nt' or not _windowMonitorEnabled():
            return {}
        rows: dict[int, WindowRow] = {}
        try:
            user32 = ctypes.windll.user32  # type: ignore[attr-defined]
            enum_proc_type = ctypes.WINFUNCTYPE(ctypes.c_bool, ctypes.c_void_p, ctypes.c_void_p)  # type: ignore[attr-defined]

            def _callback(hwnd, _lparam):
                try:
                    if not bool(user32.IsWindowVisible(hwnd)):
                        return True
                    pid_value = ctypes.c_ulong(0)
                    user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid_value))
                    title_buffer = ctypes.create_unicode_buffer(512)
                    class_buffer = ctypes.create_unicode_buffer(256)
                    user32.GetWindowTextW(hwnd, title_buffer, 512)
                    user32.GetClassNameW(hwnd, class_buffer, 256)
                    row = WindowRow(int(hwnd or 0), int(pid_value.value or 0), title_buffer.value, class_buffer.value, True)
                    if row.hwnd:
                        rows[row.hwnd] = row
                except Exception:
                    recordException('start.py:dead-window-monitor-enum-callback', sys.exc_info()[1], handled=True)
                    # Do not let one weird window handle blind the monitor.
                    return True
                return True

            user32.EnumWindows(enum_proc_type(_callback), 0)
        except Exception:
            recordException('start.py:dead-window-monitor-snapshot', sys.exc_info()[1], handled=True)
        return rows

    def _isConsoleWindow(self, row: WindowRow) -> bool:  # noqa: N802
        return str(row.className or EMPTY_STRING).strip().lower() in self.CONSOLE_CLASSES

    def _isLikelyPythonWindow(self, row: WindowRow) -> bool:  # noqa: N802
        title = str(row.title or EMPTY_STRING).strip().lower()
        return self._isConsoleWindow(row) and (not title or any(token in title for token in self.PYTHON_TITLE_TOKENS))

    def _isAllowedQtWindow(self, row: WindowRow, *, launchedPid: int, policy: str) -> bool:  # noqa: N802
        if policy != WINDOW_POLICY_QT_CHILD:
            return False
        if int(launchedPid or 0) <= 0 or int(row.pid or 0) != int(launchedPid or 0):
            return False
        if self._isConsoleWindow(row):
            return False
        class_name = str(row.className or EMPTY_STRING).lower()
        # Qt class names vary between Qt versions and WebEngine surfaces.  For
        # Python GUI children, any non-console window owned by the launched PID
        # is considered intentional; console windows are still fatal.
        return bool(class_name) or any(token in class_name for token in self.ALLOWED_QT_CLASS_TOKENS)

    def unexpectedWindows(self, before: dict[int, WindowRow], *, launchedPid: int = 0, policy: str = WINDOW_POLICY_HELPER) -> list[WindowRow]:  # noqa: N802
        if os.name != 'nt' or not _windowMonitorEnabled():
            return []
        after = self.snapshot()
        unexpected: list[WindowRow] = []
        normalized_policy = _normalizeWindowPolicy(policy)
        launched_pid = int(launchedPid or 0)
        parent_map = windowsProcessParentMap() if os.name == 'nt' and launched_pid > 0 else {}
        for hwnd, row in after.items():
            if hwnd in before:
                continue
            if row.pid == self.currentPid:
                continue
            if normalized_policy == WINDOW_POLICY_ALLOW:
                continue
            # Do not punish or kill unrelated desktop/system popups that happen
            # to appear during a helper probe.  Only the launched PID tree is
            # actionable.  The previous broad diff caught HP OSD/system windows
            # and made the debugger look guilty for someone else's popup.
            if launched_pid > 0 and not windowsPidInProcessTree(int(row.pid or 0), launched_pid, parent_map):
                continue
            if self._isAllowedQtWindow(row, launchedPid=launched_pid, policy=normalized_policy):
                continue
            if normalized_policy == WINDOW_POLICY_QT_CHILD:
                if self._isLikelyPythonWindow(row):
                    unexpected.append(row)
                continue
            # Helper/probe subprocesses should not create visible windows at all.
            unexpected.append(row)
        return unexpected

    def checkAfterLaunch(self, before: dict[int, WindowRow], *, launchedPid: int = 0, command: object = None, policy: str = WINDOW_POLICY_HELPER, sourceLine: str = EMPTY_STRING, delaySeconds: float = 0.7) -> None:  # noqa: N802
        if os.name != 'nt' or not _windowMonitorEnabled():
            return
        try:
            time.sleep(max(0.05, float(delaySeconds or 0.7)))
        except Exception:
            recordException('start.py:dead-window-monitor-delay', sys.exc_info()[1], handled=True)
        unexpected = self.unexpectedWindows(before, launchedPid=int(launchedPid or 0), policy=policy)
        if not unexpected:
            print(f'[TRACE:window-monitor] OK policy={_normalizeWindowPolicy(policy, command)} pid={int(launchedPid or 0)} opener={sourceLine or "unknown"}', file=sys.stderr, flush=True)
            return
        command_text = _launcherCommandText(command)
        print(f'[ERROR:window-monitor] unexpected visible window(s) detected count={len(unexpected)} policy={_normalizeWindowPolicy(policy, command)} launchedPid={int(launchedPid or 0)}', file=sys.stderr, flush=True)
        print(f'[ERROR:window-monitor] opener={sourceLine or "unknown launcher callsite"}', file=sys.stderr, flush=True)
        print(f'[ERROR:window-monitor] command={command_text}', file=sys.stderr, flush=True)
        killed: set[int] = set()
        for row in unexpected:
            print(f'[ERROR:window-monitor] window={row.describe()}', file=sys.stderr, flush=True)
            if int(row.pid or 0) > 0 and int(row.pid or 0) not in killed and int(row.pid or 0) != os.getpid():
                killed.add(int(row.pid or 0))
                self._killPid(int(row.pid or 0), reason=f'unexpected visible window class={row.className!r} title={row.title!r}')
        if int(launchedPid or 0) > 0 and int(launchedPid or 0) not in killed and int(launchedPid or 0) != os.getpid():
            self._killPid(int(launchedPid or 0), reason='launcher command opened unexpected visible window')
        print(f'[ERROR:window-monitor] exiting launcher with code={WINDOW_MONITOR_FAIL_EXIT_CODE}; this is diagnostic fail-fast, not a janitor cleanup loop', file=sys.stderr, flush=True)
        try:
            sys.stdout.flush(); sys.stderr.flush()
        except Exception:
            recordException('start.py:dead-window-monitor-flush-before-exit', sys.exc_info()[1], handled=True)
        os._exit(WINDOW_MONITOR_FAIL_EXIT_CODE)

    def _killPid(self, pid: int, *, reason: str) -> bool:  # noqa: N802
        pid_value = int(pid or 0)
        if pid_value <= 0 or pid_value == os.getpid():
            return False
        print(f'[WARN:window-monitor] killing pid={pid_value} reason={reason}', file=sys.stderr, flush=True)
        try:
            if os.name == 'nt':
                command = ['taskkill', '/PID', str(pid_value), '/T', '/F']
                completed = _ORIGINAL_SUBPROCESS_RUN(command, capture_output=True, text=True, timeout=8, check=False, stdin=subprocess.DEVNULL)
                output = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING) + str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
                for line in output.splitlines():
                    if line.strip():
                        print(f'[TRACE:window-monitor] taskkill {line.strip()}', file=sys.stderr, flush=True)
                return int(getattr(completed, 'returncode', 1) or 0) == 0
            os.kill(pid_value, signal.SIGKILL)
            return True
        except Exception:
            recordException('start.py:window-monitor-kill-pid', sys.exc_info()[1], handled=True)
            return False


DEAD_WINDOW_MONITOR = DeadWindowMonitor()


def monitoredRawPopen(command: object, *, sourceLine: str = EMPTY_STRING, windowPolicy: object = EMPTY_STRING, windowDelaySeconds: float = 0.7, **kwargs: Any) -> Any:  # noqa: N802
    """Central raw Popen wrapper with fail-fast dead-window diagnostics."""
    policy = _normalizeWindowPolicy(windowPolicy, command)
    source = sourceLine or _callerSourceContext(skip=3)
    before = DEAD_WINDOW_MONITOR.snapshot()
    kwargs = flatlineSubprocessKwargs(command, kwargs, policy=_flatlinePolicyFromLegacy(policy, command))
    proc = _RAW_SUBPROCESS_POPEN(command, **kwargs)
    DEAD_WINDOW_MONITOR.checkAfterLaunch(before, launchedPid=int(getattr(proc, 'pid', 0) or 0), command=command, policy=policy, sourceLine=source, delaySeconds=windowDelaySeconds)
    return proc

def safeShortMd5(path: str | Path) -> str:
    try:
        return File(path).md5Hex()[:8]
    except Exception:
        recordException('start.py:532', sys.exc_info()[1])
        return EMPTY_STRING

# --- Audited: 05/01/26 FlatLine v1274 compatibility helpers ---
TRUTHY_CONFIG_VALUES = {'1', 'true', 'yes', 'y', 'on', 'enabled', 'color', 'colored', 'colour', 'coloured'}
FALSY_CONFIG_VALUES = {'0', 'false', 'no', 'n', 'off', 'disabled', 'mono', 'monochrome', 'plain'}


def _asArgSet(argv: list[str] | None = None) -> set[str]:
    return {str(arg or '').strip().lower() for arg in (argv if argv is not None else sys.argv[1:])}


def _safeInt(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        return int(default)


def _safeOptionalInt(value: Any, default: int = 0) -> int:
    if value is None:
        return int(default)
    return _safeInt(value, default)


def _stripConfigInlineComment(value: str) -> str:
    text = str(value or '')
    quote = None
    index = 0
    while index < len(text):
        ch = text[index]
        if ch in {"'", '"'}:
            quote = None if quote == ch else (ch if quote is None else quote)
        if quote is None:
            for marker in ('#', ';', '//'):
                if text.startswith(marker, index) and (index == 0 or text[index - 1].isspace()):
                    return text[:index].strip()
        index += 1
    return text.strip()


def readConfigValue(section: str, key: str, default: str = '') -> str:
    """Read a simple config.ini value without importing Qt or the full app."""
    config_path = Path(os.environ.get('TRIO_CONFIG_PATH') or os.environ.get('CUTIEPY_CONFIG_PATH') or (BASE_DIR / 'config.ini'))
    current = 'default'
    wanted_section = str(section or '').strip().lower()
    wanted_key = str(key or '').strip().lower()
    try:
        if not config_path.exists():
            return str(default)
        text = File(config_path).readText()
        text = re.sub(r'/\*.*?\*/', '', text, flags=re.S)
        text = re.sub(r'<!--.*?-->', '', text, flags=re.S)
        for raw_line in text.splitlines():
            line = _stripConfigInlineComment(raw_line).strip()
            if not line:
                continue
            if line.startswith('[') and ']' in line:
                current = line[1:line.index(']')].strip().lower() or 'default'
                continue
            if current != wanted_section:
                continue
            if '=' in line:
                name, value = line.split('=', 1)
            elif ':' in line:
                name, value = line.split(':', 1)
            else:
                continue
            if name.strip().lower() == wanted_key:
                return str(value).strip().strip('"').strip("'")
    except Exception:
        recordException('start.py:flatline-read-config-value', sys.exc_info()[1], handled=True)
    return str(default)


def configBool(section: str, key: str, default: bool = False) -> bool:
    raw = str(readConfigValue(section, key, '1' if default else '0') or '').strip().lower()
    if raw in TRUTHY_CONFIG_VALUES:
        return True
    if raw in FALSY_CONFIG_VALUES:
        return False
    return bool(default)


def configuredColoredFont() -> bool:
    argv_lower = _asArgSet()
    if '--color' in argv_lower or '-color' in argv_lower or '/color' in argv_lower:
        return True
    env_value = str(os.environ.get('TRIO_COLORED_FONT') or os.environ.get('TRIO_COLOURED_FONT') or os.environ.get('CUTIEPY_COLORED_FONT') or os.environ.get('CUTIEPY_COLOURED_FONT') or '').strip().lower()
    if env_value in TRUTHY_CONFIG_VALUES:
        return True
    if env_value in FALSY_CONFIG_VALUES:
        return False
    return configBool('fonts', 'colored_font', configBool('font', 'colored_font', False))


def fileMd5(path: str | Path) -> str:
    return safeFileMd5Hex(path)


def _consoleFontMd5(font_path: Path) -> str:
    return safeFileMd5Hex(font_path)


def _registerConsoleTrueTypeFont(face_name: str) -> None:
    """Register face_name under HKLM console TrueTypeFont slots when possible."""
    if os.name != 'nt':
        return
    tt_key = 'HKLM/SOFTWARE/Microsoft/Windows NT/CurrentVersion/Console/TrueTypeFont'
    slot = '0'
    try:
        for _ in range(16):
            existing = Registry.getKey(f'{tt_key}/{slot}', default=None)
            if existing is None:
                break
            if str(existing) == str(face_name):
                print(f'[TRACE:font-registry] TrueTypeFont slot={slot!r} already registered as {face_name!r}', flush=True)
                return
            slot += '0'
        ok = Registry.setKey(f'{tt_key}/{slot}', face_name, kind='str')
        readback = Registry.getKey(f'{tt_key}/{slot}', default='')
        if ok and str(readback) == str(face_name):
            print(f'[TRACE:font-registry] TrueTypeFont slot={slot!r} registered {face_name!r} verify=ok', flush=True)
        else:
            print(f'[WARNING:font-registry] TrueTypeFont registration failed for {face_name!r} (needs admin?)', flush=True)
    except Exception:
        recordException('start.py:flatline-register-console-font', sys.exc_info()[1], handled=True)


def _setConsoleFontRegistry(face_name: str, height: int = 14, width: int = 0, family: int = 54, weight: int = 400) -> None:
    """Persist console font settings for default console, PowerShell, and Python."""
    if os.name != 'nt':
        return
    font_size_dword = (max(int(height or 0), 0) << 16) | max(int(width or 0), 0)
    console_apps = ['Console']
    try:
        pwsh = shutil.which('pwsh') or r'C:\Program Files\PowerShell\7\pwsh.exe'
        if Path(pwsh).exists():
            console_apps.append('Console\\' + str(pwsh).replace('\\', '_').lstrip('_'))
    except Exception:
        recordException('start.py:flatline-console-pwsh-path', sys.exc_info()[1], handled=True)
    try:
        if sys.executable:
            console_apps.append('Console\\' + str(sys.executable).replace('\\', '_').lstrip('_'))
    except Exception:
        recordException('start.py:flatline-console-python-path', sys.exc_info()[1], handled=True)
    _registerConsoleTrueTypeFont(face_name)
    expected_md5 = hashlib.md5(str(face_name).encode('utf-16-le')).hexdigest()
    for subkey in console_apps:
        Registry.setKey(f'HKCU/{subkey}/FaceName', face_name, kind='str')
        Registry.setKey(f'HKCU/{subkey}/FontSize', font_size_dword, kind='dword')
        Registry.setKey(f'HKCU/{subkey}/FontFamily', family, kind='dword')
        Registry.setKey(f'HKCU/{subkey}/FontWeight', weight, kind='dword')
        readback = Registry.getKey(f'HKCU/{subkey}/FaceName', default='')
        readback_md5 = hashlib.md5(str(readback or '').encode('utf-16-le')).hexdigest()
        if readback_md5 == expected_md5:
            print(f'[TRACE:font-registry] {subkey} FaceName={face_name!r} FontSize=0x{font_size_dword:08X} verify=ok', flush=True)
        else:
            print(f'[WARNING:font-registry] {subkey} FaceName verify failed: wrote={face_name!r} read={readback!r} md5_expected={expected_md5} md5_got={readback_md5}', flush=True)


def _installAndSetConsoleFont(source_path: Path, face_name: str) -> None:
    """Install a bundled font and apply it to the current Windows console."""
    if os.name != 'nt':
        return
    font = Font(Path(source_path))
    if not font.installForCurrentUser(face_name):
        raise RuntimeError(f'[font-install] could not install {source_path}')
    try:
        applyRecommendedConsoleFont(face_name)
    except Exception:
        recordException('start.py:flatline-apply-console-font', sys.exc_info()[1], handled=True)
    try:
        _setConsoleFontRegistry(face_name, RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT, 0, 54, 400)
    except Exception:
        recordException('start.py:flatline-set-console-font-registry', sys.exc_info()[1], handled=True)


def _printStartupBanner() -> None:
    """Compatibility hook from the v1274 FlatLine bootstrap."""
    bootstrapBanner(list(sys.argv[1:]))
