class StartWorkerProcess:
    """Lightweight launcher process wrapper for start.py."""

    def __init__(self, target, name: str = EMPTY_STRING, daemon: bool = True):
        self._target = target
        self.name = str(name or 'StartWorkerProcess')
        self.daemon = bool(daemon)
        self._workerHandle: Any | None = None
        self._startTime: float | None = None
        self._result: object | None = None
        self._error: BaseException | None = None
        self.tracebackText = EMPTY_STRING

    @property
    def runtime(self) -> float | None:
        if self._startTime is None:
            return None
        return max(0.0, time.monotonic() - self._startTime)

    def is_alive(self) -> bool:
        try:
            return bool(self._workerHandle is not None and self._workerHandle.is_alive())
        except Exception:
            recordException('start.py:559', sys.exc_info()[1])
            return False

    def start(self):
        if self.is_alive():
            return self
        lifecycle = currentStartLifecycle()
        if lifecycle is not None and not bool(getattr(self, '_phaseStartInProgress', False)) and hasattr(lifecycle, 'startExistingWorkerProcessPhase'):
            return lifecycle.startExistingWorkerProcessPhase(self)
        self._startTime = time.monotonic()
        self._error = RuntimeError('StartWorkerProcess cannot execute arbitrary Python callables on Windows spawn; use StartProcess with an explicit --worker role instead.')
        self.tracebackText = ''.join(traceback.format_stack(limit=8))
        try:
            sys.stderr.write(f'[WARN:start-worker] {self.name} was not started: callback workers are disabled; use an explicit subprocess worker role.\n')
            sys.stderr.flush()
        except Exception:
            recordException('start.py:574', sys.exc_info()[1])
            _traceSwallowedException('start.py:543', sys.exc_info()[1])
            pass
