class BootStrappedApp:
    """Logical representation of the app process bootstrapped by FlatLine.

    The debugger process is the bootstrapper. TrioDesktop itself is the
    bootstrapped app: the child process launched from start.py, usually trio.py.
    Keeping this as a first-class object prevents shutdown code from guessing
    which Popen/StartProcess is the actual app, and gives every close/fault path
    one place to flush logs, taskkill the child PID, and warn if it survived.
    """

    def __init__(self, debugger=None, name: str = 'TrioDesktop'):
        self.debugger = debugger
        self.name = str(name or 'TrioDesktop')
        self.process = None
        self.pid = 0
        self.command: list[str] = []
        self.startedAt = 0.0
        self.endedAt = 0.0
        self.killAttempts = 0
        self.lastKillReason = EMPTY_STRING

    def attach(self, process=None, *, pid: int = 0, command: list[str] | tuple[str, ...] | None = None):
        self.process = process
        try:
            self.pid = int(pid or getattr(process, 'pid', 0) or getattr(getattr(process, 'proc', None), 'pid', 0) or 0)
        except Exception:
            recordException('start.py:bootstrapped-app-attach-pid', sys.exc_info()[1], handled=True)
            self.pid = 0
        self.command = [str(part) for part in list(command or getattr(process, 'command', []) or [])]
        self.startedAt = time.time()
        self.endedAt = 0.0
        return self

    def markExited(self) -> None:
        self.endedAt = time.time()
        self.process = None
        self.pid = 0

    def isRunning(self) -> bool:  # noqa: N802
        proc = self.process
        try:
            if proc is not None and hasattr(proc, 'poll') and proc.poll() is None:
                return True
        except Exception:
            recordException('start.py:bootstrapped-app-poll', sys.exc_info()[1], handled=True)
        return bool(self.pid and Tasks.processExists(self.pid))

    def emit(self, text: str) -> None:
        owner = self.debugger
        try:
            if owner is not None and hasattr(owner, 'emit'):
                owner.emit(str(text or EMPTY_STRING), getattr(owner, 'exceptionPath', None))
            else:
                print(str(text or EMPTY_STRING), file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:bootstrapped-app-emit', sys.exc_info()[1], handled=True)
            print(str(text or EMPTY_STRING), file=sys.stderr, flush=True)

    def kill(self, reason: str = 'BootStrappedApp.kill', *, force: bool = True, tree: bool = True, timeout: float = 12.0, verify: bool = True) -> bool:
        """Flush runtime logs, taskkill the bootstrapped app PID, and verify it died."""
        try:
            RuntimeLog.flushAllLogs()
        except Exception:
            RuntimeLog.flush(final=True)
        try:
            pid_value = int(self.pid or getattr(self.process, 'pid', 0) or getattr(getattr(self.process, 'proc', None), 'pid', 0) or 0)
        except Exception:
            recordException('start.py:bootstrapped-app-kill-pid', sys.exc_info()[1], handled=True)
            pid_value = 0
        if pid_value <= 0:
            return True
        self.killAttempts += 1
        self.lastKillReason = str(reason or 'BootStrappedApp.kill')
        ok = True
        if Tasks.processExists(pid_value):
            ok = Tasks.taskkill(pid_value, tree=bool(tree), force=bool(force), reason=self.lastKillReason, timeout=float(timeout or 12.0), trace_prefix='bootstrapped-app-taskkill')
        if verify:
            time.sleep(0.20)
            proc = self.process
            try:
                still_running = bool(proc is not None and hasattr(proc, 'poll') and proc.poll() is None)
            except Exception:
                recordException('start.py:bootstrapped-app-verify-poll', sys.exc_info()[1], handled=True)
                still_running = False
            if not still_running and proc is None:
                still_running = Tasks.processExists(pid_value)
            if still_running:
                ok = False
                self.emit(f'[WARN:bootstrapped-app] {self.name} pid={pid_value} still running after taskkill reason={self.lastKillReason}')
            else:
                self.markExited()
        try:
            RuntimeLog.flushAllLogs()
        except Exception:
            RuntimeLog.flush(final=True)
        return bool(ok)

    def __del__(self) -> None:
        try:
            RuntimeLog.flushAllLogs()
            if self.isRunning():
                self.kill(reason='BootStrappedApp.__del__', force=True, tree=True, verify=True)
        except Exception:
            pass


class LauncherCompletedProcess(subprocess.CompletedProcess):
    pass

def launcherStartProcess(command, **kwargs) -> Any:
    process = StartProcess(command, ttlSeconds=float(kwargs.pop('ttlSeconds', 0.0) or 0.0), **kwargs)
    started = process.start()
    pid = int(getattr(started, 'pid', getattr(process, 'pid', 0)) or 0)
    print(f'[TRACE:start-process] launcherStartProcess pid={pid}', file=sys.stderr, flush=True)
    return started.proc

def launcherRunCommand(command, *args, **kwargs) -> Any:
    if args:
        raise TypeError('launcherRunCommand only supports keyword options after command')
    capture_output = bool(kwargs.pop('capture_output', False))
    check = bool(kwargs.pop('check', False))
    timeout = kwargs.pop('timeout', None)
    input_value = kwargs.pop('input', None)
    window_policy = kwargs.pop('windowPolicy', kwargs.pop('window_policy', WINDOW_POLICY_HELPER))
    window_delay_seconds = float(kwargs.pop('windowDelaySeconds', kwargs.pop('window_delay_seconds', 0.7)) or 0.7)
    source_line = str(kwargs.pop('sourceLine', kwargs.pop('source_line', EMPTY_STRING)) or EMPTY_STRING) or _callerSourceContext(skip=3)
    if timeout is None:
        # Small launcher helper probes (xprop/xwininfo/xdpyinfo/etc.) must never
        # block the debugger. Long dependency installs use StartDependencyRegistry.
        timeout = 10.0
    if capture_output:
        kwargs.setdefault('stdout', subprocess.PIPE)
        kwargs.setdefault('stderr', subprocess.PIPE)
    try:
        proc = monitoredRawPopen(command, sourceLine=source_line, windowPolicy=window_policy, windowDelaySeconds=window_delay_seconds, **kwargs)
        try:
            stdout, stderr = proc.communicate(input=input_value, timeout=timeout)
            returncode = int(proc.returncode or 0)
        except subprocess.TimeoutExpired as timeout_error:
            try:
                proc.kill()
            except Exception:
                recordException('start.py:launcher-run-command-timeout-kill', sys.exc_info()[1])
            try:
                stdout, stderr = proc.communicate(timeout=2.0)
            except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
                stdout = getattr(timeout_error, 'stdout', None)
                stderr = getattr(timeout_error, 'stderr', None)
            returncode = int(proc.returncode or -9)
            if check:
                raise subprocess.CalledProcessError(returncode, command, output=stdout, stderr=stderr)
        completed = LauncherCompletedProcess(command, returncode, stdout, stderr)
        if check and int(completed.returncode or 0) != 0:
            raise subprocess.CalledProcessError(completed.returncode, command, output=stdout, stderr=stderr)
        return completed
    except subprocess.CalledProcessError:
        raise
    except Exception as error:
        recordException('start.py:launcher-run-command', sys.exc_info()[1])
        if check:
            raise
        return LauncherCompletedProcess(command, 1, EMPTY_STRING, f'{type(error).__name__}: {error}')


class OperatingSystem:
    Terminal: type[Any]
    PowerShell: type[Any]
    '''Small detected OS value object used by launcher tasks and dependencies.

    Keep this intentionally small and reusable. start.py ships with Comport,
    so process cleanup and dependency install logic should ask this object for
    platform facts instead of scattering os.name/platform checks everywhere.
    '''

    def __init__(self, *, osName: str, osFamily: str, version: str, architecture: str, archBits: int):
        self.osName = str(osName or 'unknown')
        self.osFamily = str(osFamily or 'unknown')
        self.version = str(version or '')
        self.architecture = str(architecture or '')
        self.archBits = int(archBits or 0)
        self.isWindows = self.osFamily == 'windows'
        self.isLinux = self.osFamily == 'linux'
        self.isMac = self.osFamily == 'mac'

    @classmethod
    def detect(cls) -> 'OperatingSystem':
        name = str(platform.system() or EMPTY_STRING).strip() or 'unknown'
        lower = name.lower()
        if lower.startswith('win'):
            family = 'windows'
        elif lower.startswith('linux'):
            family = 'linux'
        elif lower.startswith('darwin') or lower.startswith('mac'):
            family = 'mac'
        else:
            family = lower or 'unknown'
        arch = str(platform.machine() or platform.architecture()[0] or EMPTY_STRING).strip()
        arch_lower = arch.lower()
        bits = 64 if ('64' in arch_lower or 'amd64' in arch_lower or 'x86_64' in arch_lower or 'aarch64' in arch_lower) else 86
        try:
            version = str(platform.version() or platform.release() or EMPTY_STRING)
        except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
            version = EMPTY_STRING
        detected = cls(osName=name, osFamily=family, version=version, architecture=arch, archBits=bits)
        print(f'[TRACE:operating-system] detected os={detected.osFamily} name={detected.osName} version={detected.version} arch={detected.architecture} bits={detected.archBits}', file=sys.stderr, flush=True)
        return detected

    def processRows(self, *, timeout: float = 20.0) -> list[dict[str, Any]]:
        '''Return running processes with pid/name/command line on Windows or Linux.'''
        rows: list[dict[str, Any]] = []
        if self.isWindows:
            powershell = shutil.which('pwsh') or shutil.which('powershell') or 'powershell'
            script = (
                "$ErrorActionPreference = 'SilentlyContinue'\n"
                "$CommandLines = @{}\n"
                "Get-CimInstance Win32_Process | ForEach-Object { $CommandLines[[int]$_.ProcessId] = [string]$_.CommandLine }\n"
                "Get-Process | ForEach-Object {\n"
                "  $pidValue = [int]$_.Id\n"
                "  $cmd = [string]$CommandLines[$pidValue]\n"
                "  [pscustomobject]@{ ProcessId = $pidValue; Name = [string]$_.ProcessName; CommandLine = $cmd }\n"
                "} | ConvertTo-Json -Compress -Depth 4\n"
            )
            completed = launcherRunCommand([powershell, '-NoLogo', '-NoProfile', '-Command', script], capture_output=True, text=True, timeout=timeout, check=False)
            raw = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING).strip()
            if raw:
                try:
                    data = json.loads(raw)
                    if isinstance(data, dict):
                        data = [data]
                    for row in data if isinstance(data, list) else []:
                        if not isinstance(row, dict):
                            continue
                        pid = int(row.get('ProcessId') or 0)
                        if pid <= 0:
                            continue
                        rows.append({'ProcessId': pid, 'Name': str(row.get('Name') or EMPTY_STRING), 'CommandLine': str(row.get('CommandLine') or EMPTY_STRING)})
                except Exception:
                    recordException('start.py:operating-system-windows-process-parse', sys.exc_info()[1], handled=True)
            print(f'[TRACE:operating-system] Get-Process rows={len(rows)}', file=sys.stderr, flush=True)
            return rows

        if self.isLinux or self.isMac:
            ps_command = ['ps', '-eo', 'pid=,comm=,args=']
            completed = launcherRunCommand(ps_command, capture_output=True, text=True, timeout=timeout, check=False)
            raw = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING)
            for line in raw.splitlines():
                parts = line.strip().split(None, 2)
                if len(parts) < 2:
                    continue
                try:
                    pid = int(parts[0])
                except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
                    continue
                name = parts[1]
                command_line = parts[2] if len(parts) > 2 else name
                rows.append({'ProcessId': pid, 'Name': name, 'CommandLine': command_line})
            print(f'[TRACE:operating-system] ps -eo rows={len(rows)}', file=sys.stderr, flush=True)
            return rows

        print(f'[WARN:operating-system] process listing unsupported os={self.osFamily}', file=sys.stderr, flush=True)
        return []

    def listProcesses(self, *, timeout: float = 20.0) -> list[dict[str, Any]]:
        '''Comport canonical alias for process inventory on every supported OS.

        Windows uses Get-Process plus Win32_Process.CommandLine enrichment inside
        processRows(); Linux/macOS use ps -eo pid=,comm=,args=.
        '''
        return self.processRows(timeout=timeout)

    def powershellCandidates(self) -> list[str]:
        '''Return PowerShell executables in preferred order for Windows helpers.'''
        candidates = [str(item) for item in (shutil.which('pwsh'), shutil.which('powershell'), 'pwsh', 'powershell') if item]
        seen: set[str] = set()
        ordered: list[str] = []
        for item in candidates:
            key = item.lower()
            if key not in seen:
                seen.add(key)
                ordered.append(item)
        return ordered

    def terminalCandidates(self) -> list[str]:
        '''Return terminal helper names/paths in preferred order for this OS.'''
        if self.isWindows:
            candidates = [shutil.which('wt'), shutil.which('WindowsTerminal'), shutil.which('cmd'), 'wt', 'cmd']
        else:
            candidates = [shutil.which('x-terminal-emulator'), shutil.which('gnome-terminal'), shutil.which('konsole'), shutil.which('xterm'), 'x-terminal-emulator', 'xterm']
        out: list[str] = []
        seen: set[str] = set()
        for item in candidates:
            if not item:
                continue
            text = str(item)
            key = text.lower()
            if key in seen:
                continue
            seen.add(key)
            out.append(text)
        return out

    def installSystemPackages(self, packages: list[str] | tuple[str, ...], *, reason: str = EMPTY_STRING) -> bool:
        '''Trace-only OS package install surface.

        The existing StartDependencyRegistry owns the concrete apt/winget/pip
        fallback details; this method is the small OS contract Comport can check
        so new launchers do not scatter package-manager calls.
        '''
        names = [str(item).strip() for item in list(packages or ()) if str(item).strip()]
        print(f'[TRACE:OperatingSystem:install] installSystemPackages os={self.osFamily} packages={names} reason={reason}', file=sys.stderr, flush=True)
        if not names:
            return True
        print(f'[WARN:OperatingSystem:install] package-manager install delegated to StartDependencyRegistry for packages={names}', file=sys.stderr, flush=True)
        return False

    def installDependency(self, dependency: Any, registry: Any = None) -> bool:
        '''Install one dependency through the OS-aware dependency contract.'''
        name = getattr(dependency, 'name', dependency)
        print(f'[TRACE:OperatingSystem:install] installDependency os={self.osFamily} dependency={name}', file=sys.stderr, flush=True)
        try:
            if hasattr(dependency, 'install'):
                return bool(dependency.install(registry))
            if registry is not None and hasattr(registry, '_installMissingDependenciesWithOperatingSystem'):
                return bool(registry._installMissingDependenciesWithOperatingSystem())
        except Exception as error:
            recordException('start.py:operating-system-install-dependency', sys.exc_info()[1], handled=True)
            print(f'[WARN:OperatingSystem:install] installDependency failed dependency={name}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return False
        print(f'[WARN:OperatingSystem:install] no install route for dependency={name}', file=sys.stderr, flush=True)
        return False

    def findProcessesByCommandLineNeedles(self, root: Path | str, matches: tuple[str, ...], *, excludePid: int | None = None) -> list[dict[str, Any]]:
        root_path = Path(root or BASE_DIR).resolve()
        root_forward = str(root_path).replace('\\', '/').rstrip('/')
        needles = [str(item or EMPTY_STRING).replace('\\', '/').strip('/') for item in list(matches or ()) if str(item or EMPTY_STRING).strip()]
        if not needles:
            return []
        current_pid = int(excludePid or os.getpid())
        found: list[dict[str, Any]] = []
        for row in self.listProcesses():
            try:
                pid = int(row.get('ProcessId') or 0)
            except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
                pid = 0
            if pid <= 0 or pid == current_pid:
                continue
            command_line = str(row.get('CommandLine') or EMPTY_STRING)
            normalized = command_line.replace('\\', '/')
            lowered_command = normalized.lower()
            if any(worker_token in lowered_command for worker_token in (
                '--model-catalog-worker', '--shell-rpc-worker', '--dependency-worker',
                '--startup-tools-worker', '--font-worker', '--chat-test-worker',
            )):
                continue
            for needle in needles:
                full_needle = f'{root_forward}/{needle}'
                if full_needle.lower() in normalized.lower():
                    found.append(row)
                    break
        print(f'[TRACE:operating-system] command-line process match root={root_forward} matches={len(found)}', file=sys.stderr, flush=True)
        return found

    def installDependencies(self, registry: Any) -> None:
        '''Delegate dependency installation through the detected OS contract.'''
        print(f'[TRACE:operating-system] installDependencies os={self.osFamily} arch={self.archBits}', file=sys.stderr, flush=True)
        try:
            return registry._installMissingDependenciesWithOperatingSystem()
        except Exception as error:
            recordException('start.py:operating-system-install-dependencies', sys.exc_info()[1], handled=True)
            print(f'[WARN:operating-system] dependency install failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            raise


class Tasks:
    '''Small task/process utility surface shared by launcher phases.

    Keep process-tree termination here so auto-runners, phase workers, child
    cleanup, and debugger code do not scatter raw taskkill/PID logic.  This is
    intentionally tiny: a reusable, audited utility object, not a controller.
    '''

    @staticmethod
    def taskkill(pid: int | str, *, tree: bool = True, force: bool = True, reason: str = EMPTY_STRING, timeout: float = 8.0, trace_prefix: str = 'tasks-taskkill', allowSelf: bool = False) -> bool:
        try:
            pid_value = int(pid or 0)
        except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
            pid_value = 0
        if pid_value <= 0:
            print(f'[WARN:{trace_prefix}] invalid pid={pid!r} reason={reason}', file=sys.stderr, flush=True)
            return False
        if pid_value == os.getpid() and not bool(allowSelf):
            print(f'[WARN:{trace_prefix}] refusing to kill current debugger pid={pid_value} reason={reason}', file=sys.stderr, flush=True)
            return False
        print(f'[TRACE:{trace_prefix}] stopping process tree pid={pid_value} tree={tree} force={force} reason={reason}', file=sys.stderr, flush=True)
        try:
            if os.name == 'nt':
                command = ['taskkill', '/PID', str(pid_value)]
                if tree:
                    command.append('/T')
                if force:
                    command.append('/F')
                completed = launcherRunCommand(command, capture_output=True, text=True, timeout=max(1.0, float(timeout or 8.0)), check=False)
                output = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING) + str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
                for line in output.splitlines():
                    if line.strip():
                        print(f'[TRACE:{trace_prefix}] taskkill {line.strip()}', file=sys.stderr, flush=True)
                ok = int(getattr(completed, 'returncode', 1) or 0) == 0
                print(f'[TRACE:{trace_prefix}] result ok={ok} returncode={getattr(completed, "returncode", None)} pid={pid_value}', file=sys.stderr, flush=True)
                return ok
            try:
                if tree:
                    os.killpg(os.getpgid(pid_value), signal.SIGKILL if force else signal.SIGTERM)
                else:
                    os.kill(pid_value, signal.SIGKILL if force else signal.SIGTERM)
                print(f'[TRACE:{trace_prefix}] POSIX kill ok pid={pid_value}', file=sys.stderr, flush=True)
                return True
            except ProcessLookupError:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
                print(f'[TRACE:{trace_prefix}] process already gone pid={pid_value}', file=sys.stderr, flush=True)
                return True
        except Exception as error:
            recordException(f'start.py:{trace_prefix}', sys.exc_info()[1], handled=True)
            print(f'[WARN:{trace_prefix}] failed pid={pid_value}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return False

    @staticmethod
    def processExists(pid: int | str) -> bool:  # noqa: N802
        try:
            pid_value = int(pid or 0)
        except Exception:  # swallow-ok: PID probes must be safe during shutdown
            pid_value = 0
        if pid_value <= 0:
            return False
        try:
            if os.name == 'nt':
                completed = launcherRunCommand(['tasklist', '/FI', f'PID eq {pid_value}'], capture_output=True, text=True, timeout=10, check=False)
                haystack = '\n'.join([str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING), str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)])
                return str(pid_value) in haystack
            os.kill(pid_value, 0)
            return True
        except ProcessLookupError:
            return False
        except PermissionError:
            return True
        except Exception as error:
            recordException('start.py:tasks-process-exists', sys.exc_info()[1], handled=True)
            print(f'[WARN:tasks-process-exists] pid={pid_value}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return False


STALE_CLIENT_PROCESS_MATCHES = (
    'start.py', 'trio.py', 'cutie.py', 'main.py', 'gtp.py',
    'client/start.py', 'client/main.py', 'client/trio.py', 'client/cutie.py',
    'FLOPT_ping_responder.py', 'client/FLOPT_ping_responder.py',
)
NO_STALE_CLIENT_KILL_FLAGS = {'no-stale-client-kill', '--no-stale-client-kill', '/no-stale-client-kill', '-no-stale-client-kill', 'no-stale-kill', '--no-stale-kill', '/no-stale-kill', '-no-stale-kill', 'no-taskkill-stale', '--no-taskkill-stale', '/no-taskkill-stale', '-no-taskkill-stale', 'keep-stale-client', '--keep-stale-client', '/keep-stale-client', '-keep-stale-client'}


def _staleClientKillDisabled(argv: list[str] | tuple[str, ...] | None = None) -> bool:
    '''Explicit stale-process cleanup bypass used by Comport and special debug sessions.'''
    try:
        if cliHasAnyFlag(list(argv or sys.argv[1:]), NO_STALE_CLIENT_KILL_FLAGS):
            return True
        env_value = str(os.environ.get('TRIO_NO_STALE_CLIENT_KILL', EMPTY_STRING) or EMPTY_STRING).strip().lower()
        return env_value in {'1', 'true', 'yes', 'on'}
    except Exception:
        recordException('start.py:stale-client-kill-disabled', sys.exc_info()[1], handled=True)
        return False


def findStaleClientProcesses(root: Path | str | None = None, *, matches: tuple[str, ...] = STALE_CLIENT_PROCESS_MATCHES) -> list[dict[str, Any]]:
    """Return stale project-owned Python/app processes by command line on Windows or Linux."""
    try:
        os_info = OperatingSystem.detect()
        return os_info.findProcessesByCommandLineNeedles(root or BASE_DIR, matches, excludePid=os.getpid())
    except Exception:
        recordException('start.py:findStaleClientProcesses', sys.exc_info()[1], handled=True)
        return []


def killStaleClientProcesses(root: Path | str | None = None, *, reason: str = 'before child launch') -> int:
    rows = findStaleClientProcesses(root or BASE_DIR)
    if not rows:
        print('[TRACE:STALE-CLIENT] NONE', file=sys.stderr, flush=True)
        return 0
    killed = 0
    for row in rows:
        pid = int(row.get('ProcessId') or 0)
        name = str(row.get('Name') or EMPTY_STRING)
        command = str(row.get('CommandLine') or EMPTY_STRING)
        print(f'[TRACE:STALE-CLIENT] FOUND pid={pid} name={name} command={command}', file=sys.stderr, flush=True)
        if Tasks.taskkill(pid, reason=f'stale-client cleanup: {reason}', trace_prefix='stale-client-taskkill'):
            killed += 1
    print(f'[TRACE:STALE-CLIENT] SUMMARY found={len(rows)} killed={killed}', file=sys.stderr, flush=True)
    if killed:
        time.sleep(0.15)
    return killed

def launcherOsSystem(command) -> int:
    command_text = str(command or EMPTY_STRING).strip()
    if not command_text: return 0
    if command_text.lower() in {'cls', 'clear'}:
        print('\033[2J\033[H', end=EMPTY_STRING, flush=True); return 0
    return int(getattr(launcherRunCommand(command_text, shell=True), 'returncode', 1) or 0)


def _optionalModuleImport(module_name: str):
    module_text = str(module_name or EMPTY_STRING).strip()
    if not module_text:
        return None, 'empty module name'
    try:
        return importlib.import_module(module_text), EMPTY_STRING
    except Exception as error:
        recordException('start.py:1018', sys.exc_info()[1])
        detail = f'{type(error).__name__}: {error}'
        OPTIONAL_IMPORT_WARNINGS.append(f'{module_text} import failed: {detail}')
        return None, detail

def refreshEmbeddedBindings(force_reload: bool = False, *, warn_prefix: str = 'deps-refresh') -> bool:
    try:
        importlib.invalidate_caches()
        module_name = 'data'
        module = sys.modules.get(module_name)
        if force_reload and module is not None:
            sys.modules.pop(module_name, None)
            module = None
        if module is None:
            module = importlib.import_module(module_name)
        elif force_reload:
            module = importlib.reload(module)  # nopatch
        module_globals = globals()
        for name in TRIO_EMBEDDED_BINDING_NAMES:
            if hasattr(module, name):
                module_globals.update({name: getattr(module, name)})
        return True
    except Exception as error:
        recordException('start.py:1040', sys.exc_info()[1])
        print(f'[WARN:{warn_prefix}] Failed to refresh data bindings: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        return False


