def childPidFilePath() -> Path:
    return Path(str(os.environ.get('TRIO_CHILD_PID_FILE', EMPTY_STRING) or (LOG_DIR / 'child.pid'))).resolve()


def writeChildPidFile(pid: int | str, *, reason: str = EMPTY_STRING) -> bool:
    try:
        pid_value = int(pid or 0)
        if pid_value <= 0:
            return False
        target = childPidFilePath()
        target.parent.mkdir(parents=True, exist_ok=True)
        File(target).writeText(str(pid_value), encoding='utf-8')
        print(f'[TRACE:child-pid] wrote pid={pid_value} path={target} reason={reason}', file=sys.stderr, flush=True)
        return True
    except Exception:
        recordException('start.py:write-child-pid-file', sys.exc_info()[1])
        return False


def killChildPidFileProcess(*, reason: str = EMPTY_STRING) -> bool:
    try:
        target = childPidFilePath()
        if not target.exists():
            return False
        raw = File(target).readText(encoding='utf-8', errors='replace').strip()
        try:
            pid_value = int(raw or 0)
        except Exception:
            pid_value = 0
        try:
            target.unlink(missing_ok=True)
        except Exception:
            recordException('start.py:child-pid-file-unlink', sys.exc_info()[1])
        if pid_value <= 0:
            print(f'[WARN:child-pid] invalid stale child pid file value={raw!r}', file=sys.stderr, flush=True)
            return False
        ok = Tasks.taskkill(pid_value, tree=True, force=True, reason=reason or 'stale child pid file', timeout=5.0, trace_prefix='stale-child-pid')
        time.sleep(0.15)
        if Tasks.processExists(pid_value):
            print(f'[WARN:child-pid] stale child pid still alive pid={pid_value}', file=sys.stderr, flush=True)
        return bool(ok)
    except Exception:
        recordException('start.py:kill-child-pid-file-process', sys.exc_info()[1])
        return False

