# CWV v284: manual-debug banner + debugger surface persistence repair.
STATUS_FAILED = 0
STATUS_SUCCESS = 1
STATUS_SUCESS_200 = 200
STATUS_SUCCESS_200 = STATUS_SUCESS_200
FAILED = 'FAILED!'
SUCCESS = 'SUCCESS!'
STATUS_TEXT_FAILED = FAILED
STATUS_TEXT_SUCCESS = SUCCESS
STATUS_SUCCESS_CSS_COLOR = '#1F1'
STATUS_FAILED_CSS_COLOR = '#F11'
STATUS_COLOR_RESET = '\x1b[0m'
STATUS_COLOR_BLUE = '\x1b[1;96m'

def _statusHexToRgb(value: str) -> tuple[int, int, int]:
    text = str(value or EMPTY_STRING).strip().lstrip('#')
    if len(text) == 3:
        text = ''.join(ch * 2 for ch in text)
    if len(text) != 6:
        return (255, 255, 255)
    if any(ch not in '0123456789abcdefABCDEF' for ch in text):
        return (255, 255, 255)
    return (int(text[0:2], 16), int(text[2:4], 16), int(text[4:6], 16))

def _statusAnsiColor(cssColor: str) -> str:
    red, green, blue = _statusHexToRgb(cssColor)
    return f'\x1b[1;38;2;{red};{green};{blue}m'

STATUS_COLOR_SUCCESS = _statusAnsiColor(STATUS_SUCCESS_CSS_COLOR)
STATUS_COLOR_FAILED = _statusAnsiColor(STATUS_FAILED_CSS_COLOR)
# Backward-compatible names used by older helper code.  They intentionally route
# through the unified status renderer colors instead of hard-coded ANSI colors.
STATUS_COLOR_GREEN = STATUS_COLOR_SUCCESS
STATUS_COLOR_RED = STATUS_COLOR_FAILED

def _statusIsSuccess(status) -> bool:
    if isinstance(status, str):
        lowered = str(status or EMPTY_STRING).strip().lower()
        if lowered in {'success', 'success!', 'ok', 'true', 'passed', 'pass'}:
            return True
        if lowered in {'failed', 'failed!', 'fail', 'false', 'error', 'errored'}:
            return False
        if lowered.isdigit():
            code = int(lowered)
            return (code == STATUS_SUCCESS) or (200 <= code < 300)
        return False
    if isinstance(status, bool):
        return bool(status)
    if isinstance(status, int):
        return (status == STATUS_SUCCESS) or (200 <= status < 300)
    if isinstance(status, float) and status.is_integer():
        code = int(status)
        return (code == STATUS_SUCCESS) or (200 <= code < 300)
    return False

def renderStatusMessage(status, *, mode: str = 'ansi') -> str:
    """Unified success/failure renderer for launcher output.

    Success and failure tokens are generated here only.  Terminal mode uses
    bold true-color ANSI, HTML mode uses bold CSS spans, and plain mode returns
    the raw token for logs/parsers.
    """
    if isinstance(status, str):
        lowered = str(status or EMPTY_STRING).strip().lower()
        if lowered not in {'success', 'success!', 'ok', 'true', 'passed', 'pass', 'failed', 'failed!', 'fail', 'false', 'error', 'errored'}:
            return str(status or EMPTY_STRING)
    ok = _statusIsSuccess(status)
    token = SUCCESS if ok else FAILED
    css = STATUS_SUCCESS_CSS_COLOR if ok else STATUS_FAILED_CSS_COLOR
    if str(mode or 'ansi').lower() in {'html', 'css'}:
        return f'<strong style="color:{css};font-weight:800">{html.escape(token)}</strong>'
    if str(mode or 'ansi').lower() in {'plain', 'text', 'raw'}:
        return token
    return (_statusAnsiColor(css) + token + STATUS_COLOR_RESET)

def printStatus(status, message: str = EMPTY_STRING, *, end: str = '\n', file=None) -> str:
    """Print a normalized debugger status token from the shared renderer."""
    try:
        rendered = renderStatusMessage(status, mode='ansi')
        suffix = str(message or EMPTY_STRING)
        text = rendered + ((' ' + suffix) if suffix else EMPTY_STRING)
        print(text, end=end, file=(file if file is not None else sys.stdout), flush=True)
        return rendered
    except Exception:
        recordException('start.py:printStatus', sys.exc_info()[1])
        fallback = str(status or EMPTY_STRING)
        print(fallback, end=end, file=(file if file is not None else sys.stdout), flush=True)
        return fallback

def statusText(status) -> str:
    return renderStatusMessage(status, mode='plain')

def coloredStatusText(status) -> str:
    return renderStatusMessage(status, mode='ansi')

def htmlStatusText(status) -> str:
    return renderStatusMessage(status, mode='html')
