class Dependency:
    """Single dependency contract: check modules, install packages, then re-check modules."""
    def __init__(self, name: str, displayName: str = EMPTY_STRING, modules=(), pipPackages=(), aptPackages=(), pacmanPackages=(), wingetIds=(), guiOnly: bool = False):
        self.name = str(name or EMPTY_STRING).strip()
        self.displayName = str(displayName or self.name or 'dependency').strip()
        self.modules = tuple(str(item or EMPTY_STRING).strip() for item in list(modules or []) if str(item or EMPTY_STRING).strip())
        self.pipPackages = tuple(str(item or EMPTY_STRING).strip() for item in list(pipPackages or []) if str(item or EMPTY_STRING).strip())
        self.aptPackages = tuple(str(item or EMPTY_STRING).strip() for item in list(aptPackages or []) if str(item or EMPTY_STRING).strip())
        self.pacmanPackages = tuple(str(item or EMPTY_STRING).strip() for item in list(pacmanPackages or []) if str(item or EMPTY_STRING).strip())
        self.wingetIds = tuple(str(item or EMPTY_STRING).strip() for item in list(wingetIds or []) if str(item or EMPTY_STRING).strip())
        self.guiOnly = bool(guiOnly)

    @staticmethod
    def _unique(values) -> tuple[str, ...]:
        seen: set[str] = set()
        out: list[str] = []
        for value in list(values or []):
            text = str(value or EMPTY_STRING).strip()
            key = text.lower()
            if text and key not in seen:
                seen.add(key)
                out.append(text)
        return tuple(out)

    @classmethod
    def fromRows(cls, name: str, rows: list[dict[str, Any]]):
        row_list = [dict(row or {}) for row in list(rows or [])]
        modules = cls._unique(row.get('import_name', EMPTY_STRING) for row in row_list)
        pipPackages = cls._unique(row.get('pip_package', EMPTY_STRING) for row in row_list)
        aptPackages = cls._unique(row.get('apt_package', EMPTY_STRING) for row in row_list)
        pacmanPackages = cls._unique(row.get('pacman_package', EMPTY_STRING) for row in row_list)
        wingetIds = cls._unique(row.get('winget_id', EMPTY_STRING) for row in row_list)
        display = str((row_list[0] if row_list else {}).get('display_name', name) or name)
        guiOnly = all(bool(row.get('gui_only')) for row in row_list) if row_list else False
        return cls(name=name, displayName=display, modules=modules, pipPackages=pipPackages, aptPackages=aptPackages, pacmanPackages=pacmanPackages, wingetIds=wingetIds, guiOnly=guiOnly)

    def toEntries(self) -> list[dict[str, Any]]:
        primary_pip = self.pipPackages[0] if self.pipPackages else EMPTY_STRING
        primary_apt = self.aptPackages[0] if self.aptPackages else EMPTY_STRING
        primary_pacman = self.pacmanPackages[0] if self.pacmanPackages else EMPTY_STRING
        primary_winget = self.wingetIds[0] if self.wingetIds else EMPTY_STRING
        return [
            {
                'dependency_name': self.name,
                'display_name': self.displayName,
                'import_name': module,
                'pip_package': primary_pip,
                'apt_package': primary_apt,
                'pacman_package': primary_pacman,
                'winget_id': primary_winget,
                'gui_only': self.guiOnly,
            }
            for module in self.modules
        ]

    def check(self, registry) -> bool:
        return all(bool(registry.moduleAvailableInTargetPython(module)) for module in self.modules)

    def missingModules(self, registry) -> list[str]:
        return [module for module in self.modules if not bool(registry.moduleAvailableInTargetPython(module))]

    def version(self, registry) -> str:
        target_python = str(registry.targetPythonExecutable() or sys.executable or EMPTY_STRING).strip()
        probe_module = self.modules[0] if self.modules else EMPTY_STRING
        if not target_python or not probe_module:
            return EMPTY_STRING
        code = "import importlib,json; m=importlib.import_module(%r); print(getattr(m,'__version__',getattr(m,'version','')) or '')" % probe_module
        try:
            completed = launcherRunCommand([target_python, '-c', code], capture_output=True, text=True, timeout=15, check=False)
            if int(getattr(completed, 'returncode', 1) or 1) == 0:
                return str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING).strip().splitlines()[0] if str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING).strip() else EMPTY_STRING
        except Exception:
            recordException('start.py:1208', sys.exc_info()[1])
            return EMPTY_STRING
        return EMPTY_STRING

    def install(self, registry) -> bool:
        if self.check(registry):
            version_text = self.version(registry)
            suffix = f' version={version_text}' if version_text else EMPTY_STRING
            print(f'[TRACE:deps] {self.name} already satisfied modules={",".join(self.modules)}{suffix}', file=sys.stderr, flush=True)
            return True
        missing_before = self.missingModules(registry)
        print(f'[TRACE:deps] dependency {self.name} missing modules={",".join(missing_before)} pip={",".join(self.pipPackages) or "(none)"}', file=sys.stderr, flush=True)
        target_python = str(registry.targetPythonExecutable() or sys.executable or EMPTY_STRING).strip()
        # Python import dependencies should try pip first.  psMat is checked as a
        # module, but the install package is fontforge because FontForge supplies
        # both fontforge and psMat.
        if self.pipPackages:
            succeeded, permission_error = registry.attemptPlainPipInstall(list(self.pipPackages), pythonExecutable=target_python, useUser=False, label=f'dependency pip install {self.name}', breakSystemPackages=True)
            registry._moduleAvailabilityCache.clear()
            _IMPORT_MODULE_CACHE.clear()
            importlib.invalidate_caches()
            if self.check(registry):
                print(f'[TRACE:deps] dependency {self.name} satisfied after pip install', file=sys.stderr, flush=True)
                return True
            if succeeded and _dependencyPackageListContainsPySide(list(self.pipPackages)):
                print(f'[WARN:deps] dependency {self.name} pip install returned success, but Qt import probes still failed. Not repeating the PySide6 wheel install in this run; check system Qt/XCB/WebEngine errors in child logs.', file=sys.stderr, flush=True)
                return False
            if self.name == 'fontforge_python_bindings' and not succeeded:
                print('[WARN:deps] fontforge Python package was not installable through pip for this interpreter; trying OS package route without repeating the same pip command.', file=sys.stderr, flush=True)
                permission_error = False
            if permission_error:
                if registry.isLinux():
                    registry.attemptLinuxSudoPipInstall(list(self.pipPackages), pythonExecutable=target_python)
                    registry._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
                    if self.check(registry):
                        print(f'[TRACE:deps] dependency {self.name} satisfied after sudo/root pip install', file=sys.stderr, flush=True)
                        return True
                elif registry.isWindows():
                    registry.attemptWindowsElevatedPipInstall(list(self.pipPackages), pythonExecutable=target_python)
                    registry._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
                    if self.check(registry):
                        print(f'[TRACE:deps] dependency {self.name} satisfied after elevated pip install', file=sys.stderr, flush=True)
                        return True
            if not (self.name == 'fontforge_python_bindings' and not succeeded):
                registry.attemptUserPipInstall(list(self.pipPackages), pythonExecutable=target_python)
                registry._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
                if self.check(registry):
                    print(f'[TRACE:deps] dependency {self.name} satisfied after user pip install', file=sys.stderr, flush=True)
                    return True
        if self.aptPackages and registry.isLinux():
            print(f'[TRACE:deps] dependency {self.name} trying Linux system packages after pip fallback: {",".join(self.aptPackages)}', file=sys.stderr, flush=True)
            registry.attemptAptSystemPackageInstall(list(self.aptPackages))
            registry.syncPythonToolPaths(); registry._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
            if self.check(registry):
                print(f'[TRACE:deps] dependency {self.name} satisfied after apt/system install', file=sys.stderr, flush=True)
                return True
        if self.wingetIds and registry.isWindows():
            print(f'[WARN:deps] dependency {self.name} still missing after pip routes; winget is last-ditch only.', file=sys.stderr, flush=True)
            registry.attemptWingetInstall(list(self.wingetIds))
            registry.syncPythonToolPaths(); registry._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
            if self.check(registry):
                print(f'[TRACE:deps] dependency {self.name} satisfied after winget fallback', file=sys.stderr, flush=True)
                return True
        missing_after = self.missingModules(registry)
        print(f'[WARN:deps] dependency {self.name} still missing modules={",".join(missing_after)} in target Python={registry.targetPythonExecutable() or sys.executable}', file=sys.stderr, flush=True)
        return False


class Dependencies:
    """Ordered dependency registry.  Startup key-walks this list and calls install()."""
    def __init__(self, items=()):
        self.items = list(items or [])

    @classmethod
    def fromLegacyRows(cls, rows):
        groups: dict[str, list[dict[str, Any]]] = {}
        for row in list(rows or []):
            entry = dict(row or {})
            import_name = str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()
            pip_package = str(entry.get('pip_package', EMPTY_STRING) or EMPTY_STRING).strip()
            if import_name in {'fontforge', 'psMat'}:
                key = 'fontforge_python_bindings'
                entry['display_name'] = 'FontForge Python bindings'
                entry['pip_package'] = 'fontforge'
                entry['winget_id'] = 'FontForge.FontForge'
            elif pip_package:
                key = f'python:{pip_package.lower()}'
            else:
                key = f'import:{import_name.lower()}'
            groups.setdefault(key, []).append(entry)
        return cls(Dependency.fromRows(key.replace('python:', '').replace('import:', ''), group_rows) for key, group_rows in groups.items())

    def missing(self, registry) -> list[Dependency]:
        return [dependency for dependency in self.items if not dependency.check(registry)]

    def check(self, registry) -> bool:
        return not self.missing(registry)

    def install(self, registry) -> bool:
        ok = True
        for dependency in self.items:
            if not dependency.check(registry):
                ok = bool(dependency.install(registry)) and ok
        return bool(ok)

    def installMissing(self, registry) -> bool:
        return self.install(registry)

    def detect(self, registry) -> list[Dependency]:
        '''Return missing dependencies without installing them.'''
        return self.missing(registry)

    def ensure(self, registry) -> bool:
        '''Detect and install missing dependencies through the canonical collection.'''
        return self.installMissing(registry)

