DEBUGGER_SURFACE_IMPLEMENTATION_SCHEMA = 'CREATE TABLE IF NOT EXISTS heartbeat (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    created TEXT,\n    heartbeat_microtime REAL,\n    source TEXT,\n    event_kind TEXT,\n    reason TEXT,\n    caller TEXT,\n    phase TEXT,\n    pid INTEGER,\n    stack_trace TEXT,\n    var_dump TEXT,\n    process_snapshot TEXT,\n    exec_code TEXT,\n    exec_is_file INTEGER DEFAULT 0,\n    cron_code TEXT,\n    cron_is_file INTEGER DEFAULT 0,\n    cron_interval_seconds REAL DEFAULT 0,\n    processed INTEGER DEFAULT 0\n);'

DEBUGGER_SURFACE_IMPLEMENTATION_CODE = '# Child app minimal FlatLine debugger surface contract.\nimport os, sys, time, sqlite3, traceback\n\nDEBUGGER_SURFACES = (\n    \'heartbeat\', \'vardump\', \'poll\',\n    \'debugger-exec-command\', \'debugger-cron-command\', \'accepts-proxy\',\n)\n\nif \'--debugger-query-surfaces\' in sys.argv:\n    print(\' \'.join(DEBUGGER_SURFACES), flush=True)\n    raise SystemExit(0)\n\ndef debugger_db_path():\n    return os.environ.get(\'TRIO_DEBUGGER_DB\') or \'triodesktop.db\'\n\ndef ensure_debugger_schema(conn):\n    conn.execute("""CREATE TABLE IF NOT EXISTS heartbeat (\n        id INTEGER PRIMARY KEY AUTOINCREMENT, created TEXT, heartbeat_microtime REAL,\n        source TEXT, event_kind TEXT, reason TEXT, caller TEXT, phase TEXT, pid INTEGER,\n        stack_trace TEXT, var_dump TEXT, process_snapshot TEXT,\n        exec_code TEXT, exec_is_file INTEGER DEFAULT 0, cron_code TEXT,\n        cron_is_file INTEGER DEFAULT 0, cron_interval_seconds REAL DEFAULT 0, processed INTEGER DEFAULT 0\n    )""")\n    conn.commit()\n\ndef write_debugger_heartbeat(reason=\'HEARTBEAT\', event_kind=\'heartbeat\', **payload):\n    with sqlite3.connect(debugger_db_path()) as conn:\n        ensure_debugger_schema(conn)\n        conn.execute("""INSERT INTO heartbeat\n            (created, heartbeat_microtime, source, event_kind, reason, caller, phase, pid,\n             stack_trace, var_dump, process_snapshot, processed)\n            VALUES (datetime(\'now\'), ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0)""",\n            (time.time(), \'your_child.py\', event_kind, reason, payload.get(\'caller\',\'\'),\n             payload.get(\'phase\',\'\'), os.getpid(), payload.get(\'stack_trace\',\'\'),\n             payload.get(\'var_dump\',\'\'), payload.get(\'process_snapshot\',\'\')))\n        conn.commit()\n\ndef poll_debugger_commands():\n    with sqlite3.connect(debugger_db_path()) as conn:\n        ensure_debugger_schema(conn)\n        rows = conn.execute("""SELECT id, reason, exec_code, exec_is_file, cron_code, cron_interval_seconds\n                               FROM heartbeat WHERE source=\'start.py\' AND processed=0\n                               AND event_kind IN (\'debugger-exec-request\',\'debugger-cron-request\')\n                               ORDER BY id""").fetchall()\n        for row_id, reason, exec_code, exec_is_file, cron_code, interval_seconds in rows:\n            try:\n                code = cron_code or exec_code or \'\'\n                if exec_is_file:\n                    code = open(code, \'r\', encoding=\'utf-8\').read()\n                namespace = {\'__name__\': \'__debugger__\'}\n                exec(code, namespace, namespace)\n                result = \'ok\'\n            except Exception:\n                result = traceback.format_exc()\n            conn.execute("UPDATE heartbeat SET processed=1 WHERE id=?", (row_id,))\n            conn.execute("""INSERT INTO heartbeat\n                (created, heartbeat_microtime, source, event_kind, reason, caller, phase, pid, process_snapshot, processed)\n                VALUES (datetime(\'now\'), ?, \'your_child.py\', \'debugger-result\', ?, \'child-debugger\', \'DEBUGGER\', ?, ?, 0)""",\n                (time.time(), f\'DEBUGGER-EXEC:{row_id}\' if exec_code else f\'DEBUGGER-CRON:{row_id}\', os.getpid(), result))\n        conn.commit()'

