def _safeRuntimeSettingsPayload() -> dict[str, object]:
    try:
        settings_path = BASE_DIR / 'trio_runtime_settings.json'
        if not settings_path.exists():
            return {}
        payload = json.loads(File(settings_path).readText() or '{}')
        return payload if isinstance(payload, dict) else {}
    except Exception:
        recordException('start.py:1490', sys.exc_info()[1])
        return {}


def _writeRuntimeSettingsPayload(payload: dict[str, object]) -> bool:
    try:
        settings_path = BASE_DIR / 'trio_runtime_settings.json'
        text = json.dumps(payload, indent=2, ensure_ascii=False) + '\n'
        _apiConfigTraceText('runtime-settings write attempt', settings_path, text)
        File(settings_path).writeText(text)
        print(f'[TRACE:api-config] runtime-settings write success path={settings_path}', file=sys.stderr, flush=True)
        return True
    except Exception:
        recordException('start.py:1499', sys.exc_info()[1])
        return False



def _stripConfigCommentsForConfigParser(text: str) -> str:
    """Remove human-readable config comments before feeding ConfigParser.

    Supported comment styles:
      # shell/Perl and ; INI comments
      // C++ comments when they start a line or follow whitespace
      -- SQL/Lua-style comments when they start a line or follow whitespace
      /* ... */ C-style block comments
      <!-- ... --> HTML/XML-style block comments
      =pod ... =cut and =begin ... =end Perl POD-style blocks

    The whitespace rule for // is intentional: it keeps https:// endpoints from
    being truncated to https: while still allowing readable inline comments.
    """
    payload = str(text or EMPTY_STRING)
    payload = re.sub(r'/\*.*?\*/', '', payload, flags=re.DOTALL)
    payload = re.sub(r'<!--.*?-->', '', payload, flags=re.DOTALL)
    payload = re.sub(r'(?ms)^\s*=pod\b.*?^\s*=cut\b.*?(?:\n|$)', '', payload)
    payload = re.sub(r'(?ms)^\s*=begin\b.*?^\s*=end\b.*?(?:\n|$)', '', payload)
    cleaned: list[str] = []
    for raw_line in payload.splitlines():
        line = str(raw_line or EMPTY_STRING)
        quote = None
        index = 0
        while index < len(line):
            ch = line[index]
            if quote:
                if ch == quote:
                    quote = None
                index += 1
                continue
            if ch in {'"', "'"}:
                quote = ch
                index += 1
                continue
            if ch in {'#', ';'} or ((line.startswith('//', index) or line.startswith('--', index)) and (index == 0 or line[index - 1].isspace())):
                line = line[:index]
                break
            index += 1
        cleaned.append(line.rstrip())
    return '\n'.join(cleaned) + '\n'


def defaultConfigIniText() -> str:
    return _renderCommentedConfigText(_buildDefaultConfigParser())


def writeDefaultConfigIni(path: Path | None = None) -> None:
    target = Path(path or CONFIG_INI_PATH)
    File(target).writeText(defaultConfigIniText())


