def _shellRpcEmitEvent(writer, lock, kind: str, data: str) -> None:
    payload = {'event': str(kind or EMPTY_STRING), 'data': str(data or EMPTY_STRING)}
    blob = (json.dumps(payload, ensure_ascii=False) + '\n').encode('utf-8', 'replace')
    with lock:
        try:
            writer.write(blob)
            writer.flush()
        except Exception:
            recordException('start.py:1818', sys.exc_info()[1])
            _traceSwallowedException('start.py:1780', sys.exc_info()[1])
            pass


def _shellRpcPayloadError(raw) -> tuple[dict | None, str | None]:
    try:
        if not raw:
            return None, None
        return json.loads(raw.decode('utf-8', 'replace')), None
    except Exception as error:
        recordException('start.py:1828', sys.exc_info()[1])
        return None, f'Invalid shell RPC payload: {error}'


def _shellRpcCommandPayload(payload: dict, rpc) -> tuple[str, int, str | None]:
    if str(payload.get('token') or EMPTY_STRING) != rpc.token:
        return EMPTY_STRING, 0, 'Invalid shell RPC token.'
    command = str(payload.get('command') or EMPTY_STRING).strip()
    try:
        timeout = int(payload.get('timeout') or 30)
    except Exception:
        recordException('start.py:1838', sys.exc_info()[1])
        timeout = 30
    if not command:
        return EMPTY_STRING, timeout, 'No command provided.'
    return command, timeout, None

def ensureConfigArtifacts(verbose: bool = True) -> dict[str, object]:
    created = []
    warned = []
    config_exists_before = CONFIG_INI_PATH.exists()
    if not config_exists_before:
        writeDefaultConfigIni(CONFIG_INI_PATH)
        created.append('config.ini')
    else:
        if _ensureConfigFileHasCommentedTerminalFontSection():
            created.append('config:terminal_font')
    parser, config_exists = _loadOrCreateConfigParser(created, warned)
    parser, changed = _mergeDefaultConfigSections(parser, created)
    if (changed or not config_exists) and not config_exists_before:
        writeDefaultConfigIni(CONFIG_INI_PATH)
    elif changed:
        print('[WARN:config] config.ini is missing some defaults; preserving comments and using runtime defaults for this launch.', file=sys.stderr, flush=True)
    backend_value = str(parser.get('database', 'backend', fallback=DEFAULT_CONFIG_BACKEND) or DEFAULT_CONFIG_BACKEND)
    runtime_payload = _safeRuntimeSettingsPayload()
    runtime_payload, runtime_changed = _ensureRuntimeConfigDefaults(runtime_payload, backend_value)
    if runtime_changed or not RUNTIME_SETTINGS_PATH.exists():
        _writeRuntimeSettingsPayload(runtime_payload)
        created.append('runtime-settings')
    if verbose:
        for warning in warned:
            print(f'[WARN:config] {warning}', file=sys.stderr, flush=True)
        traceCompilerStep('config-artifacts', True, f'created={created}')
    return {'config': parser, 'created': created, 'warned': warned, 'runtime': runtime_payload}


def _readConfigBackend() -> str:
    info = ensureConfigArtifacts(verbose=False)
    parser = info.get('config')
    if isinstance(parser, configparser.ConfigParser):
        return str(parser.get('database', 'backend', fallback=DEFAULT_CONFIG_BACKEND) or DEFAULT_CONFIG_BACKEND).strip().lower()
    return DEFAULT_CONFIG_BACKEND


LAUNCHER_SQLITE_DB_NAME = 'triodesktop.db'
LAUNCHER_LASTGOOD_DB_NAME = 'trio.lastgood.db'

def _launcherSqlitePath() -> Path:
    return BASE_DIR / LAUNCHER_SQLITE_DB_NAME

def _launcherLastGoodSqlitePath() -> Path:
    return BASE_DIR / LAUNCHER_LASTGOOD_DB_NAME

def _launcherDbRecoveryModels() -> list[type]:
    return [SettingRecordOrm, KnowledgeRecordOrm, DebuggerHeartbeatRecordOrm, DebuggerExceptionRecordOrm, DebuggerFaultRecordOrm, DebuggerTrafficRecordOrm]

def _sqliteErrorLooksMalformed(error: Exception | object) -> bool:
    text = f'{type(error).__name__}: {error}'.lower()
    if 'database disk image is malformed' in text:
        return True
    if 'file is not a database' in text or 'not a database' in text:
        return True
    return 'sqlite' in text and 'malformed' in text


def _refreshLastGoodLauncherDbCopy(source_path: Path | None = None) -> None:
    source = Path(source_path or _launcherSqlitePath())
    destination = _launcherLastGoodSqlitePath()
    if not source.exists():
        return
    destination.parent.mkdir(parents=True, exist_ok=True)
    File(source).copyTo(destination)

def _launcherSqliteCacheKey(path: Path | None = None) -> str:
    target = Path(path or _launcherSqlitePath()).resolve()
    return f'sqlite::{target.as_posix()}'

def _disposeLauncherSqliteDb(path: Path | None = None) -> None:
    cache_key = _launcherSqliteCacheKey(path)
    try:
        db = Database._Instances.pop(cache_key, None)
    except Exception:
        recordException('start.py:1918', sys.exc_info()[1])
        db = None
    if db is not None:
        try:
            db.close()
        except Exception:
            recordException('start.py:1923', sys.exc_info()[1])
            _traceSwallowedException('start.py:1884', sys.exc_info()[1])
            pass
    try:
        gc.collect()
    except Exception:
        recordException('start.py:1928', sys.exc_info()[1])
        _traceSwallowedException('start.py:1888', sys.exc_info()[1])
        pass

def _settingsRecoveryStatusLine(context: str, label: str, ok: bool | None = None, detail: str = EMPTY_STRING) -> str:
    base = f'[WARN:{context}] {label}'
    if ok is None:
        return base
    rendered = coloredStatusText(STATUS_SUCCESS if ok else STATUS_FAILED)
    detail_text = str(detail or EMPTY_STRING).strip()
    if detail_text:
        return f'{base}... {rendered} {detail_text}'
    return f'{base}... {rendered}'

def _printSettingsRecoveryStatus(context: str, label: str, ok: bool | None = None, detail: str = EMPTY_STRING) -> None:
    print(_settingsRecoveryStatusLine(context, label, ok=ok, detail=detail), file=sys.stderr, flush=True)

def _flattenRuntimeSettingsRecords() -> dict[str, tuple[str, str]]:
    values: dict[str, tuple[str, str]] = {}
    payload = _safeRuntimeSettingsPayload()
    settings_payload = payload.get('settings', {}) if isinstance(payload, dict) else {}
    if not isinstance(settings_payload, dict):
        return values
    for key, value in settings_payload.items():
        if isinstance(value, (str, int, float)):
            values[str(key)] = (str(value), str(key))
        elif isinstance(value, dict):
            for sub_key, sub_value in value.items():
                compound_key = f'{key}.{sub_key}'
                values[compound_key] = (str(sub_value), compound_key)
    return values

def _readSettingsFromSqlitePath(path: Path) -> dict[str, tuple[str, str]]:
    source = Path(path or EMPTY_STRING)
    results: dict[str, tuple[str, str]] = {}
    if not source.exists():
        return results
    _disposeLauncherSqliteDb(source)
    db = Database.ForSqlitePath(source)
    try:
        _ensureLauncherSettingTimestampColumns(db)
        with db.Session() as session:
            rows = session.scalars(select(SettingRecordOrm).order_by(getattr(SettingRecordOrm, "id"))).all()
            for row in list(rows or []):
                key = str(getattr(row, 'key', EMPTY_STRING) or EMPTY_STRING).strip()
                if key:
                    results[key] = (
                        str(getattr(row, 'value', EMPTY_STRING) or EMPTY_STRING),
                        str(getattr(row, 'label', key) or key),
                    )
    finally:
        try:
            db.close()
        except Exception:
            recordException('start.py:1983', sys.exc_info()[1])
            _traceSwallowedException('start.py:1942', sys.exc_info()[1])
            pass
        _disposeLauncherSqliteDb(source)
    return results

def _writeSettingsToSqlitePath(path: Path, pairs: dict[str, tuple[str, str]]) -> int:
    target = Path(path or _launcherSqlitePath())
    _disposeLauncherSqliteDb(target)
    db = Database.ForSqlitePath(target)
    count = 0
    try:
        _ensureLauncherSettingTimestampColumns(db)
        with db.Session() as session:
            for key, (value, label) in dict(pairs or {}).items():
                key_text = str(key or EMPTY_STRING).strip()
                if not key_text:
                    continue
                existing = session.scalar(select(SettingRecordOrm).where(ormColumn(SettingRecordOrm, "key") == key_text).limit(1))
                if existing is None:
                    session.add(SettingRecordOrm(key=key_text, value=str(value), label=str(label or key_text), created=datetime.datetime.now(), updated=datetime.datetime.now()))
                else:
                    if getattr(existing, 'created', None) is None:
                        existing.created = datetime.datetime.now()
                    existing.value = str(value)
                    existing.label = str(label or key_text)
                    existing.updated = datetime.datetime.now()
                count += 1
        return count
    finally:
        try:
            db.close()
        except Exception:
            recordException('start.py:2012', sys.exc_info()[1])
            _traceSwallowedException('start.py:1970', sys.exc_info()[1])
            pass
        _disposeLauncherSqliteDb(target)


def _launcherSqliteRecoveryCreateDb(state: dict[str, Any]) -> tuple[bool, str]:
    db_path = Path(state['db_path'])
    try:
        db = Database.ForSqlitePath(db_path)
        db.connect()
        state['db'] = db
        return True, db_path.name
    except Exception as error:
        recordException('start.py:2025', sys.exc_info()[1])
        return False, f'{type(error).__name__}: {error}'


def _launcherSqliteRecoveryEnsureTables(state: dict[str, Any]) -> tuple[bool, str]:
    db = cast(Any, state.get('db'))
    if db is None:
        return False, 'Database handle missing from recovery state'
    try:
        db.EnsureTables(_launcherDbRecoveryModels())
        return True, 'schema ready'
    except Exception as error:
        recordException('start.py:2036', sys.exc_info()[1])
        return False, f'{type(error).__name__}: {error}'


def _launcherSqliteRecoveryRestoreSettings(state: dict[str, Any]) -> tuple[bool, str]:
    db_path = Path(state['db_path'])
    lastgood_path = Path(state['lastgood_path'])
    restore_pairs: dict[str, tuple[str, str]] = {}
    restore_detail = '(empty)'
    if lastgood_path.exists():
        restore_pairs.update(_readSettingsFromSqlitePath(lastgood_path))
        restore_detail = f'from {lastgood_path.name} ({len(restore_pairs)})'
    runtime_pairs = _flattenRuntimeSettingsRecords()
    for key, value in runtime_pairs.items():
        restore_pairs[key] = value
    if runtime_pairs:
        restore_detail = f'{restore_detail}; runtime={len(runtime_pairs)}'
    restored = _writeSettingsToSqlitePath(db_path, restore_pairs) if restore_pairs else 0
    state['restored_settings'] = restore_pairs
    return True, f'{restore_detail}; restored={restored}'


def _launcherSqliteRecoveryLoadSettings(state: dict[str, Any]) -> tuple[bool, str]:
    db_path = Path(state['db_path'])
    try:
        verify_db = Database.ForSqlitePath(db_path)
        verify_db.EnsureTables([SettingRecordOrm])
        with verify_db.Session() as session:
            rows = session.scalars(select(SettingRecordOrm).order_by(getattr(SettingRecordOrm, "id"))).all()
            count = len(list(rows or []))
        try:
            verify_db.close()
        except Exception:
            recordException('start.py:2068', sys.exc_info()[1])
            _traceSwallowedException('start.py:2025', sys.exc_info()[1])
            pass
        _disposeLauncherSqliteDb(db_path)
        return True, f'count={count}'
    except Exception as error:
        recordException('start.py:2073', sys.exc_info()[1])
        return False, f'{type(error).__name__}: {error}'


def _launcherSqliteRecoveryStepSpecs() -> list[dict[str, Any]]:
    return [
        {'label': 'creating DB', 'runner': _launcherSqliteRecoveryCreateDb},
        {'label': 'creating tables', 'runner': _launcherSqliteRecoveryEnsureTables},
        {'label': 'restoring settings', 'runner': _launcherSqliteRecoveryRestoreSettings},
        {'label': 'loading settings', 'runner': _launcherSqliteRecoveryLoadSettings},
    ]


def _recoverMalformedLauncherSqliteDb(error: Exception | object, *, context: str = 'launcher-db') -> bool:
    if not _sqliteErrorLooksMalformed(error):
        return False
    db_path = _launcherSqlitePath()
    lastgood_path = _launcherLastGoodSqlitePath()
    timestamp = datetime.datetime.now(datetime.timezone.utc).strftime('%Y%m%d_%H%M%S')
    malformed_backup = BASE_DIR / f'trio.malformed.{timestamp}.db'
    print(f'[WARN:{context}] {type(error).__name__}: {error}. REBUILDING:', file=sys.stderr, flush=True)
    try:
        if db_path.exists():
            File(db_path).copyTo(malformed_backup)
            print(f'[WARN:{context}] Saved malformed copy: {malformed_backup.name}', file=sys.stderr, flush=True)
    except Exception as backup_error:
        recordException('start.py:2098', sys.exc_info()[1])
        print(f'[WARN:{context}] Failed to back up malformed DB: {type(backup_error).__name__}: {backup_error}', file=sys.stderr, flush=True)
    try:
        _disposeLauncherSqliteDb(db_path)
    except Exception:
        recordException('start.py:2102', sys.exc_info()[1])
        _traceSwallowedException('start.py:2058', sys.exc_info()[1])
        pass
    try:
        if db_path.exists():
            db_path.unlink()
    except Exception as unlink_error:
        recordException('start.py:2108', sys.exc_info()[1])
        _printSettingsRecoveryStatus(context, 'creating DB', False, f'{type(unlink_error).__name__}: {unlink_error}')
        return False
    state: dict[str, Any] = {'db_path': db_path, 'lastgood_path': lastgood_path}
    for spec in _launcherSqliteRecoveryStepSpecs():
        ok, detail = spec['runner'](state)
        _printSettingsRecoveryStatus(context, str(spec.get('label') or EMPTY_STRING), bool(ok), detail)
        if not ok:
            return False
    try:
        _refreshLastGoodLauncherDbCopy(db_path)
    except Exception:
        recordException('start.py:2119', sys.exc_info()[1])
        _traceSwallowedException('start.py:2074', sys.exc_info()[1])
        pass
    print(f'[WARN:{context}] {db_path.name} was rebuilt ', end=EMPTY_STRING, file=sys.stderr, flush=True)
    printStatus(STATUS_SUCCESS, file=sys.stderr)
    return True

def _errorLooksLikeMissingSqlalchemy(error: Exception | object) -> bool:
    haystack = f'{type(error).__name__}: {error}'.lower()
    return 'sqlalchemy is required but unavailable' in haystack or "no module named 'sqlalchemy'" in haystack


def ensureLauncherDatabaseDependencies(argv=None, *, context: str = 'launcher-db') -> bool:
    launch_args = list(argv or sys.argv[1:])
    if dependencyInstallDisabled(launch_args):
        print(f'[TRACE:{context}] dependency install disabled by --deps-off/--no-deps; SQLAlchemy auto-repair skipped.', file=sys.stderr, flush=True)
        return bool(hasModule('sqlalchemy'))
    if hasModule('sqlalchemy'):
        refreshEmbeddedBindings(force_reload=True, warn_prefix=context)
        return True
    print(f'[WARN:{context}] SQLAlchemy missing in launcher Python before settings/process DB access; attempting auto-install.', file=sys.stderr, flush=True)
    registry = StartDependencyRegistry(launch_args)
    launcher_python = str(sys.executable or EMPTY_STRING).strip()
    packages = ['SQLAlchemy']
    installed = False
    if launcher_python:
        succeeded, permission_error = registry.attemptPlainPipInstall(
            packages,
            pythonExecutable=launcher_python,
            useUser=False,
            label='launcher sqlalchemy pip install',
            breakSystemPackages=True,
        )
        installed = bool(succeeded)
        if not installed and permission_error:
            installed = bool(registry.attemptLinuxSudoPipInstall(packages, pythonExecutable=launcher_python))
        if not installed:
            succeeded, _ = registry.attemptPlainPipInstall(
                packages,
                pythonExecutable=launcher_python,
                useUser=True,
                label='launcher sqlalchemy user pip install',
            )
            installed = bool(succeeded)
    if installed:
        _dependencyInstallSuccess(registry)
    else:
        # Still run the normal target dependency path; it may share the same Python
        # on Windows/portable installs, and it keeps existing recovery semantics.
        installMissingDependencies(launch_args)
    importlib.invalidate_caches()
    refreshEmbeddedBindings(force_reload=True, warn_prefix=context)
    if not hasModule('sqlalchemy'):
        print(f'[WARN:{context}] SQLAlchemy is still missing from launcher Python after auto-install attempt.', file=sys.stderr, flush=True)
        return False
    print('[TRACE:deps] SQLAlchemy became available in launcher Python after auto-install attempt.', file=sys.stderr, flush=True)
    return True


def bootstrapLauncherDependencies(launch_args=None) -> None:
    args = list(launch_args or [])
    if dependencyInstallDisabled(args):
        print('[TRACE:startup-deps] dependency install disabled by --deps-off/--no-deps; bootstrap dependency repair skipped.', file=sys.stderr, flush=True)
        refreshEmbeddedBindings(force_reload=True, warn_prefix='startup-deps')
        return
    installMissingDependencies(args)
    refreshEmbeddedBindings(force_reload=True, warn_prefix='startup-deps')
    verifyRequiredModulesOrDie(args)


def _loadLauncherSettingsMap(_recovered: bool = False) -> dict[str, str]:
    values: dict[str, str] = {}
    payload = _safeRuntimeSettingsPayload()
    settings_payload = payload.get('settings', {}) if isinstance(payload, dict) else {}
    runtime_count = 0
    if isinstance(settings_payload, dict):
        for key, value in settings_payload.items():
            if isinstance(value, (str, int, float)):
                values[str(key)] = str(value)
                runtime_count += 1
            elif isinstance(value, dict):
                for sub_key, sub_value in value.items():
                    values[f'{key}.{sub_key}'] = str(sub_value)
                    runtime_count += 1
    print(f'[TRACE:settings-load] runtime settings loaded count={runtime_count}', file=sys.stderr, flush=True)
    _apiConfigTraceDict('runtime settings loaded', values)
    db_count = 0
    if not _launcherDbDependenciesPresentForChat():
        print('[TRACE:settings-load] DB settings load skipped because SQLAlchemy is unavailable.', file=sys.stderr, flush=True)
        return values
    try:
        db = Database.ForSqlitePath(_launcherSqlitePath())
        _ensureLauncherSettingTimestampColumns(db)
        with db.Session() as session:
            rows = session.scalars(select(SettingRecordOrm).order_by(getattr(SettingRecordOrm, "id"))).all()
            for row in list(rows or []):
                key = str(getattr(row, 'key', EMPTY_STRING) or EMPTY_STRING).strip()
                if key:
                    values[key] = str(getattr(row, 'value', EMPTY_STRING) or EMPTY_STRING)
                    db_count += 1
        print(f'[TRACE:settings-load] DB settings loaded count={db_count} path={_launcherSqlitePath()}', file=sys.stderr, flush=True)
        _apiConfigTraceDict('DB settings loaded', values)
        _refreshLastGoodLauncherDbCopy(_launcherSqlitePath())
    except Exception as error:
        recordException('start.py:2202', sys.exc_info()[1])
        if (not _recovered) and _errorLooksLikeMissingSqlalchemy(error):
            if ensureLauncherDatabaseDependencies(sys.argv[1:], context='settings-load'):
                return _loadLauncherSettingsMap(_recovered=True)  # recursion-ok: one-shot recovery retry
        elif (not _recovered) and _sqliteErrorLooksMalformed(error):
            if _recoverMalformedLauncherSqliteDb(error, context='settings-load'):
                return _loadLauncherSettingsMap(_recovered=True)  # recursion-ok: one-shot recovery retry
        else:
            print(f'[WARN:settings-load] {type(error).__name__}: {error}', file=sys.stderr, flush=True)
    return values


def _storeSettingRecords(pairs: dict[str, tuple[str, str]], _recovered: bool = False) -> bool:
    if not _launcherDbDependenciesPresentForChat():
        trace_pairs = {str(key): str(value_label[0] if isinstance(value_label, tuple) and value_label else EMPTY_STRING) for key, value_label in dict(pairs or {}).items()}
        _apiConfigTraceDict('DB settings save skipped; SQLAlchemy unavailable', trace_pairs)
        print('[WARN:settings-store] SQLAlchemy unavailable; setting saved to config.ini/runtime only, DB save skipped.', file=sys.stderr, flush=True)
        return False
    try:
        trace_pairs = {str(key): str(value_label[0] if isinstance(value_label, tuple) and value_label else EMPTY_STRING) for key, value_label in dict(pairs or {}).items()}
        _apiConfigTraceDict('DB settings save attempt', trace_pairs)
        db = Database.ForSqlitePath(_launcherSqlitePath())
        _ensureLauncherSettingTimestampColumns(db)
        saved = 0
        with db.Session() as session:
            for key, (value, label) in pairs.items():
                existing = session.scalar(select(SettingRecordOrm).where(ormColumn(SettingRecordOrm, "key") == str(key)).limit(1))
                if existing is None:
                    session.add(SettingRecordOrm(key=str(key), value=str(value), label=str(label), created=datetime.datetime.now(), updated=datetime.datetime.now()))
                else:
                    if getattr(existing, 'created', None) is None:
                        existing.created = datetime.datetime.now()
                    existing.value = str(value)
                    existing.label = str(label)
                    existing.updated = datetime.datetime.now()
                saved += 1
        _refreshLastGoodLauncherDbCopy(_launcherSqlitePath())
        print(f'[TRACE:settings-store] DB settings save success count={saved} path={_launcherSqlitePath()}', file=sys.stderr, flush=True)
        return True
    except Exception as error:
        recordException('start.py:2228', sys.exc_info()[1])
        if (not _recovered) and _errorLooksLikeMissingSqlalchemy(error):
            if ensureLauncherDatabaseDependencies(sys.argv[1:], context='settings-store'):
                return _storeSettingRecords(pairs, _recovered=True)  # recursion-ok: one-shot recovery retry
        elif (not _recovered) and _sqliteErrorLooksMalformed(error):
            if _recoverMalformedLauncherSqliteDb(error, context='settings-store'):
                return _storeSettingRecords(pairs, _recovered=True)  # recursion-ok: one-shot recovery retry
        else:
            print(f'[WARN:settings-store] {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        return False


def stageProviderKeys() -> dict[str, str]:
    # Environment staging should never overwrite DB/config credentials with blanks.
    # Earlier builds wrote an empty Azure key plus a hardcoded endpoint into the
    # settings DB, which made chatTest send api-key: "" instead of asking.
    values = {
        'azure_openai_endpoint': os.environ.get('AZURE_OPENAI_ENDPOINT', ''),
        'azure_openai_key1': os.environ.get('AZURE_OPENAI_KEY1', os.environ.get('AZURE_OPENAI_API_KEY', '')),
        'azure_openai_key2': os.environ.get('AZURE_OPENAI_KEY2', ''),
        'azure_openai_key': os.environ.get('AZURE_OPENAI_KEY', os.environ.get('AZURE_OPENAI_API_KEY', '')),
        'azure_deployment_name': os.environ.get('AZURE_OPENAI_DEPLOYMENT', os.environ.get('AZURE_DEPLOYMENT_NAME', '')),
        'azure_app_name': os.environ.get('AZURE_APP_NAME', os.environ.get('AZURE_CLIENT_NAME', '')),
        'azure_tenant_id': os.environ.get('AZURE_TENANT_ID', ''),
        'azure_client_id': os.environ.get('AZURE_CLIENT_ID', os.environ.get('AZURE_APP_ID', '')),
        'azure_client_secret': os.environ.get('AZURE_CLIENT_SECRET', os.environ.get('AZURE_APP_SECRET', '')),
        'azure_client_secret_id': os.environ.get('AZURE_CLIENT_SECRET_ID', os.environ.get('AZURE_APP_SECRET_ID', '')),
        'openai_api_key': os.environ.get('OPENAI_API_KEY', os.environ.get('OPENAI_KEY', '')),
        'gemini_api_key': os.environ.get('GEMINI_API_KEY', os.environ.get('GOOGLE_API_KEY', '')),
        'anthropic_api_key': os.environ.get('ANTHROPIC_API_KEY', os.environ.get('ANTHROPIC_KEY', '')),
    }
    labels = {
        'azure_openai_endpoint': 'Azure Endpoint',
        'azure_openai_key1': 'Azure API Key 1',
        'azure_openai_key2': 'Azure API Key 2',
        'azure_openai_key': 'Azure API Key',
        'azure_deployment_name': 'Azure Deployment',
        'azure_app_name': 'Azure App Registration Name',
        'azure_tenant_id': 'Azure Tenant ID',
        'azure_client_id': 'Azure Client/Application ID',
        'azure_client_secret': 'Azure Client Secret Value',
        'azure_client_secret_id': 'Azure Client Secret ID',
        'openai_api_key': 'OpenAI API Key',
        'gemini_api_key': 'Gemini API Key',
        'anthropic_api_key': 'Anthropic API Key',
    }
    nonblank_values = {key: value for key, value in values.items() if str(value or EMPTY_STRING).strip()}
    if nonblank_values:
        runtime_payload = _safeRuntimeSettingsPayload()
        settings = runtime_payload.setdefault('settings', {}) if isinstance(runtime_payload, dict) else {}
        if not isinstance(settings, dict):
            settings = {}
            runtime_payload['settings'] = settings
        for key, value in nonblank_values.items():
            settings[key] = value
        _writeRuntimeSettingsPayload(runtime_payload)
        _storeSettingRecords({key: (nonblank_values[key], labels.get(key, key)) for key in nonblank_values})
    return values



CONFIG_SETTING_MODIFIED_SECTION = 'settings_last_modified'
CONFIG_SETTING_MODIFIED_PREFIX = 'modified_'


def _configTimestampOptionForKey(key: str) -> str:
    safe = re.sub(r'[^A-Za-z0-9_.-]+', '_', str(key or EMPTY_STRING).strip())
    return CONFIG_SETTING_MODIFIED_PREFIX + (safe or 'setting')


