def _ensureLauncherSettingTimestampColumns(db) -> None:
    """Ensure settings.created/updated exist before ORM selects SettingRecordOrm."""
    db.EnsureTables([SettingRecordOrm])
    try:
        engine = getattr(db, 'engine', None)
        if engine is None:
            return
        dialect_name = str(getattr(getattr(engine, 'dialect', None), 'name', EMPTY_STRING) or EMPTY_STRING).lower()
        with engine.begin() as connection:
            if dialect_name == 'sqlite':
                column_rows = list(connection.exec_driver_sql('PRAGMA table_info(settings)'))  # raw-sql-ok: schema migration inside DB bootstrap
                existing = {str(row[1]).lower() for row in column_rows if len(row) > 1}
                if 'created' not in existing:
                    connection.exec_driver_sql('ALTER TABLE settings ADD COLUMN created DATETIME')  # raw-sql-ok: schema migration inside DB bootstrap
                if 'updated' not in existing:
                    connection.exec_driver_sql('ALTER TABLE settings ADD COLUMN updated DATETIME')
                if 'modified' not in existing:
                    connection.exec_driver_sql('ALTER TABLE settings ADD COLUMN modified DATETIME')  # raw-sql-ok: schema migration inside DB bootstrap
            elif dialect_name in {'mysql', 'mariadb'}:
                try:
                    column_rows = list(connection.exec_driver_sql('SHOW COLUMNS FROM settings'))  # raw-sql-ok: schema migration inside DB bootstrap
                    existing = {str(row[0]).lower() for row in column_rows if row}
                    if 'created' not in existing:
                        connection.exec_driver_sql('ALTER TABLE settings ADD COLUMN created DATETIME NULL')  # raw-sql-ok: schema migration inside DB bootstrap
                    if 'updated' not in existing:
                        connection.exec_driver_sql('ALTER TABLE settings ADD COLUMN updated DATETIME NULL')
                    if 'modified' not in existing:
                        connection.exec_driver_sql('ALTER TABLE settings ADD COLUMN modified DATETIME NULL')  # raw-sql-ok: schema migration inside DB bootstrap
                except Exception:
                    recordException('start.py:settings-timestamp-mariadb-migration', sys.exc_info()[1], handled=True)
    except Exception:
        recordException('start.py:settings-timestamp-migration', sys.exc_info()[1], handled=True)


def _settingRowTimestamp(row) -> datetime.datetime:
    for attr in ('modified', 'updated', 'created'):
        value = getattr(row, attr, None)
        if isinstance(value, datetime.datetime):
            return value
        if isinstance(value, str) and value.strip():
            try:
                return datetime.datetime.fromisoformat(value.strip())
            except Exception:
                recordException('start.py:setting-row-timestamp-parse', sys.exc_info()[1], handled=True)
    return datetime.datetime.fromtimestamp(0)


def _safeConfigIniMTime() -> datetime.datetime:
    try:
        if CONFIG_INI_PATH.exists():
            return datetime.datetime.fromtimestamp(float(CONFIG_INI_PATH.stat().st_mtime or 0.0))
    except Exception:
        recordException('start.py:config-mtime', sys.exc_info()[1], handled=True)
    return datetime.datetime.fromtimestamp(0)


def _normalizeSettingTimestamp(value: datetime.datetime | None) -> datetime.datetime:
    if isinstance(value, datetime.datetime):
        if value.tzinfo is not None:
            return value.astimezone(datetime.timezone.utc).replace(tzinfo=None)
        return value
    return datetime.datetime.fromtimestamp(0)


def _parseSettingTimestampText(value: object) -> datetime.datetime:
    text = str(value or EMPTY_STRING).strip()
    if not text:
        return datetime.datetime.fromtimestamp(0)
    try:
        if text.endswith('Z'):
            text = text[:-1] + '+00:00'
        return _normalizeSettingTimestamp(datetime.datetime.fromisoformat(text))
    except Exception:
        recordException('start.py:config-setting-timestamp-parse', sys.exc_info()[1], handled=True)
        return datetime.datetime.fromtimestamp(0)


def _configSettingTimestamp(parser: configparser.ConfigParser, key: str, fallback: datetime.datetime | None = None) -> datetime.datetime:
    try:
        option = _configTimestampOptionForKey(key)
        if parser.has_section(CONFIG_SETTING_MODIFIED_SECTION) and parser.has_option(CONFIG_SETTING_MODIFIED_SECTION, option):
            parsed = _parseSettingTimestampText(parser.get(CONFIG_SETTING_MODIFIED_SECTION, option, fallback=EMPTY_STRING))
            if parsed > datetime.datetime.fromtimestamp(0):
                return parsed
    except Exception:
        recordException('start.py:config-setting-timestamp-read', sys.exc_info()[1], handled=True)
    return _normalizeSettingTimestamp(fallback)


def _setConfigSettingTimestamp(parser: configparser.ConfigParser, key: str, moment: datetime.datetime | None = None) -> None:
    try:
        if not parser.has_section(CONFIG_SETTING_MODIFIED_SECTION):
            parser.add_section(CONFIG_SETTING_MODIFIED_SECTION)
        parser.set(CONFIG_SETTING_MODIFIED_SECTION, _configTimestampOptionForKey(key), _normalizeSettingTimestamp(moment or datetime.datetime.now()).isoformat())
    except Exception:
        recordException('start.py:config-setting-timestamp-write', sys.exc_info()[1], handled=True)


def _launcherDbDependenciesPresentForChat() -> bool:
    try:
        return importlib.util.find_spec('sqlalchemy') is not None
    except Exception:
        recordException('start.py:chat-db-dependency-probe', sys.exc_info()[1], handled=True)
        return False


def _readApiConfigParser() -> configparser.ConfigParser:
    parser = configparser.ConfigParser()
    try:
        if CONFIG_INI_PATH.exists():
            raw = File(CONFIG_INI_PATH).readText()
            _apiConfigTraceText('config.ini load attempt', CONFIG_INI_PATH, raw)
            parser.read_string(_stripConfigCommentsForConfigParser(raw), source=str(CONFIG_INI_PATH))
            print(f'[TRACE:api-config] config.ini load success path={CONFIG_INI_PATH} sections={parser.sections()}', file=sys.stderr, flush=True)
        else:
            print(f'[TRACE:api-config] config.ini missing path={CONFIG_INI_PATH}; using defaults', file=sys.stderr, flush=True)
            parser = _buildDefaultConfigParser()
    except Exception:
        recordException('start.py:api-config-read', sys.exc_info()[1], handled=True)
        parser = _buildDefaultConfigParser()
    return parser


def _configValueForCanonical(parser: configparser.ConfigParser, canonical: str) -> str:
    section, option, aliases = API_CONFIG_SYNC_MAP[canonical]
    candidates = [(section, option), ('api_keys', canonical), ('azure', canonical), ('default', canonical)]
    for alias in aliases:
        candidates.extend([('api_keys', alias), ('azure', alias), ('default', alias)])
    for section_name, option_name in candidates:
        try:
            if parser.has_section(section_name) and parser.has_option(section_name, option_name):
                value = str(parser.get(section_name, option_name, fallback=EMPTY_STRING) or EMPTY_STRING).strip()
                if value:
                    return value
        except Exception:
            recordException('start.py:api-config-value-read', sys.exc_info()[1], handled=True)
    return EMPTY_STRING


def _loadApiConfigIniSettingsMap() -> dict[str, str]:
    """Read API/provider credentials directly from config.ini without DB dependency.

    chatTest and model-catalog discovery must work even when SQLAlchemy/DB
    startup is not available yet. This loader lets config.ini seed the same
    canonical keys that are stored in the settings table.
    """
    values: dict[str, str] = {}
    try:
        parser = _readApiConfigParser()
        for canonical in API_CONFIG_SYNC_MAP:
            value = _configValueForCanonical(parser, canonical)
            if value:
                values[canonical] = value
        _apiConfigTraceDict('loaded canonical values from config.ini', values, keys=list(API_CONFIG_SYNC_MAP.keys()))
    except Exception:
        recordException('start.py:api-config-direct-load', sys.exc_info()[1], handled=True)
    return values


def _setConfigCanonicalValue(parser: configparser.ConfigParser, canonical: str, value: str) -> bool:
    if canonical not in API_CONFIG_SYNC_MAP:
        return False
    section, option, _aliases = API_CONFIG_SYNC_MAP[canonical]
    if not parser.has_section(section):
        parser.add_section(section)
    current = str(parser.get(section, option, fallback=EMPTY_STRING) or EMPTY_STRING).strip()
    new_value = str(value or EMPTY_STRING).strip()
    if current == new_value:
        return False
    parser.set(section, option, new_value)
    return True


def _configParserNestedDict(parser: configparser.ConfigParser) -> dict[str, dict[str, object]]:
    payload: dict[str, dict[str, object]] = {}
    try:
        for section in parser.sections():
            payload[str(section)] = {str(key): str(value or EMPTY_STRING) for key, value in parser.items(section)}
    except Exception:
        recordException('start.py:config-parser-nested-dict', sys.exc_info()[1], handled=True)
    return payload


def _writeApiConfigParser(parser: configparser.ConfigParser) -> bool:
    ini = IniConfig(CONFIG_INI_PATH)
    try:
        preview_text = _renderCommentedConfigText(parser)
        _apiConfigTraceText('config.ini sync write attempt', CONFIG_INI_PATH, preview_text)
    except Exception:
        recordException('start.py:api-config-parser-preview', sys.exc_info()[1], handled=True)
    return bool(ini.updateFile(_configParserNestedDict(parser), includeDefaults=True))



def _configCanonicalKeyForSectionOption(section: str, option: str) -> str:
    section_text = str(section or EMPTY_STRING).strip()
    option_text = str(option or EMPTY_STRING).strip()
    if not option_text:
        return EMPTY_STRING
    option_lower = option_text.lower()
    section_lower = section_text.lower()
    if section_lower == CONFIG_SETTING_MODIFIED_SECTION.lower():
        return EMPTY_STRING
    for canonical, (mapped_section, mapped_option, aliases) in API_CONFIG_SYNC_MAP.items():
        if section_lower == str(mapped_section).lower() and option_lower == str(mapped_option).lower():
            return canonical
        if section_lower in {'api_keys', 'azure', 'default', 'settings'}:
            if option_lower == canonical.lower() or option_lower in {str(alias).lower() for alias in aliases}:
                return canonical
    if section_lower in {'', 'settings'}:
        return option_text
    return f'{section_text}.{option_text}'


def _configLocationForSettingKey(key: str) -> tuple[str, str]:
    key_text = str(key or EMPTY_STRING).strip()
    if key_text in API_CONFIG_SYNC_MAP:
        section, option, _aliases = API_CONFIG_SYNC_MAP[key_text]
        return str(section), str(option)
    if '.' in key_text:
        left, right = key_text.split('.', 1)
        left = left.strip() or 'settings'
        right = right.strip() or key_text.replace('.', '_')
        return left, right
    return 'settings', key_text


def _readConfigSettingsMap(parser: configparser.ConfigParser) -> dict[str, str]:
    values: dict[str, str] = {}
    try:
        for section in parser.sections():
            for option, value in parser.items(section):
                canonical = _configCanonicalKeyForSectionOption(section, option)
                if not canonical:
                    continue
                values[canonical] = str(value or EMPTY_STRING).strip()
    except Exception:
        recordException('start.py:config-settings-map', sys.exc_info()[1], handled=True)
    return values


def _setConfigSettingValue(parser: configparser.ConfigParser, key: str, value: str) -> bool:
    section, option = _configLocationForSettingKey(key)
    if not parser.has_section(section):
        parser.add_section(section)
    current = str(parser.get(section, option, fallback=EMPTY_STRING) or EMPTY_STRING).strip()
    new_value = str(value or EMPTY_STRING).strip()
    if current == new_value:
        return False
    parser.set(section, option, new_value)
    return True


def syncApiSettingsWithConfigIni(reason: str = 'startup') -> dict[str, int]:
    """Two-way newest-wins sync between DB settings and config.ini.

    Every row in the settings table gets a config.ini location and a per-setting
    last-modified entry in [settings_last_modified]. Known provider keys go to
    their canonical [azure]/[api_keys] slots; other settings go to [settings]
    unless their DB key uses section.option. Newest wins per setting: DB
    updated/created is compared with the config setting timestamp, falling back
    to config.ini mtime for old files that have not yet been migrated.
    """
    stats = {'db_to_config': 0, 'config_to_db': 0, 'created_timestamps': 0, 'skipped': 0, 'settings_seen': 0}
    if not _launcherDbDependenciesPresentForChat():
        print(f'[TRACE:api-config-sync] reason={reason} DB sync skipped because SQLAlchemy is unavailable; config.ini/runtime settings can still be used.', file=sys.stderr, flush=True)
        return stats
    db = None
    try:
        parser = _readApiConfigParser()
        config_values = _readConfigSettingsMap(parser)
        config_mtime = _safeConfigIniMTime()
        db = Database.ForSqlitePath(_launcherSqlitePath())
        _ensureLauncherSettingTimestampColumns(db)
        now = datetime.datetime.now()
        epoch = datetime.datetime.fromtimestamp(0)
        with db.Session() as session:
            rows = session.scalars(select(SettingRecordOrm).order_by(getattr(SettingRecordOrm, 'key'))).all()
            by_key = {str(getattr(row, 'key', EMPTY_STRING) or EMPTY_STRING): row for row in list(rows or []) if str(getattr(row, 'key', EMPTY_STRING) or EMPTY_STRING)}
            all_keys = set(by_key.keys()) | set(config_values.keys()) | set(API_CONFIG_SYNC_MAP.keys())
            stats['settings_seen'] = len(all_keys)
            for key in sorted(all_keys):
                row = by_key.get(key)
                config_value = str(config_values.get(key, EMPTY_STRING) or EMPTY_STRING).strip()
                row_value = str(getattr(row, 'value', EMPTY_STRING) or EMPTY_STRING).strip() if row is not None else EMPTY_STRING
                row_time = _settingRowTimestamp(row) if row is not None else epoch
                config_time = _configSettingTimestamp(parser, key, config_mtime if config_value else epoch)
                if row is not None:
                    stamped = False
                    if getattr(row, 'created', None) is None:
                        row.created = now
                        stamped = True
                    if getattr(row, 'updated', None) is None:
                        row.updated = now
                        stamped = True
                    if stamped:
                        stats['created_timestamps'] += 1
                        row_time = now
                if config_value and config_time > row_time:
                    if row is None:
                        row = SettingRecordOrm(key=key, value=config_value, label=CHAT_TEST_SETTING_LABELS.get(key, key), created=config_time, updated=config_time, modified=config_time)
                        session.add(row)
                        by_key[key] = row
                    else:
                        if row_value != config_value:
                            row.value = config_value
                        row.label = CHAT_TEST_SETTING_LABELS.get(key, key)
                        if getattr(row, 'created', None) is None:
                            row.created = config_time
                        row.updated = config_time
                    _setConfigSettingValue(parser, key, config_value)
                    _setConfigSettingTimestamp(parser, key, config_time)
                    stats['config_to_db'] += 1
                elif row_value:
                    _setConfigSettingValue(parser, key, row_value)
                    _setConfigSettingTimestamp(parser, key, row_time)
                    stats['db_to_config'] += 1
                else:
                    if key in API_CONFIG_SYNC_MAP:
                        _setConfigSettingValue(parser, key, EMPTY_STRING)
                        _setConfigSettingTimestamp(parser, key, row_time if row_time > epoch else now)
                    stats['skipped'] += 1
            session.commit()
        _writeApiConfigParser(parser)
        _refreshLastGoodLauncherDbCopy(_launcherSqlitePath())
        print(f'[TRACE:api-config-sync] reason={reason} settings_seen={stats["settings_seen"]} db_to_config={stats["db_to_config"]} config_to_db={stats["config_to_db"]} skipped={stats["skipped"]} timestamps={CONFIG_SETTING_MODIFIED_SECTION}', file=sys.stderr, flush=True)
    except Exception:
        recordException('start.py:api-config-sync', sys.exc_info()[1], handled=True)
    finally:
        try:
            if db is not None:
                db.close()
        except Exception:
            recordException('start.py:api-config-sync-close', sys.exc_info()[1], handled=True)
        try:
            _disposeLauncherSqliteDb(_launcherSqlitePath())
        except Exception:
            recordException('start.py:api-config-sync-dispose', sys.exc_info()[1], handled=True)
    return stats

def _normalizedDbBackendChoice(raw: str | None) -> str:
    value = str(raw or EMPTY_STRING).strip().lower()
    if value in {'maria', 'mariadb', 'mysql'}:
        return 'mariadb'
    if value in {'sqlite', 'sqlite3'}:
        return 'sqlite'
    if value:
        return value
    return _readConfigBackend()


def _maskSecret(value: str) -> str:
    text = str(value or EMPTY_STRING)
    if len(text) <= 8:
        return '*' * len(text)
    return text[:4] + '...' + text[-4:]


def _apiConfigTraceRawSecretsEnabled() -> bool:
    raw = str(os.environ.get('TRIO_TRACE_API_CONFIG_RAW', os.environ.get('TRIO_TRACE_SECRETS', EMPTY_STRING)) or EMPTY_STRING).strip().lower()
    return raw in {'1', 'true', 'yes', 'y', 'on', 'raw', 'full'}


def _apiConfigMaskValueForTrace(key: str, value: object) -> str:
    text = str(value or EMPTY_STRING)
    lower = str(key or EMPTY_STRING).lower()
    sensitive_tokens = ('key', 'token', 'secret', 'password', 'authorization', 'client_id', 'tenant_id', 'subscription_id')
    if any(token in lower for token in sensitive_tokens):
        return f'[set len={len(text)}]' if text else EMPTY_STRING
    if any(token in lower for token in ('endpoint', 'host', 'url')) and text:
        try:
            parsed = urllib.parse.urlparse(text)
            return (parsed.scheme + '://' + parsed.netloc + '/...') if parsed.netloc else '[set endpoint]'
        except Exception:
            return '[set endpoint]'
    return text


def _apiConfigMaskTextForTrace(text: str) -> str:
    if _apiConfigTraceRawSecretsEnabled():
        return str(text or EMPTY_STRING)
    masked_lines: list[str] = []
    secret_tokens = ('key', 'token', 'secret', 'password', 'authorization')
    for line in str(text or EMPTY_STRING).splitlines():
        stripped_line = line.strip()
        if '=' in line:
            left, right = line.split('=', 1)
            key = left.strip()
            if any(token in key.lower() for token in secret_tokens):
                masked_lines.append(left + '= ' + _maskSecret(right.strip()))
            else:
                masked_lines.append(line)
            continue
        if ':' in line:
            left, right = line.split(':', 1)
            key = left.strip().strip('"\'')
            if any(token in key.lower() for token in secret_tokens):
                right_text = right.strip()
                comma = ',' if right_text.endswith(',') else EMPTY_STRING
                value_text = right_text[:-1].strip() if comma else right_text
                quote = '"' if value_text.startswith('"') and value_text.endswith('"') else EMPTY_STRING
                value_clean = value_text.strip('"\'')
                masked_value = _maskSecret(value_clean)
                rendered = f'{left}: {quote}{masked_value}{quote}{comma}'
                masked_lines.append(rendered)
            else:
                masked_lines.append(line)
            continue
        masked_lines.append(line)
    return '\n'.join(masked_lines)

def _apiConfigTraceDict(label: str, values: dict | None, *, keys: list[str] | tuple[str, ...] | None = None) -> None:
    try:
        payload: dict[str, object] = {}
        source = dict(values or {})
        wanted = list(keys or sorted(source.keys()))
        for key in wanted:
            if key in source:
                payload[str(key)] = _apiConfigMaskValueForTrace(str(key), source.get(key))
        print(f'[TRACE:api-config] {label}: ' + json.dumps(payload, ensure_ascii=False, sort_keys=True), file=sys.stderr, flush=True)
    except Exception:
        recordException('start.py:api-config-trace-dict', sys.exc_info()[1], handled=True)


def _apiConfigTraceText(label: str, path: Path, text: str) -> None:
    try:
        raw_text = str(text or EMPTY_STRING)
        digest = hashlib.md5(raw_text.encode('utf-8', 'replace')).hexdigest()
        mode = 'raw' if _apiConfigTraceRawSecretsEnabled() else 'masked'
        print(f'[TRACE:api-config] {label} path={path} bytes={len(raw_text.encode("utf-8", "replace"))} md5={digest} mode={mode}', file=sys.stderr, flush=True)
        dump_content = str(os.environ.get('TRIO_TRACE_API_CONFIG_CONTENT', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'}
        if dump_content or _apiConfigTraceRawSecretsEnabled():
            print('[TRACE:api-config] ' + label + ' content begin', file=sys.stderr, flush=True)
            print(_apiConfigMaskTextForTrace(raw_text), file=sys.stderr, flush=True)
            print('[TRACE:api-config] ' + label + ' content end', file=sys.stderr, flush=True)
    except Exception:
        recordException('start.py:api-config-trace-text', sys.exc_info()[1], handled=True)


def _apiTestState() -> dict[str, str]:
    values = _loadLauncherSettingsMap()
    if not values.get('azure_openai_endpoint'):
        values.update(stageProviderKeys())
    return values


