def _chatMergeSettings(values: dict[str, str], incoming: Mapping[str, object] | None, *, preferIncoming: bool = True) -> None:
    for key, value in dict(incoming or {}).items():
        if isinstance(value, Mapping):
            for sub_key, sub_value in value.items():
                _chatMergeSettings(values, {f'{key}.{sub_key}': sub_value}, preferIncoming=preferIncoming)  # recursion-ok: recursive nested settings flatten/merge
            continue
        if not isinstance(value, (str, int, float)):
            continue
        key_text = str(key or EMPTY_STRING).strip()
        value_text = str(value or EMPTY_STRING).strip()
        if not key_text:
            continue
        if preferIncoming or not str(values.get(key_text, EMPTY_STRING) or EMPTY_STRING).strip():
            values[key_text] = value_text


def _chatNormalizeSettingAliases(values: dict[str, str]) -> None:
    lowered = {str(key).strip().lower(): str(value or EMPTY_STRING) for key, value in dict(values or {}).items()}
    for canonical, aliases in CHAT_TEST_SETTING_ALIASES.items():
        if str(values.get(canonical, EMPTY_STRING) or EMPTY_STRING).strip():
            continue
        for alias in aliases:
            alias_text = str(alias or EMPTY_STRING).strip()
            found = values.get(alias_text, EMPTY_STRING)
            if not str(found or EMPTY_STRING).strip():
                found = lowered.get(alias_text.lower(), EMPTY_STRING)
            if str(found or EMPTY_STRING).strip():
                values[canonical] = str(found or EMPTY_STRING).strip()
                break


def _persistCanonicalSettingToConfigIni(key: str, value: str) -> bool:
    canonical = str(key or EMPTY_STRING).strip()
    if canonical not in API_CONFIG_SYNC_MAP:
        print(f'[TRACE:api-config] config.ini save skipped noncanonical key={canonical}', file=sys.stderr, flush=True)
        return False
    section, option, _aliases = API_CONFIG_SYNC_MAP[canonical]
    value_text = str(value or EMPTY_STRING).strip()
    try:
        print(f'[TRACE:api-config] config.ini save attempt key={canonical} section={section} option={option} value={_apiConfigMaskValueForTrace(canonical, value_text)}', file=sys.stderr, flush=True)
        ini = IniConfig(CONFIG_INI_PATH)
        ok = ini.updateFile({section: {option: value_text}}, includeDefaults=True)
        if ok:
            print(f'[TRACE:api-config] saved {canonical} to config.ini section={section} option={option}', file=sys.stderr, flush=True)
        else:
            print(f'[WARN:api-config] failed to save {canonical} to config.ini section={section} option={option}', file=sys.stderr, flush=True)
        return bool(ok)
    except Exception:
        recordException('start.py:api-config-persist-one', sys.exc_info()[1], handled=True)
        return False


def _chatPersistSetting(key: str, value: str) -> None:
    key_text = str(key or EMPTY_STRING).strip()
    value_text = str(value or EMPTY_STRING).strip()
    if not key_text or not value_text:
        return
    print(f'[TRACE:chatTest] persist setting start key={key_text} value={_apiConfigMaskValueForTrace(key_text, value_text)}', file=sys.stderr, flush=True)
    config_ok = False
    try:
        ini = IniConfig(CONFIG_INI_PATH)
        section, option = _configLocationForSettingKey(key_text)
        timestamp_option = _configTimestampOptionForKey(key_text)
        now = datetime.datetime.now().isoformat()
        config_ok = bool(ini.updateFile({section: {option: value_text}, CONFIG_SETTING_MODIFIED_SECTION: {timestamp_option: now}}, includeDefaults=True))
        if config_ok:
            print(f'[TRACE:api-config] saved {key_text} to config.ini section={section} option={option} timestamp={timestamp_option}', file=sys.stderr, flush=True)
    except Exception:
        recordException('start.py:chat-persist-config', sys.exc_info()[1], handled=True)
    runtime_ok = False
    try:
        runtime_payload = _safeRuntimeSettingsPayload()
        settings = runtime_payload.setdefault('settings', {}) if isinstance(runtime_payload, dict) else {}
        if not isinstance(settings, dict):
            settings = {}
            runtime_payload['settings'] = settings
        settings[key_text] = value_text
        last_modified = runtime_payload.setdefault('settings_last_modified', {})
        if not isinstance(last_modified, dict):
            last_modified = {}
            runtime_payload['settings_last_modified'] = last_modified
        last_modified[key_text] = datetime.datetime.now().isoformat()
        runtime_ok = _writeRuntimeSettingsPayload(runtime_payload)
        print(f'[TRACE:chatTest] runtime settings persist key={key_text} ok={runtime_ok}', file=sys.stderr, flush=True)
    except Exception:
        recordException('start.py:chat-persist-runtime', sys.exc_info()[1], handled=True)
    db_ok = _storeSettingRecords({key_text: (value_text, CHAT_TEST_SETTING_LABELS.get(key_text, key_text))})
    print(f'[TRACE:chatTest] DB settings persist key={key_text} ok={db_ok}', file=sys.stderr, flush=True)
    print(f'[TRACE:chatTest] persist setting complete key={key_text} config_ok={config_ok}', file=sys.stderr, flush=True)

def _chatPromptRequired(values: dict[str, str], key: str, prompt: str, *, secret: bool = False, default: str = EMPTY_STRING) -> str:
    current = str(values.get(key, EMPTY_STRING) or EMPTY_STRING).strip()
    if current:
        return current
    if _start_chat_cli_quiet_requested(sys.argv[1:]):
        raise RuntimeError(f'{prompt} is required for --chat. Save it in config.ini/settings first or run --testchat interactively.')
    suffix = f' [{default}]' if str(default or EMPTY_STRING).strip() else EMPTY_STRING
    while True:
        raw = input(f'{prompt}{suffix}: ').strip()
        resolved = raw or str(default or EMPTY_STRING).strip()
        if resolved:
            values[key] = resolved
            _chatPersistSetting(key, resolved)
            return resolved
        print(f'[WARN:chatTest] {prompt} is required for this provider. Press Ctrl+C to cancel.', file=sys.stderr, flush=True)

def _chatPromptOptionalSetting(values: dict[str, str], key: str, prompt: str, *, secret: bool = False, default: str = EMPTY_STRING) -> str:
    current = str(values.get(key, EMPTY_STRING) or EMPTY_STRING).strip()
    if current:
        return current
    default_text = str(default or EMPTY_STRING).strip()
    suffix = f' [{_apiConfigMaskValueForTrace(key, default_text)}]' if default_text else ' [Enter to skip]'
    try:
        raw = getpass.getpass(prompt + suffix + ': ').strip() if secret else input(prompt + suffix + ': ').strip()
    except EOFError as error:
        recordException('start.py:chat-prompt-optional-eof', error, handled=True)
        print(f'[WARN:chatTest] optional setting prompt skipped by EOF: {prompt}', file=sys.stderr, flush=True)
        return EMPTY_STRING
    value = raw or default_text
    if value:
        values[key] = value
        _chatPersistSetting(key, value)
    return value


def _chatEnsureAzureManagementSettings(values: dict[str, str], *, promptMissing: bool = False) -> bool:
    endpoint = str(values.get('azure_openai_endpoint', EMPTY_STRING) or EMPTY_STRING).strip()
    if not str(values.get('azure_account_name', EMPTY_STRING) or EMPTY_STRING).strip():
        inferred_account = _chatAzureAccountNameFromEndpoint(endpoint) or 'TrioAPI'
        if promptMissing:
            _chatPromptOptionalSetting(values, 'azure_account_name', 'Azure OpenAI account/resource name', default=inferred_account)
        elif inferred_account:
            values['azure_account_name'] = inferred_account
    if not str(values.get('azure_app_name', EMPTY_STRING) or EMPTY_STRING).strip():
        if promptMissing:
            _chatPromptOptionalSetting(values, 'azure_app_name', 'Azure app registration display name', default='Trio')
    for key, label, secret in (
        ('azure_subscription_id', 'Azure subscription ID', False),
        ('azure_resource_group', 'Azure resource group', False),
        ('azure_tenant_id', 'Azure tenant/directory ID', False),
        ('azure_client_id', 'Azure application/client ID from App Registration Overview', False),
        ('azure_client_secret', 'Azure client secret VALUE from Certificates & secrets (not Secret ID)', True),
        ('azure_client_secret_id', 'Azure client secret ID from Certificates & secrets (optional; not used for OAuth)', False),
    ):
        if promptMissing and not str(values.get(key, EMPTY_STRING) or EMPTY_STRING).strip():
            _chatPromptOptionalSetting(values, key, label, secret=secret)
    cfg = _chatAzureManagementConfig(values)
    has_scope = bool(cfg.get('subscription_id') and cfg.get('resource_group') and cfg.get('account_name'))
    has_auth = bool(cfg.get('access_token') or (cfg.get('tenant_id') and cfg.get('client_id') and cfg.get('client_secret')))
    if has_scope and has_auth:
        _apiConfigTraceDict('Azure management settings ready', values, keys=['azure_app_name', 'azure_subscription_id', 'azure_resource_group', 'azure_account_name', 'azure_tenant_id', 'azure_client_id', 'azure_client_secret', 'azure_client_secret_id', 'azure_access_token'])
        return True
    missing = []
    if not cfg.get('subscription_id'):
        missing.append('subscription_id')
    if not cfg.get('resource_group'):
        missing.append('resource_group')
    if not cfg.get('account_name'):
        missing.append('account_name')
    if not has_auth:
        missing.append('tenant_id + application/client_id + client_secret_value, or access_token')
    print(f'[TRACE:chatTest] Azure management settings incomplete; missing {", ".join(missing)}', file=sys.stderr, flush=True)
    return False


def _chatEnsureChoiceSettings(choice: dict[str, Any], values: dict[str, str]) -> None:
    kind = str(choice.get('kind') or EMPTY_STRING)
    if kind == 'openai':
        _chatPromptRequired(values, 'openai_api_key', 'OpenAI API key', secret=True)
    elif kind == 'azure':
        endpoint = _chatPromptRequired(values, 'azure_openai_endpoint', 'Azure endpoint URL')
        endpoint = _chatSanitizeAzureEndpoint(endpoint, values, persist=True)
        if endpoint and not any(host_marker in endpoint.lower() for host_marker in ('openai.azure.com', 'services.ai.azure.com', 'cognitiveservices.azure.com')):
            print(f'[WARN:chatTest] Azure endpoint does not look like a known Azure AI/OpenAI resource URL: {endpoint}', file=sys.stderr, flush=True)
        key = _chatPromptRequired(values, 'azure_openai_key1', 'Azure API key', secret=True)
        if key and not str(values.get('azure_openai_key', EMPTY_STRING) or EMPTY_STRING).strip():
            values['azure_openai_key'] = key
            _chatPersistSetting('azure_openai_key', key)
        deployment = _chatEnsureAzureDeploymentChoice(choice, values, promptIfUnverified=not bool(choice.get('_one_shot')))
        if deployment:
            choice['model'] = deployment
            choice['label'] = f'Deployment {deployment}'
            choice['source'] = 'manual-confirmed'
    elif kind == 'gemini':
        _chatPromptRequired(values, 'gemini_api_key', 'Gemini API key', secret=True)
    elif kind == 'anthropic':
        _chatPromptRequired(values, 'anthropic_api_key', 'Anthropic API key', secret=True)
    elif kind == 'ollama':
        runtime_cls = requiredSharedOllamaRuntime()
        runtime = runtime_cls(values)
        host = runtime.ensureRunning(startIfNeeded=True)
        if host:
            values['ollama_host'] = host
            _chatPersistSetting('ollama_host', host)
        else:
            _chatPromptRequired(values, 'ollama_host', 'Ollama host URL', default=str(getattr(runtime_cls, 'DEFAULT_HOST', 'http://127.0.0.1:11434')))


def _chatTestState() -> dict[str, str]:
    """Load chat debug settings from env, runtime JSON, and the real settings DB.

    The old chatTest path intentionally skipped the database to keep the model
    menu fast. That made Azure/OpenAI debug requests ignore keys stored by the
    GUI. This loader now merges the database last so persisted settings win,
    while still falling back to prompts when a required value is missing.
    """
    print('[TRACE:chatTest] loading chat settings: config.ini <-> DB sync start', file=sys.stderr, flush=True)
    syncApiSettingsWithConfigIni(reason='chat-test')
    values: dict[str, str] = {}
    _chatMergeSettings(values, {
        'azure_openai_endpoint': os.environ.get('AZURE_OPENAI_ENDPOINT', EMPTY_STRING),
        'azure_openai_key1': os.environ.get('AZURE_OPENAI_KEY1', os.environ.get('AZURE_OPENAI_API_KEY', EMPTY_STRING)),
        'azure_openai_key2': os.environ.get('AZURE_OPENAI_KEY2', EMPTY_STRING),
        'azure_openai_key': os.environ.get('AZURE_OPENAI_KEY', os.environ.get('AZURE_OPENAI_API_KEY', EMPTY_STRING)),
        'azure_deployment_name': os.environ.get('AZURE_OPENAI_DEPLOYMENT', os.environ.get('AZURE_DEPLOYMENT_NAME', EMPTY_STRING)),
        'azure_subscription_id': os.environ.get('AZURE_SUBSCRIPTION_ID', EMPTY_STRING),
        'azure_resource_group': os.environ.get('AZURE_RESOURCE_GROUP', EMPTY_STRING),
        'azure_account_name': os.environ.get('AZURE_ACCOUNT_NAME', os.environ.get('AZURE_OPENAI_ACCOUNT_NAME', EMPTY_STRING)),
        'azure_access_token': os.environ.get('AZURE_ACCESS_TOKEN', os.environ.get('AZURE_BEARER_TOKEN', EMPTY_STRING)),
        'azure_app_name': os.environ.get('AZURE_APP_NAME', os.environ.get('AZURE_CLIENT_NAME', EMPTY_STRING)),
        'azure_tenant_id': os.environ.get('AZURE_TENANT_ID', EMPTY_STRING),
        'azure_client_id': os.environ.get('AZURE_CLIENT_ID', os.environ.get('AZURE_APP_ID', EMPTY_STRING)),
        'azure_client_secret': os.environ.get('AZURE_CLIENT_SECRET', os.environ.get('AZURE_APP_SECRET', EMPTY_STRING)),
        'azure_client_secret_id': os.environ.get('AZURE_CLIENT_SECRET_ID', os.environ.get('AZURE_APP_SECRET_ID', EMPTY_STRING)),
        'openai_api_key': os.environ.get('OPENAI_API_KEY', os.environ.get('OPENAI_KEY', EMPTY_STRING)),
        'gemini_api_key': os.environ.get('GEMINI_API_KEY', os.environ.get('GOOGLE_API_KEY', EMPTY_STRING)),
        'anthropic_api_key': os.environ.get('ANTHROPIC_API_KEY', os.environ.get('ANTHROPIC_KEY', EMPTY_STRING)),
        'ollama_host': os.environ.get('OLLAMA_HOST', EMPTY_STRING),
        'ollama_model_choice': os.environ.get('OLLAMA_MODEL', EMPTY_STRING),
    }, preferIncoming=True)
    # Load config.ini directly before runtime JSON / DB. syncApiSettingsWithConfigIni
    # can be blocked by a DB dependency, but chatTest still needs saved keys.
    _chatMergeSettings(values, _loadApiConfigIniSettingsMap(), preferIncoming=True)
    payload = _safeRuntimeSettingsPayload()
    settings = payload.get('settings', {}) if isinstance(payload, dict) else {}
    if isinstance(settings, dict):
        _chatMergeSettings(values, settings, preferIncoming=True)
    try:
        _chatMergeSettings(values, _loadLauncherSettingsMap(), preferIncoming=True)
    except Exception:
        recordException('start.py:chat-settings-db-load', sys.exc_info()[1], handled=True)
    _chatNormalizeSettingAliases(values)
    _apiConfigTraceDict('chatTest final merged settings', values, keys=list(CHAT_TEST_SETTING_ALIASES.keys()))
    values.setdefault('ollama_host', 'http://127.0.0.1:11434')
    values.setdefault('ollama_model_choice', 'gpt-oss:20b')
    return values


def _httpJsonRequest(url: str, payload: dict, headers: dict[str, str], timeout: int = 120) -> tuple[int, str]:
    try:
        result = requiredSharedHttpExchange()(str(url), method='POST', headers=dict(headers or {}), payload=dict(payload or {}), timeout=float(timeout or 120))
        return int(result.get('status', 0) or 0), str(result.get('content', EMPTY_STRING) or EMPTY_STRING)
    except Exception as error:
        recordException('start.py:chat-http-json-request', sys.exc_info()[1], handled=True)
        return 0, f'{type(error).__name__}: {error}'




def _httpJsonExchange(url: str, payload: dict, headers: dict[str, str], timeout: int = 120) -> dict[str, Any]:
    try:
        result = requiredSharedHttpExchange()(str(url), method='POST', headers=dict(headers or {}), payload=dict(payload or {}), timeout=float(timeout or 120))
        return requiredSharedExchangeToStartResult()(result, url=str(url), request_headers=dict(headers or {}), request_body=payload)
    except Exception as error:
        recordException('start.py:chat-http-json-exchange', sys.exc_info()[1], handled=True)
        return {'url': str(url), 'requestHeaders': dict(headers or {}), 'requestBody': json.dumps(payload or {}, indent=2, ensure_ascii=False), 'status': 0, 'responseHeaders': {}, 'content': EMPTY_STRING, 'json': None, 'error': f'{type(error).__name__}: {error}'}


def _chatAzureResponsesUrl(endpoint: str) -> str:
    return requiredSharedAzureOpenAIModelCore()({'azure_openai_endpoint': str(endpoint or EMPTY_STRING)}).responses_url(endpoint)



def _httpJsonGetExchange(url: str, headers: dict[str, str], timeout: int = 30) -> dict[str, Any]:
    try:
        result = requiredSharedHttpExchange()(str(url), method='GET', headers=dict(headers or {}), timeout=float(timeout or 30))
        return requiredSharedExchangeToStartResult()(result, url=str(url), request_headers=dict(headers or {}))
    except Exception as error:
        recordException('start.py:chat-http-json-get-exchange', sys.exc_info()[1], handled=True)
        return {'url': str(url), 'requestHeaders': dict(headers or {}), 'status': 0, 'responseHeaders': {}, 'content': EMPTY_STRING, 'json': None, 'error': f'{type(error).__name__}: {error}'}


def _httpBytesGetExchange(url: str, headers: dict[str, str], timeout: int = 900) -> dict[str, Any]:
    try:
        req = urllib.request.Request(str(url), method='GET')
        for key, value in dict(headers or {}).items():
            if str(key or EMPTY_STRING).lower() == 'content-type':
                continue
            req.add_header(str(key), str(value))
        with urllib.request.urlopen(req, timeout=float(timeout or 900)) as response:  # nosec: user-configured provider URL
            data = response.read()
            return {'status': int(getattr(response, 'status', 200) or 200), 'headers': dict(response.headers.items()), 'bytes': data, 'error': EMPTY_STRING, 'url': str(url)}
    except urllib.error.HTTPError as error:
        try:
            detail = error.read().decode('utf-8', errors='replace')
        except Exception:
            detail = str(error)
        return {'status': int(getattr(error, 'code', 0) or 0), 'headers': {}, 'bytes': b'', 'error': detail, 'url': str(url)}
    except Exception as error:
        recordException('start.py:chat-http-bytes-get-exchange', sys.exc_info()[1], handled=True)
        return {'status': 0, 'headers': {}, 'bytes': b'', 'error': f'{type(error).__name__}: {error}', 'url': str(url)}


def _chatAzureEndpointFromAccountName(values: dict[str, str]) -> str:
    for key in ('azure_account_name', 'azure_openai_account_name', 'account_name'):
        raw = str(values.get(key, EMPTY_STRING) or EMPTY_STRING).strip()
        if raw:
            clean = ''.join(ch for ch in raw if ch.isalnum() or ch == '-')
            if clean:
                return f'https://{clean}.openai.azure.com'
    return EMPTY_STRING


def _chatSanitizeAzureEndpoint(endpoint: object, values: dict[str, str] | None = None, *, persist: bool = False) -> str:
    values = values if values is not None else {}
    text = str(endpoint or EMPTY_STRING).strip().strip('\"\'').rstrip('/')
    fallback = _chatAzureEndpointFromAccountName(values)
    if not text:
        text = fallback
    compact = text.lower().rstrip('/')
    if compact in {'http:', 'https:', 'http://http', 'http://https', 'https://http', 'https://https', 'https://https:'}:
        text = fallback
    if text and text.startswith('//'):
        text = 'https:' + text
    elif text and '://' not in text:
        text = 'https://' + text
    try:
        parsed = urllib.parse.urlparse(text)
        host = str(parsed.netloc or parsed.path or EMPTY_STRING).split(':', 1)[0].strip().lower()
        if not parsed.scheme or not parsed.netloc or host in {'http', 'https'} or (host and '.' not in host):
            text = fallback
    except Exception:
        recordException('start.py:chat-sanitize-azure-endpoint', sys.exc_info()[1], handled=True)
        text = fallback
    text = str(text or EMPTY_STRING).rstrip('/')
    if text and persist and values.get('azure_openai_endpoint') != text:
        values['azure_openai_endpoint'] = text
        try:
            _chatPersistSetting('azure_openai_endpoint', text)
        except Exception:
            recordException('start.py:chat-sanitize-azure-endpoint-persist', sys.exc_info()[1], handled=True)
    return text


def _chatAzureApiHeaders(api_key: str) -> dict[str, str]:
    return {'api-key': str(api_key or EMPTY_STRING).strip(), 'Content-Type': 'application/json'}


def _chatAzureDataPlaneDeploymentRows(endpoint: str, api_key: str, values: dict[str, str]) -> list[dict[str, str]]:
    endpoint = _chatSanitizeAzureEndpoint(endpoint, values)
    key = str(api_key or EMPTY_STRING).strip()
    if not endpoint or not key:
        return []
    rows: list[dict[str, str]] = []
    for url in _chatAzureDeploymentDiscoveryUrls(endpoint):
        result = _httpJsonGetExchange(url, _chatAzureApiHeaders(key), timeout=30)
        status = int(result.get('status', 0) or 0)
        if 200 <= status < 300:
            parsed = _chatParseAzureDeploymentRows(result.get('json'), source='azure-data-plane')
            for row in parsed:
                if row.get('name') or row.get('api_string'):
                    rows.append(row)
            if rows:
                break
    unique: list[dict[str, str]] = []
    seen: set[str] = set()
    for row in rows:
        name = str(row.get('name') or row.get('api_string') or EMPTY_STRING).strip()
        if name and name not in seen:
            seen.add(name)
            unique.append(row)
    if unique:
        values['azure_discovered_deployments'] = ','.join(str(row.get('name') or row.get('api_string') or EMPTY_STRING).strip() for row in unique if str(row.get('name') or row.get('api_string') or EMPTY_STRING).strip())
        values['azure_discovered_deployments_source'] = 'azure-data-plane'
        print(f'[TRACE:chatTest] Azure data-plane deployments discovered count={len(unique)}', file=sys.stderr, flush=True)
    return unique


def _chatAzureIsSoraName(value: object) -> bool:
    return 'sora' in _chatAzureNormalizeAlias(str(value or EMPTY_STRING))


def _httpFormExchange(url: str, form: dict[str, str], headers: dict[str, str] | None = None, timeout: int = 30) -> dict[str, Any]:
    try:
        merged_headers = {'Content-Type': 'application/x-www-form-urlencoded'}
        merged_headers.update(dict(headers or {}))
        result = requiredSharedHttpFormExchange()(str(url), dict(form or {}), headers=dict(headers or {}), timeout=float(timeout or 30))
        normalized = requiredSharedExchangeToStartResult()(result, url=str(url), request_headers=merged_headers, request_body=form)
        normalized['json'] = result.get('json')
        return normalized
    except Exception as error:
        recordException('start.py:chat-http-form-exchange', sys.exc_info()[1], handled=True)
        return {'url': str(url), 'requestHeaders': dict(headers or {}), 'requestBody': str(form or {}), 'status': 0, 'responseHeaders': {}, 'content': EMPTY_STRING, 'json': None, 'error': f'{type(error).__name__}: {error}'}



