def _chatSpinUpDeployment(values: dict[str, str], token: str, existing_rows: list[dict[str, str]] | None = None) -> str:
    print('\n── Spin up new Azure OpenAI deployment ──', flush=True)
    available = _chatListAvailableModels(values, token)
    if available:
        print('Available base models:', flush=True)
        for index, model in enumerate(available, 1):
            name = str(model.get('name') or model.get('model') or EMPTY_STRING).strip()
            version = str(model.get('version') or EMPTY_STRING).strip()
            suffix = f' v{version}' if version else EMPTY_STRING
            print(f'  {index}) {name}{suffix}', flush=True)
        raw = input('Pick model number or type model name: ').strip()
        if raw.isdigit() and 1 <= int(raw) <= len(available):
            chosen = available[int(raw) - 1]
            model_name = str(chosen.get('name') or chosen.get('model') or EMPTY_STRING).strip()
            model_version = str(chosen.get('version') or EMPTY_STRING).strip() or '2024-11-20'
        else:
            model_name = raw or 'gpt-4o'
            model_version = input(f'Model version for {model_name} (for example 2024-11-20): ').strip() or '2024-11-20'
    else:
        print('[WARN:chatTest] Could not fetch available models list from Azure.', file=sys.stderr, flush=True)
        model_name = input('Base model name (for example gpt-4o): ').strip() or 'gpt-4o'
        model_version = input(f'Model version for {model_name} (for example 2024-11-20): ').strip() or '2024-11-20'
    default_deployment = re.sub(r'[^A-Za-z0-9_.-]+', '-', model_name).strip('-') or 'gpt-4o'
    deployment_name = input(f'Deployment name [{default_deployment}]: ').strip() or default_deployment
    capacity_raw = input('Capacity TPM units [1]: ').strip() or '1'
    try:
        capacity = max(1, int(capacity_raw))
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        capacity = 1
    print(f"[chatTest] Creating Azure deployment '{deployment_name}' ({model_name} v{model_version}, capacity={capacity}) …", flush=True)
    ok = _chatCreateDeployment(values, token, deployment_name, model_name, model_version, capacity)
    if ok:
        print(f"[chatTest] Deployment '{deployment_name}' created successfully.", flush=True)
    else:
        print('[WARN:chatTest] Deployment creation may have failed. Check the Azure portal.', file=sys.stderr, flush=True)
    values['azure_deployment_name'] = deployment_name
    _chatPersistSetting('azure_deployment_name', deployment_name)
    return deployment_name

def _chatDiscoverAzureDeployments(endpoint: str, api_key: str, values: dict[str, str], *, warn: bool = True, promptManagement: bool = False) -> list[dict[str, str]]:
    """Return actual Azure OpenAI deployments, not deployable model families.

    Prefer ARM/management discovery, but also try the Azure OpenAI data-plane
    deployment/model list with the inference key.  The data-plane route is not
    available on every account, but when it is available it lets aliases such as
    `sora` resolve without asking the user to hand-enter a versioned deployment.
    """
    endpoint = _chatSanitizeAzureEndpoint(endpoint, values, persist=False)
    if endpoint:
        values['azure_openai_endpoint'] = endpoint
    cached = str(values.get('azure_discovered_deployments', EMPTY_STRING) or EMPTY_STRING).strip()
    if cached and str(values.get('azure_discovered_deployments_source', EMPTY_STRING) or EMPTY_STRING).startswith('azure-management'):
        rows = [{'name': name.strip(), 'model': EMPTY_STRING, 'version': EMPTY_STRING, 'status': 'cached', 'source': 'azure-management-cache'} for name in cached.split(',') if name.strip()]
        if rows:
            print(f'[TRACE:chatTest] Azure deployments loaded from management cache count={len(rows)}', file=sys.stderr, flush=True)
            return rows
    if not _chatEnsureAzureManagementSettings(values, promptMissing=promptManagement):
        data_plane_rows = _chatAzureDataPlaneDeploymentRows(endpoint, api_key, values)
        if data_plane_rows:
            return data_plane_rows
        print('[TRACE:chatTest] Azure deployment discovery skipped; management settings are incomplete and data-plane listing returned no rows.', file=sys.stderr, flush=True)
        if warn:
            print('[WARN:chatTest] Azure deployment listing needs subscription_id, resource_group, account_name, plus service-principal tenant_id/client_id/client_secret, an access_token, az login, or a data-plane deployment list that accepts your API key. Enter the exact deployment name or add an alias setting.', file=sys.stderr, flush=True)
        return []
    found = _chatAzureManagementDeploymentRows(values)
    unique: list[dict[str, str]] = []
    seen: set[str] = set()
    for row in list(found or []):
        name = str(row.get('name') or EMPTY_STRING).strip()
        if not name or name in seen:
            continue
        seen.add(name)
        row['source'] = str(row.get('source') or 'azure-management:/deployments')
        unique.append(row)
    if unique:
        values['azure_discovered_deployments'] = ','.join(row['name'] for row in unique if row.get('name'))
        values['azure_discovered_deployments_source'] = 'azure-management:/deployments'
        print(f'[TRACE:chatTest] Azure management deployments discovered count={len(unique)}', file=sys.stderr, flush=True)
    else:
        data_plane_rows = _chatAzureDataPlaneDeploymentRows(endpoint, api_key, values)
        if data_plane_rows:
            return data_plane_rows
        print('[TRACE:chatTest] Azure management deployment discovery returned no live deployment rows.', file=sys.stderr, flush=True)
        if warn:
            print('[WARN:chatTest] Azure API keys cannot reliably list deployed Azure OpenAI deployments. Provide Azure management settings (subscription_id, resource_group, account_name) plus service-principal tenant_id/client_id/client_secret, an access_token, or az login (or az login --use-device-code for CLI-only/device-code login), or enter the exact deployment name.', file=sys.stderr, flush=True)
    return unique


def _chatInputAvailable() -> bool:
    try:
        return bool(getattr(sys.stdin, 'isatty', lambda: False)())
    except Exception:
        return False


def _chatAzureNormalizeAlias(value: str) -> str:
    return re.sub(r'[^a-z0-9]+', EMPTY_STRING, str(value or EMPTY_STRING).strip().lower())


def _chatAzureAliasNeedles(alias: str) -> list[str]:
    normalized = _chatAzureNormalizeAlias(alias)
    if not normalized:
        return []
    groups = {
        'grok': ['grok', 'xai'],
        'xai': ['xai', 'grok'],
        'deepseek': ['deepseek'],
        'deepseekr1': ['deepseek', 'r1'],
        'kimi': ['kimi'],
        'kimik2': ['kimi', 'k2'],
        'sora': ['sora'],
        'sora2': ['sora'],
        'codex': ['codex'],
        'gpt5codex': ['codex'],
        'gpt5chat': ['gpt5', 'chat'],
        'azuregpt': ['gpt'],
    }
    needles = list(groups.get(normalized, []))
    if not needles:
        # For arbitrary aliases such as `my-grok-prod`, search both the full
        # compact form and individual useful words.
        needles.append(normalized)
        for part in re.split(r'[^A-Za-z0-9]+', str(alias or EMPTY_STRING)):
            compact = _chatAzureNormalizeAlias(part)
            if compact and compact not in needles and len(compact) >= 3:
                needles.append(compact)
    return needles


def _chatAzureLooksLikeAlias(value: str) -> bool:
    normalized = _chatAzureNormalizeAlias(value)
    if not normalized:
        return False
    known_aliases = {'grok', 'xai', 'deepseek', 'deepseekr1', 'kimi', 'kimik2', 'sora', 'sora2', 'codex', 'gpt5codex', 'gpt5chat', 'azuregpt'}
    if normalized in known_aliases:
        return True
    # Short natural language shortcuts are probably aliases.  Long strings with
    # dates, dots, or many separators are more likely exact deployment names.
    raw = str(value or EMPTY_STRING).strip()
    return bool(len(normalized) <= 18 and not any(ch.isdigit() for ch in normalized) and raw.lower() == normalized)


def _chatAzureExplicitAliasFromSettings(values: dict[str, str], alias: str) -> str:
    alias_norm = _chatAzureNormalizeAlias(alias)
    if not alias_norm:
        return EMPTY_STRING
    wanted = {
        f'azure_deployment_alias_{alias_norm}',
        f'azure_alias_{alias_norm}',
        f'azure_{alias_norm}_deployment',
        f'azure_{alias_norm}_deployment_name',
        f'azure.{alias_norm}',
        f'azure.alias_{alias_norm}',
        f'azure.deployment_alias_{alias_norm}',
        f'azure.{alias_norm}_deployment',
        f'azure.{alias_norm}_deployment_name',
    }
    for key, value in dict(values or {}).items():
        key_norm = _chatAzureNormalizeAlias(str(key or EMPTY_STRING).replace('.', '_'))
        dotted_norm = str(key or EMPTY_STRING).strip().lower()
        if key_norm in wanted or dotted_norm in wanted:
            resolved = str(value or EMPTY_STRING).strip()
            if resolved:
                return resolved
    return EMPTY_STRING


def _chatAzureRowText(row: dict[str, str]) -> str:
    parts = []
    for key in ('name', 'api_string', 'display_name', 'model', 'version', 'sku', 'status'):
        value = str(row.get(key) or EMPTY_STRING).strip()
        if value:
            parts.append(value)
    return ' '.join(parts)


def _chatResolveAzureDeploymentAlias(requested: str, rows: list[dict[str, str]], values: dict[str, str]) -> str:
    requested_text = str(requested or EMPTY_STRING).strip()
    if not requested_text or requested_text in {'enter-azure-deployment', 'discover-azure-deployments'}:
        return EMPTY_STRING
    explicit = _chatAzureExplicitAliasFromSettings(values, requested_text)
    if explicit:
        print(f'[TRACE:chatTest] Azure alias {requested_text!r} resolved from config/settings to deployment {explicit!r}', file=sys.stderr, flush=True)
        return explicit
    requested_norm = _chatAzureNormalizeAlias(requested_text)
    for row in list(rows or []):
        name = str(row.get('name') or row.get('api_string') or EMPTY_STRING).strip()
        if name and _chatAzureNormalizeAlias(name) == requested_norm:
            return name
    needles = _chatAzureAliasNeedles(requested_text)
    matches: list[dict[str, str]] = []
    for row in list(rows or []):
        row_norm = _chatAzureNormalizeAlias(_chatAzureRowText(row))
        if row_norm and any(needle and needle in row_norm for needle in needles):
            matches.append(row)
    if matches:
        chosen = str(matches[0].get('name') or matches[0].get('api_string') or EMPTY_STRING).strip()
        if len(matches) > 1:
            names = ', '.join(str(row.get('name') or EMPTY_STRING).strip() for row in matches[:5] if str(row.get('name') or EMPTY_STRING).strip())
            print(f'[WARN:chatTest] Azure alias {requested_text!r} matched multiple deployments; using {chosen!r}. Matches: {names}', file=sys.stderr, flush=True)
        else:
            print(f'[TRACE:chatTest] Azure alias {requested_text!r} resolved to deployment {chosen!r}', file=sys.stderr, flush=True)
        return chosen
    configured = str(values.get('azure_deployment_name', EMPTY_STRING) or EMPTY_STRING).strip()
    if configured and requested_norm and any(needle and needle in _chatAzureNormalizeAlias(configured) for needle in needles):
        print(f'[TRACE:chatTest] Azure alias {requested_text!r} matched configured deployment {configured!r}', file=sys.stderr, flush=True)
        return configured
    return EMPTY_STRING


def _chatChooseAzureDeployment(rows: list[dict[str, str]], values: dict[str, str], current: str = EMPTY_STRING, *, allowPrompt: bool = True) -> str:
    current_text = str(current or EMPTY_STRING).strip()
    interactive = bool(allowPrompt and _chatInputAvailable())
    resolved_alias = _chatResolveAzureDeploymentAlias(current_text, rows, values)
    if resolved_alias:
        values['azure_deployment_name'] = resolved_alias
        return resolved_alias
    if current_text and any(str(row.get('name') or EMPTY_STRING).strip() == current_text for row in rows):
        return current_text
    token = _chatAzureManagementToken(values)
    can_spin_up = bool(interactive and token and _chatEnsureAzureManagementSettings(values, promptMissing=False))
    if current_text and not interactive:
        print(f'[TRACE:chatTest] using configured Azure deployment without interactive verification: {current_text}', file=sys.stderr, flush=True)
        values['azure_deployment_name'] = current_text
        return current_text
    if rows:
        if not interactive:
            first = str(rows[0].get('name') or EMPTY_STRING).strip()
            resolved = current_text or first
            if resolved:
                print(f'[TRACE:chatTest] noninteractive Azure deployment selected: {resolved}', file=sys.stderr, flush=True)
                values['azure_deployment_name'] = resolved
                return resolved
        print('Azure deployments/models found:', flush=True)
        for index, row in enumerate(rows, 1):
            extras = ' '.join(str(row.get(key) or EMPTY_STRING).strip() for key in ('model', 'version', 'status') if str(row.get(key) or EMPTY_STRING).strip())
            print(f'  {index}) {row.get("name")} {extras}'.rstrip(), flush=True)
        spin_index = len(rows) + 1 if can_spin_up else 0
        if can_spin_up:
            print(f'  {spin_index}) Spin up new Azure OpenAI deployment', flush=True)
        while True:
            raw = input('Azure deployment number, exact deployment name, or spin-up option: ').strip()
            if not raw and current_text:
                return current_text
            if raw.isdigit():
                idx = int(raw)
                if 1 <= idx <= len(rows):
                    return str(rows[idx - 1].get('name') or EMPTY_STRING).strip()
                if can_spin_up and idx == spin_index:
                    return _chatSpinUpDeployment(values, token, rows)
            if can_spin_up and raw.lower() in {'new', 'spin', 'spinup', 'spin-up', 'create', 'deploy'}:
                return _chatSpinUpDeployment(values, token, rows)
            for row in rows:
                if raw == str(row.get('name') or EMPTY_STRING).strip():
                    return raw
            print('[WARN:chatTest] Pick a listed deployment, type the exact deployment name, or choose spin-up.', file=sys.stderr, flush=True)
    if current_text:
        print(f'[WARN:chatTest] Configured Azure deployment could not be verified through Azure management: {current_text}', file=sys.stderr, flush=True)
        if not interactive:
            print(f'[TRACE:chatTest] noninteractive mode keeps configured Azure deployment: {current_text}', file=sys.stderr, flush=True)
            values['azure_deployment_name'] = current_text
            return current_text
        if can_spin_up:
            raw = input(f'Azure deployment name, "new" to spin up one, or Enter for current [{current_text}]: ').strip()
            if raw.lower() in {'new', 'spin', 'spinup', 'spin-up', 'create', 'deploy'}:
                return _chatSpinUpDeployment(values, token, rows)
        else:
            raw = input(f'Azure deployment name (exact deployment name from Azure, not model family) [{current_text}]: ').strip()
        resolved = raw or current_text
        values['azure_deployment_name'] = resolved
        _chatPersistSetting('azure_deployment_name', resolved)
        return resolved
    if can_spin_up:
        raw = input('Azure deployment name, or type "new" to spin up a deployment: ').strip()
        if raw.lower() in {'new', 'spin', 'spinup', 'spin-up', 'create', 'deploy'}:
            return _chatSpinUpDeployment(values, token, rows)
        if raw:
            values['azure_deployment_name'] = raw
            _chatPersistSetting('azure_deployment_name', raw)
            return raw
    if not interactive:
        configured = str(values.get('azure_deployment_name', EMPTY_STRING) or EMPTY_STRING).strip()
        if configured:
            return configured
        raise RuntimeError('Azure deployment is missing and this chat request is noninteractive. Set [azure] deployment_name in config.ini or pass --chat azure <deployment> <message>.')
    return _chatPromptRequired(values, 'azure_deployment_name', 'Azure deployment name (exact deployment name from Azure, not model family)', default=EMPTY_STRING)


def _chatEnsureAzureDeploymentChoice(choice: dict[str, Any], values: dict[str, str], *, promptIfUnverified: bool = True) -> str:
    endpoint = str(values.get('azure_openai_endpoint', EMPTY_STRING) or EMPTY_STRING).strip()
    key = str(values.get('azure_openai_key1', EMPTY_STRING) or values.get('azure_openai_key', EMPTY_STRING) or EMPTY_STRING).strip()
    choice_model = str(choice.get('model') or EMPTY_STRING).strip()
    configured_deployment = str(values.get('azure_deployment_name', EMPTY_STRING) or EMPTY_STRING).strip()
    # A CLI request like `--chat azure grok "Hello"` is an alias request, not
    # the literal deployment name and not permission to ignore the alias in favor
    # of the last configured deployment.  Prefer the requested model/alias first;
    # fall back to the configured default only when no alias/model was requested.
    current = str(choice_model or configured_deployment or EMPTY_STRING).strip()
    if current in {'enter-azure-deployment', 'discover-azure-deployments'}:
        current = configured_deployment
    allow_prompt = bool(promptIfUnverified and not choice.get('_one_shot') and _chatInputAvailable())
    rows = _chatDiscoverAzureDeployments(endpoint, key, values, promptManagement=allow_prompt)
    if current and not rows and not allow_prompt:
        resolved_no_rows = _chatResolveAzureDeploymentAlias(current, rows, values)
        if resolved_no_rows and _chatAzureNormalizeAlias(resolved_no_rows) != _chatAzureNormalizeAlias(current):
            values['azure_deployment_name'] = resolved_no_rows
            return resolved_no_rows
        if _chatAzureLooksLikeAlias(current):
            raise RuntimeError(f'Azure deployment alias {current!r} could not be resolved. Trio tried ARM/data-plane deployment discovery but got no usable rows. Run `python start.py --azure-deployments`, run `az login`, or save [azure] {current.lower()}_deployment_name=<actual deployment name such as sora-2-version>.')
        print(f'[TRACE:chatTest] using already-entered Azure deployment without second prompt: {current}', file=sys.stderr, flush=True)
        values['azure_deployment_name'] = current
        return current
    deployment = _chatChooseAzureDeployment(rows, values, current=current, allowPrompt=allow_prompt)
    deployment = str(deployment or EMPTY_STRING).strip()
    if not deployment:
        raise RuntimeError('Azure chatTest requires the exact Azure deployment name before sending.')
    values['azure_deployment_name'] = deployment
    _chatPersistSetting('azure_deployment_name', deployment)
    return deployment


MODEL_CATALOG_CACHE_PATH = Path(SHARED_MODEL_CATALOG_CACHE_PATH)
MODEL_CATALOG_CACHE_VERSION = int(SHARED_MODEL_CATALOG_CACHE_VERSION)
MODEL_CATALOG_NETWORK_TIMEOUT = 20

# Provider model/runtime code lives in models.py.  start.py keeps only these
# aliases so debugger/chat-test surfaces use the exact same model core as Trio UI.

class _MissingSharedModelSymbol:
    DEFAULT_HOST = 'http://127.0.0.1:11434'

    def __init__(self, *args: Any, **kwargs: Any) -> None:
        raise RuntimeError('models.py shared provider symbol is not available; provider/runtime route cannot continue.')


OllamaRuntime: Any = SharedOllamaRuntime if SharedOllamaRuntime is not None else _MissingSharedModelSymbol
ProviderModelCatalog: Any = SharedProviderModelCatalogCore if SharedProviderModelCatalogCore is not None else _MissingSharedModelSymbol


def runStartupAzureDeploymentWarmup(values: dict[str, str] | None = None, *, warn: bool = False) -> dict[str, list[dict[str, Any]]]:
    """Warm Azure deployment rows during launcher startup using the --chat Azure path.

    Trio's Qt menu must never be the first place that attempts Azure deployment
    discovery.  The chat CLI already owns the correct management-token/config
    path, so parent startup uses that same route, writes trio_model_catalog.json,
    and leaves the UI menu to consume a cache/configured deployment only.
    """
    providers: dict[str, list[dict[str, Any]]] = {}
    state = values if isinstance(values, dict) else _chatTestState()
    try:
        endpoint = str(state.get('azure_openai_endpoint', EMPTY_STRING) or EMPTY_STRING).strip()
        api_key = str(state.get('azure_openai_key1', EMPTY_STRING) or state.get('azure_openai_key', EMPTY_STRING) or EMPTY_STRING).strip()
        rows: list[dict[str, Any]] = []
        if endpoint:
            rows = [dict(row) for row in _chatDiscoverAzureDeployments(endpoint, api_key, state, warn=warn, promptManagement=False)]
        configured = str(state.get('azure_deployment_name', EMPTY_STRING) or EMPTY_STRING).strip()
        if configured and not any(str(row.get('api_string') or row.get('name') or EMPTY_STRING).strip() == configured for row in rows):
            rows.insert(0, {
                'display_name': f'Configured Azure deployment {configured}',
                'api_string': configured,
                'name': configured,
                'deployment_name': configured,
                'is_default': True,
                'source': 'configured-startup',
            })
        if rows:
            providers['copilot'] = rows
            try:
                ProviderModelCatalog(state).writeCache(providers, source='startup-azure-warmup')
            except Exception:
                recordException('start.py:model-catalog.azure-warmup.write-cache', sys.exc_info()[1], handled=True)
        print(f'[TRACE:model-catalog] startup Azure deployment warmup rows={len(rows)} configured={int(bool(configured))} cache={MODEL_CATALOG_CACHE_PATH}', file=sys.stderr, flush=True)
    except Exception as error:
        recordException('start.py:model-catalog.azure-warmup', sys.exc_info()[1], handled=True)
        print(f'[WARN:model-catalog] startup Azure deployment warmup failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
    return providers


def runModelCatalogWorker(argv: list[str] | None = None) -> int:
    print(f'[TRACE:model-catalog-worker] started pid={os.getpid()}', file=sys.stderr, flush=True)
    try:
        if SharedProviderModelCatalogCore is None:
            raise RuntimeError('models.py ProviderModelCatalogCore is not available; cannot refresh model catalog.')
        values = _chatTestState()
        startup_azure = runStartupAzureDeploymentWarmup(values, warn=False)
        catalog = ProviderModelCatalog(values)
        providers = catalog.loadLatestDeployableVersions(allowNetwork=True)
        if startup_azure.get('copilot'):
            providers = dict(providers or {})
            providers['copilot'] = startup_azure['copilot']
            catalog.writeCache(providers, source='startup-model-catalog')
        total = sum(len(rows) for rows in providers.values())
        print(f'[TRACE:model-catalog-worker] complete providers={len(providers)} rows={total} cache={MODEL_CATALOG_CACHE_PATH}', file=sys.stderr, flush=True)
        return 0
    except BaseException as error:
        recordException('start.py:model-catalog-worker', sys.exc_info()[1], handled=False)
        print('[FATAL:model-catalog-worker] ' + ''.join(traceback.format_exception(type(error), error, error.__traceback__)), file=sys.stderr, flush=True)
        return 1


def modelCatalogWorkerRequested(argv: list[str] | None = None) -> bool:
    return bool(cliHasAnyFlag(list(argv or []), MODEL_CATALOG_WORKER_FLAGS) or str(os.environ.get('TRIO_MODEL_CATALOG_WORKER', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'})


def runAzureDeploymentsList(argv=None) -> int:
    try:
        values = _chatTestState()
        _chatEnsureAzureManagementSettings(values, promptMissing=True)
        rows = _chatAzureManagementDeploymentRows(values)
        print('=== Azure OpenAI deployments ===', flush=True)
        if not rows:
            print('No deployments were returned. Check tenant/client/subscription/resource group/account permissions.', flush=True)
            return 1
        for index, row in enumerate(rows, start=1):
            name = str(row.get('name') or EMPTY_STRING)
            model = str(row.get('model') or EMPTY_STRING)
            version = str(row.get('version') or EMPTY_STRING)
            sku = str(row.get('sku') or EMPTY_STRING)
            status = str(row.get('status') or EMPTY_STRING)
            detail = ' '.join(part for part in (model, version, sku, status) if part)
            print(f'{index}) {name}' + (f' ({detail})' if detail else EMPTY_STRING), flush=True)
        return 0
    except BaseException as error:
        recordException('start.py:azure-deployments-list', sys.exc_info()[1], handled=False)
        print('[FATAL:azure-deployments] ' + ''.join(traceback.format_exception(type(error), error, error.__traceback__)), file=sys.stderr, flush=True)
        return 1


def azureDeploymentsRequested(argv: list[str] | None = None) -> bool:
    return bool(cliHasAnyFlag(list(argv or []), AZURE_DEPLOYMENTS_FLAGS))

def _chatLoadProviderRows(values: dict[str, str], provider: str) -> list[dict[str, Any]]:
    if SharedProviderModelCatalogCore is None:
        raise RuntimeError('models.py ProviderModelCatalogCore is not available; cannot discover provider models.')
    return [dict(row) for row in ProviderModelCatalog(values).loadProvider(provider, allowNetwork=True)]


def _chatTestModels(values: dict[str, str]) -> list[dict[str, Any]]:
    catalog = ProviderModelCatalog(values)
    providers = catalog.loadLatestDeployableVersions(allowNetwork=True)
    # Azure is deployment-based. Ensure Azure is always present and appears
    # before Gemini, even if deployment discovery could not run yet. This
    # prevents numeric choices from silently moving Microsoft Azure onto a
    # Google Gemini row.
    providers = dict(providers or {})
    configured = str(values.get('azure_deployment_name', EMPTY_STRING) or EMPTY_STRING).strip()
    copilot_rows = list(providers.get('copilot') or [])
    if configured and not any(str(row.get('api_string') or row.get('name') or EMPTY_STRING).strip() == configured for row in copilot_rows if isinstance(row, dict)):
        copilot_rows.insert(0, {
            'display_name': f'Configured Azure deployment {configured}',
            'api_string': configured,
            'name': configured,
            'is_default': True,
            'source': 'configured',
        })
        providers['copilot'] = copilot_rows
    if not providers.get('copilot'):
        providers['copilot'] = [{
            'display_name': f'Configured Azure deployment {configured}' if configured else 'Azure: discover/select deployment',
            'api_string': configured or 'enter-azure-deployment',
            'is_default': True,
            'source': 'configured' if configured else 'prompt',
        }]
    choices = catalog.chatChoices(providers)
    if not any(str(choice.get('kind') or EMPTY_STRING) == 'azure' for choice in choices):
        insert_at = 0
        for idx, choice in enumerate(choices):
            if str(choice.get('kind') or EMPTY_STRING) == 'openai':
                insert_at = idx + 1
        choices.insert(insert_at, {'provider': 'Azure', 'label': 'Azure: discover/select deployment', 'model': 'enter-azure-deployment', 'kind': 'azure', 'source': 'forced-prompt'})
    if not choices:
        return [{'provider': 'Azure', 'label': 'Azure: discover/select deployment', 'model': 'enter-azure-deployment', 'kind': 'azure', 'source': 'fallback'}]
    # Keep the old muscle-memory slot useful: first five ChatGPT rows, then
    # Azure deployments. Extra OpenAI rows still appear dynamically below Azure.
    openai_rows = [choice for choice in choices if str(choice.get('kind') or EMPTY_STRING) == 'openai']
    azure_rows = [choice for choice in choices if str(choice.get('kind') or EMPTY_STRING) == 'azure']
    gemini_rows = [choice for choice in choices if str(choice.get('kind') or EMPTY_STRING) == 'gemini']
    claude_rows = [choice for choice in choices if str(choice.get('kind') or EMPTY_STRING) == 'anthropic']
    ollama_rows = [choice for choice in choices if str(choice.get('kind') or EMPTY_STRING) == 'ollama']
    other_rows = [choice for choice in choices if str(choice.get('kind') or EMPTY_STRING) not in {'openai', 'azure', 'gemini', 'anthropic', 'ollama'}]
    return openai_rows[:5] + azure_rows + openai_rows[5:] + gemini_rows + claude_rows + ollama_rows + other_rows


def _chatResolveChoice(raw_choice: str, choices: list[dict[str, Any]]) -> tuple[int, dict[str, Any]]:
    raw = str(raw_choice or EMPTY_STRING).strip()
    lowered = raw.lower().replace('-', '').replace('_', '').replace(' ', EMPTY_STRING)
    provider_aliases = {
        'azure': {'azure', 'az', 'ms', 'microsoft', 'microsoftazure', 'azureopenai', 'azure-openai', 'copilot'},
        'openai': {'openai', 'chatgpt', 'chatgtp', 'gpt', 'gtp'},
        'gemini': {'gemini', 'google', 'googlegemini'},
        'anthropic': {'anthropic', 'claude'},
        'ollama': {'ollama', 'llama', 'local'},
    }
    if lowered:
        for kind, aliases in provider_aliases.items():
            if lowered in aliases:
                for index, choice in enumerate(choices, start=1):
                    if str(choice.get('kind') or EMPTY_STRING) == kind:
                        return index, choice
    if lowered.isdigit():
        selected_index = int(lowered)
        if 1 <= selected_index <= len(choices):
            selected = choices[selected_index - 1]
            # Legacy compatibility: older TrioDesktop menus put Azure at 6.
            # If dynamic fallback rows moved Azure and made 6 select Gemini,
            # prefer the explicit historical Azure slot over a wrong-provider key prompt.
            if selected_index == 6 and str(selected.get('kind') or EMPTY_STRING) != 'azure':
                for index, choice in enumerate(choices, start=1):
                    if str(choice.get('kind') or EMPTY_STRING) == 'azure':
                        print(f'[WARN:chatTest] legacy choice 6 mapped to Azure at current menu item {index}; type gemini/google to intentionally choose Gemini.', file=sys.stderr, flush=True)
                        return index, choice
            return selected_index, selected
    raise ValueError(f'model choice out of range or unknown provider: {raw_choice}')


def _chatBuildRequest(choice: dict[str, Any], message: str, values: dict[str, str]) -> tuple[str, dict[str, str], dict[str, Any]]:
    kind = str(choice.get('kind') or EMPTY_STRING)
    model = str(choice.get('model') or EMPTY_STRING)
    if kind == 'openai':
        key = _chatPromptRequired(values, 'openai_api_key', 'OpenAI API key', secret=True)
        if model in {'discover-openai-models', 'enter-openai-model', EMPTY_STRING} or not model:
            discovered = _chatLoadProviderRows(values, 'gpt')
            if discovered:
                print('OpenAI models found:', flush=True)
                for index, row in enumerate(discovered, 1):
                    print(f'  {index}) {row.get("display_name")} [{row.get("api_string")}]', flush=True)
                raw = input('OpenAI model number or exact model id: ').strip()
                if raw.isdigit() and 1 <= int(raw) <= len(discovered):
                    model = str(discovered[int(raw) - 1].get('api_string') or EMPTY_STRING).strip()
                elif raw:
                    model = raw
            if not model or model in {'discover-openai-models', 'enter-openai-model'}:
                model = _chatPromptRequired(values, 'openai_model_choice', 'OpenAI model id')
        if SharedOpenAIModelCore is None:
            raise RuntimeError('models.py OpenAIModelCore is not available; cannot build OpenAI request.')
        return requiredSharedOpenAIModelCore()(values).buildResponsesRequest(model, message, api_key=key)
    if kind == 'azure':
        endpoint = _chatPromptRequired(values, 'azure_openai_endpoint', 'Azure endpoint URL')
        endpoint = _chatSanitizeAzureEndpoint(endpoint, values, persist=True)
        key = _chatPromptRequired(values, 'azure_openai_key1', 'Azure API key', secret=True)
        deployment = _chatEnsureAzureDeploymentChoice(choice, values, promptIfUnverified=False)
        if key and not str(values.get('azure_openai_key', EMPTY_STRING) or EMPTY_STRING).strip():
            values['azure_openai_key'] = key
            _chatPersistSetting('azure_openai_key', key)
        model = str(deployment or model or EMPTY_STRING).strip()
        if not endpoint or not key or not model:
            raise RuntimeError('Azure chatTest requires endpoint, API key, and deployment before sending.')
        if SharedAzureOpenAIModelCore is None:
            raise RuntimeError('models.py AzureOpenAIModelCore is not available; cannot build Azure request.')
        # Public `start.py --chat azure ...` is a simple command-line chat tool,
        # so use Azure's deployment chat-completions route first.  The Responses
        # API is richer for the GUI, but several Foundry deployments reject it
        # with 400/404 even though chat completions works.
        return requiredSharedAzureOpenAIModelCore()(values).buildLegacyChatCompletionsRequest(model, _chatProviderMessages(message, tools_enabled=False), endpoint=endpoint, api_key=key)
    if kind == 'gemini':
        key = _chatPromptRequired(values, 'gemini_api_key', 'Gemini API key', secret=True)
        if model in {'discover-gemini-models', 'enter-gemini-model', EMPTY_STRING} or not model:
            discovered = _chatLoadProviderRows(values, 'gemini')
            if discovered:
                print('Gemini models found:', flush=True)
                for index, row in enumerate(discovered, 1):
                    print(f'  {index}) {row.get("display_name")} [{row.get("api_string")}]', flush=True)
                raw = input('Gemini model number or exact model id: ').strip()
                if raw.isdigit() and 1 <= int(raw) <= len(discovered):
                    model = str(discovered[int(raw) - 1].get('api_string') or EMPTY_STRING).strip()
                elif raw:
                    model = raw
            if not model or model in {'discover-gemini-models', 'enter-gemini-model'}:
                model = _chatPromptRequired(values, 'gemini_model_choice', 'Gemini model id')
        if SharedGeminiModelCore is None:
            raise RuntimeError('models.py GeminiModelCore is not available; cannot build Gemini request.')
        return requiredSharedGeminiModelCore()(values).buildGenerateContentRequest(model, message, api_key=key)
    if kind == 'anthropic':
        key = _chatPromptRequired(values, 'anthropic_api_key', 'Anthropic/Claude API key', secret=True)
        if model in {'discover-claude-models', 'enter-claude-model', EMPTY_STRING} or not model:
            discovered = _chatLoadProviderRows(values, 'claude')
            if discovered:
                print('Claude models found:', flush=True)
                for index, row in enumerate(discovered, 1):
                    print(f'  {index}) {row.get("display_name")} [{row.get("api_string")}]', flush=True)
                raw = input('Claude model number or exact model id: ').strip()
                if raw.isdigit() and 1 <= int(raw) <= len(discovered):
                    model = str(discovered[int(raw) - 1].get('api_string') or EMPTY_STRING).strip()
                elif raw:
                    model = raw
            if not model or model in {'discover-claude-models', 'enter-claude-model'}:
                model = _chatPromptRequired(values, 'anthropic_model_choice', 'Claude model id')
        if SharedClaudeModelCore is None:
            raise RuntimeError('models.py ClaudeModelCore is not available; cannot build Claude request.')
        return requiredSharedClaudeModelCore()(values).buildMessagesRequest(model, message, api_key=key)
    if SharedOllamaRuntime is None:
        raise RuntimeError('models.py OllamaRuntime is not available; cannot build Ollama request.')
    runtime = requiredSharedOllamaRuntime()(values)
    host = runtime.ensureRunning(startIfNeeded=True) or runtime.normalizeHost(values.get('ollama_host') or getattr(requiredSharedOllamaRuntime(), 'DEFAULT_HOST', 'http://127.0.0.1:11434'))
    values['ollama_host'] = host
    _chatPersistSetting('ollama_host', host)
    if not model or model in {'discover-ollama-models', 'enter-ollama-model'}:
        rows = runtime.listModels(startIfNeeded=True)
        if rows:
            print('Ollama models found:', flush=True)
            for index, row in enumerate(rows, 1):
                print(f'  {index}) {row.get("display_name")} [{row.get("api_string")}]', flush=True)
            raw = input('Ollama model number or exact model id: ').strip()
            if raw.isdigit() and 1 <= int(raw) <= len(rows):
                model = str(rows[int(raw) - 1].get('api_string') or EMPTY_STRING).strip()
            elif raw:
                model = raw
        else:
            print('[WARN:ollama] No installed Ollama models were discovered. If Ollama is installed but not on PATH, set OLLAMA_EXE or config [ollama] executable.', file=sys.stderr, flush=True)
        if not model or model in {'discover-ollama-models', 'enter-ollama-model'}:
            current_default = str(values.get('ollama_model_choice') or EMPTY_STRING).strip()
            prompt = 'Ollama exact installed model id' + (f' [{current_default}]' if current_default else EMPTY_STRING)
            raw_model = input(prompt + ': ').strip()
            model = raw_model or current_default or 'gpt-oss:20b'
    if model:
        values['ollama_model_choice'] = model
        _chatPersistSetting('ollama_model_choice', model)
    if SharedOllamaModelCore is None:
        raise RuntimeError('models.py OllamaModelCore is not available; cannot build Ollama request.')
    return requiredSharedOllamaModelCore()(values).buildGenerateRequest(model, message, host=host)


def _chatMaskedHeaders(headers: dict[str, str]) -> dict[str, str]:
    safe: dict[str, str] = {}
    for key, value in dict(headers or {}).items():
        lower = str(key or EMPTY_STRING).lower()
        text = str(value or EMPTY_STRING)
        if any(token in lower for token in ('key', 'authorization', 'token')):
            if text.lower().startswith('bearer '):
                safe[str(key)] = 'Bearer ' + _maskSecret(text[7:].strip())
            else:
                safe[str(key)] = _maskSecret(text)
        else:
            safe[str(key)] = text
    return safe


def _chatPrintBlock(title: str, payload: Any, color: str = STATUS_COLOR_BLUE) -> None:
    print(color + str(title or EMPTY_STRING) + STATUS_COLOR_RESET, flush=True)
    if isinstance(payload, (dict, list)):
        rendered_payload = json.dumps(payload, indent=2, ensure_ascii=False)
        print(color + rendered_payload + STATUS_COLOR_RESET, flush=True)
    else:
        rendered_payload = str(payload or EMPTY_STRING)
        print(color + rendered_payload + STATUS_COLOR_RESET, flush=True)
    _flatlineV1274AzureLog(str(title or EMPTY_STRING), rendered_payload)


def _flatlineV1274AzureLog(title: str, payload: Any = EMPTY_STRING) -> None:
    """Mirror chat/Azure diagnostics into the centralized root debug.log."""
    try:
        stamp = datetime.datetime.now().isoformat(sep=' ', timespec='seconds')
        rendered = json.dumps(payload, indent=2, ensure_ascii=False) if isinstance(payload, (dict, list)) else str(payload or EMPTY_STRING)
        RuntimeLog.log(f'\n[{stamp}] [azure] {title}\n{rendered}\n', flush=True, channel='azure')
    except Exception as error:
        recordException('start.py:flatline-v1274-azure-log', error, handled=True)




# --- FlatLine v1274 rediff pass2: one-shot chat compatibility ---
def _chatOneShotArgs(argv=None) -> dict[str, str] | None:
    """Parse v1274-style one-shot chat args without replacing Trio's richer chat UI.

    Supported shapes:
      --chat "message"
      --chat provider "message"
      --chat provider model-or-deployment "message"
      --chat grok "message"  # Azure shortcut/deployment alias
    """
    raw_tokens = [str(item or EMPTY_STRING).strip() for item in list(argv or [])]
    ignored_flags = set(globals().get('CHAT_TEST_FLAGS', set())) | set(globals().get('CHAT_TEST_WORKER_FLAGS', set()))
    ignored_flags.update({'--chat', '-chat', '/chat', 'chat', '--testchat', '-testchat', '/testchat', 'testchat'})
    clean: list[str] = []
    files: list[str] = []
    i = 0
    while i < len(raw_tokens):
        token = raw_tokens[i]
        lowered = token.lower().strip()
        if not token or lowered in ignored_flags:
            i += 1
            continue
        if lowered.startswith('--chat-test-worker') or lowered.startswith('--testchat-worker') or lowered.startswith('--chat-worker'):
            i += 1
            continue
        if lowered in ('--file', '-file', '/file', '--files', '-files', '/files'):
            # Collect all following non-flag tokens as file paths
            i += 1
            while i < len(raw_tokens) and not raw_tokens[i].startswith('-'):
                files.append(raw_tokens[i])
                i += 1
            continue
        if lowered.startswith('--') or lowered.startswith('-') or lowered.startswith('/'):
            # Leave unrelated options out of the message so normal launcher flags do not get sent to providers.
            i += 1
            continue
        clean.append(token)
        i += 1
    if not clean:
        return None
    provider_aliases = {
        'openai': 'openai', 'chatgpt': 'openai', 'chatgtp': 'openai', 'gtp': 'openai', 'gpt': 'openai',
        'gpt4o': 'openai', 'gpt-4o': 'openai', 'gpt5': 'openai', 'gpt-5': 'openai',
        'azure': 'azure', 'az': 'azure', 'ms': 'azure', 'microsoft': 'azure', 'copilot': 'azure', 'azureopenai': 'azure', 'azure-openai': 'azure',
        'gemini': 'gemini', 'google': 'gemini',
        'claude': 'anthropic', 'anthropic': 'anthropic',
        'ollama': 'ollama', 'llama': 'ollama', 'local': 'ollama',
    }
    # These are Azure deployment aliases only.  They intentionally remain
    # aliases like `grok` / `deepseek`, not guessed deployment names.  The send
    # path resolves them against the actual Azure deployment list/cache/settings.
    # ChatGPT/GPT aliases must stay OpenAI unless the user explicitly says
    # `--chat azure ...`; mapping them to Azure made `--chat chatgtp` hit the
    # wrong provider and return Azure 400s.
    azure_shortcuts = {
        'grok': 'grok', 'grok4': 'grok', 'grok-4': 'grok', 'grok-4-20': 'grok', 'xai': 'grok',
        'gpt5chat': 'gpt5chat', 'gpt-5-chat': 'gpt5chat', 'azure-gpt': 'azuregpt', 'azuregpt': 'azuregpt',
        'gpt5.5': 'gpt5.5', 'gpt-5.5': 'gpt5.5',
        'codex': 'codex', 'gpt5codex': 'codex', '5codex': 'codex', 'gpt-5-codex': 'codex',
        'sora': 'sora', 'sora2': 'sora',
        'deepseek': 'deepseek', 'deepseek-r1': 'deepseek',
        'kimi': 'kimi', 'kimi-k2': 'kimi',
    }
    provider = EMPTY_STRING
    model = EMPTY_STRING
    remaining = list(clean)
    first = remaining[0].lower().strip() if remaining else EMPTY_STRING
    if first in azure_shortcuts:
        provider = 'azure'
        model = azure_shortcuts[first]
        remaining.pop(0)
    elif first in provider_aliases:
        provider = provider_aliases[first]
        remaining.pop(0)
    if provider and remaining:
        second = remaining[0].lower().strip()
        if provider == 'azure' and second in azure_shortcuts:
            model = azure_shortcuts[second]
            remaining.pop(0)
        elif len(remaining) >= 2:
            model = remaining.pop(0)
    message = ' '.join(remaining).strip()
    if not message and provider:
        return None
    if not message and clean:
        message = ' '.join(clean).strip()
    if not message:
        return None
    return {'provider': provider, 'model': model, 'message': message, 'files': files}


def _chatChoiceForOneShot(choices: list[dict[str, Any]], request: dict[str, str]) -> dict[str, Any]:
    provider = str(request.get('provider') or EMPTY_STRING).strip().lower()
    model = str(request.get('model') or EMPTY_STRING).strip()
    if not choices:
        raise RuntimeError('No chatTest provider choices are available.')
    if provider:
        for choice in choices:
            if str(choice.get('kind') or EMPTY_STRING).strip().lower() == provider:
                selected = dict(choice)
                if model:
                    selected['model'] = model
                    selected['api_string'] = model
                    selected['label'] = f"{selected.get('provider', provider)} {model}"
                return selected
        raise ValueError(f'No chatTest provider choice matches one-shot provider: {provider}')
    selected = dict(choices[0])
    if model:
        selected['model'] = model
        selected['api_string'] = model
    return selected
