def _fontMetricSnapshot(font: Any) -> dict[str, str]:
    snapshot: dict[str, str] = {}
    try:
        for table_name, attrs in {
            'head': ('unitsPerEm', 'xMin', 'yMin', 'xMax', 'yMax'),
            'hhea': ('ascent', 'descent', 'lineGap', 'advanceWidthMax'),
            'OS/2': ('xAvgCharWidth', 'sTypoAscender', 'sTypoDescender', 'sTypoLineGap', 'usWinAscent', 'usWinDescent'),
            'post': ('isFixedPitch', 'italicAngle'),
        }.items():
            if table_name in font:
                table = font[table_name]
                for attr in attrs:
                    if hasattr(table, attr):
                        snapshot[f'{table_name}.{attr}'] = _formatFontMetricValue(getattr(table, attr))
    except Exception as error:
        recordException('start.py:flatline-v1274-font-metric-snapshot', error, handled=True)
    return snapshot


