def ensurePackage(pip_name: str, import_name: str | None = None, timeout: int = 120) -> bool:
    module_name = str(import_name or pip_name or EMPTY_STRING).strip()
    if module_name:
        try:
            import importlib as _importlib
            _importlib.import_module(module_name)
            return True
        except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
            pass
    if dependencyInstallDisabled(sys.argv[1:]):
        print(f'[Dependency:WARN] {pip_name} unavailable and dependency install is disabled.', file=sys.stderr, flush=True)
        return False
    try:
        registry = StartDependencyRegistry(sys.argv[1:])
        return bool(registry.installPythonPackage(str(pip_name), timeout=int(timeout or 120)))
    except Exception as error:
        recordException('start.py:flatline-v1274-ensure-package', error, handled=True)
        return False


def _parseGlyphCodepoint(raw: str) -> int | None:
    text = str(raw or EMPTY_STRING).strip()
    if not text:
        return None
    try:
        if text.upper().startswith('U+'):
            return int(text[2:], 16)
        if text.lower().startswith('0x'):
            return int(text, 16)
        if text.startswith('&#') and text.endswith(';'):
            body = text[2:-1]
            return int(body[1:], 16) if body.lower().startswith('x') else int(body)
        return int(text)
    except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
        if len(text) == 1:
            return ord(text)
        return None


def renderGlyphToPng(font_path: Path, codepoint: int, output_path: Path | None = None, size: int = 256) -> Path | None:
    """Render one glyph to a transparent PNG using Pillow as the launcher fallback."""
    if not ensurePackage('Pillow', 'PIL'):
        return None
    from PIL import Image, ImageFont, ImageDraw
    char = chr(int(codepoint))
    output = Path(output_path or (BASE_DIR / 'fonts' / f'glyph_U+{int(codepoint):04X}.png'))
    output.parent.mkdir(parents=True, exist_ok=True)
    image = Image.new('RGBA', (int(size), int(size)), (0, 0, 0, 0))
    draw = ImageDraw.Draw(image)
    font = ImageFont.truetype(str(font_path), int(size * 0.75))
    draw.text((int(size * 0.1), int(size * 0.05)), char, font=font, fill=(255, 255, 255, 255))
    image.save(str(output))
    return output


def extractGlyphToPng(font_path: Path, codepoint: int, output_path: Path | None = None, size: int = 256) -> Path | None:
    try:
        return renderGlyphToPng(Path(font_path), int(codepoint), output_path=output_path, size=int(size or 256))
    except NameError:
        if not ensurePackage('Pillow', 'PIL'):
            return None
        from PIL import Image, ImageFont, ImageDraw
        char = chr(int(codepoint))
        output = Path(output_path or (BASE_DIR / 'fonts' / f'glyph_U+{int(codepoint):04X}.png'))
        output.parent.mkdir(parents=True, exist_ok=True)
        image = Image.new('RGBA', (int(size), int(size)), (0, 0, 0, 0))
        draw = ImageDraw.Draw(image)
        font = ImageFont.truetype(str(font_path), int(size * 0.75))
        draw.text((int(size * 0.1), int(size * 0.05)), char, font=font, fill=(255, 255, 255, 255))
        image.save(str(output))
        return output
    except Exception as error:
        recordException('start.py:flatline-v1274-extract-glyph', error, handled=True)
        print(f'[Font:ERROR] glyph extraction failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        return None


