def _insertProcessRows(command, ttl=None) -> dict[str, int]:
    """v1274 process-row helper implemented through TrioDesktop's ORM layer.

    The incoming Claude branch used a second raw sqlite table writer here. Keep the
    public helper behavior, but route it through ProcessRecordOrm and
    DebuggerProcessRecordOrm so the launcher still has one database abstraction.
    """
    ids: dict[str, int] = {}
    try:
        _ensureProcessTables()
        db = Database.ForSqlitePath(_processDbPath())
        now = datetime.datetime.now()
        text = _launcherCommandText(command)
        payload = dict(
            created=now,
            phaseKey=0,
            phaseName='start-wrapper',
            processName='Subprocess',
            pid=None,
            ttlSeconds=float(ttl) if ttl is not None else None,
            startedAt=now,
            status='starting',
            commandText=text,
            cwd=str(Path.cwd()),
            updatedAt=now,
            metaJson=json.dumps({'command': text}, ensure_ascii=False),
        )
        with db.Session() as session:
            row = ProcessRecordOrm(**payload)
            debugger_row = DebuggerProcessRecordOrm(**payload)
            session.add(row)
            session.add(debugger_row)
            session.flush()
            ids['processes'] = int(getattr(row, 'id', 0) or 0)
            ids['debugger_processes'] = int(getattr(debugger_row, 'id', 0) or 0)
        return ids
    except Exception as error:
        recordException('start.py:flatline-v1274-insert-process-rows', error, handled=True)
        return ids


def _updateProcessRows(ids: dict[str, int], status: str, pid=None, error: str = EMPTY_STRING) -> None:
    """v1274 process-row updater implemented through TrioDesktop's ORM layer."""
    if not ids:
        return
    try:
        db = Database.ForSqlitePath(_processDbPath())
        now = datetime.datetime.now()
        model_by_table = {'processes': ProcessRecordOrm, 'debugger_processes': DebuggerProcessRecordOrm}
        with db.Session() as session:
            for table, row_id in dict(ids or {}).items():
                model = model_by_table.get(str(table))
                if model is None or int(row_id or 0) <= 0:
                    continue
                row = session.get(model, int(row_id))
                if row is None:
                    continue
                row.status = str(status or 'errored')
                if pid is not None:
                    row.pid = int(pid or 0) or None
                if str(status or EMPTY_STRING).lower() not in {'running', 'starting', 'pending'}:
                    row.endedAt = now
                row.updatedAt = now
                if error:
                    row.errorMessage = str(error)
                try:
                    if getattr(row, 'startedAt', None):
                        started = getattr(row, 'startedAt')
                        row.runtimeSeconds = max(0.0, (now - started).total_seconds())
                except Exception:
                    recordException('start.py:flatline-v1274-update-process-runtime', sys.exc_info()[1], handled=True)
            session.flush()
    except Exception as error_obj:
        recordException('start.py:flatline-v1274-update-process-rows', error_obj, handled=True)


