def runApiTest(argv=None) -> int:
    launch_args = list(argv or [])
    option = readCliOption(launch_args, API_TEST_FLAGS, takesValue=True, knownAliases=START_VALID_CLI_ALIASES)
    prompt = str(option.get('value', EMPTY_STRING) or EMPTY_STRING).strip() or DEFAULT_API_TEST_PROMPT
    values = _apiTestState()
    rows = []
    openai_key = str(values.get('openai_api_key', EMPTY_STRING) or EMPTY_STRING).strip()
    if openai_key:
        model = str(values.get('openai_model_choice', EMPTY_STRING) or values.get('gpt_model_choice', EMPTY_STRING) or 'gpt-4.1-mini').strip()
        url, headers, payload = requiredSharedOpenAIModelCore()(values).buildResponsesRequest(model, prompt, api_key=openai_key)
        status, body = _httpJsonRequest(url, payload, headers)
        rows.append(('openai', status, body[:600]))
        traceCompilerStep('api-test-openai', 200 <= status < 300, f'status={status} key={_maskSecret(openai_key)} model={model}')
    gemini_key = str(values.get('gemini_api_key', EMPTY_STRING) or EMPTY_STRING).strip()
    if gemini_key:
        model = str(values.get('gemini_model_choice', EMPTY_STRING) or 'gemini-2.0-flash').strip()
        url, headers, payload = requiredSharedGeminiModelCore()(values).buildGenerateContentRequest(model, prompt, api_key=gemini_key)
        status, body = _httpJsonRequest(url, payload, headers)
        rows.append(('gemini', status, body[:600]))
        traceCompilerStep('api-test-gemini', 200 <= status < 300, f'status={status} key={_maskSecret(gemini_key)} model={model}')
    anthropic_key = str(values.get('anthropic_api_key', EMPTY_STRING) or EMPTY_STRING).strip()
    if anthropic_key:
        model = str(values.get('anthropic_model_choice', EMPTY_STRING) or 'claude-3-5-haiku-latest').strip()
        url, headers, payload = requiredSharedClaudeModelCore()(values).buildMessagesRequest(model, prompt, api_key=anthropic_key)
        status, body = _httpJsonRequest(url, payload, headers)
        rows.append(('anthropic', status, body[:600]))
        traceCompilerStep('api-test-anthropic', 200 <= status < 300, f'status={status} key={_maskSecret(anthropic_key)} model={model}')
    azure_endpoint = str(values.get('azure_openai_endpoint', EMPTY_STRING) or EMPTY_STRING).strip().rstrip('/')
    azure_key = str(values.get('azure_openai_key1', EMPTY_STRING) or values.get('azure_openai_key', EMPTY_STRING) or EMPTY_STRING).strip()
    azure_model = str(values.get('azure_deployment_name', EMPTY_STRING) or EMPTY_STRING).strip()
    if azure_endpoint and azure_key:
        url, headers, payload = requiredSharedAzureOpenAIModelCore()(values).buildResponsesRequest(azure_model, prompt, endpoint=azure_endpoint, api_key=azure_key)
        status, body = _httpJsonRequest(url, payload, headers)
        rows.append(('azure', status, body[:600]))
        traceCompilerStep('api-test-azure', 200 <= status < 300, f'status={status} endpoint={azure_endpoint} model={azure_model} key={_maskSecret(azure_key)}')
    try:
        runtime = requiredSharedOllamaRuntime()(values)
        ollama_host = runtime.ensureRunning(startIfNeeded=False)
        ollama_rows = runtime.listModels(startIfNeeded=False)
        status = 200 if ollama_rows else 404
        body = json.dumps({'host': ollama_host, 'models': ollama_rows}, ensure_ascii=False)
        rows.append(('ollama', status, body[:600]))
        traceCompilerStep('api-test-ollama', 200 <= status < 300, f'status={status} host={ollama_host}')
    except Exception as error:
        recordException('start.py:api-test-ollama', sys.exc_info()[1])
        traceCompilerStep('api-test-ollama', False, f'{type(error).__name__}: {error}')
    print('=== API TEST RESULTS ===', flush=True)
    for provider, status, snippet in rows:
        print(f'[{provider}] status={status}', flush=True)
        print(snippet, flush=True)
        print('-', flush=True)
    return 0 if rows else 1


