def pluginRegistryNames() -> list[str]:
    names: list[str] = []
    seen: set[str] = set()
    for plugin in allPlugins():
        key = plugin.getPluginName()
        if key in seen:
            continue
        seen.add(key)
        names.append(key)
    return names


def discoverPluginsDetailed(names: list[str] | tuple[str, ...] | None = None, *, install_if_missing: bool = False) -> list[dict[str, str]]:
    requested = [str(name or EMPTY_STRING).strip().lower() for name in list(names or pluginRegistryNames()) if str(name or EMPTY_STRING).strip()]
    rows: list[dict[str, str]] = []
    seen: set[str] = set()
    for name in requested:
        if name in seen:
            continue
        seen.add(name)
        plugin = pluginNamed(name)
        if plugin is None:
            rows.append({
                'name': name,
                'display_name': name,
                'path': EMPTY_STRING,
                'detail': f'[Plugin] Unknown plugin: {name}',
                'status': 'missing',
                'version': EMPTY_STRING,
            })
            continue
        path_text, detail = plugin.find(install_if_missing=bool(install_if_missing))
        version_text = plugin._versionFromExecutable(path_text) if path_text else EMPTY_STRING
        rows.append({
            'name': plugin.getPluginName(),
            'display_name': plugin.getName(),
            'path': str(path_text or EMPTY_STRING).strip(),
            'detail': str(detail or EMPTY_STRING),
            'status': 'found' if str(path_text or EMPTY_STRING).strip() else 'missing',
            'version': str(version_text or EMPTY_STRING).strip(),
        })
    return rows


def renderStartupPluginDiscoveryLines(names: list[str] | tuple[str, ...] | None = None, *, install_if_missing: bool = False) -> list[str]:
    rows = discoverPluginsDetailed(names, install_if_missing=install_if_missing)
    rendered = ['Inspecting Environment and Loading Plugins...']
    for row in rows:
        name = str(row.get('name', EMPTY_STRING) or EMPTY_STRING).strip()
        version = str(row.get('version', EMPTY_STRING) or EMPTY_STRING).strip()
        path_text = str(row.get('path', EMPTY_STRING) or EMPTY_STRING).strip()
        if str(row.get('status', EMPTY_STRING) or EMPTY_STRING).strip().lower() == 'found':
            label = f'\x1b[32mFOUND\x1b[0m {name}'
            if version:
                label += f' ({version})'
            if path_text:
                label += f' {path_text}'
            rendered.append(label)
        else:
            rendered.append(f'\x1b[31mMISSING\x1b[0m {name}')
    return rendered


def firstExistingExecutable(names) -> str | None:
    for name in tuple(names or ()):
        found = shutil.which(str(name or EMPTY_STRING))
        if found:
            return found
    return None


def discoverStartupRepoTools(trace_prefix: str = 'startup-tool') -> dict[str, str]:
    discovered: dict[str, str] = {}
    rows = discoverPluginsDetailed(pluginRegistryNames(), install_if_missing=False)
    for line in renderStartupPluginDiscoveryLines(pluginRegistryNames(), install_if_missing=False):
        print(line, flush=True)
    for row in rows:
        name = str(row.get('name', EMPTY_STRING) or EMPTY_STRING).strip()
        executable = str(row.get('path', EMPTY_STRING) or EMPTY_STRING).strip()
        detect_text = str(row.get('detail', EMPTY_STRING) or EMPTY_STRING).strip()
        ok = bool(executable)
        discovered[name] = executable
        traceCompilerStep(f'{trace_prefix}-{name}', ok, detect_text)
    return discovered


def runEnvTest(argv=None) -> int:
    tool_probe_details = {name: locateToolExecutable(name, install_if_missing=False) for name in ('git', 'putty', 'plink', 'pscp', 'psftp')}
    tool_probe_rows = {name: result[0] for name, result in tool_probe_details.items()}
    which_rows = (('python', ('python', 'python3')), ('gh', ('gh',)), ('ollama', ('ollama',)), ('pwsh', ('pwsh', 'pwsh.exe')), ('powershell', ('powershell', 'powershell.exe')), ('gcc', ('gcc',)), ('g++', ('g++',)))
    values = {key: firstExistingExecutable(names) for key, names in which_rows}
    values.update({key: tool_probe_rows.get(key) for key in ('git', 'putty', 'plink', 'pscp', 'psftp')})
    values['python'] = values.get('python') or sys.executable
    notes = {name: result[1] for name, result in tool_probe_details.items()}
    print('=== ENV TEST ===', flush=True)
    for key, value in values.items():
        ok = bool(str(value or EMPTY_STRING).strip())
        detail = notes.get(key) or str(value or '(missing)')
        traceCompilerStep(f'env-test-{key}', ok, detail)
    return 0


