def requiredTTFontClass():
    tt_font_class = TTFont
    if tt_font_class is None:
        raise RuntimeError('fontTools.ttLib is required. Install with: pip install fonttools')
    return cast(Any, tt_font_class)



def _traceKeyValueLine(prefix: str, context: str, source: str, payload: dict[str, object]) -> None:
    parts = [str(prefix), f'context={context}', f'source={source}']
    for key, value in payload.items():
        text = str(value if value is not None else EMPTY_STRING)
        if any(ch.isspace() for ch in text) or text == EMPTY_STRING:
            text = json.dumps(text, ensure_ascii=False)
        parts.append(f'{key}={text}')
    print(' '.join(parts), flush=True)


def _windowsConsoleFontSnapshot() -> dict[str, object]:
    return _getConsoleHostLiveFontDetails()


def _windowsConsoleRegistrySnapshots() -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    if os.name != 'nt':
        return [{'key': 'HKCU\\Console', 'available': 0, 'reason': 'not-windows'}]
    try:
        import winreg as _winreg  # type: ignore
        winreg_any = cast(Any, _winreg)
        if winreg_any is None:
            return [{'key': 'HKCU\\Console', 'available': 0, 'reason': 'winreg-unavailable'}]
        def read_key(path: str) -> dict[str, object]:
            row: dict[str, object] = {'key': 'HKCU\\' + path, 'available': 1}
            try:
                with winreg_any.OpenKey(winreg_any.HKEY_CURRENT_USER, path) as key:
                    for name in ('FaceName', 'LineSpacing', 'FontSize', 'FontFamily', 'FontWeight', 'FontFace', 'ScreenBufferSize'):
                        try:
                            value, value_type = winreg_any.QueryValueEx(key, name)
                            row[name] = value
                            row[name + 'Type'] = int(value_type)
                        except FileNotFoundError:  # swallow-ok: optional console registry value is absent
                            pass
            except FileNotFoundError:
                row['available'] = 0
                row['reason'] = 'missing'
            except Exception as error:
                recordException('start.py:console-registry-read-key', sys.exc_info()[1])
                row['available'] = 0
                row['reason'] = f'{type(error).__name__}:{error}'
            return row
        base = r'Console'
        rows.append(read_key(base))
        try:
            with winreg_any.OpenKey(winreg_any.HKEY_CURRENT_USER, base) as root:
                count = safeInt(winreg_any.QueryInfoKey(root)[0], 0)
                for index in range(count):
                    try:
                        sub = str(winreg_any.EnumKey(root, index))
                    except OSError:  # swallow-ok: registry enum exhausted or entry unreadable
                        continue
                    lower = sub.lower()
                    if 'powershell' in lower or 'pwsh' in lower or 'python' in lower or 'windowsterminal' in lower:
                        rows.append(read_key(base + '\\' + sub))
        except Exception:
            recordException('start.py:console-registry-enum', sys.exc_info()[1])
    except Exception as error:
        recordException('start.py:console-registry-snapshots', sys.exc_info()[1])
        rows.append({'key': 'HKCU\\Console', 'available': 0, 'reason': f'{type(error).__name__}:{error}'})
    return rows


def traceConsoleFontState(context: str = 'startup') -> None:
    ctx = str(context or 'startup')
    _traceKeyValueLine('[TRACE:font-env]', ctx, 'python-process', {
        'executable': sys.executable,
        'python_md5': safeFileMd5Hex(sys.executable),
        'pid': os.getpid(),
        'argv': shlex.join(sys.argv),
        'cwd': str(Path.cwd()),
        'is_tty': int(bool(getattr(sys.stdout, 'isatty', lambda: False)())),
    })
    _traceKeyValueLine('[TRACE:font-env]', ctx, 'terminal-env', {
        'WT_SESSION': os.environ.get('WT_SESSION', EMPTY_STRING),
        'TERM_PROGRAM': os.environ.get('TERM_PROGRAM', EMPTY_STRING),
        'TERM': os.environ.get('TERM', EMPTY_STRING),
        'ComSpec': os.environ.get('ComSpec', EMPTY_STRING),
        'PSModulePath_present': int(bool(os.environ.get('PSModulePath'))),
        'ConEmuPID': os.environ.get('ConEmuPID', EMPTY_STRING),
        'PYTHONINSPECT': os.environ.get('PYTHONINSPECT', EMPTY_STRING),
    })
    for alias in ('fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf'):
        path = BASE_DIR / alias
        _traceKeyValueLine('[TRACE:font-default]', ctx, 'repo-alias', {'alias': alias, 'exists': int(path.exists()), 'path': str(path), 'md5': safeFileMd5Hex(path)})
    _traceKeyValueLine('[TRACE:font-console]', ctx, 'winapi-current-console', _windowsConsoleFontSnapshot())
    for row in _windowsConsoleRegistrySnapshots():
        source = 'registry-powershell-python' if any(token in str(row.get('key', EMPTY_STRING)).lower() for token in ('powershell', 'pwsh', 'python')) else 'registry-console'
        _traceKeyValueLine('[TRACE:font-console]', ctx, source, row)


def managedSubprocessRun(command: list[str], *, cwd: str | Path | None = None, timeout: int = 600, **kwargs) -> subprocess.CompletedProcess:
    return launcherRunCommand(command, cwd=str(cwd) if cwd is not None else None, timeout=timeout, **kwargs)


def lifecycleSubprocessRun(command: list[str], *, cwd: str | Path | None = None, timeout: int = 600, **kwargs) -> subprocess.CompletedProcess:
    return managedSubprocessRun(command, cwd=cwd, timeout=timeout, **kwargs)


def managedSubprocessPopen(command: list[str], *, cwd: str | Path | None = None, **kwargs) -> subprocess.Popen:  # lifecycle-bypass-ok  # phase-ownership-ok
    return launcherStartProcess(command, cwd=str(cwd) if cwd is not None else None, **kwargs)


class Font:
    """Single source of truth for TrioDesktop font inspection and repair."""

    SUPPORTED_SUFFIXES = {'.otf', '.ttf', '.woff', '.woff2', '.wolf2'}
    GLYPH_MAPPING_FIXES = {
        'macron': 0x00AF,
        'macronmod': 0x00AF,
        'overscore': 0x00AF,
        'uni00AF': 0x00AF,
        'u00AF': 0x00AF,
        'u1F525': 0x1F525,
        'uni28FF': 0x28FF,
    }

    def __init__(self, path: Path):
        self.path = Path(path).resolve()
        self.name = self.path.stem
        self.extension = self.path.suffix.lower()
        self.isColor = 'color' in self.name.lower() or 'colour' in self.name.lower()
        self.faceName = self.detectFaceName()

    def detectFaceName(self) -> str:
        if self.isColor:
            return 'default.otf'
        return 'default.otf'

    @classmethod
    def fontsDir(cls) -> Path:
        # Historical builds kept duplicate font copies in /fonts. The canonical
        # runtime fonts are now the obvious root aliases: default.otf and
        # default.otf. Keep this helper for older call sites, but do not
        # create or depend on /fonts.
        return BASE_DIR

    @classmethod
    def discoverAll(cls) -> list['Font']:
        fonts: list[Font] = []
        canonical = [BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH]
        seen: set[str] = set()
        for path in canonical:
            if path.is_file() and path.suffix.lower() in cls.SUPPORTED_SUFFIXES:
                key = str(path.resolve()).lower()
                if key not in seen:
                    fonts.append(cls(path))
                    seen.add(key)
        return fonts

    @staticmethod
    def md5(path: Path) -> str:
        try:
            return hashlib.md5(Path(path).read_bytes()).hexdigest()
        except Exception:
            recordException('start.py:2696', sys.exc_info()[1])
            return EMPTY_STRING

    def backup(self) -> Path | None:
        try:
            folder = self.path.parent / 'backups'
            folder.mkdir(parents=True, exist_ok=True)
            digest = self.md5(self.path)[:12] or 'unknown'
            target = folder / f'{self.path.name}.{digest}.bak'
            if not target.exists():
                File(self.path).copyTo(target)
            return target
        except Exception as error:
            recordException('start.py:2708', sys.exc_info()[1])
            print(f'[WARN:font-repair] backup failed for {self.path.name}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return None

    @staticmethod
    def _configInt(section: str, key: str, default: int, minimum: int, maximum: int) -> int:
        try:
            cfg_factory = globals().get('appConfig')
            cfg = cfg_factory() if callable(cfg_factory) else None
            getter = getattr(cfg, 'getInt', None)
            if callable(getter):
                value = getter(section, key, default=default, minimum=minimum, maximum=maximum)
                return max(int(minimum), min(int(maximum), int(cast(Any, value))))
        except Exception:
            recordException('start.py:2721', sys.exc_info()[1])
            _traceSwallowedException('start.py:2673', sys.exc_info()[1])
            pass
        return int(default)

    @staticmethod
    def repairTargetWidth(default: int = 600) -> int:
        return Font._configInt('terminal_font', 'repair_target_width', default, 40, 900)

    @staticmethod
    def repairAscender(default: int = 800) -> int:
        return Font._configInt('terminal_font', 'repair_ascender', default, 500, 1200)

    @staticmethod
    def repairDescender(default: int = -250) -> int:
        return Font._configInt('terminal_font', 'repair_descender', default, -500, -50)

    def openFont(self):
        if TTFont is None:
            raise RuntimeError('fontTools.ttLib is required. Install with: pip install fonttools')
        return requiredTTFontClass()(str(self.path), recalcBBoxes=False, recalcTimestamp=False)

    def installFont(self, font_name: str | None = None) -> bool:
        """Install this font for the current Windows user and register it live."""
        desired = str(font_name or self.faceName or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        return _installFontForCurrentUser(self.path, desired)

    def installForCurrentUser(self, font_name: str | None = None) -> bool:
        """Compatibility alias used by older FlatLine startup builds."""
        return self.installFont(font_name)


    @staticmethod
    def unicodeCmapTables(font) -> list:
        tables = []
        try:
            cmap_table = font['cmap'] if 'cmap' in font else None
            for table in list(getattr(cmap_table, 'tables', []) or []):
                try:
                    if bool(table.isUnicode()) and hasattr(table, 'cmap'):
                        tables.append(table)
                except Exception:
                    recordException('start.py:2752', sys.exc_info()[1])
                    _traceSwallowedException('start.py:2703', sys.exc_info()[1])
                    continue
        except Exception:
            recordException('start.py:2755', sys.exc_info()[1])
            _traceSwallowedException('start.py:2705', sys.exc_info()[1])
            pass
        return tables

    @staticmethod
    def glyphNamesForCodepoint(font, codepoint: int) -> list[str]:
        names: list[str] = []
        for table in Font.unicodeCmapTables(font):
            try:
                glyph = table.cmap.get(int(codepoint))
                if glyph and str(glyph) not in names:
                    names.append(str(glyph))
            except Exception:
                recordException('start.py:2768', sys.exc_info()[1])
                _traceSwallowedException('start.py:2717', sys.exc_info()[1])
                continue
        return names

    @staticmethod
    def mapCodepoint(font, codepoint: int, glyphName: str) -> bool:
        changed = False
        glyph_text = str(glyphName or EMPTY_STRING).strip()
        if not glyph_text:
            return False
        cp = int(codepoint)
        for table in Font.unicodeCmapTables(font):
            try:
                table_format = int(getattr(table, 'format', 0) or 0)
                if cp > 0xFFFF and table_format not in {12, 13}:
                    continue
                if table.cmap.get(cp) != glyph_text:
                    table.cmap[cp] = glyph_text
                    changed = True
            except Exception:
                recordException('start.py:2788', sys.exc_info()[1])
                _traceSwallowedException('start.py:2736', sys.exc_info()[1])
                continue
        return changed

    @staticmethod
    def removeCodepointForGlyph(font, codepoint: int, glyphName: str) -> bool:
        changed = False
        glyph_text = str(glyphName or EMPTY_STRING).strip()
        for table in Font.unicodeCmapTables(font):
            try:
                if table.cmap.get(int(codepoint)) == glyph_text:
                    del table.cmap[int(codepoint)]
                    changed = True
            except Exception:
                recordException('start.py:2802', sys.exc_info()[1])
                _traceSwallowedException('start.py:2749', sys.exc_info()[1])
                continue
        return changed

    def repairGlyphMappings(self, font) -> tuple[bool, list[str]]:
        changed = False
        notes: list[str] = []
        glyph_order = set(str(item) for item in list(font.getGlyphOrder() or []))
        for glyph_name, codepoint in self.GLYPH_MAPPING_FIXES.items():
            if glyph_name in glyph_order:
                if self.mapCodepoint(font, int(codepoint), glyph_name):
                    changed = True
                    notes.append(f'{glyph_name}->U+{int(codepoint):04X}')
        for wrong_codepoint in (0x02C9,):
            for glyph_name in self.glyphNamesForCodepoint(font, wrong_codepoint):
                lowered = glyph_name.lower().replace('-', '').replace('_', '')
                # Validators complain when a macron-like glyph is encoded as
                # U+02C9 instead of U+00AF. Keep U+00AF covered and remove the
                # wrong modifier-letter mapping so --auto-repair-fonts is useful.
                if 'macron' in lowered or lowered in {'overscore', 'uni00af', 'u00af', 'maron', 'miron', 'maran'}:
                    current_u00af = self.glyphNamesForCodepoint(font, 0x00AF)
                    if not current_u00af and self.mapCodepoint(font, 0x00AF, glyph_name):
                        changed = True
                        notes.append(f'{glyph_name}:U+02C9->U+00AF')
                    if self.removeCodepointForGlyph(font, wrong_codepoint, glyph_name):
                        changed = True
                        notes.append(f'removed wrong macron mapping {glyph_name} from U+02C9')
        best = font.getBestCmap() or {}
        fire_glyph = best.get(0x1F525) or best.get(0x2668) or best.get(0xE525)
        if fire_glyph:
            for codepoint in (0x1F525, 0x2668, 0xE525):
                if self.mapCodepoint(font, codepoint, fire_glyph):
                    changed = True
                    notes.append(f'fire-alias U+{codepoint:04X}')
        for codepoint in range(0x2800, 0x2900):
            if codepoint in best:
                continue
            for candidate in (f'uni{codepoint:04X}', f'u{codepoint:04X}', f'braille{codepoint:04X}'):
                if candidate in glyph_order:
                    if self.mapCodepoint(font, codepoint, candidate):
                        changed = True
                        notes.append(f'braille U+{codepoint:04X}')
                    break
        return changed, notes

    def repairMetrics(self, font) -> tuple[bool, list[str]]:
        target_width = self.repairTargetWidth()
        ascender = self.repairAscender()
        descender = self.repairDescender()
        padding = max(1, min(4, int(target_width * 0.03)))
        usable_width = max(1, int(target_width) - (padding * 2))
        usable_height = max(1, int(ascender) - int(descender))
        changed = False
        notes: list[str] = []
        geometry_changed = 0
        metric_changed = 0
        if 'glyf' in font:
            try:
                glyf = font['glyf']
                hmtx = font['hmtx'].metrics if 'hmtx' in font else {}
                priority_glyph_names: set[str] = set()
                try:
                    best_cmap = font.getBestCmap() or {}
                    priority_codepoints: set[int] = set(range(0x21, 0x7F)) | set(range(0x2500, 0x25A0)) | set(range(0x2800, 0x2900)) | {0x00AF, 0x02C9, 0x1F525, 0x2668, 0xE525}
                    priority_glyph_names = {str(best_cmap.get(cp)) for cp in priority_codepoints if best_cmap.get(cp)}
                except Exception:
                    recordException('start.py:2868', sys.exc_info()[1])
                    priority_glyph_names = set()
                for glyph_name in list(font.getGlyphOrder() or []):
                    if glyph_name not in glyf:
                        continue
                    glyph = glyf[glyph_name]
                    try:
                        glyph.recalcBounds(glyf)
                    except Exception:
                        recordException('start.py:2876', sys.exc_info()[1])
                        _traceSwallowedException('start.py:2822', sys.exc_info()[1])
                        pass
                    x_min = getattr(glyph, 'xMin', None)
                    x_max = getattr(glyph, 'xMax', None)
                    y_min = getattr(glyph, 'yMin', None)
                    y_max = getattr(glyph, 'yMax', None)
                    has_bounds = None not in (x_min, x_max, y_min, y_max)
                    if has_bounds and (str(glyph_name) in priority_glyph_names):
                        x_min_i = safeInt(x_min, 0)
                        x_max_i = safeInt(x_max, 0)
                        y_min_i = safeInt(y_min, 0)
                        y_max_i = safeInt(y_max, 0)
                        width = max(0, x_max_i - x_min_i)
                        height = max(0, y_max_i - y_min_i)
                        skip_scale_names = {'.notdef', '.null', 'nonmarkingreturn', 'space', 'uni0020', 'u0020', 'tab'}
                        is_substantial = (
                            str(glyph_name).lower() not in skip_scale_names
                            and width >= max(4, int(target_width * 0.08))
                            and height >= int(usable_height * 0.22)
                        )
                        scale_x = usable_width / float(width) if width > usable_width and width else 1.0
                        scale_y = usable_height / float(height) if height > usable_height and height else 1.0
                        if is_substantial and width and width < int(usable_width * 0.82):
                            scale_x = min(1.45, usable_width / float(width))
                        if is_substantial and height and height < int(usable_height * 0.88):
                            scale_y = min(1.45, usable_height / float(height))
                        try:
                            coords, _end_pts, _flags = glyph.getCoordinates(glyf)
                            if scale_x != 1.0 or scale_y != 1.0:
                                coords.scale((scale_x, scale_y))
                                try:
                                    coords.toInt()
                                except Exception:
                                    recordException('start.py:2909', sys.exc_info()[1])
                                    _traceSwallowedException('start.py:2854', sys.exc_info()[1])
                                    pass
                                geometry_changed += 1
                                changed = True
                                try:
                                    glyph.recalcBounds(glyf)
                                except Exception:
                                    recordException('start.py:2916', sys.exc_info()[1])
                                    _traceSwallowedException('start.py:2860', sys.exc_info()[1])
                                    pass
                                x_min = getattr(glyph, 'xMin', x_min)
                                x_max = getattr(glyph, 'xMax', x_max)
                                y_min = getattr(glyph, 'yMin', y_min)
                                y_max = getattr(glyph, 'yMax', y_max)
                            dx = 0
                            dy = 0
                            if None not in (x_min, x_max):
                                x_min_i = safeInt(x_min, 0)
                                x_max_i = safeInt(x_max, 0)
                                width = max(0, x_max_i - x_min_i)
                                desired_x_min = int(round((int(target_width) - width) / 2.0))
                                dx = desired_x_min - x_min_i
                            if None not in (y_min, y_max):
                                y_min_i = safeInt(y_min, 0)
                                y_max_i = safeInt(y_max, 0)
                                height = max(0, y_max_i - y_min_i)
                                if height > 0:
                                    desired_y_min = int(round(int(descender) + ((usable_height - height) / 2.0)))
                                    dy = desired_y_min - y_min_i
                                if y_max_i + dy > int(ascender):
                                    dy += int(ascender) - (y_max_i + dy)
                                if y_min_i + dy < int(descender):
                                    dy += int(descender) - (y_min_i + dy)
                            if dx or dy:
                                coords.translate((int(dx), int(dy)))
                                try:
                                    coords.toInt()
                                except Exception:
                                    recordException('start.py:2946', sys.exc_info()[1])
                                    _traceSwallowedException('start.py:2889', sys.exc_info()[1])
                                    pass
                                geometry_changed += 1
                                changed = True
                                try:
                                    glyph.recalcBounds(glyf)
                                except Exception:
                                    recordException('start.py:2953', sys.exc_info()[1])
                                    _traceSwallowedException('start.py:2895', sys.exc_info()[1])
                                    pass
                        except Exception:
                            recordException('start.py:2956', sys.exc_info()[1])
                            _traceSwallowedException('start.py:2897', sys.exc_info()[1])
                            pass
                    if 'hmtx' in font:
                        try:
                            if has_bounds:
                                lsb = safeInt(getattr(glyph, 'xMin', 0), 0)
                            else:
                                raw_metric_pair = hmtx.get(glyph_name, (target_width, 0))
                                if isinstance(raw_metric_pair, (list, tuple)) and len(raw_metric_pair) > 1:
                                    lsb = safeInt(raw_metric_pair[1], 0)
                                else:
                                    lsb = 0
                            new_pair = (safeInt(target_width, 600), safeInt(max(-2, min(2, lsb)), 0))
                            if hmtx.get(glyph_name) != new_pair:
                                hmtx[glyph_name] = new_pair
                                metric_changed += 1
                                changed = True
                        except Exception:
                            recordException('start.py:2974', sys.exc_info()[1])
                            _traceSwallowedException('start.py:2914', sys.exc_info()[1])
                            continue
                if geometry_changed:
                    notes.append(f'glyph outlines packed={geometry_changed} padding={padding}')
                if metric_changed:
                    notes.append(f'hmtx normalized={metric_changed} advance={target_width}')
            except Exception as error:
                recordException('start.py:2981', sys.exc_info()[1])
                notes.append(f'glyf-pack skipped {type(error).__name__}: {error}')
        if 'hhea' in font:
            hhea = font['hhea']
            for attr, value in (('ascent', ascender), ('descent', descender), ('lineGap', 0), ('advanceWidthMax', target_width), ('minLeftSideBearing', -2), ('minRightSideBearing', -2), ('xMaxExtent', target_width)):
                try:
                    if safeInt(getattr(hhea, attr, 0), 0) != safeInt(value, 0):
                        setattr(hhea, attr, safeInt(value, 0))
                        changed = True
                except Exception:
                    recordException('start.py:2990', sys.exc_info()[1])
                    _traceSwallowedException('start.py:2929', sys.exc_info()[1])
                    pass
            notes.append(f'hhea ascent={ascender} descent={descender}')
        if 'OS/2' in font:
            os2 = font['OS/2']
            for attr, value in (('xAvgCharWidth', target_width), ('usWidthClass', 5), ('sTypoAscender', ascender), ('sTypoDescender', descender), ('sTypoLineGap', 0), ('usWinAscent', max(ascender, 0)), ('usWinDescent', abs(min(descender, 0)))):
                try:
                    if safeInt(getattr(os2, attr, 0), 0) != safeInt(value, 0):
                        setattr(os2, attr, safeInt(value, 0))
                        changed = True
                except Exception:
                    recordException('start.py:3001', sys.exc_info()[1])
                    _traceSwallowedException('start.py:2939', sys.exc_info()[1])
                    pass
            try:
                os2.panose.bProportion = 9
                os2.panose.bFamilyType = max(safeInt(getattr(os2.panose, 'bFamilyType', 0), 0), 2)
            except Exception:
                recordException('start.py:3007', sys.exc_info()[1])
                _traceSwallowedException('start.py:2944', sys.exc_info()[1])
                pass
            notes.append(f'OS/2 avg={target_width}')
        if 'post' in font:
            post = font['post']
            try:
                if safeInt(getattr(post, 'isFixedPitch', 0), 0) != 1:
                    post.isFixedPitch = 1
                    changed = True
                    notes.append('post fixed-pitch=1')
            except Exception:
                recordException('start.py:3018', sys.exc_info()[1])
                _traceSwallowedException('start.py:2954', sys.exc_info()[1])
                pass
        if 'head' in font:
            try:
                font['head'].xMin = 0
                font['head'].yMin = safeInt(descender, -250)
                font['head'].xMax = safeInt(target_width, 600)
                font['head'].yMax = safeInt(ascender, 820)
                changed = True
                notes.append(f'head bbox={(0, safeInt(descender, -250), safeInt(target_width, 600), safeInt(ascender, 820))}')
            except Exception:
                recordException('start.py:3029', sys.exc_info()[1])
                _traceSwallowedException('start.py:2964', sys.exc_info()[1])
                pass
        if 'kern' in font:
            try:
                del font['kern']
                changed = True
                notes.append('removed kern table')
            except Exception:
                recordException('start.py:3037', sys.exc_info()[1])
                _traceSwallowedException('start.py:2971', sys.exc_info()[1])
                pass
        return changed, notes

    def repair(self) -> dict[str, object]:
        before = self.md5(self.path)
        result: dict[str, object] = {'path': str(self.path), 'before': before, 'after': before, 'changed': False, 'ok': False, 'notes': []}
        if self.extension not in self.SUPPORTED_SUFFIXES:
            result['notes'] = ['unsupported suffix']
            return result
        self.backup()
        try:
            font = self.openFont()
            glyph_changed, glyph_notes = self.repairGlyphMappings(font)
            metric_changed, metric_notes = self.repairMetrics(font)
            changed = bool(glyph_changed or metric_changed)
            if changed:
                try:
                    font.recalcBBoxes = False
                except Exception:
                    recordException('start.py:3057', sys.exc_info()[1])
                    _traceSwallowedException('start.py:2990', sys.exc_info()[1])
                    pass
                font.save(str(self.path))
            try:
                font.close()
            except Exception:
                recordException('start.py:3063', sys.exc_info()[1])
                _traceSwallowedException('start.py:2995', sys.exc_info()[1])
                pass
            after = self.md5(self.path)
            result.update({'after': after, 'changed': before != after, 'ok': True, 'notes': glyph_notes + metric_notes})
            return result
        except Exception as error:
            recordException('start.py:3069', sys.exc_info()[1])
            result['notes'] = [f'{type(error).__name__}: {error}']
            return result

    def showInfo(self) -> None:
        print(f'{self.name}{self.extension}  face={self.faceName}  md5={self.md5(self.path)}  path={self.path}', flush=True)

    @staticmethod
    def _xmlEscape(value: object) -> str:
        try:
            return html.escape(str(value), quote=True)
        except Exception:
            recordException('start.py:3080', sys.exc_info()[1])
            return EMPTY_STRING

    @staticmethod
    def _tableTagText(font) -> str:
        try:
            return ','.join(str(tag) for tag in list(font.keys() or []))
        except Exception:
            recordException('start.py:3087', sys.exc_info()[1])
            return EMPTY_STRING

    @staticmethod
    def _metricValue(table: object, attr: str, default: object = EMPTY_STRING) -> object:
        try:
            return getattr(table, attr, default)
        except Exception:
            recordException('start.py:3094', sys.exc_info()[1])
            return default

    @staticmethod
    def _glyphBounds(font, glyph_name: str):
        try:
            if not glyph_name or 'glyf' not in font or glyph_name not in font['glyf']:
                return None
            glyf = font['glyf']
            glyph = glyf[glyph_name]
            try:
                glyph.recalcBounds(glyf)
            except Exception:
                recordException('start.py:3106', sys.exc_info()[1])
                _traceSwallowedException('start.py:3037', sys.exc_info()[1])
                pass
            return (
                getattr(glyph, 'xMin', None),
                getattr(glyph, 'yMin', None),
                getattr(glyph, 'xMax', None),
                getattr(glyph, 'yMax', None),
            )
        except Exception:
            recordException('start.py:3115', sys.exc_info()[1])
            _traceSwallowedException('start.py:3045', sys.exc_info()[1])
            return None

    @staticmethod
    def _glyphMetricRows(font) -> list[str]:
        rows: list[str] = []
        try:
            cmap = font.getBestCmap() or {}
            hmtx = font['hmtx'].metrics if 'hmtx' in font else {}
            probes = [
                ('A', 0x0041),
                ('fire', 0x1F525),
                ('hot-springs-fallback', 0x2668),
                ('private-use-fire', 0xE525),
                ('braille-full', 0x28FF),
                ('macron', 0x00AF),
                ('wrong-macron', 0x02C9),
            ]
            for label, codepoint in probes:
                glyph_name = str(cmap.get(codepoint) or EMPTY_STRING)
                advance = hmtx.get(glyph_name, ('', '')) if glyph_name else ('', '')
                bounds = Font._glyphBounds(font, glyph_name) if glyph_name else None
                rows.append(f'  glyph {label} U+{codepoint:04X}: name={glyph_name or "MISSING"} hmtx={advance} bbox={bounds}')
        except Exception as error:
            recordException('start.py:3139', sys.exc_info()[1])
            rows.append(f'  glyph probe failed: {type(error).__name__}: {error}')
        return rows

    def metadataReportRows(self, font) -> list[str]:
        rows: list[str] = []
        try:
            head = font['head'] if 'head' in font else None
            hhea = font['hhea'] if 'hhea' in font else None
            os2 = font['OS/2'] if 'OS/2' in font else None
            maxp = font['maxp'] if 'maxp' in font else None
            post = font['post'] if 'post' in font else None
            cmap = font.getBestCmap() or {}
            hmtx = font['hmtx'].metrics if 'hmtx' in font else {}
            advances = _fontMetricPairValues(hmtx, 0)
            lefts = _fontMetricPairValues(hmtx, 1)
            rows.extend([
                f'font={self.path.name}',
                f'path={self.path}',
                f'md5={self.md5(self.path)}',
                f'flavor={getattr(font, "flavor", None)} sfntVersion={getattr(font, "sfntVersion", EMPTY_STRING)}',
                f'tables={self._tableTagText(font)}',
                f'maxp.numGlyphs={self._metricValue(maxp, "numGlyphs")}',
                f'head.unitsPerEm={self._metricValue(head, "unitsPerEm")}',
                f'head.bbox=({self._metricValue(head, "xMin")},{self._metricValue(head, "yMin")},{self._metricValue(head, "xMax")},{self._metricValue(head, "yMax")})',
                f'hhea.ascent={self._metricValue(hhea, "ascent")} hhea.descent={self._metricValue(hhea, "descent")} hhea.lineGap={self._metricValue(hhea, "lineGap")} hhea.advanceWidthMax={self._metricValue(hhea, "advanceWidthMax")}',
                f'OS/2.xAvgCharWidth={self._metricValue(os2, "xAvgCharWidth")} OS/2.sTypoAscender={self._metricValue(os2, "sTypoAscender")} OS/2.sTypoDescender={self._metricValue(os2, "sTypoDescender")} OS/2.sTypoLineGap={self._metricValue(os2, "sTypoLineGap")}',
                f'OS/2.usWinAscent={self._metricValue(os2, "usWinAscent")} OS/2.usWinDescent={self._metricValue(os2, "usWinDescent")} OS/2.fsSelection={self._metricValue(os2, "fsSelection")}',
                f'post.isFixedPitch={self._metricValue(post, "isFixedPitch")}',
                f'cmap.best.count={len(cmap)}',
                f'hmtx.advance.min={min(advances) if advances else EMPTY_STRING} hmtx.advance.max={max(advances) if advances else EMPTY_STRING} hmtx.advance.unique={len(set(advances)) if advances else 0}',
                f'hmtx.lsb.min={min(lefts) if lefts else EMPTY_STRING} hmtx.lsb.max={max(lefts) if lefts else EMPTY_STRING}',
            ])
            rows.extend(self._glyphMetricRows(font))
        except Exception as error:
            recordException('start.py:3173', sys.exc_info()[1])
            rows.append(f'metadata report failed: {type(error).__name__}: {error}')
        return rows

    def writeMetadataXml(self) -> tuple[bool, Path, list[str]]:
        xml_path = self.path.with_name(self.path.name + '.xml')
        try:
            font = self.openFont()
            try:
                report_rows = self.metadataReportRows(font)
                try:
                    table_tags = [str(tag) for tag in font.keys()]
                except Exception:
                    recordException('start.py:3185', sys.exc_info()[1])
                    table_tags = []
                print(f'[TRACE:font-metadata] saveXML-start font={self.path} xml={xml_path} tables={len(table_tags)} tags={','.join(table_tags[:32])}', file=sys.stderr, flush=True)
                # Full TTX dump, not a summary.  The metric report above is the
                # human-readable trace; saveXML writes the complete font table XML.
                font.saveXML(str(xml_path))
                print(f'[TRACE:font-metadata] saveXML-complete font={self.path} xml={xml_path} bytes={safeInt(xml_path.stat().st_size, 0) if xml_path.exists() else 0}', file=sys.stderr, flush=True)
            finally:
                try:
                    font.close()
                except Exception:
                    recordException('start.py:3195', sys.exc_info()[1])
                    _traceSwallowedException('start.py:3124', sys.exc_info()[1])
                    pass
            return True, xml_path, report_rows
        except Exception as error:
            recordException('start.py:3199', sys.exc_info()[1])
            return False, xml_path, [f'{self.path.name}: {type(error).__name__}: {error}']

    @classmethod
    def _metadataSelection(cls, requested: str = EMPTY_STRING) -> list['Font']:
        fonts = cls.discoverAll()
        value = str(requested or EMPTY_STRING).strip().lower()
        if not value or value in {'all', '*'}:
            return fonts
        if value in {'default', 'terminal', 'selected', 'active'}:
            try:
                materializeDefaultFontAliases()
                settings = terminalFontSettings()
                candidates = [
                    Path(str(settings.get('selected_default_otf_path') or EMPTY_STRING)),
                    BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH,
                    BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH,
                ]
                selected: list[Font] = []
                seen: set[str] = set()
                for path in candidates:
                    try:
                        resolved = path.resolve()
                    except Exception:
                        recordException('start.py:3222', sys.exc_info()[1])
                        resolved = path
                    key = str(resolved).lower()
                    if key not in seen and resolved.exists():
                        selected.append(cls(resolved))
                        seen.add(key)
                return selected
            except Exception:
                recordException('start.py:3229', sys.exc_info()[1])
                return [cls(BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH), cls(BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH)]
        if value in {'mono', 'trio', 'triodesktop'}:
            materializeDefaultFontAliases()
            return [cls(BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH)]
        if value in {'color', 'colour', 'colored', 'coloured'}:
            materializeDefaultFontAliases()
            return [cls(BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH)]
        selected: list[Font] = []
        for font in fonts:
            haystack = {font.path.name.lower(), font.path.stem.lower(), str(font.path).lower(), font.faceName.lower()}
            if value in haystack or any(value in item for item in haystack):
                selected.append(font)
        return selected

    @classmethod
    def writeMetadataAll(cls, requested: str = EMPTY_STRING) -> tuple[int, list[str]]:
        report: list[str] = ['TrioDesktop font metadata report', f'timestamp={datetime.datetime.now().isoformat()}', f'requested={requested or "all"}']
        materializeDefaultFontAliases(report)
        settings = terminalFontSettings()
        traceDefaultFontSelection(settings, reason='font-metadata')
        report.append(f'default selection colored_font={int(bool(settings.get("colored_font", False)))} mode={settings.get("mode")} selected_otf={settings.get("selected_default_otf_path")} selected_woff2={settings.get("selected_default_woff2_path")}')
        traceRuntimeTerminalFontSnapshot('font-metadata')
        fonts = cls._metadataSelection(requested)
        request_key = str(requested or EMPTY_STRING).strip().lower()
        if not request_key or request_key in {'all', '*'}:
            for alias_path in (BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH):
                if alias_path.exists() and all(existing.path.resolve() != alias_path.resolve() for existing in fonts):
                    fonts.append(cls(alias_path))
        if not fonts:
            report.append('no matching fonts found')
            return 1, report
        exit_code = 0
        default_report_rows: list[str] = []
        selected_default_report_rows: list[str] = []
        report_dir = BASE_DIR / 'font_proofs'
        selected_default_path = Path(str(settings.get('selected_default_otf_path') or settings.get('selected_default_woff2_path') or EMPTY_STRING)).resolve()
        report_dir.mkdir(parents=True, exist_ok=True)
        for font in fonts:
            ok, xml_path, rows = font.writeMetadataXml()
            if not ok:
                exit_code = 1
            report.append(f'{font.path.name}: ok={int(ok)} xml={xml_path}')
            report.extend(rows)
            report.append('')
            if font.path.name.lower() == 'default.otf':
                default_report_rows = rows
            try:
                if font.path.resolve() == selected_default_path:
                    selected_default_report_rows = rows
            except Exception:
                recordException('start.py:3279', sys.exc_info()[1])
                _traceSwallowedException('start.py:3207', sys.exc_info()[1])
                pass
        try:
            File(report_dir / 'font_metadata_report_all.txt').writeText('\n'.join(report) + '\n')
        except Exception as error:
            recordException('start.py:3284', sys.exc_info()[1])
            report.append(f'all report write failed: {type(error).__name__}: {error}')
        if default_report_rows:
            try:
                File(report_dir / 'font_metadata_report_default_otf.txt').writeText('\n'.join(default_report_rows) + '\n')
            except Exception as error:
                recordException('start.py:3289', sys.exc_info()[1])
                report.append(f'default report write failed: {type(error).__name__}: {error}')
        if selected_default_report_rows:
            try:
                File(report_dir / 'font_metadata_report_default.txt').writeText('\n'.join(selected_default_report_rows) + '\n')
            except Exception as error:
                recordException('start.py:3294', sys.exc_info()[1])
                report.append(f'selected default report write failed: {type(error).__name__}: {error}')
        try:
            default_otf_xml = (BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH).with_name(DEFAULT_TERMINAL_OTF_RELATIVE_PATH.name + '.xml')
            default_color_otf_xml = (BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH).with_name(DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH.name + '.xml')
            default_woff2_xml = (BASE_DIR / DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH).with_name(DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH.name + '.xml')
            default_color_woff2_xml = (BASE_DIR / DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH).with_name(DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH.name + '.xml')
            if default_otf_xml.exists():
                File(default_otf_xml).copyTo(BASE_DIR / 'default.xml')
                report.append(f'default xml copied {default_otf_xml} -> {BASE_DIR / "default.xml"}')
            if default_woff2_xml.exists():
                File(default_woff2_xml).copyTo((BASE_DIR / DEFAULT_TERMINAL_WOLF2_RELATIVE_PATH).with_name(DEFAULT_TERMINAL_WOLF2_RELATIVE_PATH.name + '.xml'))
                report.append(f'default wolf2 xml copied {default_woff2_xml} -> {BASE_DIR / (DEFAULT_TERMINAL_WOLF2_RELATIVE_PATH.name + ".xml")}')
            if default_color_otf_xml.exists():
                File(default_color_otf_xml).copyTo(BASE_DIR / 'default.xml')
                report.append(f'default color xml copied {default_color_otf_xml} -> {BASE_DIR / "default.xml"}')
            if default_color_woff2_xml.exists():
                File(default_color_woff2_xml).copyTo((BASE_DIR / DEFAULT_TERMINAL_COLOR_WOLF2_RELATIVE_PATH).with_name(DEFAULT_TERMINAL_COLOR_WOLF2_RELATIVE_PATH.name + '.xml'))
                report.append(f'default color wolf2 xml copied {default_color_woff2_xml} -> {BASE_DIR / (DEFAULT_TERMINAL_COLOR_WOLF2_RELATIVE_PATH.name + ".xml")}')
        except Exception as error:
            recordException('start.py:3313', sys.exc_info()[1])
            report.append(f'default xml copy failed: {type(error).__name__}: {error}')
        return int(exit_code), report

    @staticmethod
    def _metadataString(value: object) -> str:
        if value is None:
            return EMPTY_STRING
        try:
            text = value.decode('utf-8', 'replace') if isinstance(value, bytes) else str(value)
        except Exception:
            recordException('start.py:font-metadata-string', sys.exc_info()[1])
            text = repr(value)
        return ''.join(ch if (ch in '\t\n\r' or 0x20 <= ord(ch) <= 0xD7FF or 0xE000 <= ord(ch) <= 0xFFFD) else '\uFFFD' for ch in text)

    def metadataXmlPath(self) -> Path:
        directory = BASE_DIR / 'fonts' / FONT_METADATA_DIRNAME
        directory.mkdir(parents=True, exist_ok=True)
        return directory / f'{self.path.name}{FONT_XML_SUFFIX}'

    def _collectCmap(self, font: object) -> dict[int, str]:
        collected: dict[int, str] = {}
        try:
            if 'cmap' not in cast(Any, font):
                return collected
            for table in cast(Any, font)['cmap'].tables:
                cmap = getattr(table, 'cmap', None)
                if isinstance(cmap, dict):
                    for code, glyph_name in cmap.items():
                        try:
                            collected[int(code)] = str(glyph_name)
                        except Exception:
                            recordException('start.py:font-cmap-collect', sys.exc_info()[1])
                            continue
        except Exception:
            recordException('start.py:font-cmap-collect', sys.exc_info()[1])
        return collected

    def _appendNameRecords(self, font: object, parent: object) -> None:
        import xml.etree.ElementTree as ET
        names_node = ET.SubElement(cast(Any, parent), 'names')
        try:
            if 'name' not in cast(Any, font):
                names_node.set('present', 'false')
                return
            names_node.set('present', 'true')
            seen: set[tuple[int, int, int, int, str]] = set()
            for record in cast(Any, font)['name'].names:
                try:
                    text = record.toUnicode().strip()
                except Exception:
                    recordException('start.py:font-name-unicode', sys.exc_info()[1])
                    raw = getattr(record, 'string', b'')
                    text = raw.decode('utf-8', 'replace').strip() if isinstance(raw, bytes) else str(raw).strip()
                key = (
                    safeInt(getattr(record, 'nameID', -1), -1),
                    safeInt(getattr(record, 'platformID', -1), -1),
                    safeInt(getattr(record, 'platEncID', -1), -1),
                    safeInt(getattr(record, 'langID', -1), -1),
                    self._metadataString(text),
                )
                if key in seen:
                    continue
                seen.add(key)
                ET.SubElement(names_node, 'name', {'nameID': str(key[0]), 'platformID': str(key[1]), 'encodingID': str(key[2]), 'languageID': str(key[3])}).text = key[4]
        except Exception:
            recordException('start.py:font-name-records', sys.exc_info()[1])
            names_node.set('error', 'see-exception-log')

    def _appendTableDirectory(self, font: object, parent: object) -> None:
        import xml.etree.ElementTree as ET
        tables_node = ET.SubElement(cast(Any, parent), 'tables')
        try:
            reader = getattr(font, 'reader', None)
            for tag in list(cast(Any, font).keys()):
                attrs: dict[str, str] = {'tag': str(tag).strip() or str(tag), 'present': 'true'}
                try:
                    entry = getattr(reader, 'tables', {}).get(tag) if reader is not None else None
                    if entry is not None:
                        for attr in ('offset', 'length', 'origLength', 'origChecksum', 'checkSum'):
                            if hasattr(entry, attr):
                                attrs[attr] = self._metadataString(getattr(entry, attr))
                except Exception:
                    recordException('start.py:font-table-entry', sys.exc_info()[1])
                ET.SubElement(tables_node, 'table', attrs)
        except Exception:
            recordException('start.py:font-table-directory', sys.exc_info()[1])
            tables_node.set('error', 'see-exception-log')

    def _appendMetricStats(self, font: object, parent: object) -> None:
        import xml.etree.ElementTree as ET
        metrics_node = ET.SubElement(cast(Any, parent), 'metrics')
        try:
            font_any = cast(Any, font)
            if 'head' in font_any:
                head = font_any['head']
                ET.SubElement(metrics_node, 'head', {'unitsPerEm': self._metadataString(getattr(head, 'unitsPerEm', EMPTY_STRING)), 'xMin': self._metadataString(getattr(head, 'xMin', EMPTY_STRING)), 'yMin': self._metadataString(getattr(head, 'yMin', EMPTY_STRING)), 'xMax': self._metadataString(getattr(head, 'xMax', EMPTY_STRING)), 'yMax': self._metadataString(getattr(head, 'yMax', EMPTY_STRING)), 'flags': self._metadataString(getattr(head, 'flags', EMPTY_STRING)), 'macStyle': self._metadataString(getattr(head, 'macStyle', EMPTY_STRING))})
            if 'maxp' in font_any:
                maxp = font_any['maxp']
                ET.SubElement(metrics_node, 'maxp', {'numGlyphs': self._metadataString(getattr(maxp, 'numGlyphs', EMPTY_STRING)), 'tableVersion': self._metadataString(getattr(maxp, 'tableVersion', EMPTY_STRING))})
            if 'hhea' in font_any:
                hhea = font_any['hhea']
                ET.SubElement(metrics_node, 'hhea', {'ascent': self._metadataString(getattr(hhea, 'ascent', EMPTY_STRING)), 'descent': self._metadataString(getattr(hhea, 'descent', EMPTY_STRING)), 'lineGap': self._metadataString(getattr(hhea, 'lineGap', EMPTY_STRING)), 'advanceWidthMax': self._metadataString(getattr(hhea, 'advanceWidthMax', EMPTY_STRING)), 'minLeftSideBearing': self._metadataString(getattr(hhea, 'minLeftSideBearing', EMPTY_STRING)), 'minRightSideBearing': self._metadataString(getattr(hhea, 'minRightSideBearing', EMPTY_STRING)), 'xMaxExtent': self._metadataString(getattr(hhea, 'xMaxExtent', EMPTY_STRING)), 'numberOfHMetrics': self._metadataString(getattr(hhea, 'numberOfHMetrics', EMPTY_STRING))})
            if 'OS/2' in font_any:
                os2 = font_any['OS/2']
                ET.SubElement(metrics_node, 'OS_2', {'version': self._metadataString(getattr(os2, 'version', EMPTY_STRING)), 'xAvgCharWidth': self._metadataString(getattr(os2, 'xAvgCharWidth', EMPTY_STRING)), 'usWeightClass': self._metadataString(getattr(os2, 'usWeightClass', EMPTY_STRING)), 'usWidthClass': self._metadataString(getattr(os2, 'usWidthClass', EMPTY_STRING)), 'sTypoAscender': self._metadataString(getattr(os2, 'sTypoAscender', EMPTY_STRING)), 'sTypoDescender': self._metadataString(getattr(os2, 'sTypoDescender', EMPTY_STRING)), 'sTypoLineGap': self._metadataString(getattr(os2, 'sTypoLineGap', EMPTY_STRING)), 'usWinAscent': self._metadataString(getattr(os2, 'usWinAscent', EMPTY_STRING)), 'usWinDescent': self._metadataString(getattr(os2, 'usWinDescent', EMPTY_STRING)), 'sxHeight': self._metadataString(getattr(os2, 'sxHeight', EMPTY_STRING)), 'sCapHeight': self._metadataString(getattr(os2, 'sCapHeight', EMPTY_STRING)), 'achVendID': self._metadataString(getattr(os2, 'achVendID', EMPTY_STRING))})
            if 'post' in font_any:
                post = font_any['post']
                ET.SubElement(metrics_node, 'post', {'formatType': self._metadataString(getattr(post, 'formatType', EMPTY_STRING)), 'isFixedPitch': self._metadataString(getattr(post, 'isFixedPitch', EMPTY_STRING)), 'italicAngle': self._metadataString(getattr(post, 'italicAngle', EMPTY_STRING)), 'underlinePosition': self._metadataString(getattr(post, 'underlinePosition', EMPTY_STRING)), 'underlineThickness': self._metadataString(getattr(post, 'underlineThickness', EMPTY_STRING))})
            if 'hmtx' in font_any:
                hmtx = font_any['hmtx']
                widths: list[int] = []
                lefts: list[int] = []
                for metric in getattr(hmtx, 'metrics', {}).values():
                    try:
                        width, left = metric
                        widths.append(safeInt(width, 0))
                        lefts.append(safeInt(left, 0))
                    except Exception:
                        recordException('start.py:font-hmtx-metric', sys.exc_info()[1])
                        continue
                hmtx_node = ET.SubElement(metrics_node, 'hmtx')
                if widths:
                    counts = Counter(widths)
                    dominant_width, dominant_count = counts.most_common(1)[0]
                    non_zero_widths = [width for width in widths if width > 0]
                    hmtx_node.attrib.update({'glyphMetricCount': str(len(widths)), 'minAdvanceWidth': str(min(widths)), 'maxAdvanceWidth': str(max(widths)), 'uniqueAdvanceWidthCount': str(len(counts)), 'uniqueAdvanceWidthsPreview': ','.join(str(width) for width in sorted(counts)[:64]), 'dominantAdvanceWidth': str(dominant_width), 'dominantAdvanceWidthCount': str(dominant_count), 'zeroWidthGlyphCount': str(sum(1 for width in widths if width == 0)), 'nonZeroAllSame': str(len(set(non_zero_widths)) == 1 if non_zero_widths else False).lower(), 'minLeftSideBearing': str(min(lefts) if lefts else 0), 'maxLeftSideBearing': str(max(lefts) if lefts else 0)})
                    if non_zero_widths and (len(set(non_zero_widths)) == 1 or self.shouldNormalizeMonospaceWidth()):
                        hmtx_node.set('targetAdvanceWidth', str(dominant_width))
        except Exception:
            recordException('start.py:font-metric-stats', sys.exc_info()[1])
            metrics_node.set('error', 'see-exception-log')

    def _appendCmapStats(self, font: object, parent: object) -> None:
        import xml.etree.ElementTree as ET
        cmap_node = ET.SubElement(cast(Any, parent), 'cmap')
        try:
            if 'cmap' not in cast(Any, font):
                cmap_node.set('present', 'false')
                return
            cmap_node.set('present', 'true')
            cmap_node.set('mergedCodepointCount', str(len(self._collectCmap(font))))
            for table in cast(Any, font)['cmap'].tables:
                cmap = getattr(table, 'cmap', {})
                sub = ET.SubElement(cmap_node, 'subtable', {'platformID': self._metadataString(getattr(table, 'platformID', EMPTY_STRING)), 'encodingID': self._metadataString(getattr(table, 'platEncID', EMPTY_STRING)), 'language': self._metadataString(getattr(table, 'language', EMPTY_STRING)), 'format': self._metadataString(getattr(table, 'format', EMPTY_STRING)), 'length': str(len(cmap) if isinstance(cmap, dict) else 0)})
                if isinstance(cmap, dict):
                    for code, glyph_name in list(sorted(cmap.items(), key=lambda item: int(item[0])))[:128]:
                        ET.SubElement(sub, 'map', {'codepoint': f'U+{int(code):04X}', 'glyph': str(glyph_name)})
        except Exception:
            recordException('start.py:font-cmap-stats', sys.exc_info()[1])
            cmap_node.set('error', 'see-exception-log')

    def _appendLayoutFeatures(self, font: object, parent: object) -> None:
        import xml.etree.ElementTree as ET
        features_node = ET.SubElement(cast(Any, parent), 'layoutFeatures')
        for tag in ('GSUB', 'GPOS'):
            table_node = ET.SubElement(features_node, 'table', {'tag': tag, 'present': str(tag in cast(Any, font)).lower()})
            if tag not in cast(Any, font):
                continue
            try:
                feature_list = cast(Any, font)[tag].table.FeatureList
                for record in getattr(feature_list, 'FeatureRecord', []) or []:
                    ET.SubElement(table_node, 'feature', {'tag': self._metadataString(getattr(record, 'FeatureTag', EMPTY_STRING))})
            except Exception:
                recordException('start.py:font-layout-features', sys.exc_info()[1])
                table_node.set('error', 'see-exception-log')

    def metadataElement(self) -> object:
        import xml.etree.ElementTree as ET
        try:
            font = self.openFont()
            try:
                root = ET.Element('fontMetadata', {'fileName': self.path.name, 'path': str(self.path), 'stem': self.path.stem, 'extension': self.path.suffix.lower(), 'faceName': self.faceName, 'flavor': self._metadataString(getattr(font, 'flavor', None) or 'sfnt'), 'generatedAt': datetime.datetime.now().isoformat(sep='T', timespec='seconds'), 'sizeBytes': str(self.path.stat().st_size if self.path.exists() else 0)})
                self._appendTableDirectory(font, root)
                self._appendNameRecords(font, root)
                self._appendMetricStats(font, root)
                self._appendCmapStats(font, root)
                self._appendLayoutFeatures(font, root)
                return root
            finally:
                try:
                    font.close()
                except Exception:
                    recordException('start.py:font-metadata-close', sys.exc_info()[1])
        except Exception as error:
            recordException('start.py:font-metadata-element', sys.exc_info()[1])
            return ET.Element('fontMetadata', {'fileName': self.path.name, 'path': str(self.path), 'extension': self.path.suffix.lower(), 'generatedAt': datetime.datetime.now().isoformat(sep='T', timespec='seconds'), 'error': f'{type(error).__name__}: {error}'})

    def writeRoundTripMetadataXml(self) -> Path:
        import xml.etree.ElementTree as ET
        root = cast(Any, self.metadataElement())
        path = self.metadataXmlPath()
        if str(root.attrib.get('error', EMPTY_STRING) or EMPTY_STRING).strip():
            print(f'[Font:WARN] metadata XML not written because font read failed: {root.attrib.get("error")}', flush=True)
            return path
        tree = ET.ElementTree(root)
        try:
            ET.indent(tree, space='  ')
        except Exception:
            recordException('start.py:font-metadata-indent', sys.exc_info()[1])
        tree.write(str(path), encoding='utf-8', xml_declaration=True)
        print(f'[Font] metadata XML: {path}', flush=True)
        return path

    @classmethod
    def metadataXmlFiles(cls) -> list[Path]:
        directory = BASE_DIR / 'fonts' / FONT_METADATA_DIRNAME
        if not directory.exists():
            return []
        return sorted((item for item in directory.iterdir() if item.is_file() and item.suffix.lower() == FONT_XML_SUFFIX), key=lambda item: item.name.lower())

    @classmethod
    def fontForMetadataXml(cls, xmlPath: Path | str, fonts: list['Font'] | None = None) -> 'Font | None':
        import xml.etree.ElementTree as ET
        xml_path = Path(xmlPath)
        try:
            root = ET.parse(str(xml_path)).getroot()
        except Exception as error:
            recordException('start.py:font-metadata-parse', sys.exc_info()[1])
            print(f'[Font:ERROR] cannot parse metadata XML {xml_path}: {type(error).__name__}: {error}', flush=True)
            return None
        file_name = str(root.attrib.get('fileName') or EMPTY_STRING).strip()
        root_path = str(root.attrib.get('path') or EMPTY_STRING).strip()
        candidates = list(fonts if fonts is not None else cls.discoverAll())
        for alias_name in (*DEFAULT_FONT_ALIAS_FILENAMES, *DEFAULT_COLOR_FONT_ALIAS_FILENAMES, 'default.otf', 'default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf', 'fonts/default.otf'):
            alias_path = BASE_DIR / alias_name
            if alias_path.exists() and all(existing.path.name.lower() != alias_path.name.lower() for existing in candidates):
                candidates.append(cls(alias_path))
        for wanted in (file_name, Path(root_path).name if root_path else EMPTY_STRING, xml_path.name[:-len(FONT_XML_SUFFIX)] if xml_path.name.lower().endswith(FONT_XML_SUFFIX) else xml_path.stem):
            if not wanted:
                continue
            for font in candidates:
                if font.path.name.lower() == wanted.lower():
                    return font
        print(f'[Font:WARN] no matching font found for metadata XML {xml_path.name}', flush=True)
        return None

    def _xmlInt(self, value: object, default: int | None = None) -> int | None:
        text = str(value if value is not None else EMPTY_STRING).strip()
        if text == EMPTY_STRING:
            return default
        try:
            if text.lower().startswith('0x'):
                return int(text, 16)
            return int(float(text))
        except Exception:
            recordException('start.py:font-xml-int', sys.exc_info()[1])
            return default

    def _xmlFloat(self, value: object, default: float | None = None) -> float | None:
        text = str(value if value is not None else EMPTY_STRING).strip()
        if text == EMPTY_STRING:
            return default
        try:
            return float(text)
        except Exception:
            recordException('start.py:font-xml-float', sys.exc_info()[1])
            return default

    def _parseCodepoint(self, value: object) -> int | None:
        text = str(value if value is not None else EMPTY_STRING).strip()
        if not text:
            return None
        try:
            if text.upper().startswith('U+'):
                return int(text[2:], 16)
            if text.lower().startswith('0x'):
                return int(text, 16)
            return int(text)
        except Exception:
            recordException('start.py:font-codepoint-parse', sys.exc_info()[1])
            return None

    def _applyIntAttrs(self, table: object, node: object | None, attrs: tuple[str, ...]) -> int:
        if table is None or node is None:
            return 0
        changed = 0
        node_any = cast(Any, node)
        for attr in attrs:
            if attr not in node_any.attrib or not hasattr(table, attr):
                continue
            value = self._xmlInt(node_any.attrib.get(attr), None)
            if value is None:
                continue
            try:
                if getattr(table, attr) != value:
                    setattr(table, attr, value)
                    changed += 1
            except Exception:
                recordException('start.py:font-apply-int', sys.exc_info()[1])
        return changed

    def _applyFloatAttrs(self, table: object, node: object | None, attrs: tuple[str, ...]) -> int:
        if table is None or node is None:
            return 0
        changed = 0
        node_any = cast(Any, node)
        for attr in attrs:
            if attr not in node_any.attrib or not hasattr(table, attr):
                continue
            value = self._xmlFloat(node_any.attrib.get(attr), None)
            if value is None:
                continue
            try:
                if float(getattr(table, attr)) != float(value):
                    setattr(table, attr, value)
                    changed += 1
            except Exception:
                recordException('start.py:font-apply-float', sys.exc_info()[1])
        return changed

    def _applyNameMetadata(self, font: object, root: object) -> int:
        names_node = cast(Any, root).find('names')
        if names_node is None or 'name' not in cast(Any, font):
            return 0
        changed = 0
        name_table = cast(Any, font)['name']
        for node in names_node.findall('name'):
            if str(node.attrib.get('locked', 'false')).lower() in {'1', 'true', 'yes'}:
                continue
            text = node.text or EMPTY_STRING
            name_id = self._xmlInt(node.attrib.get('nameID'), None)
            platform_id = self._xmlInt(node.attrib.get('platformID'), None)
            encoding_id = self._xmlInt(node.attrib.get('encodingID'), None)
            language_id = self._xmlInt(node.attrib.get('languageID'), None)
            if None in (name_id, platform_id, encoding_id, language_id):
                continue
            try:
                existing = None
                for record in getattr(name_table, 'names', []) or []:
                    if (safeInt(getattr(record, 'nameID', -1), -1) == int(cast(int, name_id)) and safeInt(getattr(record, 'platformID', -1), -1) == int(cast(int, platform_id)) and safeInt(getattr(record, 'platEncID', -1), -1) == int(cast(int, encoding_id)) and safeInt(getattr(record, 'langID', -1), -1) == int(cast(int, language_id))):
                        try:
                            existing = record.toUnicode()
                        except Exception:
                            recordException('start.py:font-existing-name', sys.exc_info()[1])
                            existing = None
                        break
                if existing != text:
                    name_table.setName(text, int(cast(int, name_id)), int(cast(int, platform_id)), int(cast(int, encoding_id)), int(cast(int, language_id)))
                    changed += 1
            except Exception:
                recordException('start.py:font-apply-name', sys.exc_info()[1])
        return changed

    def _applyMetricMetadata(self, font: object, root: object) -> int:
        metrics_node = cast(Any, root).find('metrics')
        if metrics_node is None:
            return 0
        changed = 0
        font_any = cast(Any, font)
        if 'head' in font_any:
            changed += self._applyIntAttrs(font_any['head'], metrics_node.find('head'), ('unitsPerEm', 'xMin', 'yMin', 'xMax', 'yMax', 'flags', 'macStyle'))
        if 'maxp' in font_any:
            changed += self._applyIntAttrs(font_any['maxp'], metrics_node.find('maxp'), ('maxZones', 'maxTwilightPoints', 'maxStorage', 'maxFunctionDefs', 'maxInstructionDefs', 'maxStackElements', 'maxSizeOfInstructions', 'maxComponentElements', 'maxComponentDepth'))
        if 'hhea' in font_any:
            changed += self._applyIntAttrs(font_any['hhea'], metrics_node.find('hhea'), ('ascent', 'descent', 'lineGap', 'advanceWidthMax', 'minLeftSideBearing', 'minRightSideBearing', 'xMaxExtent', 'numberOfHMetrics'))
        if 'OS/2' in font_any:
            os2_node = metrics_node.find('OS_2')
            changed += self._applyIntAttrs(font_any['OS/2'], os2_node, ('version', 'xAvgCharWidth', 'usWeightClass', 'usWidthClass', 'sTypoAscender', 'sTypoDescender', 'sTypoLineGap', 'usWinAscent', 'usWinDescent', 'sxHeight', 'sCapHeight'))
            if os2_node is not None and 'achVendID' in os2_node.attrib and hasattr(font_any['OS/2'], 'achVendID'):
                value = str(os2_node.attrib.get('achVendID') or EMPTY_STRING)[:4]
                if value and getattr(font_any['OS/2'], 'achVendID') != value:
                    font_any['OS/2'].achVendID = value
                    changed += 1
        if 'post' in font_any:
            post_node = metrics_node.find('post')
            changed += self._applyFloatAttrs(font_any['post'], post_node, ('formatType', 'italicAngle'))
            changed += self._applyIntAttrs(font_any['post'], post_node, ('isFixedPitch', 'underlinePosition', 'underlineThickness'))
        changed += self._applyHmtxMetadata(font, metrics_node.find('hmtx'))
        return changed

    def _truthyXmlFlag(self, value: object) -> bool:
        return str(value if value is not None else EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on', 'all', 'force'}

    def _applyHmtxMetadata(self, font: object, hmtx_node: object | None) -> int:
        if hmtx_node is None or 'hmtx' not in cast(Any, font):
            return 0
        hmtx = cast(Any, font)['hmtx']
        node_any = cast(Any, hmtx_node)
        changed = 0
        target_width: int | None = None
        all_glyphs = False
        for attr in ('setAllAdvanceWidth', 'forceAllAdvanceWidth', 'targetAllAdvanceWidth', 'advance.width', 'hmtx.advance.width'):
            if attr in node_any.attrib:
                target_width = self._xmlInt(node_any.attrib.get(attr), None)
                all_glyphs = True
                break
        if target_width is None:
            for attr in ('setAllNonZeroAdvanceWidth', 'targetAdvanceWidth'):
                if attr in node_any.attrib:
                    target_width = self._xmlInt(node_any.attrib.get(attr), None)
                    break
        requested_min = self._xmlInt(node_any.attrib.get('minAdvanceWidth', node_any.attrib.get('advance.min', node_any.attrib.get('hmtx.advance.min'))), None)
        requested_max = self._xmlInt(node_any.attrib.get('maxAdvanceWidth', node_any.attrib.get('advance.max', node_any.attrib.get('hmtx.advance.max'))), None)
        requested_unique = self._xmlInt(node_any.attrib.get('uniqueAdvanceWidthCount', node_any.attrib.get('advance.unique', node_any.attrib.get('hmtx.advance.unique'))), None)
        if requested_min is not None and requested_max is not None and requested_unique == 1 and requested_min == requested_max and requested_min > 0:
            target_width = requested_min
            all_glyphs = True
        if self._truthyXmlFlag(node_any.attrib.get('includeZeroAdvanceWidths')) or self._truthyXmlFlag(node_any.attrib.get('forceZeroAdvanceWidths')):
            all_glyphs = True
        if target_width is not None and target_width > 0:
            changed_glyphs = 0
            for glyph_name, metrics in list(getattr(hmtx, 'metrics', {}).items()):
                try:
                    width, lsb = metrics
                    width = safeInt(width, 0)
                    if (all_glyphs or width > 0) and width != target_width:
                        hmtx.metrics[glyph_name] = (safeInt(target_width, FONT_REPAIR_TARGET_WIDTH), safeInt(lsb, 0))
                        changed_glyphs += 1
                except Exception:
                    recordException('start.py:font-apply-hmtx', sys.exc_info()[1])
                    continue
            changed += changed_glyphs
        samples = node_any.find('samples')
        apply_samples = self._truthyXmlFlag(node_any.attrib.get('applySamples'))
        if samples is not None:
            for glyph_node in samples.findall('glyph'):
                if not apply_samples and not self._truthyXmlFlag(glyph_node.attrib.get('apply')):
                    continue
                glyph_name = str(glyph_node.attrib.get('name') or EMPTY_STRING).strip()
                if not glyph_name or glyph_name not in hmtx.metrics:
                    continue
                old_width, old_lsb = hmtx.metrics[glyph_name]
                new_width = self._xmlInt(glyph_node.attrib.get('advanceWidth'), safeInt(old_width, 0))
                new_lsb = self._xmlInt(glyph_node.attrib.get('leftSideBearing'), safeInt(old_lsb, 0))
                if new_width is None or new_lsb is None:
                    continue
                if (safeInt(old_width, 0), safeInt(old_lsb, 0)) != (safeInt(new_width, 0), safeInt(new_lsb, 0)):
                    hmtx.metrics[glyph_name] = (int(new_width), int(new_lsb))
                    changed += 1
        return changed

    def _applyCmapMetadata(self, font: object, root: object) -> int:
        cmap_node = cast(Any, root).find('cmap')
        if cmap_node is None or 'cmap' not in cast(Any, font):
            return 0
        changed = 0
        cmap_apply_all = str(cmap_node.attrib.get('apply', 'false')).lower() in {'1', 'true', 'yes'}
        for sub_node in cmap_node.findall('subtable'):
            sub_apply_all = cmap_apply_all or str(sub_node.attrib.get('apply', 'false')).lower() in {'1', 'true', 'yes'}
            platform_id = self._xmlInt(sub_node.attrib.get('platformID'), None)
            encoding_id = self._xmlInt(sub_node.attrib.get('encodingID'), None)
            fmt = self._xmlInt(sub_node.attrib.get('format'), None)
            language = self._xmlInt(sub_node.attrib.get('language'), None)
            for table in cast(Any, font)['cmap'].tables:
                if platform_id is not None and safeInt(getattr(table, 'platformID', -999), -999) != int(platform_id):
                    continue
                if encoding_id is not None and safeInt(getattr(table, 'platEncID', -999), -999) != int(encoding_id):
                    continue
                if fmt is not None and safeInt(getattr(table, 'format', -999), -999) != int(fmt):
                    continue
                if language is not None and safeInt(getattr(table, 'language', 0), 0) != int(language):
                    continue
                cmap = getattr(table, 'cmap', None)
                if not isinstance(cmap, dict):
                    continue
                for map_node in sub_node.findall('map'):
                    delete = str(map_node.attrib.get('delete', 'false')).lower() in {'1', 'true', 'yes'}
                    map_apply = sub_apply_all or delete or str(map_node.attrib.get('apply', 'false')).lower() in {'1', 'true', 'yes'}
                    if not map_apply:
                        continue
                    code = self._parseCodepoint(map_node.attrib.get('codepoint'))
                    if code is None:
                        continue
                    glyph_name = str(map_node.attrib.get('glyph') or EMPTY_STRING).strip()
                    if delete:
                        if code in cmap:
                            del cmap[code]
                            changed += 1
                        continue
                    if glyph_name and cmap.get(code) != glyph_name:
                        cmap[code] = glyph_name
                        changed += 1
        return changed

    def shouldNormalizeMonospaceWidth(self) -> bool:
        stem = self.path.stem.lower().replace('-', '').replace('_', '')
        if self.isColor or 'emoji' in stem or 'symbols' in stem:
            return False
        return stem in TRIODESKTOP_MONO_REPAIR_STEMS

    def applyMetadataXml(self, xmlPath: Path | str | None = None, backup: bool = True, regenerate: bool = True) -> bool:
        import xml.etree.ElementTree as ET
        xml_path = Path(xmlPath) if xmlPath is not None else self.metadataXmlPath()
        print(f'\n[Font] Applying metadata XML: {xml_path.name} -> {self.path.name}', flush=True)
        if not xml_path.exists():
            print(f'   [Font:WARN] metadata XML does not exist: {xml_path}', flush=True)
            return False
        try:
            root = ET.parse(str(xml_path)).getroot()
        except Exception as error:
            recordException('start.py:font-apply-xml-parse', sys.exc_info()[1])
            print(f'   [Font:ERROR] cannot parse XML: {type(error).__name__}: {error}', flush=True)
            return False
        if root.tag != 'fontMetadata':
            print(f'   [Font:ERROR] unsupported metadata root: {root.tag}', flush=True)
            return False
        if backup:
            self.backup()
        changed = 0
        try:
            font = self.openFont()
            try:
                changed += self._applyNameMetadata(font, root)
                changed += self._applyMetricMetadata(font, root)
                changed += self._applyCmapMetadata(font, root)
                if changed:
                    flavor = str(root.attrib.get('flavor') or EMPTY_STRING).strip().lower()
                    if self.extension == '.woff2' or flavor == 'woff2':
                        font.flavor = 'woff2'
                    elif self.extension == '.woff' or flavor == 'woff':
                        font.flavor = 'woff'
                    font.save(str(self.path))
                    print(f'   [Font] updated physical font file; changed fields/glyphs/maps={changed}', flush=True)
                else:
                    print('   [Font] XML matched current font; no file changes needed', flush=True)
            finally:
                try:
                    font.close()
                except Exception:
                    recordException('start.py:font-apply-xml-close', sys.exc_info()[1])
        except Exception as error:
            recordException('start.py:font-apply-xml', sys.exc_info()[1])
            print(f'   [Font:ERROR] metadata update failed: {type(error).__name__}: {error}', flush=True)
            return False
        if regenerate:
            self.writeRoundTripMetadataXml()
        return bool(changed)

    def installToSystem(self) -> bool:
        if os.name != 'nt':
            print('   [Font:WARN] system font install is currently Windows-only', flush=True)
            return False
        try:
            destination = Path(r'C:\Windows\Fonts') / self.path.name
            File(self.path).copyTo(destination)
            print(f'   [Font] installed to system fonts: {destination}', flush=True)
            return True
        except PermissionError:
            print('   [Font:ERROR] permission denied; run elevated for system font install', flush=True)
        except Exception as error:
            recordException('start.py:font-install-system', sys.exc_info()[1])
            print(f'   [Font:ERROR] system install failed: {type(error).__name__}: {error}', flush=True)
        return False

    @staticmethod
    def updateEmbeddedFontBlobs(fonts: list['Font'], report: list[str]) -> bool:
        # Font blobs are intentionally no longer embedded in data.py. The repo
        # carries exactly two canonical font files: default.otf and
        # default.otf. Keeping embedded copies made the runtime ambiguous
        # and could silently restore stale metrics.
        report.append('embedded font blobs skipped: physical default.otf/default.otf are canonical')
        return False

    @staticmethod
    def regenerateWoff2FromOtf(report: list[str]) -> None:
        if str(os.environ.get('TRIO_REGENERATE_WOFF2', '0') or '0').strip().lower() not in {'1', 'true', 'yes', 'on'}:
            report.append('woff2 regeneration skipped by default; set TRIO_REGENERATE_WOFF2=1 to rebuild compressed web-font copies')
            return
        if TTFont is None:
            return
        pairs = [(BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH), (BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH)]
        for source, target in pairs:
            if not source.exists():
                continue
            try:
                font = requiredTTFontClass()(str(source), recalcBBoxes=True, recalcTimestamp=False)
                font.flavor = 'woff2'
                font.save(str(target))
                try:
                    font.close()
                except Exception:
                    recordException('start.py:3343', sys.exc_info()[1])
                    _traceSwallowedException('start.py:3270', sys.exc_info()[1])
                    pass
                report.append(f'woff2 regenerated {target.name}')
            except Exception as error:
                recordException('start.py:3347', sys.exc_info()[1])
                report.append(f'woff2 skipped {target.name}: {type(error).__name__}: {error}')

    @classmethod
    def autoRepairAll(cls) -> tuple[int, list[str]]:
        report: list[str] = ['TrioDesktop font auto-repair report', f'timestamp={datetime.datetime.now().isoformat()}']
        fonts = cls.discoverAll()
        if not fonts:
            report.append('no fonts found')
            return 1, report
        exit_code = 0
        woff2_before = {font.path.name: font.md5(font.path) for font in fonts if font.path.suffix.lower() == '.woff2'}
        for font in fonts:
            before = font.md5(font.path)
            if font.path.suffix.lower() == '.woff2':
                line = f'{font.path.name}: ok=1 changed=0 before={before} after={before} deferred=regenerate-from-otf'
                report.append(line)
                print('[FontRepair] ' + line, flush=True)
                continue
            result = font.repair()
            after = font.md5(font.path)
            ok = bool(result.get('ok'))
            if not ok:
                exit_code = 1
            raw_notes = result.get('notes', [])
            note_items = raw_notes if isinstance(raw_notes, list) else []
            notes = '; '.join(str(item) for item in note_items)
            line = f'{font.path.name}: ok={int(ok)} changed={int(before != after)} before={before} after={after} {notes}'
            report.append(line)
            print('[FontRepair] ' + line, flush=True)
        cls.regenerateWoff2FromOtf(report)
        for font in cls.discoverAll():
            if font.path.suffix.lower() == '.woff2':
                before = woff2_before.get(font.path.name, EMPTY_STRING)
                after = font.md5(font.path)
                line = f'{font.path.name}: regenerated=1 changed={int(before != after)} before={before} after={after}'
                report.append(line)
                print('[FontRepair] ' + line, flush=True)
        fonts = cls.discoverAll()
        cls.updateEmbeddedFontBlobs(fonts, report)
        report_path = BASE_DIR / 'font_proofs' / 'auto_repair_fonts_report_v147.txt'
        try:
            report_path.parent.mkdir(parents=True, exist_ok=True)
            File(report_path).writeText('\n'.join(report) + '\n')
            print(f'[FontRepair] report={report_path}', flush=True)
        except Exception as error:
            recordException('start.py:3392', sys.exc_info()[1])
            print(f'[WARN:font-repair] report write failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        return int(exit_code), report



def repairFontRequested(argv: list[str] | None = None) -> bool:
    return bool(readCliOption(argv or [], REPAIR_FONT_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))



def _fontMetricNumber(value: object, default: int = 0) -> int:
    return safeInt(value, default)


def _fontMetricOptionalNumber(value: object) -> int | str:
    if value is None:
        return EMPTY_STRING
    text = str(value).strip()
    if not text:
        return EMPTY_STRING
    return safeInt(value, 0)


def _fontMetricBounds(*values: object) -> tuple[int | str, int | str, int | str, int | str]:
    padded = list(values[:4])
    while len(padded) < 4:
        padded.append(None)
    return cast(tuple[int | str, int | str, int | str, int | str], tuple(_fontMetricOptionalNumber(value) for value in padded))


def _fontMetricPairValues(metrics: object, index: int) -> list[int]:
    values: list[int] = []
    if not isinstance(metrics, dict):
        return values
    for pair in metrics.values():
        if not isinstance(pair, (tuple, list)) or len(pair) <= index:
            continue
        values.append(safeInt(pair[index], 0))
    return values

def _fontMetricSummary(path: Path) -> dict[str, object]:
    summary: dict[str, object] = {'path': str(path), 'exists': path.exists(), 'md5': Font.md5(path) if path.exists() else EMPTY_STRING}
    if not path.exists() or TTFont is None:
        return summary
    font = None
    try:
        font = requiredTTFontClass()(str(path), recalcBBoxes=False, recalcTimestamp=False)
        head = font['head'] if 'head' in font else None
        hhea = font['hhea'] if 'hhea' in font else None
        os2 = font['OS/2'] if 'OS/2' in font else None
        hmtx = font['hmtx'].metrics if 'hmtx' in font else {}
        advances = _fontMetricPairValues(hmtx, 0)
        lefts = _fontMetricPairValues(hmtx, 1)
        metric_sources = (
            ('head.unitsPerEm', head, 'unitsPerEm'),
            ('hhea.ascent', hhea, 'ascent'), ('hhea.descent', hhea, 'descent'),
            ('hhea.lineGap', hhea, 'lineGap'), ('hhea.advanceWidthMax', hhea, 'advanceWidthMax'),
            ('OS/2.xAvgCharWidth', os2, 'xAvgCharWidth'), ('OS/2.sTypoAscender', os2, 'sTypoAscender'),
            ('OS/2.sTypoDescender', os2, 'sTypoDescender'), ('OS/2.sTypoLineGap', os2, 'sTypoLineGap'),
            ('OS/2.usWinAscent', os2, 'usWinAscent'), ('OS/2.usWinDescent', os2, 'usWinDescent'),
        )
        summary.update({key: _fontMetricOptionalNumber(getattr(source, attr, None)) for key, source, attr in metric_sources})
        summary['head.bbox'] = _fontMetricBounds(getattr(head, 'xMin', None), getattr(head, 'yMin', None), getattr(head, 'xMax', None), getattr(head, 'yMax', None))
        for prefix, values in (('hmtx.advance', advances), ('hmtx.lsb', lefts)):
            summary[f'{prefix}.min'] = min(values) if values else EMPTY_STRING
            summary[f'{prefix}.max'] = max(values) if values else EMPTY_STRING
        summary['hmtx.advance.unique'] = len(set(advances)) if advances else 0
    except Exception as error:
        recordException('start.py:3460', sys.exc_info()[1])
        summary['error'] = f'{type(error).__name__}: {error}'
    finally:
        try:
            if font is not None:
                font.close()
        except Exception:
            recordException('start.py:3466', sys.exc_info()[1])
            _traceSwallowedException('start.py:3392', sys.exc_info()[1])
            pass
    return summary


def _fontMetricSummaryText(label: str, path: Path) -> str:
    data = _fontMetricSummary(path)
    keys = ['md5', 'head.unitsPerEm', 'head.bbox', 'hhea.ascent', 'hhea.descent', 'hhea.lineGap', 'hhea.advanceWidthMax', 'OS/2.xAvgCharWidth', 'OS/2.sTypoAscender', 'OS/2.sTypoDescender', 'OS/2.sTypoLineGap', 'OS/2.usWinAscent', 'OS/2.usWinDescent', 'hmtx.advance.min', 'hmtx.advance.max', 'hmtx.advance.unique', 'hmtx.lsb.min', 'hmtx.lsb.max']
    parts = [f'{key}={data.get(key, EMPTY_STRING)}' for key in keys]
    return f'{label} {path.name}: ' + ' '.join(parts)


def _terminalFontPostScriptName(family_name: str) -> str:
    raw = re.sub(r'[^A-Za-z0-9]+', '', str(family_name or RECOMMENDED_TERMINAL_FONT))
    return raw or 'defaultotf'


def _setTerminalFontNameTable(font: object, family_name: str, *, style_name: str = 'Regular') -> list[str]:
    """Cache-bust Windows font selection by writing a distinct family/name table."""
    notes: list[str] = []
    try:
        font_obj = cast(Any, font)
        if 'name' not in font_obj:
            return ['name table missing']
        family = str(family_name or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        style = str(style_name or 'Regular').strip() or 'Regular'
        full_name = family if style.lower() == 'regular' else f'{family} {style}'
        postscript = _terminalFontPostScriptName(full_name)
        unique = f'TrioDesktop;{postscript};metrics-v167'
        version = 'Version 1.0.69; TrioDesktop terminal metrics v169'
        name_values = {
            1: family,
            2: style,
            3: unique,
            4: full_name,
            5: version,
            6: postscript,
            16: family,
            17: style,
        }
        name_table = font_obj['name']
        platforms: set[tuple[int, int, int]] = set()
        for record in list(getattr(name_table, 'names', []) or []):
            try:
                platforms.add((int(record.platformID), int(record.platEncID), int(record.langID)))
            except Exception:
                recordException('start.py:3511', sys.exc_info()[1])
                _traceSwallowedException('start.py:3436', sys.exc_info()[1])
                pass
        if not platforms:
            platforms = {(3, 1, 0x409), (1, 0, 0)}
        # Keep the common Windows and Macintosh records even if the source only had one.
        platforms.add((3, 1, 0x409))
        platforms.add((1, 0, 0))
        for name_id, value in name_values.items():
            for platform_id, encoding_id, language_id in platforms:
                try:
                    name_table.setName(value, name_id, platform_id, encoding_id, language_id)
                except Exception:
                    recordException('start.py:3523', sys.exc_info()[1])
                    _traceSwallowedException('start.py:3447', sys.exc_info()[1])
                    pass
        notes.append(f'name.family={family}')
        notes.append(f'name.full={full_name}')
        notes.append(f'name.postscript={postscript}')
    except Exception as error:
        recordException('start.py:3529', sys.exc_info()[1])
        notes.append(f'name-table skipped {type(error).__name__}: {error}')
    return notes


def repair_console_font_metrics(font_path: str | Path, output_path: str | Path | None = None, *, family_name: str | None = None) -> Path | None:
    """Repair TrioDesktop console font metrics for tight terminal use."""
    if not ensureFontToolsForFontRepair():
        print('[FONT-REPAIR] ERROR: fontTools.ttLib is required. Install with: pip install fonttools', file=sys.stderr, flush=True)
        return None
    source_path = Path(font_path)
    if not source_path.exists():
        print(f'[FONT-REPAIR] ERROR: Font not found at {source_path}', file=sys.stderr, flush=True)
        return None
    if output_path is None:
        output_path = source_path.with_name(source_path.stem + '_repaired' + source_path.suffix)
    output = Path(output_path)
    try:
        backup_path = source_path.with_suffix(source_path.suffix + '.bak')
        if not backup_path.exists():
            File(source_path).copyTo(backup_path)
            print(f'[FONT-REPAIR] Backed up original -> {backup_path}', flush=True)
        before_md5 = Font.md5(source_path)
        print(f'[FONT-REPAIR] Repairing {source_path.name} before={before_md5}', flush=True)
        print('[FONT-REPAIR] ' + _fontMetricSummaryText('BEFORE', source_path), flush=True)
        font = requiredTTFontClass()(str(source_path), recalcBBoxes=True, recalcTimestamp=False)
        chosen_family = str(family_name or (RECOMMENDED_TERMINAL_COLOR_FONT if 'color' in source_path.stem.lower() else RECOMMENDED_TERMINAL_FONT)).strip()
        for name_note in _setTerminalFontNameTable(font, chosen_family):
            print(f'    ✓ {name_note}', flush=True)
        target_width = safeInt(Font.repairTargetWidth(600), 600)
        ascender = safeInt(Font.repairAscender(800), 800)
        descender = safeInt(Font.repairDescender(-250), -250)
        padding = Font._configInt('terminal_font', 'repair_padding', 20, 0, 120)
        target_glyph_width = max(1, target_width - (padding * 2))
        glyphs_scaled = 0
        glyphs_centered = 0
        # Critical vertical metrics.
        if 'hhea' in font:
            hhea = font['hhea']
            hhea.ascent = ascender
            hhea.descent = descender
            hhea.lineGap = 0
            hhea.advanceWidthMax = target_width
            try:
                hhea.minLeftSideBearing = 0
                hhea.minRightSideBearing = 0
                hhea.xMaxExtent = target_width
            except Exception:
                recordException('start.py:3576', sys.exc_info()[1])
                _traceSwallowedException('start.py:3499', sys.exc_info()[1])
                pass
            print(f'    ✓ hhea ascent={ascender} descent={descender} lineGap=0 advanceWidthMax={target_width}', flush=True)
        if 'OS/2' in font:
            os2 = font['OS/2']
            os2.xAvgCharWidth = target_width
            os2.sTypoAscender = ascender
            os2.sTypoDescender = descender
            os2.sTypoLineGap = 0
            os2.usWinAscent = max(ascender, 0)
            os2.usWinDescent = abs(min(descender, 0))
            try:
                os2.usWidthClass = 5
                os2.version = max(safeInt(getattr(os2, 'version', 0), 0), 4)
                os2.fsSelection = safeInt(getattr(os2, 'fsSelection', 0), 0) | 0x40 | 0x80 | 0x100
                os2.panose.bProportion = 9
                os2.panose.bFamilyType = max(safeInt(getattr(os2.panose, 'bFamilyType', 0), 0), 2)
            except Exception:
                recordException('start.py:3594', sys.exc_info()[1])
                _traceSwallowedException('start.py:3516', sys.exc_info()[1])
                pass
            print(f'    ✓ OS/2 xAvgCharWidth={target_width} lineGap=0 winAscent={os2.usWinAscent} winDescent={os2.usWinDescent}', flush=True)
        # Pack horizontal glyph boxes so a 600-wide advance is not just a tiny 100-wide glyph with huge side air.
        if 'glyf' in font and 'hmtx' in font:
            glyf = font['glyf']
            hmtx = font['hmtx'].metrics
            try:
                recording_pen_module = runtimeImportModule('fontTools', 'pens', 'recordingPen')
                tt_glyph_pen_module = runtimeImportModule('fontTools', 'pens', 'ttGlyphPen')
                DecomposingRecordingPen = cast(Any, getattr(recording_pen_module, 'DecomposingRecordingPen'))
                TTGlyphPen = cast(Any, getattr(tt_glyph_pen_module, 'TTGlyphPen'))
                glyph_set_for_decompose = font.getGlyphSet()
            except Exception:
                recordException('start.py:3608', sys.exc_info()[1])
                DecomposingRecordingPen = None
                TTGlyphPen = None
                glyph_set_for_decompose = None
            for glyph_name in list(font.getGlyphOrder() or []):
                glyph_name_text = str(glyph_name)
                if glyph_name_text not in glyf:
                    continue
                glyph = glyf[glyph_name_text]
                try:
                    glyph.recalcBounds(glyf)
                except Exception:
                    recordException('start.py:3619', sys.exc_info()[1])
                    _traceSwallowedException('start.py:3540', sys.exc_info()[1])
                    pass
                x_min = getattr(glyph, 'xMin', None)
                x_max = getattr(glyph, 'xMax', None)
                y_min = getattr(glyph, 'yMin', None)
                y_max = getattr(glyph, 'yMax', None)
                has_bounds = None not in (x_min, x_max, y_min, y_max)
                x_min_i = safeInt(x_min, 0) if has_bounds else 0
                x_max_i = safeInt(x_max, 0) if has_bounds else 0
                y_min_i = safeInt(y_min, 0) if has_bounds else 0
                y_max_i = safeInt(y_max, 0) if has_bounds else 0
                width = max(0, x_max_i - x_min_i) if has_bounds else 0
                lower_name = glyph_name_text.lower()
                is_blank = lower_name in {'.notdef', '.null', 'nonmarkingreturn', 'space', 'uni0020', 'u0020', 'tab'} or width <= 0
                if not is_blank:
                    try:
                        try:
                            can_decompose = bool(glyph.isComposite()) and callable(DecomposingRecordingPen) and callable(TTGlyphPen) and glyph_set_for_decompose is not None
                            if can_decompose:
                                decomposing_pen_class = cast(Any, DecomposingRecordingPen)
                                tt_glyph_pen_class = cast(Any, TTGlyphPen)
                                recording_pen = decomposing_pen_class(glyph_set_for_decompose)
                                glyph.draw(recording_pen, glyf)
                                tt_pen = tt_glyph_pen_class(glyph_set_for_decompose)
                                cast(Any, recording_pen).replay(tt_pen)
                                glyf[glyph_name_text] = cast(Any, tt_pen).glyph()
                                glyph = glyf[glyph_name_text]
                                glyph.recalcBounds(glyf)
                                x_min = getattr(glyph, 'xMin', x_min)
                                x_max = getattr(glyph, 'xMax', x_max)
                                y_min = getattr(glyph, 'yMin', y_min)
                                y_max = getattr(glyph, 'yMax', y_max)
                                x_min_i = safeInt(x_min, 0)
                                x_max_i = safeInt(x_max, 0)
                                y_min_i = safeInt(y_min, 0)
                                y_max_i = safeInt(y_max, 0)
                                width = max(0, x_max_i - x_min_i)
                        except Exception:
                            recordException('start.py:3655', sys.exc_info()[1])
                            _traceSwallowedException('start.py:3575', sys.exc_info()[1])
                            pass
                        coords, _end_pts, _flags = glyph.getCoordinates(glyf)
                        if width > 0:
                            height = max(1, y_max_i - y_min_i) if None not in (y_min, y_max) else max(1, ascender - descender)
                            target_height = max(1, int(ascender) - int(descender))
                            # Only repair obviously skinny/full-height glyphs. Do not stretch
                            # natural punctuation; that was making the terminal font look worse.
                            scale_x = 1.0
                            if height >= int(target_height * 0.45) and width < int(target_width * 0.38):
                                scale_x = min(3.0, target_glyph_width / float(width))
                            scale_y = 1.0
                            coords.translate((-x_min_i, 0))
                            coords.scale((scale_x, scale_y))
                            coords.translate((padding, 0))
                            try:
                                coords.toInt()
                            except Exception:
                                recordException('start.py:3673', sys.exc_info()[1])
                                _traceSwallowedException('start.py:3594', sys.exc_info()[1])
                                pass
                            glyphs_scaled += 1
                            try:
                                glyph.recalcBounds(glyf)
                            except Exception:
                                recordException('start.py:3679', sys.exc_info()[1])
                                _traceSwallowedException('start.py:3599', sys.exc_info()[1])
                                pass
                    except Exception:
                        recordException('start.py:3682', sys.exc_info()[1])
                        _traceSwallowedException('start.py:3601', sys.exc_info()[1])
                        pass
                else:
                    try:
                        if has_bounds and x_min_i != 0:
                            coords, _end_pts, _flags = glyph.getCoordinates(glyf)
                            coords.translate((-x_min_i, 0))
                            try:
                                coords.toInt()
                            except Exception:
                                recordException('start.py:3692', sys.exc_info()[1])
                                _traceSwallowedException('start.py:3610', sys.exc_info()[1])
                                pass
                            glyphs_centered += 1
                            glyph.recalcBounds(glyf)
                    except Exception:
                        recordException('start.py:3697', sys.exc_info()[1])
                        _traceSwallowedException('start.py:3614', sys.exc_info()[1])
                        pass
                try:
                    lsb = safeInt(getattr(glyph, 'xMin', 0), 0) if not is_blank else 0
                    hmtx[glyph_name_text] = (target_width, max(0, min(int(target_width) - 1, lsb)))
                except Exception:
                    recordException('start.py:3703', sys.exc_info()[1])
                    _traceSwallowedException('start.py:3619', sys.exc_info()[1])
                    pass
            print(f'    ✓ glyf packed glyphs={glyphs_scaled} targetWidth={target_width} padding={padding}', flush=True)
        elif 'hmtx' in font:
            hmtx = font['hmtx'].metrics
            for glyph_name in list(font.getGlyphOrder() or []):
                try:
                    hmtx[str(glyph_name)] = (target_width, 0)
                except Exception:
                    recordException('start.py:3712', sys.exc_info()[1])
                    _traceSwallowedException('start.py:3627', sys.exc_info()[1])
                    pass
            print(f'    ✓ hmtx normalized targetWidth={target_width}', flush=True)
        if 'head' in font:
            head = font['head']
            try:
                # Preserve unitsPerEm unless it is clearly unusable; the mono font is already 1000.
                if safeInt(getattr(head, 'unitsPerEm', 0), 0) <= 0:
                    head.unitsPerEm = 1000
                head.xMin = 0
                head.yMin = descender
                head.xMax = target_width
                head.yMax = ascender
            except Exception:
                recordException('start.py:3726', sys.exc_info()[1])
                _traceSwallowedException('start.py:3640', sys.exc_info()[1])
                pass
        if 'post' in font:
            try:
                font['post'].isFixedPitch = 1
            except Exception:
                recordException('start.py:3732', sys.exc_info()[1])
                _traceSwallowedException('start.py:3645', sys.exc_info()[1])
                pass
        if 'kern' in font:
            try:
                del font['kern']
            except Exception:
                recordException('start.py:3738', sys.exc_info()[1])
                _traceSwallowedException('start.py:3650', sys.exc_info()[1])
                pass
        try:
            font.recalcBBoxes = False
        except Exception:
            recordException('start.py:3743', sys.exc_info()[1])
            _traceSwallowedException('start.py:3654', sys.exc_info()[1])
            pass
        font.save(str(output))
        try:
            font.close()
        except Exception:
            recordException('start.py:3749', sys.exc_info()[1])
            _traceSwallowedException('start.py:3659', sys.exc_info()[1])
            pass
        after_md5 = Font.md5(output)
        print('[FONT-REPAIR] ', end=EMPTY_STRING, flush=True)
        printStatus(STATUS_SUCCESS, f'-> {output} after={after_md5} changed={int(before_md5 != after_md5)}')
        print('[FONT-REPAIR] ' + _fontMetricSummaryText('AFTER', output), flush=True)
        return output
    except Exception as error:
        recordException('start.py:3756', sys.exc_info()[1])
        print(f'[FONT-REPAIR] ERROR: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        try:
            print(traceback.format_exc(), file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:3760', sys.exc_info()[1])
            _traceSwallowedException('start.py:3669', sys.exc_info()[1])
            pass
        return None


def _rebuildWoff2FromOtf(source: Path, target: Path, report: list[str]) -> bool:
    try:
        if TTFont is None or not source.exists():
            return False
        before = Font.md5(target) if target.exists() else EMPTY_STRING
        font = requiredTTFontClass()(str(source), recalcBBoxes=True, recalcTimestamp=False)
        font.flavor = 'woff2'
        font.save(str(target))
        try:
            font.close()
        except Exception:
            recordException('start.py:3776', sys.exc_info()[1])
            _traceSwallowedException('start.py:3684', sys.exc_info()[1])
            pass
        after = Font.md5(target)
        report.append(f'woff2 rebuilt {source.name}->{target.name} changed={int(before != after)} before={before} after={after}')
        print(f'[FONT-REPAIR] woff2 rebuilt {target} changed={int(before != after)} md5={after}', flush=True)
        return True
    except Exception as error:
        recordException('start.py:3783', sys.exc_info()[1])
        report.append(f'woff2 rebuild failed {target.name}: {type(error).__name__}: {error}')
        print(f'[WARN:font-repair] woff2 rebuild failed {target.name}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        return False


def runRepairFontCli(argv: list[str] | None = None) -> int:
    if not ensureFontToolsForFontRepair():
        print('[FONT-REPAIR] ERROR: fontTools.ttLib is unavailable. Install with: pip install fonttools', file=sys.stderr, flush=True)
        return 2
    print('[FONT-REPAIR] Starting TrioDesktop console font repair...', flush=True)
    report: list[str] = ['TrioDesktop console font repair report', f'timestamp={datetime.datetime.now().isoformat()}']
    candidates = [BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH]
    repaired_any = False
    for candidate in candidates:
        if not candidate.exists():
            report.append(f'missing {candidate}')
            continue
        before = Font.md5(candidate)
        repair_family = RECOMMENDED_TERMINAL_COLOR_FONT if 'color' in candidate.stem.lower() else RECOMMENDED_TERMINAL_FONT
        repaired = repair_console_font_metrics(candidate, candidate, family_name=repair_family)
        after = Font.md5(candidate)
        ok = repaired is not None and repaired.exists()
        repaired_any = repaired_any or ok
        report.append(f'{candidate.name}: ok={int(ok)} changed={int(before != after)} before={before} after={after}')
    if str(os.environ.get('TRIO_REGENERATE_WOFF2', '0') or '0').strip().lower() in {'1', 'true', 'yes', 'on'}:
        _rebuildWoff2FromOtf(BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH, report)
        _rebuildWoff2FromOtf(BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH, BASE_DIR / DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH, report)
    else:
        report.append('woff2 aliases not regenerated; source repo keeps only default.otf and default.otf')
    materializeDefaultFontAliases(report)
    fonts = Font.discoverAll()
    Font.updateEmbeddedFontBlobs(fonts, report)
    metadata_code, metadata_report = Font.writeMetadataAll('default')
    report.extend(metadata_report)
    for path in candidates:
        if path.exists(): print('[FONT-REPAIR] ' + _fontMetricSummaryText('FINAL', path), flush=True)
    try:
        report_path = BASE_DIR / 'font_repair_report.txt'
        File(report_path).writeText('\n'.join(str(line) for line in report) + '\n')
        print(f'[FONT-REPAIR] report={report_path}', flush=True)
    except Exception as error:
        recordException('start.py:3824', sys.exc_info()[1])
        print(f'[WARN:font-repair] report write failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
    if os.name == 'nt' and repaired_any:
        try:
            font_path = bundledTerminalFontPath(); desired = bundledTerminalFontFace(font_path)
            print(f'[FONT-REPAIR] Installing repaired font for current user: {font_path} face={desired}', flush=True)
            _installFontForCurrentUser(font_path, desired); applyRecommendedConsoleFont(desired)
        except Exception as error:
            recordException('start.py:3831', sys.exc_info()[1])
            print(f'[WARN:font-repair] install/apply skipped: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
    print('[FONT-REPAIR] ', end=EMPTY_STRING, flush=True)
    printStatus(STATUS_SUCCESS if repaired_any else STATUS_FAILED, 'Repair complete. Restart PowerShell / Windows Terminal for the change to take effect.' if repaired_any else 'Could not locate or repair font.')
    return 0 if repaired_any and int(metadata_code) == 0 else 1

