def ensureFontToolsForFontRepair() -> bool:
    global FONTTOOLS_TTLIB_MODULE, TTFont
    if TTFont is not None:
        return True
    candidate_paths = [
        os.environ.get('TRIO_FONTTOOLS_SITE_PACKAGES', EMPTY_STRING),
        '/opt/pyvenv/lib/python3.13/site-packages',
        '/usr/local/lib/python3.13/dist-packages',
        '/usr/local/lib/python3.13/site-packages',
    ]
    for candidate in candidate_paths:
        text_path = str(candidate or EMPTY_STRING).strip()
        if text_path and Path(text_path).exists() and text_path not in sys.path:
            sys.path.insert(0, text_path)
        try:
            module = runtimeImportModule('fontTools', 'ttLib')
            FONTTOOLS_TTLIB_MODULE = module
            TTFont = getattr(module, 'TTFont', None)
            if TTFont is not None:
                return True
        except Exception:
            recordException('start.py:3868', sys.exc_info()[1])
            _traceSwallowedException('start.py:3775', sys.exc_info()[1])
            continue
    return False


