def runUpdateFontMetadata(argv: list[str] | None = None) -> int:
    prior = os.environ.get('TRIO_REGENERATE_WOFF2')
    os.environ['TRIO_REGENERATE_WOFF2'] = '1'
    try:
        # runRepairFontCli already repairs metrics, rebuilds WOFF2, refreshes
        # default aliases, updates embedded blobs, and writes metadata XML for
        # all discovered fonts. Do not immediately run --font-metadata again;
        # that re-dumps the same huge TTX XML files and makes --update-metadata
        # look hung even after the useful work has completed.
        return int(runRepairFontCli(argv or []))
    finally:
        if prior is None:
            os.environ.pop('TRIO_REGENERATE_WOFF2', None)
        else:
            os.environ['TRIO_REGENERATE_WOFF2'] = prior



def _plainDiagnosticText(text: object) -> str:
    return re.sub(r'\x1b\[[0-9;]*m', EMPTY_STRING, str(text if text is not None else EMPTY_STRING))


def _diagnosticReportPath(name: str) -> Path:
    logs_dir = BASE_DIR / 'logs'
    logs_dir.mkdir(parents=True, exist_ok=True)
    safe_name = re.sub(r'[^A-Za-z0-9_.-]+', '_', str(name or 'diagnostic').strip()).strip('._') or 'diagnostic'
    if not safe_name.lower().endswith('.txt'):
        safe_name += '.txt'
    return logs_dir / safe_name


def _emitDiagnosticPage(name: str, lines: list[str], *, echo: bool = True) -> Path:
    path = _diagnosticReportPath(name)
    text = '\n'.join(_plainDiagnosticText(line) for line in list(lines or [])) + '\n'
    File(path).writeText(text)
    if echo:
        for line in list(lines or []):
            print(str(line), flush=True)
        print(f'[TRACE:diagnostic-output] {path}', flush=True)
    return path


def _runCapturedCommand(label: str, command: list[str], *, cwd: Path | str | None = None, timeout: int = 120) -> tuple[int, list[str]]:
    lines = [f'$ {shlex.join([str(part) for part in command])}']
    try:
        proc = monitoredRawPopen(
            [str(part) for part in command],
            sourceLine=_callerSourceContext(skip=2),
            windowPolicy=WINDOW_POLICY_HELPER,
            cwd=str(cwd or BASE_DIR),
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            stdin=subprocess.DEVNULL,
            text=True,
        )
        try:
            stdout, stderr = proc.communicate(timeout=int(timeout or 120))
        except subprocess.TimeoutExpired:
            try:
                proc.kill()
            except Exception:
                recordException(f'start.py:{label}.kill-timeout', sys.exc_info()[1])
            stdout, stderr = proc.communicate(timeout=5)
            lines.append(f'{label} timeout after {timeout}s')
            code = 124
        else:
            code = int(getattr(proc, 'returncode', 1) or 0)
        lines.append(f'{label} exit={code}')
        if str(stdout or EMPTY_STRING).strip():
            lines.extend(str(stdout).rstrip().splitlines())
        if str(stderr or EMPTY_STRING).strip():
            lines.append('[stderr]')
            lines.extend(str(stderr).rstrip().splitlines())
        return code, lines
    except Exception as error:
        recordException(f'start.py:{label}', sys.exc_info()[1])
        lines.append(f'{label} exception: {type(error).__name__}: {error}')
        lines.extend(traceback.format_exc().splitlines())
        return 1, lines


def _promptDiagnosticChoice(prompt: str, default: str = EMPTY_STRING) -> str:
    if not getattr(sys.stdin, 'isatty', lambda: False)():
        return str(default or EMPTY_STRING)
    try:
        value = input(prompt)
        value = str(value or EMPTY_STRING).strip()
        return value if value else str(default or EMPTY_STRING)
    except EOFError:  # swallow-ok: noninteractive prompt should return the default
        return str(default or EMPTY_STRING)
    except Exception:
        recordException('start.py:diagnostic-prompt', sys.exc_info()[1])
        return str(default or EMPTY_STRING)


def _fontInstallCheckLines(font_path: Path, font_name: str) -> list[str]:
    info = _detectFontInstalled(font_path, font_name)
    source_md5 = str(info.get('source_md5') or safeFileMd5Hex(font_path) or EMPTY_STRING)
    lines = [
        f'Install check for {font_name}:',
        f'  source: {font_path}',
        f'  source_md5: {source_md5}',
        f'  installed: {bool(info.get("installed"))}',
        f'  md5_match: {bool(info.get("md5_match"))}',
        f'  paths: {info.get("paths", [])}',
        f'  registry: {info.get("registry", [])}',
    ]
    lines.append('  status: ' + (coloredStatusText(STATUS_SUCCESS) if bool(info.get('ok')) else coloredStatusText(STATUS_FAILED)))
    return lines


def runFontMenu(argv: list[str] | None = None) -> int:
    lines: list[str] = []
    lines.extend([
        '=== FlatLine Font Diagnostic Page ===',
        f'Base directory: {BASE_DIR}',
        f'Default mono font path: {STATUS_COLOR_BLUE}{(BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH).resolve()}{STATUS_COLOR_RESET}',
        f'Default color font path: {STATUS_COLOR_BLUE}{(BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH).resolve()}{STATUS_COLOR_RESET}',
        f'Recommended terminal font: {RECOMMENDED_TERMINAL_FONT}',
        '',
        'Font CLI arguments:',
        '  --font / --fonts                 Show this page and optionally install/change fonts',
        '  --repair-font / --repair-fonts   Repair terminal font metrics',
        '  --font-metadata                  Rebuild font XML metadata',
        '  --update-metadata                Repair and regenerate font XML/WOFF metadata',
        '  --ps7-font                       Install/apply PowerShell terminal font',
        '',
        'Discovered fonts:',
    ])
    fonts = Font.discoverAll()
    if not fonts:
        lines.append('  (none)')
    for index, font in enumerate(fonts, 1):
        path = Path(font.path)
        lines.append(f'{index}. {font.name}{font.extension} face={font.faceName} path={path} md5={Font.md5(path)} mtime={_formatFileMtime(path)}')
    font_path = bundledTerminalFontPath()
    face = bundledTerminalFontFace(font_path) or RECOMMENDED_TERMINAL_FONT
    lines.extend(['', 'Install/change options:', '  1) Install font in Windows current-user fonts', '  2) Update PowerShell Terminal font', '  3) Update Python/IDLE interpreter font', '  4) Do all three', '  Enter) Report only'])
    choice = _promptDiagnosticChoice('Font action [1/2/3/4/Enter=skip]: ', EMPTY_STRING)
    if choice:
        lines.append(f'Selected action: {choice}')
    try:
        if choice in {'1', '4'}:
            ok = Font(font_path).installFont(face)
            lines.append(f'Windows current-user install returned: {coloredStatusText(STATUS_SUCCESS if ok else STATUS_FAILED)}')
            lines.extend(_fontInstallCheckLines(font_path, face))
        if choice in {'2', '4'}:
            ok = PowerShell().changeFont(face)
            lines.append(f'PowerShell terminal font update returned: {coloredStatusText(STATUS_SUCCESS if ok else STATUS_FAILED)}')
            lines.extend(_fontInstallCheckLines(font_path, face))
        if choice in {'3', '4'}:
            ok = PythonTerminal().changeFont(face)
            lines.append(f'Python/IDLE terminal font update returned: {coloredStatusText(STATUS_SUCCESS if ok else STATUS_FAILED)}')
            lines.extend(_fontInstallCheckLines(font_path, face))
    except Exception as error:
        recordException('start.py:font-page-action', sys.exc_info()[1])
        lines.append(f'{STATUS_COLOR_RED}Font action exception: {type(error).__name__}: {error}{STATUS_COLOR_RESET}')
        lines.extend(traceback.format_exc().splitlines())
    _emitDiagnosticPage('font_page.txt', lines)
    sys.stdout.flush(); sys.stderr.flush(); os._exit(0)


def _glyphOutputPath(font_ref: str, codepoint: int, requested: str = EMPTY_STRING) -> Path:
    if requested:
        return Path(requested).expanduser().resolve()
    glyph_dir = BASE_DIR / 'glyphs'
    glyph_dir.mkdir(parents=True, exist_ok=True)
    safe_stem = re.sub(r'[^A-Za-z0-9._-]+', '_', Path(str(font_ref or 'default')).stem).strip('._') or 'default'
    return (glyph_dir / f'{safe_stem}_U{int(codepoint):06X}.png').resolve()


def _renderGlyphWithImagemagick(svg_path: Path, output_path: Path) -> bool:
    command = shutil.which('magick') or shutil.which('convert')
    if not command:
        return False
    try:
        completed = launcherRunCommand([command, str(svg_path), str(output_path)], cwd=str(BASE_DIR), capture_output=True, text=True, timeout=60, check=False)
        return int(getattr(completed, 'returncode', 1) or 0) == 0 and output_path.exists()
    except Exception as error:
        recordException('start.py:3954', sys.exc_info()[1])
        traceCompilerStep('glyph-imagemagick', False, f'{type(error).__name__}: {error}')
        return False



def _resolveFontReferencePath(font_ref: str) -> Path | None:
    text = str(font_ref or EMPTY_STRING).strip()
    if not text:
        return None
    candidate = Path(text)
    if candidate.exists():
        return candidate.resolve()
    repo_candidate = BASE_DIR / text
    if repo_candidate.exists():
        return repo_candidate.resolve()
    fonts_candidate = BASE_DIR / 'fonts' / text
    if fonts_candidate.exists():
        return fonts_candidate.resolve()
    materialized = _materializeEmbeddedStoredFile(text, directory=BASE_DIR / 'fonts')
    if materialized and materialized.exists():
        return materialized.resolve()
    return None


def _renderGlyphDirectWithImagemagick(font_path: Path, codepoint: int, output_path: Path) -> bool:
    command = shutil.which('magick') or shutil.which('convert')
    if not command:
        return False
    glyph_char = chr(int(codepoint))
    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    try:
        completed = launcherRunCommand([
            command,
            '-background', '#10141a',
            '-fill', '#8cff96',
            '-font', str(font_path),
            '-pointsize', '320',
            f'label:{glyph_char}',
            str(out_path),
        ], cwd=str(BASE_DIR), capture_output=True, text=True, timeout=60, check=False)
        ok = int(getattr(completed, 'returncode', 1) or 0) == 0 and out_path.exists()
        traceCompilerStep('glyph-imagemagick-direct', ok, f'font={font_path} output={out_path}')
        return ok
    except Exception as error:
        recordException('start.py:3999', sys.exc_info()[1])
        traceCompilerStep('glyph-imagemagick-direct', False, f'{type(error).__name__}: {error}')
        return False



def _defaultGlyphFontReference() -> str:
    try:
        return str(bundledTerminalFontPath())
    except Exception:
        recordException('start.py:4008', sys.exc_info()[1])
        return str(BUNDLED_TERMINAL_FONT_RELATIVE_PATH)


def _defaultColorGlyphFontReference() -> str:
    return str((BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH).resolve())


def _glyphFontReferenceIsDefaultColor(font_ref: str) -> bool:
    normalized = str(font_ref or EMPTY_STRING).strip().lower()
    return normalized in {'default', 'default_color', 'color-default', 'color_default', 'color', 'colour', 'colored', 'coloured'}


def _glyphFontReferenceIsDefault(font_ref: str) -> bool:
    normalized = str(font_ref or EMPTY_STRING).strip().lower()
    return normalized in {EMPTY_STRING, 'default', 'terminal', 'console', 'bundled', 'mono', 'trio', 'trio-terminal', 'triodesktop'}


def _glyphLooksLikeCodepoint(text: str) -> bool:
    value = str(text or EMPTY_STRING).strip()
    if not value:
        return False
    try:
        TTFFont.parseCodepoint(value)
        return True
    except Exception:
        recordException('start.py:4033', sys.exc_info()[1])
        return False


def _glyphMetricReport(font, codepoint: int) -> list[str]:
    rows: list[str] = []
    try:
        raw_font = getattr(font, 'font', None)
        glyph_set = getattr(font, 'glyphSet', None)
        glyph_name = font.glyphName(codepoint)
        if raw_font is None or glyph_set is None or not glyph_name:
            return rows
        units = safeInt(getattr(raw_font.get('head'), 'unitsPerEm', 0), 0)
        hhea = raw_font.get('hhea') if 'hhea' in raw_font else None
        ascent = safeInt(getattr(hhea, 'ascent', 0), 0)
        descent = safeInt(getattr(hhea, 'descent', 0), 0)
        glyph = glyph_set[glyph_name]
        try:
            bounds_pen_module = runtimeImportModule('fontTools', 'pens', 'boundsPen')
            BoundsPen = cast(Any, getattr(bounds_pen_module, 'BoundsPen'))
            pen = BoundsPen(glyph_set)
            glyph.draw(pen)
            bounds = pen.bounds
        except Exception:
            recordException('start.py:4056', sys.exc_info()[1])
            bounds = None
        advance = safeInt(getattr(glyph, 'width', 0), 0)
        rows.append(f'[GlyphMetrics] unitsPerEm={units} ascent={ascent} descent={descent} advance={advance}')
        rows.append(f'[GlyphMetrics] bounds={bounds}')
        if bounds:
            x_min, y_min, x_max, y_max = [float(item) for item in bounds]
            width = max(0.0, x_max - x_min)
            height = max(0.0, y_max - y_min)
            rows.append(f'[GlyphMetrics] box width={width:.1f} height={height:.1f} xMin={x_min:.1f} xMax={x_max:.1f} yMin={y_min:.1f} yMax={y_max:.1f}')
            if advance > 0 and (x_min < 0 or x_max > advance):
                rows.append(f'[WARN:glyph-metrics] outline exceeds terminal cell: xMin={x_min:.1f}, xMax={x_max:.1f}, advance={advance}')
            if units > 0:
                rows.append(f'[GlyphMetrics] height/em={height / units:.3f} width/em={width / units:.3f}')
    except Exception as metric_error:
        recordException('start.py:4070', sys.exc_info()[1])
        rows.append(f'[WARN:glyph-metrics] {type(metric_error).__name__}: {metric_error}')
    return rows

def runExtractGlyph(argv=None) -> int:
    ensureFontToolsForFontRepair()
    tokens = _start_cli_token_list(argv)
    option = readCliOption(tokens, EXTRACT_GLYPH_FLAGS, takesValue=True, knownAliases=START_VALID_CLI_ALIASES)
    if not option.get('present'):
        return 1

    option_index = safeInt(option.get('index', -1), -1)
    option_token = str(option.get('token') or EMPTY_STRING)
    consumed_value_in_token = bool('=' in option_token or ':' in option_token)
    first_value = str(option.get('value') or EMPTY_STRING).strip()
    cursor = option_index + (1 if consumed_value_in_token else (2 if first_value else 1))

    font_ref = first_value
    glyph_text = EMPTY_STRING

    if first_value and (_glyphLooksLikeCodepoint(first_value) or _glyphFontReferenceIsDefault(first_value) or _glyphFontReferenceIsDefaultColor(first_value)):
        if _glyphLooksLikeCodepoint(first_value):
            font_ref = 'default'
            glyph_text = first_value
        else:
            font_ref = first_value
            glyph_text = str(tokens[cursor] or EMPTY_STRING).strip() if 0 <= cursor < len(tokens) else EMPTY_STRING
            cursor += 1
    else:
        glyph_text = str(tokens[cursor] or EMPTY_STRING).strip() if 0 <= cursor < len(tokens) else EMPTY_STRING
        cursor += 1

    if _glyphFontReferenceIsDefaultColor(font_ref):
        font_ref = _defaultColorGlyphFontReference()
    elif _glyphFontReferenceIsDefault(font_ref):
        font_ref = _defaultGlyphFontReference()

    if not glyph_text or (cliTokenLooksLikeOption(glyph_text, START_VALID_CLI_ALIASES) and not _glyphLooksLikeCodepoint(glyph_text)):
        print('[WARN:glyph] Usage: python start.py --extract-glyph [default|terminal|font-file-or-embedded-name] <U+CODEPOINT|0xHEX|integer|char> [output.png|svg|jpg]', flush=True)
        print('[WARN:glyph] Examples:', flush=True)
        print('  python start.py --extract-glyph U+1F525', flush=True)
        print('  python start.py --extract-glyph default A glyphs/default_A.png', flush=True)
        print('  python start.py --extract-glyph default.otf 0x41', flush=True)
        return 1

    output_text = EMPTY_STRING
    if cursor < len(tokens):
        candidate_output = str(tokens[cursor] or EMPTY_STRING).strip()
        lowered_output = candidate_output.lower()
        if candidate_output and lowered_output not in START_VALID_CLI_ALIASES and not lowered_output.startswith('--'):
            output_text = stripCliValueQuotes(candidate_output)

    try:
        font = TTFFont.ForReference(font_ref)
        codepoint = TTFFont.parseCodepoint(glyph_text)
        has_glyph = bool(font.hasGlyph(codepoint))
        glyph_name = font.glyphName(codepoint)
        out_path = _glyphOutputPath('default' if str(font_ref) == _defaultGlyphFontReference() else font_ref, codepoint, output_text)
        if not has_glyph:
            print(f'[WARN:glyph] {font_ref} does not contain U+{codepoint:04X}', flush=True)
            return 2
        requested_suffix = out_path.suffix.lower()
        if requested_suffix in {'.png', '.jpg', '.jpeg', '.webp'}:
            svg_path = out_path.with_suffix('.svg')
            font.glyphToImage(codepoint, svg_path, size=512, fill='#8cff96', background='#10141a')
            if not _renderGlyphWithImagemagick(svg_path, out_path):
                out_path = svg_path
                print('[WARN:glyph] ImageMagick/Cairo conversion unavailable; wrote SVG fallback.', flush=True)
        else:
            if requested_suffix not in {'.svg', EMPTY_STRING}:
                print(f'[WARN:glyph] Unsupported extension {requested_suffix}; writing SVG data anyway.', flush=True)
            font.glyphToImage(codepoint, out_path, size=512, fill='#8cff96', background='#10141a')
        print(f'[Glyph] font={font_ref}', flush=True)
        print(f'[Glyph] resolved={getattr(font, "fontPath", font_ref)}', flush=True)
        print(f'[Glyph] U+{codepoint:04X} glyph={glyph_name} hasGlyph={has_glyph}', flush=True)
        for metric_line in _glyphMetricReport(font, codepoint):
            print(metric_line, flush=True)
        print(f'[Glyph] output={out_path}', flush=True)
        return 0
    except Exception as error:
        recordException('start.py:4149', sys.exc_info()[1])
        try:
            codepoint = TTFFont.parseCodepoint(glyph_text)
            out_path = _glyphOutputPath(font_ref, codepoint, output_text)
            if out_path.suffix.lower() not in {'.png', '.jpg', '.jpeg', '.webp'}:
                out_path = out_path.with_suffix('.png')
            font_path = _resolveFontReferencePath(font_ref)
            if font_path is not None and _renderGlyphDirectWithImagemagick(font_path, codepoint, out_path):
                print(f'[Glyph] font={font_ref}', flush=True)
                print(f'[Glyph] resolved={font_path}', flush=True)
                print(f'[Glyph] U+{codepoint:04X} glyph=(rendered by ImageMagick fallback) hasGlyph=unknown', flush=True)
                print(f'[Glyph] output={out_path}', flush=True)
                print(f'[WARN:glyph] TTFFont/fontTools path failed first: {type(error).__name__}: {error}', flush=True)
                return 0
        except Exception:
            recordException('start.py:4163', sys.exc_info()[1])
            _traceSwallowedException('start.py:4068', sys.exc_info()[1])
            pass
        print(f'[WARN:glyph] {type(error).__name__}: {error}', flush=True)
        try:
            print(traceback.format_exc(), flush=True)
        except Exception:
            recordException('start.py:4169', sys.exc_info()[1])
            _traceSwallowedException('start.py:4073', sys.exc_info()[1])
            pass
        return 1


def runPs7FontInstall(argv=None) -> int:
    if os.name != 'nt':
        traceCompilerStep('ps7-font-install', False, 'PS7 font install is Windows-only')
        return 1
    result = startupTerminalFontHandshake(list(argv or []))
    ok = bool(result.get('ok'))
    traceCompilerStep('ps7-font-install', ok, f"desired={result.get('desired')} reason={result.get('reason')}")
    return 0 if ok else 1

def runCliSkillSeed(argv=None) -> int:
    try:
        db = Database.ForSqlitePath(BASE_DIR / 'triodesktop.db')
        db.EnsureTables([KnowledgeRecordOrm])
        category = 'SKILL Doc: 325 - start.py CLI'
        rule = ('Use start.py as a run-and-exit tool surface when the launcher can help faster than the GUI. Supported diagnostic commands include --font/--fonts, --database, --files, --health/--code-health/--codehealth, --env/--environment, --file-test, --api-test [prompt], --testchat, --db-test [MariaDB|SQLite], --font-change-test, --import-test, --env-test, and --skill-cli. These commands should run their checks, print trace lines and warnings, then exit without launching the GUI.')
        with db.Session() as session:
            existing = session.scalar(select(KnowledgeRecordOrm).where(ormColumn(KnowledgeRecordOrm, "category") == category).limit(1))
            if existing is None:
                session.add(KnowledgeRecordOrm(source='system', category=category, rule=rule, added=datetime.datetime.now()))
            else:
                existing.source = 'system'
                existing.rule = rule
        traceCompilerStep('skill-cli-seed', True, category)
        return 0
    except Exception as error:
        recordException('start.py:4199', sys.exc_info()[1])
        traceCompilerStep('skill-cli-seed', False, f'{type(error).__name__}: {error}')
        return 1



def _formatFileMtime(path: Path) -> str:
    try:
        if not path.exists():
            return '(missing)'
        return datetime.datetime.fromtimestamp(path.stat().st_mtime).isoformat(sep=' ', timespec='seconds')
    except Exception:
        recordException('start.py:format-file-mtime', sys.exc_info()[1])
        return '(error)'


