def runDatabasePage(argv=None) -> int:
    lines = ['=== FlatLine Database Diagnostic Page ===', f'Base directory: {BASE_DIR}', 'Connection settings:']
    lines.extend('  ' + row for row in _databaseSettingsLines())
    try:
        import importlib.metadata as _metadata
        sqlalchemy_version = _metadata.version('SQLAlchemy')
    except Exception as error:
        recordException('start.py:database-page-sqlalchemy-version', sys.exc_info()[1])
        sqlalchemy_version = f'unavailable ({type(error).__name__}: {error})'
    lines.append(f'SQLAlchemy version: {sqlalchemy_version}')
    try:
        backend = str(os.environ.get('TRIO_DB_BACKEND', 'sqlite') or 'sqlite').strip().lower()
        db = Database.FromEnvironment() if backend == 'mariadb' else Database.ForSqlitePath(BASE_DIR / 'triodesktop.db')
        db.connect(reuse_if_open=True)
        lines.append('Connect: ' + coloredStatusText(STATUS_SUCCESS))
        try:
            inspector_module = runtimeImportModule('sqlalchemy')
            inspector = inspector_module.inspect(db.engine)
            schema_names = []
            try:
                schema_names = [str(item) for item in list(inspector.get_schema_names() or [])]
            except Exception:
                recordException('start.py:database-page-schema-names', sys.exc_info()[1])
            table_names = []
            try:
                table_names = [str(item) for item in list(inspector.get_table_names() or [])]
            except Exception:
                recordException('start.py:database-page-table-names', sys.exc_info()[1])
            lines.append('Databases/schemas:')
            lines.extend('  ' + row for row in (schema_names or ['(not available for this backend)']))
            lines.append('Tables visible in selected database:')
            lines.extend('  ' + row for row in (table_names or ['(none)']))
        except Exception as error:
            recordException('start.py:database-page-inspect', sys.exc_info()[1])
            lines.append(f'Inspect: {coloredStatusText(STATUS_FAILED)} {type(error).__name__}: {error}')
    except Exception as error:
        recordException('start.py:database-page-connect', sys.exc_info()[1])
        lines.append('Connect: ' + coloredStatusText(STATUS_FAILED))
        lines.append(f'{type(error).__name__}: {error}')
        lines.extend(traceback.format_exc().splitlines())
    lines.extend(['', 'Raw SQL detector result:'])
    detector = BASE_DIR / 'vendor' / 'claude' / 'rawsqldetector.py'
    if detector.exists():
        code, out_lines = _runCapturedCommand('rawsql-detector', [sys.executable, str(detector)], cwd=BASE_DIR, timeout=300)
        lines.extend(out_lines)
        lines.append('Raw SQL detector status: ' + coloredStatusText(STATUS_SUCCESS if code == 0 else STATUS_FAILED))
    else:
        lines.append(f'missing detector: {detector}')
    _emitDiagnosticPage('database_page.txt', lines)
    sys.stdout.flush(); sys.stderr.flush(); os._exit(0)


def _repoFilesForPage() -> list[Path]:
    skip = {'.git', '__pycache__', '.mypy_cache', '.ruff_cache'}
    files: list[Path] = []
    for path in BASE_DIR.rglob('*'):
        try:
            rel_parts = path.relative_to(BASE_DIR).parts
        except Exception:
            recordException('start.py:files-page-relative-path', sys.exc_info()[1])
            continue
        if any(part in skip for part in rel_parts):
            continue
        if path.is_file():
            files.append(path)
    return sorted(files, key=lambda item: str(item.relative_to(BASE_DIR)).lower())


def _embeddedFileRows() -> list[tuple[str, int]]:
    rows: list[tuple[str, int]] = []
    try:
        data_module = runtimeImportModule('data')
        factory = getattr(getattr(getattr(data_module, 'EmbeddedData'), 'StoredFilesLibrary'), 'FileFactory')
        blobs = getattr(factory, 'BLOBS', {})
        if isinstance(blobs, dict):
            for name, payload in sorted(blobs.items(), key=lambda item: str(item[0]).lower()):
                size = 0
                try:
                    size = len(str(payload or EMPTY_STRING))
                except Exception:
                    recordException('start.py:files-page-embedded-size', sys.exc_info()[1])
                    size = 0
                rows.append((str(name), int(size)))
    except Exception:
        recordException('start.py:files-page-embedded', sys.exc_info()[1])
    return rows


def runFilesPage(argv=None) -> int:
    data_mtime = _formatFileMtime(BASE_DIR / 'data.py')
    lines = ['=== FlatLine Files Diagnostic Page ===', f'Base directory: {BASE_DIR}', '', 'Repository files used by app:']
    for path in _repoFilesForPage():
        rel = path.relative_to(BASE_DIR)
        try:
            size = path.stat().st_size
        except Exception:
            recordException('start.py:files-page-stat', sys.exc_info()[1])
            size = 0
        lines.append(f'  {rel} size={size} mtime={_formatFileMtime(path)} md5={safeFileMd5Hex(path)}')
    lines.extend(['', 'Embedded files in data.py:'])
    embedded = _embeddedFileRows()
    if not embedded:
        lines.append('  (none discovered)')
    else:
        for name, size in embedded:
            lines.append(f'  {name} embedded_size={size} mtime={data_mtime} source=data.py')
    _emitDiagnosticPage('files_page.txt', lines)
    sys.stdout.flush(); sys.stderr.flush(); os._exit(0)


def _collectStaticImports(paths: list[Path]) -> dict[str, set[str]]:
    imports: dict[str, set[str]] = {}
    for path in paths:
        rel = str(path.relative_to(BASE_DIR)) if str(path).startswith(str(BASE_DIR)) else str(path)
        imports.setdefault(rel, set())
        try:
            tree = ast.parse(File(path).readText(), filename=str(path))
            for node in ast.walk(tree):
                if isinstance(node, ast.Import):
                    for alias in node.names:
                        imports[rel].add(str(alias.name))
                elif isinstance(node, ast.ImportFrom) and node.module:
                    imports[rel].add(str(node.module))
        except Exception:
            recordException('start.py:env-page-static-imports', sys.exc_info()[1])
    return imports


def _packageVersionLine(import_name: str, package_name: str | None = None) -> str:
    package = str(package_name or import_name).strip()
    try:
        import importlib.metadata as _metadata
        version = _metadata.version(package)
    except Exception:  # swallow-ok: optional package may be missing
        version = '(not installed or version unknown)'
    try:
        found = bool(importlib.util.find_spec(import_name))
    except Exception:  # swallow-ok: optional import probe may fail
        found = False
    return f'{import_name} package={package} installed={found} version={version}'


def _registryKeyRowsForEnvironmentPage() -> list[str]:
    rows: list[str] = []
    rows.extend(['HKCU\\Console', 'HKCU\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Fonts'])
    try:
        for key in getattr(PowerShell, 'CONSOLE_KEYS', ()):
            rows.append(str(key))
    except Exception:
        recordException('start.py:env-page-powershell-keys', sys.exc_info()[1])
    try:
        for plugin in PLUGIN_DEFINITIONS:
            plugin_map = cast(Any, plugin)
            registry_items = list(plugin_map.get('registry_signal_keys', ()) or []) + list(plugin_map.get('registry_known_keys', ()) or [])
            for item in registry_items:
                if isinstance(item, (tuple, list)) and len(item) >= 2:
                    rows.append(str(item[0]) + '\\' + str(item[1]))
                else:
                    rows.append(str(item))
    except Exception:
        recordException('start.py:env-page-plugin-keys', sys.exc_info()[1])
    return sorted(set(row for row in rows if row))


