def _astFilesForAudit() -> list[Path]:
    skip = {'.git', '__pycache__', '.mypy_cache', '.ruff_cache', 'vendor'}
    out: list[Path] = []
    for path in BASE_DIR.rglob('*.py'):
        try:
            rel_parts = path.relative_to(BASE_DIR).parts
        except Exception:
            recordException('start.py:ast-audit-relative-path', sys.exc_info()[1])
            continue
        if any(part in skip for part in rel_parts):
            continue
        out.append(path)
    return sorted(out, key=lambda item: str(item.relative_to(BASE_DIR)).lower())


def _astModeFromArgs(argv: list[str] | None) -> str:
    mode_rows = [
        ('full', AST_FULL_FLAGS), ('exceptions', AST_EXCEPTIONS_FLAGS), ('risk', AST_RISK_FLAGS), ('imports', AST_IMPORTS_FLAGS),
        ('functions', AST_FUNCTIONS_FLAGS), ('classes', AST_CLASSES_FLAGS), ('summary', AST_SUMMARY_FLAGS),
    ]
    for mode, flags in mode_rows:
        if readCliOption(list(argv or []), flags, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'):
            return mode
    return EMPTY_STRING


def _astCallName(node: ast.AST | None) -> str:
    if isinstance(node, ast.Name):
        return str(node.id)
    if isinstance(node, ast.Attribute):
        base = _astCallName(node.value)  # recursion-ok: AST dotted-name walker
        return f'{base}.{node.attr}' if base else str(node.attr)
    if isinstance(node, ast.Call):
        return _astCallName(node.func)  # recursion-ok: unwrap call target
    return EMPTY_STRING


def _astAuditLines(mode: str = 'summary') -> list[str]:
    mode = str(mode or 'summary').strip().lower()
    if mode == 'full':
        modes = ['summary', 'exceptions', 'risk', 'imports', 'functions', 'classes']
    else:
        modes = [mode]
    files = _astFilesForAudit()
    lines = [f'AST audit mode={mode}', 'Python ast.parse modes available: exec, eval, single, func_type', 'Project AST audit modes: summary, exceptions, risk, imports, functions, classes, full', f'Files scanned: {len(files)}']
    for path in files:
        rel = str(path.relative_to(BASE_DIR))
        try:
            source = File(path).readText()
            tree = ast.parse(source, filename=str(path), mode='exec')
            nodes = list(ast.walk(tree))
            if 'summary' in modes:
                lines.append(f'{rel}: lines={len(source.splitlines())} nodes={len(nodes)} classes={sum(isinstance(n, ast.ClassDef) for n in nodes)} functions={sum(isinstance(n, (ast.FunctionDef, ast.AsyncFunctionDef)) for n in nodes)} excepts={sum(isinstance(n, ast.ExceptHandler) for n in nodes)}')
            if 'exceptions' in modes:
                for node in nodes:
                    if isinstance(node, ast.ExceptHandler):
                        except_type = node.type
                        except_name = ast.unparse(except_type) if except_type is not None else "<bare>"
                        lines.append(f'{rel}:{getattr(node,"lineno",0)} except {except_name} body={len(node.body)}')
            if 'risk' in modes:
                risk_names = {'eval', 'exec', 'compile', 'Popen', 'run', 'Thread', 'connect', 'execute', 'system'}
                for node in nodes:
                    if isinstance(node, ast.Call):
                        name = _astCallName(getattr(node, 'func', None))
                        tail = name.split('.')[-1]
                        if tail in risk_names or name in {'subprocess.Popen', 'subprocess.run', 'threading.Thread', 'os.system'}:
                            lines.append(f'{rel}:{getattr(node,"lineno",0)} risk-call {name}')
            if 'imports' in modes:
                imported = sorted({n.name for node in nodes if isinstance(node, ast.Import) for n in node.names} | {str(node.module) for node in nodes if isinstance(node, ast.ImportFrom) and node.module})
                lines.append(f'{rel}: imports={", ".join(imported)}')
            if 'functions' in modes:
                for node in nodes:
                    if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                        lines.append(f'{rel}:{getattr(node,"lineno",0)} function {node.name}')
            if 'classes' in modes:
                for node in nodes:
                    if isinstance(node, ast.ClassDef):
                        lines.append(f'{rel}:{getattr(node,"lineno",0)} class {node.name}')
        except Exception as error:
            recordException('start.py:ast-audit', sys.exc_info()[1])
            lines.append(f'{rel}: AST ERROR {type(error).__name__}: {error}')
    return lines


def _normalizeHealthSkipToken(raw: object) -> str:
    token = str(raw or EMPTY_STRING).strip().lower()
    if not token:
        return EMPTY_STRING
    if token.startswith('~'):
        token = 'no' + token[1:]
    token = token.lstrip('-/')
    return ''.join(ch for ch in token if ch.isalnum())


def _healthSkipRequested(argv: list[str] | None, *names: str) -> bool:
    tokens = {_normalizeHealthSkipToken(item) for item in list(argv or [])}
    wanted: set[str] = set()
    for name in names:
        compact = _normalizeHealthSkipToken(name)
        if not compact:
            continue
        wanted.update({f'no{compact}', f'skip{compact}', f'{compact}off'})
    return bool(tokens & wanted)


def _runHealthToolLines(argv: list[str] | None = None) -> tuple[int, list[str]]:
    argv = list(argv or [])
    lines = ['=== FlatLine Code Health Page ===', f'Base directory: {BASE_DIR}', 'Tools run: Pyright/Plyright, Ruff, Vulture, every vendor/claude/*.py detector unless skipped by no*/skip*/~* args']
    overall_ok = True
    health_timeout = int(os.environ.get('TRIO_HEALTH_TOOL_TIMEOUT', '300') or '300')
    pyright_timeout = int(os.environ.get('TRIO_HEALTH_PYRIGHT_TIMEOUT', os.environ.get('TRIO_HEALTH_TOOL_TIMEOUT', '600')) or '600')
    tool_rows = [
        ('pyright', [sys.executable, 'start.py', '--pyrite', '--no-scan', '--ad-off'], ('pyright', 'plyright', 'pyrite', 'pirate', 'playright')),
        ('ruff', [sys.executable, '-m', 'ruff', 'check', 'start.py', 'trio.py', 'data.py'], ('ruff', 'rough')),
        ('vulture', [sys.executable, '-m', 'vulture', 'start.py', 'trio.py', 'data.py'], ('vulture',)),
    ]
    for label, command, skip_names in tool_rows:
        lines.extend(['', f'--- {label} ---'])
        if _healthSkipRequested(argv, *skip_names):
            lines.append(f'{label}: skipped by health argument')
            continue
        timeout = pyright_timeout if label == 'pyright' else health_timeout
        code, out_lines = _runCapturedCommand(label, command, cwd=BASE_DIR, timeout=timeout)
        overall_ok = overall_ok and code == 0
        lines.extend(out_lines)
    detector_dir = BASE_DIR / 'vendor' / 'claude'
    detectors = sorted(detector_dir.glob('*.py')) if detector_dir.exists() else []
    detector_skipped = _healthSkipRequested(argv, 'detector', 'detectors', 'claudedetectors', 'claude')
    lines.extend(['', f'--- detectors ({len(detectors)}) ---'])
    if detector_skipped:
        lines.append('detectors: skipped by health argument')
    else:
        for detector in detectors:
            code, out_lines = _runCapturedCommand(detector.name, [sys.executable, str(detector)], cwd=BASE_DIR, timeout=int(os.environ.get('TRIO_HEALTH_DETECTOR_TIMEOUT', '300') or '300'))
            overall_ok = overall_ok and code == 0
            lines.extend(['', f'--- detector: {detector.name} ---'])
            lines.extend(out_lines)
    return (0 if overall_ok else 1), lines


def runCodeHealthPage(argv=None) -> int:
    exit_code, lines = _runHealthToolLines(list(argv or []))
    ast_mode = _astModeFromArgs(list(argv or []))
    if not ast_mode and getattr(sys.stdin, 'isatty', lambda: False)():
        answer = _promptDiagnosticChoice('Run AST audit? [y/N]: ', 'n').lower()
        if answer in {'y', 'yes', '1', 'true'}:
            lines.append('AST modes: summary, exceptions, risk, imports, functions, classes, full')
            ast_mode = _promptDiagnosticChoice('AST mode [summary]: ', 'summary') or 'summary'
    if ast_mode:
        lines.extend(['', f'--- AST audit: {ast_mode} ---'])
        lines.extend(_astAuditLines(ast_mode))
    else:
        lines.extend(['', 'AST audit skipped. Pass --ast-summary, --ast-exceptions, --ast-risk, --ast-imports, --ast-functions, --ast-classes, or --ast-full to force it non-interactively.'])
    _emitDiagnosticPage('code_health.txt', lines)
    sys.stdout.flush(); sys.stderr.flush(); os._exit(int(exit_code))



