def _cliTokenPresent(argv: list[str] | None, token: str) -> bool:
    needle = str(token or EMPTY_STRING).strip().lower()
    if not needle:
        return False
    for raw in list(argv or []):
        if str(raw or EMPTY_STRING).strip().lower() == needle:
            return True
    return False


def traceCompilerStep(step: str, ok: bool, detail: str = EMPTY_STRING) -> None:
    status = statusText(STATUS_SUCCESS if ok else STATUS_FAILED)
    suffix = f' {detail}' if str(detail or EMPTY_STRING).strip() else EMPTY_STRING
    try:
        print(f'[TRACE:compiler] {step} {status}{suffix}', flush=True)
    except Exception:
        recordException('start.py:4243', sys.exc_info()[1])
        _traceSwallowedException('start.py:4146', sys.exc_info()[1])
        pass


class CPP:
    def __init__(self, name: str, source_text: str, target_dir: str | Path | None = None):
        self.name = str(name or START_CPP_NAME).strip() or START_CPP_NAME
        self.sourceText = str(source_text or EMPTY_STRING)
        self.targetDir = Path(target_dir or BASE_DIR)

    @property
    def path(self) -> Path:
        return Path(self.targetDir) / self.name

    def write(self) -> Path:
        target = self.path
        File(target).writeText(self.sourceText)
        return target


class CPPFactory:
    @staticmethod
    def startLauncher() -> CPP:
        source_library = getattr(EmbeddedData, 'LauncherSourceLibrary', None)
        source_text = str(getattr(source_library, 'START_CPP', EMPTY_STRING) or EMPTY_STRING)
        if not source_text.strip():
            raise RuntimeError('Embedded start.cpp source is missing from TrioDesktopEmbeddedData.LauncherSourceLibrary.START_CPP')
        return CPP(START_CPP_NAME, source_text, BASE_DIR)




class WindowsRegistry:
    """Centralized Windows registry discovery for launcher/tool/plugin detection.

    This class deliberately avoids user-specific paths.  It reads Windows registry
    data, expands environment variables such as %ProgramFiles% or %LOCALAPPDATA%,
    and returns executable/path candidates with traceable provenance.
    """

    APP_PATH_ROOTS = (
        r'Software\Microsoft\Windows\CurrentVersion\App Paths',
        r'SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths',
        r'SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\App Paths',
    )
    UNINSTALL_ROOTS = (
        r'SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall',
        r'Software\Microsoft\Windows\CurrentVersion\Uninstall',
        r'SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall',
    )
    DEFAULT_VALUE_NAMES = (
        None,
        EMPTY_STRING,
        'InstallPath',
        'InstallDir',
        'InstallDirectory',
        'InstallLocation',
        'InstallSource',
        'Path',
        'ApplicationPath',
        'ExecutablePath',
        'ExePath',
        'DisplayIcon',
        'UninstallString',
        'QuietUninstallString',
        'Target',
        'Location',
        'RootDir',
        'BinPath',
        'Directory',
    )
    ROOT_NAME_MAP = {
        'HKCU': 'HKEY_CURRENT_USER',
        'HKEY_CURRENT_USER': 'HKEY_CURRENT_USER',
        'HKLM': 'HKEY_LOCAL_MACHINE',
        'HKEY_LOCAL_MACHINE': 'HKEY_LOCAL_MACHINE',
        'HKCR': 'HKEY_CLASSES_ROOT',
        'HKEY_CLASSES_ROOT': 'HKEY_CLASSES_ROOT',
        'HKU': 'HKEY_USERS',
        'HKEY_USERS': 'HKEY_USERS',
        'HKCC': 'HKEY_CURRENT_CONFIG',
        'HKEY_CURRENT_CONFIG': 'HKEY_CURRENT_CONFIG',
    }

    def __init__(self, trace: bool | None = None):
        self.available = os.name == 'nt'
        self._winreg = None
        self.traceEnabled = self._resolveTraceFlag(trace)
        if self.available:
            try:
                import winreg  # type: ignore
                self._winreg = winreg
            except Exception as error:
                recordException('start.py:4336', sys.exc_info()[1])
                self.available = False
                self._trace(f'winreg unavailable: {type(error).__name__}: {error}')

    def _resolveTraceFlag(self, trace: bool | None) -> bool:
        if trace is not None:
            return bool(trace)
        raw = str(os.environ.get('TRIO_REGISTRY_TRACE', os.environ.get('TRIO_DEBUG_REGISTRY', '0')) or '0').strip().lower()
        return raw in {'1', 'true', 'yes', 'on', 'debug', 'trace'}

    def _trace(self, message: str) -> None:
        if not self.traceEnabled:
            return
        try:
            print(f'[TRACE:registry] {message}', file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:4351', sys.exc_info()[1])
            _traceSwallowedException('start.py:4253', sys.exc_info()[1])
            pass

    def _warn(self, message: str) -> None:
        try:
            print(f'[WARN:registry] {message}', file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:4358', sys.exc_info()[1])
            _traceSwallowedException('start.py:4259', sys.exc_info()[1])
            pass

    def _views(self) -> tuple[int, ...]:
        winreg = self._winreg
        if winreg is None:
            return (0,)
        values: list[int] = [0]
        for attr in ('KEY_WOW64_64KEY', 'KEY_WOW64_32KEY'):
            value = int(getattr(winreg, attr, 0) or 0)
            if value and value not in values:
                values.append(value)
        return tuple(values)

    def _rootFromName(self, root_name: str):
        winreg = self._winreg
        if winreg is None:
            return None
        normalized = str(root_name or EMPTY_STRING).strip().upper()
        attr = self.ROOT_NAME_MAP.get(normalized, normalized)
        return getattr(winreg, attr, None)

    def parseKeySpec(self, spec: object) -> tuple[str, str]:
        if isinstance(spec, (tuple, list)) and len(spec) >= 2:
            return str(spec[0] or EMPTY_STRING).strip(), str(spec[1] or EMPTY_STRING).strip().strip('\\')
        raw = str(spec or EMPTY_STRING).strip().strip('\\')
        if not raw:
            return EMPTY_STRING, EMPTY_STRING
        root, sep, subkey = raw.partition('\\')
        if not sep:
            return EMPTY_STRING, raw
        return root.strip(), subkey.strip().strip('\\')

    def openKey(self, root_name: str, subkey: str):
        winreg = cast(Any, self._winreg)
        if not self.available or winreg is None:
            return None
        root = self._rootFromName(root_name)
        key_path = str(subkey or EMPTY_STRING).strip().strip('\\')
        if root is None or not key_path:
            return None
        access_base = int(getattr(winreg, 'KEY_READ', 0x20019) or 0x20019)
        for view in self._views():
            access = access_base | int(view or 0)
            try:
                handle = winreg.OpenKey(root, key_path, 0, access)
                label = f'{root_name}\\{key_path}'
                if view:
                    label += f' view=0x{int(view):x}'
                self._trace(f'open ok {label}')
                return handle
            except Exception as error:
                recordException('start.py:4410', sys.exc_info()[1])
                self._trace(f'open miss {root_name}\\{key_path}: {type(error).__name__}: {error}')
        return None

    def keyExists(self, key_spec: object) -> bool:
        root_name, subkey = self.parseKeySpec(key_spec)
        handle = self.openKey(root_name, subkey)
        if handle is None:
            return False
        try:
            handle.Close()
        except Exception:
            recordException('start.py:4421', sys.exc_info()[1])
            _traceSwallowedException('start.py:4321', sys.exc_info()[1])
            pass
        return True

    def readValue(self, key, value_name: str | None = None):
        winreg = cast(Any, self._winreg)
        if winreg is None or key is None:
            return EMPTY_STRING
        try:
            query_name = str(value_name or EMPTY_STRING)
            return winreg.QueryValueEx(key, query_name)[0]
        except Exception:
            recordException('start.py:4433', sys.exc_info()[1])
            return EMPTY_STRING

    def enumSubkeys(self, root_name: str, subkey: str) -> list[str]:
        winreg = cast(Any, self._winreg)
        parent = self.openKey(root_name, subkey)
        if winreg is None or parent is None:
            return []
        names: list[str] = []
        try:
            count = int(winreg.QueryInfoKey(parent)[0] or 0)
            for index in range(count):
                try:
                    names.append(str(winreg.EnumKey(parent, index) or EMPTY_STRING))
                except Exception:
                    recordException('start.py:4447', sys.exc_info()[1])
                    _traceSwallowedException('start.py:4346', sys.exc_info()[1])
                    continue
        finally:
            try:
                parent.Close()
            except Exception:
                recordException('start.py:4453', sys.exc_info()[1])
                _traceSwallowedException('start.py:4351', sys.exc_info()[1])
                pass
        return names

    def expandPathText(self, value: object) -> str:
        raw = str(value or EMPTY_STRING).strip().strip('\x00').strip()
        if not raw:
            return EMPTY_STRING
        raw = os.path.expandvars(raw).strip().strip('"')
        return raw

    def commandPathCandidates(self, raw_value: object) -> list[str]:
        raw = self.expandPathText(raw_value)
        if not raw:
            return []
        candidates: list[str] = []
        if raw.startswith('"') and '"' in raw[1:]:
            quoted = raw[1:].split('"', 1)[0].strip()
            if quoted:
                candidates.append(quoted)
        lowered = raw.lower()
        exe_index = lowered.find('.exe')
        if exe_index >= 0:
            candidates.append(raw[:exe_index + 4].strip().strip('"'))
        if not candidates:
            candidates.append(raw.strip().strip('"'))
        unique: list[str] = []
        seen: set[str] = set()
        for candidate in candidates:
            cleaned = self.expandPathText(candidate)
            key = cleaned.lower()
            if cleaned and key not in seen:
                seen.add(key)
                unique.append(cleaned)
        return unique

    def _addCandidate(self, results: list[tuple[Path, str]], seen: set[str], value: object, source: str, executable_names: tuple[str, ...] = ()) -> None:
        for candidate_text in self.commandPathCandidates(value):
            path = Path(candidate_text)
            possibilities: list[Path] = [path]
            if executable_names and (not path.suffix or path.suffix.lower() != '.exe'):
                for exe_name in executable_names:
                    possibilities.append(path / exe_name)
            for possible in possibilities:
                normalized = str(possible).strip()
                key = normalized.lower()
                if not normalized or key in seen:
                    continue
                seen.add(key)
                results.append((Path(normalized), source))
                self._trace(f'candidate {normalized} source={source}')

    def appPathCandidates(self, executable_names: tuple[str, ...], results: list[tuple[Path, str]], seen: set[str]) -> None:
        if not executable_names:
            return
        winreg = self._winreg
        if winreg is None:
            return
        root_specs = (
            ('HKCU', self.APP_PATH_ROOTS[0]),
            ('HKLM', self.APP_PATH_ROOTS[1]),
            ('HKLM', self.APP_PATH_ROOTS[2]),
        )
        for root_name, base_key in root_specs:
            for exe_name in executable_names:
                subkey = str(base_key).rstrip('\\') + '\\' + exe_name
                handle = self.openKey(root_name, subkey)
                if handle is None:
                    continue
                try:
                    default_value = self.readValue(handle, None)
                    if default_value:
                        self._addCandidate(results, seen, default_value, f'registry app-paths {root_name}\\{subkey}', executable_names)
                    path_value = self.readValue(handle, 'Path')
                    if path_value:
                        self._addCandidate(results, seen, path_value, f'registry app-paths {root_name}\\{subkey} Path', executable_names)
                finally:
                    try:
                        handle.Close()
                    except Exception:
                        recordException('start.py:4533', sys.exc_info()[1])
                        _traceSwallowedException('start.py:4430', sys.exc_info()[1])
                        pass

    def uninstallCandidates(self, display_tokens: tuple[str, ...], executable_names: tuple[str, ...], results: list[tuple[Path, str]], seen: set[str]) -> None:
        if not display_tokens and not executable_names:
            return
        roots = (
            ('HKCU', self.UNINSTALL_ROOTS[1]),
            ('HKLM', self.UNINSTALL_ROOTS[0]),
            ('HKLM', self.UNINSTALL_ROOTS[2]),
        )
        value_names = ('InstallLocation', 'InstallSource', 'DisplayIcon', 'UninstallString', 'QuietUninstallString')
        for root_name, base_key in roots:
            for child_name in self.enumSubkeys(root_name, base_key):
                child_key_path = str(base_key).rstrip('\\') + '\\' + child_name
                handle = self.openKey(root_name, child_key_path)
                if handle is None:
                    continue
                try:
                    display_name = str(self.readValue(handle, 'DisplayName') or EMPTY_STRING).strip()
                    display_low = display_name.lower()
                    if display_tokens and not any(token in display_low for token in display_tokens):
                        continue
                    self._trace(f'uninstall match {root_name}\\{child_key_path} DisplayName={display_name!r}')
                    for value_name in value_names:
                        value = self.readValue(handle, value_name)
                        if value:
                            self._addCandidate(results, seen, value, f'registry uninstall {root_name}\\{child_key_path} {value_name}', executable_names)
                finally:
                    try:
                        handle.Close()
                    except Exception:
                        recordException('start.py:4565', sys.exc_info()[1])
                        _traceSwallowedException('start.py:4461', sys.exc_info()[1])
                        pass

    def knownKeyCandidates(self, key_specs: tuple[object, ...], value_names: tuple[str | None, ...], executable_names: tuple[str, ...], results: list[tuple[Path, str]], seen: set[str]) -> None:
        if not key_specs:
            return
        values_to_read = tuple(value_names or self.DEFAULT_VALUE_NAMES)
        for spec in key_specs:
            root_name, subkey = self.parseKeySpec(spec)
            if not root_name or not subkey:
                continue
            handle = self.openKey(root_name, subkey)
            if handle is None:
                continue
            try:
                self._trace(f'known key exists {root_name}\\{subkey}')
                for value_name in values_to_read:
                    value = self.readValue(handle, value_name)
                    if value:
                        label = '(default)' if value_name in (None, EMPTY_STRING) else str(value_name)
                        self._addCandidate(results, seen, value, f'registry known-key {root_name}\\{subkey} {label}', executable_names)
            finally:
                try:
                    handle.Close()
                except Exception:
                    recordException('start.py:4590', sys.exc_info()[1])
                    _traceSwallowedException('start.py:4485', sys.exc_info()[1])
                    pass

    def candidatesForPlugin(self, plugin) -> list[tuple[Path, str]]:
        if not self.available:
            return []
        executable_names = tuple(str(item or EMPTY_STRING).strip() for item in getattr(plugin, 'executableNames', ()) if str(item or EMPTY_STRING).strip())
        display_tokens = tuple(str(item or EMPTY_STRING).strip().lower() for item in getattr(plugin, 'registryDisplayTokens', ()) if str(item or EMPTY_STRING).strip())
        known_keys = tuple(list(getattr(plugin, 'registryKnownKeys', ()) or []) + list(getattr(plugin, 'registrySignalKeys', ()) or []))
        value_names = tuple(getattr(plugin, 'registryValueNames', ()) or self.DEFAULT_VALUE_NAMES)
        self._trace(f'plugin={getattr(plugin, "name", "")} executables={executable_names} tokens={display_tokens} known_keys={known_keys}')
        results: list[tuple[Path, str]] = []
        seen: set[str] = set()
        self.appPathCandidates(executable_names, results, seen)
        self.uninstallCandidates(display_tokens, executable_names, results, seen)
        self.knownKeyCandidates(known_keys, value_names, executable_names, results, seen)
        return results


class Registry(WindowsRegistry):
    """Windows registry helper with read/write operations for terminal setup.

    The older WindowsRegistry class was discovery-focused. Registry keeps that
    behavior and adds small typed helpers used by Font/Terminal/PowerShell so
    console font configuration is not scattered across one-off winreg blocks.
    """

    def read(self, key_spec: object, value_name: str | None = None, default: object = EMPTY_STRING) -> object:
        root_name, subkey = self.parseKeySpec(key_spec)
        handle = self.openKey(root_name, subkey)
        if handle is None:
            return default
        try:
            value = self.readValue(handle, value_name)
            return default if value in (None, EMPTY_STRING) else value
        finally:
            try:
                handle.Close()
            except Exception:
                recordException('start.py:registry-read-close', sys.exc_info()[1])
                _traceSwallowedException('start.py:registry-read-close', sys.exc_info()[1])
                pass

    def set(self, key_spec: object, value_name: str | None, value: object, value_kind: str = 'REG_SZ') -> bool:
        if not self.available or self._winreg is None:
            return False
        root_name, subkey = self.parseKeySpec(key_spec)
        root = self._rootFromName(root_name)
        if root is None or not subkey:
            return False
        try:
            winreg_module = cast(Any, self._winreg)
            kind_name = str(value_kind or 'REG_SZ').upper()
            reg_kind = getattr(winreg_module, kind_name, getattr(winreg_module, 'REG_SZ', 1))
            typed_value: int | str | list[str] | bytes | None
            if kind_name == 'REG_DWORD':
                typed_value = safeInt(value, 0)
            elif isinstance(value, (bytes, bytearray)):
                typed_value = bytes(value)
            elif isinstance(value, list):
                typed_value = [str(item) for item in value]
            elif value is None:
                typed_value = None
            else:
                typed_value = str(value)
            with winreg_module.CreateKey(root, subkey) as handle:
                winreg_module.SetValueEx(handle, str(value_name or EMPTY_STRING), 0, reg_kind, typed_value)
            self._trace(f'set ok {root_name}\\{subkey} {value_name or "(default)"}={value!r}')
            return True
        except Exception:
            recordException('start.py:registry-set', sys.exc_info()[1])
            _traceSwallowedException('start.py:registry-set', sys.exc_info()[1])
            return False

    def setDword(self, key_spec: object, value_name: str, value: int) -> bool:
        return self.set(key_spec, value_name, int(value), 'REG_DWORD')

    def setString(self, key_spec: object, value_name: str | None, value: str) -> bool:
        return self.set(key_spec, value_name, str(value or EMPTY_STRING), 'REG_SZ')

    @staticmethod
    def _root_and_subkey(key: str):
        _winreg = cast(Any, runtimeImportModule('winreg'))
        root_names = {'HKCU': getattr(_winreg, 'HKEY_CURRENT_USER'), 'HKLM': getattr(_winreg, 'HKEY_LOCAL_MACHINE')}
        parts = str(key or '').replace('\\', '/').split('/')
        root_name = parts[0].upper()
        root = root_names.get(root_name)
        if root is None:
            raise ValueError(f'Unknown registry root: {root_name!r}')
        subkey = '\\'.join(parts[1:-1])
        value_name = parts[-1] if len(parts) > 1 else ''
        return root, subkey, value_name

    @staticmethod
    def getKey(key: str, default=None):
        """Read a registry value from a forward-slash key like HKCU/Console/FaceName."""
        if os.name != 'nt':
            return default
        try:
            import winreg as _winreg  # type: ignore
            root, subkey, value_name = Registry._root_and_subkey(key)
            with _winreg.OpenKey(root, subkey, 0, _winreg.KEY_READ) as handle:
                value, _ = _winreg.QueryValueEx(handle, value_name)
                return value
        except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
            return default

    @staticmethod
    def setKey(key: str, value, kind: str = 'auto') -> bool:
        """Write a registry value from a forward-slash key like HKCU/Console/FaceName."""
        if os.name != 'nt':
            return False
        try:
            import winreg as _winreg  # type: ignore
            root, subkey, value_name = Registry._root_and_subkey(key)
            if kind == 'auto':
                reg_type = _winreg.REG_DWORD if isinstance(value, int) else _winreg.REG_SZ
            elif kind == 'dword':
                reg_type = _winreg.REG_DWORD
            else:
                reg_type = _winreg.REG_SZ
            with _winreg.CreateKeyEx(root, subkey, 0, _winreg.KEY_SET_VALUE) as handle:
                _winreg.SetValueEx(handle, value_name, 0, reg_type, value)
            return True
        except Exception:  # swallow-ok: intentional fallback/benign probe path; surfaced elsewhere or safely defaults
            return False


class Etc:
    """Linux/Unix configuration and install-path discovery for tools/plugins.

    Windows gets WindowsRegistry because the registry is the machine database.
    Linux gets Etc because /etc, XDG config directories, PATH, alternatives,
    /usr, /usr/local, /opt, snap/flatpak exports, and user dot-config files are
    the equivalent discovery surface.  This class never hard-codes a personal
    home directory; user paths are derived from HOME/XDG variables at runtime.
    """

    DEFAULT_EXECUTABLE_DIRS = (
        '~/.local/bin',
        '~/.cargo/bin',
        '~/.dotnet/tools',
        '~/go/bin',
        '/usr/local/bin',
        '/usr/bin',
        '/bin',
        '/usr/local/sbin',
        '/usr/sbin',
        '/sbin',
        '/snap/bin',
        '/var/lib/flatpak/exports/bin',
        '/usr/local/go/bin',
        '/opt/homebrew/bin',
        '/opt/local/bin',
    )
    DEFAULT_PACKAGE_ROOTS = (
        '/opt',
        '/usr/local',
        '/usr',
        '/usr/lib',
        '/usr/libexec',
        '/usr/share',
        '/var/lib',
        '~/.local',
        '~/.config',
    )
    GENERIC_CONFIG_FILES = (
        '/etc/environment',
        '/etc/profile',
        '/etc/bash.bashrc',
        '/etc/zsh/zshenv',
        '/etc/zsh/zprofile',
        '~/.profile',
        '~/.bashrc',
        '~/.zshrc',
    )

    def __init__(self, trace: bool | None = None):
        self.available = os.name == 'posix' and sys.platform != 'darwin'
        self.traceEnabled = self._resolveTraceFlag(trace)

    def _resolveTraceFlag(self, trace: bool | None) -> bool:
        if trace is not None:
            return bool(trace)
        raw = str(os.environ.get('TRIO_ETC_TRACE', os.environ.get('TRIO_DEBUG_ETC', '0')) or '0').strip().lower()
        return raw in {'1', 'true', 'yes', 'on', 'debug', 'trace'}

    def _trace(self, message: str) -> None:
        if not self.traceEnabled:
            return
        try:
            print(f'[TRACE:etc] {message}', file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:4674', sys.exc_info()[1])
            _traceSwallowedException('start.py:4568', sys.exc_info()[1])
            pass

    def _warn(self, message: str) -> None:
        try:
            print(f'[WARN:etc] {message}', file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:4681', sys.exc_info()[1])
            _traceSwallowedException('start.py:4574', sys.exc_info()[1])
            pass

    def _splitPathList(self, value: str, default: tuple[str, ...]) -> tuple[str, ...]:
        raw = str(value or EMPTY_STRING).strip()
        if not raw:
            return tuple(default)
        return tuple(item for item in raw.split(os.pathsep) if item.strip())

    def xdgConfigHome(self) -> Path:
        raw = str(os.environ.get('XDG_CONFIG_HOME', EMPTY_STRING) or EMPTY_STRING).strip()
        if raw:
            return self.expandPath(raw)
        return self.expandPath('~/.config')

    def xdgConfigDirs(self) -> tuple[Path, ...]:
        return tuple(self.expandPath(item) for item in self._splitPathList(os.environ.get('XDG_CONFIG_DIRS', EMPTY_STRING), ('/etc/xdg',)))

    def configRoots(self) -> tuple[Path, ...]:
        roots: list[Path] = [self.xdgConfigHome(), *list(self.xdgConfigDirs()), self.expandPath('/etc'), self.expandPath('/usr/local/etc'), self.expandPath('/opt/etc')]
        unique: list[Path] = []
        seen: set[str] = set()
        for root in roots:
            key = str(root)
            if key and key not in seen:
                seen.add(key)
                unique.append(root)
        return tuple(unique)

    def executableRoots(self) -> tuple[Path, ...]:
        path_dirs = tuple(item for item in str(os.environ.get('PATH', EMPTY_STRING) or EMPTY_STRING).split(os.pathsep) if item.strip())
        roots = [*(self.expandPath(item) for item in path_dirs), *(self.expandPath(item) for item in self.DEFAULT_EXECUTABLE_DIRS)]
        unique: list[Path] = []
        seen: set[str] = set()
        for root in roots:
            key = str(root)
            if key and key not in seen:
                seen.add(key)
                unique.append(root)
        return tuple(unique)

    def packageRoots(self) -> tuple[Path, ...]:
        roots = [self.expandPath(item) for item in self.DEFAULT_PACKAGE_ROOTS]
        unique: list[Path] = []
        seen: set[str] = set()
        for root in roots:
            key = str(root)
            if key and key not in seen:
                seen.add(key)
                unique.append(root)
        return tuple(unique)

    def expandPath(self, value: object) -> Path:
        raw = str(value or EMPTY_STRING).strip().strip('"').strip("'")
        raw = os.path.expandvars(raw)
        raw = os.path.expanduser(raw)
        return Path(raw) if raw else Path()

    def _addCandidate(self, results: list[tuple[Path, str]], seen: set[str], value: object, source: str, executable_names: tuple[str, ...] = ()) -> None:
        path = self.expandPath(value)
        if not str(path):
            return
        possibilities: list[Path] = [path]
        if executable_names and (not path.suffix) and path.name not in executable_names:
            # If a config entry points to a directory, try the declared executables under it.
            for exe_name in executable_names:
                possibilities.append(path / exe_name)
        for possible in possibilities:
            normalized = str(possible)
            key = normalized.lower()
            if not normalized or key in seen:
                continue
            seen.add(key)
            results.append((possible, source))
            self._trace(f'candidate {normalized} source={source}')


    def _linuxExecutableNames(self, plugin) -> tuple[str, ...]:
        names: list[str] = []
        allow_windows_exe = str(getattr(plugin, 'name', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'winscp', 'inno'}
        for item in getattr(plugin, 'executableNames', ()):
            name = str(item or EMPTY_STRING).strip()
            if not name:
                continue
            lower = name.lower()
            if not allow_windows_exe and lower.endswith(('.exe', '.cmd', '.com', '.bat')):
                continue
            if name not in names:
                names.append(name)
        return tuple(names)

    def _configFileCandidates(self, plugin) -> tuple[Path, ...]:
        raw_files = list(getattr(plugin, 'linuxConfigFiles', ()) or []) + list(self.GENERIC_CONFIG_FILES)
        executable_names = self._linuxExecutableNames(plugin)
        plugin_names = tuple(sorted(set([getattr(plugin, 'name', EMPTY_STRING), *list(getattr(plugin, 'aliases', ()) or []), *(name.split('.')[0] for name in executable_names)])))
        candidates: list[Path] = []
        for value in raw_files:
            text = str(value or EMPTY_STRING).strip()
            if not text:
                continue
            path = self.expandPath(text)
            candidates.append(path)
        for root in self.configRoots():
            for plugin_name in plugin_names:
                if not plugin_name:
                    continue
                candidates.append(root / plugin_name / 'config')
                candidates.append(root / f'{plugin_name}.conf')
                candidates.append(root / f'{plugin_name}rc')
        unique: list[Path] = []
        seen: set[str] = set()
        for candidate in candidates:
            key = str(candidate)
            if key and key not in seen:
                seen.add(key)
                unique.append(candidate)
        return tuple(unique)

    def _readSmallText(self, path: Path, *, max_bytes: int = 524288) -> str:
        try:
            if not path.exists() or not path.is_file():
                return EMPTY_STRING
            if path.stat().st_size > max_bytes:
                self._trace(f'skip large config {path} bytes={path.stat().st_size}')
                return EMPTY_STRING
            return File(path).readText()
        except Exception as error:
            recordException('start.py:4808', sys.exc_info()[1])
            self._trace(f'config read failed {path}: {type(error).__name__}: {error}')
            return EMPTY_STRING

    def _pathHintsFromConfigText(self, text: str, plugin) -> list[str]:
        if not text:
            return []
        executable_names = self._linuxExecutableNames(plugin)
        aliases = tuple(str(item or EMPTY_STRING).strip() for item in [getattr(plugin, 'name', EMPTY_STRING), *list(getattr(plugin, 'aliases', ()) or [])] if str(item or EMPTY_STRING).strip())
        tokens = tuple(sorted(set([*aliases, *(name.split('.')[0] for name in executable_names)]), key=len, reverse=True))
        hints: list[str] = []
        # Quoted and unquoted absolute paths, plus ~/ user paths.
        path_regex = re.compile(r'(?P<path>(?:~|/)[A-Za-z0-9_@%+=:,./\\~\-]+)')
        for line in text.splitlines():
            stripped = line.strip()
            if not stripped or stripped.startswith(('#', ';')):
                continue
            lower = stripped.lower()
            if tokens and not any(token.lower() in lower for token in tokens):
                # Generic profile files contain tons of unrelated PATH/noise.
                # Executable directories are handled separately from PATH; config
                # parsing only extracts lines tied to this plugin/tool.
                continue
            for match in path_regex.finditer(stripped):
                value = match.group('path').strip().strip('"').strip("'")
                if value and value not in hints:
                    hints.append(value)
        return hints

    def configCandidates(self, plugin, results: list[tuple[Path, str]], seen: set[str]) -> None:
        executable_names = self._linuxExecutableNames(plugin)
        for config_path in self._configFileCandidates(plugin):
            if config_path.exists():
                self._trace(f'config exists {config_path}')
            text = self._readSmallText(config_path)
            if not text:
                continue
            for hint in self._pathHintsFromConfigText(text, plugin):
                self._addCandidate(results, seen, hint, f'etc config {config_path}', executable_names)

    def executableDirCandidates(self, plugin, results: list[tuple[Path, str]], seen: set[str]) -> None:
        executable_names = self._linuxExecutableNames(plugin)
        for root in self.executableRoots():
            for exe_name in executable_names:
                self._addCandidate(results, seen, root / exe_name, f'linux executable dir {root}')

    def defaultPathCandidates(self, plugin, results: list[tuple[Path, str]], seen: set[str]) -> None:
        executable_names = self._linuxExecutableNames(plugin)
        for path_text in getattr(plugin, 'linuxDefaultAbsolutePaths', ()) or ():
            self._addCandidate(results, seen, path_text, 'linux default absolute path')
        for root in self.packageRoots():
            for rel in getattr(plugin, 'linuxDefaultRelativePaths', ()) or ():
                try:
                    self._addCandidate(results, seen, root.joinpath(*tuple(str(part or EMPTY_STRING) for part in rel)), f'linux default path {root}', executable_names)
                except Exception:
                    recordException('start.py:4862', sys.exc_info()[1])
                    _traceSwallowedException('start.py:4754', sys.exc_info()[1])
                    continue
            for pattern in getattr(plugin, 'linuxDefaultGlobPatterns', ()) or ():
                try:
                    for found in root.glob(str(pattern)):
                        self._addCandidate(results, seen, found, f'linux default glob {root}/{pattern}', executable_names)
                except Exception as error:
                    recordException('start.py:4869', sys.exc_info()[1])
                    self._trace(f'glob failed {root}/{pattern}: {type(error).__name__}: {error}')

    def candidatesForPlugin(self, plugin) -> list[tuple[Path, str]]:
        if not self.available:
            return []
        self._trace(f'plugin={getattr(plugin, "name", EMPTY_STRING)} config_roots={[str(p) for p in self.configRoots()]}')
        results: list[tuple[Path, str]] = []
        seen: set[str] = set()
        self.configCandidates(plugin, results, seen)
        self.executableDirCandidates(plugin, results, seen)
        self.defaultPathCandidates(plugin, results, seen)
        return results


class Plugin:
    def _trace(self, message: str) -> None:
        try:
            print(f'[TRACE:plugin] {self.name}: {message}', file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:Plugin._trace', sys.exc_info()[1])

    def __init__(
        self,
        *,
        name: str,
        display_name: str = EMPTY_STRING,
        aliases: tuple[str, ...] | list[str] | None = None,
        executable_names: tuple[str, ...] | list[str] | None = None,
        env_vars: tuple[str, ...] | list[str] | None = None,
        registry_display_tokens: tuple[str, ...] | list[str] | None = None,
        registry_signal_keys: tuple[str, ...] | list[tuple[str, str]] | None = None,
        registry_known_keys: tuple[object, ...] | list[object] | None = None,
        registry_value_names: tuple[str | None, ...] | list[str | None] | None = None,
        default_relative_paths: tuple[tuple[str, ...], ...] | list[tuple[str, ...]] | None = None,
        default_glob_patterns: tuple[str, ...] | list[str] | None = None,
        default_absolute_paths: tuple[str, ...] | list[str] | None = None,
        linux_config_files: tuple[str, ...] | list[str] | None = None,
        linux_default_absolute_paths: tuple[str, ...] | list[str] | None = None,
        linux_default_relative_paths: tuple[tuple[str, ...], ...] | list[tuple[str, ...]] | None = None,
        linux_default_glob_patterns: tuple[str, ...] | list[str] | None = None,
        version_args: tuple[str, ...] | list[str] | None = None,
        help_args: tuple[str, ...] | list[str] | None = None,
        usage_lines: tuple[str, ...] | list[str] | None = None,
        winget_id: str = EMPTY_STRING,
        choco_id: str = EMPTY_STRING,
        prefer_path_search: bool = True
    ):
        self.name = str(name or EMPTY_STRING).strip().lower()
        self.displayName = str(display_name or name or EMPTY_STRING).strip()
        self.aliases = tuple(str(item or EMPTY_STRING).strip().lower() for item in list(aliases or []) if str(item or EMPTY_STRING).strip())
        self.executableNames = tuple(str(item or EMPTY_STRING).strip() for item in list(executable_names or []) if str(item or EMPTY_STRING).strip())
        self.envVars = tuple(str(item or EMPTY_STRING).strip() for item in list(env_vars or []) if str(item or EMPTY_STRING).strip())
        self.registryDisplayTokens = tuple(str(item or EMPTY_STRING).strip().lower() for item in list(registry_display_tokens or []) if str(item or EMPTY_STRING).strip())
        self.registrySignalKeys = tuple(list(registry_signal_keys or []))
        self.registryKnownKeys = tuple(list(registry_known_keys or []))
        self.registryValueNames = tuple(list(registry_value_names or []))
        self.defaultRelativePaths = tuple(tuple(str(part or EMPTY_STRING) for part in list(path or [])) for path in list(default_relative_paths or []))
        self.defaultGlobPatterns = tuple(str(item or EMPTY_STRING).strip() for item in list(default_glob_patterns or []) if str(item or EMPTY_STRING).strip())
        self.defaultAbsolutePaths = tuple(str(item or EMPTY_STRING).strip() for item in list(default_absolute_paths or []) if str(item or EMPTY_STRING).strip())
        self.linuxConfigFiles = tuple(str(item or EMPTY_STRING).strip() for item in list(linux_config_files or []) if str(item or EMPTY_STRING).strip())
        self.linuxDefaultAbsolutePaths = tuple(str(item or EMPTY_STRING).strip() for item in list(linux_default_absolute_paths or []) if str(item or EMPTY_STRING).strip())
        self.linuxDefaultRelativePaths = tuple(tuple(str(part or EMPTY_STRING) for part in list(path or [])) for path in list(linux_default_relative_paths or []))
        self.linuxDefaultGlobPatterns = tuple(str(item or EMPTY_STRING).strip() for item in list(linux_default_glob_patterns or []) if str(item or EMPTY_STRING).strip())
        self.versionArgs = tuple(str(item or EMPTY_STRING).strip() for item in (list(['--version'] if version_args is None else version_args)) if str(item or EMPTY_STRING).strip())
        self.helpArgs = tuple(str(item or EMPTY_STRING).strip() for item in (list(['--help'] if help_args is None else help_args)) if str(item or EMPTY_STRING).strip())
        self.usageLines = tuple(str(item or EMPTY_STRING) for item in list(usage_lines or []) if str(item or EMPTY_STRING).strip())
        self.wingetId = str(winget_id or EMPTY_STRING).strip()
        self.chocoId = str(choco_id or EMPTY_STRING).strip()
        self.preferPathSearch = bool(prefer_path_search)

    def getName(self) -> str:
        return self.displayName or self.name

    def getPluginName(self) -> str:
        return self.name

    def usage(self) -> str:
        rows = list(self.usageLines or [])
        if not rows:
            rows = [f'status {self.name}', f'Use {self.name} from the debugger status menu.']
        return '\n'.join(rows)

    def _run(self, command: list[str], *, timeout: int = 15) -> subprocess.CompletedProcess:
        return launcherRunCommand([str(part) for part in list(command or []) if str(part or EMPTY_STRING).strip()], capture_output=True, text=True, timeout=timeout)

    def _versionFromExecutable(self, executable_path: str) -> str:
        path_text = str(executable_path or EMPTY_STRING).strip()
        if not path_text or not self.versionArgs:
            return EMPTY_STRING
        try:
            candidate_path = Path(path_text)
            if candidate_path.exists() and not candidate_path.is_file():
                return EMPTY_STRING
        except Exception:
            recordException('start.py:4957', sys.exc_info()[1])
            _traceSwallowedException('start.py:Plugin._versionFromExecutable.path_probe', sys.exc_info()[1])
            pass
        try:
            completed = self._run([path_text, *list(self.versionArgs)], timeout=20)
            output = str((completed.stdout or completed.stderr or EMPTY_STRING)).strip()
            if output:
                return output.splitlines()[0][:240]
        except Exception as error:
            recordException('start.py:4965', sys.exc_info()[1])
            return f'{type(error).__name__}: {error}'
        return EMPTY_STRING

    def _helpFromExecutable(self, executable_path: str) -> str:
        path_text = str(executable_path or EMPTY_STRING).strip()
        if not path_text or not self.helpArgs:
            return EMPTY_STRING
        try:
            candidate_path = Path(path_text)
            if candidate_path.exists() and not candidate_path.is_file():
                return EMPTY_STRING
        except Exception:
            recordException('start.py:4977', sys.exc_info()[1])
            _traceSwallowedException('start.py:Plugin._helpFromExecutable.path_probe', sys.exc_info()[1])
            pass
        try:
            completed = self._run([path_text, *list(self.helpArgs)], timeout=20)
            output = str((completed.stdout or completed.stderr or EMPTY_STRING)).strip()
            if output:
                lines = output.splitlines()[:24]
                return '\n'.join(lines)
        except Exception as error:
            recordException('start.py:4986', sys.exc_info()[1])
            return f'{type(error).__name__}: {error}'
        return EMPTY_STRING

    def getVersion(self) -> str:
        path_text = self.getPath()
        return self._versionFromExecutable(path_text)

    def getPath(self) -> str:
        return self.find(install_if_missing=False)[0]

    def getRootDir(self) -> str:
        path_text = self.getPath()
        if not path_text:
            return EMPTY_STRING
        try:
            return str(Path(path_text).resolve().parent)
        except Exception:
            recordException('start.py:5003', sys.exc_info()[1])
            return str(Path(path_text).parent)

    def _envCandidates(self) -> list[tuple[Path, str]]:
        results: list[tuple[Path, str]] = []
        seen: set[str] = set()
        def add(value: str | Path, source: str) -> None:
            raw = str(value or EMPTY_STRING).strip().strip('"')
            if not raw:
                return
            path = Path(raw)
            candidates: list[Path] = []
            try:
                if path.exists() and path.is_dir():
                    for exe_name in self.executableNames:
                        child = path / exe_name
                        if child.exists() and child.is_file():
                            candidates.append(child)
                    if not candidates:
                        self._trace(f'ignore env directory without executable {raw} source={source}')
                        return
                else:
                    candidates.append(path)
            except Exception:
                recordException('start.py:5026', sys.exc_info()[1])
                candidates.append(path)
            for candidate in candidates:
                key = str(candidate).lower()
                if key in seen:
                    continue
                seen.add(key)
                results.append((candidate, source))
        for env_name in self.envVars:
            raw = os.environ.get(env_name)
            if raw:
                add(raw, f'env:{env_name}')
        if self.preferPathSearch:
            for exe_name in self.executableNames:
                try:
                    found = shutil.which(exe_name)
                except Exception:
                    recordException('start.py:5042', sys.exc_info()[1])
                    found = None
                if found:
                    add(found, f'path:{exe_name}')
                if os.name == 'nt':
                    try:
                        completed = self._run(['where.exe', exe_name], timeout=10)
                        if int(completed.returncode or 1) == 0:
                            for row in str(completed.stdout or EMPTY_STRING).splitlines():
                                add(row, f'path:{exe_name}')
                    except Exception:
                        recordException('start.py:5052', sys.exc_info()[1])
                        _traceSwallowedException('start.py:4913', sys.exc_info()[1])
                        pass
        return results

    def _windowsRegistrySpecs(self, winreg) -> list[dict[str, Any]]:
        return [
            {
                'mode': 'app_paths',
                'roots': (
                    (winreg.HKEY_CURRENT_USER, r'Software\Microsoft\Windows\CurrentVersion\App Paths'),
                    (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths'),
                    (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\App Paths'),
                ),
            },
            {
                'mode': 'uninstall',
                'roots': (
                    (winreg.HKEY_CURRENT_USER, r'SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall'),
                    (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall'),
                    (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall'),
                ),
            },
            {
                'mode': 'signal_keys',
                'roots': tuple((getattr(winreg, str(root_name or EMPTY_STRING), None), str(key_path or EMPTY_STRING)) for root_name, key_path in self.registrySignalKeys),
            },
        ]


    def _registryAddCandidate(self, results: list[tuple[Path, str]], seen: set[str], value: str | Path, source: str) -> None:
        raw = str(value or EMPTY_STRING).strip().strip('"')
        if not raw:
            return
        key = raw.lower()
        if key in seen:
            return
        seen.add(key)
        results.append((Path(raw), source))

    def _registryReadValue(self, winreg, key, value_name):
        try:
            query_name = str(value_name or EMPTY_STRING)
            return winreg.QueryValueEx(key, query_name)[0]
        except Exception:
            recordException('start.py:5096', sys.exc_info()[1])
            return EMPTY_STRING

    def _registryHandleAppPaths(self, winreg, root, base_key: str, add_candidate) -> bool:
        for exe_name in self.executableNames:
            subkey = str(base_key) + '\\' + exe_name
            try:
                with winreg.OpenKey(root, subkey) as key:
                    raw = self._registryReadValue(winreg, key, None)
                    if raw:
                        add_candidate(raw, f'registry app-paths {subkey}')
                    path_value = str(self._registryReadValue(winreg, key, 'Path') or EMPTY_STRING).strip().strip('"')
                    if path_value:
                        add_candidate(Path(path_value) / exe_name, f'registry app-paths {subkey} Path')
            except Exception:
                recordException('start.py:5110', sys.exc_info()[1])
                _traceSwallowedException('start.py:4970', sys.exc_info()[1])
                continue
        return False

    def _registryHandleUninstall(self, winreg, root, base_key: str, add_candidate) -> bool:
        try:
            with winreg.OpenKey(root, str(base_key)) as parent:
                count = int(winreg.QueryInfoKey(parent)[0] or 0)
                for index in range(count):
                    try:
                        child_name = str(winreg.EnumKey(parent, index) or EMPTY_STRING)
                        with winreg.OpenKey(parent, child_name) as child:
                            display_name = str(self._registryReadValue(winreg, child, 'DisplayName') or EMPTY_STRING).strip().lower()
                            if self.registryDisplayTokens and (not display_name or not any(token in display_name for token in self.registryDisplayTokens)):
                                continue
                            install_location = str(self._registryReadValue(winreg, child, 'InstallLocation') or EMPTY_STRING).strip().strip('"')
                            install_source = str(self._registryReadValue(winreg, child, 'InstallSource') or EMPTY_STRING).strip().strip('"')
                            display_icon = str(self._registryReadValue(winreg, child, 'DisplayIcon') or EMPTY_STRING).strip().strip('"')
                            for exe_name in self.executableNames:
                                if install_location:
                                    add_candidate(Path(install_location) / exe_name, f'registry uninstall {base_key}\\{child_name} InstallLocation')
                                if install_source:
                                    add_candidate(Path(install_source) / exe_name, f'registry uninstall {base_key}\\{child_name} InstallSource')
                            if display_icon:
                                add_candidate(display_icon.split(',')[0].strip(), f'registry uninstall {base_key}\\{child_name} DisplayIcon')
                    except Exception:
                        recordException('start.py:5136', sys.exc_info()[1])
                        _traceSwallowedException('start.py:4995', sys.exc_info()[1])
                        continue
        except Exception:
            recordException('start.py:5139', sys.exc_info()[1])
            return False
        return False

    def _registryHandleSignalKeys(self, winreg, root, base_key: str, add_candidate) -> bool:
        try:
            with winreg.OpenKey(root, str(base_key or EMPTY_STRING)):
                for candidate, source in self._defaultCandidates():
                    add_candidate(candidate, f'{source}; signal={base_key}')
                return True
        except Exception:
            recordException('start.py:5149', sys.exc_info()[1])
            return False

    def _registryModeHandlers(self, winreg, add_candidate):
        return {
            'app_paths': lambda root, base_key: self._registryHandleAppPaths(winreg, root, base_key, add_candidate),
            'uninstall': lambda root, base_key: self._registryHandleUninstall(winreg, root, base_key, add_candidate),
            'signal_keys': lambda root, base_key: self._registryHandleSignalKeys(winreg, root, base_key, add_candidate),
        }

    def _registryCandidates(self) -> list[tuple[Path, str]]:
        registry = WindowsRegistry()
        candidates = registry.candidatesForPlugin(self)
        if candidates:
            return candidates
        # Compatibility fallback: a signal key means the tool is probably installed
        # even if the key does not contain a direct executable path.  Use declared
        # default paths only; never inject a user-specific hard-coded path here.
        if os.name == 'nt':
            for key_spec in self.registrySignalKeys:
                if registry.keyExists(key_spec):
                    results: list[tuple[Path, str]] = []
                    seen: set[str] = set()
                    for candidate, source in self._defaultCandidates():
                        self._registryAddCandidate(results, seen, candidate, f'{source}; signal={key_spec}')
                    return results
        return []

    def _etcCandidates(self) -> list[tuple[Path, str]]:
        if os.name != 'posix' or sys.platform == 'darwin':
            return []
        return Etc().candidatesForPlugin(self)

    def _defaultCandidates(self) -> list[tuple[Path, str]]:
        roots = [
            Path(os.environ.get('ProgramFiles', 'C:/Program Files')),
            Path(os.environ.get('ProgramFiles(x86)', 'C:/Program Files (x86)')),
            Path.home() / 'AppData' / 'Local' / 'Programs',
            Path.home() / 'AppData' / 'Local',
            BASE_DIR,
        ]
        results: list[tuple[Path, str]] = []
        seen: set[str] = set()
        def add(value: str | Path, source: str) -> None:
            raw = str(value or EMPTY_STRING).strip()
            if not raw:
                return
            key = raw.lower()
            if key in seen:
                return
            seen.add(key)
            results.append((Path(raw), source))
        for path_text in self.defaultAbsolutePaths:
            add(path_text, 'default absolute path')
        for root in roots:
            for rel in self.defaultRelativePaths:
                add(root.joinpath(*rel), 'default path')
            for pattern in self.defaultGlobPatterns:
                try:
                    for found in root.glob(pattern):
                        add(found, 'default path glob')
                except Exception:
                    recordException('start.py:5210', sys.exc_info()[1])
                    _traceSwallowedException('start.py:5068', sys.exc_info()[1])
                    continue
        return results

    def candidatePathsDetailed(self) -> list[tuple[Path, str]]:
        rows = []
        rows.extend(self._envCandidates())
        rows.extend(self._registryCandidates())
        rows.extend(self._etcCandidates())
        rows.extend(self._defaultCandidates())
        unique: list[tuple[Path, str]] = []
        seen = set()
        for path_value, source in rows:
            normalized = str(path_value or EMPTY_STRING).strip()
            key = normalized.lower()
            if not normalized or key in seen:
                continue
            seen.add(key)
            unique.append((Path(normalized), source))
        return unique

    def find(self, install_if_missing: bool = False) -> tuple[str, str]:
        prefix = f'[Plugin:{self.getPluginName()}]'
        for candidate, source in self.candidatePathsDetailed():
            try:
                if candidate.exists() and candidate.is_file():
                    appendToolDirectoryToPath(candidate)
                    os.environ[f'TRIO_{self.getPluginName().upper()}_EXE'] = str(candidate)
                    return str(candidate), f'{prefix} found via {source}: {candidate}'
            except Exception:
                recordException('start.py:5240', sys.exc_info()[1])
                _traceSwallowedException('start.py:5097', sys.exc_info()[1])
                continue
        if install_if_missing:
            install_output = attemptToolInstall(self.getPluginName())
            for candidate, source in self.candidatePathsDetailed():
                try:
                    if candidate.exists() and candidate.is_file():
                        appendToolDirectoryToPath(candidate)
                        os.environ[f'TRIO_{self.getPluginName().upper()}_EXE'] = str(candidate)
                        return str(candidate), install_output + f'\n{prefix} installed via {source}: {candidate}'
                except Exception:
                    recordException('start.py:5251', sys.exc_info()[1])
                    _traceSwallowedException('start.py:5107', sys.exc_info()[1])
                    continue
            return EMPTY_STRING, install_output + f'\n{prefix} executable not found after install attempt.'
        return EMPTY_STRING, f'{prefix} executable not found.'

    def statusText(self) -> str:
        path_text, detail = self.find(False)
        version_text = self._versionFromExecutable(path_text) if path_text else EMPTY_STRING
        md5_text = EMPTY_STRING
        if path_text:
            try:
                md5_text = safeShortMd5(Path(path_text))
            except Exception:
                recordException('start.py:5264', sys.exc_info()[1])
                md5_text = EMPTY_STRING
        root_dir = self.getRootDir()
        help_text = self._helpFromExecutable(path_text) if path_text else EMPTY_STRING
        rows = [
            '=' * 62,
            f'  Plugin Status: {self.getName()}',
            '=' * 62,
            f'  Plugin key: {self.getPluginName()}',
            f'  Aliases: {", ".join(sorted(set((self.getPluginName(), *self.aliases))))}',
            f'  Path: {path_text or "(missing)"}',
            f'  Root dir: {root_dir or "(unresolved)"}',
            f'  Version: {version_text or "(unknown)"}',
            f'  md5: {md5_text or "(unavailable)"}',
            f'  Detail: {detail or "(none)"}',
            '',
            '  Usage:',
        ]
        usage_text = self.usage().strip()
        if usage_text:
            rows.extend([f'    {line}' for line in usage_text.splitlines()])
        else:
            rows.append('    (none)')
        rows.extend(['', '  Man / Help:'])
        if help_text:
            rows.extend([f'    {line}' for line in help_text.splitlines()])
        else:
            rows.append('    (no help text available)')
        rows.append('=' * 62)
        return '\n'.join(rows)

    def usageArgs(self) -> list[str]:
        return list(self.aliases or []) + [self.getPluginName()]


