_PLUGIN_CACHE: dict[str, Plugin] = {}

def allPlugins() -> list[Plugin]:
    if _PLUGIN_CACHE:
        return list(dict.fromkeys(_PLUGIN_CACHE.values()))
    created = []
    for spec in PLUGIN_DEFINITIONS:
        plugin = Plugin(**cast(Any, spec))
        created.append(plugin)
        keys = {plugin.getPluginName(), *plugin.aliases}
        for key in keys:
            _PLUGIN_CACHE[str(key or EMPTY_STRING).strip().lower()] = plugin
    return created

def pluginNamed(name: str | None) -> Plugin | None:
    key = str(name or EMPTY_STRING).strip().lower()
    if not key:
        return None
    if not _PLUGIN_CACHE:
        allPlugins()
    return _PLUGIN_CACHE.get(key)

def pluginStatusSummaryLines() -> list[str]:
    lines = ['Plugins:']
    for row in discoverPluginsDetailed(pluginRegistryNames(), install_if_missing=False):
        key = str(row.get('name', EMPTY_STRING) or EMPTY_STRING).strip()
        path_text = str(row.get('path', EMPTY_STRING) or EMPTY_STRING).strip()
        detail = str(row.get('detail', EMPTY_STRING) or EMPTY_STRING).strip()
        version_text = str(row.get('version', EMPTY_STRING) or EMPTY_STRING).strip()
        lines.append(f'  {key}: {path_text or "(missing)"}')
        lines.append(f'    {detail or "(no detail)"}')
        if version_text:
            lines.append(f'    version: {version_text}')
    return lines

def pluginStatusText(name: str) -> str:
    plugin = pluginNamed(name)
    if plugin is None:
        available = ', '.join(sorted({plugin.getPluginName() for plugin in allPlugins()}))
        return f'[Plugin] Unknown plugin "{name}". Available: {available}'
    return plugin.statusText()

def externalRepoToolStatusLinesDetailed() -> list[str]:
    lines = ['External repo tools:']
    for row in discoverPluginsDetailed(('git', 'putty', 'plink', 'pscp', 'psftp'), install_if_missing=False):
        label = str(row.get('name', EMPTY_STRING) or EMPTY_STRING).strip()
        path_text = str(row.get('path', EMPTY_STRING) or EMPTY_STRING).strip()
        detail = str(row.get('detail', EMPTY_STRING) or EMPTY_STRING).strip()
        version_text = str(row.get('version', EMPTY_STRING) or EMPTY_STRING).strip()
        lines.append(f'  {label}: {path_text if path_text else "(missing)"}')
        lines.append(f'    {detail or "(no detail)"}')
        if version_text:
            lines.append(f'    version: {version_text}')
    return lines

class Compiler(Plugin):
    COMMON_WINDOWS_CXX = ('g++.exe', 'clang++.exe', 'c++.exe', 'cl.exe')
    MSYS2_WINGET_ID = 'MSYS2.MSYS2'
    WINLIBS_WINGET_ID = 'BrechtSanders.WinLibs.POSIX.UCRT'

    def __init__(self, base_dir: str | Path | None = None, argv: list[str] | None = None):
        super().__init__(
            name='compiler',
            display_name='Compiler',
            aliases=('compiler', 'gcc', 'mingw64'),
            executable_names=('g++.exe', 'gcc.exe', 'clang++.exe', 'cl.exe'),
            env_vars=('TRIO_COMPILER_EXE', 'CXX', 'CC'),
            usage_lines=('compiler: automatic compiler selection for start.exe', 'Pass --gcc to prefer the generic GCC plugin before mingw64.'),
        )
        self.baseDir = Path(base_dir or BASE_DIR)
        self.argv = list(argv or [])
        self.quietLifecycleTrace = bool(cliHasAnyFlag(self.argv, CHAT_TEST_FLAGS | CHAT_TEST_WORKER_FLAGS))
        self.lastCompilerPath = EMPTY_STRING

    def _run(self, command: list[str], *, cwd: str | Path | None = None, timeout: int = 600) -> subprocess.CompletedProcess:
        return launcherRunCommand(
            [str(part) for part in list(command or []) if str(part or EMPTY_STRING).strip()],
            cwd=str(cwd or self.baseDir),
            capture_output=True,
            text=True,
            timeout=timeout,
        )

    def _where(self, executable: str) -> list[str]:
        if os.name != 'nt':
            return []
        try:
            completed = self._run(['where.exe', str(executable or EMPTY_STRING).strip()])
            if completed.returncode != 0:
                return []
            hits = []
            for raw in str(completed.stdout or EMPTY_STRING).splitlines():
                value = str(raw or EMPTY_STRING).strip()
                if value and Path(value).exists():
                    hits.append(str(Path(value).resolve()))
            return hits
        except Exception:
            recordException('start.py:5730', sys.exc_info()[1])
            return []

    def requestedCompilerPlugins(self) -> list[Plugin]:
        requested_gcc = bool(readCliOption(self.argv, GCC_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))
        ordered_names = ['gcc', 'mingw64', 'clang', 'msvc'] if requested_gcc else ['mingw64', 'gcc', 'clang', 'msvc']
        plugins: list[Plugin] = []
        for name in ordered_names:
            plugin = pluginNamed(name)
            if plugin is not None:
                plugins.append(plugin)
        return plugins

    def candidateCompilersDetailed(self) -> list[tuple[str, str, str]]:
        rows: list[tuple[str, str, str]] = []
        seen = set()
        for plugin in self.requestedCompilerPlugins():
            path_text, detail = plugin.find(False)
            normalized = str(path_text or EMPTY_STRING).strip()
            key = normalized.lower()
            if normalized and key not in seen:
                seen.add(key)
                rows.append((normalized, plugin.getPluginName(), detail))
        return rows

    def candidateCompilers(self) -> list[str]:
        return [path for path, _plugin, _detail in self.candidateCompilersDetailed()]

    def _findMsys2Bash(self) -> str:
        for path in [Path('C:/msys64/usr/bin/bash.exe'), Path('C:/msys64/bin/bash.exe')]:
            if path.exists():
                return str(path.resolve())
        for hit in self._where('bash.exe'):
            lowered = str(hit).lower().replace('\\', '/')
            if '/msys64/' in lowered:
                return hit
        return EMPTY_STRING

    def installMingw64(self) -> bool:
        if os.name != 'nt':
            traceCompilerStep('winget-mingw64', False, 'non-Windows host')
            return False
        winget_hits = self._where('winget.exe')
        if not winget_hits:
            traceCompilerStep('winget-mingw64', False, 'winget.exe not found')
            return False
        try:
            completed = self._run([
                winget_hits[0], 'install', '-e', '--id', self.MSYS2_WINGET_ID,
                '--accept-package-agreements', '--accept-source-agreements', '--disable-interactivity'
            ], timeout=1800)
            ok = completed.returncode == 0
            traceCompilerStep('winget-mingw64', ok, (completed.stdout or completed.stderr or EMPTY_STRING).strip()[:240])
            if not ok:
                return False
        except Exception as error:
            recordException('start.py:5785', sys.exc_info()[1])
            traceCompilerStep('winget-mingw64', False, f'{type(error).__name__}: {error}')
            return False
        bash_path = self._findMsys2Bash()
        if not bash_path:
            traceCompilerStep('mingw64-gcc-install', False, 'MSYS2 bash.exe not found after winget install')
            return False
        try:
            completed = self._run([bash_path, '-lc', 'pacman --noconfirm -Sy --needed mingw-w64-ucrt-x86_64-gcc'], timeout=1800)
            ok = completed.returncode == 0
            traceCompilerStep('mingw64-gcc-install', ok, (completed.stdout or completed.stderr or EMPTY_STRING).strip()[:240])
            return ok
        except Exception as error:
            recordException('start.py:5797', sys.exc_info()[1])
            traceCompilerStep('mingw64-gcc-install', False, f'{type(error).__name__}: {error}')
            return False

    def installGccFallback(self) -> bool:
        if os.name != 'nt':
            traceCompilerStep('winget-gcc-fallback', False, 'non-Windows host')
            return False
        winget_hits = self._where('winget.exe')
        if not winget_hits:
            traceCompilerStep('winget-gcc-fallback', False, 'winget.exe not found')
            return False
        try:
            completed = self._run([
                winget_hits[0], 'install', '-e', '--id', self.WINLIBS_WINGET_ID,
                '--accept-package-agreements', '--accept-source-agreements', '--disable-interactivity'
            ], timeout=1800)
            ok = completed.returncode == 0
            traceCompilerStep('winget-gcc-fallback', ok, (completed.stdout or completed.stderr or EMPTY_STRING).strip()[:240])
            return ok
        except Exception as error:
            recordException('start.py:5817', sys.exc_info()[1])
            traceCompilerStep('winget-gcc-fallback', False, f'{type(error).__name__}: {error}')
            return False

    def ensureCompiler(self) -> str:
        candidates = self.candidateCompilersDetailed()
        if candidates:
            self.lastCompilerPath = candidates[0][0]
            traceCompilerStep('compiler-detect', True, f'{candidates[0][1]} => {self.lastCompilerPath}')
            return self.lastCompilerPath
        traceCompilerStep('compiler-detect', False, 'no compiler plugin resolved from env/path, registry, or defaults')
        if self.installMingw64():
            candidates = self.candidateCompilersDetailed()
            if candidates:
                self.lastCompilerPath = candidates[0][0]
                traceCompilerStep('compiler-after-mingw64', True, f'{candidates[0][1]} => {self.lastCompilerPath}')
                return self.lastCompilerPath
            traceCompilerStep('compiler-after-mingw64', False, 'compiler still missing after install')
        if self.installGccFallback():
            candidates = self.candidateCompilersDetailed()
            if candidates:
                self.lastCompilerPath = candidates[0][0]
                traceCompilerStep('compiler-after-gcc-fallback', True, f'{candidates[0][1]} => {self.lastCompilerPath}')
                return self.lastCompilerPath
            traceCompilerStep('compiler-after-gcc-fallback', False, 'compiler still missing after fallback install')
        return EMPTY_STRING

    def compile(self, cpp: CPP, output_name: str = START_EXE_NAME) -> Path:
        source_path = cpp.write()
        output_path = self.baseDir / str(output_name or START_EXE_NAME)
        compiler_path = str(self.ensureCompiler() or EMPTY_STRING).strip()
        if not compiler_path:
            raise RuntimeError('No suitable C/C++ compiler was found or installed for start.exe')
        compiler_lower = compiler_path.lower()
        if compiler_lower.endswith('cl.exe'):
            command = [compiler_path, '/nologo', '/std:c++17', '/EHsc', str(source_path), '/Fe:' + str(output_path), 'user32.lib', 'shell32.lib']
        else:
            command = [compiler_path, '-std=c++17', '-O2', '-municode', '-DUNICODE', '-D_UNICODE', str(source_path), '-o', str(output_path), '-luser32', '-lshell32']
        traceCompilerStep('create-start-cpp', True, str(source_path))
        traceCompilerStep('build-start-exe-command', True, ' '.join(shlex.quote(str(part)) for part in command))
        completed = self._run(command, cwd=self.baseDir, timeout=1800)
        stdout_text = str(completed.stdout or EMPTY_STRING).strip()
        stderr_text = str(completed.stderr or EMPTY_STRING).strip()
        ok = completed.returncode == 0 and output_path.exists()
        detail_text = stderr_text or stdout_text or str(output_path)
        traceCompilerStep('build-start-exe', ok, detail_text[:500] if detail_text else str(output_path))
        if stdout_text:
            traceCompilerStep('build-start-exe-stdout', True, stdout_text[:500])
        if stderr_text:
            traceCompilerStep('build-start-exe-stderr', bool(ok), stderr_text[:500])
        if not ok:
            raise RuntimeError((stderr_text or stdout_text or 'compiler returned non-zero exit status').strip())
        return output_path

    def ensureStartExe(self, force_rebuild: bool = False) -> Path:
        exe_path = self.baseDir / START_EXE_NAME
        if exe_path.exists() and not force_rebuild:
            traceCompilerStep('existing-start-exe', True, str(exe_path))
            return exe_path
        return self.compile(CPPFactory.startLauncher(), output_name=START_EXE_NAME)



def _stripJsonComments(text: str) -> str:
    """Strip JSONC comments without touching quoted strings."""
    value = str(text or EMPTY_STRING)
    out: list[str] = []
    index = 0
    in_string = False
    quote = EMPTY_STRING
    escape = False
    while index < len(value):
        char = value[index]
        nxt = value[index + 1] if index + 1 < len(value) else EMPTY_STRING
        if in_string:
            out.append(char)
            if escape:
                escape = False
            elif char == '\\':
                escape = True
            elif char == quote:
                in_string = False
                quote = EMPTY_STRING
            index += 1
            continue
        if char in {'"', "'"}:
            in_string = True
            quote = char
            out.append(char)
            index += 1
            continue
        if char == '/' and nxt == '/':
            index += 2
            while index < len(value) and value[index] not in {'\n', '\r'}:
                index += 1
            continue
        if char == '/' and nxt == '*':
            index += 2
            while index + 1 < len(value) and not (value[index] == '*' and value[index + 1] == '/'):
                index += 1
            index += 2 if index + 1 < len(value) else 0
            continue
        out.append(char)
        index += 1
    return ''.join(out)


def _loadJsoncFile(path: str | Path) -> dict[str, object]:
    target = Path(path)
    raw = File(target).readText(encoding='utf-8-sig', errors='replace') if target.exists() else '{}'
    if not raw.strip():
        return {}
    try:
        payload = json.loads(raw)
    except Exception:
        recordException('start.py:5931', sys.exc_info()[1])
        payload = json.loads(_stripJsonComments(raw) or '{}')
    return cast(dict[str, object], payload) if isinstance(payload, dict) else {}


def _writeJsoncFile(path: str | Path, payload: dict[str, object]) -> None:
    Path(path).parent.mkdir(parents=True, exist_ok=True)
    File(Path(path)).writeText(json.dumps(payload, indent=2, ensure_ascii=False) + '\n')



def _decodeOpenTypeNameString(raw: bytes, platform_id: int, encoding_id: int) -> str:
    if not raw:
        return EMPTY_STRING
    encodings = []
    if platform_id in {0, 3}:
        encodings.extend(['utf-16-be', 'utf-8'])
    elif platform_id == 1:
        encodings.extend(['macroman', 'latin-1'])
    else:
        encodings.extend(['utf-16-be', 'utf-8', 'latin-1'])
    for encoding in encodings:
        try:
            return raw.decode(encoding, errors='replace').replace('\x00', EMPTY_STRING).strip()
        except Exception:
            recordException('start.py:5955', sys.exc_info()[1])
            _traceSwallowedException('start.py:5810', sys.exc_info()[1])
            continue
    return EMPTY_STRING


def _readOpenTypeNameTable(font_path: str | Path) -> dict[int, list[str]]:
    names: dict[int, list[str]] = {}
    target = Path(font_path)
    if not target.exists() and _isOptionalBundledFontPath(target):
        return names
    try:
        data = target.read_bytes()
        if len(data) < 12:
            return names
        num_tables = struct.unpack('>H', data[4:6])[0]
        name_offset = 0
        name_length = 0
        table_dir = 12
        for index in range(num_tables):
            entry_offset = table_dir + (index * 16)
            if entry_offset + 16 > len(data):
                break
            tag = data[entry_offset:entry_offset + 4]
            offset, length = struct.unpack('>II', data[entry_offset + 8:entry_offset + 16])
            if tag == b'name':
                name_offset = int(offset)
                name_length = int(length)
                break
        if not name_offset or name_offset + 6 > len(data):
            return names
        table = data[name_offset:name_offset + name_length]
        if len(table) < 6:
            return names
        _format, count, string_offset = struct.unpack('>HHH', table[:6])
        for index in range(int(count)):
            rec_offset = 6 + (index * 12)
            if rec_offset + 12 > len(table):
                break
            platform_id, encoding_id, _language_id, name_id, length, offset = struct.unpack('>HHHHHH', table[rec_offset:rec_offset + 12])
            start = int(string_offset) + int(offset)
            end = start + int(length)
            if start < 0 or end > len(table) or end <= start:
                continue
            value = _decodeOpenTypeNameString(table[start:end], int(platform_id), int(encoding_id))
            if value:
                bucket = names.setdefault(int(name_id), [])
                if value not in bucket:
                    bucket.append(value)
    except Exception as error:
        recordException('start.py:6001', sys.exc_info()[1])
        if _isOptionalBundledFontPath(target):
            traceCompilerWarn('font-face-read-raw', f'{type(error).__name__}: {error}')
        else:
            traceCompilerStep('font-face-read-raw', False, f'{type(error).__name__}: {error}')
    return names


def _fontFaceFromNameTable(font_path: str | Path) -> str:
    target = Path(font_path)
    # Prefer fontTools when present, but keep the raw parser so the debugger can
    # still diagnose the font before dependencies have been repaired.
    try:
        if TTFont is not None and target.exists():
            font = requiredTTFontClass()(str(target))
            try:
                by_id: dict[int, list[str]] = {}
                for name_record in getattr(getattr(font, 'names', None), 'names', []) or font['name'].names:
                    try:
                        name_id = int(getattr(name_record, 'nameID', 0) or 0)
                        value = str(name_record.toUnicode() or EMPTY_STRING).strip()
                    except Exception:
                        recordException('start.py:6019', sys.exc_info()[1])
                        _traceSwallowedException('start.py:5873', sys.exc_info()[1])
                        continue
                    if value:
                        bucket = by_id.setdefault(name_id, [])
                        if value not in bucket:
                            bucket.append(value)
                for name_id in (16, 1, 4, 6):
                    values = by_id.get(name_id) or []
                    if values:
                        traceCompilerStep('font-face-read', True, f'fontTools path={target} nameID={name_id} face={values[0]}')
                        return values[0]
            finally:
                try:
                    font.close()
                except Exception:
                    recordException('start.py:6034', sys.exc_info()[1])
                    _traceSwallowedException('start.py:5887', sys.exc_info()[1])
                    pass
    except Exception as error:
        recordException('start.py:6037', sys.exc_info()[1])
        traceCompilerStep('font-face-read-fonttools', False, f'{type(error).__name__}: {error}')
    raw_names = _readOpenTypeNameTable(target)
    for name_id in (16, 1, 4, 6):
        values = raw_names.get(name_id) or []
        if values:
            traceCompilerStep('font-face-read', True, f'raw path={target} nameID={name_id} face={values[0]}')
            return values[0]
    if _isOptionalBundledFontPath(target) and not target.exists():
        traceCompilerWarn('font-face-read', f'no family name found because optional font binary is missing: {target}')
    else:
        traceCompilerStep('font-face-read', False, f'no family name found in {target}')
    return EMPTY_STRING


def _terminalFontFaceIsLegacy(face: str) -> bool:
    normalized = re.sub(r'[^a-z0-9]+', '', str(face or EMPTY_STRING).lower())
    return normalized in {
        'triodesktoppsmonotight',
        'triodesktoppscolortight',
        'triodesktoppsmono',
        'triodesktoppscolor',
    }


def bundledTerminalFontFace(font_path: str | Path | None = None) -> str:
    settings = terminalFontSettings()
    configured_face = str(settings.get('face') or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
    target = Path(font_path) if font_path is not None else bundledTerminalFontPath()
    face = _fontFaceFromNameTable(target)
    if face:
        if face.lower() != configured_face.lower():
            if _terminalFontFaceIsLegacy(face) or target.name.lower() in {'default.otf', 'default.otf'}:
                traceCompilerWarn('font-face-config', f'configured={configured_face} actual={face} path={target} using=configured')
                return configured_face
            traceCompilerStep('font-face-config', False, f'configured={configured_face} actual={face} path={target}')
        return face
    return configured_face


def _extractTerminalFont(payload: object) -> str:
    if not isinstance(payload, dict):
        return EMPTY_STRING
    payload_map = cast(dict[str, object], payload)
    font_payload = payload_map.get('font')
    if isinstance(font_payload, dict):
        face = str(font_payload.get('face', EMPTY_STRING) or EMPTY_STRING).strip()
        if face:
            return face
    face = str(payload_map.get('fontFace', EMPTY_STRING) or EMPTY_STRING).strip()
    if face:
        return face
    return EMPTY_STRING


def _windowsTerminalSettingsPathKind(path: Path) -> str:
    lowered = str(path).lower()
    if 'windowsterminalpreview' in lowered:
        return 'preview'
    if 'packages/microsoft.windowsterminal_' in lowered.replace('\\', '/'):
        return 'stable'
    if 'microsoft/windows terminal' in lowered.replace('\\', '/'):
        return 'unpackaged'
    return 'custom'


def windowsTerminalSettingsCandidates() -> list[Path]:
    local_appdata = Path(os.environ.get('LOCALAPPDATA') or (Path.home() / 'AppData/Local'))
    env_candidates = []
    for env_name in ('WT_SETTINGS_PATH', 'WINDOWS_TERMINAL_SETTINGS', 'TRIO_WINDOWS_TERMINAL_SETTINGS'):
        raw = str(os.environ.get(env_name) or EMPTY_STRING).strip()
        if raw:
            env_candidates.append(Path(raw))
    candidates = [
        *env_candidates,
        local_appdata / 'Packages/Microsoft.WindowsTerminal_8wekyb3d8bbwe/LocalState/settings.json',
        local_appdata / 'Packages/Microsoft.WindowsTerminalPreview_8wekyb3d8bbwe/LocalState/settings.json',
        local_appdata / 'Microsoft/Windows Terminal/settings.json',
    ]
    unique: list[Path] = []
    seen: set[str] = set()
    for path in candidates:
        normalized = str(path)
        key = normalized.lower()
        if key in seen:
            continue
        seen.add(key)
        unique.append(path)
    return unique


def _windowsTerminalWritableTargets() -> list[Path]:
    candidates = windowsTerminalSettingsCandidates()
    existing = [path for path in candidates if path.exists()]
    if existing:
        return existing
    # Microsoft documents this stable package path as the normal settings.json
    # location.  If Terminal has not created one yet, this is the safest default
    # per-user target; no elevation should be required for LOCALAPPDATA.
    return candidates[:1]


def _windowsTerminalProfileLooksPowerShell(profile: dict[str, object]) -> bool:
    haystack = ' '.join([
        str(profile.get('name', EMPTY_STRING) or EMPTY_STRING),
        str(profile.get('source', EMPTY_STRING) or EMPTY_STRING),
        str(profile.get('commandline', EMPTY_STRING) or EMPTY_STRING),
        str(profile.get('guid', EMPTY_STRING) or EMPTY_STRING),
    ]).lower()
    return bool('powershell' in haystack or 'pwsh' in haystack or 'microsoft.powershell' in haystack)


def _windowsTerminalCurrentProfileId() -> str:
    return str(os.environ.get('WT_PROFILE_ID') or os.environ.get('WT_PROFILE') or EMPTY_STRING).strip().lower()


def _windowsTerminalProfileLooksCurrent(profile: dict[str, object]) -> bool:
    profile_id = _windowsTerminalCurrentProfileId()
    if not profile_id:
        return False
    for key in ('guid', 'name'):
        value = str(profile.get(key, EMPTY_STRING) or EMPTY_STRING).strip().lower()
        if value and value == profile_id:
            return True
    return False


def _windowsTerminalProfiles(payload: dict[str, object]) -> tuple[dict[str, object], list[dict[str, object]]]:
    profiles_obj = payload.get('profiles')
    profiles = cast(dict[str, object], profiles_obj) if isinstance(profiles_obj, dict) else {}
    defaults_obj = profiles.get('defaults')
    defaults = cast(dict[str, object], defaults_obj) if isinstance(defaults_obj, dict) else {}
    list_obj = profiles.get('list')
    profile_rows: list[dict[str, object]] = []
    if isinstance(list_obj, list):
        for profile in list_obj:
            if isinstance(profile, dict):
                profile_rows.append(cast(dict[str, object], profile))
    return defaults, profile_rows


def _describeWindowsTerminalProfile(profile: dict[str, object]) -> str:
    name = str(profile.get('name', EMPTY_STRING) or EMPTY_STRING).strip() or '(unnamed)'
    guid = str(profile.get('guid', EMPTY_STRING) or EMPTY_STRING).strip()
    source = str(profile.get('source', EMPTY_STRING) or EMPTY_STRING).strip()
    return f"name={name!r} guid={guid or '(none)'} source={source or '(none)'}"


def _runTerminalProbeCommand(command: list[str], timeout: int = 4) -> tuple[bool, str]:
    try:
        # Route even tiny terminal probes through StartProcess so the lifecycle
        # bypass detector stays clean and debugger-visible process rows exist.
        completed = launcherRunCommand(command, text=True, capture_output=True, timeout=timeout, check=False)
        output = '\n'.join([str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING), str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)]).strip()
        return int(getattr(completed, 'returncode', 0) or 0) == 0, output
    except Exception as error:
        recordException('start.py:6176', sys.exc_info()[1])
        return False, f'{type(error).__name__}: {error}'


def _detectPowerShellVersion() -> str:
    if os.name != 'nt':
        return EMPTY_STRING
    for executable in (shutil.which('pwsh.exe'), shutil.which('pwsh'), shutil.which('powershell.exe'), shutil.which('powershell')):
        if not executable:
            continue
        ok, output = _runTerminalProbeCommand([executable, '-NoLogo', '-NoProfile', '-NonInteractive', '-Command', "$PSVersionTable.PSVersion.ToString()"], timeout=4)
        value = str(output or EMPTY_STRING).strip().splitlines()
        if ok and value:
            return value[-1].strip()
    return EMPTY_STRING


def _detectWindowsTerminalVersion() -> tuple[str, str]:
    if os.name != 'nt':
        return EMPTY_STRING, 'not-windows'
    powershell = shutil.which('powershell.exe') or shutil.which('powershell') or shutil.which('pwsh.exe') or shutil.which('pwsh')
    if powershell:
        script = "& { $pkg = Get-AppxPackage -Name Microsoft.WindowsTerminal -ErrorAction SilentlyContinue | Select-Object -First 1; if ($pkg) { $pkg.Version.ToString(); return }; $pkg = Get-AppxPackage -Name Microsoft.WindowsTerminalPreview -ErrorAction SilentlyContinue | Select-Object -First 1; if ($pkg) { 'Preview ' + $pkg.Version.ToString(); return } }"
        ok, output = _runTerminalProbeCommand([powershell, '-NoLogo', '-NoProfile', '-NonInteractive', '-Command', script], timeout=5)
        line = next((part.strip() for part in str(output or EMPTY_STRING).splitlines() if part.strip()), EMPTY_STRING)
        if ok and line:
            return line, 'Get-AppxPackage'
    winget = shutil.which('winget.exe') or shutil.which('winget')
    if winget:
        ok, output = _runTerminalProbeCommand([winget, 'list', '--id', 'Microsoft.WindowsTerminal', '--exact', '--accept-source-agreements'], timeout=6)
        for line in str(output or EMPTY_STRING).splitlines():
            if 'Microsoft.WindowsTerminal' in line:
                return ' '.join(line.split()), 'winget list'
    return EMPTY_STRING, 'unavailable'


def _consoleHostFontSizeDword(width: int = 0, height: int = RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT) -> int:
    # ConsoleHost stores COORD values as a DWORD with X in the low word and Y in
    # the high word. Microsoft documents FontSize as a Coordinate REG_DWORD, so
    # write the same value the Properties dialog would persist.
    x = max(0, min(0xFFFF, int(width or 0)))
    y = max(1, min(0xFFFF, int(height or RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT)))
    return int((y << 16) | x)


def _consoleHostFontSizeText(width: int = 0, height: int = 0) -> str:
    x = int(width or 0)
    y = int(height or 0)
    return f'{x}x{y}' if (x or y) else '(unknown)'


def _getConsoleHostLiveFontDetails() -> dict[str, object]:
    details: dict[str, object] = {
        'ok': False,
        'face': EMPTY_STRING,
        'width': 0,
        'height': 0,
        'family': 0,
        'weight': 0,
        'index': 0,
        'source': 'not-windows' if os.name != 'nt' else 'GetCurrentConsoleFontEx',
        'error': EMPTY_STRING,
    }
    if os.name != 'nt':
        return details
    try:
        import ctypes
        LF_FACESIZE = 32
        STD_OUTPUT_HANDLE = -11
        class COORD(ctypes.Structure):
            _fields_ = [('X', ctypes.c_short), ('Y', ctypes.c_short)]
        class CONSOLE_FONT_INFOEX(ctypes.Structure):
            _fields_ = [
                ('cbSize', ctypes.c_ulong),
                ('nFont', ctypes.c_ulong),
                ('dwFontSize', COORD),
                ('FontFamily', ctypes.c_uint),
                ('FontWeight', ctypes.c_uint),
                ('FaceName', ctypes.c_wchar * LF_FACESIZE),
            ]
        handle = ctypes.windll.kernel32.GetStdHandle(STD_OUTPUT_HANDLE)
        info = CONSOLE_FONT_INFOEX()
        info.cbSize = ctypes.sizeof(CONSOLE_FONT_INFOEX)
        ok = ctypes.windll.kernel32.GetCurrentConsoleFontEx(handle, False, ctypes.byref(info))
        if not ok:
            details['error'] = f'GetCurrentConsoleFontEx failed last_error={ctypes.get_last_error()}'
            return details
        details.update({
            'ok': True,
            'face': str(info.FaceName or EMPTY_STRING).strip(),
            'width': int(info.dwFontSize.X or 0),
            'height': int(info.dwFontSize.Y or 0),
            'family': int(info.FontFamily or 0),
            'weight': int(info.FontWeight or 0),
            'index': int(info.nFont or 0),
            'source': 'GetCurrentConsoleFontEx',
        })
        return details
    except Exception as error:
        recordException('start.py:6274', sys.exc_info()[1])
        details['error'] = f'{type(error).__name__}: {error}'
        return details


def _getConsoleHostLiveFontFace() -> tuple[str, str]:
    details = _getConsoleHostLiveFontDetails()
    if bool(details.get('ok')):
        return str(details.get('face') or EMPTY_STRING).strip(), 'GetCurrentConsoleFontEx'
    return EMPTY_STRING, str(details.get('error') or details.get('source') or 'unavailable')


def _setConsoleHostLiveFontFace(desired: str, height: int = RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT, width: int = RECOMMENDED_CONSOLE_HOST_FONT_WIDTH) -> tuple[bool, str]:
    if os.name != 'nt':
        return False, 'not Windows'
    try:
        import ctypes
        LF_FACESIZE = 32
        STD_OUTPUT_HANDLE = -11
        desired_text = str(desired or EMPTY_STRING).strip()
        if not desired_text:
            return False, 'empty font face'
        if len(desired_text) >= LF_FACESIZE:
            return False, f'font face too long for CONSOLE_FONT_INFOEX ({len(desired_text)} >= {LF_FACESIZE})'
        class COORD(ctypes.Structure):
            _fields_ = [('X', ctypes.c_short), ('Y', ctypes.c_short)]
        class CONSOLE_FONT_INFOEX(ctypes.Structure):
            _fields_ = [
                ('cbSize', ctypes.c_ulong),
                ('nFont', ctypes.c_ulong),
                ('dwFontSize', COORD),
                ('FontFamily', ctypes.c_uint),
                ('FontWeight', ctypes.c_uint),
                ('FaceName', ctypes.c_wchar * LF_FACESIZE),
            ]
        handle = ctypes.windll.kernel32.GetStdHandle(STD_OUTPUT_HANDLE)
        info = CONSOLE_FONT_INFOEX()
        info.cbSize = ctypes.sizeof(CONSOLE_FONT_INFOEX)
        got = ctypes.windll.kernel32.GetCurrentConsoleFontEx(handle, False, ctypes.byref(info))
        if not got:
            return False, f'GetCurrentConsoleFontEx failed last_error={ctypes.get_last_error()}'
        previous = str(info.FaceName or EMPTY_STRING).strip()
        previous_size = _consoleHostFontSizeText(int(info.dwFontSize.X or 0), int(info.dwFontSize.Y or 0))
        target_height = max(int(height or RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT), RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT)
        target_width = max(0, int(width or 0))
        # For ConsoleHost, preserving the existing X/Y is the exact bug that can
        # leave the new face rendered at a microscopic size. Set both dimensions
        # explicitly; X=0 lets GDI choose the natural monospace width for the Y.
        info.nFont = 0
        info.FaceName = desired_text
        info.dwFontSize.X = int(target_width)
        info.dwFontSize.Y = int(target_height)
        info.FontFamily = 54
        info.FontWeight = 400
        set_ok = ctypes.windll.kernel32.SetCurrentConsoleFontEx(handle, False, ctypes.byref(info))
        if not set_ok:
            return False, f'SetCurrentConsoleFontEx failed last_error={ctypes.get_last_error()} previous={previous or "(unknown)"} size={previous_size}'
        after = _getConsoleHostLiveFontDetails()
        after_face = str(after.get('face') or EMPTY_STRING).strip()
        after_height = safeInt(after.get('height'), 0)
        after_width = safeInt(after.get('width'), 0)
        if after_face.lower() != desired_text.lower():
            return False, f'SetCurrentConsoleFontEx returned success but live font is {after_face or "(unknown)"} via {after.get("source")}'
        if after_height < target_height:
            return False, f'SetCurrentConsoleFontEx returned success but live size is {_consoleHostFontSizeText(after_width, after_height)}; requested {_consoleHostFontSizeText(target_width, target_height)}'
        return True, f'live font changed from {previous or "(unknown)"} {previous_size} to {after_face} {_consoleHostFontSizeText(after_width, after_height)}'
    except Exception as error:
        recordException('start.py:6340', sys.exc_info()[1])
        return False, f'{type(error).__name__}: {error}'

def _consoleHostRegistryFontKeys() -> list[str]:
    keys = [r'Console']
    program_files = os.environ.get('ProgramFiles') or r'C:\Program Files'
    program_files_x86 = os.environ.get('ProgramFiles(x86)') or r'C:\Program Files (x86)'
    candidates = [
        r'%SystemRoot%_System32_WindowsPowerShell_v1.0_powershell.exe',
        str(Path(program_files) / 'PowerShell' / '7' / 'pwsh.exe').replace('\\', '_').replace(':', ':'),
        str(Path(program_files) / 'PowerShell' / '7-preview' / 'pwsh.exe').replace('\\', '_').replace(':', ':'),
        str(Path(program_files_x86) / 'PowerShell' / '7' / 'pwsh.exe').replace('\\', '_').replace(':', ':'),
    ]
    for value in candidates:
        normalized = str(value).replace('/', '_').replace('\\', '_')
        key = 'Console\\' + normalized
        if key not in keys:
            keys.append(key)
    return keys


def _persistConsoleHostFontFace(desired: str, height: int = RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT, width: int = RECOMMENDED_CONSOLE_HOST_FONT_WIDTH) -> tuple[bool, str]:
    if os.name != 'nt':
        return False, 'not Windows'
    try:
        import winreg  # type: ignore
        touched: list[str] = []
        font_size = _consoleHostFontSizeDword(width, height)
        for key_path in _consoleHostRegistryFontKeys():
            try:
                with winreg.CreateKey(winreg.HKEY_CURRENT_USER, key_path) as key:
                    winreg.SetValueEx(key, 'FaceName', 0, winreg.REG_SZ, desired)
                    winreg.SetValueEx(key, 'FontSize', 0, winreg.REG_DWORD, font_size)
                    winreg.SetValueEx(key, 'FontFamily', 0, winreg.REG_DWORD, 54)
                    winreg.SetValueEx(key, 'FontWeight', 0, winreg.REG_DWORD, 400)
                touched.append('HKCU\\' + key_path)
            except Exception as error:
                recordException('start.py:6376', sys.exc_info()[1])
                traceCompilerStep('console-font-registry-key', False, f'{key_path}: {type(error).__name__}: {error}')
        size_text = _consoleHostFontSizeText(width, height)
        return bool(touched), (', '.join(touched) + f' FontSize={size_text}') if touched else 'no registry keys touched'
    except Exception as error:
        recordException('start.py:6380', sys.exc_info()[1])
        return False, f'{type(error).__name__}: {error}'

def detectConsoleFontInfo() -> dict[str, object]:
    info: dict[str, object] = {'host': 'unknown', 'font': EMPTY_STRING, 'source': EMPTY_STRING, 'path': EMPTY_STRING, 'version': EMPTY_STRING, 'version_source': EMPTY_STRING, 'shell_version': EMPTY_STRING, 'reason': EMPTY_STRING, 'font_width': 0, 'font_height': 0, 'font_size': EMPTY_STRING}
    if os.name != 'nt':
        info['host'] = f'{sys.platform}-terminal'
        info['reason'] = 'Windows terminal font switching only applies on Windows.'
        return info
    info['shell_version'] = _detectPowerShellVersion()
    if os.environ.get('WT_SESSION'):
        info['host'] = 'windows-terminal'
        version, version_source = _detectWindowsTerminalVersion()
        info['version'] = version
        info['version_source'] = version_source
        for settings_path in windowsTerminalSettingsCandidates():
            if not settings_path.exists():
                traceCompilerStep('windows-terminal-font-detect', False, f'missing settings path={settings_path}')
                continue
            try:
                payload_dict = _loadJsoncFile(settings_path)
            except Exception as error:
                recordException('start.py:6401', sys.exc_info()[1])
                traceCompilerStep('windows-terminal-font-detect', False, f'{settings_path}: {type(error).__name__}: {error}')
                continue
            defaults, profiles = _windowsTerminalProfiles(payload_dict)
            profile_font = EMPTY_STRING
            profile_label = EMPTY_STRING
            current_profile_id = _windowsTerminalCurrentProfileId()
            for profile in profiles:
                if current_profile_id and not _windowsTerminalProfileLooksCurrent(profile):
                    continue
                profile_font = _extractTerminalFont(profile)
                if profile_font:
                    profile_label = _describeWindowsTerminalProfile(profile)
                    break
            if not profile_font:
                for profile in profiles:
                    if not _windowsTerminalProfileLooksPowerShell(profile):
                        continue
                    profile_font = _extractTerminalFont(profile)
                    if profile_font:
                        profile_label = _describeWindowsTerminalProfile(profile)
                        break
            default_font = _extractTerminalFont(defaults)
            font = profile_font or default_font
            info['font'] = str(font or EMPTY_STRING).strip()
            info['source'] = f"settings.json:{profile_label or 'profiles.defaults'}"
            info['path'] = str(settings_path)
            traceCompilerStep('windows-terminal-font-detect', bool(font), f"path={settings_path} font={font or '(unset)'} source={info['source']} version={info['version'] or '(unknown)'}")
            return info
        info['source'] = 'Windows Terminal settings.json not found'
        return info
    info['host'] = 'console-host'
    live_details = _getConsoleHostLiveFontDetails()
    live_face = str(live_details.get('face') or EMPTY_STRING).strip()
    live_source = str(live_details.get('source') or live_details.get('error') or EMPTY_STRING)
    if live_face:
        width = safeInt(live_details.get('width'), 0)
        height = safeInt(live_details.get('height'), 0)
        info['font'] = live_face
        info['font_width'] = width
        info['font_height'] = height
        info['font_size'] = _consoleHostFontSizeText(width, height)
        info['source'] = live_source
        info['path'] = 'current console screen buffer'
        return info
    try:
        import winreg  # type: ignore
        with winreg.OpenKey(winreg.HKEY_CURRENT_USER, r'Console') as key:
            face, _ = winreg.QueryValueEx(key, 'FaceName')
            info['font'] = str(face or EMPTY_STRING).strip()
            info['source'] = r'HKCU\Console'
            info['path'] = r'HKCU\Console'
            info['reason'] = live_source
            return info
    except Exception as error:
        recordException('start.py:6455', sys.exc_info()[1])
        info['reason'] = f'{live_source}; registry {type(error).__name__}: {error}'
        traceCompilerStep('console-font-detect', False, info['reason'])
        return info


def _setTerminalFontPayload(profile_payload: dict[str, object], desired: str) -> bool:
    changed = False
    settings = terminalFontSettings()
    terminal_size = safeInt(settings.get('windows_terminal_size'), RECOMMENDED_WINDOWS_TERMINAL_FONT_SIZE)
    font_payload = profile_payload.get('font')
    if not isinstance(font_payload, dict):
        font_payload = {}
        profile_payload['font'] = font_payload
        changed = True
    if str(font_payload.get('face', EMPTY_STRING) or EMPTY_STRING).strip() != desired:
        font_payload['face'] = desired
        changed = True
    if safeInt(font_payload.get('size', 0), 0) != terminal_size:
        font_payload['size'] = terminal_size
        changed = True
    # Older Windows Terminal builds and some generated profiles still use the
    # legacy flat fontFace key. Keeping both avoids a false "font changed" trace
    # where the terminal continues to render with the old key.
    if str(profile_payload.get('fontFace', EMPTY_STRING) or EMPTY_STRING).strip() != desired:
        profile_payload['fontFace'] = desired
        changed = True
    if safeInt(profile_payload.get('fontSize', 0), 0) != terminal_size:
        profile_payload['fontSize'] = terminal_size
        changed = True
    return changed


def _verifyWindowsTerminalFontPayload(payload: dict[str, object], desired: str) -> tuple[bool, str]:
    defaults, profiles = _windowsTerminalProfiles(payload)
    default_font = _extractTerminalFont(defaults)
    failures: list[str] = []
    if default_font.lower() != desired.lower():
        failures.append(f'defaults={default_font or "(unset)"}')
    matched = False
    for profile in profiles:
        if _windowsTerminalProfileLooksPowerShell(profile) or _windowsTerminalProfileLooksCurrent(profile):
            matched = True
            font = _extractTerminalFont(profile)
            if font.lower() != desired.lower():
                failures.append(f'{_describeWindowsTerminalProfile(profile)} font={font or "(unset)"}')
    if not matched:
        return (default_font.lower() == desired.lower(), 'no PowerShell profile override found; defaults checked')
    return (not failures, '; '.join(failures) if failures else 'defaults/current PowerShell profiles verified')


def _applyWindowsTerminalFontSetting(desired: str) -> bool:
    desired = str(desired or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
    targets = _windowsTerminalWritableTargets()
    traceCompilerStep('windows-terminal-font-targets', bool(targets), ', '.join(str(path) for path in targets) or '(none)')
    wrote_any = False
    verified_any = False
    for settings_path in targets:
        try:
            before = _fileTraceSnapshot(settings_path)
            payload = _loadJsoncFile(settings_path) if settings_path.exists() else {}
            if not isinstance(payload, dict):
                payload = {}
            profiles = payload.setdefault('profiles', {})
            if not isinstance(profiles, dict):
                profiles = {}
                payload['profiles'] = profiles
            defaults = profiles.setdefault('defaults', {})
            if not isinstance(defaults, dict):
                defaults = {}
                profiles['defaults'] = defaults
            changed = _setTerminalFontPayload(cast(dict[str, object], defaults), desired)
            profile_list = profiles.get('list')
            touched_profiles: list[str] = []
            if isinstance(profile_list, list):
                for profile in profile_list:
                    if isinstance(profile, dict) and (_windowsTerminalProfileLooksPowerShell(profile) or _windowsTerminalProfileLooksCurrent(profile)):
                        profile_dict = cast(dict[str, object], profile)
                        profile_changed = _setTerminalFontPayload(profile_dict, desired)
                        changed = profile_changed or changed
                        touched_profiles.append(_describeWindowsTerminalProfile(profile_dict))
            if changed or not settings_path.exists():
                _writeJsoncFile(settings_path, payload)
                wrote_any = True
            after = _fileTraceSnapshot(settings_path)
            _traceFileReplacement('windows-terminal-font-write', before, after)
            reread = _loadJsoncFile(settings_path)
            verified, detail = _verifyWindowsTerminalFontPayload(reread, desired)
            verified_any = verified_any or verified
            traceCompilerStep('windows-terminal-font-verify', verified, f'path={settings_path} font={desired} changed={changed} profiles={touched_profiles or ["defaults only"]} detail={detail}')
        except Exception as error:
            recordException('start.py:6545', sys.exc_info()[1])
            traceCompilerStep('windows-terminal-font', False, f'{settings_path}: {type(error).__name__}: {error}')
            continue
    if not verified_any:
        print(f'[WARN:font] Windows Terminal settings did not stick for {desired!r}. Magic boxes may remain until the font is installed and the active Windows Terminal profile uses that font.', file=sys.stderr, flush=True)
    return bool(wrote_any or verified_any)


def _registerFontResourceForCurrentSession(font_path: str | Path) -> bool:
    if os.name != 'nt':
        return False
    try:
        import ctypes
        source = str(Path(font_path).resolve())
        added = int(ctypes.windll.gdi32.AddFontResourceW(source))
        HWND_BROADCAST = 0xFFFF
        WM_FONTCHANGE = 0x001D
        SMTO_ABORTIFHUNG = 0x0002
        result = ctypes.c_ulonglong(0)
        try:
            ctypes.windll.user32.SendMessageTimeoutW(HWND_BROADCAST, WM_FONTCHANGE, 0, 0, SMTO_ABORTIFHUNG, 5000, ctypes.byref(result))
        except Exception:
            recordException('start.py:6566', sys.exc_info()[1])
            _traceSwallowedException('start.py:6418', sys.exc_info()[1])
            pass
        ok = added > 0
        traceCompilerStep('font-add-resource', ok, f'path={source} added={added}')
        return ok
    except Exception as error:
        recordException('start.py:6572', sys.exc_info()[1])
        traceCompilerStep('font-add-resource', False, f'{type(error).__name__}: {error}')
        return False


def _readWindowsFontRegistry(font_name: str = RECOMMENDED_TERMINAL_FONT) -> dict[str, object]:
    result: dict[str, object] = {'found': False, 'entries': []}
    if os.name != 'nt':
        return result
    try:
        import winreg  # type: ignore
        targets = [
            (winreg.HKEY_CURRENT_USER, r'SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts', 'HKCU'),
            (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts', 'HKLM'),
        ]
        entries: list[str] = []
        wanted = str(font_name or EMPTY_STRING).lower()
        for hive, key_path, label in targets:
            try:
                with winreg.OpenKey(hive, key_path) as key:
                    index = 0
                    while True:
                        try:
                            name, value, _kind = winreg.EnumValue(key, index)
                        except OSError:
                            recordException('start.py:6596', sys.exc_info()[1])
                            _traceSwallowedException('start.py:6447', sys.exc_info()[1])
                            break
                        index += 1
                        if wanted and wanted in str(name).lower():
                            entries.append(f'{label}:{name}={value}')
            except Exception:
                recordException('start.py:6602', sys.exc_info()[1])
                _traceSwallowedException('start.py:6452', sys.exc_info()[1])
                continue
        result['entries'] = entries
        result['found'] = bool(entries)
    except Exception as error:
        recordException('start.py:6607', sys.exc_info()[1])
        result['error'] = f'{type(error).__name__}: {error}'
    return result


def applyRecommendedConsoleFont(font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
    if os.name != 'nt':
        traceCompilerStep('console-font-apply', False, 'not Windows')
        return False
    desired = str(font_name or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
    before = detectConsoleFontInfo()
    traceCompilerStep('terminal-font-before', True, f"host={before.get('host')} version={before.get('version') or '(unknown)'} font={before.get('font') or '(unset)'} size={before.get('font_size') or '(unknown)'} source={before.get('source') or '(unknown)'} path={before.get('path') or '(none)'}")
    wt_ok = False
    console_live_ok = False
    console_persist_ok = False
    details: list[str] = []
    settings = terminalFontSettings()
    if str(before.get('host') or EMPTY_STRING) == 'windows-terminal' or os.environ.get('WT_SESSION'):
        wt_ok = _applyWindowsTerminalFontSetting(desired)
        details.append(f'Windows Terminal settings={wt_ok} size={settings.get("windows_terminal_size")}')
    else:
        console_width = safeInt(settings.get('console_host_width'), RECOMMENDED_CONSOLE_HOST_FONT_WIDTH)
        console_height = safeInt(settings.get('console_host_height'), RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT)
        active_font_path = bundledTerminalFontPath()
        registered_ok = _registerFontResourceForCurrentSession(active_font_path)
        traceCompilerStep('console-font-register-before-live-set', registered_ok, f'font={desired} path={active_font_path}')
        console_live_ok, console_live_detail = _setConsoleHostLiveFontFace(desired, height=console_height, width=console_width)
        traceCompilerStep('console-font-live-set', console_live_ok, console_live_detail)
        console_persist_ok, console_persist_detail = _persistConsoleHostFontFace(desired, height=console_height, width=console_width)
        traceCompilerStep('console-font-registry', console_persist_ok, console_persist_detail)
        details.append(f'ConsoleHost live={console_live_ok} persist={console_persist_ok} size={console_width}x{console_height}')
    verify = detectConsoleFontInfo()
    current = str(verify.get('font', EMPTY_STRING) or EMPTY_STRING).strip()
    ok = bool(wt_ok or console_live_ok or current.lower() == desired.lower())
    traceCompilerStep('console-font-apply-verify', ok, f"desired={desired} current={current or '(unknown)'} size={verify.get('font_size') or '(unknown)'} host={verify.get('host', EMPTY_STRING)} source={verify.get('source', EMPTY_STRING)} path={verify.get('path', EMPTY_STRING)} detail={' | '.join(details)}")
    if not ok:
        print(f'[WARN:font] Attempted to set terminal font to {desired!r}, but verification still reports {current or "(unknown)"!r}. Windows Terminal may require a new tab/restart; ConsoleHost may be overridden by a shortcut .lnk or profile-specific registry key.', file=sys.stderr, flush=True)
    return ok

def _powershellSingleQuoted(text: str) -> str:
    value = str(text or EMPTY_STRING)
    return "'" + value.replace("'", "''") + "'"


def materializeDefaultFontAliases(report: list[str] | None = None) -> dict[str, Path]:
    result: dict[str, Path] = {'default': BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH, 'default': BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH}
    for label, path in result.items():
        if report is not None:
            report.append(f'{label} canonical font path={path} exists={int(path.exists())} md5={safeFileMd5Hex(path) or "missing"}')
        try: traceFontFileState('font-default-canonical-state', path, label)
        except Exception:
            recordException('start.py:6657', sys.exc_info()[1])
            pass
    return result

def traceDefaultFontSelection(settings: dict[str, object] | None = None, reason: str = 'runtime') -> None:
    try:
        settings = dict(settings or terminalFontSettings())
        materializeDefaultFontAliases()
        selected = Path(str(settings.get('selected_default_otf_path') or EMPTY_STRING)).resolve()
        selected_web = Path(str(settings.get('selected_default_woff2_path') or EMPTY_STRING)).resolve()
        if not selected.exists():
            selected = (BASE_DIR / (DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH if bool(settings.get('colored_font', False)) else DEFAULT_TERMINAL_OTF_RELATIVE_PATH)).resolve()
        if not selected_web.exists():
            selected_web = (BASE_DIR / (DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH if bool(settings.get('colored_font', False)) else DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH)).resolve()
        snapshot = _fileTraceSnapshot(selected)
        digest = str(snapshot.get('md5') or 'missing')
        selected_detail = 'reason={} colored_font={} mode={} face={} file={} web_file={} size={} md5={} mtime={} {}'.format(
            reason,
            int(bool(settings.get('colored_font', False))),
            settings.get('mode'),
            settings.get('face'),
            selected,
            selected_web,
            snapshot.get('size', 0),
            digest,
            snapshot.get('mtime_text', EMPTY_STRING) or '(none)',
            _fontTraceMetricFields(selected),
        )
        if selected.exists():
            traceCompilerStep('font-default-selected', True, selected_detail)
        elif _isOptionalBundledFontPath(selected):
            traceCompilerWarn('font-default-selected', selected_detail + ' optional_font_binary_missing=1 install_or_repair_with_--font --font-install-all')
        else:
            traceCompilerStep('font-default-selected', False, selected_detail)
        traceFontFileState('font-default-selected-state', selected, f'{reason}:selected-default-otf')
        traceFontFileState('font-default-selected-web-state', selected_web, f'{reason}:selected-default-woff2')
    except Exception as error:
        recordException('start.py:6680', sys.exc_info()[1])
        try:
            traceCompilerStep('font-default-selected', False, f'{type(error).__name__}: {error}')
        except Exception:
            recordException('start.py:6683', sys.exc_info()[1])
            _traceSwallowedException('start.py:6531', sys.exc_info()[1])
            pass


def traceRuntimeTerminalFontSnapshot(reason: str = 'runtime') -> dict[str, object]:
    """Trace the active terminal/Python host font and the installed Trio font MD5 state.

    Python itself does not choose a console font; the visible interpreter font is
    inherited from the terminal host (Windows Terminal, ConsoleHost, VS Code, etc.).
    This trace names both the Python executable and the host font so the logs show
    exactly what screen/font path is being debugged.
    """
    snapshot: dict[str, object] = {}
    try:
        settings = terminalFontSettings()
        traceTerminalFontBundleState(reason)
        terminal_info = detectConsoleFontInfo()
        font_path = Path(str(settings.get('font_path') or EMPTY_STRING)).resolve()
        desired_face = str(settings.get('face') or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        installed = _detectFontInstalled(font_path, desired_face)
        snapshot = {
            'reason': reason,
            'python_executable': str(sys.executable or EMPTY_STRING),
            'python_inherits_terminal_font': True,
            'terminal_info': terminal_info,
            'desired_face': desired_face,
            'font_path': str(font_path),
            'font_md5': safeFileMd5Hex(font_path),
            'installed': installed,
        }
        traceCompilerStep(
            'terminal-current-font-snapshot',
            True,
            f'reason={reason} python={snapshot["python_executable"]} python_font=inherited-from-terminal host={terminal_info.get("host")} current_font={terminal_info.get("font") or "(unset)"} current_size={terminal_info.get("font_size") or "(unknown)"} source={terminal_info.get("source") or "(unknown)"} path={terminal_info.get("path") or "(none)"} desired={desired_face} desired_path={font_path} desired_md5={snapshot["font_md5"] or "(none)"} installed_md5_match={installed.get("md5_match")} installed_paths={installed.get("paths") or []}',
        )
        traceFontFileState('terminal-current-desired-font-file', font_path, f'{reason}:desired-terminal-font')
    except Exception as error:
        recordException('start.py:6720', sys.exc_info()[1])
        traceCompilerStep('terminal-current-font-snapshot', False, f'{type(error).__name__}: {error}')
        snapshot = {'reason': reason, 'error': f'{type(error).__name__}: {error}'}
    return snapshot


def _materializeBundledTerminalFonts() -> None:
    try:
        materializeDefaultFontAliases()
        for label, path in (('font-materialize-terminal', BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH), ('font-materialize-color', BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH)):
            detail = f'{path} md5={safeFileMd5Hex(path) or "missing"}'
            if path.exists():
                traceCompilerStep(label, True, detail)
            elif _isOptionalBundledFontPath(path):
                traceCompilerWarn(label, detail + ' optional_font_binary_missing=1 install_or_repair_with_--font --font-install-all')
            else:
                traceCompilerStep(label, False, detail)
    except Exception as error:
        recordException('start.py:6731', sys.exc_info()[1])
        try: traceCompilerStep('font-materialize-terminal', False, f'{type(error).__name__}: {error}')
        except Exception:
            recordException('start.py:6733', sys.exc_info()[1])
            pass

def bundledTerminalFontPath() -> Path:
    _materializeBundledTerminalFonts()
    settings = terminalFontSettings()
    configured_path = settings.get('font_path')
    if isinstance(configured_path, Path):
        target = configured_path.resolve()
    else:
        target = Path(str(configured_path or (BASE_DIR / BUNDLED_TERMINAL_FONT_RELATIVE_PATH))).resolve()
    if not target.exists():
        fallback = (BASE_DIR / BUNDLED_TERMINAL_FONT_RELATIVE_PATH).resolve()
        if fallback.exists():
            print(f'[WARN:font-config] configured terminal font path is missing: {target}; falling back to {fallback}', file=sys.stderr, flush=True)
        else:
            print(f'[WARN:font-config] terminal font binary missing: {target}; fallback also missing: {fallback}; continuing with host default font until --font/--font-install-all repairs it.', file=sys.stderr, flush=True)
        return fallback
    return target


def _fontRegistryValueName(font_path: str | Path, font_name: str = RECOMMENDED_TERMINAL_FONT) -> str:
    extension = str(Path(font_path).suffix or EMPTY_STRING).strip().lower()
    label = 'OpenType' if extension == '.otf' else 'TrueType'
    return f'{str(font_name or RECOMMENDED_TERMINAL_FONT).strip()} ({label})'


def _fileTraceSnapshot(path_value: str | Path) -> dict[str, object]:
    target = Path(path_value)
    snapshot: dict[str, object] = {
        'path': str(target),
        'exists': False,
        'md5': EMPTY_STRING,
        'mtime_epoch': 0.0,
        'mtime_text': EMPTY_STRING,
        'size': 0,
    }
    try:
        if not target.exists() or not target.is_file():
            return snapshot
        stat = target.stat()
        snapshot['exists'] = True
        snapshot['size'] = int(getattr(stat, 'st_size', 0) or 0)
        snapshot['mtime_epoch'] = float(getattr(stat, 'st_mtime', 0.0) or 0.0)
        if float(snapshot['mtime_epoch']) > 0:
            snapshot['mtime_text'] = datetime.datetime.fromtimestamp(float(snapshot['mtime_epoch'])).isoformat(sep=' ', timespec='microseconds')
        snapshot['md5'] = safeFileMd5Hex(target)
    except Exception:
        recordException('start.py:6777', sys.exc_info()[1])
        return snapshot
    return snapshot


def _traceFileReplacement(step: str, before: dict[str, object], after: dict[str, object]) -> None:
    changed = bool(before.get('md5') != after.get('md5') or before.get('mtime_epoch') != after.get('mtime_epoch') or before.get('exists') != after.get('exists'))
    detail = (
        f"path={after.get('path', before.get('path', EMPTY_STRING))} "
        f"changed={changed} before_md5={before.get('md5', EMPTY_STRING) or '(none)'} after_md5={after.get('md5', EMPTY_STRING) or '(none)'} "
        f"before_mtime={before.get('mtime_text', EMPTY_STRING) or '(none)'} after_mtime={after.get('mtime_text', EMPTY_STRING) or '(none)'}"
    )
    traceCompilerStep(step, True, detail)


def _fontTraceMetricFields(path_value: str | Path) -> str:
    target = Path(path_value)
    try:
        if not target.exists() or not target.is_file():
            return 'metrics=(missing)'
        data = _fontMetricSummary(target)
        wanted = [
            'head.unitsPerEm',
            'head.bbox',
            'hhea.ascent',
            'hhea.descent',
            'hhea.lineGap',
            'hhea.advanceWidthMax',
            'OS/2.xAvgCharWidth',
            'OS/2.sTypoAscender',
            'OS/2.sTypoDescender',
            'OS/2.sTypoLineGap',
            'OS/2.usWinAscent',
            'OS/2.usWinDescent',
            'hmtx.advance.min',
            'hmtx.advance.max',
            'hmtx.advance.unique',
            'hmtx.lsb.min',
            'hmtx.lsb.max',
        ]
        return ' '.join(f'{key}={data.get(key, EMPTY_STRING)}' for key in wanted)
    except Exception as error:
        recordException('start.py:6818', sys.exc_info()[1])
        return f'metrics_error={type(error).__name__}: {error}'



def _isOptionalBundledFontPath(path_value: str | Path) -> bool:
    try:
        target = Path(path_value).resolve()
        bundled_names = {
            DEFAULT_TERMINAL_OTF_RELATIVE_PATH.name,
            DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH.name,
            DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH.name,
            DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH.name,
            DEFAULT_TERMINAL_WOLF2_RELATIVE_PATH.name,
            DEFAULT_TERMINAL_COLOR_WOLF2_RELATIVE_PATH.name,
        }
        try:
            rel_parts = target.relative_to(BASE_DIR).parts
        except ValueError:  # swallow-ok: optional font path may be outside BASE_DIR
            return False
        return len(rel_parts) >= 2 and rel_parts[0] == 'fonts' and target.name in bundled_names
    except Exception:
        recordException('start.py:optional-bundled-font-path', sys.exc_info()[1])
        return False


def traceCompilerWarn(step: str, detail: str = EMPTY_STRING) -> None:
    suffix = f' {detail}' if str(detail or EMPTY_STRING).strip() else EMPTY_STRING
    try:
        print(f'[TRACE:compiler] {step} WARN{suffix}', flush=True)
    except Exception:
        recordException('start.py:traceCompilerWarn', sys.exc_info()[1])
        _traceSwallowedException('start.py:traceCompilerWarn', sys.exc_info()[1])

def traceFontFileState(step: str, path_value: str | Path, label: str = EMPTY_STRING, expected_md5: str = EMPTY_STRING) -> dict[str, object]:
    snapshot = _fileTraceSnapshot(path_value)
    target = Path(path_value)
    md5 = str(snapshot.get('md5') or EMPTY_STRING)
    exists = bool(snapshot.get('exists'))
    expected = str(expected_md5 or EMPTY_STRING).strip()
    match_text = 'unknown'
    if expected:
        match_text = str(md5 == expected)
    detail = (
        f"label={label or target.name} path={target} exists={exists} size={snapshot.get('size', 0)} "
        f"md5={md5 or '(none)'} expected_md5={expected or '(none)'} md5_match={match_text} "
        f"mtime={snapshot.get('mtime_text', EMPTY_STRING) or '(none)'} "
        f"{_fontTraceMetricFields(target)}"
    )
    if exists:
        traceCompilerStep(step, True, detail)
    elif _isOptionalBundledFontPath(target):
        traceCompilerWarn(step, detail + ' optional_font_binary_missing=1 install_or_repair_with_--font --font-install-all')
    else:
        traceCompilerStep(step, False, detail)
    return snapshot


def traceTerminalFontBundleState(reason: str = 'runtime') -> None:
    try:
        settings = terminalFontSettings()
    except Exception:
        recordException('start.py:6844', sys.exc_info()[1])
        settings = {}
    try:
        materializeDefaultFontAliases()
        active_default = BASE_DIR / (DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH if bool(settings.get('colored_font', False)) else DEFAULT_TERMINAL_OTF_RELATIVE_PATH)
        active_default_web = BASE_DIR / (DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH if bool(settings.get('colored_font', False)) else DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH)
        active_source = BASE_DIR / (BUNDLED_TERMINAL_COLOR_FONT_RELATIVE_PATH if bool(settings.get('colored_font', False)) else BUNDLED_TERMINAL_FONT_RELATIVE_PATH)
        mono_otf = BASE_DIR / BUNDLED_TERMINAL_FONT_RELATIVE_PATH
        mono_woff2 = BASE_DIR / DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH
        mono_default_otf = BASE_DIR / DEFAULT_TERMINAL_OTF_RELATIVE_PATH
        mono_default = BASE_DIR / DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH
        mono_wolf = BASE_DIR / DEFAULT_TERMINAL_WOLF2_RELATIVE_PATH
        color_otf = BASE_DIR / BUNDLED_TERMINAL_COLOR_FONT_RELATIVE_PATH
        color_woff2 = BASE_DIR / DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH
        color_default_otf = BASE_DIR / DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH
        color_default = BASE_DIR / DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH
        color_wolf = BASE_DIR / DEFAULT_TERMINAL_COLOR_WOLF2_RELATIVE_PATH
        states: dict[str, str] = {}
        for label, path, expected in [
            ('active-source', active_source, EMPTY_STRING),
            ('active-default-otf', active_default, safeFileMd5Hex(color_otf if bool(settings.get('colored_font', False)) else mono_otf)),
            ('active-default-woff2-optional', active_default_web, safeFileMd5Hex(active_default_web)),
            ('mono-otf', mono_otf, EMPTY_STRING),
            ('mono-default-otf', mono_default_otf, safeFileMd5Hex(mono_otf)),
            ('mono-woff2', mono_woff2, EMPTY_STRING),
            ('mono-default-woff2', mono_default, safeFileMd5Hex(mono_woff2)),
            ('mono-default-wolf2', mono_wolf, safeFileMd5Hex(mono_woff2)),
            ('color-otf', color_otf, EMPTY_STRING),
            ('color-default-otf', color_default_otf, safeFileMd5Hex(color_otf)),
            ('color-woff2', color_woff2, EMPTY_STRING),
            ('color-default-woff2', color_default, safeFileMd5Hex(color_woff2)),
            ('color-default-wolf2', color_wolf, safeFileMd5Hex(color_woff2)),
        ]:
            snapshot = traceFontFileState('font-bundle-file-state', path, f'{reason}:{label}', expected)
            states[label] = str(snapshot.get('md5') or EMPTY_STRING).strip()
        mono_base_ok = bool(states.get('mono-otf') and states.get('mono-default-otf'))
        mono_web_ok = bool(states.get('mono-woff2') and states.get('mono-default-woff2') and states.get('mono-default-wolf2'))
        color_base_ok = bool(states.get('color-otf') and states.get('color-default-otf'))
        color_web_ok = bool(states.get('color-woff2') and states.get('color-default-woff2') and states.get('color-default-wolf2'))
        mono_alias_ok = bool(mono_base_ok and states.get('mono-otf') == states.get('mono-default-otf') and mono_web_ok and states.get('mono-woff2') == states.get('mono-default-woff2') == states.get('mono-default-wolf2'))
        color_alias_ok = bool(color_base_ok and states.get('color-otf') == states.get('color-default-otf') and color_web_ok and states.get('color-woff2') == states.get('color-default-woff2') == states.get('color-default-wolf2'))
        missing_font_binary = any(not value for value in states.values())
        if missing_font_binary:
            traceCompilerWarn('font-bundle-md5-compare', f'reason={reason} active_source={active_source} active_default={active_default} optional_font_binary_missing=1 md5s={states} install_or_repair_with_--font --font-install-all')
        else:
            traceCompilerStep(
                'font-bundle-md5-compare',
                bool(mono_alias_ok and color_alias_ok),
                f'reason={reason} active_source={active_source} active_default={active_default} mono_alias_ok={mono_alias_ok} color_alias_ok={color_alias_ok} md5s={states}',
            )
    except Exception as error:
        recordException('start.py:6886', sys.exc_info()[1])
        traceCompilerStep('font-bundle-state', False, f'{type(error).__name__}: {error}')


def _windowsFontInstallTargets(font_path: str | Path) -> list[Path]:
    if os.name != 'nt':
        return []
    file_name = Path(font_path).name
    local_appdata = Path(os.environ.get('LOCALAPPDATA') or (Path.home() / 'AppData/Local'))
    windows_dir = Path(os.environ.get('WINDIR') or r'C:\Windows')
    return [
        (windows_dir / 'Fonts' / file_name).resolve(),
        (local_appdata / 'Microsoft/Windows/Fonts' / file_name).resolve(),
    ]



def _detectFontInstalled(font_path: str | Path, font_name: str = RECOMMENDED_TERMINAL_FONT) -> dict[str, object]:
    source = Path(font_path).resolve()
    source_md5 = safeFileMd5Hex(source)
    if os.name != 'nt':
        traceCompilerStep('font-installed-detect', True, f'source={source} source_md5={source_md5 or "(none)"} windows_font_install_check=skipped reason=non-windows')
        return {'installed': False, 'ok': False, 'paths': [], 'registry': [], 'source_md5': source_md5, 'md5_match': False, 'md5_match_paths': [], 'stale': False, 'stale_paths': [], 'targets': [], 'skipped': 'non-windows'}
    matches: list[str] = []
    matching_md5_paths: list[str] = []
    stale_paths: list[str] = []
    target_details: list[str] = []
    try:
        traceFontFileState('font-install-source-state', source, 'install-source')
    except Exception:
        recordException('start.py:6915', sys.exc_info()[1])
        _traceSwallowedException('start.py:6761', sys.exc_info()[1])
        pass
    for candidate in _windowsFontInstallTargets(source):
        try:
            snapshot = traceFontFileState('font-installed-target-state', candidate, 'installed-target', source_md5)
            exists = bool(snapshot.get('exists'))
            md5 = str(snapshot.get('md5') or EMPTY_STRING)
            if exists:
                matches.append(str(candidate))
                target_details.append(f'{candidate}|md5={md5 or "(none)"}|match={bool(source_md5 and md5 == source_md5)}')
                if source_md5 and md5 == source_md5:
                    matching_md5_paths.append(str(candidate))
                else:
                    stale_paths.append(str(candidate))
        except Exception as error:
            recordException('start.py:6930', sys.exc_info()[1])
            target_details.append(f'{candidate}|error={type(error).__name__}: {error}')
    registry = _readWindowsFontRegistry(font_name)
    entries = list(cast(list[str], registry.get('entries', []))) if isinstance(registry.get('entries'), list) else []
    installed = bool(matches or registry.get('found'))
    md5_match = bool(matching_md5_paths)
    stale = bool(stale_paths)
    ok = bool(installed and (md5_match or not source_md5))
    traceCompilerStep(
        'font-installed-detect',
        installed,
        f'source={source} source_md5={source_md5 or "(none)"} paths={matches or []} md5_match={md5_match} md5_match_paths={matching_md5_paths or []} stale={stale} stale_paths={stale_paths or []} registry={entries or []} targets={target_details or []}',
    )
    if installed and source_md5 and not md5_match:
        traceCompilerStep('font-installed-md5-mismatch', False, f'bundled repaired font is not the installed font; source_md5={source_md5} installed_paths={matches or []} stale_paths={stale_paths or []} registry={entries or []}')
    return {'installed': installed, 'ok': ok, 'paths': matches, 'registry': entries, 'source_md5': source_md5, 'md5_match': md5_match, 'md5_match_paths': matching_md5_paths, 'stale': stale, 'stale_paths': stale_paths, 'targets': target_details}


def _installFontForCurrentUser(font_path: str | Path, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
    if os.name != 'nt':
        return False
    try:
        import winreg  # type: ignore
        source = Path(font_path).resolve()
        if not source.exists():
            traceCompilerStep('font-user-install', False, f'missing source={source}')
            return False
        traceFontFileState('font-user-install-source', source, 'per-user-install-source')
        local_appdata = Path(os.environ.get('LOCALAPPDATA') or (Path.home() / 'AppData/Local'))
        user_fonts_dir = (local_appdata / 'Microsoft/Windows/Fonts').resolve()
        user_fonts_dir.mkdir(parents=True, exist_ok=True)
        destination = user_fonts_dir / source.name
        before = traceFontFileState('font-user-copy-before', destination, 'per-user-destination-before', safeFileMd5Hex(source))
        File(source).copyTo(destination)
        after = traceFontFileState('font-user-copy-after', destination, 'per-user-destination-after', safeFileMd5Hex(source))
        _traceFileReplacement('font-user-copy', before, after)
        registry_name = _fontRegistryValueName(source, font_name)
        with winreg.CreateKey(winreg.HKEY_CURRENT_USER, r'SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts') as key:
            winreg.SetValueEx(key, registry_name, 0, winreg.REG_SZ, destination.name)
        traceCompilerStep('font-user-registry-write', True, f'HKCU Fonts {registry_name!r}={destination.name!r}')
        _registerFontResourceForCurrentSession(destination)
        font_ok = applyRecommendedConsoleFont(font_name)
        installed = _detectFontInstalled(destination, font_name)
        ok = bool(font_ok and installed.get('installed') and installed.get('md5_match'))
        traceCompilerStep('font-user-install', ok, f'font_ok={font_ok} installed={installed}')
        if not ok:
            print(f'[WARN:font] Font install attempted but verification did not stick: {font_name!r}. See [TRACE:font-*] and [TRACE:windows-terminal-font-*] lines above.', file=sys.stderr, flush=True)
        return ok
    except Exception as error:
        recordException('start.py:6978', sys.exc_info()[1])
        traceCompilerStep('font-user-install', False, f'{type(error).__name__}: {error}')
        return False


def _attemptWindowsElevatedFontInstallAndSwitch(font_path: str | Path, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
    if os.name != 'nt':
        return False
    powershell = shutil.which('powershell.exe') or shutil.which('powershell') or shutil.which('pwsh.exe') or shutil.which('pwsh')
    if not powershell:
        traceCompilerStep('font-elevation-shell', False, 'PowerShell executable not found')
        return False
    source = Path(font_path).resolve()
    if not source.exists():
        traceCompilerStep('font-elevation-source', False, f'missing={source}')
        return False
    settings_candidates = [str(path) for path in _windowsTerminalWritableTargets()]
    # Elevation is only for the all-users font copy/registry path.  Windows
    # Terminal settings live under LOCALAPPDATA and should be user-writable.
    script_lines = [
        "$ErrorActionPreference = 'Stop'",
        f"$fontPath = {_powershellSingleQuoted(str(source))}",
        f"$fontName = {_powershellSingleQuoted(str(font_name or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT)}",
        "$fontFileName = [System.IO.Path]::GetFileName($fontPath)",
        "$fontExtension = [System.IO.Path]::GetExtension($fontFileName).ToLowerInvariant()",
        "$fontRegistryName = if ($fontExtension -eq '.otf') { $fontName + ' (OpenType)' } else { $fontName + ' (TrueType)' }",
        "$windowsFonts = Join-Path $env:WINDIR 'Fonts'",
        "$destination = Join-Path $windowsFonts $fontFileName",
        "Copy-Item -LiteralPath $fontPath -Destination $destination -Force",
        "New-Item -Path 'HKLM:\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Fonts' -Force | Out-Null",
        "New-ItemProperty -Path 'HKLM:\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Fonts' -Name $fontRegistryName -Value $fontFileName -PropertyType String -Force | Out-Null",
        "Add-Type -Namespace Win32 -Name Gdi -MemberDefinition '[DllImport(\"gdi32.dll\", SetLastError=true, CharSet=CharSet.Unicode)] public static extern int AddFontResource(string lpFileName);'",
        "[void][Win32.Gdi]::AddFontResource($destination)",
        "New-Item -Path 'HKCU:\\Console' -Force | Out-Null",
        "New-ItemProperty -Path 'HKCU:\\Console' -Name 'FaceName' -Value $fontName -PropertyType String -Force | Out-Null",
        "$settingsCandidates = @(" + ','.join(_powershellSingleQuoted(value) for value in settings_candidates) + ")",
        "foreach ($candidate in $settingsCandidates) {",
        "  if ([string]::IsNullOrWhiteSpace($candidate)) { continue }",
        "  try {",
        "    $parent = Split-Path -Parent $candidate",
        "    if (-not (Test-Path -LiteralPath $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }",
        "    $json = @{}",
        "    if (Test-Path -LiteralPath $candidate) {",
        "      $raw = Get-Content -LiteralPath $candidate -Raw -ErrorAction Stop",
        "      if (-not [string]::IsNullOrWhiteSpace($raw)) { $json = $raw | ConvertFrom-Json -AsHashtable }",
        "    }",
        "    if ($null -eq $json) { $json = @{} }",
        "    if (-not ($json.ContainsKey('profiles')) -or -not ($json['profiles'] -is [System.Collections.IDictionary])) { $json['profiles'] = @{} }",
        "    if (-not ($json['profiles'].ContainsKey('defaults')) -or -not ($json['profiles']['defaults'] -is [System.Collections.IDictionary])) { $json['profiles']['defaults'] = @{} }",
        "    if (-not ($json['profiles']['defaults'].ContainsKey('font')) -or -not ($json['profiles']['defaults']['font'] -is [System.Collections.IDictionary])) { $json['profiles']['defaults']['font'] = @{} }",
        "    $json['profiles']['defaults']['font']['face'] = $fontName",
        "    $json['profiles']['defaults']['fontFace'] = $fontName",
        "    if ($json['profiles'].ContainsKey('list') -and $json['profiles']['list'] -is [System.Collections.IEnumerable]) {",
        "      foreach ($profile in $json['profiles']['list']) {",
        "        $haystack = (($profile['name'], $profile['source'], $profile['commandline'], $profile['guid']) -join ' ').ToLowerInvariant()",
        "        if ($haystack.Contains('powershell') -or $haystack.Contains('pwsh')) {",
        "          if (-not ($profile.ContainsKey('font')) -or -not ($profile['font'] -is [System.Collections.IDictionary])) { $profile['font'] = @{} }",
        "          $profile['font']['face'] = $fontName",
        "          $profile['fontFace'] = $fontName",
        "        }",
        "      }",
        "    }",
        "    $json | ConvertTo-Json -Depth 64 | Set-Content -LiteralPath $candidate -Encoding utf8",
        "  } catch { Write-Host ('[WARN:font-elevation-settings] ' + $candidate + ' ' + $_.Exception.Message) }",
        "}",
        'exit 0',
    ]
    temp_script = Path(tempfile.mkdtemp(prefix='flatline_font_elevate_')) / 'install_flatline_font.ps1'
    File(temp_script).writeText('\n'.join(script_lines) + '\n')
    launcher_script = (
        "$ErrorActionPreference='Stop';"
        f"$process=Start-Process -FilePath {_powershellSingleQuoted(powershell)} -ArgumentList @('-NoProfile','-ExecutionPolicy','Bypass','-File',{_powershellSingleQuoted(str(temp_script))}) -Verb RunAs -Wait -PassThru;"
        "exit [int]$process.ExitCode"
    )
    ok = StartDependencyRegistry.runCommand([powershell, '-NoProfile', '-NonInteractive', '-Command', launcher_script], label='windows elevated font install', timeout=300)
    traceCompilerStep('font-elevation', ok, f'font={font_name} file={source.name} script={temp_script}')
    if ok:
        applyRecommendedConsoleFont(font_name)
    return ok

def _currentCommandTargets() -> tuple[str, str]:
    python_executable = str(sys.executable or EMPTY_STRING).strip()
    script_path = str(Path(__file__).resolve())
    return python_executable, script_path


class Terminal:
    """
    Represents the terminal host running the current process.

    Attributes
    ----------
    host : str
        Identifier for the terminal type, e.g. 'windows-terminal', 'console-host', 'unknown'.
    path : str
        Full filesystem path to the terminal executable (best-effort, may be empty).
    pid : int | None
        PID of the terminal host process (best-effort, may be None).
    version : str
        Version string of the terminal executable if detectable, else ''.
    features : list[str]
        Tags describing what this terminal supports, e.g.
        ['ansi', 'truecolor', 'unicode', 'braille', 'wt-session', 'ps7'].
    """

    # Known feature sets per host
    _HOST_FEATURES: dict[str, list[str]] = {
        'windows-terminal': ['ansi', 'truecolor', 'unicode', 'braille', 'wt-session', 'resize', 'tabs'],
        'console-host':     ['ansi', 'unicode', 'braille'],
        'unknown':          [],
    }

    def __init__(self) -> None:
        self._info: dict[str, object] = detectConsoleFontInfo()
        self.host: str = str(self._info.get('host') or 'unknown').strip()
        self.path: str = EMPTY_STRING
        self.pid: int | None = None
        self.version: str = EMPTY_STRING
        self.features: list[str] = list(self._HOST_FEATURES.get(self.host, []))
        self._detect_process()
        self._detect_version()
        self._detect_extra_features()

    # ------------------------------------------------------------------
    # Properties
    # ------------------------------------------------------------------

    @property
    def font(self) -> str:
        """Current console font name (re-reads from OS each call)."""
        return str(detectConsoleFontInfo().get('font') or EMPTY_STRING).strip()

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def installFont(self, font_path: str | Path | None = None, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
        """Install a bundled or explicit font before changing the terminal face."""
        source = Path(font_path).resolve() if font_path else bundledTerminalFontPath()
        desired = str(font_name or bundledTerminalFontFace(source) or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        return Font(source).installFont(desired)

    def changeFont(self, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
        """
        Apply *font_name* to the current terminal.
        Returns True on success. Registers the active default font before switching when possible.
        """
        desired = str(font_name or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        self.installFont(bundledTerminalFontPath(), desired)
        return applyRecommendedConsoleFont(desired)

    def upgrade(self) -> bool:
        """
        Install the bundled default.otf font (user-level, no elevation needed) and
        switch the terminal to use it.  Falls back to an elevated install if the user-level
        copy fails.  Returns True if the font is applied.
        """
        font_path = bundledTerminalFontPath()
        if not font_path.exists():
            traceCompilerStep('terminal-upgrade', False, f'bundled font not found: {font_path}')
            return False
        ok = _installFontForCurrentUser(font_path)
        if not ok:
            traceCompilerStep('terminal-upgrade', False, 'user-level install failed; attempting elevation')
            ok = _attemptWindowsElevatedFontInstallAndSwitch(font_path)
        traceCompilerStep('terminal-upgrade', ok, f'font={RECOMMENDED_TERMINAL_FONT} path={font_path}')
        return ok

    def describe(self) -> str:
        """One-line human-readable summary."""
        parts = [f'host={self.host}']
        if self.path:
            parts.append(f'path={self.path}')
        if self.pid is not None:
            parts.append(f'pid={self.pid}')
        if self.version:
            parts.append(f'version={self.version}')
        parts.append(f'font={self.font or "(unset)"}')
        parts.append(f'features=[{", ".join(self.features)}]')
        return '  '.join(parts)

    # ------------------------------------------------------------------
    # Internal detection helpers
    # ------------------------------------------------------------------

    def _detect_process(self) -> None:
        """Walk the process tree to find the terminal host PID and path."""
        if os.name != 'nt':
            return
        try:
            import ctypes, ctypes.wintypes
            TH32CS_SNAPPROCESS = 0x00000002
            _TERMINAL_EXE_NAMES = {
                'wt.exe', 'windowsterminal.exe',
                'pwsh.exe', 'powershell.exe',
                'conhost.exe', 'cmd.exe',
            }

            class _PROCESSENTRY32(ctypes.Structure):
                _fields_ = [
                    ('dwSize',              ctypes.wintypes.DWORD),
                    ('cntUsage',            ctypes.wintypes.DWORD),
                    ('th32ProcessID',       ctypes.wintypes.DWORD),
                    ('th32DefaultHeapID',   ctypes.POINTER(ctypes.c_ulong)),
                    ('th32ModuleID',        ctypes.wintypes.DWORD),
                    ('cntWorkerProcesss',          ctypes.wintypes.DWORD),
                    ('th32ParentProcessID', ctypes.wintypes.DWORD),
                    ('pcPriClassBase',      ctypes.c_long),
                    ('dwFlags',             ctypes.wintypes.DWORD),
                    ('szExeFile',           ctypes.c_char * 260),
                ]

            snap = ctypes.windll.kernel32.CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0)
            parent_map: dict[int, tuple[int, str]] = {}
            entry = _PROCESSENTRY32()
            entry.dwSize = ctypes.sizeof(_PROCESSENTRY32)
            if ctypes.windll.kernel32.Process32First(snap, ctypes.byref(entry)):
                while True:
                    pid = int(entry.th32ProcessID)
                    ppid = int(entry.th32ParentProcessID)
                    name = entry.szExeFile.decode('utf-8', errors='replace').lower()
                    parent_map[pid] = (ppid, name)
                    if not ctypes.windll.kernel32.Process32Next(snap, ctypes.byref(entry)):
                        break
            ctypes.windll.kernel32.CloseHandle(snap)

            # Collect all ancestors, pick the best terminal match.
            # Priority: wt.exe/windowsterminal.exe > conhost.exe > pwsh.exe/powershell.exe > cmd.exe
            _PRIORITY = {
                'wt.exe': 0, 'windowsterminal.exe': 0,
                'conhost.exe': 1,
                'pwsh.exe': 2, 'powershell.exe': 2,
                'cmd.exe': 3,
            }
            candidates: list[tuple[int, int, str]] = []  # (priority, pid, exe_name)
            walk_pid = os.getpid()
            seen: set[int] = set()
            for _ in range(15):
                if walk_pid in seen or walk_pid not in parent_map:
                    break
                seen.add(walk_pid)
                ppid, pname = parent_map[walk_pid]
                if pname in _PRIORITY:
                    candidates.append((_PRIORITY[pname], ppid, pname))
                walk_pid = ppid
            if candidates:
                candidates.sort(key=lambda x: x[0])
                _, best_pid, _ = candidates[0]
                self.pid = best_pid
                PROCESS_QUERY_LIMITED_INFORMATION = 0x1000
                h = ctypes.windll.kernel32.OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, False, best_pid)
                if h:
                    buf = ctypes.create_unicode_buffer(32768)
                    sz = ctypes.wintypes.DWORD(32768)
                    if ctypes.windll.kernel32.QueryFullProcessImageNameW(h, 0, buf, ctypes.byref(sz)):
                        self.path = buf.value
                    ctypes.windll.kernel32.CloseHandle(h)
        except Exception:
            recordException('start.py:7227', sys.exc_info()[1])
            _traceSwallowedException('start.py:7072', sys.exc_info()[1])
            pass

    def _detect_version(self) -> None:
        """Read the terminal executable version from its file metadata."""
        if not self.path or not Path(self.path).exists():
            return
        if os.name != 'nt':
            return
        try:
            import ctypes
            size = ctypes.windll.version.GetFileVersionInfoSizeW(self.path, None)
            if not size:
                return
            buf = ctypes.create_string_buffer(size)
            if not ctypes.windll.version.GetFileVersionInfoW(self.path, 0, size, buf):
                return
            sub_block = ctypes.create_unicode_buffer('\\')
            p_info = ctypes.c_void_p()
            n = ctypes.c_uint()
            if not ctypes.windll.version.VerQueryValueW(buf, sub_block, ctypes.byref(p_info), ctypes.byref(n)):
                return
            class _VS_FIXEDFILEINFO(ctypes.Structure):
                _fields_ = [
                    ('dwSignature',        ctypes.c_uint32),
                    ('dwStrucVersion',     ctypes.c_uint32),
                    ('dwFileVersionMS',    ctypes.c_uint32),
                    ('dwFileVersionLS',    ctypes.c_uint32),
                    ('dwProductVersionMS', ctypes.c_uint32),
                    ('dwProductVersionLS', ctypes.c_uint32),
                    ('dwFileFlagsMask',    ctypes.c_uint32),
                    ('dwFileFlags',        ctypes.c_uint32),
                    ('dwFileOS',           ctypes.c_uint32),
                    ('dwFileType',         ctypes.c_uint32),
                    ('dwFileSubtype',      ctypes.c_uint32),
                    ('dwFileDateMS',       ctypes.c_uint32),
                    ('dwFileDateLS',       ctypes.c_uint32),
                ]
            info = ctypes.cast(p_info, ctypes.POINTER(_VS_FIXEDFILEINFO)).contents
            ms = info.dwFileVersionMS
            ls = info.dwFileVersionLS
            self.version = f'{ms >> 16}.{ms & 0xFFFF}.{ls >> 16}.{ls & 0xFFFF}'
        except Exception:
            recordException('start.py:7270', sys.exc_info()[1])
            _traceSwallowedException('start.py:7114', sys.exc_info()[1])
            pass

    def _detect_extra_features(self) -> None:
        """Add feature tags based on environment variables and runtime detection."""
        if os.environ.get('WT_SESSION'):
            if 'wt-session' not in self.features:
                self.features.append('wt-session')
        if os.environ.get('TERM_PROGRAM') == 'vscode':
            if 'vscode' not in self.features:
                self.features.append('vscode')
        ps_path = shutil.which('pwsh') or shutil.which('pwsh.exe')
        if ps_path:
            if 'ps7' not in self.features:
                self.features.append('ps7')
        if consoleSupportsAnsi():
            if 'ansi' not in self.features:
                self.features.append('ansi')


def _filteredRelaunchArgs(argv: list[str] | None = None) -> list[str]:
    filtered = []
    for token in list(argv or []):
        lowered = str(token or EMPTY_STRING).strip().lower()
        if lowered in {FONT_CHANGE_YES_FLAG.lower(), FONT_RELAUNCH_FLAG.lower()}:
            continue
        filtered.append(str(token or EMPTY_STRING))
    return filtered


def _relaunchSelfInNewPowerShell(argv: list[str] | None = None) -> bool:
    if os.name != 'nt':
        return False
    powershell = shutil.which('pwsh.exe') or shutil.which('pwsh') or shutil.which('powershell.exe') or shutil.which('powershell')
    python_executable, script_path = _currentCommandTargets()
    if not powershell or not python_executable or not script_path:
        traceCompilerStep('font-relaunch-shell', False, 'missing PowerShell or Python launcher')
        return False
    relaunch_args = _filteredRelaunchArgs(argv) + [FONT_RELAUNCH_FLAG]
    command_body = '& ' + ' '.join([_powershellSingleQuoted(python_executable), _powershellSingleQuoted(script_path)] + [_powershellSingleQuoted(item) for item in relaunch_args])
    try:
        child = launcherStartProcess([powershell, '-NoLogo', '-NoExit', '-Command', command_body], cwd=str(BASE_DIR))
        traceCompilerStep('font-relaunch', True, f'pid={getattr(child, "pid", 0)} shell={powershell}')
        return True
    except Exception as error:
        recordException('start.py:7315', sys.exc_info()[1])
        traceCompilerStep('font-relaunch', False, f'{type(error).__name__}: {error}')
        return False


def _terminateCurrentWindowForFontRelaunch() -> None:
    try:
        launcherStartProcess(['taskkill', '/F', '/PID', str(os.getpid())], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        traceCompilerStep('font-taskkill-self', True, f'pid={os.getpid()}')
    except Exception as error:
        recordException('start.py:7324', sys.exc_info()[1])
        traceCompilerStep('font-taskkill-self', False, f'{type(error).__name__}: {error}')


def _renderBrailleProgressBar(frame_index: int, width: int = 24) -> str:
    width_value = max(8, int(width or 8))
    filled = int(((frame_index % (width_value + 1)) / float(width_value)) * width_value)
    cells = []
    for index in range(width_value):
        if index < filled:
            cells.append('⣿')
        elif index == filled:
            cells.append('⣄')
        else:
            cells.append('⠈')
    return ''.join(cells)


def _fontPreviewRows(frame_index: int | None = None) -> list[str]:
    settings = terminalFontSettings()
    return [
        f'Font: {settings.get("face", RECOMMENDED_TERMINAL_FONT)}',
        f'Mode: {settings.get("mode", "mono")}  file={settings.get("font_path", EMPTY_STRING)}',
        f'Default WOFF2: {settings.get("selected_default_woff2_path", EMPTY_STRING)}',
        f'Windows Terminal size: {settings.get("windows_terminal_size")}  ConsoleHost cell: {settings.get("console_host_width")}x{settings.get("console_host_height")}',
        EMPTY_STRING,
        'Braille preview: ⠁⠃⠇  ⣿⣶⣤⣀  ⠿⠿',
        f'Loading: {_renderBrailleProgressBar(16 if frame_index is None else frame_index)}',
        EMPTY_STRING,
        'Emoji: 🔥  🍆  ☺',
        'ConsoleHost-safe fire aliases: ♨  ',
        'FlatLine can use braille now.',
    ]


def _acknowledgeFontPreview(runtime_payload: dict[str, object]) -> None:
    settings = terminalFontSettings()
    runtime_payload[FONT_PREVIEW_PENDING_RUNTIME_KEY] = False
    runtime_payload[FONT_PREVIEW_SHOWN_RUNTIME_KEY] = True
    runtime_payload[FONT_ACK_RUNTIME_KEY] = str(settings.get('face') or RECOMMENDED_TERMINAL_FONT)
    runtime_payload['terminal_font_config_signature'] = terminalFontConfigSignature(settings)
    _writeRuntimeSettingsPayload(runtime_payload)


def _fontReplacementSnapshots(font_path: str | Path) -> list[dict[str, object]]:
    snapshots = [_fileTraceSnapshot(font_path)]
    snapshots.extend(_fileTraceSnapshot(path) for path in _windowsFontInstallTargets(font_path))
    snapshots.extend(_fileTraceSnapshot(path) for path in windowsTerminalSettingsCandidates())
    return snapshots


def _fontInstallAttemptSpecs(font_path: str | Path) -> list[dict[str, object]]:
    desired = str(terminalFontSettings().get('face') or bundledTerminalFontFace(font_path) or RECOMMENDED_TERMINAL_FONT).strip()
    return [
        {'key': 'elevated', 'warn': EMPTY_STRING, 'trace': EMPTY_STRING, 'runner': lambda: _attemptWindowsElevatedFontInstallAndSwitch(font_path, desired)},
        {'key': 'user', 'warn': '[WARN:font] Elevation failed or was cancelled. Falling back to per-user font install.', 'trace': 'elevation failed; trying per-user install', 'runner': lambda: _installFontForCurrentUser(font_path, desired)},
    ]


def _traceFontReplacementSnapshots(before_targets: list[dict[str, object]], after_targets: list[dict[str, object]]) -> None:
    for index, before_snapshot in enumerate(before_targets):
        after_snapshot = after_targets[index] if index < len(after_targets) else before_snapshot
        _traceFileReplacement(f'font-replace-{index + 1}', before_snapshot, after_snapshot)


def maybeShowNewFontInstalledPreview() -> None:
    if os.name != 'nt':
        return
    runtime_payload = _safeRuntimeSettingsPayload()
    pending = bool(runtime_payload.get(FONT_PREVIEW_PENDING_RUNTIME_KEY))
    shown = bool(runtime_payload.get(FONT_PREVIEW_SHOWN_RUNTIME_KEY))
    settings = terminalFontSettings()
    desired_font = str(settings.get('face') or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
    current_font = str(detectConsoleFontInfo().get('font', EMPTY_STRING) or EMPTY_STRING).strip()
    change_source = str(runtime_payload.get(FONT_CHANGE_SOURCE_RUNTIME_KEY, EMPTY_STRING) or EMPTY_STRING).strip().lower()
    config_driven = bool('config' in change_source or 'handshake' in change_source)
    if not pending or shown or not bool(settings.get('show_preview_on_change', True)):
        return
    if current_font and current_font.lower() != desired_font.lower() and not config_driven:
        traceCompilerStep('font-preview', False, f'pending but current={current_font} desired={desired_font}')
        return
    traceCompilerStep('font-preview', True, f'font={current_font or desired_font} source={change_source or "unknown"}')
    try:
        if showFlatLineFontPreviewDialog('New Font Installed', "\n".join(_fontPreviewRows()), previewFonts=flatlineTerminalPreviewFontRefs(), previewGlyphs=flatlineTerminalPreviewGlyphs()):
            _acknowledgeFontPreview(runtime_payload)
            return
    except Exception as error:
        recordException('start.py:7410', sys.exc_info()[1])
        traceCompilerStep('font-preview-modal', False, f'{type(error).__name__}: {error}')
    for frame_index in range(16):
        repaintConsoleFrame(renderConsoleBox('New Font Installed', _fontPreviewRows(frame_index), color_code='\x1b[92m'))
        time.sleep(0.08)
    time.sleep(0.35)
    _acknowledgeFontPreview(runtime_payload)

def maybeRecommendConsoleFont(argv: list[str] | None = None) -> None:
    if os.name != 'nt':
        return
    info = detectConsoleFontInfo()
    current_font = str(info.get('font', EMPTY_STRING) or EMPTY_STRING).strip()
    runtime_payload = _safeRuntimeSettingsPayload()
    settings = terminalFontSettings()
    desired_font = str(settings.get('face') or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
    runtime_payload[FONT_LAST_RUNTIME_KEY] = current_font or '(unknown)'
    if current_font.lower() == desired_font.lower():
        runtime_payload[FONT_ACK_RUNTIME_KEY] = desired_font
        _writeRuntimeSettingsPayload(runtime_payload)
        noteTerminalFontConfigChange('already-current')
        traceCompilerStep('font-check', True, f'current={current_font} mode={settings.get("mode")}')
        maybeShowNewFontInstalledPreview()
        return
    traceCompilerStep('font-check', False, f"current={current_font or '(unknown)'} recommended={desired_font} mode={settings.get('mode')} source={info.get('source', EMPTY_STRING)}")
    font_path = bundledTerminalFontPath()
    if not font_path.exists():
        traceCompilerStep('font-bundle', False, f'missing bundled font {font_path}')
        _writeRuntimeSettingsPayload(runtime_payload)
        return
    before_targets = _fontReplacementSnapshots(font_path)
    changed = False
    source_label = EMPTY_STRING
    for spec in _fontInstallAttemptSpecs(font_path):
        if spec.get('warn') and not changed:
            print(str(spec.get('warn')), file=sys.stderr, flush=True)
            traceCompilerStep('font-warning', False, str(spec.get('trace', EMPTY_STRING) or spec.get('warn', EMPTY_STRING)))
        runner = spec.get('runner')
        changed = bool(cast(Any, runner)()) if callable(runner) else False
        source_label = str(spec.get('key', EMPTY_STRING) or EMPTY_STRING)
        if changed:
            break
    _traceFontReplacementSnapshots(before_targets, _fontReplacementSnapshots(font_path))
    verify_info = detectConsoleFontInfo()
    verify_font = str(verify_info.get('font', EMPTY_STRING) or EMPTY_STRING).strip()
    install_info = _detectFontInstalled(font_path)
    verify_ok = verify_font.lower() == desired_font.lower() and bool(install_info.get('installed'))
    traceCompilerStep('font-verify', verify_ok, f"current={verify_font or '(unknown)'} desired={desired_font} source={verify_info.get('source', EMPTY_STRING)} installed={install_info.get('paths', [])}")
    runtime_payload[FONT_CHANGE_SOURCE_RUNTIME_KEY] = source_label
    runtime_payload[FONT_LAST_RUNTIME_KEY] = verify_font or current_font or '(unknown)'
    runtime_payload[FONT_ACK_RUNTIME_KEY] = desired_font if verify_ok else current_font
    runtime_payload['terminal_font_config_signature'] = terminalFontConfigSignature(settings)
    if verify_ok and bool(settings.get('show_preview_on_change', True)) and not bool(runtime_payload.get(FONT_PREVIEW_SHOWN_RUNTIME_KEY)):
        runtime_payload[FONT_PREVIEW_PENDING_RUNTIME_KEY] = True
    _writeRuntimeSettingsPayload(runtime_payload)
    if verify_ok and _relaunchSelfInNewPowerShell(argv):
        time.sleep(0.35)
        _terminateCurrentWindowForFontRelaunch()
        time.sleep(0.25)
        os._exit(0)



def legacyPackagingRequested(argv=None) -> bool:
    tokens = _start_cli_token_list(argv)
    return bool(readCliOption(tokens, PYINSTALLER_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present') or readCliOption(tokens, NUITKA_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))


class PowerShell(Terminal):
    """PowerShell-specific terminal helper.

    It persists ConsoleHost font registry values and can ask winget to install or
    upgrade Microsoft.PowerShell when the active shell is older than PowerShell 7.
    """

    CONSOLE_KEYS = (
        r'HKCU\Console',
        r'HKCU\Console\%SystemRoot%_System32_WindowsPowerShell_v1.0_powershell.exe',
        r'HKCU\Console\C:_Program Files_PowerShell_7_pwsh.exe',
        r'HKCU\Console\C:_Program Files (x86)_PowerShell_7_pwsh.exe',
    )

    def _versionTuple(self) -> tuple[int, int, int]:
        parts = [int(part) for part in re.findall(r'\d+', str(self.version or EMPTY_STRING))[:3]]
        while len(parts) < 3:
            parts.append(0)
        return (int(parts[0]), int(parts[1]), int(parts[2]))

    def installFont(self, font_path: str | Path | None = None, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
        ok = super().installFont(font_path, font_name)
        desired = str(font_name or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        registry = Registry()
        font_size = int(RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT) << 16
        for key in self.CONSOLE_KEYS:
            registry.setString(key, 'FaceName', desired)
            registry.setDword(key, 'FontFamily', 54)
            registry.setDword(key, 'FontWeight', 400)
            registry.setDword(key, 'FontSize', font_size)
        return bool(ok)

    def ensureVersion7(self) -> bool:
        if os.name != 'nt':
            return False
        if self._versionTuple() >= (7, 0, 0):
            return True
        winget = shutil.which('winget.exe') or shutil.which('winget')
        if not winget:
            traceCompilerStep('powershell-upgrade', False, 'winget not found')
            return False
        command = [winget, 'upgrade', '--id', 'Microsoft.PowerShell', '-e', '--accept-package-agreements', '--accept-source-agreements']
        ok = StartDependencyRegistry.runCommand(command, label='winget upgrade Microsoft.PowerShell', timeout=180)
        if not ok:
            command[1] = 'install'
            ok = StartDependencyRegistry.runCommand(command, label='winget install Microsoft.PowerShell', timeout=180)
        traceCompilerStep('powershell-upgrade', ok, 'Microsoft.PowerShell via winget')
        return bool(ok)

    def changeFont(self, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
        self.ensureVersion7()
        self.installFont(bundledTerminalFontPath(), font_name)
        return super().changeFont(font_name)


try:
    OperatingSystem.Terminal = Terminal
    OperatingSystem.PowerShell = PowerShell
except Exception:
    recordException('start.py:operating-system-terminal-alias', sys.exc_info()[1], handled=True)

class PythonTerminal(Terminal):
    """Python console / IDLE terminal font helper."""

    def installFont(self, font_path: str | Path | None = None, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
        return super().installFont(font_path, font_name)

    def changeFont(self, font_name: str = RECOMMENDED_TERMINAL_FONT) -> bool:
        desired = str(font_name or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
        ok = super().changeFont(desired)
        try:
            idle_dir = Path.home() / '.idlerc'
            idle_dir.mkdir(parents=True, exist_ok=True)
            cfg = idle_dir / 'config-main.cfg'
            existing = File(cfg).readText() if cfg.exists() else EMPTY_STRING
            lines = [line for line in existing.splitlines() if not line.lower().startswith('font=')]
            if '[EditorWindow]' not in existing:
                lines.append('[EditorWindow]')
            lines.append(f'font={desired}')
            File(cfg).writeText('\n'.join(lines).rstrip() + '\n')
            traceCompilerStep('idle-font-config', True, str(cfg))
        except Exception:
            recordException('start.py:python-terminal-idle-font', sys.exc_info()[1])
            _traceSwallowedException('start.py:python-terminal-idle-font', sys.exc_info()[1])
        return bool(ok)


class Packager:
    if TYPE_CHECKING:
        manifest: 'ApplicationBuildManifest'
        bestExecutablePath: str
        def iconPath(self) -> Path | None: ...
        def runBackend(self, backend: str, clean: bool = True) -> int: ...
        def buildBothExecutables(self) -> int: ...
        def discoverBestExecutable(self) -> str: ...

    def __init__(self, base_dir: str | Path | None = None, argv: list[str] | None = None):
        self.baseDir = Path(base_dir or BASE_DIR)
        self.argv = list(argv or [])
        self.bundleName = 'TrioDesktop'
        self.entryScript = self.baseDir / 'start.py'
        self.outputRoot = self.baseDir / 'dist' / 'package'

    def requestedBackend(self) -> str:
        pyinstaller_requested = bool(readCliOption(self.argv, PYINSTALLER_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))
        nuitka_requested = bool(readCliOption(self.argv, NUITKA_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))
        if pyinstaller_requested and nuitka_requested:
            raise RuntimeError('Choose only one packaging backend: --pyinstaller or --nuitka')
        if pyinstaller_requested:
            return 'pyinstaller'
        if nuitka_requested:
            return 'nuitka'
        return EMPTY_STRING

    def buildRoot(self, backend: str) -> Path:
        return self.outputRoot / str(backend or 'package')

    def targetPython(self) -> str:
        return str(resolvePreferredChildPython(guiRequired=True) or sys.executable or EMPTY_STRING).strip() or str(sys.executable or EMPTY_STRING)

    def _pipInstallPackage(self, package_name: str) -> bool:
        python_exe = self.targetPython()
        package = str(package_name or EMPTY_STRING).strip()
        if not package:
            return False
        try:
            registry = StartDependencyRegistry(self.argv)
            registry.ensureModernPip(python_exe)
            registry.predownloadPipPackages([package], executable=python_exe)
            command = registry.buildPipInstallCommand(python_exe, [package], preferBinary=True)
            traceCompilerStep(f'package-install-{package_name}', True, ' '.join(shlex.quote(str(part)) for part in command))
            ok, stdout_text, stderr_text, _ = registry.runCommandDetailed(command, label=f'packager pip install {package}', timeout=registry.pipInstallTimeoutForPackages([package], 1800))
            detail = (stdout_text or stderr_text or EMPTY_STRING).strip()[:500]
            traceCompilerStep(f'package-install-{package_name}', bool(ok), detail)
            return bool(ok)
        except Exception as error:
            recordException('start.py:7521', sys.exc_info()[1])
            traceCompilerStep(f'package-install-{package_name}', False, f'{type(error).__name__}: {error}')
            return False

    def ensureBackend(self, backend: str) -> None:
        if backend == 'pyinstaller':
            try:
                runtimeImportModule('PyInstaller', '__main__')
                return
            except Exception:
                recordException('start.py:7530', sys.exc_info()[1])
                if self._pipInstallPackage('pyinstaller'):
                    runtimeImportModule('PyInstaller', '__main__')
                    return
                raise RuntimeError('PyInstaller is missing and automatic install failed')
        if backend == 'nuitka':
            try:
                runtimeImportModule('nuitka')
                return
            except Exception:
                recordException('start.py:7539', sys.exc_info()[1])
                if self._pipInstallPackage('nuitka'):
                    runtimeImportModule('nuitka')
                    return
                raise RuntimeError('Nuitka is missing and automatic install failed')

    def dataFileSpecs(self) -> list[tuple[str, str, bool]]:
        rows: list[tuple[str, str, bool]] = []
        for name in ('config.ini', 'trio.py', 'data.py'):
            path = self.baseDir / name
            if path.exists():
                rows.append((str(path), name, False))
        for name in ('fonts', 'hooks', 'languages'):
            path = self.baseDir / name
            if path.exists() and path.is_dir():
                rows.append((str(path), name, True))
        return rows

    def pyInstallerArgs(self) -> list[str]:
        backend_root = self.buildRoot('pyinstaller')
        build_dir = backend_root / 'build'
        dist_dir = backend_root / 'dist'
        spec_dir = backend_root / 'spec'
        separator = os.pathsep
        args = [
            '--noconfirm',
            '--clean',
            '--onedir',
            '--windowed',
            '--name', self.bundleName,
            '--distpath', str(dist_dir),
            '--workpath', str(build_dir),
            '--specpath', str(spec_dir),
            '--paths', str(self.baseDir),
            '--hidden-import', 'trio',
            '--hidden-import', 'data',
            '--hidden-import', 'PySide6.QtCore',
            '--hidden-import', 'PySide6.QtGui',
            '--hidden-import', 'PySide6.QtWidgets',
            '--hidden-import', 'PySide6.QtPrintSupport',
            '--hidden-import', 'PySide6.QtSvg',
            '--hidden-import', 'PySide6.QtWebChannel',
            '--hidden-import', 'PySide6.QtWebEngineCore',
            '--hidden-import', 'PySide6.QtWebEngineWidgets',
            '--hidden-import', 'PySide6.QtMultimedia',
            '--hidden-import', 'PySide6.QtPdf',
            '--hidden-import', 'PySide6.QtPdfWidgets',
        ]
        for source_path, target_path, _is_dir in self.dataFileSpecs():
            spec = f'{source_path}{separator}{target_path}'
            args.extend(['--add-data', spec])
        args.append(str(self.entryScript))
        return args

    def nuitkaArgs(self) -> list[str]:
        backend_root = self.buildRoot('nuitka')
        args = [
            '--mode=standalone',
            '--enable-plugin=pyside6',
            f'--output-dir={backend_root}',
            f'--output-filename={self.bundleName}',
            '--follow-imports',
            '--include-module=trio',
            '--include-module=data',
        ]
        for source_path, target_path, is_dir in self.dataFileSpecs():
            if is_dir:
                args.append(f'--include-data-dir={source_path}={target_path}')
            else:
                args.append(f'--include-data-files={source_path}={target_path}')
        args.append(str(self.entryScript))
        return args

    def locateBuiltExecutable(self, backend: str) -> str:
        backend_root = self.buildRoot(backend)
        candidates = []
        for path in backend_root.rglob('*'):
            if not path.is_file():
                continue
            name = path.name.lower()
            if sys.platform == 'win32':
                if path.suffix.lower() != '.exe':
                    continue
            else:
                if path.suffix.lower() in {'.py', '.pyc', '.pyo', '.txt', '.json', '.md'}:
                    continue
                try:
                    if not os.access(path, os.X_OK):
                        continue
                except Exception:
                    recordException('start.py:7628', sys.exc_info()[1])
                    _traceSwallowedException('start.py:7471', sys.exc_info()[1])
                    continue
            rank = 0
            if self.bundleName.lower() in name:
                rank -= 10
            candidates.append((rank, str(path)))
        if not candidates:
            return EMPTY_STRING
        candidates.sort()
        return candidates[0][1]

    def run(self) -> int:
        backend = self.requestedBackend()
        if not backend:
            return 0
        self.ensureBackend(backend)
        backend_root = self.buildRoot(backend)
        if backend_root.exists():
            shutil.rmtree(backend_root, ignore_errors=True)
        backend_root.mkdir(parents=True, exist_ok=True)
        traceCompilerStep('package-backend', True, backend)
        if backend == 'pyinstaller':
            pyinstaller_main = runtimeImportModule('PyInstaller', '__main__')
            args = self.pyInstallerArgs()
            traceCompilerStep('package-command', True, 'pyinstaller ' + ' '.join(shlex.quote(str(part)) for part in args))
            try:
                cast(Any, pyinstaller_main).run(args)
            except SystemExit as error:
                recordException('start.py:7656', sys.exc_info()[1])
                code = int(error.code or 0) if isinstance(error.code, int) else 1
                if code != 0:
                    traceCompilerStep('package-build', False, f'PyInstaller exit={code}')
                    return code
            except Exception as error:
                recordException('start.py:7661', sys.exc_info()[1])
                traceCompilerStep('package-build', False, f'{type(error).__name__}: {error}')
                raise
        else:
            python_exe = self.targetPython()
            args = self.nuitkaArgs()
            command = [python_exe, '-m', 'nuitka', *args]
            traceCompilerStep('package-command', True, ' '.join(shlex.quote(str(part)) for part in command))
            completed = launcherRunCommand(command, cwd=str(self.baseDir), text=True)
            if int(completed.returncode or 0) != 0:
                traceCompilerStep('package-build', False, f'Nuitka exit={completed.returncode}')
                return int(completed.returncode or 1)
        built_path = self.locateBuiltExecutable(backend)
        traceCompilerStep('package-output', bool(built_path), built_path or str(backend_root))
        if built_path:
            print(f'[PACKAGER] backend={backend} executable={built_path}', flush=True)
        else:
            print(f'[PACKAGER] backend={backend} output={backend_root}', flush=True)
        return 0


def legacyRunStartPackaging(argv=None) -> int:
    return int(Packager(BASE_DIR, list(argv or [])).run())



# --- FlatLine Build Console / manifest / installer system ----------------------
DEFAULT_APPLICATION_MANIFEST = {
    'productName': 'TrioDesktop',
    'fileDescription': 'Desktop LLM client for ChatGPT, Claude, Gemini, Azure OpenAI, Copilot, and Ollama.',
    'companyName': 'TrioDesktop',
    'author': 'TrioDesktop',
    'copyright': 'Copyright © 2026 TrioDesktop. All rights reserved.',
    'license': 'Proprietary',
    'homepage': 'https://www.triodesktop.com',
    'fileVersion': '1.0.0.0',
    'productVersion': '1.0.0.0',
    'internalName': 'TrioDesktop',
    'originalFilename': 'TrioDesktop.exe',
    'trademarks': 'TrioDesktop',
}


def _buildXmlEscape(value) -> str:
    return html.escape(str(value or EMPTY_STRING), quote=True)


def _safeBuildManifestText(value: str) -> str:
    return re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f]', EMPTY_STRING, str(value or EMPTY_STRING)).strip()


class ApplicationBuildManifest:
    def __init__(self, base_dir: str | Path | None = None):
        self.baseDir = Path(base_dir or BASE_DIR)
        self.path = self.baseDir / 'manifest.xml'
        self.values = dict(DEFAULT_APPLICATION_MANIFEST)

    def defaultXml(self) -> str:
        rows = ['<?xml version="1.0" encoding="utf-8"?>', '<applicationManifest>']
        for key in DEFAULT_APPLICATION_MANIFEST:
            rows.append(f'  <{key}>{_buildXmlEscape(DEFAULT_APPLICATION_MANIFEST[key])}</{key}>')
        rows.append('</applicationManifest>')
        rows.append(EMPTY_STRING)
        return '\n'.join(rows)

    def ensure(self) -> Path:
        if not self.path.exists():
            File(self.path).writeText(self.defaultXml())
            traceCompilerStep('manifest-create', True, str(self.path))
        self.load()
        return self.path

    def load(self) -> dict[str, str]:
        values = dict(DEFAULT_APPLICATION_MANIFEST)
        if self.path.exists():
            text = File(self.path).readText()
            for key in values:
                match = re.search(rf'<{re.escape(key)}>(.*?)</{re.escape(key)}>', text, flags=re.IGNORECASE | re.DOTALL)
                if match:
                    raw_value = html.unescape(match.group(1).strip())
                    if raw_value:
                        values[key] = _safeBuildManifestText(raw_value)
        self.values = values
        return dict(values)

    def versionTuple(self, key: str) -> tuple[int, int, int, int]:
        raw = str(self.values.get(key) or '1.0.0.0')
        parts = []
        for piece in raw.split('.'):
            try:
                parts.append(max(0, int(re.sub(r'\D+', EMPTY_STRING, piece) or '0')))
            except Exception:
                recordException('start.py:7752', sys.exc_info()[1])
                parts.append(0)
        while len(parts) < 4:
            parts.append(0)
        return tuple(parts[:4])  # type: ignore[return-value]

    def versionString(self, key: str) -> str:
        return '.'.join(str(part) for part in self.versionTuple(key))

    def pyinstallerVersionFile(self, output_root: Path) -> Path:
        values = self.load()
        output_root.mkdir(parents=True, exist_ok=True)
        version_file = output_root / 'trio_version_info.txt'
        file_version = self.versionTuple('fileVersion')
        product_version = self.versionTuple('productVersion')
        structs = {
            'CompanyName': values.get('companyName', EMPTY_STRING),
            'FileDescription': values.get('fileDescription', EMPTY_STRING),
            'FileVersion': self.versionString('fileVersion'),
            'InternalName': values.get('internalName', values.get('productName', 'TrioDesktop')),
            'LegalCopyright': values.get('copyright', EMPTY_STRING),
            'LegalTrademarks': values.get('trademarks', EMPTY_STRING),
            'OriginalFilename': values.get('originalFilename', 'TrioDesktop.exe'),
            'ProductName': values.get('productName', 'TrioDesktop'),
            'ProductVersion': self.versionString('productVersion'),
        }
        struct_rows = []
        for key, value in structs.items():
            struct_rows.append(f"        StringStruct({key!r}, {str(value or EMPTY_STRING)!r})")
        lines = [
            '# UTF-8',
            '# Auto-generated from manifest.xml by FLATLINE build system.',
            'VSVersionInfo(',
            '  ffi=FixedFileInfo(',
            f'    filevers={file_version!r},',
            f'    prodvers={product_version!r},',
            '    mask=0x3f,',
            '    flags=0x0,',
            '    OS=0x40004,',
            '    fileType=0x1,',
            '    subtype=0x0,',
            '    date=(0, 0)',
            '  ),',
            '  kids=[',
            "    StringFileInfo([StringTable('040904B0', [",
            ',\n'.join(struct_rows),
            '    ])]),',
            "    VarFileInfo([VarStruct('Translation', [1033, 1200])])",
            '  ]',
            ')',
            EMPTY_STRING,
        ]
        File(version_file).writeText('\n'.join(lines))
        traceCompilerStep('manifest-version-file', True, str(version_file))
        return version_file


def ensureApplicationManifest(base_dir: str | Path | None = None) -> Path:
    return ApplicationBuildManifest(base_dir or BASE_DIR).ensure()


def applicationIconPath(base_dir: str | Path | None = None) -> Path | None:
    root = Path(base_dir or BASE_DIR)
    for name in ('icon.ico', 'app.ico', 'TrioDesktop.ico', 'trio.ico'):
        path = root / name
        if path.exists() and path.is_file():
            return path
    return None


def noInstallerIconRequested(argv=None) -> bool:
    return bool(readCliOption(argv or [], NO_INSTALLER_ICON_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))


def buildRequested(argv=None) -> bool:
    tokens = _start_cli_token_list(argv)
    flag_sets = (BUILD_FLAGS, BUILD_NUITKA_FLAGS, BUILD_PYINSTALLER_FLAGS, BUILD_BOTH_EXE_FLAGS, BUILD_NSIS_FLAGS, BUILD_INNO_FLAGS, BUILD_WIX_FLAGS, BUILD_INSTALLERS_FLAGS)
    return any(bool(readCliOption(tokens, flags, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present')) for flags in flag_sets)


def packagingRequested(argv=None) -> bool:
    tokens = _start_cli_token_list(argv)
    return bool(readCliOption(tokens, PYINSTALLER_FLAGS | NUITKA_FLAGS | BUILD_NUITKA_FLAGS | BUILD_PYINSTALLER_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))


_ORIGINAL_PACKAGER_INIT = Packager.__init__
_ORIGINAL_PACKAGER_PIP_INSTALL = Packager._pipInstallPackage


def _buildPackagerInit(self, base_dir: str | Path | None = None, argv: list[str] | None = None):
    _ORIGINAL_PACKAGER_INIT(self, base_dir, argv)
    self.manifest = ApplicationBuildManifest(self.baseDir)
    self.manifest.ensure()
    self.bundleName = str(self.manifest.values.get('productName') or self.bundleName or 'TrioDesktop').strip() or 'TrioDesktop'
    self.bestExecutablePath = EMPTY_STRING


def _buildPackagerRequestedBackend(self) -> str:
    pyinstaller_requested = bool(readCliOption(self.argv, PYINSTALLER_FLAGS | BUILD_PYINSTALLER_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))
    nuitka_requested = bool(readCliOption(self.argv, NUITKA_FLAGS | BUILD_NUITKA_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))
    if pyinstaller_requested and nuitka_requested:
        raise RuntimeError('Choose one backend, or use --build-exes to compare both.')
    if pyinstaller_requested:
        return 'pyinstaller'
    if nuitka_requested:
        return 'nuitka'
    return EMPTY_STRING


def _buildPackagerDataFileSpecs(self) -> list[tuple[str, str, bool]]:
    rows: list[tuple[str, str, bool]] = []
    for name in ('config.ini', 'trio.py', 'data.py', 'manifest.xml'):
        path = self.baseDir / name
        if path.exists():
            rows.append((str(path), name, False))
    icon_path = applicationIconPath(self.baseDir)
    if icon_path is not None:
        rows.append((str(icon_path), icon_path.name, False))
    for name in ('fonts', 'hooks', 'languages'):
        path = self.baseDir / name
        if path.exists() and path.is_dir():
            rows.append((str(path), name, True))
    return rows


def _buildPackagerIconPath(self) -> Path | None:
    return applicationIconPath(self.baseDir)


def _buildPackagerPyInstallerArgs(self) -> list[str]:
    backend_root = self.buildRoot('pyinstaller')
    build_dir = backend_root / 'build'
    dist_dir = backend_root / 'dist'
    spec_dir = backend_root / 'spec'
    version_file = self.manifest.pyinstallerVersionFile(backend_root)
    separator = os.pathsep
    args = [
        '--noconfirm', '--clean', '--onedir', '--windowed',
        '--name', self.bundleName,
        '--distpath', str(dist_dir), '--workpath', str(build_dir), '--specpath', str(spec_dir),
        '--paths', str(self.baseDir), '--version-file', str(version_file),
        '--hidden-import', 'trio', '--hidden-import', 'data',
        '--hidden-import', 'PySide6.QtCore', '--hidden-import', 'PySide6.QtGui', '--hidden-import', 'PySide6.QtWidgets',
        '--hidden-import', 'PySide6.QtPrintSupport', '--hidden-import', 'PySide6.QtSvg', '--hidden-import', 'PySide6.QtWebChannel',
        '--hidden-import', 'PySide6.QtWebEngineCore', '--hidden-import', 'PySide6.QtWebEngineWidgets', '--hidden-import', 'PySide6.QtMultimedia',
        '--hidden-import', 'PySide6.QtPdf', '--hidden-import', 'PySide6.QtPdfWidgets',
    ]
    icon_path = self.iconPath()
    if icon_path is not None:
        args.extend(['--icon', str(icon_path)])
    for source_path, target_path, _is_dir in self.dataFileSpecs():
        args.extend(['--add-data', f'{source_path}{separator}{target_path}'])
    args.append(str(self.entryScript))
    return args


def _buildPackagerNuitkaArgs(self) -> list[str]:
    backend_root = self.buildRoot('nuitka')
    values = self.manifest.load()
    args = [
        '--mode=standalone', '--enable-plugin=pyside6', f'--output-dir={backend_root}', f'--output-filename={self.bundleName}', '--follow-imports',
        f"--company-name={values.get('companyName', EMPTY_STRING)}",
        f"--product-name={values.get('productName', self.bundleName)}",
        f"--file-version={self.manifest.versionString('fileVersion')}",
        f"--product-version={self.manifest.versionString('productVersion')}",
        f"--file-description={values.get('fileDescription', self.bundleName)}",
        f"--copyright={values.get('copyright', EMPTY_STRING)}",
        '--include-module=trio', '--include-module=data',
    ]
    icon_path = self.iconPath()
    if icon_path is not None:
        args.append(f'--windows-icon-from-ico={icon_path}')
        args.append(f'--include-data-files={icon_path}={icon_path.name}')
    for source_path, target_path, is_dir in self.dataFileSpecs():
        if icon_path is not None and Path(source_path).resolve() == icon_path.resolve():
            continue
        args.append(f'--include-data-dir={source_path}={target_path}' if is_dir else f'--include-data-files={source_path}={target_path}')
    args.append(str(self.entryScript))
    return args


def _buildPackagerRunBackend(self, backend: str, clean: bool = True) -> int:
    self.ensureBackend(backend)
    backend_root = self.buildRoot(backend)
    if clean and backend_root.exists():
        shutil.rmtree(backend_root, ignore_errors=True)
    backend_root.mkdir(parents=True, exist_ok=True)
    traceCompilerStep('package-backend', True, backend)
    if backend == 'pyinstaller':
        pyinstaller_main = runtimeImportModule('PyInstaller', '__main__')
        args = self.pyInstallerArgs()
        traceCompilerStep('package-command', True, 'pyinstaller ' + ' '.join(shlex.quote(str(part)) for part in args))
        try:
            cast(Any, pyinstaller_main).run(args)
        except SystemExit as error:
            recordException('start.py:7946', sys.exc_info()[1])
            code = int(error.code or 0) if isinstance(error.code, int) else 1
            if code != 0:
                traceCompilerStep('package-build', False, f'PyInstaller exit={code}')
                return code
    elif backend == 'nuitka':
        command = [self.targetPython(), '-m', 'nuitka', *self.nuitkaArgs()]
        traceCompilerStep('package-command', True, ' '.join(shlex.quote(str(part)) for part in command))
        completed = launcherRunCommand(command, cwd=str(self.baseDir), text=True, timeout=3600)
        if int(completed.returncode or 0) != 0:
            traceCompilerStep('package-build', False, f'Nuitka exit={completed.returncode}')
            return int(completed.returncode or 1)
    else:
        raise RuntimeError(f'Unknown package backend: {backend}')
    built_path = self.locateBuiltExecutable(backend)
    traceCompilerStep('package-output', bool(built_path), built_path or str(backend_root))
    if built_path:
        self.bestExecutablePath = built_path
        print(f'[PACKAGER] backend={backend} executable={built_path}', flush=True)
    else:
        print(f'[PACKAGER] backend={backend} output={backend_root}', flush=True)
    return 0


def _buildPackagerRun(self) -> int:
    backend = self.requestedBackend()
    if not backend:
        return 0
    return int(self.runBackend(backend))


def _buildPackagerBuildBothExecutables(self) -> int:
    results = []
    for backend in ('nuitka', 'pyinstaller'):
        try:
            code = int(self.runBackend(backend))
        except Exception as error:
            recordException('start.py:7982', sys.exc_info()[1])
            traceCompilerStep(f'package-{backend}', False, f'{type(error).__name__}: {error}')
            code = 1
        built = self.locateBuiltExecutable(backend)
        size = Path(built).stat().st_size if built and Path(built).exists() else 0
        results.append({'backend': backend, 'code': code, 'path': built, 'size': size})
    ok_results = [row for row in results if int(row.get('code') or 0) == 0 and row.get('path') and int(row.get('size') or 0) > 0]
    if ok_results:
        best = sorted(ok_results, key=lambda row: int(row.get('size') or 0))[0]
        best_file = self.outputRoot / 'BEST_EXE.txt'
        best_file.parent.mkdir(parents=True, exist_ok=True)
        File(best_file).writeText('\n'.join([f"backend={best['backend']}", f"path={best['path']}", f"size={best['size']}", EMPTY_STRING]))
        self.bestExecutablePath = str(best.get('path') or EMPTY_STRING)
        print(f"[PACKAGER] preferred_exe backend={best['backend']} size={best['size']} path={best['path']}", flush=True)
        return 0
    print('[PACKAGER] No successful executable build was produced.', file=sys.stderr, flush=True)
    return 1


def _buildPackagerDiscoverBestExecutable(self) -> str:
    if getattr(self, 'bestExecutablePath', EMPTY_STRING) and Path(self.bestExecutablePath).exists():
        return self.bestExecutablePath
    best_file = self.outputRoot / 'BEST_EXE.txt'
    if best_file.exists():
        for line in File(best_file).readText().splitlines():
            if line.startswith('path='):
                candidate = line.split('=', 1)[1].strip()
                if candidate and Path(candidate).exists():
                    self.bestExecutablePath = candidate
                    return candidate
    candidates = []
    for backend in ('nuitka', 'pyinstaller'):
        exe = self.locateBuiltExecutable(backend)
        if exe and Path(exe).exists():
            candidates.append((Path(exe).stat().st_size, exe))
    if candidates:
        candidates.sort()
        self.bestExecutablePath = str(candidates[0][1])
        return self.bestExecutablePath
    return EMPTY_STRING


Packager.__init__ = _buildPackagerInit  # nopatch
Packager.requestedBackend = _buildPackagerRequestedBackend  # nopatch
Packager.dataFileSpecs = _buildPackagerDataFileSpecs  # nopatch
Packager.iconPath = _buildPackagerIconPath  # type: ignore[method-assign]
Packager.pyInstallerArgs = _buildPackagerPyInstallerArgs  # nopatch
Packager.nuitkaArgs = _buildPackagerNuitkaArgs  # nopatch
Packager.runBackend = _buildPackagerRunBackend  # type: ignore[method-assign]
Packager.run = _buildPackagerRun  # nopatch
Packager.buildBothExecutables = _buildPackagerBuildBothExecutables  # type: ignore[method-assign]
Packager.discoverBestExecutable = _buildPackagerDiscoverBestExecutable  # type: ignore[method-assign]


class InstallerBuilder:
    def __init__(self, packager: Packager):
        self.packager = packager
        self.baseDir = packager.baseDir
        self.manifest = packager.manifest
        self.outputRoot = self.baseDir / 'dist' / 'installers'
        self.outputRoot.mkdir(parents=True, exist_ok=True)

    def values(self) -> dict[str, str]:
        return self.manifest.load()

    def iconPathForInstaller(self) -> Path | None:
        if noInstallerIconRequested(self.packager.argv):
            return None
        return applicationIconPath(self.baseDir)

    def bestBundleDir(self) -> Path | None:
        exe = self.packager.discoverBestExecutable()
        return Path(exe).parent if exe else None

    def ensureExecutableAvailable(self) -> bool:
        if self.packager.discoverBestExecutable():
            return True
        print('[INSTALLER] No existing EXE bundle found; building both EXE backends first.', flush=True)
        return int(self.packager.buildBothExecutables()) == 0 and bool(self.packager.discoverBestExecutable())

    def findExecutable(self, names: list[str]) -> str:
        for name in names:
            found = shutil.which(name)
            if found:
                return found
        if os.name == 'nt':
            roots = [Path(p) for p in [os.environ.get('ProgramFiles'), os.environ.get('ProgramFiles(x86)'), os.environ.get('LOCALAPPDATA')] if p]
            probes = []
            for root in roots:
                probes.extend([root / 'NSIS' / 'makensis.exe', root / 'Inno Setup 6' / 'ISCC.exe', root / 'WiX Toolset v3.14' / 'bin' / 'candle.exe', root / 'WiX Toolset v3.11' / 'bin' / 'candle.exe', root / 'wix' / 'wix.exe'])
            lowered = {str(name).lower() for name in names}
            for probe in probes:
                if probe.name.lower() in lowered and probe.exists():
                    return str(probe)
        return EMPTY_STRING

    def runCommand(self, command: list[str], label: str) -> int:
        traceCompilerStep(f'installer-{label}-command', True, ' '.join(shlex.quote(str(part)) for part in command))
        completed = launcherRunCommand(command, cwd=str(self.baseDir), text=True, timeout=1800)
        ok = int(completed.returncode or 0) == 0
        traceCompilerStep(f'installer-{label}', ok, f'exit={completed.returncode}')
        return int(completed.returncode or 0)

    def writeNsisScript(self) -> Path:
        values = self.values(); script = self.outputRoot / 'TrioDesktop.nsi'; bundle_dir = self.bestBundleDir() or self.baseDir
        exe_path = Path(self.packager.discoverBestExecutable() or (bundle_dir / 'TrioDesktop.exe'))
        icon_path = self.iconPathForInstaller()
        icon_line = f'Icon "{str(icon_path)}"' if icon_path is not None else '; installer icon intentionally left default by --no-installer-icon'
        rows = [
            'Unicode true', f'Name "{values.get("productName", "TrioDesktop")}"', f'OutFile "{self.outputRoot / (values.get("productName", "TrioDesktop") + "-Setup-NSIS.exe")}"',
            f'InstallDir "$PROGRAMFILES64\\{values.get("productName", "TrioDesktop")}"', 'RequestExecutionLevel user', icon_line,
            f'VIProductVersion "{self.manifest.versionString("productVersion")}"', f'VIAddVersionKey "ProductName" "{values.get("productName", "TrioDesktop")}"',
            f'VIAddVersionKey "CompanyName" "{values.get("companyName", "TrioDesktop")}"', f'VIAddVersionKey "FileDescription" "{values.get("fileDescription", "TrioDesktop installer")}"',
            f'VIAddVersionKey "LegalCopyright" "{values.get("copyright", EMPTY_STRING)}"', 'Page directory', 'Page instfiles', 'Section "Install"', '  SetOutPath "$INSTDIR"',
            f'  File /r "{bundle_dir}\\*.*"', f'  CreateShortCut "$DESKTOP\\{values.get("productName", "TrioDesktop")}.lnk" "$INSTDIR\\{exe_path.name}"', 'SectionEnd', EMPTY_STRING,
        ]
        File(script).writeText('\n'.join(rows))
        traceCompilerStep('installer-nsis-script', True, str(script)); return script

    def buildNsis(self) -> int:
        if not self.ensureExecutableAvailable(): return 1
        exe = self.findExecutable(['makensis.exe', 'makensis'])
        if not exe:
            print('[INSTALLER] NSIS makensis not found. Install NSIS or add makensis.exe to PATH.', file=sys.stderr, flush=True); return 1
        return self.runCommand([exe, str(self.writeNsisScript())], 'nsis')

    def writeInnoScript(self) -> Path:
        values = self.values(); script = self.outputRoot / 'TrioDesktop.iss'; bundle_dir = self.bestBundleDir() or self.baseDir
        exe_path = Path(self.packager.discoverBestExecutable() or (bundle_dir / 'TrioDesktop.exe'))
        icon_path = self.iconPathForInstaller()
        setup_icon = f'SetupIconFile={icon_path}' if icon_path is not None else EMPTY_STRING
        rows = ['[Setup]', f'AppName={values.get("productName", "TrioDesktop")}', f'AppVersion={self.manifest.versionString("productVersion")}', f'AppPublisher={values.get("companyName", "TrioDesktop")}', f'AppPublisherURL={values.get("homepage", "https://www.triodesktop.com")}', f'DefaultDirName={{autopf}}\\{values.get("productName", "TrioDesktop")}', f'DefaultGroupName={values.get("productName", "TrioDesktop")}', f'OutputDir={self.outputRoot}', f'OutputBaseFilename={values.get("productName", "TrioDesktop")}-Setup-Inno', 'Compression=lzma', 'SolidCompression=yes']
        if setup_icon:
            rows.append(setup_icon)
        rows.extend(['', '[Files]', f'Source: "{bundle_dir}\\*"; DestDir: "{{app}}"; Flags: recursesubdirs ignoreversion', '', '[Icons]', f'Name: "{{autodesktop}}\\{values.get("productName", "TrioDesktop")}"; Filename: "{{app}}\\{exe_path.name}"', EMPTY_STRING])
        File(script).writeText('\n'.join(rows))
        traceCompilerStep('installer-inno-script', True, str(script)); return script

    def buildInno(self) -> int:
        if not self.ensureExecutableAvailable(): return 1
        exe = self.findExecutable(['ISCC.exe', 'iscc.exe', 'iscc'])
        if not exe:
            print('[INSTALLER] Inno Setup compiler ISCC not found. Install Inno Setup or add ISCC.exe to PATH.', file=sys.stderr, flush=True); return 1
        return self.runCommand([exe, str(self.writeInnoScript())], 'inno')

    def writeWixScript(self) -> Path:
        values = self.values(); wxs = self.outputRoot / 'TrioDesktop.wxs'; exe_path = Path(self.packager.discoverBestExecutable() or 'TrioDesktop.exe')
        icon_path = self.iconPathForInstaller()
        icon_decl = f'<Icon Id="AppIcon.ico" SourceFile="{_buildXmlEscape(str(icon_path))}" /><Property Id="ARPPRODUCTICON" Value="AppIcon.ico" />' if icon_path is not None else EMPTY_STRING
        rows = ['<?xml version="1.0" encoding="UTF-8"?>', '<Wix xmlns="http://schemas.microsoft.com/wix/2006/wi">', f'  <Product Id="*" Name="{_buildXmlEscape(values.get("productName", "TrioDesktop"))}" Language="1033" Version="{self.manifest.versionString("productVersion")}" Manufacturer="{_buildXmlEscape(values.get("companyName", "TrioDesktop"))}" UpgradeCode="11111111-2222-3333-4444-555555555555">', '    <Package InstallerVersion="500" Compressed="yes" InstallScope="perMachine" />', '    <MajorUpgrade DowngradeErrorMessage="A newer version is already installed." />', '    <MediaTemplate />', f'    {icon_decl}', f'    <Directory Id="TARGETDIR" Name="SourceDir"><Directory Id="ProgramFilesFolder"><Directory Id="INSTALLFOLDER" Name="{_buildXmlEscape(values.get("productName", "TrioDesktop"))}"><Component Id="MainExecutable" Guid="*"><File Id="MainExe" Source="{_buildXmlEscape(str(exe_path))}" KeyPath="yes" /></Component></Directory></Directory></Directory>', f'    <Feature Id="DefaultFeature" Title="{_buildXmlEscape(values.get("productName", "TrioDesktop"))}" Level="1"><ComponentRef Id="MainExecutable" /></Feature>', '  </Product>', '</Wix>', EMPTY_STRING]
        File(wxs).writeText('\n'.join(rows))
        traceCompilerStep('installer-wix-script', True, str(wxs)); return wxs

    def buildWix(self) -> int:
        if not self.ensureExecutableAvailable(): return 1
        wix = self.findExecutable(['wix.exe', 'wix']); wxs = self.writeWixScript()
        if wix:
            return self.runCommand([wix, 'build', str(wxs), '-o', str(self.outputRoot / 'TrioDesktop-Setup-WiX.msi')], 'wix')
        candle = self.findExecutable(['candle.exe', 'candle']); light = self.findExecutable(['light.exe', 'light'])
        if not candle or not light:
            print('[INSTALLER] WiX compiler not found. Install WiX Toolset and add wix.exe or candle.exe/light.exe to PATH.', file=sys.stderr, flush=True); return 1
        wixobj = self.outputRoot / 'TrioDesktop.wixobj'; msi = self.outputRoot / 'TrioDesktop-Setup-WiX.msi'
        code = self.runCommand([candle, '-out', str(wixobj), str(wxs)], 'wix-candle')
        return code if code != 0 else self.runCommand([light, '-out', str(msi), str(wixobj)], 'wix-light')

    def run(self, backend: str) -> int:
        value = str(backend or EMPTY_STRING).strip().lower()
        if value == 'nsis': return self.buildNsis()
        if value == 'inno': return self.buildInno()
        if value == 'wix': return self.buildWix()
        if value in {'all', 'installers'}:
            last = 1
            for item in ('nsis', 'inno', 'wix'):
                code = self.run(item)
                if code == 0: return 0
                last = code
            return int(last or 1)
        raise RuntimeError(f'Unknown installer backend: {backend}')


class BuildPhase:
    def __init__(self, key: str, label: str, aliases, handler):
        self.key = str(key or EMPTY_STRING)
        self.label = str(label or self.key)
        self.aliases = {str(alias or EMPTY_STRING).strip().lower() for alias in list(aliases or []) if str(alias or EMPTY_STRING).strip()}
        self.handler = handler
    def matchesArgv(self, argv=None) -> bool:
        return bool(readCliOption(argv or [], self.aliases, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))
    def run(self, build_system) -> int:
        traceCompilerStep(f'build-phase-{self.key}', True, self.label)
        return int(self.handler(build_system) or 0)


class BuildSystem:
    def __init__(self, base_dir: str | Path | None = None, argv: list[str] | None = None):
        self.baseDir = Path(base_dir or BASE_DIR)
        self.argv = list(argv or [])
        self.packager = Packager(self.baseDir, self.argv)
        self.installer = InstallerBuilder(self.packager)
        self.phases = self.buildPhaseRegistry()
        self.phaseMap = {phase.key: phase for phase in self.phases}
        self.aliasMap = {alias: phase for phase in self.phases for alias in phase.aliases}
    def buildPhaseRegistry(self) -> list[BuildPhase]:
        return [BuildPhase('nuitka', 'Create EXE with Nuitka / Nikita', NUITKA_FLAGS | BUILD_NUITKA_FLAGS, lambda system: system.packager.runBackend('nuitka')), BuildPhase('pyinstaller', 'Create EXE with PyInstaller / PyCompiler', PYINSTALLER_FLAGS | BUILD_PYINSTALLER_FLAGS, lambda system: system.packager.runBackend('pyinstaller')), BuildPhase('both-exe', 'Build both EXE backends and choose the smaller output', BUILD_BOTH_EXE_FLAGS, lambda system: system.packager.buildBothExecutables()), BuildPhase('nsis', 'Create installer with Nullsoft Scriptable Install System', BUILD_NSIS_FLAGS, lambda system: system.installer.run('nsis')), BuildPhase('inno', 'Create installer with Inno Setup', BUILD_INNO_FLAGS, lambda system: system.installer.run('inno')), BuildPhase('wix', 'Create MSI with WiX Toolset', BUILD_WIX_FLAGS, lambda system: system.installer.run('wix')), BuildPhase('installers', 'Try installer builders: NSIS, Inno Setup, WiX', BUILD_INSTALLERS_FLAGS, lambda system: system.installer.run('installers'))]
    def requestedPhase(self) -> BuildPhase | None:
        for phase in self.phases:
            if phase.matchesArgv(self.argv): return phase
        if bool(readCliOption(self.argv, NUITKA_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present')): return self.phaseMap.get('nuitka')
        if bool(readCliOption(self.argv, PYINSTALLER_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present')): return self.phaseMap.get('pyinstaller')
        return None
    def printMenu(self) -> None:
        rows = [f"{ansi('1;92')}🔥 FLATLINE BUILD CONSOLE {ansi('0')}— executable and installer builder", f"{ansi('1;96')}Manifest:{ansi('0')} {self.packager.manifest.path}", f"{ansi('1;96')}Icon:{ansi('0')} {applicationIconPath(self.baseDir) or 'icon.ico not found'}", EMPTY_STRING, 'N  Create EXE with Nuitka / Nikita', 'P  Create EXE with PyInstaller / PyCompiler', 'B  Build both EXEs and choose the smaller one', 'S  Create installer with Nullsoft/NSIS', 'I  Create installer with Inno Setup', 'W  Create MSI with WiX Toolset', 'A  Try installer builders in order: NSIS, Inno, WiX', 'M  Recreate/read manifest.xml', 'Q  Quit build console', EMPTY_STRING, 'CLI examples:', '  python start.py --build-nuitka', '  python start.py --build-pyinstaller', '  python start.py --build-nsis --no-installer-icon']
        print(writeConsoleFrame('FLATLINE BUILD MENU', rows, color_code='1;92'), flush=True)
    def runMenu(self) -> int:
        self.printMenu()
        while True:
            try: choice = input('Build command [N/P/B/S/I/W/A/M/Q]: ').strip().lower()
            except EOFError:
                recordException('start.py:8199', sys.exc_info()[1])
                return 0
            if choice in {'q', 'quit', 'exit'}: return 0
            if choice in {'m', 'manifest'}:
                self.packager.manifest.ensure(); print(f'[BUILD] manifest={self.packager.manifest.path}', flush=True); continue
            key_map = {'n': 'nuitka', 'p': 'pyinstaller', 'b': 'both-exe', 's': 'nsis', 'i': 'inno', 'w': 'wix', 'a': 'installers'}
            phase = self.phaseMap.get(key_map.get(choice, choice))
            if phase is None:
                print('[BUILD] Unknown build command.', file=sys.stderr, flush=True); continue
            return int(phase.run(self))
    def run(self) -> int:
        ensureApplicationManifest(self.baseDir)
        phase = self.requestedPhase()
        if phase is not None: return int(phase.run(self))
        return int(self.runMenu())


def runStartPackaging(argv=None) -> int:
    return int(Packager(BASE_DIR, list(argv or [])).run())


def runBuildConsole(argv=None) -> int:
    return int(BuildSystem(BASE_DIR, list(argv or [])).run())

def maybeBootstrapStartExe(argv: list[str] | None = None) -> bool:
    launch_args = list(argv or [])
    if os.name != 'nt':
        return False
    if os.environ.get(START_EXE_ENV_FLAG):
        return False
    if _cliTokenPresent(launch_args, START_EXE_SKIP_FLAG):
        return False
    if debugEnabled(launch_args) or scanDisabled(launch_args) or cliHasAnyFlag(launch_args, CLEAN_FLAGS):
        traceCompilerStep('run-start-exe', True, 'debug/no-scan/clean keeps current python launcher active; start.exe bootstrap deferred so FlatLine can start first')
        return False
    maybeRecommendConsoleFont(launch_args)
    compiler = Compiler(BASE_DIR, launch_args)
    try:
        exe_path = compiler.ensureStartExe(force_rebuild=_cliTokenPresent(launch_args, START_EXE_FORCE_BUILD_FLAG))
    except Exception as error:
        recordException('start.py:8238', sys.exc_info()[1])
        traceCompilerStep('ensure-start-exe', False, f'{type(error).__name__}: {error}')
        return False
    if debugEnabled(launch_args):
        traceCompilerStep('run-start-exe', True, f'debug-mode keeps current python launcher active path={exe_path}')
        return False
    try:
        child = launcherStartProcess([str(exe_path), *launch_args], cwd=str(BASE_DIR))
        traceCompilerStep('run-start-exe', True, f'pid={getattr(child, "pid", 0)} path={exe_path}')
    except Exception as error:
        recordException('start.py:8247', sys.exc_info()[1])
        traceCompilerStep('run-start-exe', False, f'{type(error).__name__}: {error}')
        return False
    try:
        launcherStartProcess(['taskkill', '/F', '/PID', str(os.getpid())], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        traceCompilerStep('taskkill-self', True, f'pid={os.getpid()}')
    except Exception as error:
        recordException('start.py:8253', sys.exc_info()[1])
        traceCompilerStep('taskkill-self', False, f'{type(error).__name__}: {error}')
    time.sleep(0.25)
    os._exit(0)
    return True

