def buildCliAliasSet(*names: str, includeQuestion: bool = False) -> set[str]:
    aliases: set[str] = set()
    for rawName in list(names or []):
        name = str(rawName or EMPTY_STRING).strip().lower()
        if not name:
            continue
        aliases.add(name)
        if name == '?':
            aliases.add('/?')
            continue
        aliases.add('/' + name)
        aliases.add('-' + name)
        aliases.add('--' + name)
    if includeQuestion:
        aliases.update({'?', '/?'})
    return aliases


def stripCliValueQuotes(value: str) -> str:
    text = str(value or EMPTY_STRING).strip()
    if len(text) >= 2 and text[0] == text[-1] and text[0] in {'"', "'"}:
        return text[1:-1].strip()
    return text


def cliTokenLooksLikeOption(token: str, knownAliases: set[str] | None = None) -> bool:
    lowered = str(token or EMPTY_STRING).strip().lower()
    if not lowered:
        return False
    aliases = set(knownAliases or set())
    if lowered in aliases:
        return True
    for alias in list(aliases):
        for separator in ('=', ':'):
            if lowered.startswith(alias + separator):
                return True
    return lowered.startswith('-') or lowered.startswith('/') or lowered == '?'


def readCliOption(argv=None, aliases=None, takesValue: bool = False, knownAliases: set[str] | None = None) -> dict[str, Any]:
    tokens = [str(token or EMPTY_STRING).strip() for token in list(argv or []) if str(token or EMPTY_STRING).strip()]
    aliasSet = {str(alias or EMPTY_STRING).strip().lower() for alias in list(aliases or []) if str(alias or EMPTY_STRING).strip()}
    state: dict[str, Any] = {'present': False, 'value': EMPTY_STRING, 'missing_value': False, 'token': EMPTY_STRING, 'index': -1}
    for index, token in enumerate(tokens):
        lowered = str(token or EMPTY_STRING).strip().lower()
        for alias in list(aliasSet):
            if lowered == alias:
                state.update({'present': True, 'token': token, 'index': index})
                if takesValue:
                    if index + 1 < len(tokens) and not cliTokenLooksLikeOption(tokens[index + 1], knownAliases or aliasSet):
                        state['value'] = stripCliValueQuotes(tokens[index + 1])
                    else:
                        state['missing_value'] = True
                return state
            for separator in ('=', ':'):
                prefix = alias + separator
                if lowered.startswith(prefix):
                    valueText = stripCliValueQuotes(token[len(alias) + 1:])
                    state.update({'present': True, 'token': token, 'index': index, 'value': valueText})
                    if takesValue and not valueText:
                        state['missing_value'] = True
                    return state
    return state


class Config:
    """Tiny launcher config facade with forgiving INI/TSV/CSV comment parsing."""
    def __init__(self, path: Path | str | None = None):
        self.path = Path(path or (BASE_DIR / 'config.ini'))
        self.sections: dict[str, dict[str, str]] = {}
        self.settings: dict[str, dict[str, str]] = self.sections
        self.modified: float = 0.0
        self.load()

    def stripBlockComments(self, text: str) -> str:
        payload = str(text or EMPTY_STRING)
        payload = re.sub(r'/\*.*?\*/', '', payload, flags=re.DOTALL)
        payload = re.sub(r'<!--.*?-->', '', payload, flags=re.DOTALL)
        payload = re.sub(r'(?ms)^\s*=pod\b.*?^\s*=cut\b.*?(?:\n|$)', '', payload)
        payload = re.sub(r'(?ms)^\s*=begin\b.*?^\s*=end\b.*?(?:\n|$)', '', payload)
        return payload

    def stripLineComment(self, line: str) -> str:
        text = str(line or EMPTY_STRING)
        quote = None
        index = 0
        while index < len(text):
            ch = text[index]
            if quote:
                if ch == quote:
                    quote = None
                index += 1
                continue
            if ch in {'"', "'"}:
                quote = ch
                index += 1
                continue
            if ch in {'#', ';'}:
                return text[:index].rstrip()
            if text.startswith('//', index) and (index == 0 or text[index - 1].isspace()):
                return text[:index].rstrip()
            if text.startswith('--', index) and (index == 0 or text[index - 1].isspace()):
                return text[:index].rstrip()
            index += 1
        return text.rstrip()

    def splitKeyValue(self, line: str) -> tuple[str, str] | None:
        text = str(line or EMPTY_STRING).strip()
        if not text:
            return None
        for separator in ('=', ':', '\t', ','):
            if separator in text:
                key, value = text.split(separator, 1)
                key = str(key or EMPTY_STRING).strip()
                value = str(value or EMPTY_STRING).strip()
                if key:
                    return key, value
        return None

    def load(self) -> None:
        self.sections = {}
        self.settings = self.sections
        self.modified = 0.0
        current = 'default'
        self.sections[current] = {}
        try:
            stat = self.path.stat()
            self.modified = float(getattr(stat, 'st_mtime', 0.0) or 0.0)
            raw = File(self.path).readText()
        except Exception:
            recordException('start.py:8384', sys.exc_info()[1])
            _traceSwallowedException('start.py:8225', sys.exc_info()[1])
            return
        raw = self.stripBlockComments(raw)
        for rawLine in raw.splitlines():
            line = self.stripLineComment(rawLine).strip()
            if not line:
                continue
            if line.startswith('[') and line.endswith(']'):
                current = line[1:-1].strip().lower() or 'default'
                self.sections.setdefault(current, {})
                continue
            pair = self.splitKeyValue(line)
            if pair is None:
                continue
            key, value = pair
            self.sections.setdefault(current, {})[key.strip().lower()] = value.strip()
        self.settings = self.sections

    def reload(self) -> None:
        self.load()

    def get(self, section: str, key: str, default: str = EMPTY_STRING) -> str:
        return str(self.sections.get(str(section or 'default').strip().lower(), {}).get(str(key or EMPTY_STRING).strip().lower(), default))

    def getInt(self, section: str, key: str, default: int = 0, minimum: int | None = None, maximum: int | None = None) -> int:
        try:
            value = int(str(self.get(section, key, str(default))).strip() or int(default or 0))
        except Exception:
            recordException('start.py:8408', sys.exc_info()[1])
            value = int(default or 0)
        if minimum is not None:
            value = max(int(minimum), value)
        if maximum is not None:
            value = min(int(maximum), value)
        return value

class IniConfig(Config):
    """Explicit INI config class for launcher/runtime options.

    updateFile() rewrites config.ini from a merged configparser snapshot. It is
    intentionally the single launcher-side INI write path so prompted API keys,
    DB-seeded values, and manual edits all round-trip through one class.
    """

    def set(self, section: str, key: str, value: str) -> None:
        section_text = str(section or 'default').strip().lower() or 'default'
        key_text = str(key or EMPTY_STRING).strip().lower()
        if not key_text:
            return
        self.sections.setdefault(section_text, {})[key_text] = str(value or EMPTY_STRING).strip()

    def setMany(self, updates: dict[str, dict[str, object]] | None = None) -> None:  # noqa: N802
        for section, pairs in dict(updates or {}).items():
            if not isinstance(pairs, dict):
                continue
            for key, value in pairs.items():
                self.set(str(section), str(key), str(value or EMPTY_STRING))

    def toConfigParser(self, includeDefaults: bool = True) -> configparser.ConfigParser:  # noqa: N802
        parser = _buildDefaultConfigParser() if includeDefaults else configparser.ConfigParser()
        try:
            if self.path.exists():
                existing = configparser.ConfigParser()
                existing.read_string(_stripConfigCommentsForConfigParser(File(self.path).readText()), source=str(self.path))
                for section in existing.sections():
                    if not parser.has_section(section):
                        parser.add_section(section)
                    for key, value in existing.items(section):
                        parser.set(section, key, str(value or EMPTY_STRING))
        except Exception:
            recordException('start.py:ini-existing-merge', sys.exc_info()[1], handled=True)
        for section, pairs in dict(self.sections or {}).items():
            section_text = str(section or 'default').strip()
            if not section_text or section_text == 'default':
                continue
            if not parser.has_section(section_text):
                parser.add_section(section_text)
            for key, value in dict(pairs or {}).items():
                key_text = str(key or EMPTY_STRING).strip()
                if key_text:
                    parser.set(section_text, key_text, str(value or EMPTY_STRING))
        return parser

    def updateFile(self, updates: dict[str, dict[str, object]] | None = None, *, includeDefaults: bool = True) -> bool:  # noqa: N802
        """Rewrite config.ini after merging defaults, current file values, and updates."""
        try:
            self.setMany(updates)
            parser = self.toConfigParser(includeDefaults=includeDefaults)
            self.path.parent.mkdir(parents=True, exist_ok=True)
            tmp_path = self.path.with_suffix(self.path.suffix + '.tmp')
            text = _renderCommentedConfigText(parser)
            _apiConfigTraceText('config.ini updateFile write attempt', self.path, text)
            File(tmp_path).writeText(text)
            os.replace(str(tmp_path), str(self.path))
            try:
                written = File(self.path).readText()
                _apiConfigTraceText('config.ini updateFile after write readback', self.path, written)
            except Exception:
                recordException('start.py:ini-update-readback', sys.exc_info()[1], handled=True)
            self.reload()
            global _TRIO_CONFIG_CACHE
            _TRIO_CONFIG_CACHE = self
            print(f'[TRACE:config] updateFile wrote {self.path}', file=sys.stderr, flush=True)
            return True
        except Exception:
            recordException('start.py:ini-update-file', sys.exc_info()[1], handled=True)
            return False


_TRIO_CONFIG_CACHE: IniConfig | None = None

def appConfig() -> IniConfig:
    global _TRIO_CONFIG_CACHE
    if _TRIO_CONFIG_CACHE is None:
        _TRIO_CONFIG_CACHE = IniConfig(BASE_DIR / 'config.ini')
    return _TRIO_CONFIG_CACHE


def traceBufferSizeFromConfig(default: int = 50) -> int:
    return appConfig().getInt('trace', 'buffer_size', default=default, minimum=1, maximum=5000)


def _configBool(value: str, default: bool = False) -> bool:
    raw = str(value or EMPTY_STRING).strip().lower()
    if not raw:
        return bool(default)
    if raw in {'1', 'true', 'yes', 'y', 'on', 'enabled', 'enable'}:
        return True
    if raw in {'0', 'false', 'no', 'n', 'off', 'disabled', 'disable'}:
        return False
    print(f'[WARN:config] invalid boolean value {value!r}; using {default}', file=sys.stderr, flush=True)
    return bool(default)


def terminalFontColorEnabled(rawValue: str | None = None, warn: bool = True) -> bool:
    raw = str(rawValue if rawValue is not None else appConfig().get(TERMINAL_FONT_CONFIG_SECTION, 'color', 'off')).strip().lower()
    if not raw:
        return False
    if raw in TERMINAL_FONT_COLOR_ALIASES_TRUE:
        return True
    if raw in TERMINAL_FONT_COLOR_ALIASES_FALSE:
        return False
    if warn:
        print(f'[WARN:font-config] invalid terminal_font.color={raw!r}; valid examples are off, mono, on, color. Falling back to mono.', file=sys.stderr, flush=True)
    return False


def _terminalFontConfigPath(value: str, fallback: Path) -> Path:
    raw = str(value or EMPTY_STRING).strip()
    if not raw:
        return (BASE_DIR / fallback).resolve()
    path = Path(raw)
    if not path.is_absolute():
        path = BASE_DIR / path
    return path.resolve()


def _terminalFontDefaultAliasPath(cfg: object, option: str, fallback: Path) -> Path:
    try:
        getter = getattr(cfg, 'get', None)
        raw = getter(TERMINAL_FONT_CONFIG_SECTION, option, str(fallback)) if callable(getter) else str(fallback)
    except Exception:
        recordException('start.py:8472', sys.exc_info()[1])
        raw = str(fallback)
    return _terminalFontConfigPath(str(raw or str(fallback)), fallback)


def terminalFontSettings() -> dict[str, object]:
    cfg = appConfig()
    color_enabled = terminalFontColorEnabled(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'color', 'off'))
    colored_raw = str(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'colored_font', EMPTY_STRING) or EMPTY_STRING).strip()
    colored_plural_raw = str(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'colored_fonts', EMPTY_STRING) or EMPTY_STRING).strip()
    if colored_raw:
        color_enabled = terminalFontColorEnabled(colored_raw)
    if colored_plural_raw:
        color_enabled = terminalFontColorEnabled(colored_plural_raw)
    mono_face = str(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'mono_face', RECOMMENDED_TERMINAL_FONT) or RECOMMENDED_TERMINAL_FONT).strip() or RECOMMENDED_TERMINAL_FONT
    color_face = str(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'color_face', RECOMMENDED_TERMINAL_COLOR_FONT) or RECOMMENDED_TERMINAL_COLOR_FONT).strip() or RECOMMENDED_TERMINAL_COLOR_FONT
    mono_path = _terminalFontConfigPath(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'mono_file', str(DEFAULT_TERMINAL_OTF_RELATIVE_PATH)), DEFAULT_TERMINAL_OTF_RELATIVE_PATH)
    color_path = _terminalFontConfigPath(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'color_file', str(DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH)), DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH)
    default_otf_path = _terminalFontDefaultAliasPath(cfg, 'default_otf_file', DEFAULT_TERMINAL_OTF_RELATIVE_PATH)
    default_color_otf_path = _terminalFontDefaultAliasPath(cfg, 'default_color_otf_file', DEFAULT_TERMINAL_COLOR_OTF_RELATIVE_PATH)
    default_woff2_path = _terminalFontDefaultAliasPath(cfg, 'default_woff2_file', DEFAULT_TERMINAL_WOFF2_RELATIVE_PATH)
    default_color_woff2_path = _terminalFontDefaultAliasPath(cfg, 'default_color_woff2_file', DEFAULT_TERMINAL_COLOR_WOFF2_RELATIVE_PATH)
    selected_default_otf_path = default_color_otf_path if color_enabled else default_otf_path
    selected_default_woff2_path = default_color_woff2_path if color_enabled else default_woff2_path
    wt_size = cfg.getInt(TERMINAL_FONT_CONFIG_SECTION, 'windows_terminal_size', default=RECOMMENDED_WINDOWS_TERMINAL_FONT_SIZE, minimum=8, maximum=72)
    console_width = cfg.getInt(TERMINAL_FONT_CONFIG_SECTION, 'console_host_width', default=RECOMMENDED_CONSOLE_HOST_FONT_WIDTH, minimum=0, maximum=80)
    console_height = cfg.getInt(TERMINAL_FONT_CONFIG_SECTION, 'console_host_height', default=RECOMMENDED_CONSOLE_HOST_FONT_HEIGHT, minimum=8, maximum=96)
    show_preview = _configBool(cfg.get(TERMINAL_FONT_CONFIG_SECTION, 'show_preview_on_change', '1'), True)
    return {
        'color': color_enabled,
        'colored_font': color_enabled,
        'mode': 'color' if color_enabled else 'mono',
        'face': color_face if color_enabled else mono_face,
        'font_path': color_path if color_enabled else mono_path,
        'mono_face': mono_face,
        'color_face': color_face,
        'mono_path': mono_path,
        'color_path': color_path,
        'default_otf_path': default_otf_path,
        'default_color_otf_path': default_color_otf_path,
        'selected_default_otf_path': selected_default_otf_path,
        'default_woff2_path': default_woff2_path,
        'default_color_woff2_path': default_color_woff2_path,
        'selected_default_woff2_path': selected_default_woff2_path,
        'windows_terminal_size': wt_size,
        'console_host_width': console_width,
        'console_host_height': console_height,
        'show_preview_on_change': show_preview,
    }

def terminalFontConfigSignature(settings: dict[str, object] | None = None) -> str:
    payload = dict(settings or terminalFontSettings())
    serializable = {key: str(value) for key, value in sorted(payload.items()) if key in {'color', 'colored_font', 'mode', 'face', 'font_path', 'default_otf_path', 'default_color_otf_path', 'selected_default_otf_path', 'default_woff2_path', 'default_color_woff2_path', 'selected_default_woff2_path', 'windows_terminal_size', 'console_host_width', 'console_host_height', 'show_preview_on_change'}}
    return hashlib.md5(json.dumps(serializable, sort_keys=True).encode('utf-8', 'replace')).hexdigest()


def noteTerminalFontConfigChange(reason: str = 'config-check') -> None:
    try:
        settings = terminalFontSettings()
        signature = terminalFontConfigSignature(settings)
        runtime_payload = _safeRuntimeSettingsPayload()
        previous = str(runtime_payload.get('terminal_font_config_signature', EMPTY_STRING) or EMPTY_STRING)
        runtime_payload['terminal_font_config_signature'] = signature
        runtime_payload['terminal_font_mode'] = str(settings.get('mode', EMPTY_STRING))
        runtime_payload['terminal_font_face'] = str(settings.get('face', EMPTY_STRING))
        runtime_payload['terminal_font_path'] = str(settings.get('font_path', EMPTY_STRING))
        runtime_payload['terminal_colored_font'] = bool(settings.get('colored_font', False))
        runtime_payload['terminal_default_otf_path'] = str(settings.get('selected_default_otf_path', EMPTY_STRING))
        runtime_payload['terminal_default_woff2_path'] = str(settings.get('selected_default_woff2_path', EMPTY_STRING))
        traceDefaultFontSelection(settings, reason=str(reason or 'config-check'))
        if previous and previous != signature and bool(settings.get('show_preview_on_change', True)):
            runtime_payload[FONT_PREVIEW_PENDING_RUNTIME_KEY] = True
            runtime_payload[FONT_PREVIEW_SHOWN_RUNTIME_KEY] = False
            runtime_payload[FONT_CHANGE_SOURCE_RUNTIME_KEY] = str(reason or 'config-change')
            traceCompilerStep('font-config-change', True, f'preview pending mode={settings.get("mode")} face={settings.get("face")}')
        _writeRuntimeSettingsPayload(runtime_payload)
    except Exception as error:
        recordException('start.py:8548', sys.exc_info()[1])
        print(f'[WARN:font-config] config change tracking failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)



SNAPSHOT_SAVE_DATABASE = 1
SNAPSHOT_SAVE_TEXT = 2
SNAPSHOT_SAVE_SERIES_ZIPS = 4
SNAPSHOT_SAVE_ALL = SNAPSHOT_SAVE_DATABASE | SNAPSHOT_SAVE_TEXT | SNAPSHOT_SAVE_SERIES_ZIPS


def _snapshotSaveWarn(message: str, callback=None) -> None:
    text = str(message or EMPTY_STRING)
    if not text:
        return
    line = f'[WARN:snapshots] {text}'
    if callback is not None:
        try:
            callback(line)
            return
        except Exception:
            recordException('start.py:8568', sys.exc_info()[1])
            _traceSwallowedException('start.py:8408', sys.exc_info()[1])
            pass
    print(line, file=sys.stderr, flush=True)


def parseSnapshotSaveTargets(rawValue: str | None = None, warnCallback=None) -> int:
    raw = str(rawValue if rawValue is not None else appConfig().get('snapshots', 'save', 'text') or 'text').strip()
    if not raw:
        _snapshotSaveWarn('snapshots.save is empty; falling back to text', warnCallback)
        return SNAPSHOT_SAVE_TEXT
    normalized = raw.strip().lower()
    normalized = normalized.replace('series zips', 'series_zips').replace('series zip', 'series_zips').replace('series db', 'series_zips')
    aliases: dict[str, int] = {
        'database': SNAPSHOT_SAVE_DATABASE, 'db': SNAPSHOT_SAVE_DATABASE,
        'text': SNAPSHOT_SAVE_TEXT, 'txt': SNAPSHOT_SAVE_TEXT, 'file': SNAPSHOT_SAVE_TEXT, 'files': SNAPSHOT_SAVE_TEXT,
        'series_zips': SNAPSHOT_SAVE_SERIES_ZIPS, 'series-zips': SNAPSHOT_SAVE_SERIES_ZIPS, 'serieszip': SNAPSHOT_SAVE_SERIES_ZIPS,
        'serieszips': SNAPSHOT_SAVE_SERIES_ZIPS, 'series': SNAPSHOT_SAVE_SERIES_ZIPS, 'seriesdb': SNAPSHOT_SAVE_SERIES_ZIPS, 'zip': SNAPSHOT_SAVE_SERIES_ZIPS, 'zips': SNAPSHOT_SAVE_SERIES_ZIPS,
        'all': SNAPSHOT_SAVE_ALL, 'eall': SNAPSHOT_SAVE_ALL,
        'none': 0, 'off': 0, 'false': 0, '0': 0,
    }
    simple_parts = [part for part in re.split(r'[\s,;+]+', normalized) if part]
    has_operator = any(operator in normalized for operator in ('|', '&', '~', '^', '(', ')'))
    try:
        if not has_operator:
            mask = 0
            for part in simple_parts:
                if part not in aliases:
                    raise ValueError(f'unknown token {part}')
                mask |= int(aliases[part])
            return int(mask) & SNAPSHOT_SAVE_ALL
        expression = normalized.replace(',', '|').replace(';', '|').replace('+', '|')
        tokens: list[str] = list(re.findall(r'[a-z_][a-z0-9_-]*|\d+|[|&~^()]', expression))
        if not tokens:
            raise ValueError('no tokens')
        rendered: list[str] = []
        for token in tokens:
            if token in {'|', '&', '~', '^', '(', ')'}:
                rendered.append(token)
                continue
            if token not in aliases:
                raise ValueError(f'unknown token {token}')
            rendered.append(str(int(aliases[token])))
        value = int(eval(' '.join(rendered), {'__builtins__': {}}, {})) & SNAPSHOT_SAVE_ALL  # nopatch
        return value
    except Exception as error:
        recordException('start.py:8613', sys.exc_info()[1])
        _snapshotSaveWarn(f'invalid snapshots.save={raw!r}; falling back to text ({type(error).__name__}: {error})', warnCallback)
        return SNAPSHOT_SAVE_TEXT


def snapshotSaveTargets(warnCallback=None) -> int:
    return parseSnapshotSaveTargets(appConfig().get('snapshots', 'save', 'text'), warnCallback=warnCallback)


def snapshotSaveTargetNames(mask: int) -> str:
    names = []
    if int(mask or 0) & SNAPSHOT_SAVE_DATABASE:
        names.append('database')
    if int(mask or 0) & SNAPSHOT_SAVE_TEXT:
        names.append('text')
    if int(mask or 0) & SNAPSHOT_SAVE_SERIES_ZIPS:
        names.append('series_zips')
    return ','.join(names) if names else 'none'


def writeSnapshotSeriesZip(snapshotText: str, timestamp: float = 0.0, label: str = 'snapshot') -> Path:
    stamp = datetime.datetime.fromtimestamp(float(timestamp or time.time()))
    safe_label = re.sub(r'[^A-Za-z0-9_.-]+', '-', str(label or 'snapshot')).strip('-') or 'snapshot'
    digest = hashlib.md5(str(snapshotText or EMPTY_STRING).encode('utf-8', 'replace')).hexdigest()[:12]
    folder = BASE_DIR / 'snapshots'
    folder.mkdir(parents=True, exist_ok=True)
    target = folder / f'{stamp.strftime("%Y%m%d_%H%M%S")}_{safe_label}_{digest}.zip'
    member = f'{stamp.strftime("%Y%m%d_%H%M%S")}_{safe_label}.txt'
    with zipfile.ZipFile(target, 'w', compression=zipfile.ZIP_DEFLATED) as archive:
        archive.writestr(member, str(snapshotText or EMPTY_STRING))
    return target


