CLI_OPTION_SPECS: tuple[dict[str, Any], ...] = (
    *(cliOptionSpec(key, aliases) for key, aliases in _CLI_START_FLAG_ROWS),
    *(cliOptionSpec(key, aliases, consume_mode='single') for key, aliases in _CLI_START_SINGLE_ROWS),
    *(cliOptionSpec(key, aliases, consume_mode=mode) for key, aliases, mode in _CLI_START_ARG_ROWS),
    *(cliOptionSpec(key, aliases, consume_mode='flag') for key, aliases in _CLI_START_FLAG_CONSUME_ROWS),
    *(cliOptionSpec(key, aliases, scope='both', passthrough_to_child=passthrough) for key, aliases, passthrough in _CLI_BOTH_FLAG_ROWS),
    *(cliOptionSpec(key, aliases, scope='both', consume_mode=mode) for key, aliases, mode in _CLI_BOTH_VALUE_ROWS),
    *(cliOptionSpec(key, aliases, scope='child', passthrough_to_child=True) for key, aliases in _CLI_CHILD_ROWS),
)


def cliOptionSpecsForScope(*scopes: str) -> dict[str, set[str]]:
    requested = {str(scope or EMPTY_STRING).strip().lower() for scope in list(scopes or []) if str(scope or EMPTY_STRING).strip()}
    rows: dict[str, set[str]] = {}
    for spec in CLI_OPTION_SPECS:
        scope = str(spec.get('scope') or EMPTY_STRING).strip().lower()
        if scope in requested:
            aliases_raw = spec.get('aliases') or set()
            rows[str(spec.get('key') or EMPTY_STRING)] = set(cast(Iterable[str], aliases_raw)) if isinstance(aliases_raw, (set, list, tuple, frozenset)) else set()
    return rows


def cliOptionSpecForAlias(lowered: str, *, scopes=None):
    token = str(lowered or EMPTY_STRING).strip().lower()
    requested = {str(scope or EMPTY_STRING).strip().lower() for scope in list(scopes or ['start']) if str(scope or EMPTY_STRING).strip()}
    for spec in CLI_OPTION_SPECS:
        scope = str(spec.get('scope') or EMPTY_STRING).strip().lower()
        if scope not in requested:
            continue
        aliases_raw = spec.get('aliases') or set()
        aliases = set(cast(Iterable[str], aliases_raw)) if isinstance(aliases_raw, (set, list, tuple, frozenset)) else set()
        if token in aliases:
            return spec
    return None


START_VALID_FLAG_GROUPS = cliOptionSpecsForScope('start', 'both')
KNOWN_CHILD_FLAG_GROUPS = cliOptionSpecsForScope('child', 'both')
START_VALID_CLI_ALIASES = set().union(*START_VALID_FLAG_GROUPS.values(), *KNOWN_CHILD_FLAG_GROUPS.values())
