def generatedHeadlessChildPath(source_path: Path | None = None) -> Path:
    source = Path(source_path or primaryChildSourcePath())
    return source.with_name(source.stem + '.headless.py')


def _headlessQtStubNames(source_lines: list[str], start_index: int, end_index: int) -> list[str]:
    names: list[str] = []
    pattern = re.compile(r'^\s*([A-Za-z_][A-Za-z0-9_]*)\s*=\s*HeadlessQtDummy\s*$')
    for line in source_lines[start_index:end_index]:
        match = pattern.match(line.rstrip('\n'))
        if match:
            name = str(match.group(1) or EMPTY_STRING).strip()
            if name and name not in names:
                names.append(name)
    for fallback in ['QWebEngineProfile', 'QWebEngineView', 'QWebEnginePage', 'QWebChannel', 'QSoundEffect', 'QMediaPlayer', 'QAudioOutput']:
        if fallback not in names:
            names.append(fallback)
    return names


def _headlessQtStubBlock(stub_names: list[str]) -> str:
    names_literal = ', '.join(repr(name) for name in list(stub_names or []))
    return (
        "# Auto-generated Qt-free headless bootstrap\n"
        "print('[HEADLESS] Qt bootstrap stripped', flush=True)\n"
        f"_HEADLESS_QT_STUB_NAMES = [{names_literal}]\n"
        "for _qt_name in list(_HEADLESS_QT_STUB_NAMES):\n"
        "    globals().update({_qt_name: HeadlessQtDummy})\n"
        "class _HeadlessQtNamespace:\n"
        "    class AlignmentFlag:\n"
        "        AlignCenter=0\n"
        "        AlignTop=0\n"
        "        AlignLeft=0\n"
        "        AlignRight=0\n"
        "    class Orientation:\n"
        "        Horizontal=0\n"
        "        Vertical=1\n"
        "    class MouseButton:\n"
        "        LeftButton=1\n"
        "        RightButton=2\n"
        "    class CheckState:\n"
        "        Unchecked=0\n"
        "        Checked=2\n"
        "    class Key:\n"
        "        Key_F1=0\n"
        "        Key_F2=0\n"
        "        Key_F3=0\n"
        "        Key_F8=0\n"
        "        Key_F9=0\n"
        "        Key_F10=0\n"
        "        Key_F12=0\n"
        "    def __getattr__(self, name):\n"
        "        shared = HeadlessQtDummy.__dict__.get('_shared_instance')\n"
        "        if shared is None:\n"
        "            shared = HeadlessQtDummy()\n"
        "            type.__setattr__(HeadlessQtDummy, '_shared_instance', shared)\n"
        "        return shared\n"
        "Qt = _HeadlessQtNamespace()\n"
        "def Signal(*args, **kwargs):\n"
        "    return HeadlessQtDummy()\n"
        "def Slot(*args, **kwargs):\n"
        "    def decorator(fn):\n"
        "        return fn\n"
        "    return decorator\n"
        "def Property(*args, **kwargs):\n"
        "    return HeadlessQtDummy()\n"
        "HAS_QTMULTIMEDIA = False\n"
        "HAS_QTWEBENGINE = False\n"
        "HAS_QTWEBCHANNEL = False\n"
        "QSoundEffect = None\n"
        "QMediaPlayer = None\n"
        "QAudioOutput = None\n"
        "QWebEngineView = None\n"
        "QWebEnginePage = None\n"
        "QWebEngineProfile = None\n"
        "QWebChannel = None\n"
    )


def generateHeadlessChildScript(source_path: Path | None = None, *, force: bool = False) -> dict[str, object]:
    source = Path(source_path or primaryChildSourcePath())
    target = generatedHeadlessChildPath(source)
    source_text = File(source).readText()
    source_lines = source_text.splitlines(keepends=True)
    total_lines = len(source_lines)
    qt_block_start = -1
    qt_block_end = -1
    for index, line in enumerate(source_lines):
        if str(line).startswith('if not HEADLESS:') and index + 1 < len(source_lines) and 'Early Qt surface import' in str(source_lines[index + 1]):
            qt_block_start = index
            break
    if qt_block_start >= 0:
        for index in range(qt_block_start + 1, len(source_lines)):
            if str(source_lines[index]).startswith('if TRIO_OFFSCREEN_ACTIVE:'):
                qt_block_end = index
                break
    stub_names = _headlessQtStubNames(source_lines, qt_block_start, qt_block_end) if qt_block_start >= 0 and qt_block_end > qt_block_start else []
    out_lines: list[str] = []
    kept_line_count = 0
    index = 0
    header_inserted = False
    while index < len(source_lines):
        line = source_lines[index]
        if qt_block_start >= 0 and qt_block_end > qt_block_start and index == qt_block_start:
            out_lines.append(_headlessQtStubBlock(stub_names))
            index = qt_block_end
            header_inserted = True
            continue
        if any(keyword in line for keyword in HEADLESS_QT_FILTER_KEYWORDS):
            indent_match = re.match(r'^\s*', line)
            indent = indent_match.group(0) if indent_match is not None else EMPTY_STRING
            out_lines.append(f"{indent}pass  # stripped headless Qt line\n")
            index += 1
            continue
        out_lines.append(line)
        kept_line_count += 1
        index += 1
    if not header_inserted:
        out_lines.insert(0, _headlessQtStubBlock(stub_names))
    banner = (
        "# Auto-generated headless child file from trio.py\n"
        f"HEADLESS_SOURCE_TOTAL_LINES = {total_lines}\n"
        f"HEADLESS_SOURCE_KEPT_LINES = {kept_line_count}\n"
        "print(f'Running headless {HEADLESS_SOURCE_KEPT_LINES} lines / {HEADLESS_SOURCE_TOTAL_LINES}', flush=True)\n"
    )
    if out_lines and out_lines[0].startswith('#!'):
        out_lines.insert(1, banner)
    else:
        out_lines.insert(0, banner)
    rendered = ''.join(out_lines)
    if force or (not target.exists()) or File(target).readText() != rendered:
        File(target).writeText(rendered)
    return {
        'path': str(target),
        'kept_lines': kept_line_count,
        'total_lines': total_lines,
    }


def resolvedChildPath(argv=None, *, forceHeadlessGenerate: bool = False) -> Path:
    source = primaryChildSourcePath()
    tokens = _start_cli_token_list(argv)
    if cliHasAnyFlag(tokens, HEADLESS_FLAGS):
        info = generateHeadlessChildScript(source, force=forceHeadlessGenerate)
        return Path(str(info.get('path') or generatedHeadlessChildPath(source)))
    return source




