def _debuggerActionMenuText(action_spec: dict[str, Any]) -> str:
    key = str(action_spec.get('key', EMPTY_STRING) or EMPTY_STRING).strip()
    label = str(action_spec.get('label', EMPTY_STRING) or EMPTY_STRING).strip()
    if not key or not label:
        return EMPTY_STRING
    if key.upper() == 'X':
        return f'  E({key.lower()})it Child Gracefully'
    first = label[:1]
    rest = label[1:] if len(label) > 1 else EMPTY_STRING
    return f'  ({key.upper()}){first.lower()}{rest}'


def _debuggerActionHelpText(action_spec: dict[str, Any]) -> str:
    key = str(action_spec.get('key', EMPTY_STRING) or EMPTY_STRING).strip().upper()
    label = str(action_spec.get('label', EMPTY_STRING) or EMPTY_STRING).strip()
    body = str(action_spec.get('help', EMPTY_STRING) or EMPTY_STRING).strip()
    return f'{key}  {label:<18} {body}'.rstrip()


def _buildDebuggerActionSpec(action_spec: dict[str, Any]) -> dict[str, Any]:
    rendered = dict(action_spec or {})
    rendered['menu_text'] = _debuggerActionMenuText(rendered)
    rendered['help_text'] = _debuggerActionHelpText(rendered)
    return rendered


def _pluginInstallStrategies(name: str, plugin, python_exe: str) -> list[dict[str, Any]]:
    if platform.system().lower().startswith('win'):
        winget = shutil.which('winget')
        choco = shutil.which('choco')
        return [
            {'enabled': bool(winget and plugin is not None and str(getattr(plugin, 'wingetId', EMPTY_STRING) or EMPTY_STRING).strip()), 'commands': [[winget, 'install', '--id', str(getattr(plugin, 'wingetId', EMPTY_STRING) or EMPTY_STRING).strip(), '-e', '--accept-package-agreements', '--accept-source-agreements']]},
            {'enabled': bool(choco and plugin is not None and str(getattr(plugin, 'chocoId', EMPTY_STRING) or EMPTY_STRING).strip()), 'commands': [[choco, 'install', str(getattr(plugin, 'chocoId', EMPTY_STRING) or EMPTY_STRING).strip(), '-y']]},
        ]
    unix_specs = {
        'git': {
            'commands': [
                [python_exe, '-m', 'pip', 'install', '--upgrade', 'pip'],
                [python_exe, '-m', 'pip', 'install', '--upgrade', 'GitPython', 'dulwich'],
            ],
            'notes': ['[Plugin] Unix auto-install uses pip helpers and then rechecks PATH/defaults for a real git binary.'],
        },
        'github': {
            'commands': [
                [python_exe, '-m', 'pip', 'install', '--upgrade', 'pip'],
                [python_exe, '-m', 'pip', 'install', '--upgrade', 'ghapi'],
            ],
            'notes': ['[Plugin] Unix auto-install uses pip helpers and then rechecks PATH/defaults for a real gh binary.'],
        },
    }
    spec = unix_specs.get(name, {})
    return [{'enabled': bool(python_exe and spec), 'commands': list(spec.get('commands', [])), 'notes': list(spec.get('notes', []))}]


