def startManSectionName(tokens=None) -> str:
    raw_tokens = [str(value or EMPTY_STRING).strip() for value in list(tokens or []) if str(value or EMPTY_STRING).strip()]
    normalized = [token.lower() for token in raw_tokens]
    for index, token in enumerate(normalized):
        if token in {'man', '/man', '-man', '--man'}:
            if index + 1 < len(normalized):
                return START_MAN_SECTION_ALIASES.get(normalized[index + 1], 'toc')
            return 'toc'
    return 'toc'


def startUsageText() -> str:
    return START_MAN_SECTIONS['toc']


def startVersionText() -> str:
    return f'FLATLINE Debugger v{DEBUGGER_VERSION}'


def startAboutText() -> str:
    return '\n'.join([
        startVersionText(),
        'Trenton Tompkins (c) 2026',
        'https://www.triodesktop.com',
        'https://github.com/tibberous',
        'https://trentontompkins.com',
        '(724) 431-5207',
        'Call for free estimate on your next project! (Python / PHP / Mobile)',
        '<trenttompkins@gmail.com>',
        'Coded with ♥ by ChatGPT 5.4 Thinking',
        f'Base directory: {BASE_DIR}',
        'Writes: root debug.log, snapshots.txt, logs/trace.log and logs/trace-full.log,',
        '        screenshots/offscreen_*.png, and heartbeat / traffic DB rows.',
    ])


def renderVersion() -> str:
    return startVersionText()


def renderAbout() -> str:
    return startAboutText()


def startHelpText(section: str = 'toc') -> str:
    key = START_MAN_SECTION_ALIASES.get(str(section or 'toc').strip().lower(), 'toc')
    if key == 'about':
        return startAboutText()
    return START_MAN_SECTIONS.get(key, START_MAN_SECTIONS['toc'])


START_CLI_INFO_SPECS = (
    {'group': 'help', 'renderer': lambda man_section: startHelpText(man_section)},
    {'group': 'usage', 'renderer': lambda man_section: startUsageText()},
    {'group': 'about', 'renderer': lambda man_section: startAboutText()},
    {'group': 'version', 'renderer': lambda man_section: startVersionText()},
)


def runStartCliInfo(argv=None) -> int | None:
    tokens = _start_cli_token_list(argv)
    man_section = startManSectionName(tokens)
    for spec in START_CLI_INFO_SPECS:
        group = str(spec.get('group') or EMPTY_STRING)
        group_flags_raw = KNOWN_CHILD_FLAG_GROUPS.get(group, set())
        group_flags = set(group_flags_raw) if isinstance(group_flags_raw, (set, list, tuple, frozenset)) else set()
        option = readCliOption(tokens, group_flags, takesValue=False, knownAliases=START_VALID_CLI_ALIASES)
        if bool(option.get('present')):
            renderer = spec.get('renderer')
            print(str(renderer(man_section) if callable(renderer) else EMPTY_STRING), flush=True)
            try:
                sys.stdout.flush()
                sys.stderr.flush()
            except Exception:
                recordException('start.py:9408', sys.exc_info()[1])
                _traceSwallowedException('start.py:9248', sys.exc_info()[1])
                pass
            if str(os.environ.get('TRIO_CLI_INFO_SOFT_EXIT', EMPTY_STRING) or EMPTY_STRING).strip().lower() not in {'1', 'true', 'yes', 'on'}:
                os._exit(0)
            return 0
    return None


def consumeOptionalSingleValue(raw_tokens: list[str], index: int) -> int:
    position = index + 1
    if position < len(raw_tokens):
        value = str(raw_tokens[position] or EMPTY_STRING).strip()
        if value and not cliTokenLooksLikeOption(value, START_VALID_CLI_ALIASES):
            return 1
    return 0


def consumeOptionalColorValue(raw_tokens: list[str], index: int) -> int:
    def next_token(offset: int) -> str:
        position = index + offset
        if position < len(raw_tokens):
            return str(raw_tokens[position] or EMPTY_STRING).strip()
        return EMPTY_STRING
    if next_token(1) and not cliTokenLooksLikeOption(next_token(1), START_VALID_CLI_ALIASES):
        if parseFlexibleRgbSpec(next_token(1)) is not None:
            return 1
        triplet = [next_token(1), next_token(2), next_token(3)]
        if all(value and not cliTokenLooksLikeOption(value, START_VALID_CLI_ALIASES) for value in triplet):
            try:
                if parseFlexibleRgbSpec(' '.join(triplet)) is not None:
                    return 3
            except Exception:
                recordException('start.py:9440', sys.exc_info()[1])
                _traceSwallowedException('start.py:9279', sys.exc_info()[1])
                pass
        return 1
    return 0


def consumeOptionalPointerTokens(raw_tokens: list[str], index: int) -> int:
    consumed = 0
    for offset in (1, 2, 3):
        position = index + offset
        if position >= len(raw_tokens):
            break
        value = str(raw_tokens[position] or EMPTY_STRING).strip()
        if not value or cliTokenLooksLikeOption(value, START_VALID_CLI_ALIASES):
            break
        consumed += 1
    return consumed


def startOnlyOptionConsumesExtraTokens(raw_tokens: list[str], index: int, lowered: str) -> int:
    spec = cliOptionSpecForAlias(lowered, scopes=['start', 'both'])
    consume_mode = str((spec or {}).get('consume_mode') or 'none').strip().lower()
    if consume_mode in ('', 'none', 'arg', 'args'):
        return 0
    if consume_mode == 'single':
        return consumeOptionalSingleValue(raw_tokens, index)
    if consume_mode == 'color':
        return consumeOptionalColorValue(raw_tokens, index)
    if consume_mode == 'xy_or_xy_button':
        return consumeOptionalPointerTokens(raw_tokens, index)
    return 0


def parseStartCli(argv=None) -> tuple[list[str], list[str], list[str]]:
    raw_tokens = [str(token or EMPTY_STRING).strip() for token in list(argv or []) if str(token or EMPTY_STRING).strip()]
    child_tokens: list[str] = []
    passthrough_tokens: list[str] = []
    unknown_tokens: list[str] = []
    start_specs = [spec for spec in CLI_OPTION_SPECS if str(spec.get('scope') or EMPTY_STRING).strip().lower() in {'start', 'both'}]
    inline_alias_groups: list[set[str]] = []
    for spec in start_specs:
        aliases_raw = spec.get('aliases') or set()
        if isinstance(aliases_raw, (set, list, tuple, frozenset)):
            aliases = set(cast(Iterable[str], aliases_raw))
        else:
            aliases = set()
        if (not bool(spec.get('passthrough_to_child'))) and str(spec.get('consume_mode') or EMPTY_STRING).strip().lower() in {'single', 'color', 'xy_or_xy_button'}:
            inline_alias_groups.append(aliases)
    inline_value_aliases = set().union(*inline_alias_groups) if inline_alias_groups else set()
    index = 0
    while index < len(raw_tokens):
        token = str(raw_tokens[index] or EMPTY_STRING).strip()
        lowered = token.lower()
        spec = cliOptionSpecForAlias(lowered, scopes=['start'])
        if spec is not None and str(spec.get('key') or EMPTY_STRING) == 'arg':
            if index + 1 < len(raw_tokens):
                passthrough_tokens.append(str(raw_tokens[index + 1] or EMPTY_STRING).strip())
                index += 2
                continue
            unknown_tokens.append(token)
            index += 1
            continue
        if any(lowered.startswith(prefix) for prefix in tuple(alias + '=' for alias in START_ARG_FLAGS)):
            passthrough_tokens.append(stripCliValueQuotes(token.split('=', 1)[1]))
            index += 1
            continue
        if spec is not None and str(spec.get('key') or EMPTY_STRING) == 'args':
            passthrough_tokens.extend(str(item or EMPTY_STRING).strip() for item in raw_tokens[index + 1:] if str(item or EMPTY_STRING).strip())
            break
        if any(lowered.startswith(prefix) for prefix in tuple(alias + '=' for alias in START_ARGS_FLAGS)):
            payload = token.split('=', 1)[1]
            if payload.strip():
                passthrough_tokens.extend([part for part in re.split(r'[;,\s]+', payload) if str(part or EMPTY_STRING).strip()])
            index += 1
            continue
        launcher_spec = cliOptionSpecForAlias(lowered, scopes=['start', 'both'])
        if launcher_spec is not None and not bool(launcher_spec.get('passthrough_to_child')):
            index += 1 + startOnlyOptionConsumesExtraTokens(raw_tokens, index, lowered)
            continue
        if any(lowered.startswith(prefix) for prefix in tuple(alias + '=' for alias in inline_value_aliases)):
            index += 1
            continue
        child_tokens.append(token)
        flag_name = lowered.split('=', 1)[0].split(':', 1)[0]
        if (lowered.startswith('-') or lowered.startswith('/')) and flag_name not in START_VALID_CLI_ALIASES:
            unknown_tokens.append(token)
        index += 1
    return raw_tokens, child_tokens + passthrough_tokens, unknown_tokens

def normalizedCliTokens(argv=None) -> set[str]:
    return {str(token or EMPTY_STRING).strip().lower() for token in list(argv or []) if str(token or EMPTY_STRING).strip()}

def cliHasAnyFlag(argv=None, flags=None) -> bool:
    tokens = normalizedCliTokens(argv)
    for token in tokens:
        if token in set(flags or []):
            return True
    return False

def traceRequested(argv=None) -> bool:
    return cliHasAnyFlag(argv, TRACE_FLAGS)


def traceVerboseTimestampRequested(argv=None) -> bool:
    return cliHasAnyFlag(argv, TRACE_VERBOSE_TS_FLAGS)


def traceVerboseFileValue(argv=None) -> str:
    state = readCliOption(argv, TRACE_VERBOSE_FILE_FLAGS, takesValue=True, knownAliases=START_VALID_CLI_ALIASES)
    if not bool(state.get('present')):
        return EMPTY_STRING
    value = str(state.get('value') or EMPTY_STRING).strip()
    return value or 'verbose.py'


def traceVerboseRequested(argv=None) -> bool:
    return bool(cliHasAnyFlag(argv, TRACE_VERBOSE_FLAGS) or traceVerboseTimestampRequested(argv) or traceVerboseFileValue(argv))


def anyTraceRequested(argv=None) -> bool:
    return bool(traceRequested(argv) or traceVerboseRequested(argv))


def traceInterlacedRequested(argv=None) -> bool:
    return cliHasAnyFlag(argv, TRACE_INTERLACED_FLAGS)


def xdummyRequested(argv=None) -> bool:
    return cliHasAnyFlag(argv, XDUMMY_FLAGS)


def xpraRequested(argv=None) -> bool:
    return cliHasAnyFlag(argv, XPRA_FLAGS)


def requestedCaptureEngineKind(argv=None) -> str:
    if xpraRequested(argv):
        return 'xpra'
    if xdummyRequested(argv):
        return 'xdummy'
    return 'xvfb'


def offscreenRequested(argv=None) -> bool:
    return cliHasAnyFlag(argv, OFFSCREEN_FLAGS) or xdummyRequested(argv) or xpraRequested(argv)


def offscreenExitAfterActionsRequested(argv=None) -> bool:
    return bool(cliHasAnyFlag(list(argv or []), OFFSCREEN_EXIT_FLAGS))


def readRepeatedCliValues(argv=None, aliases=None, knownAliases: set[str] | None = None) -> list[str]:
    tokens = [str(token or EMPTY_STRING).strip() for token in list(argv or []) if str(token or EMPTY_STRING).strip()]
    aliasSet = {str(alias or EMPTY_STRING).strip().lower() for alias in list(aliases or []) if str(alias or EMPTY_STRING).strip()}
    results: list[str] = []
    index = 0
    while index < len(tokens):
        token = tokens[index]
        lowered = token.lower()
        matched = False
        for alias in list(aliasSet):
            if lowered == alias:
                matched = True
                if index + 1 < len(tokens) and not cliTokenLooksLikeOption(tokens[index + 1], knownAliases or aliasSet):
                    results.append(stripCliValueQuotes(tokens[index + 1]))
                    index += 2
                else:
                    index += 1
                break
            for separator in ('=', ':'):
                prefix = alias + separator
                if lowered.startswith(prefix):
                    matched = True
                    results.append(stripCliValueQuotes(token[len(alias) + 1:]))
                    index += 1
                    break
            if matched:
                break
        if not matched:
            index += 1
    return results


def parseFlexibleRgbSpec(text: str) -> tuple[int, int, int] | None:
    raw = str(text or EMPTY_STRING).strip()
    if not raw:
        return None
    lowered = raw.lower().strip()
    if lowered in {'transparent', 'none', 'clear'}:
        return (0, 0, 0)
    named_hex = getattr(getattr(EmbeddedData, "ColorLibrary"), "ResolveHex")(raw)
    if named_hex:
        lowered = str(named_hex or EMPTY_STRING).strip().lstrip('#').lower()
    else:
        lowered = lowered.lstrip('#')
    if re.fullmatch(r'[0-9a-f]{1}', lowered):
        channel = lowered * 2
        value = int(channel, 16)
        return (value, value, value)
    if re.fullmatch(r'[0-9a-f]{2}', lowered):
        value = int(lowered, 16)
        return (value, value, value)
    if re.fullmatch(r'[0-9a-f]{3}', lowered):
        return (int(lowered[0] * 2, 16), int(lowered[1] * 2, 16), int(lowered[2] * 2, 16))
    if re.fullmatch(r'[0-9a-f]{4}', lowered):
        expanded = ''.join(ch * 2 for ch in lowered)
        return (int(expanded[0:2], 16), int(expanded[2:4], 16), int(expanded[4:6], 16))
    if re.fullmatch(r'[0-9a-f]{6,8}', lowered):
        return (int(lowered[0:2], 16), int(lowered[2:4], 16), int(lowered[4:6], 16))
    parts = [part for part in re.split(r'[\s,;x]+', raw) if str(part or EMPTY_STRING).strip()]
    if len(parts) == 3:
        try:
            rgb = [max(0, min(255, int(float(part)))) for part in parts]
            return (int(rgb[0]), int(rgb[1]), int(rgb[2]))
        except Exception:
            recordException('start.py:9646', sys.exc_info()[1])
            _traceSwallowedException('start.py:9480', sys.exc_info()[1])
            return None
    return None


def parseBackgroundAlphaFloat(rawValue: str = EMPTY_STRING, defaultFloat: float = 0.0) -> float:
    text = str(rawValue or EMPTY_STRING).strip().lower()
    if not text:
        try:
            return max(0.0, min(1.0, float(defaultFloat or 0.0)))
        except Exception:
            recordException('start.py:9657', sys.exc_info()[1])
            return 0.0
    if text in {'transparent', 'none', 'clear'}:
        return 0.0
    numeric = None
    if text.startswith('#'):
        raw = text[1:]
        if re.fullmatch(r'[0-9a-f]{1,2}', raw):
            numeric = int(raw, 16) / 255.0
    elif text.startswith('0x'):
        raw = text[2:]
        if re.fullmatch(r'[0-9a-f]{1,2}', raw):
            numeric = int(raw, 16) / 255.0
    elif re.fullmatch(r'0[0-9]+', text):
        numeric = int(text, 10) / 255.0
    if numeric is not None:
        return max(0.0, min(1.0, float(numeric)))
    try:
        numeric = float(text.rstrip('%').strip())
    except Exception:
        recordException('start.py:9676', sys.exc_info()[1])
        try:
            return max(0.0, min(1.0, float(defaultFloat or 0.0)))
        except Exception:
            recordException('start.py:9679', sys.exc_info()[1])
            return 0.0
    if text.endswith('%'):
        value = float(numeric) / 100.0
    elif float(numeric) <= 1.0:
        value = float(numeric)
    else:
        value = float(numeric) / 100.0
    return max(0.0, min(1.0, float(value)))


def parseBackgroundAlpha(rawValue: str = EMPTY_STRING, defaultPercent: float = 0.0) -> int:
    default_float = max(0.0, min(1.0, float(defaultPercent or 0.0) / 100.0))
    return max(0, min(255, int(round(parseBackgroundAlphaFloat(rawValue, defaultFloat=default_float) * 255.0))))



def _cliAliasTokenMatch(token: str, aliases) -> tuple[str, bool] | None:
    text = str(token or EMPTY_STRING)
    lowered = text.lower()
    for alias in list(aliases or []):
        alias_text = str(alias or EMPTY_STRING).strip().lower()
        if not alias_text:
            continue
        if lowered == alias_text:
            return EMPTY_STRING, False
        for separator in ('=', ':'):
            prefix = alias_text + separator
            if lowered.startswith(prefix):
                return stripCliValueQuotes(text[len(alias_text) + 1:]), True
    return None


def _consumeCliTextValue(tokens: list[str], index: int, aliases) -> tuple[bool, int, str]:
    if index < 0 or index >= len(tokens):
        return False, index, EMPTY_STRING
    match = _cliAliasTokenMatch(tokens[index], aliases)
    if match is None:
        return False, index, EMPTY_STRING
    inline_value, inline = match
    if inline:
        return True, index + 1, str(inline_value or EMPTY_STRING)
    if index + 1 < len(tokens) and not cliTokenLooksLikeOption(tokens[index + 1], START_VALID_CLI_ALIASES):
        return True, index + 2, stripCliValueQuotes(tokens[index + 1])
    return True, index + 1, EMPTY_STRING


def _consumeCliTextPieces(tokens: list[str], index: int, aliases, *, max_pieces: int = 1) -> tuple[bool, int, list[str]]:
    if index < 0 or index >= len(tokens):
        return False, index, []
    match = _cliAliasTokenMatch(tokens[index], aliases)
    if match is None:
        return False, index, []
    inline_value, inline = match
    if inline:
        value = str(inline_value or EMPTY_STRING).strip()
        pieces = [value] if value else []
        return True, index + 1, pieces
    pieces: list[str] = []
    cursor = index + 1
    while cursor < len(tokens) and len(pieces) < max(1, int(max_pieces or 1)) and not cliTokenLooksLikeOption(tokens[cursor], START_VALID_CLI_ALIASES):
        value = stripCliValueQuotes(tokens[cursor])
        if value:
            pieces.append(value)
        cursor += 1
    return True, cursor, pieces


def _splitCliCoordinateParts(text) -> list[str]:
    return [part for part in re.split(r'[\s,;x]+', str(text or EMPTY_STRING)) if str(part or EMPTY_STRING).strip()]


def _buildOffscreenClickAction(payload) -> dict[str, Any] | None:
    parts = _splitCliCoordinateParts(' '.join(list(payload or [])))
    if len(parts) < 2:
        return None
    try:
        return {'kind': 'click', 'x': int(float(parts[0])), 'y': int(float(parts[1])), 'button': int(float(parts[2])) if len(parts) >= 3 else 1}
    except Exception:
        recordException('start.py:9757', sys.exc_info()[1])
        _traceSwallowedException('start.py:9590', sys.exc_info()[1])
        return None


def _buildOffscreenMoveAction(payload) -> dict[str, Any] | None:
    parts = _splitCliCoordinateParts(' '.join(list(payload or [])))
    if len(parts) < 2:
        return None
    try:
        return {'kind': 'move', 'x': int(float(parts[0])), 'y': int(float(parts[1]))}
    except Exception:
        recordException('start.py:9768', sys.exc_info()[1])
        _traceSwallowedException('start.py:9600', sys.exc_info()[1])
        return None


def _buildOffscreenWaitAction(payload) -> dict[str, Any] | None:
    try:
        delay = float(str(payload or EMPTY_STRING).strip())
    except Exception:
        recordException('start.py:9776', sys.exc_info()[1])
        delay = None
    if delay is None:
        return None
    return {'kind': 'wait', 'seconds': max(0.0, float(delay))}


def _buildOffscreenValueAction(kind: str, payload) -> dict[str, Any] | None:
    value = str(payload or EMPTY_STRING).strip()
    if not value:
        return None
    return {'kind': kind, 'value': value}


def _offscreenActionSpecs() -> list[dict[str, Any]]:
    return [
        {'aliases': OFFSCREEN_CLICK_FLAGS, 'consumer': 'pieces', 'max_pieces': 3, 'builder': _buildOffscreenClickAction},
        {'aliases': OFFSCREEN_MOVE_FLAGS, 'consumer': 'pieces', 'max_pieces': 2, 'builder': _buildOffscreenMoveAction},
        {'aliases': OFFSCREEN_WAIT_FLAGS, 'consumer': 'value', 'builder': _buildOffscreenWaitAction},
        {'aliases': OFFSCREEN_KEY_FLAGS, 'consumer': 'value', 'builder': lambda payload: _buildOffscreenValueAction('key', payload)},
        {'aliases': OFFSCREEN_TYPE_FLAGS, 'consumer': 'value', 'builder': lambda payload: _buildOffscreenValueAction('type', payload)},
    ]


def _backgroundColorPayloadToRgb(payload) -> tuple[int, int, int] | None:
    pieces = list(payload or [])
    if not pieces:
        return None
    return parseFlexibleRgbSpec(' '.join(pieces)) or parseFlexibleRgbSpec(pieces[0])


def parseBackgroundColorAndAlpha(argv=None) -> tuple[tuple[int, int, int] | None, int]:
    tokens = [str(token or EMPTY_STRING).strip() for token in list(argv or []) if str(token or EMPTY_STRING).strip()]
    state = {'color': None, 'alpha_token': EMPTY_STRING, 'alpha_provided': False}
    spec_walk = (
        {'field': 'color', 'consumer': lambda index: _consumeCliTextPieces(tokens, index, BG_COLOR_FLAGS, max_pieces=3)},
        {'field': 'alpha', 'consumer': lambda index: _consumeCliTextValue(tokens, index, BG_ALPHA_FLAGS)},
    )
    index = 0
    while index < len(tokens):
        matched = False
        for spec in spec_walk:
            found, cursor, payload = spec['consumer'](index)
            if not found:
                continue
            matched = True
            if spec['field'] == 'color':
                candidate = _backgroundColorPayloadToRgb(payload)
                if candidate is not None:
                    state['color'] = candidate
            else:
                state['alpha_provided'] = True
                state['alpha_token'] = str(payload or EMPTY_STRING)
            index = cursor
            break
        if not matched:
            index += 1
    if state['color'] is None and state['alpha_provided']:
        state['color'] = (255, 255, 255)
    alpha = parseBackgroundAlpha(state['alpha_token'], defaultPercent=100.0 if state['color'] is not None else 0.0)
    return state['color'], alpha

def parseOffscreenActionPlan(argv=None) -> list[dict[str, Any]]:
    tokens = [str(token or EMPTY_STRING).strip() for token in list(argv or []) if str(token or EMPTY_STRING).strip()]
    plan: list[dict[str, Any]] = []
    specs = _offscreenActionSpecs()
    index = 0
    while index < len(tokens):
        matched = False
        for spec in specs:
            consumer = str(spec.get('consumer') or EMPTY_STRING).strip().lower()
            if consumer == 'pieces':
                found, cursor, payload = _consumeCliTextPieces(tokens, index, spec.get('aliases'), max_pieces=int(spec.get('max_pieces') or 1))
            else:
                found, cursor, payload = _consumeCliTextValue(tokens, index, spec.get('aliases'))
            if not found:
                continue
            matched = True
            action = spec['builder'](payload)
            if action is not None:
                plan.append(action)
            index = cursor
            break
        if not matched:
            index += 1
    return plan


def prepareTraceEnvironment(argv, env: MutableMapping[str, str], debugWritesAllowed: bool = False) -> None:
    trace_requested = bool(anyTraceRequested(argv))
    trace_verbose_requested = bool(traceVerboseRequested(argv))
    trace_verbose_ts_requested = bool(traceVerboseTimestampRequested(argv))
    trace_verbose_file_value = str(traceVerboseFileValue(argv) or EMPTY_STRING).strip()
    trace_env_allowed = bool(debugWritesAllowed or trace_requested or trace_verbose_requested or trace_verbose_ts_requested or trace_verbose_file_value)
    trace_keys = ('TRIO_TRACE_ENABLED', 'TRIO_TRACE_EARLY', 'TRIO_TRACE_SOURCE_PATH', 'TRIO_TRACE_TOTAL_LINES', 'TRIO_TRACE_LOG_PATH', 'TRIO_TRACE_FULL_LOG_PATH', 'TRIO_TRACE_MODE', 'TRIO_TRACE_VERBOSE', 'TRIO_TRACE_VERBOSE_TS', 'TRIO_TRACE_VERBOSE_LIVE', 'TRIO_TRACE_VERBOSE_FILE_PATH', 'TRIO_TRACE_BUFFER_SIZE', 'TRIO_TRACE_VERBOSE_FILE_BUFFER_LIMIT', 'TRIO_TRACE_INTERLACED')
    if offscreenRequested(argv) and (trace_requested or trace_verbose_requested or trace_verbose_ts_requested) and not cliHasAnyFlag(argv, buildCliAliasSet('trace-force', 'trace-verbose-force', 'force-trace', 'force-verbose-trace')):
        print('[WARN:trace] Offscreen child trace disabled so GUI construction can paint; parent debug.log and child stdout/stderr relay remain active. Use --trace-force to override.', file=sys.stderr, flush=True)
        for key in trace_keys:
            env.pop(key, None)
        return
    if not trace_env_allowed:
        for key in trace_keys:
            env.pop(key, None)
        return
    if not (trace_requested or trace_verbose_requested or trace_verbose_ts_requested or trace_verbose_file_value):
        for key in trace_keys:
            env.pop(key, None)
        return
    try:
        source_text = File(GTP_PATH).readText()
        total_lines = len(source_text.splitlines())
    except Exception:
        recordException('start.py:9882', sys.exc_info()[1])
        total_lines = 0
    child_trace_verbose_requested = bool(trace_verbose_requested)
    child_trace_verbose_ts_requested = bool(trace_verbose_ts_requested)
    if offscreenRequested(argv) and trace_verbose_requested and not cliHasAnyFlag(argv, buildCliAliasSet('trace-verbose-force', 'force-verbose-trace')):
        print('[WARN:trace] --offscreen --verbose-trace would line-trace GUI construction and can prevent the window from painting. Downgrading child to normal trace; use --trace-verbose-force to override.', file=sys.stderr, flush=True)
        child_trace_verbose_requested = False
        child_trace_verbose_ts_requested = False
    trace_dir = launcherLogDir(env)
    trace_log_path = trace_dir / 'trace.log'
    trace_full_log_path = trace_dir / 'trace-full.log'
    trace_verbose_file_path = Path(trace_verbose_file_value).expanduser() if trace_verbose_file_value else (trace_dir / 'verbose.py')
    if trace_verbose_file_value and not trace_verbose_file_path.is_absolute():
        trace_verbose_file_path = (BASE_DIR / trace_verbose_file_path).resolve()
    else:
        trace_verbose_file_path = trace_verbose_file_path.resolve()
    try:
        trace_log_path.parent.mkdir(parents=True, exist_ok=True)
        trace_full_log_path.parent.mkdir(parents=True, exist_ok=True)
        trace_verbose_file_path.parent.mkdir(parents=True, exist_ok=True)
        File(trace_log_path).writeText(EMPTY_STRING)
        File(trace_full_log_path).writeText(EMPTY_STRING)
        if child_trace_verbose_requested:
            File(trace_verbose_file_path).writeText(EMPTY_STRING)
    except Exception:
        recordException('start.py:9900', sys.exc_info()[1])
        _traceSwallowedException('start.py:9731', sys.exc_info()[1])
        pass
    tokens = normalizedCliTokens(argv)
    regular_trace_requested = bool(traceRequested(argv))
    trace_mode = 'headless-verbose-ts' if child_trace_verbose_ts_requested else ('headless-verbose' if child_trace_verbose_requested else 'trace')
    if not any(flag in tokens for flag in HEADLESS_FLAGS):
        trace_mode = 'qt-verbose-ts' if child_trace_verbose_ts_requested else ('qt-verbose' if child_trace_verbose_requested else 'qt')
    elif regular_trace_requested and not child_trace_verbose_requested and not child_trace_verbose_ts_requested:
        trace_mode = 'qt-headless'
    trace_buffer_size = traceBufferSizeFromConfig(default=50)
    env['TRIO_TRACE_ENABLED'] = '1'
    env['TRIO_TRACE_EARLY'] = '1'
    env['TRIO_TRACE_SOURCE_PATH'] = str(GTP_PATH.resolve())
    env['TRIO_TRACE_TOTAL_LINES'] = str(int(total_lines or 0))
    env['TRIO_TRACE_LOG_PATH'] = str(trace_log_path.resolve())
    env['TRIO_TRACE_FULL_LOG_PATH'] = str(trace_full_log_path.resolve())
    env['TRIO_TRACE_MODE'] = trace_mode
    env['TRIO_TRACE_VERBOSE'] = '1' if child_trace_verbose_requested else '0'
    env['TRIO_TRACE_VERBOSE_TS'] = '1' if child_trace_verbose_ts_requested else '0'
    env['TRIO_TRACE_VERBOSE_LIVE'] = '1' if cliHasAnyFlag(argv, buildCliAliasSet('trace-verbose-live', 'mtrace-live')) else '0'
    env['TRIO_TRACE_VERBOSE_FILE_PATH'] = str(trace_verbose_file_path) if child_trace_verbose_requested else EMPTY_STRING
    env['TRIO_TRACE_BUFFER_SIZE'] = str(trace_buffer_size)
    env['TRIO_TRACE_VERBOSE_FILE_BUFFER_LIMIT'] = str(trace_buffer_size)
    env['TRIO_TRACE_INTERLACED'] = '1' if traceInterlacedRequested(argv) else '0'



class CaptureEngine:
    ENGINE_KIND = 'capture'
    DEFAULT_SCREEN = '1920x1080x24'

    def __init__(self, owner=None, screenSpec: str = EMPTY_STRING, backgroundColor=None, backgroundAlpha: int = 0):
        self.owner = owner
        self.screenSpec = self.normalizeScreenSpec(screenSpec)
        self.displayNumber = 0
        self.displayName = EMPTY_STRING
        self.tempDir = None
        self.xauthorityPath = EMPTY_STRING
        self.framebufferDir = EMPTY_STRING
        self.proc = None
        self.ready = False
        self.windowCache = {}
        self.backgroundColor = tuple(backgroundColor[:3]) if isinstance(backgroundColor, (tuple, list)) and len(backgroundColor) >= 3 else None
        self.backgroundAlpha = max(0, min(255, int(backgroundAlpha or 0)))
        self.compositorProc = None
        self.compositorName = EMPTY_STRING
        self.experimentalAlphaActive = False

    def toolPath(self, name: str) -> str:
        tool_name = str(name or EMPTY_STRING).strip()
        path = str(shutil.which(tool_name) or EMPTY_STRING)
        if not path:
            return EMPTY_STRING
        if tool_name == 'xdotool':
            try:
                probe = monitoredRawPopen([path, '--version'], sourceLine='CaptureEngine.toolPath xdotool --version', windowPolicy=WINDOW_POLICY_HELPER, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, stdin=subprocess.DEVNULL)
                code = probe.wait(timeout=2)
                if int(code or 0) != 0:
                    return EMPTY_STRING
            except Exception:
                recordException('start.py:9959', sys.exc_info()[1])
                return EMPTY_STRING
        return path

    def hasTool(self, name: str) -> bool:
        return bool(self.toolPath(name))

    def requireTool(self, name: str) -> str:
        path = self.toolPath(name)
        if not path:
            raise RuntimeError(f'Missing required offscreen tool: {name}')
        return path

    def emit(self, text: str, path: str = EMPTY_STRING) -> None:
        owner = getattr(self, 'owner', None)
        if owner is not None and callable(getattr(owner, 'emit', None)):
            owner.emit(text, path or getattr(owner, 'logPath', EMPTY_STRING))
            return
        print(str(text or EMPTY_STRING), flush=True)

    def normalizeScreenSpec(self, rawValue: str = EMPTY_STRING) -> str:
        text = str(rawValue or EMPTY_STRING).strip().lower()
        if not text:
            return self.DEFAULT_SCREEN
        match = re.match(r'^(\d{2,5})x(\d{2,5})(?:x(\d{1,2}))?$', text)
        if not match:
            return self.DEFAULT_SCREEN
        width = max(320, int(match.group(1) or 1920))
        height = max(200, int(match.group(2) or 1080))
        depth = int(match.group(3) or 24)
        if depth <= 0:
            depth = 24
        return f'{width}x{height}x{depth}'

    def parseScreenSpec(self) -> tuple[int, int, int]:
        match = re.match(r'^(\d{2,5})x(\d{2,5})(?:x(\d{1,2}))?$', str(self.screenSpec or self.DEFAULT_SCREEN).strip().lower())
        if not match:
            return (1920, 1080, 24)
        width = max(320, int(match.group(1) or 1920))
        height = max(200, int(match.group(2) or 1080))
        depth = max(8, int(match.group(3) or 24))
        return (width, height, depth)

    def windowGeometryArgument(self) -> str:
        width, height, _ = self.parseScreenSpec()
        return f'{width}x{height}+0+0'

    def screenDimensions(self) -> tuple[int, int]:
        width, height, _ = self.parseScreenSpec()
        return (width, height)

    def chooseDisplayNumber(self, start: int = 99, end: int = 140) -> int:
        xdpyinfo = self.toolPath('xdpyinfo')
        for number in range(int(start), int(end) + 1):
            socketPath = Path(f'/tmp/.X11-unix/X{number}')
            if socketPath.exists():
                continue
            if xdpyinfo:
                probe = launcherRunCommand([xdpyinfo, '-display', f':{number}'], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, check=False)
                if int(getattr(probe, 'returncode', 1)) == 0:
                    continue
            return number
        raise RuntimeError('Could not find a free offscreen X11 display number in :99-:140')

    def makeCookie(self) -> str:
        return os.urandom(16).hex()

    def buildEnvironment(self, baseEnv: dict | None = None) -> dict:
        env = dict(baseEnv or os.environ.copy())
        env['DISPLAY'] = str(self.displayName or EMPTY_STRING)
        env['XAUTHORITY'] = str(self.xauthorityPath or EMPTY_STRING)
        engineKind = str(getattr(self, 'ENGINE_KIND', EMPTY_STRING) or EMPTY_STRING).strip().lower()
        managedX11Kinds = {'xvfb', 'xdummy', 'xpra'}
        managedX11 = bool(engineKind in managedX11Kinds)
        env['TRIO_MANAGED_DISPLAY'] = '1'
        env['TRIO_CAPTURE_ENGINE'] = engineKind or 'xvfb'
        env['TRIO_OFFSCREEN'] = '0' if managedX11 else '1'
        if self.backgroundColor is not None:
            env['TRIO_BG_ACTIVE'] = '1'
            env['TRIO_BG_COLOR'] = '#%02x%02x%02x' % (
                int(self.backgroundColor[0]),
                int(self.backgroundColor[1]),
                int(self.backgroundColor[2]),
            )
            env['TRIO_BG_ALPHA'] = str(max(0, min(255, int(self.backgroundAlpha or 0))))
            env['TRIO_BG_ALPHA_FLOAT'] = f"{max(0.0, min(1.0, float(int(self.backgroundAlpha or 0)) / 255.0)):.4f}"
        else:
            env.pop('TRIO_BG_ACTIVE', None)
            env.pop('TRIO_BG_COLOR', None)
            env.pop('TRIO_BG_ALPHA', None)
            env.pop('TRIO_BG_ALPHA_FLOAT', None)
        env['TRIO_XPRA_ALPHA_CAPABLE'] = '1' if engineKind == 'xpra' else '0'
        env['TRIO_EXPERIMENTAL_ALPHA_CAPABLE'] = '1' if self.wantsExperimentalAlpha() and bool(getattr(self, 'experimentalAlphaActive', False)) else '0'
        if os.name != 'nt':
            prependEnvPathList(env, 'LD_LIBRARY_PATH', packagedLinuxRuntimeLibDirs())
            if managedX11:
                platformName = 'xcb'
            else:
                platformName = str(packagedQtPlatformName('offscreen') or 'offscreen').strip() or 'offscreen'
            env['TRIO_QT_PLATFORM'] = platformName
            env['QT_QPA_PLATFORM'] = platformName
            env.setdefault('QT_XCB_GL_INTEGRATION', 'none')
            env.setdefault('QT_OPENGL', 'software')
            env.setdefault('LIBGL_ALWAYS_SOFTWARE', '1')
            env.setdefault('QTWEBENGINE_DISABLE_SANDBOX', '1')
        return env

    def waitUntilReady(self, timeoutSeconds: float = 8.0) -> bool:
        xdpyinfo = self.requireTool('xdpyinfo')
        deadline = time.time() + float(timeoutSeconds or 8.0)
        while time.time() < deadline:
            if self.proc is not None and self.proc.poll() is not None:
                raise RuntimeError(f'Offscreen X11 server exited early with code {self.proc.returncode}')
            result = launcherRunCommand(
                [xdpyinfo, '-display', self.displayName],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                env=self.buildEnvironment(),
                check=False,
            )
            if int(getattr(result, 'returncode', 1)) == 0:
                self.ready = True
                return True
            time.sleep(0.10)
        raise RuntimeError(f'Offscreen X11 server did not become ready on {self.displayName}')

    def wantsExperimentalAlpha(self) -> bool:
        engine_kind = str(getattr(self, 'ENGINE_KIND', EMPTY_STRING) or EMPTY_STRING).strip().lower()
        return bool(engine_kind in {'xvfb', 'xdummy'} and self.backgroundColor is not None and 0 < int(self.backgroundAlpha or 0) < 255)

    def compositorCommand(self) -> list[str]:
        picom = self.toolPath('picom')
        if picom:
            self.compositorName = 'picom'
            return [
                picom,
                '--backend', 'xrender',
                '--vsync', 'none',
                '--config', '/dev/null',
                '--log-level', 'warn',
                '--shadow=false',
                '--fading=false',
                '--inactive-opacity=1.0',
                '--active-opacity=1.0',
                '--frame-opacity=1.0',
                '--detect-client-opacity=false',
            ]
        xcompmgr = self.toolPath('xcompmgr') or self.toolPath('compton')
        if xcompmgr:
            self.compositorName = Path(xcompmgr).name
            return [xcompmgr, '-a']
        self.compositorName = EMPTY_STRING
        return []

    def startExperimentalAlphaSupport(self) -> bool:
        self.experimentalAlphaActive = False
        if not self.wantsExperimentalAlpha():
            return False
        self.emit('[WARN:offscreen] This feature is experimental. For native support use --xpra.', getattr(self.owner, 'logPath', EMPTY_STRING))
        command = self.compositorCommand()
        if not command:
            self.emit('[WARN:offscreen] Experimental alpha requested, but no compositor tool was found (picom/xcompmgr). Falling back to opaque/background-only behavior.', getattr(self.owner, 'logPath', EMPTY_STRING))
            return False
        try:
            self.compositorProc = launcherStartProcess(
                command,
                cwd=str(BASE_DIR),
                stdin=subprocess.DEVNULL,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                env=self.buildEnvironment(),
                start_new_session=True,
            )
            time.sleep(0.20)
            if self.compositorProc is not None and self.compositorProc.poll() is None:
                self.experimentalAlphaActive = True
                self.emit(f'[FlatLineDebugger.debugger] Experimental alpha compositor ready  engine={self.ENGINE_KIND}  compositor={self.compositorName}', getattr(self.owner, 'logPath', EMPTY_STRING))
                return True
            self.emit(f'[WARN:offscreen] Experimental alpha compositor exited immediately: {self.compositorName or "(unknown)"}', getattr(self.owner, 'logPath', EMPTY_STRING))
        except Exception as error:
            recordException('start.py:10138', sys.exc_info()[1])
            self.emit(f'[WARN:offscreen] Experimental alpha compositor failed: {type(error).__name__}: {error}', getattr(self.owner, 'logPath', EMPTY_STRING))
        return False

    def stopExperimentalAlphaSupport(self) -> None:
        proc = getattr(self, 'compositorProc', None)
        self.compositorProc = None
        self.experimentalAlphaActive = False
        if proc is not None:
            try:
                if proc.poll() is None:
                    proc.terminate()
                    proc.wait(timeout=2.0)
            except Exception:
                recordException('start.py:10151', sys.exc_info()[1])
                try:
                    proc.kill()
                except Exception:
                    recordException('start.py:10154', sys.exc_info()[1])
                    _traceSwallowedException('start.py:9972', sys.exc_info()[1])
                    pass
        self.compositorName = EMPTY_STRING

    def start(self) -> bool:
        if os.name == 'nt':
            raise RuntimeError('Managed offscreen X11 capture engines are only supported on Linux/X11')
        if self.proc is not None and self.proc.poll() is None and self.ready:
            return True
        xvfb = self.requireTool('Xvfb')
        self.requireTool('xauth')
        self.requireTool('xdpyinfo')
        self.tempDir = tempfile.TemporaryDirectory(prefix='trio-xvfb-')
        tempPath = Path(self.tempDir.name)
        self.displayNumber = self.chooseDisplayNumber()
        self.displayName = f':{self.displayNumber}'
        self.xauthorityPath = str(tempPath / 'Xauthority')
        self.framebufferDir = str(tempPath / 'fb')
        Path(self.framebufferDir).mkdir(parents=True, exist_ok=True)
        cookie = self.makeCookie()
        xauth = self.requireTool('xauth')
        Path(self.xauthorityPath).touch()
        command = [xauth, '-f', self.xauthorityPath, 'add', self.displayName, '.', cookie]
        result = launcherRunCommand(command, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, check=False)
        if int(getattr(result, 'returncode', 1)) != 0:
            raise RuntimeError(f'Failed preparing Xauthority for {self.displayName}')
        command = [
            xvfb,
            self.displayName,
            '-screen', '0', self.screenSpec,
            '-auth', self.xauthorityPath,
            '-fbdir', self.framebufferDir,
            '-nolisten', 'tcp',
            '+extension', 'Composite',
            '+extension', 'RENDER',
            '+extension', 'DAMAGE',
            '+extension', 'GLX',
        ]
        self.proc = launcherStartProcess(
            command,
            cwd=str(BASE_DIR),
            stdin=subprocess.DEVNULL,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            env=self.buildEnvironment(),
            start_new_session=True,
        )
        self.waitUntilReady()
        self.startExperimentalAlphaSupport()
        self.emit(f'[FlatLineDebugger.debugger] Offscreen Xvfb ready  display={self.displayName}  screen={self.screenSpec}', getattr(self.owner, 'logPath', EMPTY_STRING))
        return True

    def stop(self) -> bool:
        self.stopExperimentalAlphaSupport()
        proc = self.proc
        self.proc = None
        self.ready = False
        if proc is not None:
            try:
                if proc.poll() is None:
                    proc.terminate()
                    proc.wait(timeout=2.0)
            except Exception:
                recordException('start.py:10217', sys.exc_info()[1])
                try:
                    proc.kill()
                except Exception:
                    recordException('start.py:10220', sys.exc_info()[1])
                    _traceSwallowedException('start.py:10037', sys.exc_info()[1])
                    pass
        tempDir = self.tempDir
        self.tempDir = None
        if tempDir is not None:
            try:
                tempDir.cleanup()
            except Exception:
                recordException('start.py:10228', sys.exc_info()[1])
                _traceSwallowedException('start.py:10044', sys.exc_info()[1])
                pass
        return True

    def framebufferSnapshotPath(self) -> str:
        if not self.framebufferDir or not self.displayNumber:
            return EMPTY_STRING
        candidate = Path(self.framebufferDir) / 'Xvfb_screen0'
        if candidate.exists():
            return str(candidate)
        return EMPTY_STRING

    def rgbPixel(self, rgbBytes: bytes, width: int, x: int, y: int) -> tuple[int, int, int]:
        index = ((int(y) * int(width)) + int(x)) * 3
        chunk = bytes(rgbBytes[index:index + 3])
        r = int(chunk[0]) if chunk else 0
        g = int(chunk[1]) if len(chunk) > 1 else 0
        b = int(chunk[2]) if len(chunk) > 2 else 0
        return r, g, b

    def cropRgbBuffer(self, width: int, height: int, rgbBytes: bytes, x: int, y: int, cropWidth: int, cropHeight: int) -> tuple[int, int, bytes]:
        sourceWidth = int(width or 0)
        sourceHeight = int(height or 0)
        left = max(0, min(sourceWidth, int(x or 0)))
        top = max(0, min(sourceHeight, int(y or 0)))
        right = max(left, min(sourceWidth, left + max(1, int(cropWidth or 0))))
        bottom = max(top, min(sourceHeight, top + max(1, int(cropHeight or 0))))
        targetWidth = max(1, right - left)
        targetHeight = max(1, bottom - top)
        rowStride = sourceWidth * 3
        cropped = bytearray(targetWidth * targetHeight * 3)
        targetOffset = 0
        for rowIndex in range(top, bottom):
            start = (rowIndex * rowStride) + (left * 3)
            end = start + (targetWidth * 3)
            segment = rgbBytes[start:end]
            cropped[targetOffset:targetOffset + len(segment)] = segment
            targetOffset += len(segment)
        return targetWidth, targetHeight, bytes(cropped)

    def windowGeometry(self, windowId: str) -> dict[str, int]:
        token = str(windowId or EMPTY_STRING).strip()
        if not token:
            return {}
        cached = self.windowCache.get(token)
        if isinstance(cached, dict) and cached.get('width') and cached.get('height'):
            return dict(cached)
        xwininfo = self.toolPath('xwininfo')
        if not xwininfo:
            return {}
        result = launcherRunCommand([xwininfo, '-display', self.displayName, '-id', token], capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
        if int(getattr(result, 'returncode', 1)) != 0:
            return {}
        stdout = str(result.stdout or EMPTY_STRING)
        def read_int(label: str) -> int:
            match = re.search(rf'{re.escape(label)}:\s*(-?\d+)', stdout)
            return int(match.group(1)) if match else 0
        geometry = {
            'x': read_int('Absolute upper-left X'),
            'y': read_int('Absolute upper-left Y'),
            'width': read_int('Width'),
            'height': read_int('Height'),
        }
        if geometry['width'] > 0 and geometry['height'] > 0:
            self.windowCache[token] = dict(geometry)
            return dict(geometry)
        return {}

    def activeWindowId(self) -> str:
        xprop = self.toolPath('xprop')
        if not xprop:
            return EMPTY_STRING
        result = launcherRunCommand([xprop, '-display', self.displayName, '-root', '_NET_ACTIVE_WINDOW'], capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
        match = re.search(r'(0x[0-9a-fA-F]+)', str(result.stdout or EMPTY_STRING))
        token = str(match.group(1) if match else EMPTY_STRING).strip()
        if token.lower() in {'0x0', '0'}:
            return EMPTY_STRING
        return token

    def bestChildWindow(self, pid: int = 0) -> dict[str, Any]:
        activeId = self.activeWindowId()
        best: dict[str, Any] = {}
        bestScore = -1
        for entry in self.findChildWindows(pid):
            windowId = str(entry.get('id', EMPTY_STRING) or EMPTY_STRING).strip()
            if not windowId:
                continue
            geometry = self.windowGeometry(windowId)
            width = int(geometry.get('width', 0) or 0)
            height = int(geometry.get('height', 0) or 0)
            if width < 64 or height < 64:
                continue
            title = str(entry.get('title', EMPTY_STRING) or EMPTY_STRING).strip().lower()
            area = width * height
            bonus = 0
            if windowId == activeId:
                bonus += 15000000
            if 'help center' in title:
                bonus += 10000000
            if 'trio' in title:
                bonus += 5000000
            if 'desktop' in title:
                bonus += 2500000
            if 'root window' in title or 'has no name' in title:
                bonus -= 10000000
            score = area + bonus
            if score > bestScore:
                bestScore = score
                best = {'id': windowId, 'title': title, 'geometry': geometry}
        return best

    def backgroundReplacementRgba(self, rootRgb: tuple[int, int, int]) -> tuple[int, int, int, int] | None:
        if self.backgroundColor is not None:
            return (int(self.backgroundColor[0]), int(self.backgroundColor[1]), int(self.backgroundColor[2]), int(self.backgroundAlpha))
        if tuple(int(value) for value in rootRgb) == (0, 0, 0):
            return (0, 0, 0, 0)
        return None

    def writeRgbaPng(self, outputPath: str | Path, width: int, height: int, rgbaBytes: bytes) -> str:
        target = Path(outputPath)
        target.parent.mkdir(parents=True, exist_ok=True)
        expected = int(width or 0) * int(height or 0) * 4
        if len(rgbaBytes) != expected:
            raise RuntimeError(f'RGBA payload length mismatch: expected {expected}, got {len(rgbaBytes)}')
        def chunk(tag: bytes, payload: bytes) -> bytes:
            crc = zlib.crc32(tag + payload) & 0xffffffff
            return struct.pack('>I', len(payload)) + tag + payload + struct.pack('>I', crc)
        scanlines = bytearray()
        stride = width * 4
        for rowIndex in range(height):
            start = rowIndex * stride
            scanlines.extend(b'\x00')
            scanlines.extend(rgbaBytes[start:start + stride])
        ihdr = struct.pack('>IIBBBBB', width, height, 8, 6, 0, 0, 0)
        payload = b''.join([b'\x89PNG\r\n\x1a\n', chunk(b'IHDR', ihdr), chunk(b'IDAT', zlib.compress(bytes(scanlines), level=9)), chunk(b'IEND', b'')])
        File(target).writeBytes(payload)
        return str(target)

    def rootRgbWithSyntheticBackground(self, width: int, height: int, rgbBytes: bytes) -> tuple[int, int, bytes, bool]:
        if width <= 0 or height <= 0 or not rgbBytes:
            return width, height, rgbBytes, False
        rootColor = self.rgbPixel(rgbBytes, width, 0, 0)
        replacement = self.backgroundReplacementRgba(rootColor)
        if replacement is None:
            return width, height, rgbBytes, False
        rgba = bytearray(width * height * 4)
        target = 0
        for index in range(0, len(rgbBytes), 3):
            pixel = (rgbBytes[index], rgbBytes[index + 1], rgbBytes[index + 2])
            if pixel == rootColor:
                rgba[target:target + 4] = bytes(replacement)
            else:
                rgba[target:target + 4] = bytes((pixel[0], pixel[1], pixel[2], 255))
            target += 4
        return width, height, bytes(rgba), True

    def decodeXwdFramebufferToRgb(self, sourcePath: str | Path) -> tuple[int, int, bytes]:
        source = Path(sourcePath)
        raw = source.read_bytes()
        if len(raw) < 160:
            raise RuntimeError(f'Framebuffer file too small: {source}')
        header = struct.unpack('>25I', raw[:100])
        header_values = {name: int(header[index] or 0) for name, index in (
            ('headerSize', 0), ('pixmapFormat', 2), ('width', 4), ('height', 5), ('byteOrder', 6),
            ('bitsPerPixel', 11), ('bytesPerLine', 12), ('redMask', 14), ('greenMask', 15), ('blueMask', 16),
        )}
        headerSize, pixmapFormat, width, height, byteOrder, bitsPerPixel, bytesPerLine, redMask, greenMask, blueMask = (
            header_values[name]
            for name in ('headerSize', 'pixmapFormat', 'width', 'height', 'byteOrder', 'bitsPerPixel', 'bytesPerLine', 'redMask', 'greenMask', 'blueMask')
        )
        if pixmapFormat != 2:
            raise RuntimeError(f'Unsupported XWD pixmap format: {pixmapFormat}')
        if width <= 0 or height <= 0 or bytesPerLine <= 0:
            raise RuntimeError('Invalid XWD framebuffer geometry')
        pixelData = raw[headerSize:headerSize + (height * bytesPerLine)]
        if len(pixelData) < height * bytesPerLine:
            raise RuntimeError('Incomplete XWD framebuffer payload')
        if bitsPerPixel == 32 and redMask == 0x00ff0000 and greenMask == 0x0000ff00 and blueMask == 0x000000ff:
            rgb = bytearray(width * height * 3)
            offset = 0
            for rowIndex in range(height):
                row = pixelData[rowIndex * bytesPerLine:(rowIndex + 1) * bytesPerLine][:width * 4]
                if byteOrder == 0:
                    rgb[offset:offset + width * 3:3] = row[2::4]
                    rgb[offset + 1:offset + width * 3:3] = row[1::4]
                    rgb[offset + 2:offset + width * 3:3] = row[0::4]
                else:
                    rgb[offset:offset + width * 3:3] = row[1::4]
                    rgb[offset + 1:offset + width * 3:3] = row[2::4]
                    rgb[offset + 2:offset + width * 3:3] = row[3::4]
                offset += width * 3
            return width, height, bytes(rgb)
        if bitsPerPixel not in {24, 32}:
            raise RuntimeError(f'Unsupported XWD bits_per_pixel: {bitsPerPixel}')
        bytesPerPixel = max(1, bitsPerPixel // 8)
        shifts = []
        for mask in (redMask, greenMask, blueMask):
            shift = 0
            if mask:
                while ((mask >> shift) & 1) == 0:
                    shift += 1
            shifts.append(shift)
        unpackOrder = 'little' if byteOrder == 0 else 'big'
        rgb = bytearray(width * height * 3)
        target = 0
        for rowIndex in range(height):
            row = pixelData[rowIndex * bytesPerLine:(rowIndex + 1) * bytesPerLine]
            for colIndex in range(width):
                start = colIndex * bytesPerPixel
                pixelBytes = row[start:start + bytesPerPixel]
                value = int.from_bytes(pixelBytes, unpackOrder, signed=False)
                rgb[target] = (value & redMask) >> shifts[0] if redMask else 0
                rgb[target + 1] = (value & greenMask) >> shifts[1] if greenMask else 0
                rgb[target + 2] = (value & blueMask) >> shifts[2] if blueMask else 0
                target += 3
        return width, height, bytes(rgb)

    def writeRgbPng(self, outputPath: str | Path, width: int, height: int, rgbBytes: bytes) -> str:
        target = Path(outputPath)
        target.parent.mkdir(parents=True, exist_ok=True)
        expected = int(width or 0) * int(height or 0) * 3
        if len(rgbBytes) != expected:
            raise RuntimeError(f'RGB payload length mismatch: expected {expected}, got {len(rgbBytes)}')
        def chunk(tag: bytes, payload: bytes) -> bytes:
            crc = zlib.crc32(tag + payload) & 0xffffffff
            return struct.pack('>I', len(payload)) + tag + payload + struct.pack('>I', crc)
        scanlines = bytearray()
        stride = width * 3
        for rowIndex in range(height):
            start = rowIndex * stride
            scanlines.extend(b'\x00')
            scanlines.extend(rgbBytes[start:start + stride])
        ihdr = struct.pack('>IIBBBBB', width, height, 8, 2, 0, 0, 0)
        payload = b''.join([b'\x89PNG\r\n\x1a\n', chunk(b'IHDR', ihdr), chunk(b'IDAT', zlib.compress(bytes(scanlines), level=9)), chunk(b'IEND', b'')])
        File(target).writeBytes(payload)
        return str(target)

    def convertFramebufferToPng(self, sourcePath: str | Path, outputPath: str | Path) -> str:
        width, height, rgb = self.decodeXwdFramebufferToRgb(sourcePath)
        return self.writeRgbPng(outputPath, width, height, rgb)

    def bestWindowId(self, pid: int = 0) -> str:
        entry = self.bestChildWindow(pid)
        return str(entry.get('id', EMPTY_STRING) or EMPTY_STRING).strip()

    def focusWindow(self, windowId: str) -> bool:
        xdotool = self.toolPath('xdotool')
        token = str(windowId or EMPTY_STRING).strip()
        if not xdotool or not token:
            return False
        commands = (
            [xdotool, 'windowactivate', '--sync', token],
            [xdotool, 'windowfocus', '--sync', token],
        )
        for command in commands:
            result = launcherRunCommand(command, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
            if int(getattr(result, 'returncode', 1)) == 0:
                return True
        probe = launcherRunCommand([xdotool, 'mousemove', '--window', token, '1', '1'], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
        return int(getattr(probe, 'returncode', 1)) == 0

    def captureScreenshot(self, outputPath: str | Path | None = None, windowId: str = EMPTY_STRING) -> str:
        if not self.ready:
            raise RuntimeError('Offscreen display is not ready')
        target = Path(outputPath or (SCREENSHOTS_DIR / 'offscreen-root.png')).resolve()
        target.parent.mkdir(parents=True, exist_ok=True)
        framebufferSource = self.framebufferSnapshotPath()
        resolvedWindowId = str(windowId or EMPTY_STRING).strip()
        if not resolvedWindowId:
            resolvedWindowId = self.bestWindowId(getattr(getattr(self, 'owner', None), 'childPid', 0))
        if framebufferSource:
            width, height, rgb = self.decodeXwdFramebufferToRgb(framebufferSource)
            if resolvedWindowId:
                geometry = self.windowGeometry(resolvedWindowId)
                if geometry.get('width') and geometry.get('height'):
                    cropWidth, cropHeight, cropped = self.cropRgbBuffer(width, height, rgb, geometry.get('x', 0), geometry.get('y', 0), geometry.get('width', 0), geometry.get('height', 0))
                    return self.writeRgbPng(target.with_suffix('.png'), cropWidth, cropHeight, cropped)
            rootWidth, rootHeight, payload, hasAlpha = self.rootRgbWithSyntheticBackground(width, height, rgb)
            if hasAlpha:
                return self.writeRgbaPng(target.with_suffix('.png'), rootWidth, rootHeight, payload)
            return self.writeRgbPng(target.with_suffix('.png'), rootWidth, rootHeight, payload)
        imageImport = self.toolPath('import')
        if imageImport:
            command = [imageImport, '-display', self.displayName, '-window', str(resolvedWindowId or 'root'), str(target)]
            result = launcherRunCommand(command, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
            if int(getattr(result, 'returncode', 1)) == 0 and target.exists():
                return str(target)
        xwdPath = self.toolPath('xwd')
        if xwdPath:
            xwdTarget = target if target.suffix.lower() == '.xwd' else target.with_suffix('.xwd')
            command = [xwdPath, '-silent', '-display', self.displayName, '-id', str(resolvedWindowId)] if resolvedWindowId else [xwdPath, '-silent', '-display', self.displayName, '-root']
            command += ['-out', str(xwdTarget)]
            result = launcherRunCommand(command, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
            if int(getattr(result, 'returncode', 1)) == 0 and xwdTarget.exists():
                return self.convertFramebufferToPng(xwdTarget, target.with_suffix('.png'))
        raise RuntimeError('Could not capture an offscreen screenshot from the managed offscreen X11 session')

    def visibleWindows(self) -> list[dict[str, str]]:
        if not self.ready:
            return []
        xwininfo = self.toolPath('xwininfo')
        if not xwininfo:
            return []
        result = launcherRunCommand([xwininfo, '-root', '-tree', '-display', self.displayName], capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
        windows = []
        for rawLine in result.stdout.splitlines():
            line = str(rawLine or EMPTY_STRING).rstrip()
            match = re.match(r'\s*(0x[0-9a-fA-F]+)\s+"([^"]*)"', line)
            if not match:
                continue
            windows.append({'id': match.group(1), 'title': match.group(2)})
        return windows

    def windowPid(self, windowId: str) -> int:
        xprop = self.toolPath('xprop')
        if not xprop:
            return 0
        result = launcherRunCommand([xprop, '-display', self.displayName, '-id', str(windowId), '_NET_WM_PID'], capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
        match = re.search(r'=\s*(\d+)', str(result.stdout or EMPTY_STRING))
        return int(match.group(1)) if match else 0

    def findChildWindows(self, pid: int = 0) -> list[dict[str, str]]:
        childPid = int(pid or 0)
        windows = []
        xdotool = self.toolPath('xdotool')
        if childPid > 0 and xdotool:
            result = launcherRunCommand([xdotool, 'search', '--all', '--pid', str(childPid), '--onlyvisible'], capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
            for line in result.stdout.splitlines():
                windowId = str(line or EMPTY_STRING).strip()
                if windowId:
                    windows.append({'id': windowId, 'title': EMPTY_STRING})
            if windows:
                return windows
        visible = self.visibleWindows()
        for entry in visible:
            if childPid <= 0 or self.windowPid(entry.get('id', EMPTY_STRING)) == childPid:
                windows.append(entry)
        if windows:
            return windows
        titled = [entry for entry in visible if str(entry.get('title', EMPTY_STRING) or EMPTY_STRING).strip() and str(entry.get('title', EMPTY_STRING) or EMPTY_STRING).strip().lower() not in {'(has no name)', 'the root window'}]
        if childPid > 0 and titled:
            # Some Qt/Xvfb windows do not publish _NET_WM_PID reliably.
            # Fall back to titled non-root windows so scripted offscreen actions
            # do not spin forever while the GUI is already painted.
            return titled
        return visible if childPid <= 0 else []

    def sendKey(self, windowId: str, keySpec: str) -> bool:
        xdotool = self.requireTool('xdotool')
        command = [xdotool, 'key', '--delay', '0', '--window', str(windowId), str(keySpec or EMPTY_STRING)]
        result = launcherRunCommand(command, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
        return int(getattr(result, 'returncode', 1)) == 0

    def typeText(self, windowId: str, textValue: str) -> bool:
        xdotool = self.requireTool('xdotool')
        command = [xdotool, 'type', '--delay', '1', '--window', str(windowId), str(textValue or EMPTY_STRING)]
        result = launcherRunCommand(command, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
        return int(getattr(result, 'returncode', 1)) == 0

    def move(self, windowId: str, x: int, y: int) -> bool:
        xdotool = self.requireTool('xdotool')
        moveResult = launcherRunCommand([xdotool, 'mousemove', '--window', str(windowId), str(int(x)), str(int(y))], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
        return int(getattr(moveResult, 'returncode', 1)) == 0

    def click(self, windowId: str, x: int, y: int, button: int = 1) -> bool:
        if not self.move(windowId, x, y):
            return False
        if int(button or 0) <= 0:
            return True
        xdotool = self.requireTool('xdotool')
        clickResult = launcherRunCommand([xdotool, 'click', '--window', str(windowId), str(int(button or 1))], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
        return int(getattr(clickResult, 'returncode', 1)) == 0





def packagedLinuxRuntimeLibDirs() -> list[str]:
    roots = [
        LINUX_RUNTIME_DIR / 'usr' / 'lib' / 'x86_64-linux-gnu',
        LINUX_RUNTIME_DIR / 'lib' / 'x86_64-linux-gnu',
        LINUX_RUNTIME_DIR / 'usr' / 'local' / 'lib',
    ]
    result: list[str] = []
    for root in roots:
        try:
            if root.exists():
                value = str(root.resolve())
                if value not in result:
                    result.append(value)
        except Exception:
            recordException('start.py:10622', sys.exc_info()[1])
            _traceSwallowedException('start.py:10437', sys.exc_info()[1])
            continue
    return result


def prependEnvPathList(env: dict, key: str, values) -> None:
    existing = [part for part in str(env.get(key, EMPTY_STRING) or EMPTY_STRING).split(os.pathsep) if str(part or EMPTY_STRING).strip()]
    ordered: list[str] = []
    for raw in list(values or []):
        value = str(raw or EMPTY_STRING).strip()
        if value and value not in ordered:
            ordered.append(value)
    for value in existing:
        if value and value not in ordered:
            ordered.append(value)
    if ordered:
        env[key] = os.pathsep.join(ordered)


def packagedQtPlatformName(default: str = 'offscreen') -> str:
    libdirs = packagedLinuxRuntimeLibDirs()
    for root in libdirs:
        try:
            if (Path(root) / 'libxcb-cursor.so.0').exists():
                return 'xcb'
        except Exception:
            recordException('start.py:10648', sys.exc_info()[1])
            _traceSwallowedException('start.py:10462', sys.exc_info()[1])
            pass
    return str(default or 'offscreen')

def preflightCompileOrDie(path: Path) -> None:
    try:
        py_compile.compile(str(path), doraise=True)
    except py_compile.PyCompileError as error:
        recordException('start.py:10656', sys.exc_info()[1])
        message = str(error)
        print(f'[FATAL:compile] Failed compiling {path.name}', file=sys.stderr, flush=True)
        print(message, file=sys.stderr, flush=True)
        raise
    except Exception as error:
        recordException('start.py:10661', sys.exc_info()[1])
        print(f'[FATAL:compile] Unexpected compile failure for {path.name}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        raise
def _dependencyProbeModuleName(name: str) -> str:
    module_text = str(name or EMPTY_STRING).strip()
    if not module_text:
        return EMPTY_STRING
    if module_text == 'PySide6' or module_text.startswith('PySide6.'):
        return 'PySide6.QtCore'
    return module_text


def hasModule(name: str) -> bool:
    module_text = _dependencyProbeModuleName(name)
    if not module_text:
        return False
    try:
        importlib.import_module(module_text)
        return True
    except Exception:
        recordException('start.py:10680', sys.exc_info()[1])
        return False


def canInterpreterImportModule(pythonExecutable: str, moduleName: str) -> bool:
    executable = str(pythonExecutable or EMPTY_STRING).strip()
    module_text = _dependencyProbeModuleName(moduleName)
    if not executable or not module_text:
        return False
    cache_key = (executable, module_text)
    if cache_key in _IMPORT_MODULE_CACHE:
        return bool(_IMPORT_MODULE_CACHE.get(cache_key))
    current_python = str(sys.executable or EMPTY_STRING).strip()
    try:
        same_runtime = bool(executable and current_python and (os.path.samefile(executable, current_python) if os.path.exists(executable) and os.path.exists(current_python) else executable == current_python))
    except Exception:
        recordException('start.py:10695', sys.exc_info()[1])
        same_runtime = executable == current_python
    if moduleSpecAvailableInSupplementalPath(module_text):
        _IMPORT_MODULE_CACHE[cache_key] = True
        return True
    if same_runtime:
        ok = hasModule(module_text)
        if ok:
            _IMPORT_MODULE_CACHE[cache_key] = True
            return True
        # start.py is often launched with -S during smoke tests, which disables
        # site-packages in the parent process. Do not trust a same-runtime
        # in-process miss; verify with a clean child interpreter that loads site.
    cmd = [executable, '-c', f"import importlib.util,sys; sys.exit(0 if importlib.util.find_spec({module_text!r}) is not None else 1)"]
    ok = False
    process = None
    try:
        launch_kwargs = dict(stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=applySupplementalPythonPath(), nonzeroExitOk=True)
        if os.name != 'nt':
            launch_kwargs['start_new_session'] = True
        process = StartProcess(cmd, name=f'OptionalImportProbe:{module_text}', ttlSeconds=4.0, **launch_kwargs)
        process.start()
        pid = int(getattr(process, 'pid', 0) or 0)
        print(f'[TRACE:import-probe] module={module_text} pid={pid}', file=sys.stderr, flush=True)
        deadline = time.time() + 4.0
        while process.poll() is None and time.time() < deadline:
            time.sleep(0.05)
        if process.poll() is None:
            process.kill(reason=f'optional import probe timeout: {module_text}')
            ok = False
        else:
            ok = int(getattr(process, 'returnCode', getattr(getattr(process, 'proc', None), 'returncode', 1)) or 0) == 0
    except Exception:
        recordException('start.py:10725', sys.exc_info()[1])
        try:
            if process is not None and process.isAlive():
                process.kill(reason=f'optional import probe exception: {module_text}')
        except Exception:
            recordException('start.py:10729', sys.exc_info()[1])
            _traceSwallowedException('start.py:10550', sys.exc_info()[1])
            pass
        ok = False
    _IMPORT_MODULE_CACHE[cache_key] = bool(ok)
    return bool(ok)



MSYS_PATH_MARKERS = ('msys2', 'msys64', 'mingw', 'ucrt64', 'clang64', 'openshotbuild')
MSYS_SOABI_MARKERS = ('mingw', 'ucrt', 'gnu')


def safeFileMd5Hex(pathValue: str | Path) -> str:
    try:
        target = Path(pathValue).resolve()
        if not target.exists() or not target.is_file():
            return EMPTY_STRING
        digest = hashlib.md5()
        with File(target).open('rb') as handle:
            while True:
                chunk = handle.read(1024 * 1024)
                if not chunk:
                    break
                digest.update(chunk)
        return digest.hexdigest()
    except Exception:
        recordException('start.py:10755', sys.exc_info()[1])
        return EMPTY_STRING


def clearPycacheDirectories(rootValue: str | Path = BASE_DIR, *, reason: str = EMPTY_STRING) -> dict[str, int]:
    root = Path(rootValue).resolve()
    removed_dirs = 0
    removed_files = 0
    if not root.exists():
        return {'dirs': 0, 'files': 0}
    candidates = sorted([path for path in root.rglob('__pycache__') if path.is_dir()], key=lambda item: len(str(item)), reverse=True)
    for cache_dir in candidates:
        try:
            removed_files += sum(1 for child in cache_dir.rglob('*') if child.is_file())
        except Exception:
            recordException('start.py:10769', sys.exc_info()[1])
            _traceSwallowedException('start.py:10589', sys.exc_info()[1])
            pass
        try:
            shutil.rmtree(cache_dir, ignore_errors=False)
            removed_dirs += 1
        except FileNotFoundError:
            recordException('start.py:10775', sys.exc_info()[1])
            _traceSwallowedException('start.py:10594', sys.exc_info()[1])
            continue
        except Exception as error:
            recordException('start.py:10778', sys.exc_info()[1])
            print(f'[WARN:pycache] Failed removing {cache_dir}: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
    if removed_dirs:
        suffix = f' ({reason})' if str(reason or EMPTY_STRING).strip() else EMPTY_STRING
        print(f'[TRACE:pycache] removed {removed_dirs} __pycache__ director{"y" if removed_dirs == 1 else "ies"} and {removed_files} file{"s" if removed_files != 1 else EMPTY_STRING}{suffix}', flush=True)
    return {'dirs': removed_dirs, 'files': removed_files}


def requiredBundleArtifactPaths(baseDir: str | Path = BASE_DIR) -> list[Path]:
    root = Path(baseDir or BASE_DIR)
    return [root / rel_path for rel_path in BUNDLE_REQUIRED_RELATIVE_PATHS]


def missingBundleArtifacts(baseDir: str | Path = BASE_DIR) -> list[Path]:
    root = Path(baseDir or BASE_DIR)
    missing: list[Path] = []
    for path in requiredBundleArtifactPaths(root):
        if not path.exists():
            missing.append(path)
    return missing


def bundleWarningMessages(baseDir: str | Path = BASE_DIR) -> list[str]:
    root = Path(baseDir or BASE_DIR)
    messages = list(BUNDLE_IMPORT_WARNINGS or [])
    missing_paths = missingBundleArtifacts(root)
    if missing_paths:
        rel_list = ', '.join(str(path.relative_to(root)) for path in missing_paths)
        messages.append(f'incomplete TrioDesktop bundle next to start.py: {rel_list}')
    return messages


def verifyBundleArtifactsOrDie(baseDir: str | Path = BASE_DIR) -> None:
    messages = bundleWarningMessages(baseDir)
    if not messages:
        return
    details = '\n'.join(f'- {line}' for line in messages)
    raise RuntimeError('TrioDesktop bundle is incomplete.\n' + details + '\nLaunch the full bundle that includes languages/ and data.py.')


def printLauncherIdentity(targetPath: str | Path = GTP_PATH, *, preferredChildPython: str = EMPTY_STRING, context: str = 'startup') -> None:
    timestamp = datetime.datetime.now().astimezone().isoformat()
    launcher_path = Path(__file__).resolve()
    target_path = Path(targetPath).resolve()
    launcher_md5 = safeFileMd5Hex(launcher_path) or '(unavailable)'
    target_md5 = safeFileMd5Hex(target_path) or '(unavailable)'
    current_python = str(Path(sys.executable).resolve()) if str(sys.executable or EMPTY_STRING).strip() else '(unavailable)'
    lines = [
        f'[FlatLineDebugger.debugger] timestamp={timestamp} context={context}',
        f'[FlatLineDebugger.debugger] launcher name={launcher_path.name}',
        f'[FlatLineDebugger.debugger] launcher path={launcher_path}',
        f'[FlatLineDebugger.debugger] launcher md5={launcher_md5}',
        f'[FlatLineDebugger.debugger] current python={current_python}',
        f'[FlatLineDebugger.debugger] target name={target_path.name}',
        f'[FlatLineDebugger.debugger] target path={target_path}',
        f'[FlatLineDebugger.debugger] target md5={target_md5}',
    ]
    preferred = str(preferredChildPython or EMPTY_STRING).strip()
    if preferred:
        lines.append(f'[FlatLineDebugger.debugger] preferred child python={preferred}')
    try:
        term = Terminal()
        if term.pid is not None:
            lines.append(f'[FlatLineDebugger.debugger] terminal pid={term.pid}')
        if term.path:
            lines.append(f'[FlatLineDebugger.debugger] terminal path={term.path}')
        if term.version:
            lines.append(f'[FlatLineDebugger.debugger] terminal version={term.version}')
        font = term.font
        if font:
            lines.append(f'[FlatLineDebugger.debugger] terminal font={font}  host={term.host}')
        if term.features:
            lines.append(f'[FlatLineDebugger.debugger] terminal features=[{", ".join(term.features)}]')
    except Exception:
        recordException('start.py:10851', sys.exc_info()[1])
        _traceSwallowedException('start.py:10669', sys.exc_info()[1])
        pass
    for line in lines:
        print(line, flush=True)



def supplementalPythonPathEntries() -> list[str]:
    """Return safe supplemental site-packages paths for launcher probes/child boot."""
    entries: list[str] = []
    def add(path_value) -> None:
        try:
            path = Path(path_value).resolve()
            text_value = str(path)
            if path.is_dir() and text_value not in entries:
                entries.append(text_value)
        except Exception:
            recordException('start.py:10868', sys.exc_info()[1])
            _traceSwallowedException('start.py:10685', sys.exc_info()[1])
            pass
    version_tokens = []
    try:
        version_tokens.append(f"python{sys.version_info.major}.{sys.version_info.minor}")
    except Exception:
        recordException('start.py:10874', sys.exc_info()[1])
        _traceSwallowedException('start.py:10690', sys.exc_info()[1])
        pass
    for token in ('python3.13', 'python3.12', 'python3.11', 'python3.10'):
        if token not in version_tokens:
            version_tokens.append(token)
    for root in (Path('/opt/pyvenv/lib'), Path('/opt/venv/lib')):
        for token in version_tokens:
            add(root / token / 'site-packages')
    env_virtual = str(os.environ.get('VIRTUAL_ENV', EMPTY_STRING) or EMPTY_STRING).strip()
    if env_virtual:
        for token in version_tokens:
            add(Path(env_virtual) / 'lib' / token / 'site-packages')
    return entries


def applySupplementalPythonPath(env: dict[str, str] | None = None) -> dict[str, str]:
    payload = dict(env or os.environ.copy())
    additions = supplementalPythonPathEntries()
    if not additions:
        return payload
    existing = [item for item in str(payload.get('PYTHONPATH', EMPTY_STRING) or EMPTY_STRING).split(os.pathsep) if item]
    merged: list[str] = []
    for item in additions + existing:
        if item and item not in merged:
            merged.append(item)
    payload['PYTHONPATH'] = os.pathsep.join(merged)
    return payload


def moduleSpecAvailableInSupplementalPath(moduleName: str) -> bool:
    module_text = _dependencyProbeModuleName(moduleName)
    if not module_text:
        return False
    additions = supplementalPythonPathEntries()
    if not additions:
        return False
    original_path = list(sys.path)
    try:
        for entry in reversed(additions):
            if entry not in sys.path:
                sys.path.insert(0, entry)
        try:
            return importlib.util.find_spec(module_text) is not None
        except Exception:
            recordException('start.py:10918', sys.exc_info()[1])
            return False
    finally:
        try:
            sys.path.clear()
            sys.path.extend(original_path)
        except Exception:
            recordException('start.py:10924', sys.exc_info()[1])
            _traceSwallowedException('start.py:10738', sys.exc_info()[1])
            pass

def _candidatePythonExecutables() -> list[str]:
    candidates: list[str] = []

    def add(candidate) -> None:
        text = str(candidate or EMPTY_STRING).strip().strip('"')
        if text and text not in candidates:
            candidates.append(text)

    add(sys.executable)
    if os.name == 'nt':
        for candidate in (
            r'C:\Python312\python.exe',
            r'C:\Python311\python.exe',
            r'C:\Python310\python.exe',
            r'C:\Python313\python.exe',
        ):
            add(candidate)
        local_app_data = str(os.environ.get('LOCALAPPDATA', EMPTY_STRING) or EMPTY_STRING).strip()
        if local_app_data:
            for version in ('312', '311', '310', '313'):
                add(Path(local_app_data) / 'Programs' / 'Python' / f'Python{version}' / 'python.exe')
    for candidate in (shutil.which('python3'), shutil.which('python'), shutil.which('py')):
        add(candidate)
    return candidates


def _probePythonCommand(command: str) -> tuple[bool, str, tuple[int, int, int], str]:
    executable = str(command or EMPTY_STRING).strip().strip('"')
    if not executable:
        return False, EMPTY_STRING, (0, 0, 0), EMPTY_STRING
    try:
        payload = (
            'import json, sys, sysconfig;'
            'print(json.dumps({'
            '"exe": sys.executable,'
            '"version": list(sys.version_info[:3]),'
            '"soabi": str(sysconfig.get_config_var("EXT_SUFFIX") or "")'
            '}))'
        )
        completed = launcherRunCommand([executable, '-c', payload], capture_output=True, text=True, check=False, timeout=20)
        if int(getattr(completed, 'returncode', 1)) != 0:
            return False, EMPTY_STRING, (0, 0, 0), EMPTY_STRING
        data = json.loads(str(completed.stdout or EMPTY_STRING).strip())
        exe = str(data.get('exe', EMPTY_STRING) or EMPTY_STRING).strip() or executable
        version_list = list(data.get('version', []) or [])
        while len(version_list) < 3:
            version_list.append(0)
        version = (int(version_list[0]), int(version_list[1]), int(version_list[2]))
        soabi = str(data.get('soabi', EMPTY_STRING) or EMPTY_STRING).strip()
        return True, exe, version, soabi
    except Exception:
        recordException('start.py:10978', sys.exc_info()[1])
        return False, EMPTY_STRING, (0, 0, 0), EMPTY_STRING


def _isStandardCPythonExe(executable: str, soabi: str = EMPTY_STRING) -> bool:
    exe_text = str(executable or EMPTY_STRING).strip().lower()
    soabi_text = str(soabi or EMPTY_STRING).strip().lower()
    if any(marker in exe_text for marker in MSYS_PATH_MARKERS):
        return False
    if any(marker in soabi_text for marker in MSYS_SOABI_MARKERS):
        return False
    return True


def _scorePreferredPythonExecutable(executable: str, version: tuple[int, int, int], soabi: str = EMPTY_STRING) -> int:
    if not _isStandardCPythonExe(executable, soabi):
        return 99
    major = int(version[0] if version else 0)
    minor = int(version[1] if len(version) > 1 else 0)
    if major == 3 and minor in (10, 11, 12):
        return 0
    if major == 3 and minor >= 13:
        return 1
    if major == 3 and minor >= 10:
        return 2
    return 50


def resolvePreferredPythonCommand(guiRequired: bool = True, minVersion: tuple[int, int] = (3, 10)) -> str:
    candidates = _candidatePythonExecutables()
    required_modules = ['PySide6.QtWidgets', 'PySide6.QtGui'] if bool(guiRequired) and os.name == 'nt' else []
    if os.name != 'nt':
        if not required_modules:
            return candidates[0] if candidates else str(sys.executable or EMPTY_STRING)
        for candidate in candidates:
            if all(canInterpreterImportModule(candidate, module_name) for module_name in required_modules):
                return candidate
        return candidates[0] if candidates else str(sys.executable or EMPTY_STRING)
    scored: list[tuple[int, int, int, str, tuple[int, int, int], str]] = []
    for candidate in candidates:
        ok, executable, version, soabi = _probePythonCommand(candidate)
        if not ok:
            continue
        if tuple(version[:2]) < tuple(minVersion[:2]):
            continue
        base_score = _scorePreferredPythonExecutable(executable, version, soabi)
        module_penalty = 0
        if required_modules and not all(canInterpreterImportModule(executable, module_name) for module_name in required_modules):
            module_penalty = 5
        scored.append((base_score + module_penalty, base_score, module_penalty, executable, version, soabi))
    if scored:
        scored.sort(key=lambda item: (item[0], item[1], item[2], item[4], item[3].lower()))
        return str(scored[0][3] or EMPTY_STRING).strip()
    return candidates[0] if candidates else str(sys.executable or EMPTY_STRING)


def resolvePreferredChildPython(guiRequired: bool = True) -> str:
    cache_key = (bool(guiRequired),)
    cached = str(_PREFERRED_CHILD_CACHE.get(cache_key, EMPTY_STRING) or EMPTY_STRING).strip()
    if cached:
        return cached
    candidates = []
    if os.name == 'nt' and bool(guiRequired):
        try:
            current = Path(str(sys.executable or EMPTY_STRING))
            pythonw = current.with_name('pythonw.exe')
            if pythonw.exists():
                candidates.append(str(pythonw))
        except Exception:
            recordException('start.py:resolve-pythonw-candidate', sys.exc_info()[1], handled=True)
        for candidate in (shutil.which('pythonw.exe'), shutil.which('pythonw')):
            text = str(candidate or EMPTY_STRING).strip()
            if text and text not in candidates:
                candidates.append(text)
    for candidate in (sys.executable, '/usr/bin/python3', shutil.which('python3'), shutil.which('python')):
        text = str(candidate or EMPTY_STRING).strip()
        if text and text not in candidates:
            candidates.append(text)
    required_modules = ['PySide6.QtWidgets', 'PySide6.QtGui'] if bool(guiRequired) and os.name != 'nt' else []
    if not required_modules:
        chosen = candidates[0] if candidates else str(sys.executable or EMPTY_STRING)
        _PREFERRED_CHILD_CACHE[cache_key] = str(chosen or EMPTY_STRING).strip()
        return str(chosen or EMPTY_STRING).strip()
    for candidate in candidates:
        if all(canInterpreterImportModule(candidate, module_name) for module_name in required_modules):
            _PREFERRED_CHILD_CACHE[cache_key] = str(candidate or EMPTY_STRING).strip()
            return str(candidate or EMPTY_STRING).strip()
    chosen = candidates[0] if candidates else str(sys.executable or EMPTY_STRING)
    _PREFERRED_CHILD_CACHE[cache_key] = str(chosen or EMPTY_STRING).strip()
    return str(chosen or EMPTY_STRING).strip()


class XvfbCaptureEngine(CaptureEngine):
    ENGINE_KIND = 'xvfb'


class XdummyCaptureEngine(CaptureEngine):
    ENGINE_KIND = 'xdummy'
    DUMMY_DRIVER_CANDIDATE_PATHS = (
        '/usr/lib/xorg/modules/drivers/dummy_drv.so',
        '/usr/lib64/xorg/modules/drivers/dummy_drv.so',
        '/usr/lib/x86_64-linux-gnu/xorg/modules/drivers/dummy_drv.so',
        '/usr/lib/aarch64-linux-gnu/xorg/modules/drivers/dummy_drv.so',
    )
    PRECONFIGURED_MODE_STRINGS = (
        '1920x1080', '1920x1200', '1680x1050', '1600x1200', '1600x900',
        '1440x900', '1366x768', '1360x768', '1280x1024', '1280x800',
        '1280x768', '1280x720', '1152x864', '1024x768', '1024x600', '800x600',
        '2560x1440', '2560x1600', '3840x2160', '3840x2560',
    )
    DUMMY_VIDEO_RAM_KIB = 1048576
    MODELINE_PIXEL_CLOCK = '108.9'
    MODELINE_TOTAL = 33000
    MODELINE_HSYNC_KHZ = '3.3'
    MODELINE_VREFRESH_HZ = '0.1'

    def parseModeToken(self, token: str) -> tuple[int, int] | None:
        match = re.match(r'^(\d{2,5})x(\d{2,5})$', str(token or EMPTY_STRING).strip().lower())
        if not match:
            return None
        return int(match.group(1)), int(match.group(2))

    def preconfiguredModeSizes(self) -> list[tuple[int, int]]:
        requestedWidth, requestedHeight, _ = self.parseScreenSpec()
        modes: list[tuple[int, int]] = [(requestedWidth, requestedHeight)]
        for raw in self.PRECONFIGURED_MODE_STRINGS:
            parsed = self.parseModeToken(raw)
            if parsed is not None:
                modes.append(parsed)
        unique: list[tuple[int, int]] = []
        seen: set[tuple[int, int]] = set()
        for width, height in modes:
            if width < 320 or height < 200:
                continue
            if width > self.MODELINE_TOTAL or height > self.MODELINE_TOTAL:
                continue
            key = (width, height)
            if key in seen:
                continue
            seen.add(key)
            unique.append(key)
        return unique

    def modelineName(self, width: int, height: int) -> str:
        return f'{int(width)}x{int(height)}'

    def buildConfigModeline(self, width: int, height: int) -> str:
        total = int(self.MODELINE_TOTAL)
        return f'    Modeline "{self.modelineName(width, height)}" {self.MODELINE_PIXEL_CLOCK} {int(width)} {total - 2} {total - 1} {total} {int(height)} {total - 2} {total - 1} {total}'
    def dummyDriverPath(self) -> str:
        for candidate in self.DUMMY_DRIVER_CANDIDATE_PATHS:
            if Path(candidate).exists():
                return str(candidate)
        return EMPTY_STRING

    def prepareSessionArtifacts(self) -> None:
        self.stop()
        self.tempDir = tempfile.TemporaryDirectory(prefix='trio-xdummy-')
        tempPath = Path(self.tempDir.name)
        self.displayNumber = self.chooseDisplayNumber()
        self.displayName = f':{self.displayNumber}'
        self.xauthorityPath = str(tempPath / 'Xauthority')
        self.framebufferDir = EMPTY_STRING
        self.windowCache = {}
        cookie = self.makeCookie()
        xauth = self.requireTool('xauth')
        Path(self.xauthorityPath).touch()
        result = launcherRunCommand([xauth, '-f', self.xauthorityPath, 'add', self.displayName, '.', cookie], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, check=False)
        if int(getattr(result, 'returncode', 1)) != 0:
            raise RuntimeError(f'Failed preparing Xauthority for {self.displayName}')

    def writeDummyConfig(self) -> str:
        ctx = _xdummyConfigContext(self)
        temp_path = Path(getattr(self.tempDir, 'name', EMPTY_STRING) or tempfile.gettempdir())
        config_path = temp_path / 'xorg-dummy.conf'
        config_text = '\n\n'.join(_xdummyConfigSectionSpecs(self, ctx)) + '\n'
        File(config_path).writeText(config_text)
        return str(config_path)

    def xrandrOutputState(self) -> tuple[str, list[str], str]:
        xrandr = self.toolPath('xrandr')
        if not xrandr:
            return EMPTY_STRING, [], EMPTY_STRING
        result = launcherRunCommand([xrandr, '--display', self.displayName, '--query'], capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
        stdout = str(result.stdout or EMPTY_STRING)
        chosen = EMPTY_STRING
        modes: list[str] = []
        currentOutput = EMPTY_STRING
        for rawLine in stdout.splitlines():
            line = str(rawLine or EMPTY_STRING).rstrip()
            header = re.match(r'^(\S+)\s+(connected|disconnected)\b', line)
            if header:
                currentOutput = str(header.group(1) or EMPTY_STRING).strip()
                if str(header.group(2) or EMPTY_STRING) == 'connected' and not chosen:
                    chosen = currentOutput
                continue
            if currentOutput and re.match(r'^\s+\d+x\d+\s', line):
                token = str(line.strip().split()[0] or EMPTY_STRING).strip()
                if currentOutput == chosen and token:
                    modes.append(token)
        return chosen, modes, stdout

    def ensureRequestedMode(self) -> bool:
        xrandr = self.toolPath('xrandr')
        if not xrandr:
            return False
        width, height, _ = self.parseScreenSpec()
        targetMode = f'{width}x{height}'
        outputName, modes, _ = self.xrandrOutputState()
        if not outputName:
            return False
        env = self.buildEnvironment()
        if targetMode not in modes:
            cvt = self.toolPath('cvt')
            if cvt:
                cvtResult = launcherRunCommand([cvt, str(width), str(height), '60'], capture_output=True, text=True, encoding='utf-8', errors='replace', env=env, check=False)
                modelineMatch = re.search(r'^Modeline\s+"([^"]+)"\s+(.+)$', str(cvtResult.stdout or EMPTY_STRING), re.MULTILINE)
                if modelineMatch:
                    modeName = str(modelineMatch.group(1) or targetMode).strip()
                    modelineBody = str(modelineMatch.group(2) or EMPTY_STRING).strip()
                    launcherRunCommand([xrandr, '--display', self.displayName, '--newmode', modeName, *shlex.split(modelineBody)], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=env, check=False)
                    launcherRunCommand([xrandr, '--display', self.displayName, '--addmode', outputName, modeName], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=env, check=False)
                    targetMode = modeName
        setMode = launcherRunCommand([xrandr, '--display', self.displayName, '--fb', f'{width}x{height}', '--output', outputName, '--mode', targetMode], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=env, check=False)
        if int(getattr(setMode, 'returncode', 1)) != 0:
            return False
        finalOutput, _, finalState = self.xrandrOutputState()
        return bool(finalOutput == outputName and re.search(rf'^Screen 0:.*current\s+{width} x {height}\b', finalState, re.MULTILINE))

    def launchViaXdummyWrapper(self) -> None:
        xdummy = self.requireTool('Xdummy')
        width, height, depth = self.parseScreenSpec()
        command = [
            xdummy,
            self.displayName,
            '-geometry', f'{width}x{height}',
            '-depth', str(depth),
            '-auth', self.xauthorityPath,
            '-nolisten', 'tcp',
        ]
        self.proc = launcherStartProcess(command, cwd=str(BASE_DIR), stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), start_new_session=True)

    def launchViaXorgDummy(self) -> None:
        xorg = self.requireTool('Xorg')
        configPath = self.writeDummyConfig()
        logPath = str(Path(getattr(self.tempDir, 'name', tempfile.gettempdir())) / 'Xorg.dummy.log')
        command = [
            xorg,
            self.displayName,
            '-config', configPath,
            '-auth', self.xauthorityPath,
            '-nolisten', 'tcp',
            '-noreset',
            '-logfile', logPath,
        ]
        self.proc = launcherStartProcess(command, cwd=str(BASE_DIR), stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), start_new_session=True)

    def start(self):
        if os.name == 'nt':
            raise RuntimeError('Managed offscreen X11 capture engines are only supported on Linux/X11')
        if self.proc is not None and self.proc.poll() is None and self.ready:
            return True
        self.requireTool('xauth')
        self.requireTool('xdpyinfo')
        directError = None
        self.prepareSessionArtifacts()
        try:
            self.launchViaXorgDummy()
            self.waitUntilReady()
            modeOk = self.ensureRequestedMode()
            if not modeOk:
                self.emit(f'[WARN:offscreen] Xdummy display {self.displayName} did not confirm requested mode {self.screenSpec}', getattr(self.owner, 'logPath', EMPTY_STRING))
            self.emit(f'[FlatLineDebugger.debugger] Offscreen Xdummy ready  display={self.displayName}  screen={self.screenSpec}  launcher=Xorg-dummy', getattr(self.owner, 'logPath', EMPTY_STRING))
            return True
        except Exception as error:
            recordException('start.py:11240', sys.exc_info()[1])
            directError = error
            self.emit(f'[WARN:offscreen] Direct Xorg dummy launch failed on {self.displayName}: {type(error).__name__}: {error}; falling back to Xdummy wrapper if available', getattr(self.owner, 'logPath', EMPTY_STRING))
            self.stop()
        if self.hasTool('Xdummy'):
            self.prepareSessionArtifacts()
            try:
                self.launchViaXdummyWrapper()
                self.waitUntilReady()
                modeOk = self.ensureRequestedMode()
                if not modeOk:
                    self.emit(f'[WARN:offscreen] Xdummy display {self.displayName} did not confirm requested mode {self.screenSpec}', getattr(self.owner, 'logPath', EMPTY_STRING))
                self.startExperimentalAlphaSupport()
                self.emit(f'[FlatLineDebugger.debugger] Offscreen Xdummy ready  display={self.displayName}  screen={self.screenSpec}  launcher=Xdummy-wrapper', getattr(self.owner, 'logPath', EMPTY_STRING))
                return True
            except Exception as error:
                recordException('start.py:11255', sys.exc_info()[1])
                self.stop()
                raise RuntimeError(f'Direct Xorg dummy launch failed ({type(directError).__name__}: {directError}) and Xdummy wrapper fallback failed ({type(error).__name__}: {error})')
        raise RuntimeError(f'Direct Xorg dummy launch failed ({type(directError).__name__}: {directError}) and no Xdummy wrapper fallback is available')

class XpraCaptureEngine(CaptureEngine):
    ENGINE_KIND = 'xpra'

    def __init__(self, owner=None, screenSpec: str = EMPTY_STRING, backgroundColor=None, backgroundAlpha: int = 0):
        super().__init__(owner, screenSpec=screenSpec, backgroundColor=backgroundColor, backgroundAlpha=backgroundAlpha)
        self.displayProc = None
        self.socketDir = EMPTY_STRING
        self.xpraLogPath = EMPTY_STRING
        self.xpraLogHandle = None
        self.lastReadyText = EMPTY_STRING
        self.launchMode = 'wrap-xvfb'

    def socketArguments(self) -> list[str]:
        socketDir = str(self.socketDir or EMPTY_STRING).strip()
        if not socketDir:
            return []
        return [f'--socket-dir={socketDir}']

    def openXpraLogHandle(self):
        self.closeXpraLogHandle()
        logPath = str(self.xpraLogPath or EMPTY_STRING).strip()
        if not logPath:
            return None
        Path(logPath).parent.mkdir(parents=True, exist_ok=True)
        self.xpraLogHandle = File(logPath).open('ab', buffering=0)
        return self.xpraLogHandle

    def closeXpraLogHandle(self) -> None:
        handle = getattr(self, 'xpraLogHandle', None)
        self.xpraLogHandle = None
        if handle is not None:
            try:
                handle.close()
            except Exception:
                recordException('start.py:11293', sys.exc_info()[1])
                _traceSwallowedException('start.py:11106', sys.exc_info()[1])
                pass

    def xpraLogTail(self, limitBytes: int = 8192) -> str:
        logPath = str(self.xpraLogPath or EMPTY_STRING).strip()
        if not logPath:
            return EMPTY_STRING
        try:
            data = Path(logPath).read_bytes()
            tail = data[-max(256, int(limitBytes or 8192)):]
            return tail.decode('utf-8', errors='replace').strip()
        except Exception:
            recordException('start.py:11305', sys.exc_info()[1])
            return EMPTY_STRING

    def xpraReadyCommands(self) -> list[list[str]]:
        xpra = self.requireTool('xpra')
        socketArgs = self.socketArguments()
        return [
            [xpra, 'info', self.displayName, *socketArgs],
            [xpra, 'id', self.displayName, *socketArgs],
            [xpra, 'list', *socketArgs],
        ]

    def xpraOutputLooksReady(self, stdoutText: str, stderrText: str = EMPTY_STRING) -> bool:
        haystack = '\n'.join([str(stdoutText or EMPTY_STRING), str(stderrText or EMPTY_STRING)]).strip()
        if not haystack:
            return False
        lowered = haystack.lower()
        displayToken = str(self.displayName or EMPTY_STRING).strip().lower()
        if displayToken and displayToken in lowered:
            return True
        readyMarkers = (
            'session-name',
            'server.ready',
            'server_state',
            'uuid=',
            'socket',
            'mode=',
            'desktop',
            'start time',
        )
        return any(marker in lowered for marker in readyMarkers)

    def waitForXpraReady(self, timeoutSeconds: float = 12.0) -> bool:
        deadline = time.time() + float(timeoutSeconds or 12.0)
        commands = self.xpraReadyCommands()
        lastError = EMPTY_STRING
        while time.time() < deadline:
            if self.proc is not None and self.proc.poll() is not None:
                logTail = self.xpraLogTail()
                detail = f'Xpra server exited early with code {self.proc.returncode}'
                if logTail:
                    detail += f'\n--- xpra.log tail ---\n{logTail}'
                raise RuntimeError(detail)
            for command in commands:
                result = launcherRunCommand(command, capture_output=True, text=True, encoding='utf-8', errors='replace', env=self.buildEnvironment(), check=False)
                stdoutText = str(result.stdout or EMPTY_STRING)
                stderrText = str(result.stderr or EMPTY_STRING)
                if int(getattr(result, 'returncode', 1)) == 0 and self.xpraOutputLooksReady(stdoutText, stderrText):
                    self.ready = True
                    self.lastReadyText = stdoutText.strip() or stderrText.strip()
                    return True
                if stderrText.strip():
                    lastError = stderrText.strip()
            time.sleep(0.15)
        logTail = self.xpraLogTail()
        detail = f'Xpra server did not become ready on {self.displayName}'
        if lastError:
            detail += f'\nLast xpra probe error: {lastError}'
        if logTail:
            detail += f'\n--- xpra.log tail ---\n{logTail}'
        raise RuntimeError(detail)

    def xpraStartCommand(self) -> list[str]:
        xpra = self.requireTool('xpra')
        return [
            xpra,
            'start', self.displayName,
            '--use-display=yes',
            '--daemon=no',
            '--attach=no',
            '--mdns=no',
            '--notifications=no',
            '--pulseaudio=no',
            '--dbus-launch=no',
            '--dbus-proxy=no',
            '--dbus-control=no',
            '--printing=no',
            '--file-transfer=no',
            '--open-files=no',
            '--webcam=no',
            '--clipboard=no',
            '--mmap=no',
            '--systemd-run=no',
            '--resize-display=no',
            '--sync-xvfb=50',
            '--start-new-commands=no',
            '--exit-with-client=no',
            '--bell=no',
            '--microphone=no',
            '--speaker=no',
            '--xsettings=no',
            '--session-name=TrioDesktop-Offscreen-Xpra',
            *self.socketArguments(),
        ]

    def start(self):
        if os.name == 'nt':
            raise RuntimeError('Managed offscreen X11 capture engines are only supported on Linux/X11')
        if self.proc is not None and self.proc.poll() is None and self.ready:
            return True
        self.requireTool('xpra')
        CaptureEngine.start(self)
        self.displayProc = self.proc
        self.proc = None
        self.ready = False
        self.lastReadyText = EMPTY_STRING
        tempPath = Path(getattr(self.tempDir, 'name', tempfile.gettempdir()))
        socketPath = tempPath / 'xpra-sockets'
        socketPath.mkdir(parents=True, exist_ok=True)
        self.socketDir = str(socketPath)
        self.xpraLogPath = str(tempPath / 'xpra.log')
        env = self.buildEnvironment()
        env.setdefault('XPRA_LOG_DIR', str(tempPath))
        env.setdefault('XPRA_SOCKET_DIR', self.socketDir)
        command = self.xpraStartCommand()
        self.emit(f'[FlatLineDebugger.debugger] Starting Xpra wrapper  display={self.displayName}  screen={self.screenSpec}  socketDir={self.socketDir}', getattr(self.owner, 'logPath', EMPTY_STRING))
        logHandle = self.openXpraLogHandle()
        self.proc = launcherStartProcess(
            command,
            cwd=str(BASE_DIR),
            stdin=subprocess.DEVNULL,
            stdout=logHandle if logHandle is not None else subprocess.DEVNULL,
            stderr=subprocess.STDOUT if logHandle is not None else subprocess.DEVNULL,
            env=env,
            start_new_session=True,
        )
        try:
            self.waitForXpraReady()
            self.emit(f'[FlatLineDebugger.debugger] Offscreen Xpra ready  display={self.displayName}  screen={self.screenSpec}  socketDir={self.socketDir}  mode={self.launchMode}', getattr(self.owner, 'logPath', EMPTY_STRING))
            return True
        except Exception as error:
            recordException('start.py:11435', sys.exc_info()[1])
            logTail = self.xpraLogTail()
            self.stop()
            detail = str(error or EMPTY_STRING).strip() or f'Failed starting xpra on {self.displayName}'
            if logTail and 'xpra.log tail' not in detail:
                detail += f'\n--- xpra.log tail ---\n{logTail}'
            raise RuntimeError(detail)

    def stop(self) -> bool:
        xpraProc = self.proc
        xpraPath = self.toolPath('xpra')
        if xpraPath and str(self.displayName or EMPTY_STRING).strip() and str(self.socketDir or EMPTY_STRING).strip():
            launcherRunCommand([xpraPath, 'stop', self.displayName, *self.socketArguments()], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, env=self.buildEnvironment(), check=False)
        self.proc = None
        self.ready = False
        self.lastReadyText = EMPTY_STRING
        if xpraProc is not None:
            try:
                if xpraProc.poll() is None:
                    xpraProc.terminate()
                    xpraProc.wait(timeout=2.0)
            except Exception:
                recordException('start.py:11456', sys.exc_info()[1])
                try:
                    xpraProc.kill()
                except Exception:
                    recordException('start.py:11459', sys.exc_info()[1])
                    _traceSwallowedException('start.py:11271', sys.exc_info()[1])
                    pass
        self.closeXpraLogHandle()
        self.proc = self.displayProc
        self.displayProc = None
        self.socketDir = EMPTY_STRING
        self.xpraLogPath = EMPTY_STRING
        self.launchMode = 'wrap-xvfb'
        return CaptureEngine.stop(self)


def createCaptureEngine(kind: str, debugger, screenSpec: str = EMPTY_STRING, backgroundColor=None, backgroundAlpha: int = 0):
    engineKind = str(kind or 'xvfb').strip().lower() or 'xvfb'
    engineMap = {
        'xvfb': XvfbCaptureEngine,
        'xdummy': XdummyCaptureEngine,
        'xpra': XpraCaptureEngine,
    }
    engineClass = engineMap.get(engineKind, XvfbCaptureEngine)
    return engineClass(debugger, screenSpec=screenSpec, backgroundColor=backgroundColor, backgroundAlpha=backgroundAlpha)




def _dependencyInstallSuccess(registry) -> None:
    registry._moduleAvailabilityCache.clear()
    _IMPORT_MODULE_CACHE.clear()


def _dependencyPackageListContainsPySide(packages: list[str]) -> bool:
    return any(str(package or EMPTY_STRING).strip().lower() == 'pyside6' for package in list(packages or []))


def _dependencyLinuxFallbackInstall(registry, missing_packages: list[str], target_python: str, state: dict[str, object]) -> None:
    # Linux can reject ordinary pip with PEP 668/external-management messages that
    # are not plain permission errors. Do not stop at a warning: try the stronger
    # managed routes, then warn only after all known routes fail.
    installed = False
    if registry.attemptLinuxSudoPipInstall(missing_packages, pythonExecutable=target_python):
        installed = True
    else:
        succeeded, permission_error = registry.attemptPlainPipInstall(
            missing_packages,
            pythonExecutable=target_python,
            useUser=True,
            label='linux user pip install',
            breakSystemPackages=True,
        )
        installed = bool(succeeded)
        state['permission_error'] = bool(state.get('permission_error')) or bool(permission_error)
    if installed:
        _dependencyInstallSuccess(registry)
        registry.syncPythonToolPaths()
        return
    print('[WARN:deps] Linux pip install failed after normal, system-package, break-system-packages, sudo/root, and user fallback routes.', file=sys.stderr, flush=True)


def _dependencyInstallAttemptSpecs(registry, missing_packages: list[str], target_python: str) -> list[dict[str, object]]:
    return [
        {
            'enabled': registry.isWindows(),
            'runner': lambda: registry.attemptPlainPipInstall(
                missing_packages,
                pythonExecutable=target_python,
                useUser=False,
                label='windows pip install',
            ),
        },
        {
            'enabled': registry.isWindows(),
            'runner': lambda: registry.attemptPlainPipInstall(
                missing_packages,
                pythonExecutable=target_python,
                useUser=True,
                label='windows user pip install',
            ),
        },
        {
            'enabled': registry.isWindows() and registry.isWindowsAdmin(),
            'predicate': lambda state: bool(state.get('permission_error')),
            'runner': lambda: registry.attemptPlainPipInstall(
                missing_packages,
                pythonExecutable=target_python,
                useUser=False,
                label='windows admin pip install',
            ),
        },
        {
            'enabled': registry.isWindows() and not registry.isWindowsAdmin(),
            'predicate': lambda state: bool(state.get('permission_error')),
            'runner': lambda: (
                registry.attemptWindowsElevatedPipInstall(
                    missing_packages,
                    pythonExecutable=target_python,
                ),
                False,
            ),
            'on_failure': lambda state: print(
                '[WARN:deps] Windows elevation was denied or failed after a real permissions error.',
                file=sys.stderr,
                flush=True,
            ),
        },
        {
            'enabled': registry.isLinux(),
            'runner': lambda: registry.attemptPlainPipInstall(
                missing_packages,
                pythonExecutable=target_python,
                useUser=False,
                label='linux pip install',
                breakSystemPackages=True,
            ),
            'on_failure': lambda state: _dependencyLinuxFallbackInstall(registry, missing_packages, target_python, state),
        },
        {
            'enabled': not registry.isWindows() and not registry.isLinux(),
            'runner': lambda: registry.attemptPlainPipInstall(
                missing_packages,
                pythonExecutable=target_python,
                useUser=False,
                label='generic pip install with persistent cache',
            ),
            'on_failure': lambda state: print(
                '[WARN:deps] Generic pip install failed.',
                file=sys.stderr,
                flush=True,
            ),
        },
    ]

class StartDependencyRegistry:
    PYTHON_DEPENDENCY_TABLE = tuple(dict(item) for item in PYTHON_DEPENDENCIES)
    LINUX_SYSTEM_GROUPS = {
        'qt_x11_runtime': (
            {'kind': 'library', 'name': 'libxcb-cursor.so.0', 'lookup': 'xcb-cursor', 'package': 'libxcb-cursor0'},
        ),
        'offscreen_common_tools': (
            {'kind': 'tool', 'name': 'xauth', 'package': 'xauth', 'purpose': 'offscreen display auth'},
            {'kind': 'tool', 'name': 'xdpyinfo', 'package': 'x11-utils', 'purpose': 'offscreen display probe'},
            {'kind': 'tool', 'name': 'xwininfo', 'package': 'x11-utils', 'purpose': 'offscreen window probe'},
            {'kind': 'tool', 'name': 'xprop', 'package': 'x11-utils', 'purpose': 'offscreen window property probe'},
            {'kind': 'tool', 'name': 'xwd', 'package': 'x11-apps', 'purpose': 'offscreen screenshot capture'},
            {'kind': 'tool', 'name': 'xdotool', 'package': 'xdotool', 'purpose': 'offscreen mouse and keyboard injection'},
            {'kind': 'tool', 'name': 'convert', 'package': 'imagemagick', 'purpose': 'offscreen screenshot conversion'},
            {'kind': 'tool', 'name': 'import', 'package': 'imagemagick', 'purpose': 'offscreen screenshot fallback'},
        ),
        'xvfb_tools': (
            {'kind': 'tool', 'name': 'Xvfb', 'package': 'xvfb'},
        ),
        'xdummy_tools': (
            {'kind': 'tool', 'name': 'Xorg', 'package': 'xserver-xorg-core', 'purpose': 'Xdummy display server'},
            {'kind': 'tool', 'name': 'xrandr', 'package': 'x11-xserver-utils', 'purpose': 'Xdummy resize and mode control'},
            {'kind': 'tool', 'name': 'cvt', 'package': 'xcvt', 'alternatives': ['xcvt'], 'purpose': 'Xdummy modeline generation'},
            {'kind': 'path', 'name': 'dummy_drv.so', 'package': 'xserver-xorg-video-dummy', 'candidates': list(XdummyCaptureEngine.DUMMY_DRIVER_CANDIDATE_PATHS), 'purpose': 'Xdummy driver module'},
            {'kind': 'tool', 'name': 'Xdummy', 'package': 'x11vnc', 'purpose': 'Xdummy wrapper helper'},
        ),
        'xpra_tools': (
            {'kind': 'tool', 'name': 'xpra', 'package': 'xpra'},
        ),
        'experimental_alpha_tools': (
            {'kind': 'tool', 'name': 'picom', 'package': 'picom', 'purpose': 'experimental offscreen alpha compositor'},
            {'kind': 'tool', 'name': 'xcompmgr', 'package': 'xcompmgr', 'purpose': 'experimental offscreen alpha compositor', 'alternatives': ['compton']},
        ),
    }

    def __init__(self, argv=None):
        self.argv = list(argv or [])
        self.operatingSystem = OperatingSystem.detect()
        self.osFamily = self.operatingSystem.osFamily
        self._moduleAvailabilityCache = {}
        self._targetPythonCache = {}

    @staticmethod
    def detectOsFamily() -> str:
        name = str(platform.system() or EMPTY_STRING).strip().lower()
        if name.startswith('win'):
            return 'windows'
        if name.startswith('linux'):
            return 'linux'
        if name.startswith('darwin') or name.startswith('mac'):
            return 'mac'
        return name or 'unknown'

    def isWindows(self) -> bool:
        return bool(getattr(self.operatingSystem, 'isWindows', False))

    def isLinux(self) -> bool:
        return bool(getattr(self.operatingSystem, 'isLinux', False))

    def isGuiRequired(self) -> bool:
        tokens = normalizedCliTokens(self.argv)
        return not any(flag in tokens for flag in HEADLESS_FLAGS)

    def requestedCaptureEngineKind(self) -> str:
        return requestedCaptureEngineKind(self.argv)  # recursion-ok: method delegates to module helper

    def experimentalAlphaRequested(self) -> bool:
        color, alpha = parseBackgroundColorAndAlpha(self.argv)
        engine_kind = self.requestedCaptureEngineKind()
        return bool(offscreenRequested(self.argv) and color is not None and 0 < int(alpha or 0) < 255 and engine_kind in {'xvfb', 'xdummy'})

    def pythonDependencyEntries(self) -> list[dict[str, Any]]:
        gui_required = self.isGuiRequired()
        debugger_safe = bool(scanDisabled(self.argv) or debugEnabled(self.argv) or offscreenRequested(self.argv) or cliHasAnyFlag(self.argv, CLEAN_FLAGS))
        entries: list[dict[str, Any]] = []
        for item in self.PYTHON_DEPENDENCY_TABLE:
            entry = dict(item)
            import_name = str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()
            if bool(entry.get('gui_only')) and not gui_required:
                continue
            if debugger_safe and import_name in LAUNCHER_DEBUG_SAFE_OPTIONAL_IMPORTS:
                continue
            entries.append(entry)
        return entries

    @staticmethod
    def launcherCriticalImportNames() -> set[str]:
        return set(LAUNCHER_CRITICAL_IMPORTS)

    def requiredPythonModules(self) -> dict[str, str]:
        required: dict[str, str] = {}
        critical = self.launcherCriticalImportNames()
        for entry in self.pythonDependencyEntries():
            import_name = str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()
            pip_package = str(entry.get('pip_package', EMPTY_STRING) or EMPTY_STRING).strip()
            if import_name and import_name in critical:
                required[import_name] = pip_package
        return required

    @staticmethod
    def dependencyPackageName(entry: dict[str, Any], field_name: str) -> str:
        return str(entry.get(field_name, EMPTY_STRING) or EMPTY_STRING).strip()

    def targetPythonExecutable(self, guiRequired: bool | None = None) -> str:
        """Return the Python interpreter that dependency pip installs must target.

        Dependency repair must install into the interpreter running start.py.
        Child-process preference is a launch decision, not a pip target decision.
        Otherwise start.py can install PySide6 into /usr/bin/python3 while it is
        running under /opt/pyvenv/bin/python3, then still fail imports afterward.
        """
        required = self.isGuiRequired() if guiRequired is None else bool(guiRequired)
        override = str(os.environ.get('TRIO_DEPENDENCY_TARGET_PYTHON', EMPTY_STRING) or EMPTY_STRING).strip()
        if override:
            return override
        cache_key = bool(required)
        if cache_key in self._targetPythonCache:
            return str(self._targetPythonCache.get(cache_key) or EMPTY_STRING).strip()
        active = str(sys.executable or EMPTY_STRING).strip()
        if self.isWindows():
            # Windows may launch from MSYS/UCRT or another unsupported shim; keep
            # the existing preferred-CPython escape hatch there. Linux/macOS must
            # not drift to /usr/bin/python3 unless explicitly overridden above.
            value = str(resolvePreferredPythonCommand(guiRequired=required) or active or EMPTY_STRING).strip()
        else:
            value = active
        self._targetPythonCache[cache_key] = value
        return str(value or EMPTY_STRING).strip()

    @staticmethod
    def _sameExecutablePath(left: str, right: str) -> bool:
        left_text = str(left or EMPTY_STRING).strip()
        right_text = str(right or EMPTY_STRING).strip()
        if not left_text or not right_text:
            return False
        try:
            return os.path.samefile(left_text, right_text)
        except Exception as error:
            recordException('start.py:same-executable-os-samefile', error, handled=True)
            try:
                return str(Path(left_text).resolve()).lower() == str(Path(right_text).resolve()).lower()
            except Exception as fallback_error:
                recordException('start.py:same-executable-resolve', fallback_error, handled=True)
                return left_text.lower() == right_text.lower()

    def tracePipInterpreterTarget(self, executable: str, context: str) -> None:
        target = str(executable or EMPTY_STRING).strip()
        launcher = str(sys.executable or EMPTY_STRING).strip()
        label = str(context or 'pip').strip() or 'pip'
        print(f'[TRACE:deps] {label} launcher_python={launcher}', file=sys.stderr, flush=True)
        print(f'[TRACE:deps] {label} pip_target_python={target}', file=sys.stderr, flush=True)
        if target and launcher and not self._sameExecutablePath(target, launcher):
            if str(os.environ.get('TRIO_DEPENDENCY_TARGET_PYTHON', EMPTY_STRING) or EMPTY_STRING).strip():
                print(f'[WARN:deps] {label} pip target differs from launcher because TRIO_DEPENDENCY_TARGET_PYTHON is set.', file=sys.stderr, flush=True)
            else:
                print(f'[WARN:deps] {label} pip target differs from launcher; this can install packages into the wrong Python runtime.', file=sys.stderr, flush=True)

    def moduleAvailableInTargetPython(self, module_name: str) -> bool:
        module_text = _dependencyProbeModuleName(module_name)
        if not module_text:
            return False
        cache_key = (str(self.targetPythonExecutable() or EMPTY_STRING).strip(), module_text)
        cached = self._moduleAvailabilityCache.get(cache_key)
        if cached is not None:
            return bool(cached)
        target_python = self.targetPythonExecutable()
        if target_python:
            result = canInterpreterImportModule(target_python, module_text)
        else:
            result = hasModule(module_text)
        self._moduleAvailabilityCache[cache_key] = bool(result)
        return bool(result)

    def refreshModuleAvailabilityCacheForEntries(self, entries: list[dict[str, Any]]) -> None:
        target_python = self.targetPythonExecutable()
        if not target_python:
            return
        modules = []
        for entry in list(entries or []):
            module_text = _dependencyProbeModuleName(str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip())
            if module_text and module_text not in modules:
                modules.append(module_text)
        pending = [module for module in modules if (str(target_python), module) not in self._moduleAvailabilityCache]
        if not pending:
            return
        code = (
            'import importlib.util,json; '
            f'mods={pending!r}; '
            'out={}; '
            '[(out.__setitem__(m, importlib.util.find_spec(m) is not None)) for m in mods]; '
            'print(json.dumps(out))'
        )
        try:
            completed = launcherRunCommand([target_python, '-c', code], capture_output=True, text=True, timeout=20, check=False)
            if int(getattr(completed, 'returncode', 1) or 1) == 0:
                payload = json.loads(str(getattr(completed, 'stdout', EMPTY_STRING) or '{}').strip() or '{}')
                if isinstance(payload, dict):
                    for module, available in payload.items():
                        self._moduleAvailabilityCache[(str(target_python), str(module))] = bool(available)
        except Exception as error:
            recordException('start.py:11756', sys.exc_info()[1])
            print(f'[WARN:deps] batch module probe failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)

    def missingPythonDependencyEntries(self) -> list[dict[str, Any]]:
        entries = self.pythonDependencyEntries()
        self.refreshModuleAvailabilityCacheForEntries(entries)
        missing: list[dict[str, Any]] = []
        for entry in entries:
            import_name = str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()
            if import_name and not self.moduleAvailableInTargetPython(import_name):
                missing.append(dict(entry))
        return missing

    def missingPythonModules(self) -> list[tuple[str, str]]:
        missing_entries = self.missingPythonDependencyEntries()
        return [
            (
                str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip(),
                self.dependencyPackageName(entry, 'pip_package'),
            )
            for entry in missing_entries
        ]

    @staticmethod
    def uniquePackagesFromDependencyEntries(entries: list[dict[str, Any]], field_name: str) -> list[str]:
        packages: list[str] = []
        for entry in list(entries or []):
            package_name = str(entry.get(field_name, EMPTY_STRING) or EMPTY_STRING).strip()
            if package_name and package_name not in packages:
                packages.append(package_name)
        return packages

    @staticmethod
    def uniquePackagesForMissingModules(missing_modules: list[tuple[str, str]]) -> list[str]:
        packages: list[str] = []
        for _, package_name in list(missing_modules or []):
            package_text = str(package_name or EMPTY_STRING).strip()
            if package_text and package_text not in packages:
                packages.append(package_text)
        return packages

    def targetPythonScriptDirectories(self) -> list[str]:
        executable = str(self.targetPythonExecutable() or sys.executable or EMPTY_STRING).strip()
        if not executable:
            return []
        candidates: list[str] = []
        try:
            exe_path = Path(executable).resolve()
        except Exception:
            recordException('start.py:11804', sys.exc_info()[1])
            exe_path = Path(executable)
        base_dir = exe_path.parent
        if os.name == 'nt':
            candidates.extend([
                str(base_dir / 'Scripts'),
                str(base_dir),
            ])
        else:
            candidates.extend([
                str(base_dir),
                str(base_dir / 'bin'),
                str(base_dir.parent / 'bin'),
            ])
        try:
            probe = launcherRunCommand(
                [
                    executable,
                    '-c',
                    (
                        'import json, os, sysconfig; '
                        'paths=[]; '
                        'scripts=str(sysconfig.get_path("scripts") or "").strip(); '
                        'paths.append(scripts) if scripts else None; '
                        'print(json.dumps(paths))'
                    ),
                ],
                capture_output=True,
                text=True,
                timeout=30,
                check=False,
            )
            if int(getattr(probe, 'returncode', 1) or 1) == 0:
                payload = json.loads(str(probe.stdout or '[]').strip() or '[]')
                for item in list(payload or []):
                    item_text = str(item or EMPTY_STRING).strip()
                    if item_text:
                        candidates.append(item_text)
        except Exception:
            recordException('start.py:11842', sys.exc_info()[1])
            _traceSwallowedException('start.py:11653', sys.exc_info()[1])
            pass
        seen: set[str] = set()
        results: list[str] = []
        for item in candidates:
            item_text = str(item or EMPTY_STRING).strip().strip('"')
            if not item_text:
                continue
            key = item_text.lower()
            if key in seen:
                continue
            seen.add(key)
            results.append(item_text)
        return results

    def syncPythonToolPaths(self) -> list[str]:
        added: list[str] = []
        for path_text in self.targetPythonScriptDirectories():
            try:
                path_obj = Path(path_text)
            except Exception:
                recordException('start.py:11863', sys.exc_info()[1])
                _traceSwallowedException('start.py:11673', sys.exc_info()[1])
                continue
            if not path_obj.exists() or not path_obj.is_dir():
                continue
            current_path = str(os.environ.get('PATH', EMPTY_STRING) or EMPTY_STRING)
            parts = [part for part in current_path.split(os.pathsep) if str(part or EMPTY_STRING).strip()]
            normalized = {str(Path(part)).lower() for part in parts if str(part or EMPTY_STRING).strip()}
            resolved_text = str(path_obj)
            if resolved_text.lower() in normalized:
                continue
            os.environ['PATH'] = os.pathsep.join([resolved_text, *parts])
            added.append(resolved_text)
        return added

    @staticmethod
    def commandAvailable(command_name: str) -> bool:
        return bool(shutil.which(str(command_name or EMPTY_STRING).strip()))

    def fontComposerDependencyEntries(self) -> list[dict[str, Any]]:
        names = {'fontTools.ttLib', 'fontTools.merge', 'fontTools.subset', 'fontTools.ttx', 'nanoemoji', 'fontforge', 'psMat', 'brotli', 'zopfli'}
        return [dict(entry) for entry in self.pythonDependencyEntries() if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() in names]

    def fontComposerDependencyStatusRows(self) -> list[dict[str, Any]]:
        rows: list[dict[str, Any]] = []
        for entry in self.fontComposerDependencyEntries():
            import_name = str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()
            pip_package = str(entry.get('pip_package', EMPTY_STRING) or EMPTY_STRING).strip()
            install_hint = EMPTY_STRING
            command_names: list[str] = []
            if import_name.startswith('fontTools.'):
                if import_name == 'fontTools.merge':
                    command_names = ['pyftmerge', 'fonttools']
                elif import_name == 'fontTools.subset':
                    command_names = ['pyftsubset', 'fonttools']
                elif import_name == 'fontTools.ttx':
                    command_names = ['ttx', 'fonttools']
                install_hint = 'pip install fonttools'
            elif import_name == 'nanoemoji':
                command_names = ['nanoemoji']
                install_hint = 'pip install nanoemoji'
            elif import_name in {'fontforge', 'psMat'}:
                command_names = ['fontforge', 'fontforge-console', 'ffpython']
                install_hint = 'pip install fontforge (supplies fontforge + psMat); OS app installers are last-ditch fallbacks'
            elif import_name == 'brotli':
                install_hint = 'pip install brotli'
            elif import_name == 'zopfli':
                install_hint = 'pip install zopfli'
            command_available = any(self.commandAvailable(name) for name in command_names) if command_names else False
            import_available = self.moduleAvailableInTargetPython(import_name)
            import_error = EMPTY_STRING
            cached_status = FONT_COMPOSER_IMPORT_STATUS.get(import_name)
            if isinstance(cached_status, dict):
                import_error = str(cached_status.get('error', EMPTY_STRING) or EMPTY_STRING).strip()
            rows.append({
                'import_name': import_name,
                'pip_package': pip_package,
                'install_hint': install_hint,
                'import_available': import_available,
                'command_names': list(command_names),
                'command_available': command_available,
                'import_error': import_error,
            })
        return rows

    def installMissingFontComposerDependencies(self) -> None:
        global _FONT_COMPOSER_AUTOINSTALL_ATTEMPTED
        self.syncPythonToolPaths()
        dependency_registry = Dependencies.fromLegacyRows(self.fontComposerDependencyEntries())
        missing_dependencies = dependency_registry.missing(self)
        if not missing_dependencies:
            return
        missing_modules: list[str] = []
        for dependency in missing_dependencies:
            missing_modules.extend(dependency.missingModules(self))
        install_font_deps = str(os.environ.get('TRIO_INSTALL_FONT_DEPS', EMPTY_STRING) or os.environ.get('TRIO_INSTALL_OPTIONAL_DEPS', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'}
        if not install_font_deps:
            print(f'[WARN:font-deps] Missing optional font composer Python modules: {", ".join(missing_modules)}', file=sys.stderr, flush=True)
            print('[TRACE:font-deps] optional font composer auto-install skipped; set TRIO_INSTALL_FONT_DEPS=1 to attempt fontforge/psMat repair.', file=sys.stderr, flush=True)
            return
        if _FONT_COMPOSER_AUTOINSTALL_ATTEMPTED:
            print(f'[WARN:font-deps] Missing font composer Python modules after prior install attempt; not repeating installers in this run: {", ".join(missing_modules)}', file=sys.stderr, flush=True)
            return
        _FONT_COMPOSER_AUTOINSTALL_ATTEMPTED = True
        print(f'[WARN:font-deps] Missing font composer Python modules; auto-install will be attempted once: {", ".join(missing_modules)}', file=sys.stderr, flush=True)
        print('[TRACE:font-deps] psMat is an import check only; installing package fontforge supplies fontforge + psMat.', file=sys.stderr, flush=True)
        for dependency in missing_dependencies:
            dependency.install(self)
        self.syncPythonToolPaths()
        self._moduleAvailabilityCache.clear()
        _IMPORT_MODULE_CACHE.clear()
        importlib.invalidate_caches()

    def warnForFontComposerDependencies(self, force: bool = False, autoInstall: bool = True) -> None:
        self.syncPythonToolPaths()
        debugger_safe = bool(scanDisabled(self.argv) or debugEnabled(self.argv) or offscreenRequested(self.argv) or cliHasAnyFlag(self.argv, CLEAN_FLAGS))
        if debugger_safe and str(os.environ.get('TRIO_FONT_DEPS_AUTOINSTALL_DEBUG_SAFE', EMPTY_STRING) or EMPTY_STRING).strip().lower() not in {'1', 'true', 'yes', 'y', 'on'}:
            autoInstall = False
        if autoInstall and str(os.environ.get('TRIO_FONT_DEPS_AUTOINSTALL', '1') or '1').strip().lower() not in {'0', 'false', 'no', 'off'}:
            self.installMissingFontComposerDependencies()
        rows = self.fontComposerDependencyStatusRows()
        if not rows:
            return
        show = bool(force)
        if not show:
            for row in rows:
                if not bool(row.get('import_available')) or (row.get('command_names') and not bool(row.get('command_available'))):
                    show = True
                    break
        if not show:
            return
        print('[TRACE:font-deps] font composer dependency report', file=sys.stderr, flush=True)
        for row in rows:
            module_name = str(row.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()
            import_available = bool(row.get('import_available'))
            command_names = list(row.get('command_names') or [])
            command_available = bool(row.get('command_available')) if command_names else True
            install_hint = str(row.get('install_hint', EMPTY_STRING) or EMPTY_STRING).strip()
            import_error = str(row.get('import_error', EMPTY_STRING) or EMPTY_STRING).strip()
            commands_text = ','.join(command_names) if command_names else EMPTY_STRING
            status = 'OK' if import_available and command_available else 'MISSING'
            line = f'[TRACE:font-deps] {module_name} status={status} import={import_available}'
            if command_names:
                line += f' commands={commands_text} command_ok={command_available}'
                if module_name in {'fontforge', 'psMat'} and command_available and not import_available:
                    line += ' command_only_does_not_satisfy_python_import=True'
            if install_hint:
                line += f' hint={install_hint}'
            if import_error and not import_available:
                line += f' error={import_error[:240]}'
            print(line, file=sys.stderr, flush=True)

    def requiredAptPythonPackages(self) -> list[str]:
        return self.uniquePackagesFromDependencyEntries(self.missingPythonDependencyEntries(), 'apt_package')

    @staticmethod
    def wingetInstallIds(import_names: list[str] | tuple[str, ...] | None = None) -> dict[str, str]:
        mapping = {
            'fontforge': 'FontForge.FontForge',
            'psMat': 'FontForge.FontForge',
        }
        ids: dict[str, str] = {}
        for import_name in list(import_names or []):
            import_text = str(import_name or EMPTY_STRING).strip()
            winget_id = str(mapping.get(import_text, EMPTY_STRING) or EMPTY_STRING).strip()
            if import_text and winget_id:
                ids[import_text] = winget_id
        return ids

    def attemptWingetInstall(self, winget_ids: dict[str, str] | list[str] | tuple[str, ...] | None = None) -> bool:
        if isinstance(winget_ids, dict):
            requested = [(str(import_name or EMPTY_STRING).strip(), str(package_id or EMPTY_STRING).strip()) for import_name, package_id in winget_ids.items()]
        else:
            requested = [(EMPTY_STRING, str(item or EMPTY_STRING).strip()) for item in list(winget_ids or [])]
        deduped: list[tuple[str, str]] = []
        seen_ids: set[str] = set()
        for import_name, package_id in requested:
            if package_id and package_id not in seen_ids:
                deduped.append((import_name, package_id))
                seen_ids.add(package_id)
        if not self.isWindows() or not deduped:
            return False
        winget = shutil.which('winget.exe') or shutil.which('winget')
        if not winget:
            return False
        installed_any = False
        for import_name, winget_id in deduped:
            command = [winget, 'install', '--id', winget_id, '-e', '--silent', '--disable-interactivity', '--accept-package-agreements', '--accept-source-agreements']
            import_detail = f' import={import_name}' if import_name else EMPTY_STRING
            print(f'[TRACE:deps] winget install id={winget_id}{import_detail}', file=sys.stderr, flush=True)
            if self.runCommand(command, label=f'winget install {winget_id}', timeout=240):
                installed_any = True
            else:
                print(f'[WARN:deps] winget install failed or timed out for {winget_id}{import_detail}', file=sys.stderr, flush=True)
        return installed_any

    @staticmethod
    def expandLinuxSystemPackageNames(packages: list[str] | tuple[str, ...] | None = None) -> list[str]:
        # Some bundled .deb packages need dependency packages that are not visible
        # from the direct tool requirement. Include the known closure so apt can
        # repair/install them automatically when the distro repository is usable.
        dependency_closure = {
            'x11-apps': ['man-db'],
            'xdotool': ['libxdo3'],
            'python3-fontforge': ['fontforge'],
            'fontforge': ['python3-fontforge'],
        }
        expanded: list[str] = []
        for raw_package in list(packages or []):
            package_name = str(raw_package or EMPTY_STRING).strip()
            if not package_name:
                continue
            for candidate in [package_name, *dependency_closure.get(package_name, [])]:
                candidate_text = str(candidate or EMPTY_STRING).strip()
                if candidate_text and candidate_text not in expanded:
                    expanded.append(candidate_text)
        return expanded

    def attemptAptSystemPackageInstall(self, packages: list[str] | tuple[str, ...] | None = None) -> bool:
        package_names = [str(item or EMPTY_STRING).strip() for item in list(packages or []) if str(item or EMPTY_STRING).strip()]
        if not self.isLinux() or not package_names:
            return False
        apt_get = shutil.which('apt-get')
        if not apt_get:
            return False
        expanded_package_names = self.expandLinuxSystemPackageNames(package_names)
        sudo = shutil.which('sudo')
        prefix: list[str] = []
        if not self.isPosixRoot():
            if not sudo:
                print(f"[WARN:deps] apt install skipped; not root and sudo unavailable. packages={', '.join(package_names)}", file=sys.stderr, flush=True)
                return False
            if not self.nonInteractiveSudoAvailable():
                print(f"[WARN:deps] apt install skipped; non-interactive sudo is unavailable. packages={', '.join(package_names)}", file=sys.stderr, flush=True)
                return False
            prefix = [sudo, '-n']
        command = [*prefix, apt_get, 'install', '-y', *expanded_package_names]
        print(f"[TRACE:deps] apt install packages: {', '.join(package_names)}", file=sys.stderr, flush=True)
        succeeded, stdout_text, stderr_text, _ = self.runCommandDetailed(command, label='apt system package install', timeout=1800)
        if succeeded:
            return True
        haystack = '\n'.join([stdout_text, stderr_text]).lower()
        should_update = any(marker in haystack for marker in ('unable to locate package', 'no installation candidate', 'has been obsoleted'))
        update_allowed = str(os.environ.get('TRIO_APT_UPDATE_ON_MISSING', '1') or '1').strip().lower() not in {'0', 'false', 'no', 'off'}
        if should_update and update_allowed:
            print('[WARN:deps] apt package metadata could not locate one or more packages; running apt-get update once, then retrying install.', file=sys.stderr, flush=True)
            update_command = [*prefix, apt_get, 'update']
            update_ok, _, _, _ = self.runCommandDetailed(update_command, label='apt metadata update', timeout=600)
            if update_ok:
                return self.runCommand(command, label='apt system package install after update', timeout=1800)
            print('[WARN:deps] apt-get update failed or timed out; local /debs or manual OS package install is still required.', file=sys.stderr, flush=True)
        return False

    @staticmethod
    def nonInteractiveSudoAvailable() -> bool:
        sudo = shutil.which('sudo')
        if not sudo:
            return False
        try:
            completed = launcherRunCommand([sudo, '-n', 'true'], capture_output=True, text=True, timeout=5, check=False)
            return int(getattr(completed, 'returncode', 1)) == 0
        except Exception:
            recordException('start.py:12104', sys.exc_info()[1])
            return False

    @staticmethod
    def isWindowsAdmin() -> bool:
        try:
            import ctypes
            windll = getattr(ctypes, "windll")
            return bool(windll.shell32.IsUserAnAdmin())
        except Exception:
            recordException('start.py:12113', sys.exc_info()[1])
            return False

    @staticmethod
    def isPosixRoot() -> bool:
        geteuid = getattr(os, 'geteuid', None)
        if not callable(geteuid):
            return False
        try:
            return int(cast(Any, geteuid)()) == 0
        except Exception:
            recordException('start.py:12123', sys.exc_info()[1])
            return False

    @staticmethod
    def libExists(lookupName: str, reportedName: str = EMPTY_STRING) -> bool:
        report = str(reportedName or lookupName or EMPTY_STRING).strip()
        located = EMPTY_STRING
        try:
            located = str(ctypes.util.find_library(lookupName) or EMPTY_STRING).strip()
        except Exception:
            recordException('start.py:12132', sys.exc_info()[1])
            located = EMPTY_STRING
        candidate_names: list[str] = []
        for raw_name in (report, located):
            name = str(raw_name or EMPTY_STRING).strip()
            if name and name not in candidate_names:
                candidate_names.append(name)
        candidates: list[str] = []
        for root in packagedLinuxRuntimeLibDirs():
            for name in candidate_names:
                candidate = str((Path(root) / name))
                if candidate not in candidates:
                    candidates.append(candidate)
        for raw_name in candidate_names:
            name = str(raw_name or EMPTY_STRING).strip()
            if not name:
                continue
            if os.path.isabs(name):
                if name not in candidates:
                    candidates.append(name)
                continue
            for prefix in (
                '/usr/lib/x86_64-linux-gnu',
                '/usr/lib64',
                '/usr/lib',
                '/lib/x86_64-linux-gnu',
                '/lib64',
                '/lib',
            ):
                candidate = f'{prefix}/{name}'
                if candidate not in candidates:
                    candidates.append(candidate)
        return any(Path(candidate).exists() for candidate in candidates)

    def linuxSystemRequirements(self) -> list[dict[str, Any]]:
        if not self.isLinux():
            return []
        requirements: list[dict[str, Any]] = []
        if self.isGuiRequired():
            requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('qt_x11_runtime', ())))
        if offscreenRequested(self.argv):
            requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('offscreen_common_tools', ())))
            engineKind = self.requestedCaptureEngineKind()
            if engineKind == 'xdummy':
                requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('xdummy_tools', ())))
            elif engineKind == 'xpra':
                requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('xvfb_tools', ())))
                requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('xpra_tools', ())))
            else:
                requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('xvfb_tools', ())))
            if self.experimentalAlphaRequested():
                requirements.extend(list(self.LINUX_SYSTEM_GROUPS.get('experimental_alpha_tools', ())))
        return [dict(item) for item in requirements]

    @staticmethod
    def toolCandidates(requirement: dict[str, Any]) -> list[str]:
        names: list[str] = []
        primary = str(requirement.get('name', EMPTY_STRING) or EMPTY_STRING).strip()
        if primary:
            names.append(primary)
        for raw_name in list(requirement.get('alternatives', []) or []):
            name = str(raw_name or EMPTY_STRING).strip()
            if name and name not in names:
                names.append(name)
        return names

    def toolAvailable(self, requirement: dict[str, Any]) -> bool:
        return any(shutil.which(name) for name in self.toolCandidates(requirement))

    def missingLinuxSystemRequirements(self) -> list[dict[str, Any]]:
        missing: list[dict[str, Any]] = []
        for requirement in self.linuxSystemRequirements():
            kind = str(requirement.get('kind', EMPTY_STRING) or EMPTY_STRING)
            name = str(requirement.get('name', EMPTY_STRING) or EMPTY_STRING)
            is_missing = False
            if kind == 'tool':
                is_missing = not self.toolAvailable(requirement)
            elif kind == 'library':
                lookup_name = str(requirement.get('lookup', EMPTY_STRING) or name)
                is_missing = not self.libExists(lookup_name, reportedName=name)
            elif kind == 'path':
                candidates = [str(item or EMPTY_STRING).strip() for item in list(requirement.get('candidates', []) or []) if str(item or EMPTY_STRING).strip()]
                is_missing = not any(Path(candidate).exists() for candidate in candidates)
            if is_missing:
                missing.append(requirement)
        return missing



    @staticmethod
    def dependencyCommandTimeout(command: list[str], timeout: int = 300) -> int:
        timeout_value = max(1, int(timeout or 1))
        command_text = ' '.join([str(part or EMPTY_STRING) for part in list(command or [])]).lower()
        env_timeout = str(os.environ.get('TRIO_DEPENDENCY_TIMEOUT', EMPTY_STRING) or EMPTY_STRING).strip()
        # When the operator gives TRIO_DEPENDENCY_TIMEOUT, honor it as a hard
        # debugger/recovery limit.  This is what lets FlatLine keep breathing
        # during broken dependency recovery instead of vanishing behind pip/winget.
        if env_timeout.isdigit():
            return max(5, int(env_timeout))
        is_pip = ' -m pip ' in f' {command_text} ' or command_text.strip().startswith('pip ')
        is_winget = 'winget' in command_text
        # Winget/installer UI can wedge the launcher if allowed to run forever.
        # It still runs in a managed child process, but dependency recovery must
        # yield back to the FlatLine debugger quickly enough for D/status/crash
        # handling to remain useful.
        if is_winget:
            winget_timeout = str(os.environ.get('TRIO_WINGET_TIMEOUT', EMPTY_STRING) or EMPTY_STRING).strip()
            return max(30, min(int(winget_timeout) if winget_timeout.isdigit() else timeout_value, 180))
        if 'pyside6' in command_text:
            pyside_timeout = str(os.environ.get('TRIO_PYSIDE_TIMEOUT', EMPTY_STRING) or EMPTY_STRING).strip()
            if pyside_timeout.isdigit():
                return max(60, int(pyside_timeout))
            return max(900, min(timeout_value, PIP_HEAVY_PACKAGE_TIMEOUT_SECONDS))
        heavy_packages = ('sqlalchemy', 'torch', 'tensorflow', 'opencv', 'numpy')
        if is_pip or any(package in command_text for package in heavy_packages):
            return max(300, min(timeout_value, PIP_HEAVY_PACKAGE_TIMEOUT_SECONDS))
        return max(30, min(timeout_value, 300))

    @staticmethod
    def _emitStreamedCommandLine(source: str, line: str) -> None:
        text = str(line or EMPTY_STRING).rstrip('\r\n')
        if not text:
            return
        print(f"[TRACE:deps:{source}] {text}", flush=True)

    @staticmethod
    def _streamCommandPipe(pipe, source: str, bucket: list[str]) -> None:
        try:
            while True:
                raw = pipe.readline()
                if raw == EMPTY_STRING:
                    break
                bucket.append(raw)
                StartDependencyRegistry._emitStreamedCommandLine(source, raw)
        except Exception as error:
            recordException('start.py:12266', sys.exc_info()[1])
            print(f"[WARN:deps] stream {source} failed: {type(error).__name__}: {error}", flush=True)
        finally:
            try:
                pipe.close()
            except Exception:
                recordException('start.py:12271', sys.exc_info()[1])
                _traceSwallowedException('start.py:12075', sys.exc_info()[1])
                pass

    @staticmethod
    def _relayFileDelta(path: str | Path, offset: int, source: str, bucket: list[str]) -> int:
        file_path = Path(path)
        if not file_path.exists():
            return offset
        try:
            with File(file_path).open('r', encoding='utf-8', errors='replace') as handle:
                handle.seek(offset)
                chunk = handle.read()
                new_offset = handle.tell()
        except Exception as error:
            recordException('start.py:12285', sys.exc_info()[1])
            print(f"[WARN:deps] tail {source} failed: {type(error).__name__}: {error}", flush=True)
            return offset
        if not chunk:
            return new_offset
        bucket.append(chunk)
        for line in chunk.splitlines():
            StartDependencyRegistry._emitStreamedCommandLine(source, line)
        return new_offset

    @staticmethod
    def _windowsProcessExists(pid: int) -> bool:
        if int(pid or 0) <= 0:
            return False
        try:
            completed = launcherRunCommand(['tasklist', '/FI', f'PID eq {int(pid)}'], capture_output=True, text=True, timeout=15, check=False)
            haystack = '\n'.join([str(completed.stdout or EMPTY_STRING), str(completed.stderr or EMPTY_STRING)])
            return str(int(pid)) in haystack
        except Exception:
            recordException('start.py:12303', sys.exc_info()[1])
            return False

    @staticmethod
    def _spawnStandaloneWorkerProcess(target, name: str, daemon: bool = True):
        return StartWorkerProcess(target=target, name=str(name or 'StartWorkerProcess'), daemon=bool(daemon)).start()

    @staticmethod
    def _waitForStreamedProcess(command: list[str], *, label: str = EMPTY_STRING, timeout: int = 900) -> tuple[bool, str, str, int]:
        effective_timeout = StartDependencyRegistry.dependencyCommandTimeout(command, timeout)
        process = StartProcess(
            command,
            name=f'DependencyCommand:{label or Path(str(command[0])).name if command else "command"}',
            ttlSeconds=float(effective_timeout or 0),
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            encoding='utf-8',
            errors='replace',
            bufsize=1,
        )
        try:
            process.start()
            pid = int(getattr(process, 'pid', 0) or 0)
            print(f'[TRACE:dependency-command] pid={pid} label={label}', file=sys.stderr, flush=True)
            stdout_text, stderr_text = process.communicate(timeout=effective_timeout)
        except Exception as error:
            recordException('start.py:12327', sys.exc_info()[1])
            stdout_text = EMPTY_STRING
            stderr_text = f'{type(error).__name__}: {error}'
            try:
                process.kill(reason=f'dependency command failed: {type(error).__name__}')
            except Exception:
                recordException('start.py:12332', sys.exc_info()[1])
                _traceSwallowedException('start.py:12135', sys.exc_info()[1])
                pass
            return False, stdout_text, stderr_text, int(getattr(process, 'returnCode', 1) or 1)
        for line in str(stdout_text or EMPTY_STRING).splitlines():
            StartDependencyRegistry._emitStreamedCommandLine('stdout', line)
        for line in str(stderr_text or EMPTY_STRING).splitlines():
            StartDependencyRegistry._emitStreamedCommandLine('stderr', line)
        returncode = int(getattr(process, 'returnCode', 0) or 0)
        return returncode == 0, str(stdout_text or EMPTY_STRING).strip(), str(stderr_text or EMPTY_STRING).strip(), returncode

    @staticmethod
    def runCommandDetailed(command: list[str], *, label: str = EMPTY_STRING, timeout: int = 900) -> tuple[bool, str, str, int]:
        try:
            effective_timeout = StartDependencyRegistry.dependencyCommandTimeout(command, timeout)
            print(f"[TRACE:deps] {label or 'running'}: {' '.join(command)}  timeout={effective_timeout}s", flush=True)
            return StartDependencyRegistry._waitForStreamedProcess(command, label=label, timeout=effective_timeout)
        except Exception as error:
            recordException('start.py:12349', sys.exc_info()[1])
            print(f"[WARN:deps] {label or 'command'} failed: {type(error).__name__}: {error}", flush=True)
            return False, EMPTY_STRING, str(error), 1

    @staticmethod
    def runCommand(command: list[str], *, label: str = EMPTY_STRING, timeout: int = 900) -> bool:
        succeeded, _, _, _ = StartDependencyRegistry.runCommandDetailed(command, label=label, timeout=timeout)
        return succeeded

    @staticmethod
    def outputLooksLikePermissionError(stdout_text: str, stderr_text: str) -> bool:
        haystack = '\n'.join([str(stdout_text or EMPTY_STRING), str(stderr_text or EMPTY_STRING)]).lower()
        permission_markers = (
            'permission denied',
            'access is denied',
            'winerror 5',
            'errno 13',
            'operation not permitted',
            'could not install packages due to an oserror',
            'site-packages is not writeable',
            'site-packages is not writable',
            'not writeable',
            'not writable',
            'requires administrator',
        )
        return any(marker in haystack for marker in permission_markers)



    @staticmethod
    def _versionTupleFromText(version_text: str) -> tuple[int, int, int]:
        match = re.search(r'(\d+)\.(\d+)(?:\.(\d+))?', str(version_text or EMPTY_STRING))
        if not match:
            return (0, 0, 0)
        return (int(match.group(1)), int(match.group(2)), int(match.group(3) or 0))

    @staticmethod
    def pipPersistentDirs() -> dict[str, Path]:
        dirs = {
            'root': PIP_PACKAGE_ROOT,
            'cache': PIP_CACHE_DIR,
            'wheelhouse': PIP_WHEELHOUSE_DIR,
            'parts': PIP_PARTS_DIR,
            'logs': PIP_LOG_DIR,
        }
        for directory in dirs.values():
            directory.mkdir(parents=True, exist_ok=True)
        return dirs

    @staticmethod
    def pipEnvironment() -> dict[str, str]:
        dirs = StartDependencyRegistry.pipPersistentDirs()
        env = dict(os.environ)
        env['PIP_CACHE_DIR'] = str(dirs['cache'])
        env['PIP_RETRIES'] = str(PIP_DEFAULT_RETRIES)
        env['PIP_RESUME_RETRIES'] = str(PIP_DEFAULT_RESUME_RETRIES)
        env['PIP_TIMEOUT'] = str(PIP_DEFAULT_TIMEOUT_SECONDS)
        env['PIP_DEFAULT_TIMEOUT'] = str(PIP_DEFAULT_TIMEOUT_SECONDS)
        env.setdefault('PIP_DISABLE_PIP_VERSION_CHECK', '0')
        return env

    @staticmethod
    def pipBaseOptions(*, includeResume: bool = True) -> list[str]:
        StartDependencyRegistry.pipPersistentDirs()
        options = [
            '--cache-dir', str(PIP_CACHE_DIR),
            '--retries', str(PIP_DEFAULT_RETRIES),
            '--timeout', str(PIP_DEFAULT_TIMEOUT_SECONDS),
            '--progress-bar', 'off',
        ]
        if includeResume:
            options.extend(['--resume-retries', str(PIP_DEFAULT_RESUME_RETRIES)])
        return options

    @staticmethod
    def pipVersion(executable: str) -> tuple[int, int, int]:
        try:
            completed = launcherRunCommand(
                [executable, '-m', 'pip', '--version'],
                capture_output=True,
                text=True,
                timeout=45,
                check=False,
            )
            return StartDependencyRegistry._versionTupleFromText('\n'.join([str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING), str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)]))
        except Exception as error:
            recordException('start.py:pipVersion', sys.exc_info()[1])
            print(f'[WARN:deps] pip version probe failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return (0, 0, 0)

    def ensureModernPip(self, executable: str) -> None:
        if not executable:
            return
        checked = getattr(self, '_modernPipChecked', set())
        if not isinstance(checked, set):
            checked = set()
        if executable in checked:
            return
        checked.add(executable)
        setattr(self, '_modernPipChecked', checked)
        self.tracePipInterpreterTarget(executable, 'pip self-upgrade')
        before = self.pipVersion(executable)
        print(f'[TRACE:deps] pip version before upgrade for {executable}: {before}', file=sys.stderr, flush=True)
        command = [executable, '-m', 'pip', 'install', *self.pipBaseOptions(includeResume=False), '--upgrade', 'pip']
        succeeded, stdout_text, stderr_text, return_code = self.runCommandDetailed(command, label='pip self-upgrade with persistent cache', timeout=PIP_BOOTSTRAP_TIMEOUT_SECONDS)
        after = self.pipVersion(executable)
        print(f'[TRACE:deps] pip version after upgrade for {executable}: {after} rc={return_code}', file=sys.stderr, flush=True)
        if not succeeded:
            print('[WARN:deps] pip self-upgrade failed; continuing with installed pip but resumable downloads may be limited.', file=sys.stderr, flush=True)
            if self.outputLooksLikePackageUnavailable(stdout_text, stderr_text):
                print('[WARN:deps] pip package was unexpectedly unavailable during self-upgrade.', file=sys.stderr, flush=True)

    @staticmethod
    def pipSupportsResumeRetries(executable: str) -> bool:
        version = StartDependencyRegistry.pipVersion(executable)
        return tuple(version) >= tuple(PIP_SUPPORTS_RESUME_RETRIES_MIN_VERSION)

    @staticmethod
    def pipInstallTimeoutForPackages(packages: list[str], default: int = 1800) -> int:
        names = ' '.join(str(package or EMPTY_STRING).lower() for package in list(packages or []))
        if any(token in names for token in ('pyside6', 'torch', 'tensorflow', 'opencv', 'numpy')):
            return max(int(default or 0), PIP_HEAVY_PACKAGE_TIMEOUT_SECONDS)
        return max(int(default or 0), 1800)

    def pipOptionsForExecutable(self, executable: str) -> list[str]:
        return self.pipBaseOptions(includeResume=self.pipSupportsResumeRetries(executable))

    def predownloadPipPackages(self, packages: list[str], *, executable: str, breakSystemPackages: bool = False) -> bool:
        package_list = [str(package or EMPTY_STRING).strip() for package in list(packages or []) if str(package or EMPTY_STRING).strip()]
        if not package_list or not executable:
            return True
        self.pipPersistentDirs()
        self.tracePipInterpreterTarget(executable, 'pip download')
        command = [
            executable, '-m', 'pip', 'download',
            *self.pipOptionsForExecutable(executable),
            '--dest', str(PIP_WHEELHOUSE_DIR),
            '--prefer-binary',
        ]
        # pip download does not accept --break-system-packages; that flag is only
        # valid for install/self-upgrade paths under PEP 668 environments.
        command.extend(package_list)
        succeeded, _, stderr_text, return_code = self.runCommandDetailed(
            command,
            label=f'pip wheelhouse predownload {", ".join(package_list)}',
            timeout=self.pipInstallTimeoutForPackages(package_list, PIP_HEAVY_PACKAGE_TIMEOUT_SECONDS),
        )
        if succeeded:
            print(f'[TRACE:deps] pip wheelhouse ready: {PIP_WHEELHOUSE_DIR}', file=sys.stderr, flush=True)
            return True
        print(f'[WARN:deps] pip wheelhouse predownload failed rc={return_code}; direct install will still use persistent cache. {stderr_text[:400]}', file=sys.stderr, flush=True)
        return False

    def buildPipInstallCommand(self, executable: str, packages: list[str], *, useUser: bool = False, breakSystemPackages: bool = False, preferBinary: bool = True) -> list[str]:
        command = [executable, '-m', 'pip', 'install', *self.pipOptionsForExecutable(executable)]
        if useUser:
            command.append('--user')
        if breakSystemPackages and self.isLinux():
            command.append('--break-system-packages')
        if PIP_WHEELHOUSE_DIR.exists() and any(PIP_WHEELHOUSE_DIR.glob('*')):
            command.extend(['--find-links', str(PIP_WHEELHOUSE_DIR)])
        if preferBinary:
            command.append('--prefer-binary')
        command.extend([str(package or EMPTY_STRING).strip() for package in list(packages or []) if str(package or EMPTY_STRING).strip()])
        return command

    @staticmethod
    def outputLooksLikePackageUnavailable(stdout_text: str, stderr_text: str) -> bool:
        haystack = '\n'.join([str(stdout_text or EMPTY_STRING), str(stderr_text or EMPTY_STRING)]).lower()
        unavailable_markers = (
            'no matching distribution found',
            'could not find a version that satisfies the requirement',
            'not a supported wheel on this platform',
        )
        return any(marker in haystack for marker in unavailable_markers)

    def attemptWindowsElevatedPipInstallDetailed(self, packages: list[str], *, pythonExecutable: str = EMPTY_STRING, timeout: int = 1800) -> tuple[bool, str, str, int]:
        if not self.isWindows() or not list(packages or []):
            return False, EMPTY_STRING, 'not Windows or no packages', 1
        executable = str(pythonExecutable or self.targetPythonExecutable() or sys.executable or EMPTY_STRING).strip()
        if not executable:
            return False, EMPTY_STRING, 'no target Python executable', 1
        package_list = [str(package or EMPTY_STRING).strip() for package in list(packages or []) if str(package or EMPTY_STRING).strip()]
        if not package_list:
            return True, EMPTY_STRING, EMPTY_STRING, 0
        self.tracePipInterpreterTarget(executable, 'windows elevated pip install')
        self.ensureModernPip(executable)
        self.predownloadPipPackages(package_list, executable=executable)
        command = self.buildPipInstallCommand(executable, package_list, preferBinary=True)
        return self.runCommandDetailed(command, label='windows elevated pip install with persistent cache', timeout=self.pipInstallTimeoutForPackages(package_list, timeout))

    def attemptWindowsElevatedPipInstall(self, packages: list[str], *, pythonExecutable: str = EMPTY_STRING) -> bool:
        succeeded, _, _, _ = self.attemptWindowsElevatedPipInstallDetailed(packages, pythonExecutable=pythonExecutable, timeout=1800)
        return succeeded

    def attemptLinuxSudoPipInstall(self, packages: list[str], *, pythonExecutable: str = EMPTY_STRING) -> bool:
        if not self.isLinux() or not list(packages or []):
            return False
        executable = str(pythonExecutable or self.targetPythonExecutable() or sys.executable or EMPTY_STRING).strip()
        if not executable:
            return False
        package_list = [str(package or EMPTY_STRING).strip() for package in list(packages or []) if str(package or EMPTY_STRING).strip()]
        self.tracePipInterpreterTarget(executable, 'linux sudo/root pip install')
        self.ensureModernPip(executable)
        self.predownloadPipPackages(package_list, executable=executable, breakSystemPackages=True)
        pip_args = self.buildPipInstallCommand(executable, package_list, breakSystemPackages=True, preferBinary=True)
        if self.isPosixRoot():
            return self.runCommand(pip_args, label='linux root pip install --break-system-packages with persistent cache', timeout=self.pipInstallTimeoutForPackages(package_list, 1800))
        sudo = shutil.which('sudo')
        if not sudo:
            print('[WARN:deps] Linux sudo was not found; falling back to non-elevated pip.', file=sys.stderr, flush=True)
            return False
        command = [sudo, '-n', *pip_args]
        succeeded = self.runCommand(command, label='linux sudo pip install --break-system-packages with persistent cache', timeout=self.pipInstallTimeoutForPackages(package_list, 1800))
        if not succeeded:
            print('[WARN:deps] Linux sudo pip install was denied or failed; falling back to non-elevated pip.', file=sys.stderr, flush=True)
        return succeeded



    def attemptPlainPipInstall(self, packages: list[str], *, pythonExecutable: str = EMPTY_STRING, useUser: bool = False, label: str = EMPTY_STRING, breakSystemPackages: bool = False) -> tuple[bool, bool]:
        if not list(packages or []):
            return True, False
        executable = str(pythonExecutable or self.targetPythonExecutable() or sys.executable or EMPTY_STRING).strip()
        if not executable:
            return False, False
        package_list = [str(package or EMPTY_STRING).strip() for package in list(packages or []) if str(package or EMPTY_STRING).strip()]
        self.tracePipInterpreterTarget(executable, label or f'{self.osFamily} pip install')
        self.ensureModernPip(executable)
        is_pyside_package = _dependencyPackageListContainsPySide(package_list)
        if is_pyside_package:
            print('[TRACE:deps] PySide6 missing; using persistent pip cache, wheelhouse predownload, retries, and resume-retries for the large wheel set.', file=sys.stderr, flush=True)
        self.predownloadPipPackages(package_list, executable=executable, breakSystemPackages=breakSystemPackages)
        command = self.buildPipInstallCommand(
            executable,
            package_list,
            useUser=useUser,
            breakSystemPackages=breakSystemPackages,
            preferBinary=True,
        )
        succeeded, stdout_text, stderr_text, _ = self.runCommandDetailed(command, label=label or f'{self.osFamily} pip install with persistent cache', timeout=self.pipInstallTimeoutForPackages(package_list, 1800))
        return succeeded, self.outputLooksLikePermissionError(stdout_text, stderr_text)

    def attemptUserPipInstall(self, packages: list[str], *, pythonExecutable: str = EMPTY_STRING) -> bool:
        succeeded, _ = self.attemptPlainPipInstall(packages, pythonExecutable=pythonExecutable, useUser=True, label=f'{self.osFamily} user pip install')
        return succeeded

    def installPythonPackage(self, pip_name: str, *, importName: str | None = None, timeout: int = 120) -> bool:
        """Install one Python package through the canonical persistent pip path."""
        package = str(pip_name or EMPTY_STRING).strip()
        if not package:
            return False
        module_name = str(importName or package or EMPTY_STRING).strip()
        if module_name and self.moduleAvailableInTargetPython(module_name):
            return True
        target_python = self.targetPythonExecutable()
        print(f'[TRACE:deps] installPythonPackage package={package} import={module_name or package} target={target_python}', file=sys.stderr, flush=True)
        succeeded, permission_error = self.attemptPlainPipInstall([package], pythonExecutable=target_python, useUser=False, label=f'launcher pip install {package}', breakSystemPackages=True)
        self._moduleAvailabilityCache.clear()
        _IMPORT_MODULE_CACHE.clear()
        importlib.invalidate_caches()
        if module_name and self.moduleAvailableInTargetPython(module_name):
            return True
        if permission_error:
            if self.isLinux() and self.attemptLinuxSudoPipInstall([package], pythonExecutable=target_python):
                self._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
                if not module_name or self.moduleAvailableInTargetPython(module_name):
                    return True
            if self.isWindows() and self.attemptWindowsElevatedPipInstall([package], pythonExecutable=target_python):
                self._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
                if not module_name or self.moduleAvailableInTargetPython(module_name):
                    return True
        if not succeeded:
            self.attemptUserPipInstall([package], pythonExecutable=target_python)
            self._moduleAvailabilityCache.clear(); _IMPORT_MODULE_CACHE.clear(); importlib.invalidate_caches()
        return bool(not module_name or self.moduleAvailableInTargetPython(module_name))


    def installMissingPythonDependencies(self) -> None:
        dependency_registry = Dependencies.fromLegacyRows(self.pythonDependencyEntries())
        missing_dependencies = dependency_registry.missing(self)
        if not missing_dependencies:
            return
        critical_imports = self.launcherCriticalImportNames()
        missing_dependencies.sort(key=lambda dependency: 0 if any(module in critical_imports for module in dependency.modules) else 1)
        target_python = self.targetPythonExecutable()
        missing_modules: list[str] = []
        for dependency in missing_dependencies:
            missing_modules.extend(dependency.missingModules(self))
        print(f"[TRACE:deps] platform={self.osFamily}", file=sys.stderr, flush=True)
        print(f"[TRACE:deps] target python={target_python or '(unavailable)'}", file=sys.stderr, flush=True)
        print(f"[TRACE:deps] dependency registry keywalk count={len(dependency_registry.items)} missing={len(missing_dependencies)}", file=sys.stderr, flush=True)
        print(f"[TRACE:deps] auto-installing missing modules: {', '.join([name for name in missing_modules if name])}", file=sys.stderr, flush=True)
        global _FONT_COMPOSER_AUTOINSTALL_ATTEMPTED
        for dependency in missing_dependencies:
            dependency.install(self)
            if dependency.name == 'fontforge_python_bindings':
                _FONT_COMPOSER_AUTOINSTALL_ATTEMPTED = True
        self.syncPythonToolPaths()

    def installMissingCriticalPythonDependencies(self) -> None:
        # Used by debugger-safe startup: do not wander into apt/winget/font
        # composer repair here.  Only repair Python modules that the child must
        # have before trio.py can import and paint.
        self.syncPythonToolPaths()
        critical_imports = self.launcherCriticalImportNames()
        missing_entries = [
            entry for entry in self.missingPythonDependencyEntries()
            if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() in critical_imports
        ]
        if not missing_entries:
            print('[TRACE:deps] critical Python dependencies already satisfied.', file=sys.stderr, flush=True)
            return
        missing_names = ', '.join(str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING) for entry in missing_entries)
        print(f'[TRACE:deps] critical Python dependency repair only: {missing_names}', file=sys.stderr, flush=True)
        dependency_registry = Dependencies.fromLegacyRows(missing_entries)
        missing_dependencies = dependency_registry.missing(self)
        target_python = self.targetPythonExecutable()
        print(f"[TRACE:deps] target python={target_python or '(unavailable)'}", file=sys.stderr, flush=True)
        for dependency in missing_dependencies:
            dependency.install(self)
        self.syncPythonToolPaths()

    def requiredLinuxSystemPackages(self, missing_requirements: list[dict[str, Any]]) -> list[str]:
        packages: list[str] = []
        for requirement in list(missing_requirements or []):
            package_name = str(requirement.get('package', EMPTY_STRING) or EMPTY_STRING).strip()
            if package_name and package_name not in packages:
                packages.append(package_name)
        return packages

    def attemptLinuxSystemPackageInstall(self, missing_requirements: list[dict[str, Any]]) -> bool:
        if not self.isLinux() or not list(missing_requirements or []):
            return False
        package_names = self.requiredLinuxSystemPackages(missing_requirements)
        if not package_names:
            return False
        installed = self.attemptBundledLinuxSystemPackageInstall(missing_requirements)
        if installed:
            return True
        return self.attemptAptSystemPackageInstall(package_names)

    def attemptLinuxPythonPackageInstall(self, packages: list[str]) -> bool:
        _ = packages
        return False

    def bundledLinuxPackageCandidates(self, package_name: str) -> list[Path]:
        package_text = str(package_name or EMPTY_STRING).strip()
        if not package_text or not self.isLinux():
            return []
        roots = []
        for candidate_root in (DEPLOY_MONITOR_DIR, LINUX_RUNTIME_DIR, ABSOLUTE_DEBS_DIR, ABSOLUTE_LINUX_RUNTIME_DIR):
            try:
                path = Path(candidate_root)
            except Exception:
                recordException('start.py:12531', sys.exc_info()[1])
                _traceSwallowedException('start.py:12333', sys.exc_info()[1])
                continue
            if path.exists() and path.is_dir():
                roots.append(path)
        prefixes = [package_text, package_text.replace(':', '_'), package_text.replace(':', '-')]
        candidates: list[Path] = []
        seen: set[str] = set()
        for root in roots:
            for item in sorted(root.rglob('*.deb')):
                name = item.name
                if not any(name.startswith(prefix + '_') or name == prefix + '.deb' or name.startswith(prefix + '-') for prefix in prefixes):
                    continue
                key = str(item.resolve())
                if key in seen:
                    continue
                seen.add(key)
                candidates.append(item)
        return candidates

    def attemptBundledLinuxSystemPackageInstall(self, missing_requirements: list[dict[str, Any]]) -> bool:
        if not self.isLinux() or not list(missing_requirements or []):
            return False
        dpkg = shutil.which('dpkg')
        sudo = shutil.which('sudo')
        if not dpkg:
            print('[WARN:deps] Bundled Linux package install requested but dpkg was not found.', file=sys.stderr, flush=True)
            return False
        if not self.isPosixRoot() and not self.nonInteractiveSudoAvailable():
            print('[WARN:deps] Bundled Linux package install skipped; non-interactive sudo is unavailable.', file=sys.stderr, flush=True)
            return False
        installed_any = False
        attempted_any = False
        for requirement in list(missing_requirements or []):
            package_name = str(requirement.get('package', EMPTY_STRING) or EMPTY_STRING).strip()
            if not package_name:
                continue
            package_candidates = self.bundledLinuxPackageCandidates(package_name)
            if not package_candidates:
                searched_roots = ', '.join(str(root) for root in (DEPLOY_MONITOR_DIR, LINUX_RUNTIME_DIR, ABSOLUTE_DEBS_DIR, ABSOLUTE_LINUX_RUNTIME_DIR))
                print(f'[WARN:deps] no bundled .deb found for package={package_name}; searched={searched_roots}', file=sys.stderr, flush=True)
                continue
            attempted_any = True
            for package_path in package_candidates:
                command = [dpkg, '-i', str(package_path)]
                if not self.isPosixRoot() and sudo:
                    command = [sudo, '-n', *command]
                print(f'[TRACE:deps] bundled linux install package={package_name} file={package_path}', file=sys.stderr, flush=True)
                if self.runCommand(command, label=f'bundled linux package install {package_name}', timeout=1800):
                    installed_any = True
                    break
        if not attempted_any:
            print('[WARN:deps] no bundled Linux .deb candidates matched missing packages; falling back to apt if available.', file=sys.stderr, flush=True)
        elif not installed_any:
            print('[WARN:deps] Bundled Linux package install attempted but no package installed successfully.', file=sys.stderr, flush=True)
        return installed_any

    def warnForMissingLinuxSystemRequirements(self, missing_requirements: list[dict[str, Any]]) -> None:
        if not self.isLinux() or not list(missing_requirements or []):
            return
        for requirement in list(missing_requirements or []):
            kind = str(requirement.get('kind', EMPTY_STRING) or EMPTY_STRING)
            name = str(requirement.get('name', EMPTY_STRING) or EMPTY_STRING)
            package_name = str(requirement.get('package', EMPTY_STRING) or EMPTY_STRING)
            purpose = str(requirement.get('purpose', EMPTY_STRING) or EMPTY_STRING).strip()
            candidate_text = ', '.join(self.toolCandidates(requirement)) if kind == 'tool' else EMPTY_STRING
            line = f'[WARN:deps] Missing Linux {kind}: {name}  package={package_name}'
            if candidate_text and candidate_text != name:
                line += f'  candidates={candidate_text}'
            if purpose:
                line += f'  purpose={purpose}'
            print(line, file=sys.stderr, flush=True)

    def installMissing(self) -> None:
        self.installMissingDependencies()

    def installMissingDependencies(self) -> None:
        print(f'[TRACE:deps] StartDependencyRegistry.installMissingDependencies using OperatingSystem.detect/installDependencies os={self.osFamily}', file=sys.stderr, flush=True)
        return self.operatingSystem.installDependencies(self)

    def _installMissingDependenciesWithOperatingSystem(self) -> None:
        self.syncPythonToolPaths()
        missing_modules = self.missingPythonModules()
        missing_system = self.missingLinuxSystemRequirements() if self.isLinux() else []
        if self.isLinux() and missing_system:
            self.warnForMissingLinuxSystemRequirements(missing_system)
            self.attemptLinuxSystemPackageInstall(missing_system)
            missing_system = self.missingLinuxSystemRequirements()
        if missing_modules:
            critical_imports = self.launcherCriticalImportNames()
            critical_missing = [(module_name, package_name) for module_name, package_name in missing_modules if module_name in critical_imports]
            optional_missing = [(module_name, package_name) for module_name, package_name in missing_modules if module_name not in critical_imports]
            if critical_missing:
                module_names = ', '.join(module_name for module_name, _ in critical_missing)
                package_names = ', '.join(self.uniquePackagesForMissingModules(critical_missing))
                print(f'[WARN:deps] Missing critical Python modules; auto-install will be attempted: {module_names}', file=sys.stderr, flush=True)
                if package_names:
                    print(f'[WARN:deps] Expected critical Python package source: {package_names}', file=sys.stderr, flush=True)
                self.installMissingCriticalPythonDependencies()
                self.syncPythonToolPaths()
                missing_modules = self.missingPythonModules()
                optional_missing = [(module_name, package_name) for module_name, package_name in missing_modules if module_name not in critical_imports]
            if optional_missing:
                module_names = ', '.join(module_name for module_name, _ in optional_missing)
                package_names = ', '.join(self.uniquePackagesForMissingModules(optional_missing))
                print(f'[WARN:deps] Missing optional/lazy Python modules: {module_names}', file=sys.stderr, flush=True)
                if package_names:
                    print(f'[WARN:deps] Optional package source(s): {package_names}', file=sys.stderr, flush=True)
                install_optional = str(os.environ.get('TRIO_INSTALL_OPTIONAL_DEPS', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'}
                if install_optional:
                    print('[WARN:deps] TRIO_INSTALL_OPTIONAL_DEPS enabled; optional dependency auto-install will be attempted.', file=sys.stderr, flush=True)
                    optional_entries = [
                        entry for entry in self.missingPythonDependencyEntries()
                        if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() not in critical_imports
                    ]
                    Dependencies.fromLegacyRows(optional_entries).installMissing(self)
                    self.syncPythonToolPaths()
                    missing_modules = self.missingPythonModules()
                else:
                    print('[TRACE:deps] optional/lazy dependency auto-install skipped; providers/font tools will warn when those features are used.', file=sys.stderr, flush=True)
                    missing_modules = [(module_name, package_name) for module_name, package_name in missing_modules if module_name in critical_imports]
        if missing_system:
            self.warnForMissingLinuxSystemRequirements(missing_system)
        if missing_modules:
            module_names = ', '.join(module_name for module_name, _ in missing_modules)
            package_names = ', '.join(self.uniquePackagesForMissingModules(missing_modules))
            print(f'[WARN:deps] Still missing Python modules after auto-install attempts: {module_names}', file=sys.stderr, flush=True)
            if package_names:
                print(f'[WARN:deps] Expected package source: {package_names}', file=sys.stderr, flush=True)
        self.warnForFontComposerDependencies(force=traceVerboseRequested(self.argv))


def requiredModulesForArgv(argv=None) -> dict[str, str]:
    return StartDependencyRegistry(argv).requiredPythonModules()


def missingRequiredModules(argv=None) -> list[tuple[str, str]]:
    registry = StartDependencyRegistry(argv)
    critical = registry.launcherCriticalImportNames()
    return [item for item in registry.missingPythonModules() if str(item[0] or EMPTY_STRING).strip() in critical]


def uniquePackagesForMissingModules(missing_modules: list[tuple[str, str]]) -> list[str]:
    return StartDependencyRegistry.uniquePackagesForMissingModules(missing_modules)


def installMissingDependencies(argv=None) -> None:
    StartDependencyRegistry(argv).installMissingDependencies()


def verifyRequiredModulesOrDie(argv=None) -> None:
    missing_modules = missingRequiredModules(argv)
    if not missing_modules:
        return
    missing_names = ', '.join(module_name for module_name, _ in missing_modules)
    package_names = ', '.join(uniquePackagesForMissingModules(missing_modules))
    message = 'Missing Python modules needed before launch can continue: ' + missing_names
    if package_names:
        message += '\nExpected package(s): ' + package_names
    message += '\nstart.py attempted automatic installation through every platform/package-manager and pip route it knows for this runtime. Any module still named above needs a manual install or a corrected installer route.'
    raise RuntimeError(message)


def missingLinuxSystemRequirements(argv=None) -> list[dict[str, Any]]:
    return StartDependencyRegistry(argv).missingLinuxSystemRequirements()


def verifyLinuxSystemRequirementsOrDie(argv=None) -> None:
    missing_requirements = missingLinuxSystemRequirements(argv)
    if not missing_requirements:
        return
    lines = ['Missing Linux system dependencies:']
    for requirement in missing_requirements:
        kind = str(requirement.get('kind', EMPTY_STRING) or EMPTY_STRING)
        name = str(requirement.get('name', EMPTY_STRING) or EMPTY_STRING)
        package_name = str(requirement.get('package', EMPTY_STRING) or EMPTY_STRING)
        line = f'- {kind}: {name}'
        if package_name:
            line += f'  package={package_name}'
        lines.append(line)
    lines.append('start.py attempted automatic Linux package installation where possible. Install any remaining missing system packages before launching again.')
    raise RuntimeError('\n'.join(lines))

def safeRepr(value: Any, limit: int = 400) -> str:
    try:
        rendered = repr(value)
    except BaseException as error:
        recordException('start.py:12710', sys.exc_info()[1])
        try:
            detail = str(error)
        except Exception:
            recordException('start.py:12713', sys.exc_info()[1])
            try:
                detail = repr(getattr(error, 'args', ()))
            except Exception:
                recordException('start.py:12716', sys.exc_info()[1])
                detail = 'unprintable error'
        rendered = f"<repr failed: {type(error).__name__}: {detail}>"
    if len(rendered) > limit:
        rendered = rendered[:limit] + '…'
    return rendered

