class DebuggerCodeDialog(QDialog if ensureDebuggerQtImports() else object):  # type: ignore[reportGeneralTypeIssues]
    def __init__(self, debugger, title: str = EMPTY_STRING, sourceText: str = EMPTY_STRING, languageHint: str = EMPTY_STRING, readOnly: bool = True, submitLabel: str = 'Submit', showSubmit: bool = False, intervalSeconds: float | None = None, showInterval: bool = False):
        if not ensureDebuggerQtImports():
            raise RuntimeError(debuggerQtUnavailableText())
        super().__init__(None)
        self.debugger = debugger
        self.editorTitle = str(title or 'Code Editor').strip() or 'Code Editor'
        self.languageHint = str(languageHint or EMPTY_STRING).strip()
        self.readOnly = bool(readOnly)
        self.intervalSpin = None
        self.showSubmit = bool(showSubmit)
        self.setModal(True)
        self.setWindowTitle(self.editorTitle)
        try:
            self.resize(1120, 760)
        except Exception:
            recordException('start.py:13335', sys.exc_info()[1])
            _traceSwallowedException('start.py:13096', sys.exc_info()[1])
            pass
        root = QVBoxLayout(self)
        root.setContentsMargins(12, 12, 12, 12)
        root.setSpacing(8)
        if showInterval:
            row = QHBoxLayout()
            row.setContentsMargins(0, 0, 0, 0)
            row.setSpacing(8)
            row.addWidget(QLabel(localize(default='Interval (seconds):'), self))
            self.intervalSpin = QDoubleSpinBox(self)
            self.intervalSpin.setDecimals(2)
            self.intervalSpin.setSingleStep(0.05)
            self.intervalSpin.setMinimum(0.05)
            self.intervalSpin.setMaximum(86400.0)
            self.intervalSpin.setValue(max(0.05, float(intervalSeconds or 1.0)))
            row.addWidget(self.intervalSpin)
            row.addStretch(1)
            root.addLayout(row)
        def _error(context: str, error):
            if self.debugger is not None:
                try:
                    self.debugger.emit(f'[FlatLineDebugger.debugger] {context}: {type(error).__name__ if isinstance(error, Exception) else "Error"}: {error}', getattr(self.debugger, 'exceptionPath', None))
                    return
                except Exception:
                    recordException('start.py:13360', sys.exc_info()[1])
                    _traceSwallowedException('start.py:13120', sys.exc_info()[1])
                    pass
            try:
                print(f'[FlatLineDebugger.debugger] {context}: {error}', file=sys.stderr, flush=True)
            except Exception:
                recordException('start.py:13365', sys.exc_info()[1])
                _traceSwallowedException('start.py:13124', sys.exc_info()[1])
                pass
        def _status(message: str, timeout_ms: int = 4000):
            if self.debugger is not None:
                try:
                    self.debugger.emit(f'[FlatLineDebugger.debugger] {message}', getattr(self.debugger, 'debugPath', None))
                except Exception:
                    recordException('start.py:13372', sys.exc_info()[1])
                    _traceSwallowedException('start.py:13130', sys.exc_info()[1])
                    pass
        self.editorPane = SharedCodeEditorPane(
            parent=self,
            title=title,
            sourceText=sourceText,
            languageHint=languageHint,
            readOnly=readOnly,
            textProvider=lambda key, default: str(default or EMPTY_STRING),
            errorHandler=_error,
            statusHandler=_status,
            normalizeLanguage=debuggerCodeEditorNormalizeLanguage,
            prismAssetsPresent=debuggerCodeEditorPrismAssetsPresent,
            htmlShellBuilder=debuggerCodeEditorHtmlShell,
            baseUrlBuilder=debuggerCodeEditorBaseUrl,
            browserFactory=lambda parent: DebuggerWebEngineView(debugger=debugger, parent=parent),
            setSourceFunctionName='window.debuggerCodeEditorSetSource',
            getSourceScript='window.debuggerCodeEditorGetSource();',
        )
        root.addWidget(self.editorPane, 1)
        button_row = QHBoxLayout()
        button_row.setContentsMargins(0, 0, 0, 0)
        button_row.setSpacing(8)
        find_button = QPushButton(localize(default='Find'), self)
        find_button.clicked.connect(self.focusSearch)
        button_row.addWidget(find_button)
        replace_button = QPushButton(localize(default='Replace'), self)
        replace_button.clicked.connect(self.toggleReplacePanel)
        replace_button.setEnabled(not bool(readOnly))
        button_row.addWidget(replace_button)
        button_row.addStretch(1)
        if self.showSubmit:
            submit_button = QPushButton(str(submitLabel or 'Submit'), self)
            submit_button.clicked.connect(self.accept)
            button_row.addWidget(submit_button)
            cancel_button = QPushButton(localize(default='Cancel'), self)
            cancel_button.clicked.connect(self.reject)
            button_row.addWidget(cancel_button)
        else:
            close_button = QPushButton(localize(default='Close'), self)
            close_button.clicked.connect(self.accept)
            button_row.addWidget(close_button)
        root.addLayout(button_row)

