def flatlineTerminalPreviewFontRefs() -> list[str]:
    settings = terminalFontSettings()
    refs = [
        str(settings.get('font_path') or EMPTY_STRING),
        str(settings.get('mono_path') or EMPTY_STRING),
        str(settings.get('color_path') or EMPTY_STRING),
        'default.otf',
        'default.otf',
    ]
    seen = set()
    ordered = []
    for ref in refs:
        if ref in seen:
            continue
        seen.add(ref)
        ordered.append(ref)
    return ordered


def flatlineTerminalPreviewGlyphs() -> list[int]:
    return [0x28FF, 0x1F346, 0x1F525]


def flatlineGlyphLabel(codepoint: int) -> str:
    mapping = {
        0x28FF: 'Braille Full Cell',
        0x1F346: 'Eggplant Emoji',
        0x1F525: 'Fire Emoji',
    }
    return mapping.get(int(codepoint or 0), f'U+{int(codepoint or 0):04X}')




def _flatlineTerminalGlyphCellHtml(font, codepoint: int) -> str:
    has_glyph = bool(font.hasGlyph(codepoint))
    badge = 'YES' if has_glyph else 'NO'
    badge_class = 'ok' if has_glyph else 'bad'
    if has_glyph:
        try:
            src = font.glyphDataUri(codepoint, size=112, fill='#8cff96', background='#10141a')
            img_html = '<img src="' + src + '" alt="' + html.escape(flatlineGlyphLabel(codepoint)) + '"/>'
        except Exception as image_error:
            recordException('start.py:13499', sys.exc_info()[1])
            img_html = '<div class="glyph-missing">' + html.escape(type(image_error).__name__ + ': ' + str(image_error)) + '</div>'
    else:
        img_html = '<div class="glyph-missing">Missing</div>'
    return (
        '<div class="glyph-card">'
        + '<div class="glyph-label">' + html.escape(flatlineGlyphLabel(codepoint)) + '</div>'
        + '<div class="glyph-badge ' + badge_class + '">' + badge + '</div>'
        + img_html
        + '<div class="glyph-code">U+' + format(int(codepoint), '04X') + '</div>'
        + '</div>'
    )


def _flatlineTerminalPreviewCardHtml(reference: str, preview_glyphs: list[int]) -> str:
    try:
        font = TTFFont.ForReference(reference)
        resolved = str(getattr(font, 'fontPath', reference) or reference)
        return (
            '<section class="font-card">'
            + '<h3>' + html.escape(str(reference)) + '</h3>'
            + '<div class="font-path">' + html.escape(resolved) + '</div>'
            + '<div class="glyph-grid">' + ''.join(_flatlineTerminalGlyphCellHtml(font, codepoint) for codepoint in preview_glyphs) + '</div>'
            + '</section>'
        )
    except Exception as error:
        recordException('start.py:13524', sys.exc_info()[1])
        return (
            '<section class="font-card">'
            + '<h3>' + html.escape(str(reference)) + '</h3>'
            + '<div class="glyph-missing">' + html.escape(type(error).__name__ + ': ' + str(error)) + '</div>'
            + '</section>'
        )


def _flatlineTerminalPreviewCardsHtml(preview_fonts: list[str], preview_glyphs: list[int]) -> str:
    return ''.join(_flatlineTerminalPreviewCardHtml(reference, preview_glyphs) for reference in preview_fonts)


