def buildFlatLinePowerShellTerminalHtml(title: str, terminalText: str, previewFonts=None, previewGlyphs=None) -> str:
    safe_title = html.escape(str(title or 'FlatLine PowerShell Terminal'))
    terminal_html = html.escape(str(terminalText or EMPTY_STRING)).replace('\n', '<br/>')
    preview_fonts = list(previewFonts or flatlineTerminalPreviewFontRefs())
    preview_glyphs = [int(value) for value in (previewGlyphs or flatlineTerminalPreviewGlyphs())]
    parts = [
        '<!DOCTYPE html>',
        '<html>',
        '<head>',
        '<meta charset="utf-8" />',
        f'<title>{safe_title}</title>',
        f'<style>{_flatlineTerminalHtmlStyles()}</style>',
        '</head>',
        '<body>',
        f'<div class="header"><div><div class="title">{safe_title}</div><div class="subtitle">FlatLine PowerShell Terminal • copy • print • save HTML • save PDF</div></div></div>',
        f'<div class="terminal">{terminal_html}</div>',
        '<div class="preview-title">TTFFont glyph proof</div>',
        f'<div class="font-grid">{_flatlineTerminalPreviewCardsHtml(preview_fonts, preview_glyphs)}</div>',
        '<div class="note">Preview glyphs are rendered through TTFFont glyphToImage() using the current embedded font blobs or on-disk font files.</div>',
        '</body>',
        '</html>',
    ]
    return '\n'.join(parts)



def showFlatLineFontPreviewDialog(title: str, terminalText: str, previewFonts=None, previewGlyphs=None) -> bool:
    if os.environ.get('TRIO_OFFSCREEN'):
        return False
    if not ensureDebuggerQtImports():
        return False
    app = ensureDebuggerQtApplication()
    if app is None:
        return False
    dialog = FlatLinePowerShellTerminalDialog(debugger=None, parent=None, title=title, terminalText=terminalText, previewFonts=previewFonts, previewGlyphs=previewGlyphs)
    dialog.exec()  # qt-main-thread-ok
    return True


class FlatLinePowerShellTerminalDialog(QDialog if ensureDebuggerQtImports() else object):  # type: ignore[reportGeneralTypeIssues]
    def __init__(self, debugger=None, parent=None, title: str = 'FlatLine PowerShell Terminal', terminalText: str = EMPTY_STRING, previewFonts=None, previewGlyphs=None):
        if not ensureDebuggerQtImports():
            raise RuntimeError(debuggerQtUnavailableText())
        super().__init__(parent)
        self.debugger = debugger
        self.terminalText = str(terminalText or EMPTY_STRING)
        self.previewFonts = list(previewFonts or flatlineTerminalPreviewFontRefs())
        self.previewGlyphs = [int(value) for value in (previewGlyphs or flatlineTerminalPreviewGlyphs())]
        self.htmlText = EMPTY_STRING
        self.browser: Any = None
        self.setWindowTitle(str(title or 'FlatLine PowerShell Terminal'))
        self.resize(1180, 860)
        layout = QVBoxLayout(self)
        layout.setContentsMargins(12, 12, 12, 12)
        layout.setSpacing(8)
        buttonRow = QHBoxLayout()
        buttonRow.setContentsMargins(0, 0, 0, 0)
        buttonRow.setSpacing(8)
        button_specs = (
            ('copyButton', 'Copy', self.copyText), ('saveHtmlButton', 'Save HTML', self.saveHtml),
            ('savePdfButton', 'Save PDF', self.savePdf), ('printButton', 'Print', self.printDocument),
            ('refreshButton', 'Refresh', self.reloadContent), ('closeButton', 'Close', self.accept),
        )
        for attrName, label, handler in button_specs:
            button = QPushButton(label, self)
            setattr(self, attrName, button)
            button.clicked.connect(handler)
            buttonRow.addWidget(button)
        buttonRow.addStretch(1)
        layout.addLayout(buttonRow)
        if QWebEngineView is not None:
            self.browser = DebuggerWebEngineView(debugger=debugger, parent=self)
        else:
            self.browser = QTextBrowser(self)
            self.browser.setOpenExternalLinks(True)
        layout.addWidget(self.browser, 1)
        self.reloadContent()

    def defaultStem(self) -> str:
        return 'flatline_powershell_terminal'

    def buildHtml(self) -> str:
        return buildFlatLinePowerShellTerminalHtml(self.windowTitle(), self.terminalText, previewFonts=self.previewFonts, previewGlyphs=self.previewGlyphs)

    def reloadContent(self):
        self.htmlText = self.buildHtml()
        try:
            if isinstance(self.browser, QTextBrowser):
                self.browser.setHtml(self.htmlText)
            else:
                try:
                    self.browser.setHtml(self.htmlText, debuggerCodeEditorBaseUrl())
                except TypeError:
                    recordException('start.py:13653', sys.exc_info()[1])
                    self.browser.setHtml(self.htmlText)
        except Exception as error:
            recordException('start.py:13655', sys.exc_info()[1])
            if self.debugger is not None:
                self.debugger.emit(f'[FlatLineDebugger.debugger] Terminal modal load failed: {type(error).__name__}: {error}', getattr(self.debugger, 'exceptionPath', None))

    def copyText(self):
        app = QApplication.instance()
        clipboard = app.clipboard() if app is not None else None
        if clipboard is not None:
            clipboard.setText(self.terminalText)

    def saveHtml(self):
        chosen, _ = QFileDialog.getSaveFileName(self, 'Save HTML', str(Path.cwd() / f'{self.defaultStem()}.html'), 'HTML Files (*.html);;All Files (*.*)')
        if not chosen:
            return
        File(Path(chosen)).writeText(self.htmlText)

    def savePdf(self):
        chosen, _ = QFileDialog.getSaveFileName(self, 'Save PDF', str(Path.cwd() / f'{self.defaultStem()}.pdf'), 'PDF Files (*.pdf)')
        if not chosen:
            return
        if self.browser is not None and hasattr(self.browser, 'page'):
            page = self.browser.page()
            if page is not None and hasattr(page, 'printToPdf'):
                page.printToPdf(str(chosen))
                return
        if QPrinter is None:
            return
        printer = QPrinter(QPrinter.PrinterMode.HighResolution)
        try:
            printer.setOutputFormat(QPrinter.OutputFormat.PdfFormat)
            printer.setOutputFileName(str(chosen))
        except Exception:
            recordException('start.py:13686', sys.exc_info()[1])
            _traceSwallowedException('start.py:13442', sys.exc_info()[1])
            pass
        browser = self.browser
        if browser is not None and isinstance(browser, QTextBrowser):
            cast(Any, browser).document().print(printer)

    def printDocument(self):
        if QPrinter is None or QPrintDialog is None:
            return
        printer = QPrinter(QPrinter.PrinterMode.HighResolution)
        dialog = QPrintDialog(printer, self)
        if dialog.exec() != QDialog.DialogCode.Accepted:  # qt-main-thread-ok
            return
        browser = self.browser
        if browser is not None and hasattr(browser, 'print'):
            try:
                browser.print(printer)
                return
            except Exception:
                recordException('start.py:13705', sys.exc_info()[1])
                _traceSwallowedException('start.py:13460', sys.exc_info()[1])
                pass
        if browser is not None and isinstance(browser, QTextBrowser):
            cast(Any, browser).document().print(printer)


