    def captureDbPollBaseline(self):
        try:
            db = getattr(self, 'db', None)
            baseline = dict(db.readLatestDebuggerRowIds() or {}) if db is not None else {}
        except Exception:
            recordException('start.py:17231', sys.exc_info()[1])
