    def launcherProcessInfoAction(self, low: str) -> str:
        target = str(str(low or EMPTY_STRING).split(' ', 1)[1] if ' ' in str(low or EMPTY_STRING) else EMPTY_STRING).strip().lower()
        if not target:
            return '[FlatLineDebugger.debugger] Usage: process-info <key>'
        info = dict(self.pruneManagedProcesses().get(target, {}) or {})
        if not info:
            return f'[FlatLineDebugger.debugger] No managed launcher process found for key={target}'
        worker = (info.get('worker') or info.get('worker')) if isinstance(info, dict) else None
        alive = bool(info.get('alive', self.workerProcessIsAlive(worker)))
        started_at = float(info.get('startedAt', 0.0) or 0.0)
        ended_at = float(info.get('endedAt', 0.0) or 0.0)
        runtime = max(0.0, ((time.time() if alive else ended_at or time.time()) - started_at)) if started_at else 0.0
        payload = {
            'key': target,
            'name': str(info.get('name', EMPTY_STRING) or getattr(worker, 'name', EMPTY_STRING) or EMPTY_STRING),
            'alive': alive,
            'status': str(info.get('status', 'running' if alive else 'done') or ('running' if alive else 'done')),
            'daemon': bool(info.get('daemon', True)),
            'runtime': round(runtime, 2),
            'startedAt': started_at or None,
            'endedAt': ended_at or None,
            'nativeId': info.get('nativeId'),
            'details': str(info.get('details', EMPTY_STRING) or EMPTY_STRING),
            'meta': dict(info.get('meta', {}) or {}),
            'lastError': str(info.get('lastError', EMPTY_STRING) or EMPTY_STRING),
            'tracebackText': str(info.get('tracebackText', EMPTY_STRING) or EMPTY_STRING),
            'events': list(info.get('events', []) or []),
            'wrapperRuntime': round(float(getattr(worker, 'runtime', 0.0) or 0.0), 2) if worker is not None else None,
            'wrapperError': str(getattr(worker, '_error', EMPTY_STRING) or EMPTY_STRING) if worker is not None else EMPTY_STRING,
        }
        return json.dumps(payload, ensure_ascii=False, indent=2, default=str) + '\n'




    def launcherProcessEventsAction(self, low: str) -> str:
        target = str(str(low or EMPTY_STRING).split(' ', 1)[1] if ' ' in str(low or EMPTY_STRING) else EMPTY_STRING).strip().lower()
        if not target:
            return '[FlatLineDebugger.debugger] Usage: process-events <key>'
        info = dict(self.pruneManagedProcesses().get(target, {}) or {})
        if not info:
            return f'[FlatLineDebugger.debugger] No managed launcher process found for key={target}'
        events = list(info.get('events', []) or [])
        if not events:
            return f'[FlatLineDebugger.debugger] No launcher process events recorded for key={target}'
        lines = ['=' * 62, f'  Launcher Process Events: {target}', '=' * 62]
        for event in events[-20:]:
            if not isinstance(event, dict):
                continue
            ts = float(event.get('ts', 0.0) or 0.0)
            kind = str(event.get('kind', EMPTY_STRING) or EMPTY_STRING)
            text_value = str(event.get('text', EMPTY_STRING) or EMPTY_STRING)
            payload = dict(event.get('payload', {}) or {})
            payload_bits = []
            for key_name in ('status', 'alive', 'nativeId'):
                if key_name in payload:
                    payload_bits.append(f'{key_name}={payload.get(key_name)}')
            payload_suffix = f"  {' '.join(payload_bits)}" if payload_bits else EMPTY_STRING
            stamp = time.strftime('%H:%M:%S', time.localtime(ts)) if ts else '??:??:??'
            lines.append(f'  [{stamp}] {kind}: {text_value}{payload_suffix}')
        lines.append('=' * 62)
        return '\n'.join(lines) + '\n'




    def launcherProcessErrorsAction(self) -> str:
        rows = []
        for key, info in self.pruneManagedProcesses().items():
            info = dict(info or {})
            error_text = str(info.get('lastError', EMPTY_STRING) or EMPTY_STRING).strip()
            status = str(info.get('status', EMPTY_STRING) or EMPTY_STRING).strip().lower()
            if not error_text and status != 'error':
                continue
            rows.append(f"  process[{key}] status={status or 'error'} error={error_text or '(unknown error)'}")
        if not rows:
            return '[FlatLineDebugger.debugger] No managed launcher process errors recorded.\n'
        return '\n'.join(['=' * 62, '  Launcher Process Errors', '=' * 62, *rows, '=' * 62]) + '\n'




    def launcherProcessStopAction(self, low: str) -> str:
        target = str(str(low or EMPTY_STRING).split(' ', 1)[1] if ' ' in str(low or EMPTY_STRING) else EMPTY_STRING).strip()
        if not target:
            return '[FlatLineDebugger.debugger] Usage: stop-process <key>'
        if target.lower() == 'all':
            registry = dict(getattr(self, 'managedProcesses', {}) or {})
            stopped = []
            errors = []
            for key in list(registry.keys()):
                result = self.stopManagedProcess(key, quiet=True)
                if bool(result.get('ok', False)):
                    stopped.append(str(result.get('key', key) or key))
                else:
                    errors.append(str(result.get('error', EMPTY_STRING) or EMPTY_STRING))
            if stopped:
                return f'[FlatLineDebugger.debugger] Requested stop for launcher processes: {", ".join(stopped)}'
            if errors:
                return f'[FlatLineDebugger.debugger] No launcher processes stopped: {"; ".join(errors)}'
            return '[FlatLineDebugger.debugger] No managed launcher processs were registered.'
        result = self.stopManagedProcess(target, quiet=True)
        if not bool(result.get('ok', False)):
            return f"[FlatLineDebugger.debugger] {result.get('error', 'Failed to stop launcher process.')}"
        return f"[FlatLineDebugger.debugger] Requested stop for launcher process {result.get('key', target)}  alive={result.get('alive', False)}"




