    def restartAction(self) -> str:
        proc = self.child
        if proc is not None and proc.poll() is None:
            return '[FlatLineDebugger.debugger] Child is still running — kill it first (press 5)'
        self.dismissedSignature = EMPTY_STRING
        self.lastOpenedSignature = EMPTY_STRING
        self.inCrashConsole = False
        self.heartbeatEverFired = False
        self.childExitCode = None
        self.consoleDone.set()
        try:
            self.launchChild(self.childArgs)
            watchdog = getattr(self, 'watchdogProcess', None)
            if watchdog is None or not watchdog.is_alive():
                self.consoleStop.clear()
                self.watchdogProcess = self.spawnManagedProcess('watchdog', self.poll, 'TrioProcessWatchdog', daemon=False, details='watchdog poll loop', meta={'role': 'watchdog'})
            return f'[FlatLineDebugger.debugger] Child relaunched  pid={self.childPid}'
        except Exception as error:
            recordException('start.py:19691', sys.exc_info()[1])
            return f'[FlatLineDebugger.debugger] Relaunch failed: {error}'




