    def executeConsoleLeafAction(self, cmd: str, token: str, interactive: bool = True) -> str:
        low = str(token or EMPTY_STRING).lower()
        for spec in self.consoleLeafActionSpecs():
            raw_prefixes = cast(Any, spec).get('prefixes')
            prefixes = tuple(raw_prefixes) if isinstance(raw_prefixes, (list, tuple, set)) else ()
            if prefixes:
                if not any(low.startswith(str(prefix or EMPTY_STRING).lower()) for prefix in prefixes):
                    continue
            elif not self.commandMatches(low, str(spec.get('group') or EMPTY_STRING)):
                continue
            surface_name = str(spec.get('surface') or EMPTY_STRING).strip().lower()
            if surface_name and not self.childSurfaceSupported(surface_name, default=False):
                return self.childSurfaceUnavailableText(surface_name, str(spec.get('label') or spec.get('group') or surface_name))
            handler = getattr(self, str(spec.get('handler_name') or EMPTY_STRING), None)
            if handler is None:
                continue
            args = []
            if spec.get('pass_cmd'):
                args.append(cmd)
            if spec.get('pass_low'):
                args.append(low)
            try:
                if spec.get('pass_interactive'):
                    return handler(*args, interactive=interactive)
                return handler(*args)
            except Exception as error:
                recordException('start.py:19751', sys.exc_info()[1])
                try:
                    self.emit(f'[FlatLineDebugger.debugger] command {low or cmd} failed without closing console: {type(error).__name__}: {error}', self.exceptionPath)
                except Exception:
                    recordException('start.py:19754', sys.exc_info()[1])
                    _traceSwallowedException('start.py:19388', sys.exc_info()[1])
                    pass
                return f'[FlatLineDebugger.debugger] Command failed but debugger console is still alive: {type(error).__name__}: {error}'
        return f'[FlatLineDebugger.debugger] Unknown command: {cmd}'


    def consoleLoop(self):
        while not self.consoleStop.is_set():
            self.consoleWake.wait(timeout=0.25)
            self.consoleWake.clear()
            if self.consoleStop.is_set():
                break
            self.emitCrashContextPreludeOnce(context_lines=10)
            self.printBanner()
            import contextlib as _contextlib
            buf = _ConsoleOutputBuffer(self)
            with _contextlib.redirect_stdout(cast(Any, buf)):
                while self.inCrashConsole and not self.consoleStop.is_set():
                    try:
                        self.lastStatusLine = EMPTY_STRING
                        raw = input(buf.prompt_line())
                    except EOFError:
                        recordException('start.py:19775', sys.exc_info()[1])
                        raw = 'q'
                    except KeyboardInterrupt:
                        recordException('start.py:19777', sys.exc_info()[1])
                        raw = 'q'
                    if raw.strip() in ('\x03',):
                        raw = 'q'
                    cmd = self.normalizeConsoleCommand(raw.strip())
                    if not cmd:
                        continue
                    if cmd.lower() in ('u', 'update'):
                        buf.flush_buffer()
                        continue
                    buf.flush_buffer()
                    try:
                        output = self.dispatchConsoleCommand(cmd, interactive=True)
                    except Exception as error:
                        recordException('start.py:19790', sys.exc_info()[1])
                        output = f'[FlatLineDebugger.debugger] Command failed but debugger console is still alive: {type(error).__name__}: {error}'
                        try:
                            self.emit(output, self.exceptionPath)
                        except Exception:
                            recordException('start.py:19794', sys.exc_info()[1])
                            _traceSwallowedException('start.py:19427', sys.exc_info()[1])
                            pass
                    if output:
                        real = cast(Any, buf._real)
                        real.write(output + '\n')
                        real.flush()
                        self.write(self.logPath, output + ('\n' if not str(output).endswith('\n') else EMPTY_STRING))
            buf.flush_buffer()


    def startSnapshotCapture(self, payload: dict | None):
        info = dict(payload or {})
        existing = getattr(self, 'snapshotProcess', None)
        try:
            if existing is not None and existing.is_alive():
                return existing
        except Exception:
            recordException('start.py:19811', sys.exc_info()[1])
            _traceSwallowedException('start.py:19443', sys.exc_info()[1])
            pass
        def runner():
            if self.childSurfaceSupported('vardump', default=False):
                try:
                    self.requestChildSnapshot(command='vardump', timeout=0.90, reason=str(info.get('type_name', 'pre-console')))
                except Exception:
                    recordException('start.py:19818', sys.exc_info()[1])
                    _traceSwallowedException('start.py:19449', sys.exc_info()[1])
                    pass
            try:
                self.capturePreConsoleSnapshot(info)
            except Exception as error:
                recordException('start.py:19823', sys.exc_info()[1])
                self.emit(f'[FlatLineDebugger.debugger] Snapshot capture failed: {error}', self.exceptionPath)
        try:
            worker = self.spawnManagedProcess('snapshot-capture', runner, 'TrioSnapshotCapture', daemon=True, details='capture debugger snapshot', meta={'role': 'snapshot-capture'})
            self.snapshotProcess = worker
            return worker
        except Exception as error:
            recordException('start.py:19829', sys.exc_info()[1])
            self.emit(f'[FlatLineDebugger.debugger] Snapshot process start failed: {error}', self.exceptionPath)
            return None


    def runActionAsync(self, label: str, target):
        def runner():
            try:
                result = target()
                if result:
                    self.emit(str(result), self.exceptionPath)
            except Exception as error:
                recordException('start.py:19840', sys.exc_info()[1])
                self.emit(f'[FlatLineDebugger.debugger] {label} failed: {error}', self.exceptionPath)
        worker = self.spawnManagedProcess(f'action:{label}', runner, f'TrioAction:{label}', daemon=True, details='async debugger action', meta={'role': 'action', 'label': str(label or EMPTY_STRING)})
        self.actionProcess = worker


    def openCrashConsole(self, info: dict | None, block: bool = False):
        payload = dict(info or {})
        try:
            if self.inCrashConsole and str((self.crashInfo or {}).get('type_name', EMPTY_STRING) or EMPTY_STRING) == str(payload.get('type_name', EMPTY_STRING) or EMPTY_STRING):
                self.crashInfo = payload
                if _debugger_is_real_crash_payload(payload):
                    self.lastRealCrashInfo = dict(payload)
                return
        except Exception:
            recordException('start.py:19852', sys.exc_info()[1])
            _traceSwallowedException('start.py:19482', sys.exc_info()[1])
            pass
        signature = self.crashSignature(payload)
        with self.lock:
            now = time.time()
            if signature and self.inCrashConsole and signature == self.lastOpenedSignature:
                self.crashInfo = payload
                if _debugger_is_real_crash_payload(payload):
                    self.lastRealCrashInfo = dict(payload)
                return
            if signature and signature == self.dismissedSignature and now < float(self.consoleSnoozeUntil or 0.0):
                self.crashInfo = payload
                if _debugger_is_real_crash_payload(payload):
                    self.lastRealCrashInfo = dict(payload)
                return
            self.crashInfo = payload
            if _debugger_is_real_crash_payload(payload):
                self.lastRealCrashInfo = dict(payload)
            self.lastOpenedSignature = signature
            if bool(getattr(self, 'offscreenEnabled', False)) and getattr(self, 'captureEngine', None) or getattr(self, 'offscreenSession', None) is not None:
                self.scheduleOffscreenCapture('crash', delaySeconds=0.0, allowRepeat=True, stamped=True)
            self.consoleDone.clear()
            self.inCrashConsole = True
            self.consoleWake.set()
        # Snapshot capture is useful, but the crash console must appear first.
        # Never hold the debugger menu hostage behind vardump/snapshot transport.
        try:
            self.startSnapshotCapture(self.crashInfo)
        except Exception:
            recordException('start.py:open-crash-console-snapshot', sys.exc_info()[1], handled=True)
        if block and str(payload.get('type_name', EMPTY_STRING) or EMPTY_STRING) != 'Freeze':
            deadline = time.monotonic() + 300.0
            while not self.consoleDone.wait(timeout=0.25):
                if time.monotonic() >= deadline:
                    print('[WARN:debugger-console] consoleDone wait timed out after 300 seconds', file=sys.stderr, flush=True)
                    break


    def formatFaultRowText(self, row: dict | None) -> str:
        payload = dict(row or {})
        lines = [
            self.psColor('=' * 78, PS_RED, bold=True),
            self.psColor('Child Fault from Faults Table', PS_RED, bold=True),
            self.psColor('=' * 78, PS_RED, bold=True),
            self.psColor('reason', PS_YELLOW, bold=True) + self.psColor(' = ', PS_DIM) + self.psColor(str(payload.get('reason', EMPTY_STRING) or EMPTY_STRING), PS_WHITE),
            self.psColor('caller', PS_YELLOW, bold=True) + self.psColor(' = ', PS_DIM) + self.psColor(str(payload.get('caller', EMPTY_STRING) or EMPTY_STRING), PS_WHITE),
            self.psColor('source', PS_YELLOW, bold=True) + self.psColor(' = ', PS_DIM) + self.psColor(str(payload.get('source', EMPTY_STRING) or EMPTY_STRING), PS_WHITE),
            self.psColor('worker', PS_YELLOW, bold=True) + self.psColor(' = ', PS_DIM) + self.psColor(str(payload.get('worker', EMPTY_STRING) or EMPTY_STRING), PS_WHITE),
            self.psColor('pid', PS_YELLOW, bold=True) + self.psColor(' = ', PS_DIM) + self.psColor(str(payload.get('pid', 0) or 0), PS_WHITE),
            self.psColor('created', PS_YELLOW, bold=True) + self.psColor(' = ', PS_DIM) + self.psColor(str(payload.get('created', EMPTY_STRING) or EMPTY_STRING), PS_WHITE),
        ]
        stack_text = str(payload.get('stack_trace', EMPTY_STRING) or EMPTY_STRING).strip()
        if stack_text:
            lines.append(EMPTY_STRING)
            lines.append(self.psColor('Stack / Fault Data', PS_CYAN, bold=True))
            lines.extend(self.psColor(line, PS_WHITE) for line in stack_text.splitlines())
        var_text = str(payload.get('var_dump', EMPTY_STRING) or EMPTY_STRING).strip()
        if var_text:
            lines.append(EMPTY_STRING)
            lines.append(self.psColor('Variable Dump', PS_CYAN, bold=True))
            lines.extend(self.psColor(line, PS_DIM if not line.strip() else PS_WHITE) for line in var_text.splitlines())
        process_text = str(payload.get('process_snapshot', EMPTY_STRING) or EMPTY_STRING).strip()
        if process_text:
            lines.append(EMPTY_STRING)
            lines.append(self.psColor('Process Snapshot', PS_CYAN, bold=True))
            lines.extend(self.psColor(line, PS_DIM if not line.strip() else PS_WHITE) for line in process_text.splitlines())
        lines.append(self.psColor('=' * 78, PS_RED, bold=True))
        return '\n'.join(lines)


    def processHeartbeatRows(self):
        baseline = int((getattr(self, 'dbPollBaseline', {}) or {}).get('heartbeat', 0) or 0)
        db = getattr(self, 'db', None)
        rows = list(db.readUnprocessedHeartbeatRows(limit=100, min_id=baseline) or []) if db is not None else []
        if not rows:
            return False
        self.advanceDbPollBaseline('heartbeat', rows)
        self.advanceDbPollBaseline('exceptions', rows)
        self.advanceDbPollBaseline('faults', rows)
        ids = [int(row.get('id', 0) or 0) for row in rows if int(row.get('id', 0) or 0) > 0]
        for row in rows:
            kind = str(row.get('event_kind', EMPTY_STRING) or EMPTY_STRING).strip().lower()
            reason = str(row.get('reason', EMPTY_STRING) or EMPTY_STRING)
            caller = str(row.get('caller', EMPTY_STRING) or EMPTY_STRING)
            timestamp = float(row.get('heartbeat_microtime', 0.0) or time.time())
            if kind == 'heartbeat':
                self.touchHeartbeat(reason or 'HEARTBEAT', caller=caller, timestamp=timestamp)
            elif kind == 'process':
                with self.lock:
                    self.lastProcessLoop = timestamp
                    self.lastProcessReason = str(reason or 'PROCESS')
        if ids:
            try:
                self.db.markHeartbeatProcessed(ids)
            except Exception:
                recordException('start.py:19932', sys.exc_info()[1])
                _traceSwallowedException('start.py:19561', sys.exc_info()[1])
                pass
        return True


    def processUnhandledExceptionRows(self):
        baseline = int((getattr(self, 'dbPollBaseline', {}) or {}).get('exceptions', 0) or 0)
        db = getattr(self, 'db', None)
        rows = list(db.readUnprocessedUnhandledExceptionRows(limit=10, min_id=baseline) or []) if db is not None else []
        if not rows:
            return False
        ids = [int(row.get('id', 0) or 0) for row in rows if int(row.get('id', 0) or 0) > 0]
        if ids:
            try:
                self.db.markExceptionProcessed(ids)
            except Exception:
                recordException('start.py:19948', sys.exc_info()[1])
                _traceSwallowedException('start.py:19576', sys.exc_info()[1])
                pass
        for row in rows:
            pretty = self.formatExceptionRowText(row)
            self.emit(pretty, self.exceptionPath)
            self.openCrashConsole({
                'type_name': str(row.get('type_name', 'UnhandledException') or 'UnhandledException'),
                'message': str(row.get('message', 'Unhandled exception') or 'Unhandled exception'),
                'worker': str(row.get('worker', processsync.current_process().name) or processsync.current_process().name),
                'timestamp': time.time(),
                'traceback_text': pretty,
            }, block=False)
        return True


    def processHeartbeatFaultRows(self):
        baseline = int((getattr(self, 'dbPollBaseline', {}) or {}).get('faults', 0) or 0)
        db = getattr(self, 'db', None)
        rows = list(db.readUnprocessedFaultRows(limit=10, min_id=baseline) or []) if db is not None else []
        if not rows:
            return False
        self.advanceDbPollBaseline('faults', rows)
        ids = [int(row.get('id', 0) or 0) for row in rows if int(row.get('id', 0) or 0) > 0]
        if ids:
            try:
                self.db.markFaultProcessed(ids)
            except Exception:
                recordException('start.py:19975', sys.exc_info()[1])
                _traceSwallowedException('start.py:19602', sys.exc_info()[1])
                pass
        for row in rows:
            pretty = self.formatFaultRowText(row)
            self.emit(pretty, self.exceptionPath)
            self.openCrashConsole({
                'type_name': 'ChildFault',
                'message': str(row.get('reason', 'Child fault') or 'Child fault'),
                'worker': str(row.get('worker', processsync.current_process().name) or processsync.current_process().name),
                'timestamp': time.time(),
                'traceback_text': pretty,
            }, block=False)
        return True



    @staticmethod
    def _debuggerPollProcessorNames() -> tuple[str, ...]:
        return ('processHeartbeatRows', 'processUnhandledExceptionRows', 'processHeartbeatFaultRows')


    @staticmethod
    def _debuggerPollRunProcessors(target) -> None:
        for name in Debugger._debuggerPollProcessorNames():
            try:
                getattr(target, name)()
            except Exception:
                recordException('start.py:20002', sys.exc_info()[1])
                _traceSwallowedException('start.py:19628', sys.exc_info()[1])
                pass


    @staticmethod
    def _debuggerPollHandleChildExit(target, proc) -> bool:
        try:
            code = proc.poll()
        except Exception:
            recordException('start.py:20011', sys.exc_info()[1])
            code = None
        if code is None or getattr(target, 'childExitCode', None) is not None:
            return False
        target.markChildExited(proc)
        if int(getattr(target, 'childExitCode', 0) or 0) != 0:
            target.openCrashConsole({
                'type_name': 'ChildExit',
                'message': f'{primaryChildFileName()} exited with code {target.childExitCode}',
                'worker': processsync.current_process().name,
                'timestamp': time.time(),
                'traceback_text': target.readFile(target.exceptionPath),
            }, block=True)
        return True


    @staticmethod
    def _debuggerPollShouldStop(target) -> bool:
        if getattr(target, 'childExitCode', None) is None:
            return False
        if getattr(target, 'inCrashConsole', False):
            target.consoleDone.wait(timeout=5.0)
        target.statusStop.set()
        target.consoleStop.set()
        return True


    @staticmethod
    def _debuggerPollSurfacesReady(target) -> bool:
        return bool(target.childSurfaceSupported('heartbeat', default=False) and target.childSurfaceSupported('poll', default=False) and getattr(target, 'heartbeatEverFired', False))


    @staticmethod
    def _debuggerPollFreshness(target, now: float, min_threshold: float) -> tuple[bool, float]:
        process_age = now - float(getattr(target, 'lastProcessLoop', 0.0) or 0.0)
        heartbeat_age = now - float(getattr(target, 'lastHeartbeat', 0.0) or 0.0)
        stale = now - max(getattr(target, 'lastHeartbeat', 0.0), getattr(target, 'lastProcessLoop', 0.0))
        if process_age < min_threshold or heartbeat_age < min_threshold:
            return False, stale
        for attr_name in ('lastProcessLoop', 'lastHeartbeat'):
            value = float(getattr(target, attr_name, 0.0) or 0.0)
            if value and (now - value) < 15.0:
                return False, stale
        return True, stale


    @staticmethod
    def _debuggerPollMaybeFreezeDump(target, now: float, stale: float, min_threshold: float) -> None:
        if stale < min_threshold or (now - float(getattr(target, 'lastFreezeDump', 0.0) or 0.0)) < min_threshold or getattr(target, 'inCrashConsole', False):
            return
        target.lastFreezeDump = now
        try:
            target.requestChildSnapshot(command='freeze_dump', timeout=0.90, reason='watchdog-freeze')
        except Exception:
            recordException('start.py:20064', sys.exc_info()[1])
            _traceSwallowedException('start.py:19689', sys.exc_info()[1])
            pass
        target.openCrashConsole({
            'type_name': 'Freeze',
            'message': target.flatlined() + f'  stalled={stale:.1f}s',
            'worker': processsync.current_process().name,
            'timestamp': time.time(),
        }, block=False)


    @staticmethod
    def _runDebuggerPollLoop(target) -> None:
        min_threshold = max(float(getattr(target, 'freezeThresholdSeconds', 8.0) or 8.0), 20.0)
        while not target.consoleStop.wait(target.deathPollInterval):
            proc = getattr(target, 'child', None)
            if proc is not None and Debugger._debuggerPollHandleChildExit(target, proc):
                continue
            if Debugger._debuggerPollShouldStop(target):
                return
            db_surfaces_available = bool(
                target.childSurfaceSupported('heartbeat', default=False)
                or target.childSurfaceSupported('poll', default=False)
            )
            if db_surfaces_available:
                Debugger._debuggerPollRunProcessors(target)
            if not Debugger._debuggerPollSurfacesReady(target):
                continue
            now = time.time()
            ready, stale = Debugger._debuggerPollFreshness(target, now, min_threshold)
            if not ready:
                continue
            Debugger._debuggerPollMaybeFreezeDump(target, now, stale, min_threshold)


    def poll(self):
        return Debugger._runDebuggerPollLoop(self)


    def closeChildStreams(self):
        _traceVerboseFlushFileBuffer(self, final=True)
        for attr in ('childStdoutHandle', 'childStderrHandle'):
            handle = getattr(self, attr, None)
            setattr(self, attr, None)
            if handle is None:
                continue
            try:
                handle.flush()
            except Exception:
                recordException('start.py:20107', sys.exc_info()[1])
                _traceSwallowedException('start.py:19731', sys.exc_info()[1])
                pass
            try:
                handle.close()
            except Exception:
                recordException('start.py:20112', sys.exc_info()[1])
                _traceSwallowedException('start.py:19735', sys.exc_info()[1])
                pass


    def readChildOutputTail(self, path: str, limit: int = 16000) -> str:
        path_text = str(path or EMPTY_STRING).strip()
        if not path_text or path_text.upper() == 'DEVNULL':
            return EMPTY_STRING
        try:
            target = Path(path_text)
            if not target.exists() or not target.is_file():
                return EMPTY_STRING
            size = int(target.stat().st_size or 0)
            with File(target).open('rb') as handle:
                if size > int(limit or 0):
                    handle.seek(max(0, size - int(limit or 0)))
                data = handle.read()
            return data.decode('utf-8', 'replace')
        except Exception as error:
            recordException('start.py:20131', sys.exc_info()[1])
            return f'<failed to read {path_text}: {type(error).__name__}: {error}>'


    def emitChildOutputTailOnExit(self) -> None:
        stdout_tail = self.readChildOutputTail(str(getattr(self, 'childStdoutPath', EMPTY_STRING) or EMPTY_STRING), 12000)
        stderr_tail = self.readChildOutputTail(str(getattr(self, 'childStderrPath', EMPTY_STRING) or EMPTY_STRING), 16000)
        code = int(getattr(self, 'childExitCode', 0) or 0)
        if stdout_tail:
            self.emit('[child:stdout:tail]\n' + stdout_tail.rstrip(), self.logPath)
        if stderr_tail:
            self.emit('[child:stderr:tail]\n' + stderr_tail.rstrip(), self.exceptionPath)
        expected_reason = str(getattr(self, 'expectedChildExitReason', EMPTY_STRING) or EMPTY_STRING).strip()
        if code != 0 and not stderr_tail and not expected_reason:
            self.emit(f'[WARN:child-output] child exited code={code} with no stderr captured. stdout={getattr(self, "childStdoutPath", EMPTY_STRING)} stderr={getattr(self, "childStderrPath", EMPTY_STRING)}', self.exceptionPath)
        elif code != 0 and expected_reason:
            self.emit(f'[TRACE:child-output] expected child exit code={code} reason={expected_reason}', self.logPath)


    def startChildPipePump(self, pipe, label: str, path: str):
        if pipe is None:
            return None
        import threading as _threading  # thread-ok: explicit debugger pipe relay; no long-lived debug.log handle
        def runner():
            try:
                while True:
                    chunk = pipe.readline()
                    if not chunk:
                        break
                    text = str(chunk or EMPTY_STRING).rstrip()
                    if not text:
                        continue
                    lowered = text.lower()
                    if label == 'stderr':
                        if 'ffmpeg log:' in lowered:
                            continue
                        if lowered.startswith('qt.multimedia.ffmpeg:'):
                            continue
                        if lowered.startswith('using qt multimedia with ffmpeg version'):
                            continue
                    try:
                        self.touchProcessLoop(f'PIPE:{str(label or "child").upper()}')
                    except Exception:
                        recordException('start.py:20170', sys.exc_info()[1])
                        _traceSwallowedException('start.py:19789', sys.exc_info()[1])
                        pass
                    verbose_line = self.tryFormatTraceVerboseLine(text)
                    if verbose_line is not None:
                        self.emit(verbose_line, path)
                        continue
                    prefixed = f'[child:{label}] {text}'
                    self.emit(prefixed, path)
            except Exception as error:
                recordException('start.py:20179', sys.exc_info()[1])
                self.emit(f'[FlatLineDebugger.debugger] {label} pump failed: {error}', self.exceptionPath)
            finally:
                try:
                    pipe.close()
                except Exception:
                    recordException('start.py:child-pipe-close', sys.exc_info()[1])
                _traceVerboseFlushFileBuffer(self, final=True)
                RuntimeLog.flush(final=True)
        worker = _threading.Thread(target=runner, name=f'TrioChild{str(label or "Child").title()}PipePump', daemon=True)  # lifecycle-bypass-ok: child stdout/stderr pipe relay only
        worker.start()
        return worker


    def shutdownKernel(self):
        try:
            rpc = getattr(self, 'shellRpcServer', None)
            if rpc is not None:
                rpc.close()
                self.shellRpcServer = None
        except Exception:
            recordException('start.py:20192', sys.exc_info()[1])
            _traceSwallowedException('start.py:19810', sys.exc_info()[1])
            pass
        self.statusStop.set()
        self.clearStatusLine()
        self.consoleStop.set()
        self.consoleWake.set()
        self.keyStop.set()
        self.connectionMonitorStop.set()
        for server_attr in ('server', 'relayServer'):
            server = getattr(self, server_attr, None)
            if server is None:
                continue
            try:
                server.shutdown()
            except Exception:
                recordException('start.py:20207', sys.exc_info()[1])
                _traceSwallowedException('start.py:19824', sys.exc_info()[1])
                pass
            try:
                server.server_close()
            except Exception:
                recordException('start.py:20212', sys.exc_info()[1])
                _traceSwallowedException('start.py:19828', sys.exc_info()[1])
                pass
            setattr(self, server_attr, None)
        try:
            app = getattr(self, 'bootStrappedApp', None)
            if app is not None and app.isRunning():
                app.kill(reason='Debugger.shutdownKernel', force=True, tree=True, verify=True)
        except Exception:
            recordException('start.py:bootstrapped-app-shutdown-kill', sys.exc_info()[1], handled=True)
        self.closeChildStreams()
        current = processsync.current_process()
        for attr in ('serverProcess', 'relayProcess', 'watchdogProcess', 'consoleProcess', 'keyProcess', 'connectionMonitorProcess', 'statusProcess', 'childStdoutWorkerProcess', 'childStderrWorkerProcess'):
            worker = getattr(self, attr, None)
            if worker is None or worker is current:
                continue
            try:
                if worker.is_alive():
                    timeout_value = self.managedProcessJoinTimeout(str(attr or EMPTY_STRING), {})
                    worker.join(timeout=timeout_value)
                    if worker.is_alive():
                        self.emit(f'[WARNING:shutdown] {attr} still alive after join timeout={timeout_value}', self.exceptionPath)
            except Exception as join_error:
                recordException('start.py:20228', sys.exc_info()[1])
                self.emit(f'[WARNING:shutdown] failed joining {attr}: {type(join_error).__name__}: {join_error}', self.exceptionPath)
        self.stopOffscreenSession()
        try:
            RuntimeLog.flushAllLogs()
        except Exception:
            RuntimeLog.flush(final=True)


    def killSelf(self, reason: str = 'Debugger.killSelf', *, force: bool = True, verify: bool = False) -> bool:  # noqa: N802
        """Flush logs and terminate the debugger process itself as the last resort.

        This is intentionally separate from bootStrappedApp.kill(): the normal
        shutdown target is the child app. killSelf exists for the final line /
        __del__ cleanup path so a wedged FlatLine parent does not stay alive
        after its app has already been killed.
        """
        try:
            RuntimeLog.flushAllLogs()
        except Exception:
            RuntimeLog.flush(final=True)
        pid_value = int(getattr(self, 'debuggerPid', 0) or os.getpid())
        if os.name == 'nt':
            try:
                command = ['taskkill', '/PID', str(pid_value), '/F']
                completed = subprocess.Popen(command, stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)  # lifecycle-bypass-ok: final debugger self-kill only
                if verify:
                    completed.wait(timeout=3)
                return True
            except Exception:
                recordException('start.py:debugger-kill-self-taskkill', sys.exc_info()[1], handled=True)
                return False
        if verify:
            try:
                os.kill(pid_value, signal.SIGTERM if not force else signal.SIGKILL)
            except Exception:
                recordException('start.py:debugger-kill-self-posix', sys.exc_info()[1], handled=True)
                return False
        return True

    def __del__(self) -> None:
        try:
            RuntimeLog.flushAllLogs()
            app = getattr(self, 'bootStrappedApp', None)
            if app is not None and app.isRunning():
                app.kill(reason='Debugger.__del__', force=True, tree=True, verify=True)
            try:
                clearPycacheDirectories(BASE_DIR, reason='Debugger.__del__')
            except Exception:
                pass
        except Exception:
            pass


    def startTrafficProxyServer(self):
        if not bool(getattr(self, 'enabled', False)):
            return None
        existing = getattr(self, 'trafficProxyServer', None)
        if existing is not None and getattr(existing, 'httpd', None) is not None:
            return existing
        bind_value = str(os.environ.get('TRIO_PROXY_BIND', '127.0.0.1:6666') or '127.0.0.1:6666').strip()
        host = '127.0.0.1'
        port = 6666
        if ':' in bind_value:
            host, port_text = bind_value.rsplit(':', 1)
            host = str(host or '127.0.0.1').strip() or '127.0.0.1'
            try:
                port = int(port_text or 6666)
            except Exception:
                recordException('start.py:20247', sys.exc_info()[1])
                port = 6666
        server = TrafficProxyServer(self, host=host, port=port)
        try:
            server.start()
            self.trafficProxyServer = server
            self.emit(f'[FlatLineDebugger.debugger] Traffic proxy bound to {server.endpointUrl()}', self.logPath)
            def _probe_proxy_background():
                for delay in (2.0, 3.0, 5.0):
                    try:
                        time.sleep(delay)
                        with urllib.request.urlopen(server.endpointUrl(), timeout=2.0) as response:
                            if int(getattr(response, 'status', 200) or 200) == 200:
                                self.emit(f'[FlatLineDebugger.debugger] Traffic proxy probe ok {server.endpointUrl()} delay={delay}', self.logPath)
                                return
                    except Exception as probe_error:
                        recordException('start.py:traffic-proxy-probe-retry', sys.exc_info()[1])
                self.emit(f'[WARNING:proxy] probe failed after retries for {server.endpointUrl()}; provider sends will fall back direct if the proxy is down.', self.exceptionPath)
            try:
                threading.Thread(target=_probe_proxy_background, name='TrioTrafficProxyProbe', daemon=True).start()
            except Exception:
                recordException('start.py:traffic-proxy-probe-thread', sys.exc_info()[1])
            return server
        except Exception as error:
            recordException('start.py:20261', sys.exc_info()[1])
            self.emit(f'[WARNING:proxy] bind failed for http://{host}:{port}: {type(error).__name__}: {error}', self.exceptionPath)
            return None


    def stopTrafficProxyServer(self):
        server = getattr(self, 'trafficProxyServer', None)
        if server is None:
            return False
        try:
            server.stop()
            return True
        finally:
            self.trafficProxyServer = None


    def launchChild(self, argv: list[str]) -> Any:
        return _sharedDebuggerLaunchChild(self, argv)


    def waitForChild(self, pollInterval: float = 0.25) -> int:
        proc = self.child
        if proc is None:
            return int(self.childExitCode or 1)
        try:
            while True:
                try:
                    self.pollManualDebugKeyOnce()
                except Exception:
                    recordException('start.py:20289', sys.exc_info()[1])
                    _traceSwallowedException('start.py:19904', sys.exc_info()[1])
                    pass
                code = proc.poll()
                if code is not None:
                    self.markChildExited(proc)
                    should_open = int(self.childExitCode or 0) != 0 and not self.inCrashConsole
                    if should_open and time.time() >= float(getattr(self, 'consoleSnoozeUntil', 0.0) or 0.0):
                        payload = {
                            'type_name': 'ChildExit',
                            'message': f'{primaryChildFileName()} exited with code {self.childExitCode}',
                            'worker': processsync.current_process().name,
                            'timestamp': time.time(),
                            'traceback_text': self.readFile(self.exceptionPath),
                        }
                        if bool(getattr(self, 'offscreenEnabled', False)):
                            self.emit(f"[FlatLineDebugger.debugger] Offscreen child exited nonzero rc={self.childExitCode}; crash console suppressed for non-interactive offscreen run.", self.exceptionPath)
                            try:
                                self.emitChildOutputTailOnExit()
                            except Exception:
                                recordException('start.py:offscreen-child-exit-tail', sys.exc_info()[1], handled=True)
                        else:
                            self.openCrashConsole(payload, block=True)
                    return int(self.childExitCode or 0)
                if float(getattr(self, 'consoleSnoozeUntil', 0.0) or 0.0) > time.time() and not self.inCrashConsole:
                    time.sleep(max(0.05, float(pollInterval or 0.25)))
                    continue
                time.sleep(max(0.05, float(pollInterval or 0.25)))
        finally:
            self.closeChildStreams()





