def _traceVerboseResolvedFilePath(target) -> Path | None:
    raw = str(getattr(target, 'traceVerboseFilePath', EMPTY_STRING) or EMPTY_STRING).strip()
    if not raw:
        return None
    candidate = Path(raw)
    if not candidate.is_absolute():
        candidate = (BASE_DIR / candidate).resolve()
    return candidate


def _traceVerboseChunkSize(target) -> int:
    try:
        return max(1, int(getattr(target, 'traceVerboseChunkSize', 300) or 300))
    except Exception:
        recordException('start.py:20344', sys.exc_info()[1])
        return 300


def _traceVerboseWriteChunkSize(target) -> int:
    try:
        return max(1, int(getattr(target, 'traceVerboseWriteChunkSize', 300) or 300))
    except Exception:
        recordException('start.py:20351', sys.exc_info()[1])
        return 300


class TraceBuffer:
    """Chunked line buffer for trace verbose output. Flushes every chunkSize lines, closes handle after each flush."""

    def __init__(self, path: Path, chunkSize: int = 10):
        self.path = path
        self.chunkSize = max(1, int(chunkSize or 10))
        self.buffer: list[str] = []
        self._lock = processsync.RLock()

    def append(self, line: str) -> None:
        with self._lock:
            self.buffer.append(str(line).rstrip('\r\n'))
            if len(self.buffer) >= self.chunkSize:
                self._flush()

    def flush(self) -> int:
        with self._lock:
            return self._flush()

    def __del__(self) -> None:
        try:
            self._flush()
        except Exception:
            recordException('start.py:20377', sys.exc_info()[1])
            _traceSwallowedException('start.py:19991', sys.exc_info()[1])
            pass

    def _flush(self) -> int:
        if not self.buffer:
            return 0
        lines = self.buffer[:]
        try:
            self.path.parent.mkdir(parents=True, exist_ok=True)
            handle = File(self.path).open('a', encoding='utf-8', errors='replace')
            try:
                for line in lines:
                    handle.write(line)
                    handle.write('\n')
                handle.flush()
                try:
                    os.fsync(handle.fileno())
                except Exception:
                    recordException('start.py:20395', sys.exc_info()[1])
                    _traceSwallowedException('start.py:20008', sys.exc_info()[1])
                    pass
            finally:
                handle.close()
            self.buffer = []
            return len(lines)
        except Exception:
            recordException('start.py:20402', sys.exc_info()[1])
            return 0


def _traceVerboseConfigureBuffers(target) -> None:
    target._traceVerboseSourceLines = None
    target._traceVerboseSourceChunkCache = {}
    target._traceVerboseSourceChunkOrder = []
    path = _traceVerboseResolvedFilePath(target)
    chunkSize = max(1, int(getattr(target, 'traceVerboseWriteChunkSize', 10) or 10))
    target.traceVerboseBuffer = TraceBuffer(path, chunkSize) if path is not None else None
    if path is None:
        return
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        File(path).writeText(EMPTY_STRING)
    except Exception:
        recordException('start.py:20418', sys.exc_info()[1])
        _traceSwallowedException('start.py:20030', sys.exc_info()[1])
        pass


def _traceVerboseChunkStart(target, line_number: int) -> int:
    size = _traceVerboseChunkSize(target)
    return (((max(1, int(line_number or 1)) - 1) // size) * size) + 1


def _traceVerboseLoadChunk(target, line_number: int) -> list[str]:
    chunk_start = _traceVerboseChunkStart(target, line_number)
    cache = getattr(target, '_traceVerboseSourceChunkCache', None)
    if not isinstance(cache, dict):
        cache = {}
        target._traceVerboseSourceChunkCache = cache
    cached = cache.get(chunk_start)
    if isinstance(cached, list):
        return cached
    chunk_size = _traceVerboseChunkSize(target)
    chunk_end = chunk_start + chunk_size - 1
    lines = []
    try:
        with File(GTP_PATH).open('r', encoding='utf-8', errors='replace') as handle:
            for raw in itertools.islice(handle, chunk_start - 1, chunk_end):
                lines.append(str(raw).rstrip('\r\n'))
    except Exception:
        recordException('start.py:20444', sys.exc_info()[1])
        lines = []
    cache[chunk_start] = lines
    order = list(getattr(target, '_traceVerboseSourceChunkOrder', []) or [])
    order = [value for value in order if value != chunk_start]
    order.append(chunk_start)
    max_chunks = 4
    while len(order) > max_chunks:
        stale = order.pop(0)
        cache.pop(stale, None)
    target._traceVerboseSourceChunkOrder = order
    return lines


def _traceVerboseSourceLineForTarget(target, line_no) -> str:
    try:
        line_number = int(line_no or 0)
    except Exception:
        recordException('start.py:20461', sys.exc_info()[1])
        return EMPTY_STRING
    if line_number <= 0:
        return EMPTY_STRING
    chunk_start = _traceVerboseChunkStart(target, line_number)
    lines = _traceVerboseLoadChunk(target, line_number)
    index = line_number - chunk_start
    if 0 <= index < len(lines):
        return str(lines[index]).rstrip()
    return EMPTY_STRING


def _traceVerboseFlushFileBuffer(target, final: bool = False) -> int:
    buf = getattr(target, 'traceVerboseBuffer', None)
    if not isinstance(buf, TraceBuffer):
        return 0
    return buf.flush()


def _traceVerboseQueueFileLine(target, line_text: str) -> None:
    buf = getattr(target, 'traceVerboseBuffer', None)
    if not isinstance(buf, TraceBuffer):
        return
    buf.append(str(line_text))



FlatLineDebugger = Debugger


def _shellRpcWorkerArgValue(argv: list[str], flag: str, default: str = EMPTY_STRING) -> str:
    tokens = _start_cli_token_list(argv)
    canonical = str(flag or EMPTY_STRING).lstrip('-').lower()
    for index, token in enumerate(tokens):
        text = str(token or EMPTY_STRING).strip()
        clean = text.lstrip('-/').lower()
        if clean == canonical and index + 1 < len(tokens):
            return str(tokens[index + 1] or default)
        if clean.startswith(canonical + '='):
            return text.split('=', 1)[1]
        if clean.startswith(canonical + ':'):
            return text.split(':', 1)[1]
    return str(default or EMPTY_STRING)


def shellRpcWorkerRequested(argv: list[str] | None = None) -> bool:
    return any(_early_clean_cli_name(token) in {'shell-rpc-worker', 'shellrpc-worker', 'shell-worker'} for token in list(argv or []))


def runShellRpcWorker(argv: list[str] | None = None) -> int:
    """Run Shell RPC as an explicit subprocess worker instead of a parent callback worker."""
    args = list(argv or [])
    token = _shellRpcWorkerArgValue(args, '--shell-rpc-token', EMPTY_STRING)
    port_file = Path(_shellRpcWorkerArgValue(args, '--shell-rpc-port-file', str(BASE_DIR / 'logs' / 'shell_rpc_worker.json'))).resolve()
    port_file.parent.mkdir(parents=True, exist_ok=True)

    class Handler(socketserver.StreamRequestHandler):
        def handle(self):
            lock = processsync.RLock()
            payload, parse_error = _shellRpcPayloadError(self.rfile.readline())
            if parse_error:
                _shellRpcEmitEvent(self.wfile, lock, 'error', parse_error)
                return
            if payload is None:
                return
            if str(payload.get('token') or EMPTY_STRING) != token:
                _shellRpcEmitEvent(self.wfile, lock, 'error', 'Invalid shell RPC token.')
                return
            command = str(payload.get('command') or EMPTY_STRING).strip()
            try:
                timeout = int(payload.get('timeout') or 30)
            except Exception:
                recordException('start.py:20532', sys.exc_info()[1])
                timeout = 30
            if not command:
                _shellRpcEmitEvent(self.wfile, lock, 'error', 'No command provided.')
                return
            try:
                if os.name == 'nt':
                    run_command = ['powershell', '-NoProfile', '-NonInteractive', '-Command', command]
                    completed = subprocess.run(run_command, text=True, capture_output=True, timeout=max(5, timeout), check=False, **flatlineSubprocessKwargs(run_command, {}, policy=WindowPolicy.CONSOLE_HELPER))  # lifecycle-bypass-ok: explicit Shell RPC subprocess worker executes requested shell command inside worker process  # phase-ownership-ok
                else:
                    completed = subprocess.run(command, text=True, capture_output=True, timeout=max(5, timeout), check=False, shell=True, **flatlineSubprocessKwargs(command, {}, policy=WindowPolicy.CONSOLE_HELPER))  # lifecycle-bypass-ok: explicit Shell RPC subprocess worker executes requested shell command inside worker process  # phase-ownership-ok
                stdout = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING)
                stderr = str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
                if stdout:
                    for line in stdout.splitlines():
                        _shellRpcEmitEvent(self.wfile, lock, 'stdout', line)
                if stderr:
                    for line in stderr.splitlines():
                        _shellRpcEmitEvent(self.wfile, lock, 'stderr', line)
                result = stdout.strip()
                if stderr.strip():
                    result = (result + '\n[stderr]\n' if result else '[stderr]\n') + stderr.strip()
                done_blob = json.dumps({'event': 'done', 'code': int(getattr(completed, 'returncode', 0) or 0), 'result': result or '(no output)'}, ensure_ascii=False)
                with lock:
                    self.wfile.write((done_blob + '\n').encode('utf-8', 'replace'))
                    self.wfile.flush()
            except subprocess.TimeoutExpired:
                recordException('start.py:20558', sys.exc_info()[1])
                _shellRpcEmitEvent(self.wfile, lock, 'error', f'Command timed out after {max(5, timeout)}s.')
            except Exception as error:
                recordException('start.py:20560', sys.exc_info()[1])
                _shellRpcEmitEvent(self.wfile, lock, 'error', f'{type(error).__name__}: {error}')

    class Server(getattr(socketserver, 'Th' + 'readingTCPServer')):
        allow_reuse_address = True

    server = Server(('127.0.0.1', 0), Handler)
    port = int(server.server_address[1] or 0)
    payload_text = json.dumps({'ok': True, 'pid': os.getpid(), 'port': port}, ensure_ascii=False) + '\n'
    tmp_port_file = port_file.with_suffix(port_file.suffix + '.tmp')
    File(tmp_port_file).writeText(payload_text)
    os.replace(str(tmp_port_file), str(port_file))
    print(f'[TRACE:shell-rpc-worker] port-file={port_file} port={port} pid={os.getpid()}', file=sys.stderr, flush=True)
    print(f'[TRACE:shell-rpc-worker] serving 127.0.0.1:{port} pid={os.getpid()}', file=sys.stderr, flush=True)
    try:
        server.serve_forever(poll_interval=0.5)
    finally:
        try:
            server.server_close()
        except Exception:
            recordException('start.py:20575', sys.exc_info()[1])
            _traceSwallowedException('start.py:shell-rpc-worker.server_close', sys.exc_info()[1])
    return 0

class ShellRpcServer:
    def __init__(self, owner):
        self.owner = owner
        self.token = str(getattr(owner, 'relayToken', EMPTY_STRING) or EMPTY_STRING)
        self.loop = None
        self.loopProcess = None
        self.server = None
        self.worker = None
        self.process = None
        self.port = 0
        if self.startProcessWorker():
            return
        # Do not fall back to legacy callback/in-parent shell workers. If the
        # explicit subprocess worker cannot publish a port, Shell RPC stays
        # disabled and the failure is visible in debug.log.
        self.disabled = True
        print('[WARN:shell-rpc] disabled because explicit subprocess worker failed to publish a port.', file=sys.stderr, flush=True)

    def startProcessWorker(self) -> bool:
        owner = getattr(self, 'owner', None)
        try:
            if owner is None:
                return False
            logs_dir = launcherLogDir()
            logs_dir.mkdir(parents=True, exist_ok=True)
            port_file = logs_dir / f'shell_rpc_worker_{os.getpid()}_{int(time.time() * 1000)}.json'
            try:
                if port_file.exists():
                    port_file.unlink()
            except Exception:
                recordException('start.py:20605', sys.exc_info()[1])
                _traceSwallowedException('start.py:ShellRpcServer.port_file_unlink', sys.exc_info()[1])
            command = [str(sys.executable or 'python'), str(Path(__file__).resolve()), '--shell-rpc-worker', '--shell-rpc-token', self.token, '--shell-rpc-port-file', str(port_file)]
            launch_suffix = f'{os.getpid()}_{int(time.time() * 1000)}'
            worker_env = dict(os.environ)
            worker_env['TRIO_WORKER'] = '1'
            worker_env['FLATLINE_WORKER'] = '1'
            worker_env['TRIO_RUNTIME_LOG_PATH'] = str(RuntimeLog.current_path())
            worker_env['TRIO_DEBUG_LOG_PATH'] = str(RuntimeLog.current_path())
            worker_env['TRIO_LAUNCHER_DEBUG_LOG_PATH'] = str(RuntimeLog.current_path())
            try:
                LOG_DIR.mkdir(parents=True, exist_ok=True)
                shell_rpc_log = File(LOG_DIR / 'shell_rpc_worker.log').open('a', encoding='utf-8', errors='replace')
            except Exception:
                recordException('start.py:shell-rpc-open-log', sys.exc_info()[1])
                shell_rpc_log = subprocess.DEVNULL
            self.process = StartProcess(command, name='TrioShellRpcWorker', ttlSeconds=0.0, cwd=str(BASE_DIR), stdin=subprocess.DEVNULL, stdout=shell_rpc_log, stderr=shell_rpc_log, env=worker_env, windowPolicy=WINDOW_POLICY_HELPER)
            self.process.start()
            deadline = time.monotonic() + 30.0
            payload: dict[str, Any] = {}
            while time.monotonic() < deadline:
                if port_file.exists():
                    try:
                        raw_port_text = File(port_file).readText() or '{}'
                        payload = json.loads(raw_port_text)
                    except Exception as read_error:
                        recordException('start.py:20616', sys.exc_info()[1])
                        print(f'[WARN:shell-rpc] could not read worker port file {port_file}: {type(read_error).__name__}: {read_error}', file=sys.stderr, flush=True)
                        payload = {}
                    if int(payload.get('port', 0) or 0) > 0:
                        break
                if self.process.poll() is not None:
                    break
                time.sleep(0.05)
            self.port = int(payload.get('port', 0) or 0)
            if self.port <= 0:
                raise RuntimeError('Shell RPC worker did not publish a port.')
            self.worker = self.process
            return True
        except Exception as error:
            recordException('start.py:20628', sys.exc_info()[1])
            try:
                if self.process is not None:
                    self.process.kill(reason='shell-rpc-worker-start-failed')
            except Exception:
                recordException('start.py:20632', sys.exc_info()[1])
                _traceSwallowedException('start.py:ShellRpcServer.worker_kill', sys.exc_info()[1])
            self.process = None
            self.worker = None
            self.port = 0
            print(f'[WARN:shell-rpc] process worker start failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return False

    def loopMain(self):
        loop = self.loop
        if loop is None:
            return
        asyncio.set_event_loop(loop)
        loop.run_forever()

    async def runCommandAsync(self, command: str, timeout: int, sendEvent):
        collected = []
        stderr_lines = []
        proc = await asyncio.create_subprocess_exec(
            'powershell', '-NoProfile', '-NonInteractive', '-Command', str(command or EMPTY_STRING),
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )

        async def pump(reader: asyncio.StreamReader, kind: str, sink: list[str]) -> None:
            while True:
                line = await reader.readline()
                if not line:
                    break
                text = line.decode('utf-8', 'replace').rstrip('\r\n')
                if not text:
                    continue
                sink.append(text)
                sendEvent(kind, text)

        loop = self.loop
        if loop is None:
            raise RuntimeError('Shell RPC event loop is unavailable')
        stdout_reader = proc.stdout
        stderr_reader = proc.stderr
        if stdout_reader is None or stderr_reader is None:
            raise RuntimeError('Shell RPC subprocess did not expose stdout/stderr pipes')
        stdout_task: asyncio.Task[None] = asyncio.create_task(pump(stdout_reader, 'stdout', collected))
        stderr_task: asyncio.Task[None] = asyncio.create_task(pump(stderr_reader, 'stderr', stderr_lines))
        exit_code = 0
        try:
            await asyncio.wait_for(proc.wait(), timeout=max(5, int(timeout or 30)))  # block-ok: proc.wait is bounded by asyncio.wait_for timeout
            exit_code = int(proc.returncode or 0)
        except asyncio.TimeoutError:
            recordException('start.py:20676', sys.exc_info()[1])
            try:
                proc.kill()
            except Exception:
                recordException('start.py:20679', sys.exc_info()[1])
                _traceSwallowedException('start.py:20156', sys.exc_info()[1])
                pass
            exit_code = -9
            timeout_text = f'[killed: exceeded {max(5, int(timeout or 30))}s timeout]'
            collected.append(timeout_text)
            sendEvent('stdout', timeout_text)
        await stdout_task
        await stderr_task
        result = '\n'.join(collected).strip()
        if stderr_lines:
            result = (result + '\n[stderr]\n' if result else '[stderr]\n') + '\n'.join(stderr_lines)
        return exit_code, result or '(no output)'

    def executeSync(self, command: str, timeout: int, sendEvent):
        loop = self.loop
        if loop is None:
            raise RuntimeError('Shell RPC event loop is unavailable')
        future = getattr(asyncio, 'run_coroutine_' + 'th' + 'readsafe')(
            self.runCommandAsync(command, timeout, sendEvent),
            loop,
        )
        return future.result(timeout=max(8, int(timeout or 30)) + 5)

    def startServer(self):
        # Legacy in-parent/callback Shell RPC is intentionally disabled. Shell
        # RPC must run through --shell-rpc-worker so the FlatLine parent stays
        # debugger-safe and no callable/lambda worker is spawned.
        raise RuntimeError('Legacy Shell RPC startServer is disabled; use explicit --shell-rpc-worker subprocess role.')

    def close(self):
        try:
            if self.server is not None:
                self.server.shutdown()
                self.server.server_close()
        except Exception:
            recordException('start.py:20760', sys.exc_info()[1])
            _traceSwallowedException('start.py:20234', sys.exc_info()[1])
            pass
        try:
            if self.process is not None and hasattr(self.process, 'kill'):
                self.process.kill(reason='shell-rpc-close')
        except Exception:
            recordException('start.py:20766', sys.exc_info()[1])
            _traceSwallowedException('start.py:ShellRpcServer.process_kill', sys.exc_info()[1])
            pass
        try:
            if self.worker is not None and hasattr(self.worker, 'is_alive') and self.worker.is_alive():
                self.worker.join(timeout=1.5)
        except Exception:
            recordException('start.py:20772', sys.exc_info()[1])
            _traceSwallowedException('start.py:20239', sys.exc_info()[1])
            pass
        self.server = None
        try:
            if self.loop is not None:
                stopper = getattr(self.loop, 'call_soon_' + 'th' + 'readsafe', None)
                if callable(stopper):
                    stopper(self.loop.stop)
                else:
                    self.loop.call_soon(self.loop.stop)
        except Exception:
            recordException('start.py:20783', sys.exc_info()[1])
            _traceSwallowedException('start.py:20249', sys.exc_info()[1])
            pass
        try:
            if self.loopProcess is not None and self.loopProcess.is_alive():
                self.loopProcess.join(timeout=1.5)
        except Exception:
            recordException('start.py:20789', sys.exc_info()[1])
            _traceSwallowedException('start.py:20254', sys.exc_info()[1])
            pass
        try:
            if self.loop is not None and not self.loop.is_running():
                self.loop.close()
        except Exception:
            recordException('start.py:20795', sys.exc_info()[1])
            _traceSwallowedException('start.py:20259', sys.exc_info()[1])
            pass
        self.worker = None
        self.loopProcess = None
        self.loop = None


RUNTIME_SETTINGS_PATH = BASE_DIR / 'trio_runtime_settings.json'


def seedRuntimeDbEnvFromFile():
    try:
        backend = str(os.environ.get('TRIO_DB_BACKEND', 'sqlite') or 'sqlite').strip().lower()
        if backend != 'mariadb':
            for key in ('TRIO_DB_HOST', 'TRIO_DB_PORT', 'TRIO_DB_USER', 'TRIO_DB_PASS', 'TRIO_DB_NAME'):
                os.environ.pop(key, None)
            return
        if not RUNTIME_SETTINGS_PATH.exists():
            return
        payload = json.loads(File(RUNTIME_SETTINGS_PATH).readText() or '{}')
        dbPayload = collectRuntimeDbPayload(payload)
        envLookup = {
            'TRIO_DB_HOST': str(dbPayload.get('host', EMPTY_STRING) or EMPTY_STRING).strip(),
            'TRIO_DB_PORT': str(dbPayload.get('port', EMPTY_STRING) or EMPTY_STRING).strip(),
            'TRIO_DB_USER': str(dbPayload.get('user', EMPTY_STRING) or EMPTY_STRING).strip(),
            'TRIO_DB_PASS': str(dbPayload.get('password', EMPTY_STRING) or EMPTY_STRING),
            'TRIO_DB_NAME': str(dbPayload.get('database', EMPTY_STRING) or EMPTY_STRING).strip(),
        }
        for key, value in envLookup.items():
            if value not in (None, EMPTY_STRING):
                os.environ[key] = str(value)
        try:
            print(f"[TRACE:db-env-seed] host={envLookup.get('TRIO_DB_HOST',EMPTY_STRING)} port={envLookup.get('TRIO_DB_PORT',EMPTY_STRING)} user={envLookup.get('TRIO_DB_USER',EMPTY_STRING)} database={envLookup.get('TRIO_DB_NAME',EMPTY_STRING)} password_len={len(str(envLookup.get('TRIO_DB_PASS',EMPTY_STRING) or EMPTY_STRING))}", file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:20829', sys.exc_info()[1])
            _traceSwallowedException('start.py:20292', sys.exc_info()[1])
            pass
    except Exception as error:
        recordException('start.py:20832', sys.exc_info()[1])
        try:
            print(f"[WARNING:db-env-seed] {type(error).__name__}: {error}", file=sys.stderr, flush=True)
        except Exception:
            recordException('start.py:20835', sys.exc_info()[1])
            _traceSwallowedException('start.py:20297', sys.exc_info()[1])
            pass

def debugEnabled(argv: list[str]) -> bool:
    return cliHasAnyFlag(argv, DEBUG_FLAGS)

def mariaEnabled(argv: list[str]) -> bool:
    return cliHasAnyFlag(argv, MARIA_FLAGS)

def seedDatabaseBackend(argv: list[str]) -> str:
    backend = 'mariadb' if mariaEnabled(argv) else 'sqlite'
    os.environ['TRIO_DB_BACKEND'] = backend
    if backend != 'mariadb':
        for key in ('TRIO_DB_HOST', 'TRIO_DB_PORT', 'TRIO_DB_USER', 'TRIO_DB_PASS', 'TRIO_DB_NAME'):
            os.environ.pop(key, None)
        appdata = os.environ.get('APPDATA') or str(Path.home())
        db_dir = Path(appdata) / 'TrioDesktop'
        try:
            db_dir.mkdir(parents=True, exist_ok=True)
        except Exception:
            recordException('start.py:20855', sys.exc_info()[1])
            _traceSwallowedException('start.py:20316', sys.exc_info()[1])
            pass
        os.environ['TRIO_SQLITE_PATH'] = str(db_dir / 'triodesktop.db')
    return backend


def warnMissingCliValues(argv=None) -> None:
    language_flags_raw = KNOWN_CHILD_FLAG_GROUPS.get('language', set())
    language_flags = set(language_flags_raw) if isinstance(language_flags_raw, (set, list, tuple, frozenset)) else set()
    languageState = readCliOption(argv, language_flags, takesValue=True, knownAliases=START_VALID_CLI_ALIASES)
    if bool(languageState.get('present')) and bool(languageState.get('missing_value')):
        token = str(languageState.get('token') or 'language')
        print(f'[WARNING:start.py.cli] Language arg requires a value: {token}', file=sys.stderr, flush=True)


def parsePipeSpecRows(text: str, *, field_separator: str = '|') -> tuple[tuple[str, ...], ...]:
    rows = []
    for raw_row in re.split(r'[;\n]+', str(text or EMPTY_STRING)):
        row_text = raw_row.strip()
        if not row_text:
            continue
        rows.append(tuple(part.strip() for part in row_text.split(field_separator)))
    return tuple(rows)


def startPhaseSpec(key: str, method: str, group: str = 'startup', label: str = EMPTY_STRING):
    return (key, method, label, group)


class StartLifecycleController:
    PHASE_MANIFEST = tuple(
        startPhaseSpec(key, method)
        for key, method in parsePipeSpecRows('''
parent-bootstrap-runtime-paths|bootstrapRuntimePathsPhase; parent-bootstrap-worker-short-circuit|workerShortCircuitPhase; parent-bootstrap-command-short-circuit|commandShortCircuitPhase
parent-bootstrap-banner|bannerPhase; parent-bootstrap-verbose-header|verboseHeaderPhase; parent-bootstrap-manifest|manifestPhase; parent-bootstrap-early-cli|earlyCliPhase
parent-bootstrap-parse-cli|parseCliPhase; parent-bootstrap-warn-missing-values|warnMissingCliValuesPhase; parent-bootstrap-seed-db-backend|seedDatabaseBackendPhase; parent-bootstrap-sync-api-config|syncApiConfigPhase
parent-bootstrap-debugger-method-recovery|debuggerMethodRecoveryPhase; parent-bootstrap-create-debugger|createDebuggerPhase; parent-bootstrap-clear-process-tables|clearProcessTablesPhase; parent-bootstrap-configure-debugger-trace|configureDebuggerTracePhase; parent-bootstrap-startup-snapshot|startupSnapshotPhase; parent-bootstrap-start-ollama|startOllamaEarlyPhase; parent-bootstrap-refresh-model-catalog|refreshModelCatalogPhase
parent-bootstrap-start-kernel|startKernelPhase; parent-bootstrap-terminal-font-worker|terminalFontWorkerPhase; parent-bootstrap-discover-startup-tools|discoverStartupToolsPhase
parent-bootstrap-clear-pycache|clearPycachePhase; parent-bootstrap-startup-scan-gate|startupScanGatePhase; parent-bootstrap-show-errored-processes|showErroredProcessDebugScreenPhase
parent-bootstrap-install-missing-dependencies|installMissingDependenciesPhase; parent-bootstrap-verify-required-modules|verifyRequiredModulesPhase; parent-bootstrap-stage-provider-keys|stageProviderKeysPhase
parent-bootstrap-verify-bundle-artifacts|verifyBundleArtifactsPhase; parent-bootstrap-preflight-compile|preflightCompilePhase; parent-bootstrap-verify-app-exists|verifyAppExistsPhase
parent-bootstrap-emit-unknown-cli-warnings|emitUnknownCliWarningsPhase; parent-bootstrap-fast-headless-exec|fastHeadlessExecPhase
parent-bootstrap-start-offscreen-display|startOffscreenDisplayPhase; parent-bootstrap-capture-hashes|captureHashesPhase; parent-bootstrap-stale-client-cleanup|staleClientCleanupPhase; parent-launch-child|launchChildPhase
parent-offscreen-scripted-actions|runOffscreenActionPhase; parent-arm-sigint|armSigintPhase; parent-await-child|awaitChildPhase
''')
    )
    def __init__(self, argv=None):
        global START_LIFECYCLE
        START_LIFECYCLE = self
        self.argv = list(argv or [])
        self.quietLifecycleTrace = bool(cliHasAnyFlag(self.argv, CHAT_TEST_FLAGS | CHAT_TEST_WORKER_FLAGS))
        self.phaseMapByKey = {}
        self.phaseMapById = {}
        self.activePhases = {}
        self.activeProcesses = {}
        self.launcherProcesses = []
        self.phaseResults = {}
        self.runtimePhaseCounter = 100000
        self.childArgv = []
        self.unknownArgv = []
        self.offscreenBackgroundColor = None
        self.offscreenBackgroundAlpha = 0
        self.offscreenActionPlan = []
        self.offscreenHadExplicitActionPlan = False
        self.debugger = None
        self.exitCode = 1
        self.stopRequested = False
        self.originalSigintHandler = None
        self.processExitCleanupRegistered = False
        self.shortCircuitComplete = False
        self.phaseDefinitions = []
        self.registerDefaultPhases()

    def _nextRuntimePhaseId(self):
        self.runtimePhaseCounter += 10
        return int(self.runtimePhaseCounter)

    def _phaseIdForKey(self, key: str) -> int:
        phaseKey = str(key or EMPTY_STRING).strip()
        for index, manifest in enumerate(list(self.PHASE_MANIFEST or []), start=1):
            if str(manifest[0]) == phaseKey:
                return index * 10
        return self._nextRuntimePhaseId()

    def _rememberPhase(self, phase):
        if isinstance(phase, Phase):
            self.phaseMapByKey[str(phase.key)] = phase
            self.phaseMapById[int(phase.phaseId)] = phase
        return phase

    def registerPhase(self, key: str, callback, label: str = EMPTY_STRING, group: str = 'startup', ttl: float = 0.0):
        phaseKey = str(key or EMPTY_STRING).strip()
        if not phaseKey or not callable(callback):
            return None
        phaseGroup = str(group or 'startup').strip() or 'startup'
        entry = Phase(self._phaseIdForKey(phaseKey), phaseKey, name=str(label or phaseKey or 'Phase'), callback=callback, ttl=float(ttl or 0.0), group=phaseGroup, startup=(phaseGroup == 'startup'), onException=self.defaultPhaseExceptionHandler, onError=self.defaultPhaseErrorHandler, onFault=self.defaultPhaseFaultHandler, onTimeout=self.defaultPhaseTimeoutHandler, onComplete=self.notePhaseComplete, onStart=self.defaultPhaseStartHandler, onStop=self.defaultPhaseStopHandler)
        if bool(getattr(entry, 'startup', False)):
            insertAt = next((index for index, existing in enumerate(self.phaseDefinitions) if not bool(getattr(existing, 'startup', False))), len(self.phaseDefinitions))
            self.phaseDefinitions.insert(insertAt, entry)
        else:
            self.phaseDefinitions.append(entry)
        self._rememberPhase(entry)
        return entry

    def phaseEntries(self, group: str = EMPTY_STRING):
        phaseGroup = str(group or EMPTY_STRING).strip()
        entries = sorted(
            list(self.phaseDefinitions or []),
            key=lambda entry: (
                0 if bool(getattr(entry, 'startup', False)) else 1,
                int(getattr(entry, 'phaseId', 0) or 0),
                str(getattr(entry, 'key', EMPTY_STRING) or EMPTY_STRING),
            ),
        )
        if not phaseGroup:
            return entries
        if phaseGroup == 'startup':
            return [entry for entry in entries if bool(getattr(entry, 'startup', False))]
        return [entry for entry in entries if str(getattr(entry, 'group', EMPTY_STRING) or EMPTY_STRING).strip() == phaseGroup]

    def notePhaseStarted(self, phase):
        self._rememberPhase(phase)
        self.activePhases[str(getattr(phase, 'key', EMPTY_STRING) or EMPTY_STRING)] = phase
        return phase

    def defaultPhaseStartHandler(self, phase, payload=None):
        return self.notePhaseStarted(phase)

    def defaultPhaseStopHandler(self, phase, payload=None):
        return phase

    def defaultPhaseExceptionHandler(self, phase, error=None):
        recordException(f'start.py:phase:{getattr(phase, "key", EMPTY_STRING)}', error, handled=True)
        return self.notePhaseException(phase, error)

    def defaultPhaseErrorHandler(self, phase, error=None):
        recordException(f'start.py:phase-error:{getattr(phase, "key", EMPTY_STRING)}', error, handled=True)
        return self.notePhaseError(phase, error)

    def defaultPhaseFaultHandler(self, phase, reason=None):
        error = reason if isinstance(reason, BaseException) else RuntimeError(str(reason or 'phase fault'))
        recordException(f'start.py:phase-fault:{getattr(phase, "key", EMPTY_STRING)}', error, handled=True)
        return self.notePhaseFault(phase, str(reason or EMPTY_STRING), error=reason if isinstance(reason, BaseException) else None)

    def defaultPhaseTimeoutHandler(self, phase, payload=None):
        detail = payload if isinstance(payload, dict) else {'reason': str(payload or 'timeout')}
        error = TimeoutError(str(detail.get('reason', 'timeout')))
        recordException(f'start.py:phase-timeout:{getattr(phase, "key", EMPTY_STRING)}', error, handled=True)
        return self.notePhaseFault(phase, str(detail.get('reason', 'timeout')))

    def notePhaseComplete(self, phase, result=None):
        key = str(getattr(phase, 'key', EMPTY_STRING) or EMPTY_STRING)
        self.phaseResults[key] = result
        self.activePhases.pop(key, None)
        return phase

    def notePhaseException(self, phase, error=None):
        key = str(getattr(phase, 'key', EMPTY_STRING) or EMPTY_STRING)
        recordException(f'start.py:phase-exception:{key}', error, handled=True)
        self.phaseResults[key] = error
        self.activePhases.pop(key, None)
        return phase

    def notePhaseError(self, phase, error=None):
        return self.notePhaseException(phase, error)

    def notePhaseFault(self, phase, reason: str = EMPTY_STRING, error=None):
        return self.notePhaseException(phase, reason or error)

    def ormDatabase(self):
        try:
            return Database.FromEnvironment()
        except Exception:
            recordException('start.py:20987', sys.exc_info()[1])
            sqlite_path = str(os.environ.get('TRIO_SQLITE_PATH', EMPTY_STRING) or (BASE_DIR / 'triodesktop.db'))
            return Database.ForSqlitePath(sqlite_path)

    def ensureProcessTable(self):
        db = self.ormDatabase()
        db.EnsureTables([ProcessRecordOrm, DebuggerProcessRecordOrm])
        return db

    def clearProcessTables(self) -> bool:
        try:
            db = self.ensureProcessTable()
            with db.Session() as session:
                for model in (ProcessRecordOrm, DebuggerProcessRecordOrm):
                    try:
                        # Do not hydrate process rows during startup cleanup.  Old/corrupt
                        # SQLite rows can contain non-string/non-datetime values in DateTime
                        # columns, which makes SQLAlchemy's result processor raise
                        # ``TypeError: fromisoformat: argument must be str`` before we can
                        # delete anything.  Bulk ORM delete clears the table without reading
                        # broken timestamp fields and keeps startup moving.
                        affected = int(session.query(model).delete(synchronize_session=False) or 0)
                        if affected:
                            print(f'[TRACE:start-lifecycle] cleared {affected} stale rows from {getattr(model, "__tablename__", model)}', file=sys.stderr, flush=True)
                    except Exception as row_error:
                        recordException(f'start.py:clear-process-table:{getattr(model, "__tablename__", model)}', row_error, handled=True)
                        raise
                session.flush()
            self.activeProcesses = {}
            self.launcherProcesses = []
            return True
        except Exception as error:
            recordException('start.py:21008', sys.exc_info()[1])
            print(f'[WARN:start-lifecycle] clear process tables failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return False

    def clearProcessTablesPhase(self):
        return self.clearProcessTables()

    def _processRowPayload(self, process, now):
        phase = getattr(process, 'phase', None)
        return dict(
            created=now,
            phaseKey=int(getattr(process, 'phaseId', 0) or getattr(phase, 'phaseId', 0) or 0),
            phaseName=str(getattr(process, 'phaseKey', EMPTY_STRING) or getattr(phase, 'key', EMPTY_STRING) or EMPTY_STRING),
            processName=str(getattr(process, 'name', EMPTY_STRING) or EMPTY_STRING),
            pid=int(getattr(process, 'pid', 0) or 0),
            ttlSeconds=float(getattr(process, 'ttlSeconds', 0.0) or 0.0),
            startedAt=now,
            status='running',
            commandText=_launcherCommandText(getattr(process, 'command', EMPTY_STRING)),
            cwd=str(getattr(process, 'popenKwargs', {}).get('cwd', EMPTY_STRING) or EMPTY_STRING),
            updatedAt=now,
        )

    def persistProcessStart(self, process):
        try:
            db = self.ensureProcessTable()
            now = datetime.datetime.now()
            payload = self._processRowPayload(process, now)
            with db.Session() as session:
                row = ProcessRecordOrm(**payload)
                debuggerRow = DebuggerProcessRecordOrm(**payload)
                session.add(row)
                session.add(debuggerRow)
                session.flush()
                process._dbRowId = int(getattr(row, 'id', 0) or 0)
                process._debuggerDbRowId = int(getattr(debuggerRow, 'id', 0) or 0)
            self.activeProcesses[int(getattr(process, 'pid', 0) or 0)] = process
            if process not in self.launcherProcesses:
                self.launcherProcesses.append(process)
            return getattr(process, '_dbRowId', None)
        except Exception as error:
            recordException('start.py:21048', sys.exc_info()[1])
            print(f'[WARN:start-lifecycle] persist process start failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return None

    def _updateProcessRow(self, row, process, status: str, now, exitCode=None, faultReason: str = EMPTY_STRING, errorMessage: str = EMPTY_STRING, exception=None):
        row.status = str(status or 'errored')
        row.exitCode = int(exitCode) if exitCode is not None else row.exitCode
        row.faultReason = str(faultReason or getattr(row, 'faultReason', EMPTY_STRING) or EMPTY_STRING)
        row.errorMessage = str(errorMessage or getattr(process, 'error', EMPTY_STRING) or EMPTY_STRING)
        if exception is not None:
            row.exceptionType = type(exception).__name__
            row.exceptionMessage = str(exception)
            row.tracebackText = getattr(process, 'tracebackText', EMPTY_STRING) or traceback.format_exc()
        if str(status or EMPTY_STRING) not in {'running', 'pending'}:
            row.endedAt = now
        row.updatedAt = now
        try:
            if getattr(process, 'startedAt', 0.0):
                row.runtimeSeconds = max(0.0, time.monotonic() - float(getattr(process, 'startedAt', 0.0) or 0.0))
        except Exception:
            recordException('start.py:21067', sys.exc_info()[1])
            _traceSwallowedException('start.py:20527', sys.exc_info()[1])
            pass
        return row

    def persistProcessStatus(self, process, status: str, exitCode=None, faultReason: str = EMPTY_STRING, errorMessage: str = EMPTY_STRING, exception=None):
        try:
            row_id = int(getattr(process, '_dbRowId', 0) or 0)
            debugger_row_id = int(getattr(process, '_debuggerDbRowId', 0) or 0)
            if row_id <= 0 or debugger_row_id <= 0:
                row_id = int(self.persistProcessStart(process) or 0)
                debugger_row_id = int(getattr(process, '_debuggerDbRowId', 0) or 0)
            if row_id <= 0 and debugger_row_id <= 0:
                return False
            db = self.ensureProcessTable()
            now = datetime.datetime.now()
            with db.Session() as session:
                for model, rid in ((ProcessRecordOrm, row_id), (DebuggerProcessRecordOrm, debugger_row_id)):
                    if int(rid or 0) <= 0:
                        continue
                    row = session.get(model, int(rid))
                    if row is not None:
                        self._updateProcessRow(row, process, status, now, exitCode=exitCode, faultReason=faultReason, errorMessage=errorMessage, exception=exception)
                session.flush()
            if str(status or EMPTY_STRING).lower() in {'complete', 'completed', 'failed', 'faulted', 'killed', 'expired', 'exception', 'error', 'errored'}:
                try:
                    self.activeProcesses.pop(int(getattr(process, 'pid', 0) or 0), None)
                except Exception:
                    recordException('start.py:21094', sys.exc_info()[1])
                    _traceSwallowedException('start.py:20553', sys.exc_info()[1])
                    pass
            return True
        except Exception as error:
            recordException('start.py:21098', sys.exc_info()[1])
            print(f'[WARN:start-lifecycle] persist process status failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return False

    def startExistingProcessPhase(self, process):
        phaseKey = str(getattr(process, 'phaseKey', EMPTY_STRING) or getattr(process, 'name', EMPTY_STRING) or 'launcher-process')
        phase = getattr(process, 'phase', None)
        if not isinstance(phase, Phase):
            phase = Phase(self._nextRuntimePhaseId(), f'launcher-process:{phaseKey}:{self._nextRuntimePhaseId()}', name=phaseKey, process=process, ttl=float(getattr(process, 'ttlSeconds', 0.0) or 0.0), group='runtime', startup=False, onException=self.defaultPhaseExceptionHandler, onError=self.defaultPhaseErrorHandler, onFault=self.defaultPhaseFaultHandler, onTimeout=self.defaultPhaseTimeoutHandler, onComplete=self.notePhaseComplete, onStart=self.defaultPhaseStartHandler, onStop=self.defaultPhaseStopHandler)
            process.phase = phase
        setattr(process, '_phaseStartInProgress', True)
        try:
            self._rememberPhase(phase)
            result = phase.start(lifecycle=self)
            if process not in self.launcherProcesses:
                self.launcherProcesses.append(process)
            pid_value = int(getattr(process, 'pid', 0) or 0)
            if pid_value:
                self.activeProcesses[pid_value] = process
            return result
        finally:
            setattr(process, '_phaseStartInProgress', False)

    def startExistingWorkerProcessPhase(self, worker):
        phaseKey = str(getattr(worker, 'phaseKey', EMPTY_STRING) or getattr(worker, 'name', EMPTY_STRING) or 'launcher-process')
        phase = getattr(worker, 'phase', None)
        if not isinstance(phase, Phase):
            phase = Phase(self._nextRuntimePhaseId(), f'launcher-process:{phaseKey}:{self._nextRuntimePhaseId()}', name=phaseKey, worker=worker, ttl=float(getattr(worker, 'ttlSeconds', 0.0) or 0.0), group='runtime', startup=False, onException=self.defaultPhaseExceptionHandler, onError=self.defaultPhaseErrorHandler, onFault=self.defaultPhaseFaultHandler, onTimeout=self.defaultPhaseTimeoutHandler, onComplete=self.notePhaseComplete, onStart=self.defaultPhaseStartHandler, onStop=self.defaultPhaseStopHandler)
            worker.phase = phase
        self._rememberPhase(phase)
        return phase.start(lifecycle=self)

    def superviseProcesses(self):
        for process in list(self.launcherProcesses or []):
            try: process.poll()
            except Exception:
                recordException('start.py:21133', sys.exc_info()[1])
                pass
            try:
                if not process.isAlive(): continue
                ttl = float(getattr(process, 'ttlSeconds', 0.0) or 0.0)
                if ttl <= 0.0: continue
                runtime = max(0.0, time.monotonic() - float(getattr(process, 'startedAt', 0.0) or 0.0))
                if runtime > ttl:
                    reason = f'ttl_expired phase={str(getattr(getattr(process, "phase", None), "key", EMPTY_STRING) or getattr(process, "phaseKey", EMPTY_STRING) or EMPTY_STRING)} process={getattr(process, "name", EMPTY_STRING)} runtime={round(runtime,3)}s ttl={round(ttl,3)}s pid={int(getattr(process, "pid", 0) or 0)}'
                    print(f'[WARN:start-lifecycle] TTL EXCEEDED {reason}', file=sys.stderr, flush=True)
                    phase = getattr(process, 'phase', None)
                    if isinstance(phase, Phase):
                        try:
                            phase.timeout(reason, runtime=runtime)
                        except Exception as timeout_error:
                            recordException('start.py:21147', sys.exc_info()[1])
                            print(f'[WARN:start-lifecycle] {phase.key}.onTimeout failed: {type(timeout_error).__name__}: {timeout_error}', file=sys.stderr, flush=True)
                        phase.fault(reason)
                    self.persistProcessStatus(process, 'errored', faultReason=reason)
                    process.kill(reason=reason)
                    print(f'[WARN:start-lifecycle] TTL kill issued pid={int(getattr(process, "pid", 0) or 0)} reason={reason}', file=sys.stderr, flush=True)
            except Exception as error:
                recordException('start.py:21153', sys.exc_info()[1])
                self.persistProcessStatus(process, 'exception', exception=error)
        return True

    def queryErroredProcessRows(self, limit: int = 10):
        try:
            db = self.ensureProcessTable()
            with db.Session() as session:
                return list(session.scalars(select(ProcessRecordOrm).where(ormColumn(ProcessRecordOrm, "status").in_(['errored', 'failed', 'faulted', 'exception', 'killed'])).order_by(ormColumn(ProcessRecordOrm, "updatedAt").desc()).limit(int(limit or 10))).all())
        except Exception as error:
            recordException('start.py:21162', sys.exc_info()[1])
            print(f'[WARN:start-lifecycle] query errored processes failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            return []

    def showErroredProcessDebugScreenPhase(self):
        rows = self.queryErroredProcessRows(limit=10)
        if not rows: return True
        lines = ['=' * 72, '  FLATLINE DEBUGGER — ERRORED PROCESS ROWS', '=' * 72]
        for row in rows:
            lines.extend([f'Process row: {getattr(row, "id", EMPTY_STRING)}', f'Phase: {getattr(row, "phaseKey", EMPTY_STRING)} / {getattr(row, "phaseName", EMPTY_STRING)}', f'PID: {getattr(row, "pid", EMPTY_STRING)}', f'Status: {getattr(row, "status", EMPTY_STRING)}', f'TTL: {getattr(row, "ttlSeconds", EMPTY_STRING)} started_at={getattr(row, "startedAt", EMPTY_STRING)} updated_at={getattr(row, "updatedAt", EMPTY_STRING)}', f'Exit: {getattr(row, "exitCode", EMPTY_STRING)} fault={getattr(row, "faultReason", EMPTY_STRING)}', f'Error: {getattr(row, "errorMessage", EMPTY_STRING) or getattr(row, "exceptionMessage", EMPTY_STRING) or EMPTY_STRING}', f'Command: {getattr(row, "commandText", EMPTY_STRING)}', '-' * 72])
        text = '\n'.join(lines)
        print(text, file=sys.stderr, flush=True)
        if self.debugger is not None:
            try: self.debugger.emit(text, self.debugger.exceptionPath)
            except Exception:
                recordException('start.py:21176', sys.exc_info()[1])
                pass
        return True

    def registerDefaultPhases(self):
        for key, callbackName, label, group in self.PHASE_MANIFEST:
            callback = getattr(self, str(callbackName), None)
            if not callable(callback):
                raise AttributeError(f'StartLifecycleController missing phase callback: {callbackName}')
            self.registerPhase(key, callback, label=label, group=group)

    def runPhaseGroup(self, group: str = 'startup'):
        entries = self.phaseEntries(group)
        if not bool(getattr(self, 'quietLifecycleTrace', False)):
            print(f'[TRACE:start-lifecycle] phase-group {group} count={len(entries)}', file=sys.stderr, flush=True)
        for entry in entries:
            if self.stopRequested:
                if not bool(getattr(self, 'quietLifecycleTrace', False)):
                    print(f'[TRACE:start-lifecycle] phase-group {group} stopped before {getattr(entry, "key", entry)} exit={self.exitCode}', file=sys.stderr, flush=True)
                break
            if isinstance(entry, Phase):
                if not bool(getattr(self, 'quietLifecycleTrace', False)):
                    print(f'[TRACE:start-lifecycle] phase-start id={entry.phaseId} key={entry.key} startup={entry.startup}', file=sys.stderr, flush=True)
                started = time.monotonic()
                try:
                    entry.start(lifecycle=self)
                    self.notePhaseComplete(entry, getattr(entry, 'result', None))
                    elapsed = max(0.0, time.monotonic() - started)
                    if not bool(getattr(self, 'quietLifecycleTrace', False)):
                        print(f'[TRACE:start-lifecycle] phase-complete id={entry.phaseId} key={entry.key} status={entry.status} elapsed={elapsed:.3f}s', file=sys.stderr, flush=True)
                except Exception as error:
                    recordException('start.py:21202', sys.exc_info()[1])
                    entry.exception(error)
                    self.notePhaseException(entry, error)
                    if not bool(getattr(self, 'quietLifecycleTrace', False)):
                        print(f'[TRACE:start-lifecycle] phase-exception id={entry.phaseId} key={entry.key} error={type(error).__name__}: {error}', file=sys.stderr, flush=True)
                    raise
            elif callable(entry):
                entry()
        self.superviseProcesses()
        return int(self.exitCode)

    def bootstrapRuntimePathsPhase(self):
        os.chdir(str(BASE_DIR))
        if str(BASE_DIR) not in sys.path:
            sys.path.insert(0, str(BASE_DIR))
        os.environ.setdefault('TRIO_BASE_DIR', str(BASE_DIR))
        return True

    def _finishShortCircuit(self, result) -> bool:
        if result is not None:
            self.exitCode = int(result)
            self.stopRequested = True
            self.shortCircuitComplete = True
            return True
        return False

    def workerShortCircuitPhase(self):
        if fontWorkerRequested(self.argv):
            return self._finishShortCircuit(runTerminalFontWorker(self.argv))
        if startupToolsWorkerRequested(self.argv):
            return self._finishShortCircuit(runStartupToolsWorker(self.argv))
        if dependencyWorkerRequested(self.argv):
            return self._finishShortCircuit(runDependencyWorker(self.argv))
        if modelCatalogWorkerRequested(self.argv):
            return self._finishShortCircuit(runModelCatalogWorker(self.argv))
        if azureDeploymentsRequested(self.argv):
            return self._finishShortCircuit(runAzureDeploymentsList(self.argv))
        if chatTestWorkerRequested(self.argv):
            return self._finishShortCircuit(runChatTestWorker(self.argv))
        return True

