    def installMissingDependenciesPhase(self):
        debugger_safe = bool(debugEnabled(self.argv) or scanDisabled(self.argv) or offscreenRequested(self.argv) or cliHasAnyFlag(self.argv, CLEAN_FLAGS))
        if offscreenRequested(self.argv):
            print('[TRACE:deps-worker] offscreen mode: checking critical dependencies before child launch; optional probes still stay out of the smoke path.', file=sys.stderr, flush=True)
        if not debugger_safe:
            try:
                registry_args = list(getattr(self, 'childArgv', []) or []) or list(getattr(self, 'argv', []) or [])
                registry = StartDependencyRegistry(registry_args)
                critical_imports = registry.launcherCriticalImportNames()
                missing_entries = list(registry.missingPythonDependencyEntries())
                critical_missing = [entry for entry in missing_entries if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() in critical_imports]
                install_optional = str(os.environ.get('TRIO_INSTALL_OPTIONAL_DEPS', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'}
                missing_system = registry.missingLinuxSystemRequirements() if registry.isLinux() else []
                if not critical_missing and not missing_system and not install_optional:
                    optional_missing = [str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() for entry in missing_entries if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip()]
                    if optional_missing:
                        print(f'[TRACE:deps-worker] normal startup skipped dependency worker; only optional/lazy Python modules are missing: {", ".join(optional_missing)}', file=sys.stderr, flush=True)
                    else:
                        print('[TRACE:deps-worker] normal startup skipped dependency worker; dependency probes are clean.', file=sys.stderr, flush=True)
                    return True
            except Exception as error:
                recordException('start.py:21356', sys.exc_info()[1])
                print(f'[WARN:deps-worker] normal startup dependency preflight failed; falling back to dependency worker: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
        if debugger_safe:
            # Debugger-safe mode should not waste startup time on optional provider/font
            # packages, but it also must not launch trio.py when critical GUI/runtime
            # modules are missing.  Repair critical dependencies synchronously here,
            # after FlatLine exists but before the child process starts.
            registry_args = list(getattr(self, 'childArgv', []) or []) or list(getattr(self, 'argv', []) or [])
            child_python = str(getattr(self, 'childPythonPath', EMPTY_STRING) or sys.executable or EMPTY_STRING).strip()
            if child_python:
                # Child Python is launch metadata only. Do not make dependency
                # repair install into a different interpreter than start.py.
                os.environ['TRIO_CHILD_PYTHON'] = child_python
            registry = StartDependencyRegistry(registry_args)
            critical_imports = registry.launcherCriticalImportNames()
            missing_entries = []
            try:
                missing_entries = [
                    entry for entry in registry.missingPythonDependencyEntries()
                    if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() in critical_imports
                ]
            except Exception as error:
                recordException('start.py:21376', sys.exc_info()[1])
                print(f'[WARN:deps-worker] critical dependency probe failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
            if not missing_entries:
                print('[TRACE:deps-worker] debugger-safe mode: no critical dependency repair needed before child launch.', file=sys.stderr, flush=True)
                return True
            missing_names = ', '.join(str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING) for entry in missing_entries)
            print(f'[TRACE:deps-worker] debugger-safe mode: repairing critical dependencies before child launch: {missing_names}', file=sys.stderr, flush=True)
            # Critical GUI/runtime dependencies cannot be repaired asynchronously.
            # If offscreen mode launches trio.py while PySide6 is still missing,
            # the child dies immediately and the parent waits for a window that
            # can never exist.  Wait for the critical-only worker before launch.
            self.runDependencyWorkerPhase(waitForCompletion=True, reason='critical-missing-before-child')
            try:
                registry_after = StartDependencyRegistry(registry_args)
                remaining_entries = [
                    entry for entry in registry_after.missingPythonDependencyEntries()
                    if str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING).strip() in critical_imports
                ]
            except Exception as verify_error:
                recordException('start.py:critical-dependency-recheck', sys.exc_info()[1], handled=False)
                remaining_entries = [{'import_name': 'critical dependency recheck failed', 'error': f'{type(verify_error).__name__}: {verify_error}'}]
            if remaining_entries:
                remaining_names = ', '.join(str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING) for entry in remaining_entries)
                message = f'Critical dependencies are still missing after repair attempt: {remaining_names}'
                print(f'[WARN:deps-worker] {message}', file=sys.stderr, flush=True)
                recordException('start.py:critical-dependencies-still-missing', RuntimeError(message), handled=False)
                self.exitCode = 1
                self.stopRequested = True
                return False
            return True
        return self.runDependencyWorkerPhase(waitForCompletion=True, reason='normal-startup')


    def startupScanGatePhase(self):
        if debugEnabled(self.argv) and str(os.environ.get('TRIO_STARTUP_SCAN_IN_DEBUG', EMPTY_STRING) or EMPTY_STRING).strip().lower() not in {'1','true','yes','y','on'}:
            print('[TRACE:pyright] debugger-safe mode: startup scan gate skipped unless TRIO_STARTUP_SCAN_IN_DEBUG=1.', file=sys.stderr, flush=True)
            return True
        if scanDisabled(self.argv):
            ok = bool(runStartupPyrightGate(self.argv, None))
        else:
            ok = bool(runStartupPyrightGate(self.argv, resolvedChildPath(getattr(self, 'childArgv', self.argv), forceHeadlessGenerate=True)))
        if not ok:
            self.exitCode = 1
            self.stopRequested = True
        return ok

    def runDependencyWorkerPhase(self, waitForCompletion: bool | None = None, reason: str = EMPTY_STRING):
        timeout_text = str(os.environ.get('TRIO_DEPENDENCY_WORKER_TIMEOUT', EMPTY_STRING) or EMPTY_STRING).strip()
        timeout_seconds = int(timeout_text) if timeout_text.isdigit() else 900
        env = os.environ.copy()
        env['TRIO_DEPENDENCY_WORKER'] = '1'
        if str(reason or EMPTY_STRING).strip() == 'critical-missing-before-child':
            env['TRIO_CRITICAL_PYTHON_DEPS_ONLY'] = '1'
        worker_arg_source = list(getattr(self, 'childArgv', []) or []) or list(getattr(self, 'argv', []) or [])
        child_python = str(getattr(self, 'childPythonPath', EMPTY_STRING) or sys.executable or EMPTY_STRING).strip()
        if child_python:
            # Child Python is launch metadata only. The dependency worker itself
            # runs through sys.executable, so its pip target remains the launcher
            # interpreter unless TRIO_DEPENDENCY_TARGET_PYTHON was set by the user.
            env['TRIO_CHILD_PYTHON'] = child_python
        env['TRIO_DEPENDENCY_WORKER_ARGS_JSON'] = json.dumps(worker_arg_source)
        env.setdefault('PYTHONUNBUFFERED', '1')
        command = [str(sys.executable or 'python'), str(Path(__file__).resolve()), '--dependency-worker']
        process = StartProcess(command, name='DependencyInstallWorker', cwd=str(BASE_DIR), env=env, ttlSeconds=float(timeout_seconds or 900))
        print(f'[TRACE:deps-worker] launching dependency worker process timeout={timeout_seconds}s reason={reason or "dependency-repair"}', file=sys.stderr, flush=True)
        self.startExistingProcessPhase(process)
        print(f"[TRACE:deps-worker] worker started pid={int(getattr(process, 'pid', 0) or 0)}", file=sys.stderr, flush=True)
        debugger_safe = bool(debugEnabled(self.argv) or scanDisabled(self.argv) or offscreenRequested(self.argv) or cliHasAnyFlag(self.argv, CLEAN_FLAGS))
        should_wait = (not debugger_safe) if waitForCompletion is None else bool(waitForCompletion)
        if debugger_safe and not should_wait:
            print('[TRACE:deps-worker] debugger-safe async mode: dependency worker is lifecycle-owned; parent will not block D/heartbeat on pip/winget.', file=sys.stderr, flush=True)
            return True
        wait_start = time.monotonic()
        deadline = wait_start + max(1.0, float(timeout_seconds or 900))
        next_wait_trace = wait_start + 1.0
        print(f'[TRACE:deps-worker] parent watchdog armed timeout={timeout_seconds}s deadline={round(deadline, 3)}', file=sys.stderr, flush=True)
        code = None
        raw_proc = getattr(process, 'proc', None)
        pid_value = int(getattr(process, 'pid', 0) or getattr(raw_proc, 'pid', 0) or 0)
        while True:
            now_value = time.monotonic()
            if os.name != 'nt' and pid_value:
                try:
                    waited_pid, status_value = os.waitpid(pid_value, os.WNOHANG)
                    if waited_pid == pid_value:
                        if os.WIFEXITED(status_value):
                            code = os.WEXITSTATUS(status_value)
                        elif os.WIFSIGNALED(status_value):
                            code = 128 + os.WTERMSIG(status_value)
                        else:
                            code = 1
                        process._completeWithReturnCode(code)
                        break
                except ChildProcessError:
                    recordException('start.py:21445', sys.exc_info()[1])
                    code = int(getattr(process, 'returnCode', 0) or getattr(raw_proc, 'returncode', 0) or 0)
                    break
                except Exception as poll_error:
                    recordException('start.py:21448', sys.exc_info()[1])
                    print(f'[WARN:deps-worker] nonblocking waitpid failed: {type(poll_error).__name__}: {poll_error}', file=sys.stderr, flush=True)
            elif raw_proc is not None:
                try:
                    code = raw_proc.poll()
                    if code is not None:
                        process._completeWithReturnCode(code)
                        break
                except Exception as poll_error:
                    recordException('start.py:21456', sys.exc_info()[1])
                    print(f'[WARN:deps-worker] nonblocking poll failed: {type(poll_error).__name__}: {poll_error}', file=sys.stderr, flush=True)
            else:
                code = None
                break
            if now_value >= next_wait_trace:
                print(f'[TRACE:deps-worker] waiting elapsed={round(now_value - wait_start, 1)}s timeout={timeout_seconds}s', file=sys.stderr, flush=True)
                next_wait_trace = now_value + 1.0
            if now_value >= deadline:
                reason = f'dependency worker timeout after {timeout_seconds}s'
                print(f'[WARN:deps-worker] {reason}', file=sys.stderr, flush=True)
                process.kill(reason=reason)
                code = int(getattr(process, 'returnCode', 1) or 1)
                break
            time.sleep(0.1)
        if code not in (0, None):
            print(f'[WARN:deps-worker] dependency worker exited rc={code}; startup will continue to verification so FlatLine can report the real missing modules.', file=sys.stderr, flush=True)
        return True

    def verifyRequiredModulesPhase(self):
        if debugEnabled(self.argv) or scanDisabled(self.argv) or offscreenRequested(self.argv) or cliHasAnyFlag(self.argv, CLEAN_FLAGS):
            print('[TRACE:start-lifecycle] debugger-safe mode: skipping parent fatal required-module gate; child launch/debugger capture owns the real failure.', file=sys.stderr, flush=True)
            return True
        try:
            verifyLinuxSystemRequirementsOrDie(self.childArgv)
            verifyRequiredModulesOrDie(self.childArgv)
            return True
        except Exception as error:
            recordException('start.py:21483', sys.exc_info()[1])
            message = f'{type(error).__name__}: {error}'
            print(f'[WARN:start-lifecycle] required module verification failed after dependency worker launch: {message}', file=sys.stderr, flush=True)
            raise


