    def refreshModelCatalogPhase(self):
        # Load Azure deployments before the Qt child builds the Models menu.
        # This intentionally reuses the --chat Azure path instead of allowing
        # menu construction to become the first network/management probe.
        try:
            runStartupAzureDeploymentWarmup(warn=False)
        except Exception:
            recordException('start.py:model-catalog.startup-azure-direct', sys.exc_info()[1], handled=True)
        if debugEnabled(self.argv) or scanDisabled(self.argv) or offscreenRequested(self.argv) or cliHasAnyFlag(self.argv, CLEAN_FLAGS):
            print('[TRACE:model-catalog] debugger/offscreen mode: startup Azure warmup complete; skipping background full-catalog worker.', file=sys.stderr, flush=True)
            return True
        timeout_text = str(os.environ.get('TRIO_MODEL_CATALOG_WORKER_TIMEOUT', EMPTY_STRING) or EMPTY_STRING).strip()
        timeout_seconds = int(timeout_text) if timeout_text.isdigit() else 180
        env = os.environ.copy()
        env['TRIO_MODEL_CATALOG_WORKER'] = '1'
        env.setdefault('PYTHONUNBUFFERED', '1')
        command = [str(sys.executable or 'python'), str(Path(__file__).resolve()), '--model-catalog-worker']
        process = StartProcess(command, name='ModelCatalogRefreshWorker', cwd=str(BASE_DIR), env=env, ttlSeconds=float(timeout_seconds or 180))
        process.onException(lambda proc, error: recordException('start.py:model-catalog.process.exception', error, handled=False))
        process.onFault(lambda proc, fault: recordException('start.py:model-catalog.process.fault', RuntimeError(str(fault)), handled=False))
        process.onError(lambda proc, error: recordException('start.py:model-catalog.process.error', RuntimeError(str(error)), handled=True))
        print(f'[TRACE:model-catalog] launching refresh worker timeout={timeout_seconds}s', file=sys.stderr, flush=True)
        self.startExistingProcessPhase(process)
        print(f'[TRACE:model-catalog] worker started pid={int(getattr(process, "pid", 0) or 0)}', file=sys.stderr, flush=True)
        # Do not block the launcher/menu on the full provider catalog worker.
        # Azure deployment rows were already warmed synchronously above using the
        # chat-tested path; the worker can finish in the background without
        # poisoning FlatLine with a fake TimeoutExpired process row.
        return True

