    def fastHeadlessExecPhase(self):
        headlessRequested = cliHasAnyFlag(self.childArgv, HEADLESS_FLAGS)
        verboseTraceRequested = traceVerboseRequested(self.argv)
        if headlessRequested and not verboseTraceRequested and not debugEnabled(self.argv) and not offscreenRequested(self.argv):
            env = os.environ.copy()
            prepareTraceEnvironment(self.argv, env, debugWritesAllowed=debugEnabled(self.argv))
            headlessInfo = generateHeadlessChildScript(primaryChildSourcePath(), force=True)
            childPython = str(getattr(self, 'childPythonPath', EMPTY_STRING) or resolvePreferredChildPython(guiRequired=False)).strip() or str(sys.executable or EMPTY_STRING)
            self.childPythonPath = childPython
            cmd = [childPython, str(headlessInfo.get('path') or resolvedChildPath(self.childArgv, forceHeadlessGenerate=True)), *self.childArgv]
            process = StartProcess(cmd, name='FastHeadlessChild', env=env, ttlSeconds=300.0)
            self.startExistingProcessPhase(process)
            pid = int(getattr(process, 'pid', 0) or 0)
            print(f'[TRACE:fast-headless] worker pid={pid}', file=sys.stderr, flush=True)
            self.exitCode = int(process.wait(timeout=300.0) or 0)
            self.stopRequested = True
        return True

