BOX_DARK = '▓'
HEARTBEAT_FRAMES = ['⠁⠃⠇⡇⣇⣧⣷⣿⣾⣼⣸⢸⠸', '⠃⠇⡇⣇⣧⣷⣿⣾⣼⣸⢸⠸⠘', '⠇⡇⣇⣧⣷⣿⣾⣼⣸⢸⠸⠘⠁', '⡇⣇⣧⣷⣿⣾⣼⣸⢸⠸⠘⠁⠃', '⣇⣧⣷⣿⣾⣼⣸⢸⠸⠘⠁⠃⠇', '⣧⣷⣿⣾⣼⣸⢸⠸⠘⠁⠃⠇⡇', '⣷⣿⣾⣼⣸⢸⠸⠘⠁⠃⠇⡇⣇', '⣿⣾⣼⣸⢸⠸⠘⠁⠃⠇⡇⣇⣧']
DEPLOY_TOUCH_EXTENSIONS = {'.py', '.md', '.html', '.js', '.css', '.json', '.txt', '.bat', '.php', '.xml', '.yml', '.yaml'}
_LAST_CONSOLE_FRAME_LINES = 0



def consoleSupportsAnsi() -> bool:
    try:
        if not getattr(sys.stdout, 'isatty', lambda: False)():
            return False
    except Exception:
        recordException('start.py:21744', sys.exc_info()[1])
        return False
    if os.name != 'nt':
        return True
    try:
        import ctypes
        kernel32 = ctypes.windll.kernel32
        handle = kernel32.GetStdHandle(-11)
        if handle in (0, -1):
            return False
        mode = ctypes.c_uint()
        if kernel32.GetConsoleMode(handle, ctypes.byref(mode)) == 0:
            return False
        kernel32.SetConsoleMode(handle, mode.value | 0x0004)
        return True
    except Exception:
        recordException('start.py:21759', sys.exc_info()[1])
        return bool(os.environ.get('WT_SESSION') or os.environ.get('TERM_PROGRAM') or os.environ.get('ConEmuANSI') == 'ON')


def consoleSupportsUnicode() -> bool:
    try:
        encoding = str(getattr(sys.stdout, 'encoding', EMPTY_STRING) or EMPTY_STRING).lower()
    except Exception:
        recordException('start.py:21766', sys.exc_info()[1])
        encoding = EMPTY_STRING
    if 'utf' in encoding or 'unicode' in encoding:
        return True
    return os.name == 'nt' or bool(os.environ.get('WT_SESSION') or os.environ.get('TERM'))


def ansi(code: str) -> str:
    return f'\x1b[{code}m' if consoleSupportsAnsi() else EMPTY_STRING


def stripAnsi(text_value: str) -> str:
    return re.sub(r'\x1b\[[0-9;]*m', EMPTY_STRING, str(text_value or EMPTY_STRING))


def consoleCharWidth(char: str) -> int:
    value = str(char or EMPTY_STRING)[:1]
    if not value or value in ('\n', '\r'):
        return 0
    if unicodedata.combining(value):
        return 0
    category = unicodedata.category(value)
    if category in ('Cc', 'Cf'):
        return 0
    return 2 if unicodedata.east_asian_width(value) in ('F', 'W') else 1


def consoleVisibleWidth(text_value: str) -> int:
    plain = stripAnsi(text_value)
    return sum(consoleCharWidth(char) for char in plain)


def ansiAwareWrap(text_value: str, width: int) -> list[str]:
    value = str(text_value or EMPTY_STRING)
    limit = max(1, int(width or 1))
    if not value:
        return [EMPTY_STRING]
    tokens = re.findall(r'\x1b\[[0-9;]*m|.', value, flags=re.DOTALL)
    lines: list[str] = []
    current = EMPTY_STRING
    current_width = 0
    active_codes: list[str] = []
    reset_code = ansi('0') if consoleSupportsAnsi() else EMPTY_STRING

    def active_prefix() -> str:
        return ''.join(active_codes) if consoleSupportsAnsi() else EMPTY_STRING

    def flush_current() -> None:
        nonlocal current, current_width
        rendered = current
        if active_codes and reset_code and not rendered.endswith(reset_code):
            rendered += reset_code
        lines.append(rendered)
        current = active_prefix()
        current_width = 0

    for token in tokens:
        if re.fullmatch(r'\x1b\[[0-9;]*m', token):
            current += token
            if token == '\x1b[0m':
                active_codes = []
            elif consoleSupportsAnsi():
                active_codes.append(token)
            continue
        if token == '\n':
            flush_current()
            continue
        token_width = consoleCharWidth(token)
        if current_width > 0 and current_width + token_width > limit:
            flush_current()
        current += token
        current_width += token_width
    if current or not lines:
        if active_codes and reset_code and not current.endswith(reset_code):
            current += reset_code
        lines.append(current)
    return lines or [EMPTY_STRING]


class Border:
    def __init__(self, inner_width: int = 78, color_code: str = '90', padding: int = 1, use_unicode: bool | None = None):
        self.inner_width = max(20, int(inner_width or 20))
        self.color_code = str(color_code or '90')
        self.padding = max(0, int(padding or 0))
        self.use_unicode = consoleSupportsUnicode() if use_unicode is None else bool(use_unicode)
        glyphs = ('╔', '╗', '╚', '╝', '║', '║', '═', '╠', '╣') if self.use_unicode else ('+', '+', '+', '+', '|', '|', '-', '+', '+')
        (self.top_left, self.top_right, self.bottom_left, self.bottom_right, self.left, self.right, self.fill, self.mid_left, self.mid_right) = glyphs

    @classmethod
    def from_rows(cls, rows: list[str] | None = None, min_inner: int = 78, max_inner: int | None = None, color_code: str = '90', padding: int = 1):
        row_list = [str(row or EMPTY_STRING) for row in list(rows or [])]
        try:
            term_columns = int(shutil.get_terminal_size((100, 30)).columns or 100)
        except Exception:
            recordException('start.py:21860', sys.exc_info()[1])
            term_columns = 100
        available = max(40, term_columns - 4 - (padding * 2))
        cap = available if max_inner is None else max(40, min(int(max_inner or available), available))
        longest = max([int(min_inner or 0)] + [consoleVisibleWidth(row) for row in row_list])
        return cls(inner_width=max(20, min(cap, longest)), color_code=color_code, padding=padding)

    def _color(self, text_value: str) -> str:
        value = str(text_value or EMPTY_STRING)
        if consoleSupportsAnsi():
            return f"{ansi(self.color_code)}{value}{ansi('0')}"
        return value

    def _pad_right(self, text_value: str) -> str:
        value = str(text_value or EMPTY_STRING)
        return value + (' ' * max(0, self.inner_width - consoleVisibleWidth(value)))

    def top(self) -> str:
        return self._color(self.top_left + (self.fill * (self.inner_width + (self.padding * 2))) + self.top_right)

    def separator(self) -> str:
        return self._color(self.mid_left + (self.fill * (self.inner_width + (self.padding * 2))) + self.mid_right)

    def bottom(self) -> str:
        return self._color(self.bottom_left + (self.fill * (self.inner_width + (self.padding * 2))) + self.bottom_right)

    def line(self, text_value: str = EMPTY_STRING) -> str:
        padded = self._pad_right(text_value)
        left_pad = ' ' * self.padding
        right_pad = ' ' * self.padding
        if consoleSupportsAnsi():
            return f"{self._color(self.left)}{left_pad}{padded}{right_pad}{self._color(self.right)}"
        return f"{self.left}{left_pad}{stripAnsi(padded)}{right_pad}{self.right}"

    def render_text_lines(self, text_value: str) -> list[str]:
        rows: list[str] = []
        for raw_line in str(text_value or EMPTY_STRING).splitlines() or [EMPTY_STRING]:
            for wrapped in ansiAwareWrap(raw_line, self.inner_width):
                rows.append(self.line(wrapped))
        return rows or [self.line(EMPTY_STRING)]

    def frame(self, rows: list[str]) -> str:
        rendered = [self.top()]
        for row in list(rows or []):
            rendered.extend(self.render_text_lines(str(row or EMPTY_STRING)))
        rendered.append(self.bottom())
        return '\n'.join(rendered)


def wrapBorder(text_value: str, width: int | None = None, color_code: str = '90') -> str:
    plain_rows = str(text_value or EMPTY_STRING).splitlines() or [EMPTY_STRING]
    border = Border.from_rows(plain_rows, min_inner=int(width or 78), max_inner=int(width or 78), color_code=color_code)
    return border.frame(plain_rows)


def writeConsoleBorderLine(width: int, top: bool = True, color_code: str = '90') -> str:
    border = Border(inner_width=max(1, int(width or 1) - 2), color_code=color_code, padding=1)
    return border.top() if top else border.bottom()


def writeConsoleBodyLine(content: str, width: int, color_code: str = '90') -> str:
    border = Border(inner_width=max(1, int(width or 1)), color_code=color_code, padding=1)
    return border.line(str(content or EMPTY_STRING))


def writeConsoleFrame(title: str, rows: list[str], color_code: str = '90') -> str:
    values = [str(title or EMPTY_STRING)] + [str(row or EMPTY_STRING) for row in list(rows or [])]
    border = Border.from_rows(values, min_inner=max(40, max((consoleVisibleWidth(value) for value in values), default=78)), max_inner=max(40, max((consoleVisibleWidth(value) for value in values), default=78)), color_code=color_code, padding=1)
    frame = [border.top()]
    frame.extend(border.render_text_lines(str(title or EMPTY_STRING)))
    for row in list(rows or []):
        frame.extend(border.render_text_lines(str(row or EMPTY_STRING)))
    frame.append(border.bottom())
    return '\n'.join(frame)


def clearConsoleFrame(lines_count: int) -> None:
    if lines_count <= 0:
        return
    if consoleSupportsAnsi():
        for index in range(int(lines_count)):
            if index > 0:
                sys.stdout.write('\x1b[1A')
            sys.stdout.write('\r\x1b[2K')
        sys.stdout.flush()
    else:
        sys.stdout.write('\r')
        sys.stdout.flush()


def repaintConsoleFrame(frame_text: str) -> None:
    global _LAST_CONSOLE_FRAME_LINES
    lines = str(frame_text or EMPTY_STRING).splitlines() or [EMPTY_STRING]
    clearConsoleFrame(_LAST_CONSOLE_FRAME_LINES)
    sys.stdout.write('\n'.join(lines))
    sys.stdout.write('\n')
    sys.stdout.flush()
    _LAST_CONSOLE_FRAME_LINES = len(lines)


def buildDeployProgressTitleLine(label: str, width: int) -> str:
    return str(label or 'Deploying').ljust(width)[:width]


def buildDeployProgressValueLine(percent: float, width: int = 42) -> str:
    pct = max(0.0, min(100.0, float(percent or 0.0)))
    filled = int(round((pct / 100.0) * width))
    if consoleSupportsAnsi():
        parts = []
        for index in range(width):
            if index < filled:
                code = '92' if index < max(1, width // 3) else ('1;92' if index < max(2, (2 * width) // 3) else '1;92')
                parts.append(f"{ansi(code)}█{ansi('0')}")
            else:
                parts.append(' ')
        bar = ''.join(parts)
    else:
        bar = ('#' * filled) + (' ' * max(0, width - filled))
    return f'{bar} {pct:6.2f}%'


def buildDeployProgressShadowLine(width: int) -> str:
    if consoleSupportsAnsi():
        return f"{ansi('90')}  {'░' * max(0, width)}{ansi('0')}"
    return EMPTY_STRING


def renderConsoleBox(title: str, rows: list[str], color_code: str = '\x1b[90m') -> str:
    match = re.search(r'\x1b\[([0-9;]+)m', str(color_code or EMPTY_STRING))
    resolved = str(match.group(1) or '90') if match else '90'
    return writeConsoleFrame(title, rows, color_code=resolved)


def renderDeployProgressFrame(label: str, percent: float, width: int = 42) -> str:
    rows = [
        buildDeployProgressTitleLine(label, width + 8),
        buildDeployProgressValueLine(percent, width),
    ]
    frame = writeConsoleFrame(str(label or 'Deploying'), rows, color_code='90')
    shadow = buildDeployProgressShadowLine(width + 12)
    if shadow:
        frame += '\n' + shadow
    return frame


def renderDeployProgressBar(label: str, percent: float, width: int = 42) -> str:
    return renderDeployProgressFrame(label, percent, width=width)


def heartbeatMonitorFrames() -> list[str]:
    # Real FlatLine Braille heartbeat frames. These are Unicode Braille Pattern
    # cells, not ASCII punctuation placeholders. The bundled terminal font has
    # glyph coverage for these cells, so the debugger console gets the proper
    # neon Braille look when Unicode is available.
    if consoleSupportsUnicode():
        return [
            '⠁⠂⠄⡀⢀⠠⠐⠈  ⣿⣶⣤⣀⠈⠁⣀⣤⣶⣿',
            '⠂⠄⡀⢀⠠⠐⠈⠁  ⣶⣤⣀⠈⠁⣀⣤⣶⣿⣷',
            '⠄⡀⢀⠠⠐⠈⠁⠂  ⣤⣀⠈⠁⣀⣤⣶⣿⣷⣶',
            '⡀⢀⠠⠐⠈⠁⠂⠄  ⣀⠈⠁⣀⣤⣶⣿⣷⣶⣤',
            '⢀⠠⠐⠈⠁⠂⠄⡀  ⠈⠁⣀⣤⣶⣿⣷⣶⣤⣀',
            '⠠⠐⠈⠁⠂⠄⡀⢀  ⠁⣀⣤⣶⣿⣷⣶⣤⣀⠈',
            '⠐⠈⠁⠂⠄⡀⢀⠠  ⣀⣤⣶⣿⣷⣶⣤⣀⠈⠁',
            '⠈⠁⠂⠄⡀⢀⠠⠐  ⣤⣶⣿⣷⣶⣤⣀⠈⠁⣀',
        ]
    return [
        r'__/^^\____/^^\__',
        r'_/^^\____/^^\___',
        r'/^^\____/^^\____',
        r'^^\____/^^\_____',
        r'^\____/^^\______',
        r'\____/^^\_______',
        r'____/^^\_________',
        r'___/^^\____/^^\_',
    ]

def buildHeartbeatMonitorText(frame_index: int, candidate_script: str = EMPTY_STRING) -> str:
    frames = heartbeatMonitorFrames()
    frame = frames[int(frame_index or 0) % len(frames)]
    candidate_name = Path(candidate_script).name if str(candidate_script or EMPTY_STRING).strip() else 'none'
    if consoleSupportsAnsi():
        pulse = f"{ansi('1;92')}{frame}{ansi('0')}"
        title = f"{ansi('1;92')}FLATLINE Debugger v{DEBUGGER_VERSION}{ansi('0')}"
    else:
        pulse = frame
        title = f'FLATLINE Debugger v{DEBUGGER_VERSION}'
    return f'{title} {pulse} candidate={candidate_name} [R relaunch | Q quit]'


def deployMonitorHeartbeatLine(frame_index: int, candidate_script: str = EMPTY_STRING) -> str:
    return buildHeartbeatMonitorText(frame_index, candidate_script)


def writeHeartbeatMonitorLine(frame_index: int, candidate_script: str = EMPTY_STRING) -> None:
    global _LAST_CONSOLE_FRAME_LINES
    _LAST_CONSOLE_FRAME_LINES = 0
    line = buildHeartbeatMonitorText(frame_index, candidate_script)
    sys.stdout.write('\r' + (line if consoleSupportsAnsi() else stripAnsi(line)))
    sys.stdout.flush()

def deployMonitorRequested(argv=None) -> bool:
    return bool(readCliOption(argv, DEPLOY_MONITOR_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))

def deployOnceRequested(argv=None) -> bool:
    return bool(readCliOption(argv, DEPLOY_ONCE_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))

def autoDeployAllowed(argv=None) -> bool:
    """Return True only when implicit zip deploy was explicitly enabled.

    Explicit deploy commands (--deploy-monitor / --deploy-once) still work.
    This guard only controls the old surprise behavior where a stray *.zip in
    the app folder made start.py auto-enter deploy monitor mode.
    """
    if bool(readCliOption(argv, AUTO_DEPLOY_OFF_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present')):
        return False
    env_value = str(os.environ.get('TRIO_AUTO_DEPLOY', EMPTY_STRING) or EMPTY_STRING).strip().lower()
    if env_value in {'1', 'true', 'yes', 'on'}:
        return True
    return bool(readCliOption(argv, AUTO_DEPLOY_ON_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))

def mergeDirectoryContents(source_path: Path, destination_path: Path) -> None:
    source = Path(source_path)
    destination = Path(destination_path)
    destination.mkdir(parents=True, exist_ok=True)
    for item in list(source.iterdir()):
        dest = destination / item.name
        if item.is_dir():
            mergeDirectoryContents(item, dest)  # recursion-ok: directory tree merge
            shutil.rmtree(item, ignore_errors=True)
        else:
            dest.parent.mkdir(parents=True, exist_ok=True)
            File(item).copyTo(dest)
            try:
                item.unlink()
            except Exception:
                recordException('start.py:22083', sys.exc_info()[1])
                _traceSwallowedException('start.py:21504', sys.exc_info()[1])
                pass

def promoteSingleChildFolder(base_path: Path) -> bool:
    base = Path(base_path)
    if (base / 'start.py').exists():
        return False
    candidate_directories = [item for item in base.iterdir() if item.is_dir() and item.name not in {'.git', '.venv', 'venv', '__pycache__', 'debs', 'linux_runtime'}]
    if len(candidate_directories) != 1:
        return False
    directory = candidate_directories[0]
    print(f'[INFO] Promoting files from {directory}', flush=True)
    mergeDirectoryContents(directory, base)
    shutil.rmtree(directory, ignore_errors=True)
    return True

def flattenProjectWrappers(base_path: Path) -> bool:
    promoted = False
    if promoteSingleChildFolder(base_path):
        promoted = True
    if promoteSingleChildFolder(base_path):
        promoted = True
    return promoted

def touchExtractedProjectFiles(base_path: Path, touch_time: datetime.datetime) -> None:
    target_timestamp = touch_time.astimezone(datetime.timezone.utc).timestamp()
    for path in Path(base_path).rglob('*'):
        if path.is_file() and path.suffix.lower() in DEPLOY_TOUCH_EXTENSIONS:
            try:
                os.utime(path, (target_timestamp, target_timestamp))
            except Exception:
                recordException('start.py:22114', sys.exc_info()[1])
                _traceSwallowedException('start.py:21534', sys.exc_info()[1])
                pass


def safeZipMtimeUtc(zip_path: Path) -> datetime.datetime:
    try:
        return datetime.datetime.fromtimestamp(Path(zip_path).stat().st_mtime, tz=datetime.timezone.utc)
    except FileNotFoundError:
        recordException('start.py:22122', sys.exc_info()[1])
        return datetime.datetime.fromtimestamp(0, tz=datetime.timezone.utc)
    except Exception:
        recordException('start.py:22124', sys.exc_info()[1])
        return datetime.datetime.now(datetime.timezone.utc)


def _normalizeZipMemberName(name: str) -> str:
    return str(name or EMPTY_STRING).replace('\\', '/').lstrip('/')


def _zipMemberBasename(name: str) -> str:
    return Path(_normalizeZipMemberName(name)).name.lower()


def zipLooksLikeDeployment(zip_path: Path) -> bool:
    """Return True only for complete TrioDesktop deployment bundles.

    Deploy monitor runs from user-controlled folders, often the Desktop. It must
    not blindly unpack unrelated tool/vendor archives such as ruff-main.zip, and
    it must not crash when an external auto-deploy script deletes a zip between
    glob() and open().
    """
    target = Path(zip_path)
    if not target.exists():
        print(f'[WARN:deploy] Zip disappeared before inspection; skipping {target.name}', flush=True)
        return False
    try:
        with zipfile.ZipFile(target, 'r') as archive:
            names = [_normalizeZipMemberName(info.filename) for info in archive.infolist() if not info.is_dir()]
    except FileNotFoundError:
        recordException('start.py:22151', sys.exc_info()[1])
        print(f'[WARN:deploy] Zip disappeared before inspection; skipping {target.name}', flush=True)
        return False
    except zipfile.BadZipFile as error:
        recordException('start.py:22154', sys.exc_info()[1])
        print(f'[WARN:deploy] Bad zip skipped {target.name}: {error}', flush=True)
        return False
    except Exception as error:
        recordException('start.py:22157', sys.exc_info()[1])
        print(f'[WARN:deploy] Could not inspect zip {target.name}: {type(error).__name__}: {error}', flush=True)
        return False
    basenames = {_zipMemberBasename(name) for name in names}
    if 'start.py' not in basenames:
        print(f'[INFO] Skipping non-TrioDesktop zip {target.name}: no start.py deployment marker.', flush=True)
        return False
    if not ({'trio.py', 'data.py'} & basenames):
        print(f'[INFO] Skipping non-TrioDesktop zip {target.name}: missing trio.py/data.py marker.', flush=True)
        return False
    return True

_FAILED_DEPLOY_ZIP_KEYS: set[str] = set()


def deployTrace(message: str) -> None:
    print(f'[TRACE:deploy] {message}', file=sys.stderr, flush=True)


def deployWarn(message: str) -> None:
    print(f'[WARN:deploy] {message}', file=sys.stderr, flush=True)


def deployZipKey(zip_path: Path) -> str:
    try:
        stat_row = Path(zip_path).stat()
        return f'{Path(zip_path).resolve()}|{int(stat_row.st_mtime_ns)}|{int(stat_row.st_size)}'
    except Exception:
        recordException('start.py:deploy-zip-key', sys.exc_info()[1], handled=True)
        return str(Path(zip_path).resolve())


def deployZipFailedBefore(zip_path: Path) -> bool:
    return deployZipKey(Path(zip_path)) in _FAILED_DEPLOY_ZIP_KEYS


def markDeployZipFailed(zip_path: Path, reason: str) -> None:
    key = deployZipKey(Path(zip_path))
    _FAILED_DEPLOY_ZIP_KEYS.add(key)
    deployWarn(f'zip marked failed for this launcher session; will not retry until file changes zip={Path(zip_path).name} reason={reason}')
    try:
        RuntimeLog.log(f'[{datetime.datetime.now().isoformat(timespec="seconds")}] [deploy-failed-zip] {key} {reason}\n', flush=True, channel='deploy')
    except Exception:
        recordException('start.py:mark-deploy-zip-failed-log', sys.exc_info()[1], handled=True)


def _deploySafeDestinationForMember(destination: Path, member_name: str) -> Path:
    normalized = _normalizeZipMemberName(member_name)
    if not normalized or normalized.endswith('/'):
        return Path(destination)
    target = (Path(destination) / normalized).resolve()
    root = Path(destination).resolve()
    try:
        target.relative_to(root)
    except ValueError:
        raise RuntimeError(f'unsafe zip member path outside deployment root: {member_name!r}')
    return target


def _deployFileMd5(path: Path) -> str:
    try:
        digest = hashlib.md5()
        with File(path).open('rb') as handle:
            for chunk in iter(lambda: handle.read(1024 * 1024), b''):
                digest.update(chunk)
        return digest.hexdigest()
    except Exception:
        recordException('start.py:deploy-file-md5', sys.exc_info()[1], handled=True)
        return EMPTY_STRING


def _deployZipMemberMd5(archive: zipfile.ZipFile, info: zipfile.ZipInfo) -> str:
    try:
        digest = hashlib.md5()
        with archive.open(info, 'r') as handle:  # file-io-ok: zip archive member read wrapper
            for chunk in iter(lambda: handle.read(1024 * 1024), b''):
                digest.update(chunk)
        return digest.hexdigest()
    except Exception:
        recordException('start.py:deploy-zip-member-md5', sys.exc_info()[1], handled=True)
        return EMPTY_STRING


def _deployMemberIdentical(archive: zipfile.ZipFile, info: zipfile.ZipInfo, target: Path) -> bool:
    try:
        if not target.exists() or not target.is_file():
            return False
        if int(target.stat().st_size) != int(getattr(info, 'file_size', -1)):
            return False
        same = _deployZipMemberMd5(archive, info) == _deployFileMd5(target)
        if same:
            deployTrace(f'skip identical existing member target={target}')
        return bool(same)
    except Exception:
        recordException('start.py:deploy-member-identical', sys.exc_info()[1], handled=True)
        return False


def _extractZipMemberAtomic(archive: zipfile.ZipFile, info: zipfile.ZipInfo, destination: Path) -> Path:
    target = _deploySafeDestinationForMember(destination, info.filename)
    if info.is_dir() or str(info.filename or '').endswith('/'):
        target.mkdir(parents=True, exist_ok=True)
        return target
    target.parent.mkdir(parents=True, exist_ok=True)
    if _deployMemberIdentical(archive, info, target):
        return target
    temp_path = target.with_name(target.name + f'.deploytmp-{os.getpid()}')
    try:
        with archive.open(info, 'r') as src, File(temp_path).open('wb') as dst:  # file-io-ok: zip archive member read wrapper
            shutil.copyfileobj(src, dst, 1024 * 1024)
        os.replace(temp_path, target)
        return target
    except Exception:
        try:
            if temp_path.exists():
                temp_path.unlink()
        except Exception:
            recordException('start.py:deploy-clean-temp-member', sys.exc_info()[1], handled=True)
        raise


def _deployOSErrorCode(error: BaseException) -> tuple[int, int]:
    return (int(getattr(error, 'errno', 0) or 0), int(getattr(error, 'winerror', 0) or 0))


def deployDestinationLooksPermissionBlocked(path: Path) -> bool:
    target = Path(path)
    try:
        probe = target if target.exists() else target.parent
        if target.exists() and not bool(int(target.stat().st_mode) & 0o200):
            deployTrace(f'permission probe: owner write bit missing target={target}')
            return True
        if not os.access(str(probe), os.W_OK):
            deployTrace(f'permission probe: os.access write false path={probe}')
            return True
    except Exception as error:
        recordException('start.py:deploy-permission-probe', sys.exc_info()[1], handled=True)
        deployWarn(f'permission probe failed path={target}: {type(error).__name__}: {error}')
    return False


def deployExtractionFailureLooksPermission(error: BaseException, target: Path) -> bool:
    errno_value, winerror_value = _deployOSErrorCode(error)
    if deployDestinationLooksPermissionBlocked(target):
        return True
    if isinstance(error, PermissionError) and winerror_value not in {32, 33}:
        return True
    if errno_value in {getattr(errno, 'EACCES', 13), getattr(errno, 'EPERM', 1)} and winerror_value not in {32, 33}:
        return True
    return False


def resetDeployPermissions(path: Path) -> bool:
    target = Path(path)
    existing = target if target.exists() else target.parent
    deployWarn(f'permission repair requested target={target} existing={existing}')
    ok = False
    try:
        if existing.exists():
            import stat as _stat
            os.chmod(existing, int(existing.stat().st_mode) | _stat.S_IWRITE | _stat.S_IREAD | 0o200)
            ok = True
            deployTrace(f'chmod write/modify attempted path={existing}')
    except Exception as error:
        recordException('start.py:deploy-chmod-permissions', sys.exc_info()[1], handled=True)
        deployWarn(f'chmod permission repair failed path={existing}: {type(error).__name__}: {error}')
    if os.name == 'nt':
        for command in (['attrib', '-R', str(existing)], ['icacls', str(existing), '/grant', f'{getpass.getuser()}:M', '/C']):
            try:
                deployTrace(f'permission repair command={_launcherCommandText(command)}')
                completed = launcherRunCommand(command, capture_output=True, text=True, timeout=20, check=False)
                output = (str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING) + str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)).strip()
                deployTrace(f'permission repair exit={getattr(completed, "returncode", None)} output={output[:500]}')
                ok = ok or int(getattr(completed, 'returncode', 1) or 0) == 0
            except Exception as error:
                recordException('start.py:deploy-windows-permission-command', sys.exc_info()[1], handled=True)
                deployWarn(f'permission command failed command={command[0]} path={existing}: {type(error).__name__}: {error}')
    after = deployDestinationLooksPermissionBlocked(target)
    deployTrace(f'permission repair verify path={target} writable={not after}')
    return bool(ok and not after)


class DeployLockProcess:
    def __init__(self, pid: int, name: str = EMPTY_STRING, commandLine: str = EMPTY_STRING, source: str = EMPTY_STRING):
        self.pid = int(pid or 0)
        self.name = str(name or EMPTY_STRING)
        self.commandLine = str(commandLine or EMPTY_STRING)
        self.source = str(source or EMPTY_STRING)


def windowsRestartManagerLockingProcesses(path: Path) -> list[DeployLockProcess]:
    if os.name != 'nt':
        return []
    try:
        from ctypes import wintypes
        rstrtmgr = ctypes.WinDLL('rstrtmgr')
        error_more_data = 234
        class RM_UNIQUE_PROCESS(ctypes.Structure):
            _fields_ = [('dwProcessId', wintypes.DWORD), ('ProcessStartTime', wintypes.FILETIME)]
        class RM_PROCESS_INFO(ctypes.Structure):
            _fields_ = [('Process', RM_UNIQUE_PROCESS), ('strAppName', wintypes.WCHAR * 256), ('strServiceShortName', wintypes.WCHAR * 64), ('ApplicationType', wintypes.DWORD), ('AppStatus', wintypes.ULONG), ('TSSessionId', wintypes.DWORD), ('bRestartable', wintypes.BOOL)]
        session = wintypes.DWORD(0)
        key = ctypes.create_unicode_buffer(64)
        result = rstrtmgr.RmStartSession(ctypes.byref(session), 0, key)
        if result != 0:
            deployWarn(f'Restart Manager RmStartSession failed code={result} file={path}')
            return []
        try:
            arr = (wintypes.LPCWSTR * 1)(str(Path(path).resolve()))
            result = rstrtmgr.RmRegisterResources(session, 1, arr, 0, None, 0, None)
            if result != 0:
                deployWarn(f'Restart Manager RmRegisterResources failed code={result} file={path}')
                return []
            needed = wintypes.DWORD(0)
            count = wintypes.DWORD(0)
            reboot = wintypes.DWORD(0)
            result = rstrtmgr.RmGetList(session, ctypes.byref(needed), ctypes.byref(count), None, ctypes.byref(reboot))
            if result == error_more_data and needed.value:
                count = wintypes.DWORD(needed.value)
                info = (RM_PROCESS_INFO * needed.value)()
                result = rstrtmgr.RmGetList(session, ctypes.byref(needed), ctypes.byref(count), info, ctypes.byref(reboot))
                if result == 0:
                    rows = [DeployLockProcess(pid=int(info[i].Process.dwProcessId or 0), name=str(info[i].strAppName or EMPTY_STRING), source='restart-manager') for i in range(int(count.value)) if int(info[i].Process.dwProcessId or 0) > 0]
                    deployTrace(f'Restart Manager locking pids file={path} pids={[row.pid for row in rows]}')
                    return rows
            deployWarn(f'Restart Manager found no lock owners result={result} file={path}')
            return []
        finally:
            try:
                rstrtmgr.RmEndSession(session)
            except Exception:
                recordException('start.py:deploy-rm-end-session', sys.exc_info()[1], handled=True)
    except Exception as error:
        recordException('start.py:deploy-restart-manager-locking-processes', sys.exc_info()[1], handled=True)
        deployWarn(f'Restart Manager lock discovery failed file={path}: {type(error).__name__}: {error}')
        return []


def linuxLockingProcesses(path: Path) -> list[DeployLockProcess]:
    if os.name == 'nt':
        return []
    rows: list[DeployLockProcess] = []
    commands: list[list[str]] = []
    if shutil.which('fuser'):
        commands.append(['fuser', str(path)])
    if shutil.which('lsof'):
        commands.append(['lsof', '-t', '--', str(path)])
    for command in commands:
        try:
            deployTrace(f'Linux lock probe command={_launcherCommandText(command)}')
            completed = launcherRunCommand(command, capture_output=True, text=True, timeout=10, check=False)
            output = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING) + '\n' + str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
            for token in re.findall(r'\b\d+\b', output):
                pid = int(token)
                if pid > 0 and pid != os.getpid() and all(row.pid != pid for row in rows):
                    rows.append(DeployLockProcess(pid=pid, source=Path(command[0]).name))
        except Exception as error:
            recordException('start.py:deploy-linux-lock-probe', sys.exc_info()[1], handled=True)
            deployWarn(f'Linux lock probe failed command={command[0]} file={path}: {type(error).__name__}: {error}')
    if not rows:
        deployWarn(f'Linux lock discovery found no pids file={path}; install/use fuser or lsof for better diagnostics.')
    else:
        deployTrace(f'Linux locking pids file={path} pids={[row.pid for row in rows]}')
    return rows


def discoverLockingProcesses(path: Path) -> list[DeployLockProcess]:
    rows = windowsRestartManagerLockingProcesses(path) if os.name == 'nt' else linuxLockingProcesses(path)
    unique: list[DeployLockProcess] = []
    seen: set[int] = set()
    for row in rows:
        pid = int(row.pid or 0)
        if pid > 0 and pid not in seen and pid != os.getpid():
            seen.add(pid)
            unique.append(row)
    if not unique:
        deployWarn(f'no locking process PID discovered file={path}')
    return unique


def deployProcessStillAlive(pid: int) -> bool:
    if int(pid or 0) <= 0:
        return False
    if os.name == 'nt':
        try:
            c = launcherRunCommand(['tasklist', '/FI', f'PID eq {int(pid)}', '/FO', 'CSV', '/NH'], capture_output=True, text=True, timeout=10, check=False)
            return str(int(pid)) in str(getattr(c, 'stdout', EMPTY_STRING) or EMPTY_STRING)
        except Exception:
            recordException('start.py:deploy-process-alive-tasklist', sys.exc_info()[1], handled=True)
            return True
    try:
        os.kill(int(pid), 0)
        return True
    except ProcessLookupError:
        return False
    except PermissionError:
        return True
    except Exception:
        recordException('start.py:deploy-process-alive-posix', sys.exc_info()[1], handled=True)
        return True


def killDeployLockingProcesses(path: Path) -> bool:
    rows = discoverLockingProcesses(path)
    if not rows:
        return False
    killed = False
    for row in rows:
        pid = int(row.pid or 0)
        deployWarn(f'locked file owner found file={path} pid={pid} name={row.name} source={row.source} command={row.commandLine}')
        ok = Tasks.taskkill(pid, tree=(os.name == 'nt'), force=True, reason=f'auto-deploy locked file {path}', timeout=30.0, trace_prefix='deploy-lock-taskkill')
        alive = deployProcessStillAlive(pid)
        deployTrace(f'locked owner kill verify pid={pid} killed_ok={ok} still_alive={alive}')
        if ok and not alive:
            killed = True
        elif alive:
            deployWarn(f'locked owner could not be killed or is still alive pid={pid}; may require admin/system rights')
    if killed:
        time.sleep(0.75)
    return killed


def repairDeployExtractionFailure(zip_path: Path, destination: Path, info: zipfile.ZipInfo | None, target: Path | None, error: BaseException, attempt: int) -> str:
    member = str(getattr(info, 'filename', EMPTY_STRING) or '<unknown>')
    failed_target = Path(target or destination)
    errno_value, winerror_value = _deployOSErrorCode(error)
    deployWarn(f'extraction failed attempt={attempt} zip={Path(zip_path).name} member={member} target={failed_target} error={type(error).__name__}: {error} errno={errno_value} winerror={winerror_value}')
    if attempt >= 2:
        deployWarn(f'extraction already retried; giving up zip={Path(zip_path).name} member={member}')
        return 'give-up'
    if deployExtractionFailureLooksPermission(error, failed_target):
        deployWarn(f'extraction failure classified as permissions target={failed_target}')
        return 'retry' if resetDeployPermissions(failed_target) else 'give-up'
    deployWarn(f'extraction failure classified as locked/in-use target={failed_target}; attempting lock-owner discovery')
    return 'retry' if killDeployLockingProcesses(failed_target) else 'give-up'

def extractZipIntoDirectory(zip_path: Path, destination_path: Path, *, attempt: int = 1) -> bool:
    zip_target = Path(zip_path)
    destination = Path(destination_path)
    if not zip_target.exists():
        print(f'[WARN:deploy] Zip disappeared before extraction; skipping {zip_target.name}', flush=True)
        return False
    if deployZipFailedBefore(zip_target):
        deployWarn(f'previous deployment failure remembered; skipping unchanged zip={zip_target.name}')
        return False
    failed_info: zipfile.ZipInfo | None = None
    failed_target: Path | None = None
    try:
        with zipfile.ZipFile(zip_target, 'r') as archive:
            infos = [info for info in archive.infolist() if not info.is_dir()]
            total = max(1, len(infos))
            for index, info in enumerate(infos, start=1):
                failed_info = info
                failed_target = _deploySafeDestinationForMember(destination, info.filename)
                _extractZipMemberAtomic(archive, info, destination)
                percent = (index / total) * 100.0
                repaintConsoleFrame(renderDeployProgressBar(f'Extracting {zip_target.name}', percent))
            clearConsoleFrame(_LAST_CONSOLE_FRAME_LINES)
            sys.stdout.write('\r')
            sys.stdout.flush()
            return True
    except FileNotFoundError:
        recordException('start.py:deploy-extract-zip-disappeared', sys.exc_info()[1])
        print(f'[WARN:deploy] Zip disappeared during extraction; skipping {zip_target.name}', flush=True)
        return False
    except zipfile.BadZipFile as error:
        recordException('start.py:deploy-bad-zip', sys.exc_info()[1])
        print(f'[WARN:deploy] Bad zip skipped {zip_target.name}: {error}', flush=True)
        markDeployZipFailed(zip_target, f'bad zip: {error}')
        return False
    except Exception as error:
        recordException('start.py:deploy-extraction-failure', sys.exc_info()[1])
        clearConsoleFrame(_LAST_CONSOLE_FRAME_LINES)
        action = repairDeployExtractionFailure(zip_target, destination, failed_info, failed_target, error, attempt)
        if action == 'retry' and attempt < 2:
            deployWarn(f'retrying extraction once after repair zip={zip_target.name}')
            return extractZipIntoDirectory(zip_target, destination, attempt=attempt + 1)
        markDeployZipFailed(zip_target, f'{type(error).__name__}: {error}')
        deployWarn(f'auto-deploy failed gracefully; keeping current working start.py active zip={zip_target.name}')
        return False

def expandZipsInDirectory(root_path: Path) -> datetime.datetime | None:
    root = Path(root_path)
    try:
        raw_zip_files = [path for path in root.glob('*.zip') if path.exists()]
    except Exception as error:
        recordException('start.py:22201', sys.exc_info()[1])
        print(f'[WARN:deploy] Could not list zip files in {root}: {type(error).__name__}: {error}', flush=True)
        return None
    zip_files = sorted(raw_zip_files, key=lambda path: safeZipMtimeUtc(path).timestamp())
    if not zip_files:
        return None
    newest_deployment = None
    extracted_any = False
    for zip_path in zip_files:
        if deployZipFailedBefore(zip_path):
            deployWarn(f'skipping failed unchanged zip={zip_path.name}')
            continue
        if not zipLooksLikeDeployment(zip_path):
            continue
        stamp = safeZipMtimeUtc(zip_path)
        if newest_deployment is None or stamp > newest_deployment:
            newest_deployment = stamp
        print(f'[INFO] Extracting {zip_path.name}', flush=True)
        extracted = extractZipIntoDirectory(zip_path, root)
        if not extracted:
            continue
        extracted_any = True
        touchExtractedProjectFiles(root, stamp)
        try:
            zip_path.unlink()
            print(f'[INFO] Deleted {zip_path.name}', flush=True)
        except FileNotFoundError:
            recordException('start.py:22224', sys.exc_info()[1])
            print(f'[WARN:deploy] Zip was already deleted after extraction: {zip_path.name}', flush=True)
        except Exception as error:
            recordException('start.py:22226', sys.exc_info()[1])
            print(f'[WARN:deploy] Could not delete zip {zip_path.name}: {type(error).__name__}: {error}', flush=True)
    if extracted_any:
        flattenProjectWrappers(root)
        return newest_deployment
    return None

def resolveLaunchScript(root_path: Path, deployment_floor_utc: datetime.datetime | None = None) -> str:
    root = Path(root_path)
    floor_ts = None
    if deployment_floor_utc is not None:
        try:
            floor_ts = deployment_floor_utc.astimezone(datetime.timezone.utc).timestamp() - 1.0
        except Exception:
            recordException('start.py:22238', sys.exc_info()[1])
            floor_ts = None

    def is_eligible(path: Path) -> bool:
        try:
            if floor_ts is None:
                return True
            return path.stat().st_mtime >= floor_ts
        except Exception:
            recordException('start.py:22246', sys.exc_info()[1])
            return False

    preferred_names = ('start.py', 'trio.py', 'main.py')
    for name in preferred_names:
        matches = [candidate for candidate in sorted(root.rglob(name), key=lambda candidate: str(candidate)) if is_eligible(candidate)]
        if matches:
            return str(matches[0].resolve())
    matches = [candidate for candidate in sorted(root.rglob('*.py'), key=lambda candidate: str(candidate)) if is_eligible(candidate)]
    return str(matches[0].resolve()) if matches else EMPTY_STRING


def getDefaultDeployScriptArgs(argv=None) -> list[str]:
    filtered = []
    for token in list(argv or []):
        low = str(token or EMPTY_STRING).strip().lower()
        if low in DEPLOY_MONITOR_FLAGS or low in DEPLOY_ONCE_FLAGS or low in AUTO_DEPLOY_OFF_FLAGS or low in AUTO_DEPLOY_ON_FLAGS:
            continue
        filtered.append(str(token or EMPTY_STRING))
    return filtered or ['--debug', '--trace-verbose']

def launchTargetScript(script_path: str, argv=None, manual: bool = False) -> bool:
    manualMode = bool(manual)
    target = str(script_path or EMPTY_STRING).strip()
    if not target or not Path(target).exists():
        print('[WARN] No Python script found to run.', flush=True)
        return False
    args = getDefaultDeployScriptArgs(argv)
    if manualMode and '--manual' not in args:
        args.append('--manual')
    python_executable = str(resolvePreferredChildPython(guiRequired=('--headless' not in args and '/headless' not in args)) or sys.executable or EMPTY_STRING).strip()
    if not python_executable:
        return False
    cmd = [python_executable, target, *args]
    display_name = Path(target).name
    print(f'[INFO] Launched {display_name}', flush=True)
    if os.name == 'nt':
        creationflags = getattr(subprocess, 'CREATE_NEW_CONSOLE', 0)
        try:
            launcherStartProcess(cmd, cwd=str(Path(target).resolve().parent), creationflags=creationflags)
            return True
        except Exception as error:
            recordException('start.py:22287', sys.exc_info()[1])
            print(f'[ERROR] Failed launching {display_name}: {error}', flush=True)
            return False
    try:
        launcherStartProcess(cmd, cwd=str(Path(target).resolve().parent), start_new_session=True)
        return True
    except Exception as error:
        recordException('start.py:22293', sys.exc_info()[1])
        print(f'[ERROR] Failed launching {display_name}: {error}', flush=True)
        return False

def readSingleConsoleKey(timeout_seconds: float = 1.0) -> str:
    deadline = time.time() + max(0.05, float(timeout_seconds or 0.0))
    if os.name == 'nt':
        try:
            import msvcrt
            while time.time() < deadline:
                if getattr(msvcrt, 'kbhit')():
                    raw = _msvcrtGetch()
                    if raw in (b'\x00', b'\xe0'):
                        try:
                            _msvcrtGetch()
                        except Exception:
                            recordException('start.py:22308', sys.exc_info()[1])
                            _traceSwallowedException('start.py:21727', sys.exc_info()[1])
                            pass
                        continue
                    try:
                        return raw.decode('utf-8', 'replace')
                    except Exception:
                        recordException('start.py:22314', sys.exc_info()[1])
                        return EMPTY_STRING
                time.sleep(0.05)
        except Exception:
            recordException('start.py:22317', sys.exc_info()[1])
            return EMPTY_STRING
        return EMPTY_STRING
    try:
        import select, termios, tty
        if not sys.stdin.isatty():
            time.sleep(timeout_seconds)
            return EMPTY_STRING
        fd = sys.stdin.fileno()
        old = termios.tcgetattr(fd)
        try:
            tty.setcbreak(fd)
            ready, _, _ = select.select([sys.stdin], [], [], max(0.05, float(timeout_seconds or 0.0)))
            if ready:
                return sys.stdin.read(1)
            return EMPTY_STRING
        finally:
            termios.tcsetattr(fd, termios.TCSADRAIN, old)
    except Exception:
        recordException('start.py:22335', sys.exc_info()[1])
        time.sleep(timeout_seconds)
        return EMPTY_STRING

def runDeployMonitor(argv=None, root_path: str | Path | None = None) -> int:
    root = Path(root_path or Path.cwd())
    print(renderConsoleBox(startVersionText(), [f'Root: {root}', 'Mode: zip deploy monitor', 'Press R to rerun, Q/Esc/any other key to quit.'], color_code='\x1b[90m'), flush=True)
    frame_index = 0
    deployment_floor = None
    candidate = resolveLaunchScript(root)
    while True:
        deployed = expandZipsInDirectory(root)
        if deployed is not None:
            deployment_floor = deployed
            candidate = resolveLaunchScript(root, deployment_floor)
            if candidate:
                launchTargetScript(candidate, argv=argv, manual=False)
        else:
            candidate = resolveLaunchScript(root, deployment_floor) if deployment_floor is not None else resolveLaunchScript(root)
        sys.stdout.write('\r' + deployMonitorHeartbeatLine(frame_index, candidate))
        sys.stdout.flush()
        key = readSingleConsoleKey(1.0)
        frame_index += 1
        if not key:
            continue
        low = key.lower()
        sys.stdout.write('\n')
        sys.stdout.flush()
        if low == 'r':
            if candidate:
                launchTargetScript(candidate, argv=argv, manual=True)
            else:
                print('[WARN] No Python entrypoint found to run.', flush=True)
            continue
        if low == 'd':
            if candidate:
                debug_args = list(getDefaultDeployScriptArgs(argv))
                if not any(str(item).lower() in DEBUG_FLAGS for item in debug_args):
                    debug_args.append('--debug')
                launchTargetScript(candidate, argv=debug_args, manual=True)
            else:
                print('[WARN] No Python entrypoint found to debug.', flush=True)
            continue
        break
    print('\nMonitor stopped. Press any key to exit.', flush=True)
    if os.name == 'nt':
        readSingleConsoleKey(30.0)
    return 0

def runDeployOnce(argv=None, root_path: str | Path | None = None) -> int:
    root = Path(root_path or Path.cwd())
    deployed = expandZipsInDirectory(root)
    candidate = resolveLaunchScript(root, deployed) if deployed is not None else resolveLaunchScript(root)
    if deployed is not None and candidate:
        launchTargetScript(candidate, argv=argv, manual=False)
    print(renderConsoleBox('Deploy Once', [f'Root: {root}', f'Expanded zips: {bool(deployed)}', f'Candidate: {Path(candidate).name if candidate else "none"}'], color_code='\x1b[90m'), flush=True)
    return 0


def proxyDaemonRequested(argv=None) -> bool:
    return bool(readCliOption(argv, PROXY_DAEMON_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))


def proxyBindValue(argv=None) -> str:
    state = readCliOption(argv, PROXY_BIND_FLAGS, takesValue=True, knownAliases=START_VALID_CLI_ALIASES)
    return str(state.get('value') or EMPTY_STRING).strip()


def gitRequested(argv=None) -> bool:
    return bool(readCliOption(argv, GIT_FLAGS, takesValue=False, knownAliases=START_VALID_CLI_ALIASES).get('present'))


def extractGitCliArgs(argv=None) -> list[str]:
    tokens = [str(token or EMPTY_STRING).strip() for token in list(argv or []) if str(token or EMPTY_STRING).strip()]
    for index, token in enumerate(tokens):
        lowered = token.lower()
        if lowered in GIT_FLAGS:
            return tokens[index + 1:]
        for alias in GIT_FLAGS:
            prefix = alias + '='
            if lowered.startswith(prefix):
                payload = token[len(alias) + 1:].strip()
                return shlex.split(payload) if payload else []
    return []



def appendToolDirectoryToPath(executable_path: str | Path, env: dict | None = None) -> str:
    target_env = env if isinstance(env, dict) else os.environ
    path_text = str(target_env.get('PATH', EMPTY_STRING) or EMPTY_STRING)
    exe_path = Path(executable_path or EMPTY_STRING)
    parent = exe_path.parent if exe_path.name else exe_path
    parent_text = str(parent or EMPTY_STRING).strip()
    if not parent_text:
        return path_text
    current_parts = [part for part in path_text.split(os.pathsep) if str(part or EMPTY_STRING).strip()]
    normalized_existing = {str(Path(part)).lower() for part in current_parts if str(part or EMPTY_STRING).strip()}
    if str(Path(parent_text)).lower() in normalized_existing:
        return path_text
    new_parts = [parent_text, *current_parts]
    new_value = os.pathsep.join(new_parts)
    target_env['PATH'] = new_value
    return new_value


def _toolTracePrefix(tool_name: str) -> str:
    name = str(tool_name or EMPTY_STRING).strip().lower()
    if name in {'git', 'gh'}:
        return '[TrioGit]'
    return '[TrioTool]'


def _windowsRegistryToolCandidates(tool_name: str) -> list[tuple[Path, str]]:
    plugin = pluginNamed(tool_name)
    if plugin is None:
        return []
    return list(plugin._registryCandidates())


def _windowsDefaultToolCandidates(tool_name: str) -> list[tuple[Path, str]]:
    plugin = pluginNamed(tool_name)
    if plugin is None:
        return []
    return list(plugin._defaultCandidates())


def toolExecutableCandidatesDetailed(tool_name: str) -> list[tuple[Path, str]]:
    plugin = pluginNamed(tool_name)
    if plugin is not None:
        return list(plugin.candidatePathsDetailed())
    name = str(tool_name or EMPTY_STRING).strip().lower()
    candidates: list[tuple[Path, str]] = []
    found = shutil.which(name)
    if found:
        candidates.append((Path(found), 'path'))
    return candidates


def toolExecutableCandidates(tool_name: str) -> list[Path]:
    return [Path(candidate) for candidate, _source in toolExecutableCandidatesDetailed(tool_name)]



def locateToolExecutable(tool_name: str, install_if_missing: bool = False) -> tuple[str, str]:
    name = str(tool_name or EMPTY_STRING).strip().lower()
    if not name:
        return EMPTY_STRING, '[Plugin] Missing tool name.'
    plugin = pluginNamed(name)
    if plugin is not None:
        path_text, detail = plugin.find(install_if_missing=bool(install_if_missing))
        if path_text:
            if plugin.getPluginName() == 'git':
                os.environ['GIT_PYTHON_GIT_EXECUTABLE'] = str(path_text)
            return path_text, detail
        return EMPTY_STRING, detail
    prefix = _toolTracePrefix(name)
    found = shutil.which(name)
    if found:
        appendToolDirectoryToPath(found)
        os.environ[f'TRIO_{name.upper()}_EXE'] = str(found)
        return str(found), f'{prefix} {name} found on PATH: {found}'
    return EMPTY_STRING, f'{prefix} {name} executable not found.'


def attemptToolInstall(tool_name: str) -> str:
    name = str(tool_name or EMPTY_STRING).strip().lower()
    if not name:
        return '[Plugin] Missing tool name for install.'
    plugin = pluginNamed(name)
    python_exe = str(sys.executable or EMPTY_STRING).strip()
    strategy_specs = _pluginInstallStrategies(name, plugin, python_exe)
    lines = [f'[Plugin] Attempting to install {name}.']
    command_specs = []
    for spec in strategy_specs:
        if not bool(spec.get('enabled')):
            continue
        lines.extend(str(note) for note in spec.get('notes', []) if str(note or EMPTY_STRING).strip())
        for rawCommand in spec.get('commands', []):
            command = [part for part in list(rawCommand or []) if str(part or EMPTY_STRING).strip()]
            if command:
                command_specs.append(command)
    if not command_specs:
        return f'[Plugin] No automatic installer path is configured for {name} on this platform.'
    for command in command_specs:
        ok, stdout_text, stderr_text, exit_code = StartDependencyRegistry.runCommandDetailed(command, label=f'{name} install', timeout=1800)
        rendered = ' '.join(shlex.quote(str(part or EMPTY_STRING)) for part in command)
        lines.append(f'[Plugin] install command={rendered}')
        lines.append(f'[Plugin] install exit={exit_code}')
        if stdout_text:
            lines.extend(['[stdout]', str(stdout_text).strip()])
        if stderr_text:
            lines.extend(['[stderr]', str(stderr_text).strip()])
        if ok and name not in {'git', 'github'}:
            break
    return '\n'.join(part for part in lines if str(part or EMPTY_STRING).strip())

def debuggerGitConfigValue(key: str, repo_root: str | Path = BASE_DIR) -> str:
    config_key = str(key or EMPTY_STRING).strip()
    if not config_key:
        return EMPTY_STRING
    git_exe, _ = locateToolExecutable('git', install_if_missing=False)
    if not git_exe:
        return EMPTY_STRING
    try:
        completed = launcherRunCommand([git_exe, 'config', '--get', config_key], cwd=str(Path(repo_root or BASE_DIR)), capture_output=True, text=True)
        if int(getattr(completed, 'returncode', 1)) != 0:
            return EMPTY_STRING
        return str(completed.stdout or EMPTY_STRING).strip()
    except Exception:
        recordException('start.py:22543', sys.exc_info()[1])
        return EMPTY_STRING


def externalRepoToolStatusLines() -> list[str]:
    lines = ['External repo tools:']
    for label in ('git', 'putty', 'plink', 'pscp', 'psftp'):
        path_text, detail = locateToolExecutable(label, install_if_missing=False)
        ok = bool(str(path_text or EMPTY_STRING).strip())
        source_text = str(detail or EMPTY_STRING).strip() or '(no detail)'
        lines.append(f'  {label}: {path_text if ok else "(missing)"}')
        lines.append(f'    {source_text}')
    return lines


def gitHelpText(repo_root: str | Path = BASE_DIR) -> str:
    root = Path(repo_root or BASE_DIR)
    lines = []
    for section in _gitHelpSectionSpecs(root):
        heading = str(section.get('heading', EMPTY_STRING) or EMPTY_STRING).strip()
        if heading:
            lines.append(heading)
        lines.extend(str(line) for line in section.get('lines', []) if str(line or EMPTY_STRING).strip())
        lines.append(EMPTY_STRING)
    lines.extend(externalRepoToolStatusLines())
    lines.extend([EMPTY_STRING, 'Anything else is passed through to git or gh directly.'])
    return '\n'.join(lines)

def runGitProcess(args: list[str], cwd: str | Path = BASE_DIR) -> str:
    repo_root = Path(cwd or BASE_DIR)
    git_exe, detect_text = locateToolExecutable('git', install_if_missing=True)
    if not git_exe:
        return detect_text
    command = [git_exe, *list(args or [])]
    completed = launcherRunCommand(command, cwd=str(repo_root), capture_output=True, text=True)
    stdout = str(completed.stdout or EMPTY_STRING).strip()
    stderr = str(completed.stderr or EMPTY_STRING).strip()
    lines = [detect_text, f"[TrioGit] cwd={repo_root}", f"[TrioGit] command={' '.join(shlex.quote(part) for part in command)}", f"[TrioGit] exit={completed.returncode}"]
    if stdout:
        lines.extend(['', '[stdout]', stdout])
    if stderr:
        lines.extend(['', '[stderr]', stderr])
    return '\n'.join(part for part in lines if str(part or EMPTY_STRING).strip()).strip()


def runGhProcess(args: list[str], cwd: str | Path = BASE_DIR, stdin_text: str = EMPTY_STRING) -> str:
    repo_root = Path(cwd or BASE_DIR)
    gh_exe, detect_text = locateToolExecutable('gh', install_if_missing=True)
    if not gh_exe:
        return detect_text
    command = [gh_exe, *list(args or [])]
    completed = launcherRunCommand(command, cwd=str(repo_root), input=str(stdin_text or EMPTY_STRING), capture_output=True, text=True)
    stdout = str(completed.stdout or EMPTY_STRING).strip()
    stderr = str(completed.stderr or EMPTY_STRING).strip()
    lines = [detect_text, f"[TrioGit] cwd={repo_root}", f"[TrioGit] command={' '.join(shlex.quote(part) for part in command)}", f"[TrioGit] exit={completed.returncode}"]
    if stdout:
        lines.extend(['', '[stdout]', stdout])
    if stderr:
        lines.extend(['', '[stderr]', stderr])
    return '\n'.join(part for part in lines if str(part or EMPTY_STRING).strip()).strip()


def chooseGitCredentialHelper() -> str:
    for helper in ('manager-core', 'manager', 'store'):
        if helper == 'store':
            return helper
        test = shutil.which(f'git-credential-{helper}')
        if test:
            return helper
    return 'store'


def applyGitAuthSettings(payload: dict[str, Any], cwd: str | Path = BASE_DIR, interactive: bool = False) -> str:
    repo_root = Path(cwd or BASE_DIR)
    values = dict(payload or {})
    author_name = str(values.get('author_name', EMPTY_STRING) or EMPTY_STRING).strip()
    author_email = str(values.get('author_email', EMPTY_STRING) or EMPTY_STRING).strip()
    username = str(values.get('username', EMPTY_STRING) or EMPTY_STRING).strip()
    password = str(values.get('password', EMPTY_STRING) or EMPTY_STRING)
    host = str(values.get('host', 'github.com') or 'github.com').strip() or 'github.com'
    setup_git = bool(values.get('setup_git'))
    lines: list[str] = []
    if author_name:
        lines.append(runGitProcess(['config', 'user.name', author_name], cwd=repo_root))
    if author_email:
        lines.append(runGitProcess(['config', 'user.email', author_email], cwd=repo_root))
    if not username and not password:
        if lines:
            return '\n\n'.join(lines)
        return '[TrioGit] Auth needs at least a username and password/token.'
    helper = chooseGitCredentialHelper()
    lines.append(runGitProcess(['config', 'credential.helper', helper], cwd=repo_root))
    if username and password:
        approve_payload = f'protocol=https\nhost={host}\nusername={username}\npassword={password}\n\n'
        git_exe, detect_text = locateToolExecutable('git', install_if_missing=True)
        if git_exe:
            completed = launcherRunCommand([git_exe, 'credential', 'approve'], cwd=str(repo_root), input=approve_payload, capture_output=True, text=True)
            block = [detect_text, f"[TrioGit] credential approve host={host}", f"[TrioGit] exit={completed.returncode}"]
            if str(completed.stdout or EMPTY_STRING).strip():
                block.extend(['[stdout]', str(completed.stdout).strip()])
            if str(completed.stderr or EMPTY_STRING).strip():
                block.extend(['[stderr]', str(completed.stderr).strip()])
            lines.append('\n'.join(block))
    if password:
        gh_path, _ = locateToolExecutable('gh', install_if_missing=True)
        if gh_path:
            login_output = runGhProcess(['auth', 'login', '--hostname', host, '--with-token'], cwd=repo_root, stdin_text=password + '\n')
            lines.append(login_output)
            if setup_git:
                lines.append(runGhProcess(['auth', 'setup-git'], cwd=repo_root))
        else:
            lines.append('[TrioGit] gh CLI not found; git credentials were stored through git credential approve instead.')
    return '\n\n'.join(part for part in lines if str(part or EMPTY_STRING).strip()).strip()


def normalizeGitAlias(primary: str) -> str:
    token = str(primary or EMPTY_STRING).strip().lower()
    mapping = {
        'gs': 'status',
        'ga': 'add',
        'gc': 'commit',
        'gb': 'branch',
        'gd': 'diff',
        'bd': 'diff',
        'gp': 'push',
        'gpush': 'push',
        'gu': 'pull',
        'gpull': 'pull',
        'gr': 'remote',
        'gl': 'log',
        'gf': 'fetch',
        'gco': 'checkout',
        'gsw': 'switch',
        'gm': 'help',
        'man': 'help',
        'gi': 'gitignore',
        'gauth': 'auth',
    }
    return mapping.get(token, token)


def runGitCommand(args: list[str], cwd: str | Path = BASE_DIR, interactive: bool = False) -> str:
    repo_root = Path(cwd or BASE_DIR)
    normalized = [str(part or EMPTY_STRING).strip() for part in list(args or []) if str(part or EMPTY_STRING).strip()]
    if not normalized:
        return gitHelpText(repo_root)
    primary = normalizeGitAlias(normalized[0])
    tail = normalized[1:]
    if primary in {'help', 'h', '?'}:
        return gitHelpText(repo_root)
    if primary in {'version', 'ver', 'v'}:
        return runGitProcess(['--version'], cwd=repo_root)
    if primary == 'gitignore':
        return f"[TrioGit] .gitignore path: {repo_root / '.gitignore'}"
    if primary == 'status':
        return runGitProcess(['status', '--short', '--branch'], cwd=repo_root)
    if primary == 'branch':
        return runGitProcess(['branch', '--all'], cwd=repo_root)
    if primary == 'log':
        return runGitProcess(['log', '--oneline', '--decorate', '-n', '20'], cwd=repo_root)
    if primary == 'diff':
        stat_text = runGitProcess(['diff', '--stat'], cwd=repo_root)
        full_text = runGitProcess(['diff'], cwd=repo_root)
        return stat_text + '\n\n' + full_text
    if primary == 'add':
        return runGitProcess(['add', *(tail or ['.'])], cwd=repo_root)
    if primary == 'commit':
        commit_args = ['commit', *tail]
        if '-m' not in commit_args and '--message' not in commit_args:
            if not interactive:
                return '[TrioGit] commit needs a message. Use: --git commit -m "message"'
            try:
                message = input('[TrioGit:commit message] > ').strip()
            except Exception:
                recordException('start.py:22716', sys.exc_info()[1])
                message = EMPTY_STRING
            if not message:
                return '[TrioGit] Commit cancelled.'
            commit_args = ['commit', '-m', message]
        return runGitProcess(commit_args, cwd=repo_root)
    if primary == 'fetch':
        return runGitProcess(['fetch', *(tail or ['--all', '--prune'])], cwd=repo_root)
    if primary == 'remote':
        return runGitProcess(['remote', *(tail or ['-v'])], cwd=repo_root)
    if primary == 'gh':
        return runGhProcess(tail or ['auth', 'status'], cwd=repo_root)
    if primary == 'auth':
        if not tail:
            return '[TrioGit] auth opens the Qt modal in debugger mode. CLI usage: --git auth login --username NAME --password TOKEN [--host github.com] [--author-name NAME] [--author-email EMAIL]'
        sub = normalizeGitAlias(tail[0])
        tail_rest = tail[1:]
        if sub == 'status':
            return runGhProcess(['auth', 'status'], cwd=repo_root)
        if sub == 'logout':
            host = 'github.com'
            if '--host' in tail_rest:
                idx = tail_rest.index('--host')
                if idx + 1 < len(tail_rest):
                    host = str(tail_rest[idx + 1] or host).strip() or host
            return runGhProcess(['auth', 'logout', '--hostname', host], cwd=repo_root)
        if sub in {'setup-git', 'setupgit'}:
            return runGhProcess(['auth', 'setup-git'], cwd=repo_root)
        if sub in {'login', 'save', 'store'}:
            parsed = {'host': 'github.com', 'setup_git': True}
            index = 0
            while index < len(tail_rest):
                key = str(tail_rest[index] or EMPTY_STRING).strip().lower()
                value = str(tail_rest[index + 1] or EMPTY_STRING).strip() if index + 1 < len(tail_rest) else EMPTY_STRING
                if key in {'--username', '-u'}:
                    parsed['username'] = value
                    index += 2
                    continue
                if key in {'--password', '--token', '-p'}:
                    parsed['password'] = value
                    index += 2
                    continue
                if key == '--host':
                    parsed['host'] = value or 'github.com'
                    index += 2
                    continue
                if key == '--author-name':
                    parsed['author_name'] = value
                    index += 2
                    continue
                if key == '--author-email':
                    parsed['author_email'] = value
                    index += 2
                    continue
                if key == '--no-setup-git':
                    parsed['setup_git'] = False
                    index += 1
                    continue
                index += 1
            return applyGitAuthSettings(parsed, cwd=repo_root, interactive=interactive)
        return runGhProcess(['auth', sub, *tail_rest], cwd=repo_root)
    if primary in {'init', 'push', 'pull', 'checkout', 'switch'}:
        return runGitProcess([primary, *tail], cwd=repo_root)
    return runGitProcess([primary, *tail], cwd=repo_root)

def runGitCli(argv=None) -> int:
    args = extractGitCliArgs(argv)
    print(runGitCommand(args, cwd=BASE_DIR, interactive=False), flush=True)
    return 0


def runProxyDaemon(argv=None) -> int:
    bind_value = proxyBindValue(argv) or str(os.environ.get('TRIO_PROXY_BIND', '127.0.0.1:6666') or '127.0.0.1:6666').strip()
    os.environ['TRIO_PROXY_BIND'] = bind_value
    host = '127.0.0.1'
    port = 6666
    if ':' in bind_value:
        host, port_text = bind_value.rsplit(':', 1)
        host = str(host or '127.0.0.1').strip() or '127.0.0.1'
        try:
            port = int(port_text or 6666)
        except Exception:
            recordException('start.py:22797', sys.exc_info()[1])
            port = 6666
    class _ProxyOwner:
        def __init__(self):
            self.db = DebuggerDatabase(self)
            self.logPath = str(launcherDebugLogPath())
            self.exceptionPath = str(launcherExceptionLogPath())
            self.childPid = 0
        def emit(self, text: str, path: str | None = None):
            print(str(text or EMPTY_STRING), flush=True)
            if path:
                try:
                    with File(path).open('a', encoding='utf-8', errors='replace') as handle:
                        handle.write(str(text or EMPTY_STRING) + ('\n' if not str(text or EMPTY_STRING).endswith('\n') else EMPTY_STRING))
                except Exception:
                    recordException('start.py:22811', sys.exc_info()[1])
                    _traceSwallowedException('start.py:22229', sys.exc_info()[1])
                    pass
    owner = _ProxyOwner()
    server = TrafficProxyServer(owner, host=host, port=port)
    server.mode = 'daemon'
    server.start()
    print(f'[TRACE:proxy-bind] endpoint={server.endpointUrl()} status=bound', file=sys.stderr, flush=True)
    print(server.statusText(), flush=True)
    try:
        
        if server.worker is not None:
            while bool(getattr(server.worker, 'is_alive', lambda: False)()):
                server.worker.join(timeout=1.0)
    except KeyboardInterrupt:
        recordException('start.py:22823', sys.exc_info()[1])
        server.stop()
    return 0


_PYRIGHT_GATE_CHECKED_PATHS: set[str] = set()
_PYRIGHT_PIP_INSTALL_ATTEMPTED = False



def scanDisabled(argv: list[str] | None = None) -> bool:
    tokens = [str(arg or EMPTY_STRING).strip().lower() for arg in list(argv or []) if str(arg or EMPTY_STRING).strip()]
    if any(token in NO_SCAN_FLAGS for token in tokens):
        return True
    if str(os.environ.get('TRIO_NO_SCAN', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'}:
        return True
    return False


def pyrightGateDisabled(argv: list[str]) -> bool:
    if str(os.environ.get('TRIO_SKIP_PYRIGHT_BOOTSTRAP', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'on'}:
        return True
    if scanDisabled(argv):
        return True
    return any(str(arg or EMPTY_STRING).strip().lower() in PYRIGHT_DISABLE_FLAGS for arg in list(argv or []))


def pyrightStartupGateAllowed(argv: list[str] | None = None) -> bool:
    return bool(debugEnabled(list(argv or [])) and not scanDisabled(list(argv or [])))


def pyrightGreen(text: str) -> str:
    value = str(text or EMPTY_STRING)
    if consoleSupportsAnsi():
        return f"{ansi('1;92')}{value}{ansi('0')}"
    return value


def pyrightYellow(text: str) -> str:
    value = str(text or EMPTY_STRING)
    if consoleSupportsAnsi():
        return f"{ansi('1;93')}{value}{ansi('0')}"
    return value


def pyrightRed(text: str) -> str:
    value = str(text or EMPTY_STRING)
    if consoleSupportsAnsi():
        return f"{ansi('1;91')}{value}{ansi('0')}"
    return value


def pyrightTrace(message: str) -> None:
    print(f"[TRACE:pyright] {message}", flush=True)


def bundledPyrightRootPath() -> Path:
    return BASE_DIR / 'vendor' / 'pyright'


def bundledPyrightPackagePath() -> Path:
    return bundledPyrightRootPath() / 'packages' / 'pyright'


def bundledPyrightIndexPath() -> Path:
    return bundledPyrightPackagePath() / 'index.js'


def bundledPyrightDistPath() -> Path:
    return bundledPyrightPackagePath() / 'dist'


def bundledPyrightDistLooksRunnable() -> bool:
    dist = bundledPyrightDistPath()
    return bool((dist / 'pyright.js').is_file() and (dist / 'typeshed-fallback' / 'stdlib' / 'builtins.pyi').is_file())


def bundledPyrightSourceLooksPresent() -> bool:
    root = bundledPyrightRootPath()
    return bool((root / 'package.json').is_file() and (root / 'packages' / 'pyright' / 'package.json').is_file() and bundledPyrightIndexPath().is_file())


def pyrightBuildLogPreview(stdout_text: str, stderr_text: str, limit: int = 2400) -> str:
    combined = '\n'.join([str(stdout_text or EMPTY_STRING).strip(), str(stderr_text or EMPTY_STRING).strip()]).strip()
    if not combined:
        return EMPTY_STRING
    if len(combined) <= int(limit or 2400):
        return combined
    return combined[-int(limit or 2400):]


def runBundledPyrightBuildStep(command: list[str], cwd: Path, label: str, timeout_seconds: int) -> bool:
    pyrightTrace(f"{label}: {' '.join(map(str, command))}")
    try:
        completed = launcherRunCommand(command, cwd=str(cwd), capture_output=True, text=True, timeout=int(timeout_seconds or 300), check=False)
    except Exception as error:
        recordException('start.py:22918', sys.exc_info()[1])
        print(pyrightYellow(f"[Pyright] {label} failed before completion: {type(error).__name__}: {error}"), flush=True)
        return False
    return_code = int(getattr(completed, 'returncode', 0))
    if return_code == 0:
        pyrightTrace(f"{label}: success")
        return True
    preview = pyrightBuildLogPreview(str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING), str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING))
    print(pyrightYellow(f"[Pyright] {label} failed with exit code {return_code}."), flush=True)
    if preview:
        print(preview, flush=True)
    return False


def ensureBundledPyrightRunnable() -> bool:
    if bundledPyrightDistLooksRunnable():
        return True
    if not bundledPyrightSourceLooksPresent():
        pyrightTrace('Vendored Pyright source tree is missing or incomplete.')
        return False
    node_exe = shutil.which('node')
    npm_exe = shutil.which('npm.cmd') or shutil.which('npm')
    if not node_exe or not npm_exe:
        pyrightTrace('Vendored Pyright source is present, but Node/npm is missing; cannot build vendor/pyright.')
        return False
    root = bundledPyrightRootPath()
    pyrightTrace('Vendored Pyright source found; building runnable CLI because dist is missing.')
    install_needed = not (root / 'node_modules').is_dir()
    if install_needed:
        print(pyrightYellow('[Pyright] Building vendored Pyright: installing npm dependencies. First run can take a while.'), flush=True)
        if not runBundledPyrightBuildStep([npm_exe, 'install'], root, 'npm install vendor/pyright', 900):
            return False
    print(pyrightYellow('[Pyright] Building vendored Pyright CLI.'), flush=True)
    if not runBundledPyrightBuildStep([npm_exe, 'run', 'build:cli:dev'], root, 'npm run build:cli:dev vendor/pyright', 600):
        return False
    if bundledPyrightDistLooksRunnable():
        print(f"[Pyright] vendor/pyright build: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
        return True
    print(pyrightYellow('[Pyright] vendor/pyright build finished, but dist/pyright.js or typeshed fallback is still missing.'), flush=True)
    return False


def pyrightTargetPythonExecutable() -> str:
    try:
        registry = StartDependencyRegistry(sys.argv[1:])
        value = str(registry.targetPythonExecutable(guiRequired=False) or EMPTY_STRING).strip()
        if value:
            return value
    except Exception as error:
        recordException('start.py:22966', sys.exc_info()[1])
        pyrightTrace(f'Could not resolve dependency target Python for Pyright: {type(error).__name__}: {error}')
    return str(sys.executable or EMPTY_STRING).strip()


def pythonPyrightModuleLooksRunnable(python_executable: str) -> bool:
    executable = str(python_executable or EMPTY_STRING).strip()
    if not executable:
        return False
    try:
        ok, stdout_text, stderr_text, _ = StartDependencyRegistry.runCommandDetailed(
            [executable, '-m', 'pyright', '--version'],
            label='python pyright probe',
            timeout=45,
        )
    except Exception as error:
        recordException('start.py:22981', sys.exc_info()[1])
        pyrightTrace(f'Python Pyright probe failed before completion: {type(error).__name__}: {error}')
        return False
    if ok:
        version_text = (str(stdout_text or EMPTY_STRING).strip() or str(stderr_text or EMPTY_STRING).strip()).splitlines()
        if version_text:
            pyrightTrace(f'Python Pyright available: {version_text[0]}')
        return True
    return False


def installPythonPyrightPackage(python_executable: str) -> bool:
    global _PYRIGHT_PIP_INSTALL_ATTEMPTED
    if _PYRIGHT_PIP_INSTALL_ATTEMPTED:
        pyrightTrace('Python Pyright pip install was already attempted in this launcher process.')
        return False
    _PYRIGHT_PIP_INSTALL_ATTEMPTED = True
    executable = str(python_executable or EMPTY_STRING).strip()
    if not executable:
        pyrightTrace('Cannot pip install Pyright because no target Python executable was resolved.')
        return False
    registry = StartDependencyRegistry(sys.argv[1:])
    packages = ['pyright[nodejs]']
    pyrightTrace('Python Pyright package missing; attempting dependency-managed pip install pyright[nodejs].')
    print(pyrightYellow('[Pyright] Python package fallback missing; attempting pip install pyright[nodejs].'), flush=True)
    if registry.isWindows():
        succeeded, permission_error = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='windows pyright pip install')
        if succeeded:
            _dependencyInstallSuccess(registry)
            print(f"[Pyright] pip install pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='windows pyright user pip install')
        if succeeded:
            _dependencyInstallSuccess(registry)
            print(f"[Pyright] pip install --user pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        if permission_error and registry.isWindowsAdmin():
            succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='windows admin pyright pip install')
            if succeeded:
                _dependencyInstallSuccess(registry)
                print(f"[Pyright] admin pip install pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
                return True
        if permission_error and not registry.isWindowsAdmin():
            print(pyrightYellow('[Pyright] Standard Windows pip install hit a permissions error; trying user install already failed, so not blocking startup.'), flush=True)
        return False
    if registry.isLinux():
        succeeded, permission_error = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='linux pyright pip install')
        if succeeded:
            _dependencyInstallSuccess(registry)
            print(f"[Pyright] pip install pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        if permission_error and registry.attemptLinuxSudoPipInstall(packages, pythonExecutable=executable):
            _dependencyInstallSuccess(registry)
            print(f"[Pyright] sudo pip install pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='linux pyright user pip install')
        if succeeded:
            _dependencyInstallSuccess(registry)
            print(f"[Pyright] pip install --user pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        return False
    succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='pyright pip install')
    if succeeded:
        _dependencyInstallSuccess(registry)
        print(f"[Pyright] pip install pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
        return True
    succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='pyright user pip install')
    if succeeded:
        _dependencyInstallSuccess(registry)
        print(f"[Pyright] pip install --user pyright[nodejs]: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
        return True
    return False


def resolvePythonPyrightCommand() -> tuple[list[str], str]:
    executable = pyrightTargetPythonExecutable()
    if pythonPyrightModuleLooksRunnable(executable):
        try:
            import nodejs_wheel  # type: ignore[import-not-found]
            import pyright  # type: ignore[import-not-found]
            nodejs_file = str(getattr(nodejs_wheel, '__file__', '') or '')
            pyright_file = str(getattr(pyright, '__file__', '') or '')
            if not nodejs_file or not pyright_file:
                raise RuntimeError('pyright/nodejs_wheel module file path unavailable')
            node_exe = Path(nodejs_file).resolve().parent / 'bin' / ('node.exe' if os.name == 'nt' else 'node')
            index_js = Path(pyright_file).resolve().parent / 'dist' / 'index.js'
            if node_exe.is_file() and index_js.is_file():
                try:
                    node_exe.chmod(node_exe.stat().st_mode | 0o111)
                except Exception:
                    recordException('start.py:pyright-pip-node-chmod', sys.exc_info()[1])
                pyrightTrace(f'Pip Pyright direct Node runtime available: {node_exe}')
                return [str(node_exe), str(index_js)], 'pip pyright direct-node'
        except Exception:
            recordException('start.py:pyright-pip-direct-node', sys.exc_info()[1])
        return [executable, '-m', 'pyright'], 'pip pyright'
    if installPythonPyrightPackage(executable) and pythonPyrightModuleLooksRunnable(executable):
        try:
            import nodejs_wheel  # type: ignore[import-not-found]
            import pyright  # type: ignore[import-not-found]
            nodejs_file = str(getattr(nodejs_wheel, '__file__', '') or '')
            pyright_file = str(getattr(pyright, '__file__', '') or '')
            if not nodejs_file or not pyright_file:
                raise RuntimeError('pyright/nodejs_wheel module file path unavailable')
            node_exe = Path(nodejs_file).resolve().parent / 'bin' / ('node.exe' if os.name == 'nt' else 'node')
            index_js = Path(pyright_file).resolve().parent / 'dist' / 'index.js'
            if node_exe.is_file() and index_js.is_file():
                try:
                    node_exe.chmod(node_exe.stat().st_mode | 0o111)
                except Exception:
                    recordException('start.py:pyright-pip-node-chmod-after-install', sys.exc_info()[1])
                pyrightTrace(f'Pip Pyright direct Node runtime available after install: {node_exe}')
                return [str(node_exe), str(index_js)], 'pip pyright direct-node'
        except Exception:
            recordException('start.py:pyright-pip-direct-node-after-install', sys.exc_info()[1])
        return [executable, '-m', 'pyright'], 'pip pyright'
    pyrightTrace('Python Pyright package fallback is unavailable.')
    return [], EMPTY_STRING


def pyrightWheelhousePath() -> Path:
    return BASE_DIR / 'packages' / 'wheelhouse'


def pyrightWheelRuntimePath() -> Path:
    return BASE_DIR / 'packages' / 'pyright_runtime'


def _newestPyrightWheel(pattern: str) -> Path | None:
    try:
        wheels = sorted(pyrightWheelhousePath().glob(pattern), key=lambda item: item.stat().st_mtime, reverse=True)
    except Exception:
        recordException('start.py:pyright-wheel-glob', sys.exc_info()[1])
        wheels = []
    return wheels[0] if wheels else None


def ensureWheelhousePyrightRuntime() -> bool:
    """Extract downloaded Pyright wheels into a local runnable runtime.

    This avoids npm/npx network/auth failures and avoids PEP 668 system-install
    failures. The dependency installer may only be able to download wheels in a
    locked Linux environment, so --plyright must be able to run directly from the
    wheelhouse.
    """
    wheelhouse = pyrightWheelhousePath()
    runtime = pyrightWheelRuntimePath()
    pyright_wheel = _newestPyrightWheel('pyright-*.whl')
    node_wheel = _newestPyrightWheel('nodejs_wheel_binaries-*.whl')
    if not pyright_wheel:
        pyrightTrace(f'Wheelhouse Pyright runtime unavailable: no pyright wheel in {wheelhouse}.')
        return False
    if not node_wheel:
        pyrightTrace(f'Wheelhouse Pyright runtime unavailable: no nodejs wheel in {wheelhouse}.')
        return False
    try:
        runner = runtime / 'pyright_runner.py'
        node_exe = runtime / 'nodejs_wheel' / 'bin' / ('node.exe' if os.name == 'nt' else 'node')
        pyright_main = runtime / 'pyright' / '__main__.py'
        needs_extract = not (runner.is_file() and node_exe.is_file() and pyright_main.is_file())
        if needs_extract:
            runtime.mkdir(parents=True, exist_ok=True)
            for wheel in sorted(wheelhouse.glob('*.whl')):
                with zipfile.ZipFile(wheel) as archive:
                    archive.extractall(runtime)
            File(runner).writeText('import runpy, sys\n'
                                   'sys.argv = ["pyright", *sys.argv[1:]]\n'
                                   'runpy.run_module("pyright", run_name="__main__")\n')
        for candidate in (runtime / 'nodejs_wheel' / 'bin' / 'node', runtime / 'nodejs_wheel' / 'bin' / 'npm'):
            if candidate.exists():
                try:
                    candidate.chmod(candidate.stat().st_mode | 0o111)
                except Exception:
                    recordException('start.py:pyright-wheel-chmod', sys.exc_info()[1])
        if not runner.is_file() or not pyright_main.is_file() or not node_exe.is_file():
            pyrightTrace('Wheelhouse Pyright runtime extraction incomplete.')
            return False
        return True
    except Exception as error:
        recordException('start.py:pyright-wheel-runtime', sys.exc_info()[1])
        pyrightTrace(f'Wheelhouse Pyright runtime failed: {type(error).__name__}: {error}')
        return False


def resolveWheelhousePyrightCommand() -> tuple[list[str], str]:
    executable = pyrightTargetPythonExecutable() or str(sys.executable or EMPTY_STRING)
    if not executable:
        return [], EMPTY_STRING
    if not ensureWheelhousePyrightRuntime():
        return [], EMPTY_STRING
    runtime = pyrightWheelRuntimePath()
    node_exe = runtime / 'nodejs_wheel' / 'bin' / ('node.exe' if os.name == 'nt' else 'node')
    index_js = runtime / 'pyright' / 'dist' / 'index.js'
    runner = runtime / 'pyright_runner.py'
    command = [str(node_exe), str(index_js)] if node_exe.is_file() and index_js.is_file() else [executable, str(runner)]
    try:
        ok, stdout_text, stderr_text, _ = StartDependencyRegistry.runCommandDetailed(
            [*command, '--version'],
            label='wheelhouse pyright probe',
            timeout=45,
        )
        if ok:
            version_text = (str(stdout_text or EMPTY_STRING).strip() or str(stderr_text or EMPTY_STRING).strip()).splitlines()
            if version_text:
                pyrightTrace(f'Wheelhouse Pyright available: {version_text[0]}')
            return command, 'wheelhouse pyright'
    except Exception as error:
        recordException('start.py:pyright-wheel-probe', sys.exc_info()[1])
        pyrightTrace(f'Wheelhouse Pyright probe failed: {type(error).__name__}: {error}')
    return [], EMPTY_STRING


def resolvePyrightCommand() -> tuple[list[str], str]:
    node_exe = shutil.which('node')
    bundled_index = bundledPyrightIndexPath()
    if node_exe and bundled_index.is_file() and ensureBundledPyrightRunnable():
        return [node_exe, str(bundled_index)], 'vendor/pyright'
    wheel_command, wheel_label = resolveWheelhousePyrightCommand()
    if wheel_command:
        return wheel_command, wheel_label
    python_command, python_label = resolvePythonPyrightCommand()
    if python_command:
        return python_command, python_label
    wheel_command, wheel_label = resolveWheelhousePyrightCommand()
    if wheel_command:
        return wheel_command, wheel_label
    pyright_exe = shutil.which('pyright.cmd') or shutil.which('pyright')
    if pyright_exe:
        return [pyright_exe], 'pyright'
    if os.environ.get('TRIO_PYRIGHT_ALLOW_NPX', '').strip().lower() in {'1', 'true', 'yes', 'on'}:
        npx_exe = shutil.which('npx.cmd') or shutil.which('npx')
        if npx_exe:
            return [npx_exe, '--yes', 'pyright'], 'npx pyright'
    pyrightTrace('npx pyright fallback skipped; set TRIO_PYRIGHT_ALLOW_NPX=1 to permit npm network fallback.')
    return [], EMPTY_STRING



def pyrightDiagnosticRows(payload: dict[str, Any], target: Path, limit: int = 30) -> list[str]:
    rows: list[str] = []
    diagnostics = list(payload.get('generalDiagnostics') or [])
    try:
        target_resolved = str(Path(target).resolve())
    except Exception:
        recordException('start.py:23088', sys.exc_info()[1])
        target_resolved = str(target)
    for diag in diagnostics:
        file_name = str(diag.get('file') or EMPTY_STRING)
        severity = str(diag.get('severity') or EMPTY_STRING)
        message = str(diag.get('message') or EMPTY_STRING).replace('\r\n', '\n').replace('\r', '\n').strip()
        rng = diag.get('range') or {}
        start_pos = rng.get('start') or {}
        line_no = int(start_pos.get('line', 0) or 0) + 1
        char_no = int(start_pos.get('character', 0) or 0) + 1
        try:
            display_file = str(Path(file_name).resolve().relative_to(BASE_DIR))
        except Exception:
            recordException('start.py:23100', sys.exc_info()[1])
            display_file = Path(file_name).name if file_name else Path(target_resolved).name
        rows.append(f"{severity.upper()}: {display_file}:{line_no}:{char_no} - {message}")
        if len(rows) >= int(limit or 30):
            remaining = max(0, len(diagnostics) - len(rows))
            if remaining:
                rows.append(f"... {remaining} more diagnostics omitted from console preview.")
            break
    return rows


def pyrightAskContinue(label: str, error_count: int) -> bool:
    assume = str(os.environ.get('TRIO_PYRIGHT_ASSUME_CONTINUE', EMPTY_STRING) or EMPTY_STRING).strip().lower()
    prompt = str(os.environ.get('TRIO_PYRIGHT_PROMPT', EMPTY_STRING) or EMPTY_STRING).strip().lower()
    if assume in {'0', 'false', 'no', 'n', 'off'}:
        return False
    if prompt not in {'1', 'true', 'yes', 'y', 'on'}:
        print(pyrightYellow(f"[Pyright] {label} has {error_count} error(s); continuing automatically. Set TRIO_PYRIGHT_PROMPT=1 to make this gate interactive."), flush=True)
        return True
    try:
        interactive = bool(getattr(sys.stdin, 'isatty', lambda: False)())
    except Exception:
        recordException('start.py:23121', sys.exc_info()[1])
        interactive = False
    if not interactive:
        print(pyrightYellow(f"[Pyright] {label} has {error_count} error(s), but stdin is not interactive; continuing so startup does not hang."), flush=True)
        return True
    try:
        answer = input(pyrightYellow(f"[Pyright] {label} has {error_count} error(s). Continue running anyway? [Y/n] ")).strip().lower()
    except Exception:
        recordException('start.py:23128', sys.exc_info()[1])
        return True
    return answer not in {'n', 'no'}





def pyrightSafeFilename(value: str) -> str:
    cleaned = re.sub(r'[^A-Za-z0-9_.-]+', '-', str(value or 'target')).strip('.-')
    return cleaned or 'target'


def writePyrightStartupConfig(target: Path) -> Path:
    logs_dir = BASE_DIR / 'logs'
    try:
        logs_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        recordException('start.py:23145', sys.exc_info()[1])
        logs_dir = BASE_DIR
    try:
        include_value = str(Path(target).resolve().relative_to(BASE_DIR))
    except Exception:
        recordException('start.py:23149', sys.exc_info()[1])
        include_value = str(Path(target).resolve())
    config = {
        'include': [include_value],
        'exclude': [
            'vendor',
            '**/vendor/**',
            '**/__pycache__/**',
            '**/.git/**',
            '**/node_modules/**',
            'logs',
            '**/logs/**',
        ],
        'typeCheckingMode': 'basic',
        'pythonVersion': '3.12',
        'reportMissingImports': False,
        'reportMissingModuleSource': False,
    }
    # Keep the generated project file at BASE_DIR so relative include paths
    # resolve against the repo root instead of logs/.
    path = BASE_DIR / f"pyright-startup-{pyrightSafeFilename(Path(target).stem or 'target')}.json"
    try:
        File(path).writeText(json.dumps(config, indent=2))
    except Exception:
        recordException('start.py:23172', sys.exc_info()[1])
        handle = tempfile.NamedTemporaryFile('w', suffix='.json', prefix='trio-pyright-', delete=False, encoding='utf-8')
        with handle:
            json.dump(config, handle, indent=2)
        path = Path(handle.name)
    return path


def runPyrightForTarget(target_path: Path, label: str, argv: list[str] | None = None) -> bool:
    if pyrightGateDisabled(list(argv or [])):
        pyrightTrace(f"Skipping Pyright for {label}; disabled by flag or environment.")
        return True
    try:
        target = Path(target_path).resolve()
    except Exception:
        recordException('start.py:23186', sys.exc_info()[1])
        target = Path(str(target_path or EMPTY_STRING))
    key = str(target)
    if key in _PYRIGHT_GATE_CHECKED_PATHS:
        pyrightTrace(f"Skipping Pyright for {label}; already checked {target.name}.")
        return True
    _PYRIGHT_GATE_CHECKED_PATHS.add(key)
    if not target.is_file():
        pyrightTrace(f"Skipping Pyright for {label}; target not found: {target}")
        return True
    command_base, source_label = resolvePyrightCommand()
    if not command_base:
        print(pyrightYellow('[Pyright] No bundled runnable Pyright, pip pyright, npx, or pyright command was found. Skipping startup type check.'), flush=True)
        return True
    pyrightTrace(f"Starting Pyright for {label} using {source_label}.")
    pyrightTrace(f"Scanning for errors... {target.name}")
    config_path = writePyrightStartupConfig(target)
    command = [*command_base, '--outputjson', '--level', 'error', '--project', str(config_path), str(target)]
    try:
        completed = launcherRunCommand(command, cwd=str(BASE_DIR), capture_output=True, text=True, timeout=75, check=False)
    except Exception as error:
        recordException('start.py:23206', sys.exc_info()[1])
        print(pyrightYellow(f"[Pyright] Could not complete Pyright for {label}: {type(error).__name__}: {error}"), flush=True)
        return True
    stdout_text = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING)
    stderr_text = str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
    payload: dict[str, Any] = {}
    if stdout_text.strip():
        try:
            payload = json.loads(stdout_text)
        except Exception:
            recordException('start.py:23215', sys.exc_info()[1])
            payload = {}
    summary = dict(payload.get('summary') or {})
    error_count = int(summary.get('errorCount', 0) or 0)
    warning_count = int(summary.get('warningCount', 0) or 0)
    if not payload and int(getattr(completed, 'returncode', 0) or 0) != 0:
        error_count = max(1, error_count)
    if error_count <= 0:
        print(f"[Pyright] {label}: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
        pyrightTrace(f"Pyright success for {label}. warnings={warning_count}")
        return True
    print(pyrightRed(f"[Pyright] {label}: {error_count} error(s), {warning_count} warning(s)."), flush=True)
    for row in pyrightDiagnosticRows(payload, target):
        print(row, flush=True)
    if stderr_text.strip():
        print(stderr_text.strip()[:4000], flush=True)
    return pyrightAskContinue(label, error_count)


def runStartupPyrightGate(argv: list[str], target_path: Path | None = None) -> bool:
    launch_args = list(argv or [])
    if scanDisabled(launch_args):
        pyrightTrace('Startup Pyright gate disabled by --no-scan / -no-scan.')
        return True
    if not debugEnabled(launch_args):
        pyrightTrace('Startup Pyright gate skipped; scans run only with --debug.')
        return True
    if pyrightGateDisabled(launch_args):
        pyrightTrace('Startup Pyright gate disabled.')
        return True
    if not runPyrightForTarget(Path(__file__).resolve(), 'launcher start.py', argv):
        return False
    if target_path is not None:
        try:
            target_resolved = Path(target_path).resolve()
        except Exception:
            recordException('start.py:23250', sys.exc_info()[1])
            target_resolved = Path(str(target_path or EMPTY_STRING))
        if target_resolved != Path(__file__).resolve():
            if not runPyrightForTarget(target_resolved, f'boot target {target_resolved.name}', argv):
                return False
    return True



# --- FlatLine Pyrite / Pyright report-only mode ---
def pyriteRequested(argv: list[str] | None = None) -> bool:
    tokens = _start_cli_token_list(argv)
    if scanDisabled(tokens):
        return False
    env_value = str(os.environ.get('TRIO_PYRITE', EMPTY_STRING) or EMPTY_STRING).strip().lower()
    return bool(cliHasAnyFlag(tokens, PYRITE_FLAGS) or env_value in {'1', 'true', 'yes', 'y', 'on'})


def pyriteTrace(message: str) -> None:
    print(f"[TRACE:pyrite] {message}", flush=True)


def pyriteLogPath() -> Path:
    logs_dir = BASE_DIR / 'logs'
    try:
        logs_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        recordException('start.py:23276', sys.exc_info()[1])
        logs_dir = BASE_DIR
    return logs_dir / 'Pyrite.LOG'


def pyriteAnalysisTargets(argv: list[str] | None = None) -> list[tuple[str, Path]]:
    launch_args = list(argv or [])
    current = Path(__file__).resolve()
    child_requested = cliHasAnyFlag(launch_args, {'--plyright-all', '--pyright-all', '--pyrite-all', '--pirate-all', '--typecheck-all', '--plyright-child', '--pyright-child', '--pyrite-child'})
    child_only = cliHasAnyFlag(launch_args, {'--plyright-child', '--pyright-child', '--pyrite-child'})
    targets: list[tuple[str, Path]] = [] if child_only else [('launcher start.py', current)]
    if child_requested:
        try:
            child = resolvedChildPath(launch_args, forceHeadlessGenerate=False).resolve()
        except Exception:
            recordException('start.py:23285', sys.exc_info()[1])
            child = primaryChildSourcePath().resolve()
        if child != current:
            targets.append((f'boot target {child.name}', child))
    return targets


def appendPyriteSection(lines: list[str], title: str, text: str) -> None:
    lines.append('')
    lines.append(title)
    lines.append('-' * len(title))
    content = str(text or EMPTY_STRING).rstrip()
    lines.append(content if content else '(empty)')


def runPyrightJsonCommand(command: list[str], *, cwd: Path, timeout_seconds: float) -> LauncherCompletedProcess:
    """Run Pyright/Pyrite with hard timeout and file-backed output capture."""
    timeout_seconds = max(5.0, float(timeout_seconds or 240.0))
    start_time = time.monotonic()
    command = [str(part) for part in list(command or [])]
    if not command:
        return LauncherCompletedProcess(command, 1, EMPTY_STRING, 'Empty Pyright command.')
    cwd_path = Path(cwd or BASE_DIR).resolve()
    stdout_path = cwd_path / 'logs' / f'pyright_stdout_{int(time.time() * 1000)}_{os.getpid()}.json'
    stderr_path = cwd_path / 'logs' / f'pyright_stderr_{int(time.time() * 1000)}_{os.getpid()}.txt'
    try:
        stdout_path.parent.mkdir(parents=True, exist_ok=True)
    except Exception:
        recordException('start.py:pyright-json-logdir', sys.exc_info()[1])
    timeout_cmd = shutil.which('timeout') if os.name != 'nt' else None
    sh_cmd = shutil.which('sh') if os.name != 'nt' else None
    if timeout_cmd and sh_cmd:
        # On Linux, Pyright can outlive or hostage direct capture pipes on very large files.
        # Run through coreutils timeout and redirect the checker output to files, then read them back.
        timeout_token = str(max(1, int(timeout_seconds)))
        quoted_command = ' '.join(shlex.quote(str(part)) for part in [timeout_cmd, '--kill-after=5', timeout_token, *command])
        shell_command = (
            f"cd {shlex.quote(str(cwd_path))} && "
            f"{quoted_command} > {shlex.quote(str(stdout_path))} 2> {shlex.quote(str(stderr_path))}"
        )
        pyrightTrace(f"Pyright shell timeout={timeout_seconds:.1f}s command={quoted_command}")
        try:
            completed = _ORIGINAL_SUBPROCESS_RUN(
                [sh_cmd, '-lc', shell_command],
                cwd=str(cwd_path),
                stdin=subprocess.DEVNULL,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                text=True,
                encoding='utf-8',
                errors='replace',
                timeout=timeout_seconds + 30.0,
                check=False,
            )  # lifecycle-bypass-ok  # phase-ownership-ok
            elapsed = max(0.0, time.monotonic() - start_time)
            return_code = int(getattr(completed, 'returncode', 0) or 0)
            pyrightTrace(f"Pyright shell completed rc={return_code} elapsed={elapsed:.2f}s")
            stdout_text = File(str(stdout_path)).readText() if stdout_path.exists() else EMPTY_STRING
            stderr_text = File(str(stderr_path)).readText() if stderr_path.exists() else EMPTY_STRING
            if return_code in (124, 137, 143):
                stderr_text = (stderr_text + '\n' if stderr_text else EMPTY_STRING) + f'[Pyrite] Pyright timed out after {timeout_seconds:.1f}s.'
                return LauncherCompletedProcess(command, -9, stdout_text, stderr_text)
            return LauncherCompletedProcess(command, return_code, stdout_text, stderr_text)
        except subprocess.TimeoutExpired as error:
            recordException('start.py:pyright-json-shell-runner-timeout', error, handled=True)
            elapsed = max(0.0, time.monotonic() - start_time)
            message = f"[Pyrite] Pyright shell wrapper timed out after {timeout_seconds:.1f}s; elapsed={elapsed:.2f}s."
            print(pyrightYellow(message), flush=True)
            stdout_text = File(str(stdout_path)).readText() if stdout_path.exists() else EMPTY_STRING
            stderr_text = File(str(stderr_path)).readText() if stderr_path.exists() else EMPTY_STRING
            return LauncherCompletedProcess(command, -9, stdout_text, stderr_text or message)
        except Exception as error:
            recordException('start.py:pyright-json-shell-runner', sys.exc_info()[1])
            stdout_text = File(str(stdout_path)).readText() if stdout_path.exists() else EMPTY_STRING
            stderr_text = File(str(stderr_path)).readText() if stderr_path.exists() else EMPTY_STRING
            return LauncherCompletedProcess(command, 1, stdout_text, stderr_text or f'{type(error).__name__}: {error}')
        finally:
            for temp_path in (stdout_path, stderr_path):
                try:
                    if temp_path.exists():
                        temp_path.unlink()
                except Exception:
                    recordException('start.py:pyright-json-temp-cleanup', sys.exc_info()[1])
    run_kwargs: dict[str, Any] = {
        'cwd': str(cwd_path),
        'capture_output': True,
        'stdin': subprocess.DEVNULL,
        'text': True,
        'encoding': 'utf-8',
        'errors': 'replace',
        'timeout': timeout_seconds,
        'check': False,
    }
    if os.name == 'nt':
        try:
            run_kwargs['creationflags'] = int(getattr(subprocess, 'CREATE_NEW_PROCESS_GROUP', 0) or 0)
        except Exception:
            recordException('start.py:pyright-json-creationflags', sys.exc_info()[1])
    else:
        run_kwargs['start_new_session'] = True
    pyrightTrace(f"Pyright subprocess.run timeout={timeout_seconds:.1f}s command={_launcherCommandText(command)}")
    try:
        completed = _ORIGINAL_SUBPROCESS_RUN(command, **run_kwargs)  # lifecycle-bypass-ok  # phase-ownership-ok
        elapsed = max(0.0, time.monotonic() - start_time)
        pyrightTrace(f"Pyright subprocess.run completed rc={int(getattr(completed, 'returncode', 0) or 0)} elapsed={elapsed:.2f}s")
        return LauncherCompletedProcess(
            command,
            int(getattr(completed, 'returncode', 0) or 0),
            str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING),
            str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING),
        )
    except subprocess.TimeoutExpired as error:
        recordException('start.py:pyright-json-runner-timeout', error, handled=True)
        elapsed = max(0.0, time.monotonic() - start_time)
        message = f"[Pyrite] Pyright timed out after {timeout_seconds:.1f}s; subprocess timeout elapsed={elapsed:.2f}s."
        print(pyrightYellow(message), flush=True)
        stdout_text = error.stdout.decode('utf-8', 'replace') if isinstance(error.stdout, bytes) else str(error.stdout or EMPTY_STRING)
        stderr_text = error.stderr.decode('utf-8', 'replace') if isinstance(error.stderr, bytes) else str(error.stderr or EMPTY_STRING)
        return LauncherCompletedProcess(command, -9, stdout_text, stderr_text or message)
    except Exception as error:
        recordException('start.py:pyright-json-runner', sys.exc_info()[1])
        return LauncherCompletedProcess(command, 1, EMPTY_STRING, f'{type(error).__name__}: {error}')


def runPyriteForTarget(target_path: Path, label: str, command_base: list[str], source_label: str) -> tuple[int, int, int, list[str]]:
    try:
        target = Path(target_path).resolve()
    except Exception:
        recordException('start.py:23303', sys.exc_info()[1])
        target = Path(str(target_path or EMPTY_STRING))
    log_lines: list[str] = [f'Target: {label}', f'Path: {target}', f'Source: {source_label}']
    if not target.is_file():
        message = f'[Pyrite] Skipping missing target: {target}'
        print(pyrightYellow(message), flush=True)
        log_lines.append(message)
        return 0, 0, 0, log_lines
    config_path = writePyrightStartupConfig(target)
    command = [*command_base, '--outputjson', '--project', str(config_path), str(target)]
    log_lines.append('Command: ' + ' '.join(shlex.quote(str(part)) for part in command))
    pyriteTrace(f'Starting Pyrite for {label} using {source_label}.')
    pyriteTrace(f'Scanning for errors... {target.name}')
    try:
        completed = runPyrightJsonCommand(command, cwd=BASE_DIR, timeout_seconds=float(os.environ.get('TRIO_PYRITE_TARGET_TIMEOUT', os.environ.get('TRIO_PYRIGHT_TARGET_TIMEOUT', '180')) or '180'))
    except Exception as error:
        recordException('start.py:23318', sys.exc_info()[1])
        message = f'[Pyrite] {label} failed before completion: {type(error).__name__}: {error}'
        print(pyrightRed(message), flush=True)
        log_lines.append(message)
        log_lines.append(traceback.format_exc())
        return 1, 0, 1, log_lines
    stdout_text = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING)
    stderr_text = str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
    return_code = int(getattr(completed, 'returncode', 0) or 0)
    payload: dict[str, Any] = {}
    if stdout_text.strip():
        try:
            payload = json.loads(stdout_text)
        except Exception:
            recordException('start.py:23331', sys.exc_info()[1])
            payload = {}
    summary = dict(payload.get('summary') or {})
    error_count = int(summary.get('errorCount', 0) or 0)
    warning_count = int(summary.get('warningCount', 0) or 0)
    if not payload and return_code != 0:
        error_count = max(1, error_count)
    log_lines.append(f'Return code: {return_code}')
    log_lines.append(f'Errors: {error_count}')
    log_lines.append(f'Warnings: {warning_count}')
    if error_count <= 0:
        print(f"[Pyrite] {label}: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
    else:
        print(pyrightRed(f'[Pyrite] {label}: {error_count} error(s), {warning_count} warning(s).'), flush=True)
        for row in pyrightDiagnosticRows(payload, target, limit=80):
            print(row, flush=True)
    if stderr_text.strip():
        print(stderr_text.strip()[:4000], flush=True)
    appendPyriteSection(log_lines, 'Diagnostics', '\n'.join(pyrightDiagnosticRows(payload, target, limit=500)))
    appendPyriteSection(log_lines, 'stdout', stdout_text)
    appendPyriteSection(log_lines, 'stderr', stderr_text)
    return error_count, warning_count, return_code, log_lines


def runPyriteAudit(argv: list[str] | None = None) -> int:
    launch_args = list(argv or [])
    print('[Pyrite] Static type-check mode requested; application launch will be skipped.', flush=True)
    command_base, source_label = resolvePyrightCommand()
    log_path = pyriteLogPath()
    header_lines = [
        'TrioDesktop Pyrite / Pyright Report',
        f'Generated: {datetime.datetime.now().isoformat(timespec="seconds")}',
        'Mode: report-only; application launch skipped.',
    ]
    if not command_base:
        message = '[Pyrite] No vendored runnable Pyright, pip pyright, npx pyright, or global pyright command was found.'
        print(pyrightRed(message), flush=True)
        File(log_path).writeText('\n'.join([*header_lines, message, '']))
        return 1
    total_errors = 0
    total_warnings = 0
    worst_return = 0
    all_log_lines = [*header_lines, f'Source: {source_label}', '']
    for label, target in pyriteAnalysisTargets(launch_args):
        errors, warnings, return_code, lines = runPyriteForTarget(target, label, command_base, source_label)
        total_errors += errors
        total_warnings += warnings
        worst_return = max(worst_return, return_code)
        all_log_lines.extend(lines)
        all_log_lines.append('')
    summary_line = f'[Pyrite] total: {total_errors} error(s), {total_warnings} warning(s). Report: {log_path}'
    if total_errors <= 0:
        print(f"[Pyrite] total: {coloredStatusText(STATUS_SUCCESS)} - 0 errors, {total_warnings} warning(s).", flush=True)
    else:
        print(pyrightRed(summary_line), flush=True)
    all_log_lines.insert(3, f'Total errors: {total_errors}')
    all_log_lines.insert(4, f'Total warnings: {total_warnings}')
    all_log_lines.append(summary_line)
    File(log_path).writeText('\n'.join(all_log_lines).rstrip() + '\n')
    print(f'[Pyrite] log: {log_path}', flush=True)
    return 0 if total_errors <= 0 and worst_return == 0 else 1


