def roughAnalysisPaths(argv: list[str] | None = None) -> list[Path]:
    paths: list[Path] = []
    for candidate in (BASE_DIR / 'start.py', BASE_DIR / 'trio.py'):
        if candidate.exists() and candidate not in paths:
            paths.append(candidate)
    return paths


def _roughRunCommand(command: list[str], *, env: dict[str, str] | None = None, timeout: int = 120):
    # Report-only diagnostic mode intentionally bypasses normal application launch.
    # Use a direct subprocess here because the lifecycle-wrapped launcher command
    # can create recursive process records before the lifecycle database is ready.
    # lifecycle-bypass-ok: explicit --rough diagnostic mode must not recursively enter the launcher lifecycle.
    return subprocess.run(  # lifecycle-bypass-ok  # phase-ownership-ok
        command,
        cwd=str(BASE_DIR),
        env=env or os.environ.copy(),
        capture_output=True,
        text=True,
        timeout=int(timeout or 120),
        check=False,
    )


def _roughProbeCommand(command: list[str], *, env: dict[str, str] | None = None) -> bool:
    try:
        completed = _roughRunCommand(command, env=env, timeout=20)
        return int(getattr(completed, 'returncode', 1) or 1) == 0
    except Exception as error:
        recordException('start.py:23458', sys.exc_info()[1])
        roughTrace(f'Ruff probe failed: {type(error).__name__}: {error}')
        return False


def _ruffCommandText(command: list[str]) -> str:
    return ' '.join(shlex.quote(str(part)) for part in list(command or []))


def ensurePipRuffInstalled() -> bool:
    registry = StartDependencyRegistry(['--headless'])
    executable = roughTargetPythonExecutable()
    if not executable:
        print(roughRed('[ROUGH] Cannot resolve a Python interpreter for Ruff installation.'), flush=True)
        return False
    packages = ['ruff']
    roughTrace('Ruff package missing; attempting dependency-managed pip install.')
    print(roughYellow('[ROUGH] Python Ruff package missing; attempting dependency-managed pip install ruff.'), flush=True)
    state = {'permission_error': False}
    attempts: list[dict[str, object]] = [
        {
            'enabled': registry.isWindows(),
            'label': 'windows ruff pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='windows ruff pip install'),
        },
        {
            'enabled': registry.isWindows(),
            'label': 'windows ruff user pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='windows ruff user pip install'),
        },
        {
            'enabled': registry.isWindows() and registry.isWindowsAdmin(),
            'predicate': lambda st: bool(st.get('permission_error')),
            'label': 'windows admin ruff pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='windows admin ruff pip install'),
        },
        {
            'enabled': registry.isWindows() and not registry.isWindowsAdmin(),
            'predicate': lambda st: bool(st.get('permission_error')),
            'label': 'windows elevated ruff pip install',
            'runner': lambda: (registry.attemptWindowsElevatedPipInstall(packages, pythonExecutable=executable), False),
        },
        {
            'enabled': registry.isLinux(),
            'label': 'linux ruff pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='linux ruff pip install', breakSystemPackages=True),
        },
        {
            'enabled': registry.isLinux(),
            'predicate': lambda st: bool(st.get('permission_error')),
            'label': 'linux ruff user pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='linux ruff user pip install'),
        },
        {
            'enabled': registry.isLinux(),
            'predicate': lambda st: bool(st.get('permission_error')),
            'label': 'linux sudo ruff pip install',
            'runner': lambda: (registry.attemptLinuxSudoPipInstall(packages, pythonExecutable=executable), False),
        },
        {
            'enabled': not registry.isWindows() and not registry.isLinux(),
            'label': 'generic ruff pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='generic ruff pip install'),
        },
        {
            'enabled': not registry.isWindows() and not registry.isLinux(),
            'label': 'generic ruff user pip install',
            'runner': lambda: registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='generic ruff user pip install'),
        },
    ]
    for attempt in attempts:
        if not bool(attempt.get('enabled')):
            continue
        predicate = attempt.get('predicate')
        if callable(predicate) and not bool(predicate(state)):
            continue
        label = str(attempt.get('label', 'ruff pip install') or 'ruff pip install')
        runner = attempt.get('runner')
        if not callable(runner):
            continue
        try:
            result = cast(Any, runner)()
            result_pair = cast(tuple[Any, Any], tuple(cast(Any, result)))
            succeeded, permission_error = result_pair
        except Exception as error:
            recordException('start.py:23542', sys.exc_info()[1])
            print(roughRed(f'[ROUGH] {label} failed: {type(error).__name__}: {error}'), flush=True)
            succeeded, permission_error = False, False
        state['permission_error'] = bool(state.get('permission_error')) or bool(permission_error)
        if succeeded:
            _dependencyInstallSuccess(registry)
            registry.syncPythonToolPaths()
            print(f"[ROUGH] pip install ruff: {coloredStatusText(STATUS_SUCCESS)} via {label}", flush=True)
            return True
        print(roughYellow(f'[ROUGH] {label} did not install Ruff.'), flush=True)
    return False



def ruffExecutableCandidates(registry: StartDependencyRegistry | None = None, pythonExecutable: str = EMPTY_STRING) -> list[str]:
    candidates: list[str] = []
    for value in (shutil.which('ruff.exe'), shutil.which('ruff')):
        if value and value not in candidates:
            candidates.append(value)
    try:
        executable = Path(str(pythonExecutable or roughTargetPythonExecutable() or sys.executable)).resolve()
        for name in ('ruff.exe', 'ruff') if os.name == 'nt' else ('ruff', 'ruff.exe'):
            candidate = str(executable.parent / name)
            if Path(candidate).exists() and candidate not in candidates:
                candidates.append(candidate)
    except Exception:
        recordException('start.py:23567', sys.exc_info()[1])
        _traceSwallowedException('start.py:22984', sys.exc_info()[1])
        pass
    try:
        active_registry = registry or StartDependencyRegistry(['--headless'])
        for directory in active_registry.targetPythonScriptDirectories():
            for name in ('ruff.exe', 'ruff') if os.name == 'nt' else ('ruff', 'ruff.exe'):
                candidate = str(Path(directory) / name)
                if Path(candidate).exists() and candidate not in candidates:
                    candidates.append(candidate)
    except Exception:
        recordException('start.py:23577', sys.exc_info()[1])
        _traceSwallowedException('start.py:22993', sys.exc_info()[1])
        pass
    return candidates

def resolveRuffCommand() -> tuple[list[str], str, dict[str, str]]:
    env = os.environ.copy()
    env_command = os.environ.get('TRIO_RUFF_COMMAND') or os.environ.get('TRIO_ROUGH_COMMAND')
    if env_command:
        command = shlex.split(env_command)
        if command and _roughProbeCommand([*command, '--version'], env=env):
            return command, 'TRIO_RUFF_COMMAND/TRIO_ROUGH_COMMAND', env
    registry = StartDependencyRegistry(['--headless'])
    python_executable = roughTargetPythonExecutable() or sys.executable
    for executable in ruffExecutableCandidates(registry, python_executable):
        if Path(executable).exists():
            return [executable], 'Ruff executable', env
    module_command = [python_executable, '-m', 'ruff']
    if _roughProbeCommand([*module_command, '--version'], env=env):
        return module_command, 'python -m ruff', env
    if not (os.environ.get('TRIO_ROUGH_NO_INSTALL') or os.environ.get('TRIO_RUFF_NO_INSTALL')):
        ensurePipRuffInstalled()
        registry.syncPythonToolPaths()
        env = os.environ.copy()
        for executable in ruffExecutableCandidates(registry, python_executable):
            if Path(executable).exists():
                return [executable], 'dependency-managed Ruff executable', env
        # Last resort only. Some environments expose a Ruff console script while
        # `python -m ruff` is slow or broken, so this stays behind executable probes.
        if _roughProbeCommand([*module_command, '--version'], env=env):
            return module_command, 'dependency-managed python -m ruff', env
    return [], EMPTY_STRING, env

def renderRoughReportHeader(paths: list[Path], source_label: str, command: list[str], return_code: int) -> str:
    return '\n'.join([
        'ROUGH / RUFF REPORT',
        '===================',
        '',
        f'Generated at: {datetime.datetime.now().isoformat(timespec="seconds")}',
        f'Project root: {BASE_DIR}',
        'Launcher: start.py',
        f'Bootstrapped target(s): {", ".join(path.name for path in paths if path.name != "start.py") or "<none detected>"}',
        f'Files requested: {", ".join(path.name for path in paths) or "<none>"}',
        f'Ruff source: {source_label or "<unresolved>"}',
        f'Command: {_ruffCommandText(command) if command else "<not run>"}',
        f'Exit code: {return_code}',
        '',
    ])


def runRoughAudit(launch_args: list[str] | None = None) -> int:
    paths = roughAnalysisPaths(launch_args)
    report_path = roughReportPath()
    log_path = roughLogReportPath()
    log_path.parent.mkdir(parents=True, exist_ok=True)
    if not paths:
        message = renderRoughReportHeader([], EMPTY_STRING, [], 1) + 'No analysis paths were found.\n'
        File(report_path).writeText(message)
        File(log_path).writeText(message)
        print(message, flush=True)
        return 1
    command_base, source_label, command_env = resolveRuffCommand()
    if not command_base:
        message = renderRoughReportHeader(paths, EMPTY_STRING, [], 2) + '\n'.join([
            'Ruff setup or execution failed.',
            'No runnable Ruff command was found. The launcher tried TRIO_RUFF_COMMAND/TRIO_ROUGH_COMMAND, PATH ruff, python -m ruff, and dependency-managed pip install ruff.',
            '',
        ])
        File(report_path).writeText(message)
        File(log_path).writeText(message)
        print(message, flush=True)
        print(f'[ROUGH] report: {report_path}', flush=True)
        return 2
    relative_files = [str(path.relative_to(BASE_DIR)) for path in paths]
    command = [*command_base, 'check', *relative_files]
    roughTrace('Starting real Ruff diagnostics; normal application startup is skipped.')
    try:
        completed = _roughRunCommand(command, env=command_env or os.environ.copy(), timeout=int(os.environ.get('TRIO_ROUGH_TIMEOUT', '900') or '900'))
        stdout_text = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING)
        stderr_text = str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
        return_code = int(getattr(completed, 'returncode', 0) or 0)
    except Exception:
        recordException('start.py:23658', sys.exc_info()[1])
        stdout_text = EMPTY_STRING
        stderr_text = traceback.format_exc()
        return_code = 2
    report_body = '\n'.join([
        'STDOUT:',
        stdout_text.rstrip() or '<empty>',
        '',
        'STDERR:',
        stderr_text.rstrip() or '<empty>',
        '',
        'NEXT STEPS:',
        '1. Read each Ruff diagnostic.',
        '2. Fix the smallest safe issue first.',
        '3. Re-run: python start.py --rough',
        '4. Repeat until Ruff reports: All checks passed!',
        '',
    ])
    report_text = renderRoughReportHeader(paths, source_label, command, return_code) + report_body
    File(report_path).writeText(report_text)
    File(log_path).writeText(report_text)
    print(report_text, flush=True)
    print(f'[ROUGH] report: {report_path}', flush=True)
    print(f'[ROUGH] log copy: {log_path}', flush=True)
    if return_code == 0:
        print(f"[ROUGH] lint scan: {coloredStatusText(STATUS_SUCCESS)} - Ruff reported no diagnostics.", flush=True)
    else:
        print(roughYellow(f'[ROUGH] lint scan completed with Ruff exit code {return_code}.'), flush=True)
    return return_code

def vultureRequested(argv: list[str] | None = None) -> bool:
    tokens = _start_cli_token_list(argv)
    env_value = str(os.environ.get('TRIO_VULTURE', EMPTY_STRING) or EMPTY_STRING).strip().lower()
    return bool(cliHasAnyFlag(tokens, VULTURE_FLAGS) or env_value in {'1', 'true', 'yes', 'y', 'on'})


def vultureTrace(message: str) -> None:
    print(f"[TRACE:vulture] {message}", flush=True)


def vultureYellow(text: str) -> str:
    return pyrightYellow(text)


def vultureGreen(text: str) -> str:
    return pyrightGreen(text)


def vultureRed(text: str) -> str:
    return pyrightRed(text)


def bundledVultureRootPath() -> Path:
    return BASE_DIR / 'vendor' / 'vulture'


def bundledVulturePackagePath() -> Path:
    return bundledVultureRootPath() / 'vulture'


def bundledVultureLooksPresent() -> bool:
    root = bundledVultureRootPath()
    return bool((root / 'pyproject.toml').is_file() and (root / 'vulture' / '__main__.py').is_file())


def vultureReportPath() -> Path:
    logs_dir = BASE_DIR / 'logs'
    try:
        logs_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        recordException('start.py:23727', sys.exc_info()[1])
        logs_dir = BASE_DIR
    return logs_dir / 'Vulture.txt'


def vultureTargetPythonExecutable() -> str:
    # Vulture is a launcher audit tool, so run it with the same interpreter that is running start.py.
    # That keeps vendored source imports deterministic and avoids accidentally probing a GUI child Python first.
    return str(sys.executable or EMPTY_STRING).strip()


def _vultureEnvForVendor() -> dict[str, str]:
    env = os.environ.copy()
    root_text = str(bundledVultureRootPath())
    existing = str(env.get('PYTHONPATH', EMPTY_STRING) or EMPTY_STRING).strip()
    env['PYTHONPATH'] = root_text + (os.pathsep + existing if existing else EMPTY_STRING)
    return env


def pythonVultureModuleLooksRunnable(python_executable: str, *, env: dict[str, str] | None = None) -> bool:
    executable = str(python_executable or EMPTY_STRING).strip()
    if not executable:
        return False
    try:
        completed = launcherRunCommand(
            [executable, '-m', 'vulture', '--version'],
            cwd=str(BASE_DIR),
            env=env or os.environ.copy(),
            capture_output=True,
            text=True,
            timeout=30,
            check=False,
        )
    except Exception as error:
        recordException('start.py:23760', sys.exc_info()[1])
        vultureTrace(f'Vulture probe failed before completion: {type(error).__name__}: {error}')
        return False
    ok = int(getattr(completed, 'returncode', 1)) == 0
    if ok:
        version_text = str(getattr(completed, 'stdout', EMPTY_STRING) or getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING).strip().splitlines()
        if version_text:
            vultureTrace(f'Vulture available: {version_text[0]}')
    return bool(ok)


def installPythonVulturePackage(python_executable: str) -> bool:
    global _VULTURE_INSTALL_ATTEMPTED
    if _VULTURE_INSTALL_ATTEMPTED:
        vultureTrace('Python Vulture pip install was already attempted in this launcher process.')
        return False
    _VULTURE_INSTALL_ATTEMPTED = True
    executable = str(python_executable or EMPTY_STRING).strip()
    if not executable:
        vultureTrace('Cannot pip install Vulture because no target Python executable was resolved.')
        return False
    packages = ['vulture']
    registry = StartDependencyRegistry([])
    vultureTrace('Python Vulture package missing; attempting dependency-managed pip install.')
    print(vultureYellow('[Vulture] Python package fallback missing; attempting pip install vulture.'), flush=True)
    if registry.isWindows():
        succeeded, permission_error = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='windows vulture pip install')
        if succeeded:
            print(f"[Vulture] pip install vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='windows vulture user pip install')
        if succeeded:
            print(f"[Vulture] pip install --user vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        if permission_error:
            succeeded = registry.attemptWindowsElevatedPipInstall(packages, pythonExecutable=executable)
            if succeeded:
                print(f"[Vulture] admin pip install vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
                return True
        return False
    if registry.isLinux():
        succeeded, permission_error = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='linux vulture pip install')
        if succeeded:
            print(f"[Vulture] pip install vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        if permission_error and registry.attemptLinuxSudoPipInstall(packages, pythonExecutable=executable):
            print(f"[Vulture] sudo pip install vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='linux vulture user pip install')
        if succeeded:
            print(f"[Vulture] pip install --user vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
            return True
        return False
    succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=False, label='vulture pip install')
    if succeeded:
        print(f"[Vulture] pip install vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
        return True
    succeeded, _ = registry.attemptPlainPipInstall(packages, pythonExecutable=executable, useUser=True, label='vulture user pip install')
    if succeeded:
        print(f"[Vulture] pip install --user vulture: {coloredStatusText(STATUS_SUCCESS)}", flush=True)
        return True
    return False


def resolveVultureCommand() -> tuple[list[str], str, dict[str, str] | None]:
    executable = vultureTargetPythonExecutable()
    if bundledVultureLooksPresent():
        vendor_env = _vultureEnvForVendor()
        if pythonVultureModuleLooksRunnable(executable, env=vendor_env):
            return [executable, '-m', 'vulture'], 'vendor/vulture', vendor_env
        vultureTrace('Vendored Vulture source tree is present but did not run.')
    if pythonVultureModuleLooksRunnable(executable):
        return [executable, '-m', 'vulture'], 'pip vulture', os.environ.copy()
    if installPythonVulturePackage(executable) and pythonVultureModuleLooksRunnable(executable):
        return [executable, '-m', 'vulture'], 'pip vulture', os.environ.copy()
    vulture_exe = shutil.which('vulture.exe') or shutil.which('vulture')
    if vulture_exe:
        return [vulture_exe], 'vulture command', os.environ.copy()
    return [], EMPTY_STRING, None


def vultureAnalysisPaths(argv: list[str] | None = None) -> list[Path]:
    paths: list[Path] = []
    for candidate in [Path(__file__).resolve(), primaryChildSourcePath().resolve(), BASE_DIR / 'data.py', BASE_DIR / 'hooks', BASE_DIR / 'languages']:
        try:
            resolved = Path(candidate).resolve()
        except Exception:
            recordException('start.py:23846', sys.exc_info()[1])
            resolved = Path(str(candidate or EMPTY_STRING))
        if resolved.exists() and resolved not in paths:
            paths.append(resolved)
    return paths


def vultureIgnoreNames() -> str:
    # TrioDesktop uses Qt signals, reflection, string dispatch, DB hooks, and generated callbacks heavily.
    # These broad names reduce obvious false positives while still showing real cleanup candidates.
    return ','.join([
        'visit_*', 'on*', 'On*', 'handle*', 'Handle*', 'slot*', 'Slot*',
        'show*', 'hide*', 'open*', 'close*', 'refresh*', 'reload*', 'export*',
        'import*', 'run*', 'main', 'headlessMain', 'start*', 'stop*', 'kill*',
        'to*', 'from*', 'as*', 'get*', 'set*', 'is*', 'has*', 'can*',
        'qt_*', 'Qt*', 'mouse*', 'key*', 'paint*', 'resize*', 'event*',
    ])


def vultureCommandArgs() -> list[str]:
    exclude_patterns = ','.join([
        '*/vendor/*', '*/__pycache__/*', '*/logs/*', '*/.git/*',
        '*/node_modules/*', '*/fonts/*', '*/tests/*', '*/test_*',
    ])
    ignore_decorators = ','.join(['@Slot', '@QtCore.Slot', '@pyqtSlot', '@app.route', '@*.route'])
    return [
        '--min-confidence', '80',
        '--sort-by-size',
        '--exclude', exclude_patterns,
        '--ignore-decorators', ignore_decorators,
        '--ignore-names', vultureIgnoreNames(),
    ]


def summarizeVultureReport(report_text: str) -> dict[str, int]:
    rows = [line for line in str(report_text or EMPTY_STRING).splitlines() if line.strip()]
    counts = {'total': len(rows), 'functions': 0, 'classes': 0, 'imports': 0, 'variables': 0, 'attributes': 0, 'unreachable': 0, 'other': 0}
    for line in rows:
        lowered = line.lower()
        if 'unused function' in lowered or 'unused method' in lowered:
            counts['functions'] += 1
        elif 'unused class' in lowered:
            counts['classes'] += 1
        elif 'unused import' in lowered:
            counts['imports'] += 1
        elif 'unused variable' in lowered:
            counts['variables'] += 1
        elif 'unused attribute' in lowered or 'unused property' in lowered:
            counts['attributes'] += 1
        elif 'unreachable code' in lowered:
            counts['unreachable'] += 1
        else:
            counts['other'] += 1
    return counts


def renderVultureReportHeader(paths: list[Path], source_label: str, command: list[str], return_code: int) -> str:
    lines = [
        'TrioDesktop Vulture Dead-Code Report',
        f'Generated: {datetime.datetime.now().isoformat(timespec="seconds")}',
        f'Source: {source_label}',
        f'Return code: {return_code}',
        'Mode: report-only; Vulture can produce false positives for Qt callbacks, dynamic dispatch, hooks, and reflection.',
        'Paths:',
    ]
    lines.extend(f'  - {path}' for path in paths)
    lines.append('Command:')
    lines.append('  ' + ' '.join(shlex.quote(str(part)) for part in command))
    lines.append('')
    lines.append('Findings:')
    return '\n'.join(lines) + '\n'


def runVultureAudit(argv: list[str] | None = None) -> int:
    launch_args = list(argv or [])
    print('[Vulture] Dead-code audit mode requested; application launch will be skipped.', flush=True)
    command_base, source_label, command_env = resolveVultureCommand()
    if not command_base:
        message = '[Vulture] No vendored, pip-installed, or global Vulture command was found.'
        print(vultureRed(message), flush=True)
        path = vultureReportPath()
        File(path).writeText(message + '\n')
        return 1
    paths = vultureAnalysisPaths(launch_args)
    if not paths:
        message = '[Vulture] No analysis paths were found.'
        print(vultureRed(message), flush=True)
        path = vultureReportPath()
        File(path).writeText(message + '\n')
        return 1
    command = [*command_base, *vultureCommandArgs(), *[str(path) for path in paths]]
    vultureTrace(f"Starting Vulture using {source_label}.")
    vultureTrace('Scanning for dead code...')
    try:
        completed = launcherRunCommand(command, cwd=str(BASE_DIR), env=command_env or os.environ.copy(), capture_output=True, text=True, timeout=900, check=False)
    except Exception as error:
        recordException('start.py:23941', sys.exc_info()[1])
        message = f'[Vulture] Audit failed before completion: {type(error).__name__}: {error}'
        print(vultureRed(message), flush=True)
        File(vultureReportPath()).writeText(message + '\n' + traceback.format_exc())
        return 1
    stdout_text = str(getattr(completed, 'stdout', EMPTY_STRING) or EMPTY_STRING)
    stderr_text = str(getattr(completed, 'stderr', EMPTY_STRING) or EMPTY_STRING)
    return_code = int(getattr(completed, 'returncode', 0) or 0)
    report_body = stdout_text.strip()
    if stderr_text.strip():
        report_body = (report_body + '\n\nStderr:\n' + stderr_text.strip()).strip()
    if not report_body:
        report_body = 'No dead-code candidates reported by Vulture.'
    report_path = vultureReportPath()
    report_text = renderVultureReportHeader(paths, source_label, command, return_code) + report_body.strip() + '\n'
    File(report_path).writeText(report_text)
    counts = summarizeVultureReport(stdout_text)
    if counts.get('total', 0) <= 0:
        print(f"[Vulture] dead-code scan: {coloredStatusText(STATUS_SUCCESS)} - no candidates reported.", flush=True)
    else:
        print(vultureYellow(f"[Vulture] dead-code scan completed with {counts['total']} candidate line(s)."), flush=True)
        print(vultureYellow(f"[Vulture] functions={counts['functions']} classes={counts['classes']} imports={counts['imports']} variables={counts['variables']} attributes={counts['attributes']} unreachable={counts['unreachable']} other={counts['other']}"), flush=True)
    print(f"[Vulture] report: {report_path}", flush=True)
    return 0

def _flatlineConsoleColor(text: object, code: str) -> str:
    value = str(text if text is not None else EMPTY_STRING)
    if consoleSupportsAnsi():
        return f"{ansi(code)}{value}{ansi('0')}"
    return value


def _flatlineFileModifiedIso(path: Path) -> str:
    try:
        return datetime.datetime.fromtimestamp(Path(path).stat().st_mtime).astimezone().isoformat()
    except Exception:
        recordException('start.py:23976', sys.exc_info()[1])
        return 'unavailable'


def _flatlineFileMd5(path: Path) -> str:
    try:
        return safeFileMd5Hex(Path(path)) or 'unavailable'
    except Exception:
        recordException('start.py:23983', sys.exc_info()[1])
        return 'unavailable'


def _flatlineBrailleHeartbeat() -> str:
    # Startup banner heartbeat: real Braille cells using the bundled console font.
    # No punctuation filler here; when Unicode is available the FlatLine banner
    # should look like the same Braille/glass-console surface as the live monitor.
    if consoleSupportsUnicode():
        return '⠁⠂⠄⡀⢀⠠⠐⠈  ⣿⣶⣤⣀⠈⠁⣀⣤⣶⣿  ⠈⠐⠠⢀⡀⠄⠂⠁'
    return r'__/^^\____/^^\____/^^\__'

def _flatlineFileIdentityLine(prefix: str, filename: str, pid: int, md5: str, mtime: str) -> str:
    return (
        f"{prefix}: "
        f"{_flatlineConsoleColor(filename, '1;92')}  "
        f"md5={_flatlineConsoleColor(md5, '1;96')}  "
        f"modified={_flatlineConsoleColor(mtime, '1;93')}  "
        f"pid={pid}"
    )



def startupTerminalFontHandshake(argv: list[str] | None = None) -> dict[str, object]:
    settings = terminalFontSettings()
    result: dict[str, object] = {'attempted': False, 'ok': False, 'desired': str(settings.get('face') or RECOMMENDED_TERMINAL_FONT), 'reason': EMPTY_STRING}
    try:
        noteTerminalFontConfigChange('font-handshake')
        font_path = bundledTerminalFontPath()
        desired = bundledTerminalFontFace(font_path)
        traceTerminalFontBundleState('font-handshake')
        traceFontFileState('font-handshake-source', font_path, 'active-terminal-font-source')
        settings = terminalFontSettings()
        result['desired'] = desired
        result['mode'] = str(settings.get('mode') or 'mono')
        before = detectConsoleFontInfo()
        host = str(before.get('host') or 'unknown')
        version = str(before.get('version') or 'unavailable')
        version_source = str(before.get('version_source') or 'unknown')
        shell_version = str(before.get('shell_version') or EMPTY_STRING)
        font_before = str(before.get('font') or '(unset)')
        font_size = str(before.get('font_size') or '(unknown)')
        source = str(before.get('source') or '(unknown)')
        path = str(before.get('path') or '(none)')
        print(f'Running on {host} version {version} (version source: {version_source})' + (f'  PowerShell={shell_version}' if shell_version else EMPTY_STRING), flush=True)
        print(f'Terminal font before change: {font_before}  size={font_size}  source={source}  path={path}', flush=True)
        print(f'Attempting to change terminal font to {desired} mode={settings.get("mode")} from {font_path}', flush=True)
        if os.name != 'nt':
            reason = 'not Windows; font switch skipped in this environment'
            print('Terminal font change ', end=EMPTY_STRING, flush=True)
            printStatus(STATUS_FAILED, str(reason or EMPTY_STRING))
            result['reason'] = reason
            return result
        installed_before = _detectFontInstalled(font_path, desired)
        print(f'Terminal font install before handshake: {installed_before}', flush=True)
        install_ok = bool(installed_before.get('installed') and installed_before.get('md5_match'))
        if bool(installed_before.get('installed')) and not bool(installed_before.get('md5_match')):
            print(f'[WARN:font] Installed {desired} exists but its MD5 does not match the bundled repaired font; reinstalling per-user copy. installed={installed_before}', file=sys.stderr, flush=True)
            traceCompilerStep('font-install-md5-gate', False, f'forcing reinstall because installed font md5 does not match source; installed={installed_before}')
        if not install_ok:
            print(f'Terminal font install: not found or stale; attempting per-user install for {desired}', flush=True)
            install_ok = _installFontForCurrentUser(font_path, desired)
            installed_after = _detectFontInstalled(font_path, desired)
            print(f'Terminal font install after repair/update: {installed_after}', flush=True)
            if bool(installed_after.get('stale')) and bool(installed_after.get('md5_match')):
                print(f'[WARN:font] A stale all-user TrioDesktop font is still present but a matching per-user font was installed. Restart the terminal or remove the stale C:\\Windows\\Fonts copy if Windows keeps choosing the old metrics. stale_paths={installed_after.get("stale_paths")}', file=sys.stderr, flush=True)
        else:
            print(f'Terminal font install: already present and MD5-matched {installed_before}', flush=True)
        apply_ok = applyRecommendedConsoleFont(desired)
        if os.name == 'nt':
            installed_verify = _detectFontInstalled(font_path, desired)
            print(f'Terminal font install verify after apply: {installed_verify}', flush=True)
            if bool(installed_verify.get('stale')):
                print(f'[WARN:font] Stale TrioDesktop font files still exist and may be chosen by Windows before the repaired per-user font. stale_paths={installed_verify.get("stale_paths")} md5_match_paths={installed_verify.get("md5_match_paths")}', file=sys.stderr, flush=True)
        after = detectConsoleFontInfo()
        font_after = str(after.get('font') or '(unset)')
        success = bool(apply_ok or font_after.lower() == desired.lower())
        result['attempted'] = True
        result['ok'] = success
        if success:
            reason = f'verified font={font_after} size={after.get("font_size", EMPTY_STRING) or "(unknown)"} source={after.get("source", EMPTY_STRING)}'
            print('Terminal font change ', end=EMPTY_STRING, flush=True)
            printStatus(STATUS_SUCCESS, str(reason or EMPTY_STRING))
            runtime_payload = _safeRuntimeSettingsPayload()
            if bool(settings.get('show_preview_on_change', True)):
                runtime_payload[FONT_PREVIEW_PENDING_RUNTIME_KEY] = True
                runtime_payload[FONT_PREVIEW_SHOWN_RUNTIME_KEY] = False
                runtime_payload[FONT_CHANGE_SOURCE_RUNTIME_KEY] = 'font-handshake-success'
                runtime_payload[FONT_ACK_RUNTIME_KEY] = desired
                runtime_payload['terminal_font_config_signature'] = terminalFontConfigSignature(settings)
                _writeRuntimeSettingsPayload(runtime_payload)
            if str(after.get('host') or EMPTY_STRING) == 'console-host':
                print('Terminal glyph proof after change: fire(U+1F525)=🔥  consolehost-bmp-fire(U+2668)=♨  private-fire(U+E525)=  A=A', flush=True)
                print('[WARN:font] Classic ConsoleHost can still reject or substitute non-BMP emoji such as U+1F525. TrioDesktop maps the same fire glyph to U+2668 and U+E525 for ConsoleHost-safe banners; Windows Terminal is the preferred host for real emoji.', file=sys.stderr, flush=True)
        else:
            reason = f'font did not verify; current={font_after}; size={after.get("font_size", EMPTY_STRING) or "(unknown)"}; source={after.get("source", EMPTY_STRING)}; install_ok={install_ok}; apply_ok={apply_ok}; detail={after.get("reason", EMPTY_STRING)}'
            print('Terminal font change ', end=EMPTY_STRING, flush=True)
            printStatus(STATUS_FAILED, str(reason or EMPTY_STRING))
            print('[WARN:font] Magic boxes can remain until the active Windows Terminal profile uses the installed TrioDesktop font. For Windows Terminal, open a new tab/window after the settings.json write; for classic PowerShell/ConsoleHost, shortcut properties can override HKCU\\Console.', file=sys.stderr, flush=True)
        result['reason'] = reason
        return result
    except Exception as error:
        recordException('start.py:24081', sys.exc_info()[1])
        reason = f'{type(error).__name__}: {error}'
        print('Terminal font change ', end=EMPTY_STRING, flush=True)
        printStatus(STATUS_FAILED, str(reason or EMPTY_STRING))
        result['reason'] = reason
        return result


def _flatlineClassicConsoleHostLikely() -> bool:
    try:
        if os.name != 'nt':
            return False
        info = detectConsoleFontInfo()
        host = str(info.get('host') or EMPTY_STRING).lower()
        source = str(info.get('source') or EMPTY_STRING).lower()
        return 'console' in host or 'console' in source or 'conhost' in host or 'conhost' in source
    except Exception:
        recordException('start.py:24096', sys.exc_info()[1])
        return False

def _flatlineFirePrefix() -> str:
    # Windows ConsoleHost commonly fails on non-BMP surrogate-pair emoji even
    # after the font is set. The repaired default.otf maps U+2668 to
    # the same fire glyph as U+1F525, so legacy ConsoleHost gets a BMP-safe
    # fire-looking banner instead of magic boxes. Windows Terminal and modern
    # hosts can keep the real emoji code point.
    forced = str(os.environ.get('TRIO_FORCE_EMOJI_BANNER', EMPTY_STRING) or EMPTY_STRING).strip().lower()
    if forced in {'1', 'true', 'yes', 'y', 'on'}:
        return '🔥🔥🔥'
    if _flatlineClassicConsoleHostLikely():
        return '♨♨♨'
    return '🔥🔥🔥'

