def bootstrapBanner(argv: list[str]) -> None:
    if _start_chat_cli_quiet_requested(argv):
        return
    # Keep these as the first three launcher identity lines. The terminal/font
    # handshake deliberately starts on the next line so magic-box/debug output
    # never hides the basic FlatLine identity block again.
    launcher_path = Path(__file__).resolve()
    pid = os.getpid()
    launcher_md5 = _flatlineFileMd5(launcher_path)
    launcher_mtime = _flatlineFileModifiedIso(launcher_path)
    try:
        child_path = Path(primaryChildPath()).resolve()
    except Exception:
        recordException('start.py:24148', sys.exc_info()[1])
        child_path = BASE_DIR / primaryChildFileName()
    child_md5 = _flatlineFileMd5(child_path)
    child_mtime = _flatlineFileModifiedIso(child_path)
    child_label = child_path.name or (primaryChildFileName() if callable(primaryChildFileName) else 'trio.py')
    fire = _flatlineConsoleColor(_flatlineFirePrefix(), '1;91')
    title = _flatlineConsoleColor(f'FlatLine Debugger v{DEBUGGER_VERSION}', '1;92')
    heartbeat = _flatlineConsoleColor(_flatlineBrailleHeartbeat(), '1;92')
    print(f'{fire} {title} {heartbeat}', flush=True)
    print(_flatlineFileIdentityLine('start.py', launcher_path.name, pid, launcher_md5, launcher_mtime), flush=True)
    print(_flatlineFileIdentityLine('bootstrap', child_label, pid, child_md5, child_mtime), flush=True)
    if not cliHasAnyFlag(argv, CHAT_TEST_FLAGS) and not diagnosticPageRequested(argv):
        startupTerminalFontSnapshot(argv)


def _writeEarlyVerboseHeader(argv: list[str]) -> None:
    if not traceVerboseRequested(argv):
        return
    try:
        log_dir = launcherLogDir()
        log_dir.mkdir(parents=True, exist_ok=True)
        verbose_path = log_dir / 'verbose.log'
        launcher_md5 = safeFileMd5Hex(Path(__file__).resolve()) or 'unavailable'
        ts = datetime.datetime.now().astimezone().isoformat()
        header_lines = [
            '# FlatLineDebugger verbose.log',
            f'# version={DEBUGGER_VERSION} pid={os.getpid()} timestamp={ts}',
            f'# launcher={Path(__file__).name} md5={launcher_md5}',
            f'# argv={argv!r}',
            '# (early header — written before bootstrap phases run)',
            '# ---',
            EMPTY_STRING,
        ]
        File(verbose_path).writeText('\n'.join(header_lines))
        print(f'[TRACE:verbose] header written {verbose_path}', flush=True)
    except Exception as err:
        recordException('start.py:24182', sys.exc_info()[1])
        print(f'[TRACE:verbose] header write failed {type(err).__name__}: {err} {statusText(STATUS_FAILED)}', file=sys.stderr, flush=True)


