def runTerminalFontWorker(argv: list[str] | None = None) -> int:
    print(f'[TRACE:font-worker] started pid={os.getpid()}', file=sys.stderr, flush=True)
    try:
        result = startupTerminalFontHandshake(list(argv or []))
        ok = bool(result.get('ok'))
        reason = str(result.get("reason", EMPTY_STRING) or EMPTY_STRING)
        print(f'[TRACE:font-worker] complete ok={ok} reason={reason}', file=sys.stderr, flush=True)
        if not ok:
            print(f'[WARN:font-worker] optional terminal font update skipped/failed without blocking startup: {reason}', file=sys.stderr, flush=True)
        # Terminal font setup is cosmetic.  It must not create scary errored
        # process rows or block the debugger/chat path when Windows refuses a
        # registry/font update.  The warning above is the durable evidence.
        return 0
    except BaseException as error:
        recordException('start.py:24209', sys.exc_info()[1])
        print('[WARN:font-worker] optional terminal font worker failed without blocking startup: ' + ''.join(traceback.format_exception(type(error), error, error.__traceback__)), file=sys.stderr, flush=True)
        return 0

