def runDependencyWorker(argv: list[str] | None = None) -> int:
    raw = str(os.environ.get('TRIO_DEPENDENCY_WORKER_ARGS_JSON', EMPTY_STRING) or EMPTY_STRING).strip()
    try:
        worker_args = json.loads(raw) if raw else list(argv or [])
        if not isinstance(worker_args, list):
            worker_args = list(argv or [])
    except Exception:
        recordException('start.py:24223', sys.exc_info()[1])
        worker_args = list(argv or [])
    worker_args = [str(item or EMPTY_STRING) for item in list(worker_args or []) if str(item or EMPTY_STRING).strip()]
    print(f'[TRACE:deps-worker] started pid={os.getpid()} args={len(worker_args)}', file=sys.stderr, flush=True)
    try:
        registry = StartDependencyRegistry(worker_args)
        if str(os.environ.get('TRIO_CRITICAL_PYTHON_DEPS_ONLY', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'y', 'on'}:
            registry.installMissingCriticalPythonDependencies()
        else:
            registry.installMissingDependencies()
        remaining = registry.missingPythonDependencyEntries()
        if remaining:
            remaining_names = ', '.join(str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING) for entry in remaining)
            print(f'[WARN:deps-worker] remaining missing imports after install attempts: {remaining_names}', file=sys.stderr, flush=True)
            critical = registry.launcherCriticalImportNames()
            if any(str(entry.get('import_name', EMPTY_STRING) or EMPTY_STRING) in critical for entry in remaining):
                return 2
        print('[TRACE:deps-worker] complete', file=sys.stderr, flush=True)
        return 0
    except BaseException as error:
        recordException('start.py:24242', sys.exc_info()[1])
        print('[FATAL:deps-worker] ' + ''.join(traceback.format_exception(type(error), error, error.__traceback__)), file=sys.stderr, flush=True)
        return 1


def shouldPrintEarlyStartupBanner(argv: list[str] | None = None) -> bool:
    tokens = _start_cli_token_list(argv)
    if not tokens:
        return True
    skip_groups = [
        CHILD_VERSION_FLAGS,
        CHILD_HELP_FLAGS,
        FONT_WORKER_FLAGS,
        STARTUP_TOOLS_WORKER_FLAGS,
        DEPENDENCY_WORKER_FLAGS,
        CHAT_TEST_WORKER_FLAGS,
        MODEL_CATALOG_WORKER_FLAGS,
        ROUGH_FLAGS,
        MONKEY_PATCH_FLAGS,
        RECURSION_FLAGS,
        RAW_SQL_FLAGS,
        COMPORT_FLAGS,
        SWALLOWED_EXCEPTION_FLAGS,
        LIFECYCLE_BYPASS_FLAGS,
        REPAIR_FONT_FLAGS,
        FONT_METADATA_FLAGS,
        UPDATE_FONT_METADATA_FLAGS,
        EXTRACT_GLYPH_FLAGS,
        CLEAN_FLAGS,
    ]
    for aliases in skip_groups:
        try:
            if cliHasAnyFlag(tokens, aliases):
                return False
        except Exception:
            recordException('start.py:24273', sys.exc_info()[1])
            _traceSwallowedException('start.py:23689', sys.exc_info()[1])
            continue
    return True


def _launchFlatlineTerminal() -> None:
    """If terminal.flatline_terminal=true, pipe stdout/stderr into a local Qt terminal helper when present."""
    if not configBool('terminal', 'flatline_terminal', False):
        return
    terminal_script = BASE_DIR / 'classes' / '_terminal.py'
    if not terminal_script.exists():
        terminal_script = BASE_DIR / '_terminal.py'
    if not terminal_script.exists():
        return
    print('Launching FlatLine Terminal...', flush=True)
    try:
        proc = monitoredRawPopen(
            [sys.executable, str(terminal_script), '--wait-ready'],
            sourceLine='_launchFlatlineTerminal -> terminal helper',
            windowPolicy=WINDOW_POLICY_QT_CHILD,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            encoding='utf-8',
            errors='replace',
        )
        started = time.monotonic()
        ready = False
        while time.monotonic() - started < 5.0:
            line = proc.stdout.readline() if proc.stdout is not None else ''
            if not line:
                if proc.poll() is not None:
                    break
                time.sleep(0.05)
                continue
            if 'READY' in line.upper():
                ready = True
                break
        if not ready or proc.stdin is None:
            try:
                proc.terminate()
            except Exception:
                recordException('start.py:flatline-terminal-terminate', sys.exc_info()[1], handled=True)
            return
        pipe = proc.stdin
        original_stdout = sys.stdout
        original_stderr = sys.stderr

        def _pipe_write(text: str) -> None:
            try:
                pipe.write(str(text))
                pipe.flush()
            except Exception:
                try:
                    original_stdout.write(str(text))
                    original_stdout.flush()
                except Exception:
                    recordException('start.py:flatline-terminal-pipe-fallback-write', sys.exc_info()[1], handled=True)

        class _TerminalTee:
            def __init__(self, fallback):
                self.fallback = fallback
                self.encoding = getattr(fallback, 'encoding', 'utf-8')
                self.errors = getattr(fallback, 'errors', 'replace')

            def write(self, data):
                value = str(data)
                _pipe_write(value)
                try:
                    self.fallback.write(value)
                except Exception:
                    recordException('start.py:flatline-terminal-fallback-write', sys.exc_info()[1], handled=True)
                return len(value)

            def flush(self):
                try:
                    pipe.flush()
                except Exception:
                    recordException('start.py:flatline-terminal-pipe-flush', sys.exc_info()[1], handled=True)
                try:
                    self.fallback.flush()
                except Exception:
                    recordException('start.py:flatline-terminal-fallback-flush', sys.exc_info()[1], handled=True)

            def isatty(self):
                return False

        import builtins as _builtins
        original_print = _builtins.print

        def _terminal_print(*args, sep=' ', end='\n', file=None, flush=False):
            if file not in (None, sys.stdout, sys.stderr):
                return original_print(*args, sep=sep, end=end, file=file, flush=flush)
            rendered = sep.join(str(arg) for arg in args) + end
            _pipe_write(rendered)
            target = original_stderr if file is sys.stderr else original_stdout
            try:
                original_print(rendered, end='', file=target, flush=flush)
            except Exception:
                try:
                    target.write(rendered)
                    if flush:
                        target.flush()
                except Exception:
                    recordException('start.py:flatline-terminal-print-fallback', sys.exc_info()[1], handled=True)

        _builtins.print = _terminal_print  # type: ignore[assignment]
        sys.stdout = _TerminalTee(original_stdout)  # type: ignore[assignment]  # monkeypatch-ok: intentional parent terminal/stdout mirror
        sys.stderr = _TerminalTee(original_stderr)  # type: ignore[assignment]  # monkeypatch-ok: intentional parent terminal/stderr mirror
    except Exception as error:
        recordException('start.py:flatline-terminal-launch', sys.exc_info()[1], handled=True)
        print(f'[WARNING:terminal] Could not launch FlatLine Terminal: {type(error).__name__}: {error}', flush=True)


def pauseBeforeClose(reason: str = '') -> None:
    if os.environ.get('TRIO_NO_PAUSE_ON_EXIT') or os.environ.get('CUTIEPY_NO_PAUSE_ON_EXIT'):
        return
    argv_text = ' '.join(str(arg or '').lower() for arg in sys.argv[1:])
    automated = any(flag in argv_text for flag in ('--version', '--usage', '--help', '--chat-test-worker', '--model-catalog-worker'))
    should_pause = os.name == 'nt' and (not automated or os.environ.get('TRIO_PAUSE_ON_EXIT') or os.environ.get('CUTIEPY_PAUSE_ON_EXIT'))
    if not should_pause:
        return
    try:
        print('\n' + (reason or 'TrioDesktop startup ended.') + '\nPress any key to close...', file=sys.stderr, flush=True)
        msvcrt = cast(Any, runtimeImportModule('msvcrt'))
        msvcrt.getch()
    except Exception:
        try:
            input('\nPress Enter to close...')
        except Exception:
            recordException('start.py:pause-before-close-input', sys.exc_info()[1], handled=True)


def _cleanPycache() -> None:
    """Clean local __pycache__ folders without walking heavy vendored payloads.

    v1274 avoided vendor/node/.git trees here. Keep that bug fix because the
    Trio repo can contain large vendored detector/deb payloads and --version
    must not hang after printing.
    """
    try:
        argv_text = ' '.join(str(arg or EMPTY_STRING).lower() for arg in sys.argv[1:])
        if any(flag in argv_text for flag in ('--version', '-version', '/version', '--help', '-help', '/help', '--usage', '-usage', '/usage')):
            return
        skipped = {'__pycache__', '.git', 'node_modules', 'vendor', 'debs', 'dist', 'build', '.mypy_cache', '.ruff_cache'}
        removed = 0
        for root, dirs, _files in os.walk(BASE_DIR):
            dirs[:] = [name for name in dirs if name not in skipped]
            if '__pycache__' in dirs:
                target = Path(root) / '__pycache__'
                try:
                    shutil.rmtree(target, ignore_errors=True)
                    removed += 1
                except Exception:
                    recordException('start.py:flatline-v1274-clean-pycache-rmtree', sys.exc_info()[1], handled=True)
                dirs[:] = [name for name in dirs if name != '__pycache__']
        if removed:
            print(f'[TRACE:pycache] removed {removed} __pycache__ director{"y" if removed == 1 else "ies"} (flatline-clean-pycache)', flush=True)
    except Exception:
        recordException('start.py:flatline-v1274-clean-pycache', sys.exc_info()[1], handled=True)

def main() -> int:  # phase-hooks-ok
    argv = list(sys.argv[1:])
    if _start_chat_cli_quiet_requested(argv):
        if chatTestWorkerRequested(argv):
            return int(runChatTestWorker(argv))
        return int(runCliChat(argv))
    _launchFlatlineTerminal()  # phase-hooks-ok: FlatLine terminal transport is the parent debugger console bootstrap before lifecycle construction.
    if shellRpcWorkerRequested(argv):
        return int(runShellRpcWorker(argv))
    if cliHasAnyFlag(argv, CHILD_VERSION_FLAGS):
        print(startVersionText(), flush=True)
        return 0
    if pyriteRequested(argv):
        return int(runPyriteAudit(argv))
    early_banner_printed = False
    if shouldPrintEarlyStartupBanner(argv):
        bootstrapBanner(argv)
        early_banner_printed = True
    controller = StartLifecycleController(argv)
    globals()['LAST_START_CONTROLLER'] = controller
    if early_banner_printed:
        setattr(controller, '_earlyBannerPrinted', True)
    return int(controller.run())




# --- TrioDebugger method recovery patch (regenerated) ---

# Several debugger methods were stranded in DebuggerDatabase or nested under
# collectRuntimeDbPayload(). Rebind/recover them onto TrioDebugger so the
# launcher/debugger can actually run.

def _debugger_collectRuntimeDbPayload(self, payload: dict | None) -> dict[str, str]:
    return collectRuntimeDbPayload(payload)


def _debugger_resolveMariaDbStatusTarget(self) -> tuple[str, str, str, str, str]:
    host = str(os.environ.get('TRIO_DB_HOST', EMPTY_STRING) or EMPTY_STRING).strip()
    port = str(os.environ.get('TRIO_DB_PORT', EMPTY_STRING) or EMPTY_STRING).strip()
    user = str(os.environ.get('TRIO_DB_USER', EMPTY_STRING) or EMPTY_STRING).strip()
    database = str(os.environ.get('TRIO_DB_NAME', EMPTY_STRING) or EMPTY_STRING).strip()
    source = 'env'
    if any((host, port, user, database)):
        return host, port, user, database, source
    try:
        if not RUNTIME_SETTINGS_PATH.exists():
            return EMPTY_STRING, EMPTY_STRING, EMPTY_STRING, EMPTY_STRING, 'missing runtime settings'
        payload = json.loads(File(RUNTIME_SETTINGS_PATH).readText() or '{}')
        dbPayload = collectRuntimeDbPayload(payload)
        return (
            str(dbPayload.get('host', EMPTY_STRING) or EMPTY_STRING).strip(),
            str(dbPayload.get('port', EMPTY_STRING) or EMPTY_STRING).strip(),
            str(dbPayload.get('user', EMPTY_STRING) or EMPTY_STRING).strip(),
            str(dbPayload.get('database', EMPTY_STRING) or EMPTY_STRING).strip(),
            'runtime settings',
        )
    except Exception:
        recordException('start.py:24321', sys.exc_info()[1])
        return EMPTY_STRING, EMPTY_STRING, EMPTY_STRING, EMPTY_STRING, 'unavailable'



def _debugger_configureTraceVerbose(self, argv=None):
    self.traceArgv = list(argv or [])
    self.traceVerbose = bool(traceVerboseRequested(argv))
    self.traceVerboseTs = bool(traceVerboseTimestampRequested(argv))
    self.traceVerboseFilePath = str(traceVerboseFileValue(argv) or EMPTY_STRING).strip()
    _traceVerboseConfigureBuffers(self)
    return self.traceVerbose


def _debugger_traceVerboseSourceLine(self, line_no) -> str:
    return _traceVerboseSourceLineForTarget(self, line_no)


def _debugger_tryFormatTraceVerboseLine(self, text: str) -> str | None:
    content = str(text or EMPTY_STRING).strip()
    if not self.traceVerbose or not content:
        return None
    marker = '__TRIO_TRACE_VERBOSE__|'
    if content.startswith(marker):
        payload = content[len(marker):]
        parts = payload.split('|')
        line_no = str(parts[0] if parts else EMPTY_STRING).strip() or '?'
        elapsed = str(parts[1] if len(parts) >= 2 else EMPTY_STRING).strip()
        wall = str(parts[2] if len(parts) >= 3 else EMPTY_STRING).strip()
        source_line = self.traceVerboseSourceLine(line_no)
        _traceVerboseQueueFileLine(self, source_line)
        if wall:
            return f'[trace] line={line_no} elapsed={elapsed}s ts={wall} :: {source_line}' if source_line else f'[trace] line={line_no} elapsed={elapsed}s ts={wall}'
        if elapsed:
            return f'[trace] line={line_no} elapsed={elapsed}s :: {source_line}' if source_line else f'[trace] line={line_no} elapsed={elapsed}s'
        return f'[trace] line={line_no} :: {source_line}' if source_line else f'[trace] line={line_no}'
    return content




# --- Process-only architecture repair v1.0.22 ---
# Windows multiprocessing uses spawn and cannot pickle bound methods, lambdas, or
# local functions.  These overrides keep FlatLine alive by avoiding fake
# callback-backed "processes" in the parent debugger.  Real long-running work
# must be a command-line StartProcess worker role.

def _debugger_startKernel_process_zero(self):
    if not self.enabled:
        return
    try:
        self.installParentStackTracing()
    except Exception as error:
        recordException('start.py:24373', sys.exc_info()[1])
        self.emit(f'[FlatLineDebugger.debugger] Parent stack tracing disabled: {error}', self.exceptionPath)
    try:
        self.emit('[FlatLineDebugger.debugger] Kernel running in parent-supervised process mode with explicit subprocess workers.', self.logPath)
        self.emit('[FlatLineDebugger.debugger] Key binding active: D -> debugger console (parent wait-loop poll)', self.logPath)
        self.emit('[FlatLineDebugger.debugger] Relay/socket/status workers use explicit subprocess roles where runtime background work is required.', self.logPath)
    except Exception:
        recordException('start.py:24379', sys.exc_info()[1])
        _traceSwallowedException('start.py:23792', sys.exc_info()[1])
        pass
    return True



def _start_lifecycle_column_specs_for_table(table_name: str) -> dict[str, str]:
    if table_name in {'processes', 'debugger_processes'}:
        return {
            'exception_type': 'TEXT',
            'exception_message': 'TEXT',
            'traceback_text': 'TEXT',
            'command_text': 'TEXT',
            'cwd': 'TEXT',
            'runtime_seconds': 'FLOAT',
            'meta_json': 'TEXT',
            'updated_at': 'DATETIME',
        }
    if table_name in {'faults', 'exceptions'}:
        return {
            'worker': 'TEXT',
            'pid': 'INTEGER',
        }
    return {}


def _start_lifecycle_existing_columns(db, table_name: str) -> set[str]:
    columns: set[str] = set()
    engine = getattr(db, 'engine', None)
    if engine is None:
        return columns
    with engine.connect() as connection:
        try:
            dialect = getattr(engine, 'dialect', None)
            dialect_name = str(getattr(dialect, 'name', EMPTY_STRING)).lower()
            if dialect_name == 'sqlite':
                rows = connection.exec_driver_sql(f'PRAGMA table_info({table_name})').fetchall()
                for row in rows:
                    try:
                        columns.add(str(row[1]))
                    except Exception:
                        recordException('start.py:24420', sys.exc_info()[1])
                        _traceSwallowedException('start.py:23832', sys.exc_info()[1])
                        pass
            else:
                rows = connection.exec_driver_sql(f'SHOW COLUMNS FROM {table_name}').fetchall()
                for row in rows:
                    try:
                        columns.add(str(row[0]))
                    except Exception:
                        recordException('start.py:24428', sys.exc_info()[1])
                        _traceSwallowedException('start.py:23839', sys.exc_info()[1])
                        pass
        except Exception:
            recordException('start.py:24431', sys.exc_info()[1])
            _traceSwallowedException('start.py:23841', sys.exc_info()[1])
            pass
    return columns


def _start_lifecycle_ensure_columns(db, table_name: str) -> None:
    specs = _start_lifecycle_column_specs_for_table(table_name)
    if not specs:
        return
    engine = getattr(db, 'engine', None)
    if engine is None:
        return
    existing = _start_lifecycle_existing_columns(db, table_name)
    missing = [name for name in specs if name not in existing]
    if not missing:
        return
    with engine.begin() as connection:
        for name in missing:
            ddl = specs[name]
            try:
                connection.exec_driver_sql(f'ALTER TABLE {table_name} ADD COLUMN {name} {ddl}')
                print(f'[TRACE:start-schema] added column {table_name}.{name} {ddl}', file=sys.stderr, flush=True)
            except Exception as error:
                recordException('start.py:24454', sys.exc_info()[1])
                print(f'[WARN:start-schema] add column {table_name}.{name} failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)


def _start_lifecycle_ensureProcessTable_v1022(self):
    db = self.ormDatabase()
    db.EnsureTables([DebuggerFaultRecordOrm, DebuggerExceptionRecordOrm, ProcessRecordOrm, DebuggerProcessRecordOrm])
    for table_name in ('faults', 'exceptions', 'processes', 'debugger_processes'):
        try:
            _start_lifecycle_ensure_columns(db, table_name)
        except Exception as error:
            recordException('start.py:24464', sys.exc_info()[1])
            print(f'[WARN:start-schema] ensure columns for {table_name} failed: {type(error).__name__}: {error}', file=sys.stderr, flush=True)
    return db



# --- Snapshot capture phase repair v1.0.23 ---
# Manual debugger entry needs a snapshot, but snapshot capture cannot be
# launched by pickling bound methods or local callables on Windows spawn.  This
# stays in the debugger parent because it must use the live child connection
# and parent DB handles, but it is explicitly marked as a parent-owned phase so
# it no longer trips the legacy callback-worker guard.
def _debugger_startSnapshotCapture_parent_phase(self, payload: dict | None):
    info = dict(payload or {})
    phase_key = 'snapshot-capture-parent-phase'
    try:
        self.write(self.logPath, '[TRACE:snapshot-capture] parent-inline phase started; snapshot uses live debugger handles and is intentionally not spawned as a pickle worker.\n')
    except Exception:
        recordException('start.py:24481', sys.exc_info()[1])
        _traceSwallowedException('start.py:23890', sys.exc_info()[1])
        pass
    marker = StartWorkerProcess(target=None, name='TrioSnapshotCaptureParentPhase', daemon=False)
    marker._startTime = time.monotonic()
    marker._result = None
    marker._error = None
    try:
        self.registerManagedProcess(
            phase_key,
            marker,
            name='TrioSnapshotCaptureParentPhase',
            daemon=False,
            details='capture debugger snapshot in parent phase because it needs live child/debugger handles',
            meta={'role': 'snapshot-capture', 'mode': 'parent-phase'},
        )
    except Exception:
        recordException('start.py:24497', sys.exc_info()[1])
        _traceSwallowedException('start.py:23905', sys.exc_info()[1])
        pass
    try:
        if self.childSurfaceSupported('vardump', default=False):
            try:
                self.requestChildSnapshot(command='vardump', timeout=0.90, reason=str(info.get('type_name', 'pre-console')))
            except Exception as surface_error:
                recordException('start.py:24504', sys.exc_info()[1])
                try:
                    self.emit(f'[WARN:snapshot-capture] child vardump surface failed: {type(surface_error).__name__}: {surface_error}', self.exceptionPath)
                except Exception:
                    recordException('start.py:24507', sys.exc_info()[1])
                    _traceSwallowedException('start.py:23914', sys.exc_info()[1])
                    pass
        try:
            self.capturePreConsoleSnapshot(info)
        except Exception as capture_error:
            recordException('start.py:24512', sys.exc_info()[1])
            try:
                self.emit(f'[FlatLineDebugger.debugger] Snapshot capture failed: {capture_error}', self.exceptionPath)
            except Exception:
                recordException('start.py:24515', sys.exc_info()[1])
                _traceSwallowedException('start.py:23921', sys.exc_info()[1])
                pass
            marker._error = capture_error
            raise
        marker._result = 'complete'
        try:
            self.updateManagedProcessInfo(phase_key, status='complete', endedAt=float(time.time()), lastError=EMPTY_STRING)
        except Exception:
            recordException('start.py:24523', sys.exc_info()[1])
            _traceSwallowedException('start.py:23928', sys.exc_info()[1])
            pass
        try:
            self.write(self.logPath, '[TRACE:snapshot-capture] parent-inline phase complete.\n')
        except Exception:
            recordException('start.py:24528', sys.exc_info()[1])
            _traceSwallowedException('start.py:23932', sys.exc_info()[1])
            pass
    except Exception as error:
        recordException('start.py:24531', sys.exc_info()[1])
        marker._error = error
        marker.tracebackText = ''.join(traceback.format_exception(type(error), error, error.__traceback__))
        try:
            self.updateManagedProcessInfo(phase_key, status='failed', endedAt=float(time.time()), lastError=str(error), tracebackText=marker.tracebackText)
        except Exception:
            recordException('start.py:24536', sys.exc_info()[1])
            _traceSwallowedException('start.py:23939', sys.exc_info()[1])
            pass
    self.snapshotProcess = marker
    return marker



# --- Debugger console safety repair v1.0.25 ---
def _debugger_ensureConsoleBuffer_v1025(self) -> None:
    if not hasattr(self, '_consoleBuffer') or getattr(self, '_consoleBuffer', None) is None:
        self._consoleBuffer = []
    if not hasattr(self, '_consoleBufferLock') or getattr(self, '_consoleBufferLock', None) is None:
        self._consoleBufferLock = processsync.Lock()


def _debugger_renderParentFrames_safe_v1025(self, include_locals: bool = False) -> str:
    lines = [f"[FlatLineDebugger.debugger] Parent process stack dump  PID={os.getpid()}", EMPTY_STRING]
    try:
        current_frame = sys._getframe(1)
        stack = [
            item for item in reversed(list(traceback.StackSummary.extract(traceback.walk_stack(current_frame))))
            if str(getattr(item, 'name', EMPTY_STRING) or EMPTY_STRING) not in {'_debugger_renderParentFrames_safe_v1025', 'renderParentFrames'}
        ]
    except Exception as error:
        recordException('start.py:24557', sys.exc_info()[1])
        lines.append(f"  <parent stack failed: {type(error).__name__}: {error}>")
        return '\n'.join(lines).rstrip() + '\n'
    lines.append(f"  --- ParentProcess: {processsync.current_process().name}  pid={os.getpid()} ---")
    for item in stack:
        function_name = str(getattr(item, 'name', EMPTY_STRING) or EMPTY_STRING)
        if function_name in {'_debugger_renderParentFrames_safe_v1025', 'renderParentFrames'}:
            continue
        lines.append(f'    File "{item.filename}", line {item.lineno}, in {item.name}')
        source = str(item.line or EMPTY_STRING).strip()
        if source and 'StackSummary.extract' not in source and 'walk_stack' not in source:
            lines.append(f'      {source}')
    if include_locals:
        try:
            frame_now = sys._getframe()
            for key, value in list(getattr(frame_now, 'f_locals', {}).items())[:40]:
                lines.append(f'      {key} = {safeRepr(value)}')
        except Exception as local_error:
            recordException('start.py:24571', sys.exc_info()[1])
            lines.append(f'      <locals failed: {type(local_error).__name__}: {local_error}>')
    lines.append(EMPTY_STRING)
    return '\n'.join(lines).rstrip() + '\n'


def _debugger_openInlineManualDebugConsole_safe_v1025(self, payload: dict | None = None) -> bool:
    if not sys.stdin.isatty():
        return False
    _debugger_ensureConsoleBuffer_v1025(self)
    self.crashInfo = dict(payload or {})
    if _debugger_is_real_crash_payload(self.crashInfo):
        self.lastRealCrashInfo = dict(self.crashInfo)
    self.lastOpenedSignature = self.crashSignature(self.crashInfo)
    self.inCrashConsole = True
    self.consoleDone.clear()
    self.emitCrashContextPreludeOnce(context_lines=10)
    self.printBanner()
    try:
        self.startSnapshotCapture(self.crashInfo)
    except Exception:
        recordException('start.py:inline-manual-snapshot', sys.exc_info()[1], handled=True)
    buf = _ConsoleOutputBuffer(self)
    try:
        while self.inCrashConsole and not self.consoleStop.is_set():
            try:
                raw = input(buf.prompt_line())
            except EOFError:
                recordException('start.py:24592', sys.exc_info()[1])
                raw = 'q'
            except KeyboardInterrupt:
                recordException('start.py:24594', sys.exc_info()[1])
                raw = 'q'
            command = self.normalizeConsoleCommand(str(raw or EMPTY_STRING))
            if not command:
                continue
            if command.lower() in ('u', 'update'):
                buf.flush_buffer()
                continue
            buf.flush_buffer()
            try:
                output = self.dispatchConsoleCommand(command, interactive=True)
            except Exception as error:
                recordException('start.py:24605', sys.exc_info()[1])
                output = f'[FlatLineDebugger.debugger] Command failed but debugger console is still alive: {type(error).__name__}: {error}'
                try:
                    self.emit(output, self.exceptionPath)
                except Exception:
                    recordException('start.py:24609', sys.exc_info()[1])
                    _traceSwallowedException('start.py:24011', sys.exc_info()[1])
                    pass
            if output:
                print(output, flush=True)
                self.write(self.logPath, output + ('\n' if not str(output).endswith('\n') else EMPTY_STRING))
            if command.lower() in ('q', 'quit', 'exit'):
                self.inCrashConsole = False
                self.consoleDone.set()
                self.consoleSnoozeUntil = time.time() + 3.0
                return True
        return True
    finally:
        try:
            buf.flush_buffer()
        except Exception:
            recordException('start.py:24624', sys.exc_info()[1])
            _traceSwallowedException('start.py:24025', sys.exc_info()[1])
            pass


def _debugger_openManualDebug_safe_v1025(self):
    _debugger_ensureConsoleBuffer_v1025(self)
    now = time.time()
    cooldown = float(getattr(self, 'manualDebugCooldownUntil', 0.0) or 0.0)
    if self.inCrashConsole or now < cooldown:
        return
    self.manualDebugCooldownUntil = now + 1.5
    self.statusOverrideReason = 'DEBUG'
    self.emit('[FlatLineDebugger.debugger] Manual debug requested (D key)', self.logPath)
    # Manual debug is a user action, not a crash.  Do not stamp this method's
    # own source line into the payload, because that made FlatLine accuse
    # _debugger_openManualDebug_safe_v1025() of being the failure site.
    payload = {
        'type_name': 'ManualDebug',
        'message': 'Manually entered debug console (D key)',
        'worker': 'TrioKeyReader',
        'timestamp': time.time(),
    }
    if _debugger_openInlineManualDebugConsole_safe_v1025(self, payload):
        return
    self.openCrashConsole(payload, block=False)

def applyDebuggerMethodRecoveryPatch() -> bool:
    """Apply debugger recovery bindings as a lifecycle phase, not at module load."""
    debugger_database_methods = (
        'startKernel', 'workerMain', 'keyReaderLoop', 'keyReaderWindows', 'keyReaderPosix',
        'openManualDebug', 'startSocketRepl', 'startRelayServer', 'handleRelayMessage',
        'touchProcessLoop', 'touchHeartbeat', 'recordInit', 'onCallbackEnter', 'onCallbackExit',
        'onWarning', 'onFault', 'hasFlag', 'flatlined', 'crashSignature', 'formatError', 'warn', 'die',
        'renderParentFrames', 'renderParentLocals', 'capturePreConsoleSnapshot', 'dumpStacks', 'variableDump',
        'heartbeatClock', 'clearStatusLine', 'clearConsoleScreen', 'statusSpinnerLine', 'statusLoop',
        'formatCommandLine', 'socketReplTargetText', 'shellRpcTargetText', 'childOutputTargetTexts',
        'safeShortMd5', 'safeFileInfo', 'formatTimestampForStatus',
    )
    for method_name in debugger_database_methods:
        setattr(Debugger, method_name, getattr(DebuggerDatabase, method_name))

    app_only_patches = {
        'collectRuntimeDbPayload': _debugger_collectRuntimeDbPayload,
        'resolveMariaDbStatusTarget': _debugger_resolveMariaDbStatusTarget,
        'configureTraceVerbose': _debugger_configureTraceVerbose,
        'traceVerboseSourceLine': _debugger_traceVerboseSourceLine,
        'tryFormatTraceVerboseLine': _debugger_tryFormatTraceVerboseLine,
    }
    shared_debugger_patches = {
        'startKernel': _debugger_startKernel_process_zero,
        'startSnapshotCapture': _debugger_startSnapshotCapture_parent_phase,
        'renderParentFrames': _debugger_renderParentFrames_safe_v1025,
        'openInlineManualDebugConsole': _debugger_openInlineManualDebugConsole_safe_v1025,
        'openManualDebug': _debugger_openManualDebug_safe_v1025,
    }
    for attribute_name, callback in app_only_patches.items():
        setattr(Debugger, attribute_name, callback)
    for attribute_name, callback in shared_debugger_patches.items():
        for owner in (Debugger, DebuggerDatabase):
            setattr(owner, attribute_name, callback)
    setattr(StartLifecycleController, 'ensureProcessTable', _start_lifecycle_ensureProcessTable_v1022)
    return True

if __name__ == '__main__':
    _exit_code = int(main())
    try:
        _controller = globals().get('LAST_START_CONTROLLER')
        if _controller is not None and hasattr(_controller, 'finalTeardown'):
            _kill_self = str(os.environ.get('TRIO_DEBUGGER_KILL_SELF_ON_EXIT', EMPTY_STRING) or EMPTY_STRING).strip().lower() in {'1', 'true', 'yes', 'on'}
            _controller.finalTeardown(killDebuggerSelf=bool(_kill_self))
        else:
            RuntimeLog.flushAllLogs()
    except Exception:
        recordException('start.py:final-line-teardown', sys.exc_info()[1], handled=True)
        RuntimeLog.flush(final=True)
    if offscreenExitAfterActionsRequested(sys.argv[1:]):
        try:
            sys.stdout.flush(); sys.stderr.flush(); RuntimeLog.flushAllLogs()
        except Exception:
            recordException('start.py:offscreen-exit-flush', sys.exc_info()[1], handled=True)
        os._exit(_exit_code)
    raise SystemExit(_exit_code)
